import { CheckCircle2, XCircle, AlertTriangle, TrendingUp, ArrowRight, Lightbulb } from 'lucide-react';

export interface SeoTest {
    test: string;
    passed: boolean;
    message: string;
}

interface SeoAnalysisPanelProps {
    score: number;
    tests: SeoTest[];
    focusKeyword?: string;
    onUpdateKeyword?: (keyword: string) => void;
}

export function SeoAnalysisPanel({ score, tests, focusKeyword }: SeoAnalysisPanelProps) {
    const passedTests = tests.filter(t => t.passed);
    const failedTests = tests.filter(t => !t.passed);

    // Color logic
    const scoreColor = score >= 80 ? 'text-green-600' : score >= 50 ? 'text-amber-500' : 'text-red-600';
    const progressBarColor = score >= 80 ? 'bg-green-500' : score >= 50 ? 'bg-amber-500' : 'bg-red-500';

    return (
        <div className="bg-white/70 backdrop-blur-md rounded-xl shadow-xs border border-white/50 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Header / Score Card */}
            <div className="p-6 border-b border-gray-100 bg-white/50">
                <div className="flex items-start justify-between mb-4">
                    <div>
                        <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                            <TrendingUp className="text-blue-600" size={20} />
                            SEO Health Score
                        </h3>
                        <p className="text-sm text-gray-500 mt-1">
                            Optimize your product to improve search visibility.
                        </p>
                    </div>
                    <div className="text-right">
                        <div className={`text-3xl font-black ${scoreColor}`}>
                            {score}
                            <span className="text-lg text-gray-400 font-medium">/100</span>
                        </div>
                    </div>
                </div>

                {/* Progress Bar */}
                <div className="h-2 w-full bg-gray-100 rounded-full overflow-hidden">
                    <div
                        className={`h-full ${progressBarColor} transition-all duration-1000 ease-out`}
                        style={{ width: `${score}%` }}
                    />
                </div>
            </div>

            <div className="p-6 space-y-8">
                {/* Actionable Hints (Failed Tests) */}
                {failedTests.length > 0 && (
                    <div className="space-y-4">
                        <h4 className="text-sm font-bold text-gray-900 uppercase tracking-wide flex items-center gap-2">
                            <AlertTriangle size={16} className="text-amber-500" />
                            Action Items ({failedTests.length})
                        </h4>
                        <div className="space-y-3">
                            {failedTests.map((t, idx) => (
                                <div key={idx} className="group bg-white border border-l-4 border-l-amber-500 border-gray-100 rounded-lg p-4 shadow-xs hover:shadow-md transition-all">
                                    <div className="flex items-start gap-4">
                                        <div className="bg-amber-50 p-2 rounded-full shrink-0 group-hover:bg-amber-100 transition-colors">
                                            <Lightbulb className="text-amber-600" size={18} />
                                        </div>
                                        <div className="flex-1">
                                            <h5 className="font-semibold text-gray-900 text-sm mb-1">{t.test}</h5>
                                            <p className="text-sm text-gray-600 leading-relaxed">
                                                <span className="font-medium text-amber-700">Hint: </span>
                                                {t.message}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Passed Checks */}
                {passedTests.length > 0 && (
                    <div className="space-y-4">
                        <h4 className="text-sm font-bold text-gray-900 uppercase tracking-wide flex items-center gap-2">
                            <CheckCircle2 size={16} className="text-green-600" />
                            Passed Checks ({passedTests.length})
                        </h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                            {passedTests.map((t, idx) => (
                                <div key={idx} className="flex items-center gap-2 text-sm text-gray-700 bg-green-50/50 px-3 py-2 rounded-lg border border-green-100">
                                    <CheckCircle2 className="text-green-500 shrink-0" size={14} />
                                    <span className="truncate">{t.test}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {tests.length === 0 && (
                    <div className="text-center py-8 bg-gray-50 rounded-lg border-dashed border-2 border-gray-200">
                        <p className="text-gray-500 font-medium">Sync product to generate SEO analysis.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Activity, Download, Trash2, RefreshCw, Server, Mail, ShoppingBag } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

export function SystemHealth() {
    const { token } = useAuth();
    const [stats, setStats] = useState<any>(null);
    const [logs, setLogs] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    const fetchStats = async () => {
        setIsLoading(true);
        try {
            // Placeholder: accessing a hypothetical system-stats endpoint
            // In a real app, you'd likely have a dedicated admin route.
            // For now, we'll simulate or use a safe fallback if the endpoint doesn't exist yet.
            const res = await fetch('/api/admin/system-stats', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setStats(data);
            }
        } catch (error) {
            Logger.error('Failed to fetch stats', { error: error });
        } finally {
            setIsLoading(false);
        }
    };

    const fetchLogs = async () => {
        try {
            const res = await fetch('/api/admin/logs', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json(); // Assuming returns { files: ["error.log", "debug.log"] }
                setLogs(data.files || []);
            }
        } catch (error) {
            Logger.error('Failed to fetch logs', { error: error });
        }
    };

    useEffect(() => {
        if (token) {
            fetchStats();
            fetchLogs();
        }
    }, [token]);

    const handleDownloadLog = async (filename: string) => {
        try {
            const res = await fetch(`/api/admin/logs/download?file=${filename}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (!res.ok) throw new Error("Download failed");

            const blob = await res.blob();
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = filename;
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            document.body.removeChild(a);
        } catch (error) {
            alert('Failed to download log');
        }
    };

    const handleClearLogs = async () => {
        if (!confirm("Are you sure you want to clear all server logs? This cannot be undone.")) return;
        try {
            const res = await fetch('/api/admin/logs', {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                alert('Logs cleared');
                fetchLogs();
            }
        } catch (error) {
            alert('Failed to clear logs');
        }
    };

    return (
        <div className="space-y-6">
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-6">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h2 className="text-lg font-medium text-gray-900 flex items-center gap-2">
                            <Activity className="text-blue-600" size={20} />
                            System Health & Logs
                        </h2>
                        <p className="text-sm text-gray-500">Monitor server status and manage Application logs.</p>
                    </div>
                    <button onClick={fetchStats} className="p-2 hover:bg-gray-100 rounded-lg text-gray-600 transition-colors">
                        <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                    <div className="bg-gray-50 p-4 rounded-lg border border-gray-100">
                        <div className="flex items-center gap-3 mb-2">
                            <div className="w-8 h-8 rounded-full bg-green-100 flex items-center justify-center text-green-600">
                                <Server size={16} />
                            </div>
                            <span className="text-sm font-medium text-gray-700">Server Status</span>
                        </div>
                        <div className="text-2xl font-semibold text-gray-900">{stats?.uptime ? 'Online' : 'Unknown'}</div>
                        <div className="text-xs text-gray-500 mt-1">Uptime: {stats?.uptime || '--'}</div>
                    </div>
                    {/* Add more cards for Memory, DB Status etc. */}
                </div>

                <div className="border-t border-gray-100 pt-6">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-sm font-medium text-gray-900">Log Files</h3>
                        <button
                            onClick={handleClearLogs}
                            className="text-red-600 hover:text-red-700 text-sm flex items-center gap-1 px-3 py-1.5 hover:bg-red-50 rounded-lg transition-colors"
                        >
                            <Trash2 size={14} />
                            Clear All Logs
                        </button>
                    </div>

                    <div className="bg-slate-50 rounded-lg border border-slate-200 divide-y divide-slate-100">
                        {logs.length > 0 ? (
                            logs.map(log => (
                                <div key={log} className="p-3 flex justify-between items-center text-sm">
                                    <span className="font-mono text-slate-700">{log}</span>
                                    <button
                                        onClick={() => handleDownloadLog(log)}
                                        className="text-blue-600 hover:text-blue-800 flex items-center gap-1"
                                    >
                                        <Download size={14} />
                                        Download
                                    </button>
                                </div>
                            ))
                        ) : (
                            <div className="p-4 text-center text-gray-400 text-sm">No log files found</div>
                        )}
                    </div>
                </div>

                <div className="border-t border-gray-100 pt-6 mt-6">
                    <h3 className="text-sm font-medium text-gray-900 mb-4">Quick Diagnostics</h3>
                    <div className="flex gap-4">
                        <button className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors">
                            <Mail size={16} />
                            Test Email System
                        </button>
                        <button className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors">
                            <ShoppingBag size={16} />
                            Test Woo Connection
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import {
    Activity,
    Database,
    Server,
    HardDrive,
    RefreshCw,
    CheckCircle,
    XCircle,
    AlertTriangle,
    Clock,
    Inbox,
    Webhook,
    Layers
} from 'lucide-react';
import { cn } from '../../utils/cn';

interface ServiceHealth {
    status: 'healthy' | 'degraded' | 'unhealthy';
    latencyMs?: number;
    details?: string;
}

interface QueueStats {
    waiting: number;
    active: number;
    completed: number;
    failed: number;
}

interface SyncEntityType {
    type: string;
    accountsTracked: number;
    accountsSynced: number;
    oldestSync: string | null;
    newestSync: string | null;
}

interface SystemHealthData {
    status: 'healthy' | 'degraded' | 'unhealthy';
    timestamp: string;
    version: {
        app: string;
        node: string;
        uptime: number;
        uptimeFormatted: string;
    };
    services: Record<string, ServiceHealth>;
    queues: Record<string, QueueStats>;
    sync: {
        totalAccounts: number;
        entityTypes: SyncEntityType[];
    };
    webhooks: {
        failed24h: number;
        processed24h: number;
        received24h: number;
    };
}

/**
 * System Health Panel for Super Admin diagnostics.
 * Displays version info, service health, queue stats, and sync status.
 */
export function SystemHealthPanel() {
    const { token } = useAuth();
    const [loading, setLoading] = useState(false);
    const [health, setHealth] = useState<SystemHealthData | null>(null);
    const [error, setError] = useState<string | null>(null);

    const fetchHealth = async () => {
        setLoading(true);
        setError(null);
        try {
            const res = await fetch('/api/admin/system-health', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (!res.ok) throw new Error('Failed to fetch system health');
            const data = await res.json();
            setHealth(data);
        } catch (e: any) {
            setError(e.message);
        } finally {
            setLoading(false);
        }
    };

    const getStatusIcon = (status: 'healthy' | 'degraded' | 'unhealthy') => {
        switch (status) {
            case 'healthy':
                return <CheckCircle className="text-green-500" size={20} />;
            case 'degraded':
                return <AlertTriangle className="text-amber-500" size={20} />;
            case 'unhealthy':
                return <XCircle className="text-red-500" size={20} />;
        }
    };

    const getStatusBg = (status: 'healthy' | 'degraded' | 'unhealthy') => {
        switch (status) {
            case 'healthy':
                return 'bg-green-50 border-green-200';
            case 'degraded':
                return 'bg-amber-50 border-amber-200';
            case 'unhealthy':
                return 'bg-red-50 border-red-200';
        }
    };

    const formatRelativeTime = (isoString: string | null) => {
        if (!isoString) return 'Never';
        const date = new Date(isoString);
        const now = new Date();
        const diffMs = now.getTime() - date.getTime();
        const diffMins = Math.floor(diffMs / 60000);

        if (diffMins < 1) return 'Just now';
        if (diffMins < 60) return `${diffMins}m ago`;
        const diffHours = Math.floor(diffMins / 60);
        if (diffHours < 24) return `${diffHours}h ago`;
        const diffDays = Math.floor(diffHours / 24);
        return `${diffDays}d ago`;
    };

    return (
        <div className="bg-white rounded-xl shadow-xs border border-slate-200 p-6">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                    <Activity size={20} />
                    System Health
                </h2>
                <button
                    onClick={fetchHealth}
                    disabled={loading}
                    className="inline-flex items-center gap-2 px-4 py-2 text-sm font-medium text-blue-700 bg-blue-50 rounded-lg hover:bg-blue-100 transition-colors disabled:opacity-50"
                >
                    <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                    {health ? 'Refresh' : 'Load Health'}
                </button>
            </div>

            {error && (
                <div className="flex items-center gap-2 p-3 mb-4 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
                    <XCircle size={16} />
                    {error}
                </div>
            )}

            {health && (
                <div className="space-y-6">
                    {/* Overall Status */}
                    <div className={cn("flex items-center justify-between p-4 rounded-lg border", getStatusBg(health.status))}>
                        <div className="flex items-center gap-3">
                            {getStatusIcon(health.status)}
                            <div>
                                <div className="font-medium text-slate-800 capitalize">{health.status}</div>
                                <div className="text-sm text-slate-500">
                                    v{health.version.app} • Node {health.version.node} • Up {health.version.uptimeFormatted}
                                </div>
                            </div>
                        </div>
                        <div className="text-xs text-slate-500">
                            {new Date(health.timestamp).toLocaleTimeString()}
                        </div>
                    </div>

                    {/* Services Grid */}
                    <div>
                        <h3 className="text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                            <Server size={16} />
                            Services
                        </h3>
                        <div className="grid grid-cols-3 gap-3">
                            {Object.entries(health.services).map(([name, service]) => (
                                <div key={name} className="flex items-center gap-2 p-3 bg-slate-50 rounded-lg">
                                    {getStatusIcon(service.status)}
                                    <div className="flex-1 min-w-0">
                                        <div className="font-medium text-slate-700 capitalize text-sm">{name}</div>
                                        {service.latencyMs !== undefined && (
                                            <div className="text-xs text-slate-500">{service.latencyMs}ms</div>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Queue Stats */}
                    <div>
                        <h3 className="text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                            <Layers size={16} />
                            Queue Statistics
                        </h3>
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm">
                                <thead>
                                    <tr className="text-left text-slate-500 border-b border-slate-200">
                                        <th className="pb-2 font-medium">Queue</th>
                                        <th className="pb-2 font-medium text-center">Waiting</th>
                                        <th className="pb-2 font-medium text-center">Active</th>
                                        <th className="pb-2 font-medium text-center">Completed</th>
                                        <th className="pb-2 font-medium text-center">Failed</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {Object.entries(health.queues).map(([name, stats]) => (
                                        <tr key={name} className="border-b border-slate-100">
                                            <td className="py-2 font-medium text-slate-700 capitalize">{name}</td>
                                            <td className="py-2 text-center text-slate-600">{stats.waiting >= 0 ? stats.waiting : '-'}</td>
                                            <td className="py-2 text-center text-slate-600">{stats.active >= 0 ? stats.active : '-'}</td>
                                            <td className="py-2 text-center text-green-600">{stats.completed >= 0 ? stats.completed : '-'}</td>
                                            <td className="py-2 text-center text-red-600">{stats.failed >= 0 ? stats.failed : '-'}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    {/* Sync Status */}
                    <div>
                        <h3 className="text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                            <Database size={16} />
                            Sync Status ({health.sync.totalAccounts} accounts)
                        </h3>
                        <div className="grid grid-cols-2 gap-3">
                            {health.sync.entityTypes.map(entity => (
                                <div key={entity.type} className="p-3 bg-slate-50 rounded-lg">
                                    <div className="font-medium text-slate-700 capitalize mb-1">{entity.type}</div>
                                    <div className="text-xs text-slate-500 space-y-0.5">
                                        <div>{entity.accountsSynced}/{entity.accountsTracked} accounts synced</div>
                                        <div className="flex items-center gap-1">
                                            <Clock size={12} />
                                            Last: {formatRelativeTime(entity.newestSync)}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Webhook Health */}
                    <div>
                        <h3 className="text-sm font-medium text-slate-700 mb-3 flex items-center gap-2">
                            <Webhook size={16} />
                            Webhooks (24h)
                        </h3>
                        <div className="grid grid-cols-3 gap-3">
                            <div className="p-3 bg-slate-50 rounded-lg text-center">
                                <div className="text-2xl font-bold text-slate-700">{health.webhooks.received24h}</div>
                                <div className="text-xs text-slate-500">Received</div>
                            </div>
                            <div className="p-3 bg-green-50 rounded-lg text-center">
                                <div className="text-2xl font-bold text-green-600">{health.webhooks.processed24h}</div>
                                <div className="text-xs text-green-600">Processed</div>
                            </div>
                            <div className={cn(
                                "p-3 rounded-lg text-center",
                                health.webhooks.failed24h > 0 ? "bg-red-50" : "bg-slate-50"
                            )}>
                                <div className={cn(
                                    "text-2xl font-bold",
                                    health.webhooks.failed24h > 0 ? "text-red-600" : "text-slate-400"
                                )}>
                                    {health.webhooks.failed24h}
                                </div>
                                <div className={cn(
                                    "text-xs",
                                    health.webhooks.failed24h > 0 ? "text-red-600" : "text-slate-500"
                                )}>
                                    Failed
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {!health && !loading && !error && (
                <div className="text-center py-8 text-slate-400">
                    <Activity size={32} className="mx-auto mb-2 opacity-50" />
                    <p className="text-sm">Click "Load Health" to view system status</p>
                </div>
            )}
        </div>
    );
}

import { useState, useRef, useEffect, useMemo, memo } from 'react';
import { Bot, Send, Loader2, Sparkles, ChevronDown, BarChart2, TrendingUp, ShoppingCart, Target, Users, Search, DollarSign } from 'lucide-react';
import { useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

interface Message {
    id: string;
    role: 'user' | 'assistant' | 'system';
    content: string;
    sources?: any[];
}


/** Why memo: AIChatWidget lives in DashboardLayout and has no page-specific props.
 *  Without memo, every route change re-renders it unnecessarily. */
function AIChatWidgetInner() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const location = useLocation();
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<Message[]>([
        { id: 'welcome', role: 'assistant', content: 'Hi! I\'m your **Store Analyst**. Ask me about **Sales**, **Live Traffic**, **Profitability**, or valid **Forecasts**.' }
    ]);
    const [input, setInput] = useState('');
    const [isThinking, setIsThinking] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isOpen]);

    const handleSend = async (e?: React.FormEvent, textOverride?: string) => {
        if (e) e.preventDefault();
        const textToSend = textOverride || input;

        if (!textToSend.trim() || !currentAccount) return;

        const userMsg: Message = { id: Date.now().toString(), role: 'user', content: textToSend };
        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsThinking(true);

        try {
            const res = await fetch('/api/ai/chat', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                },
                body: JSON.stringify({
                    message: userMsg.content,
                    context: { path: location.pathname } // Inject URL context
                })
            });

            const data = await res.json();

            if (res.ok) {
                const aiMsg: Message = {
                    id: Date.now().toString() + '_ai',
                    role: 'assistant',
                    content: data.reply,
                    sources: data.sources
                };
                setMessages(prev => [...prev, aiMsg]);
            } else {
                throw new Error(data.error);
            }
        } catch (err) {
            setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: "Sorry, I had trouble reaching the AI. Please try again." }]);
        } finally {
            setIsThinking(false);
        }
    };

    const suggestedActions = useMemo(() => {
        const path = location.pathname;
        const actions = [
            { label: "Live Traffic", icon: <Users size={14} />, query: "Who is on the site right now?" },
            { label: "Forecast Sales", icon: <TrendingUp size={14} />, query: "Forecast my sales for next week" },
        ];

        if (path.includes('/orders/') && !path.includes('/orders/new')) {
            actions.unshift({ label: "Analyze Order", icon: <DollarSign size={14} />, query: "Is this order profitable?" });
        } else if (path.includes('/inventory/product/')) {
            actions.unshift({ label: "Product Performance", icon: <BarChart2 size={14} />, query: "How is this product performing?" });
        } else if (path.includes('/customers/')) {
            actions.unshift({ label: "Customer Value", icon: <Users size={14} />, query: "Is this a high value customer?" });
        } else {
            actions.push({ label: "Profitability", icon: <DollarSign size={14} />, query: "How profitable were we last month?" });
            actions.push({ label: "Search Terms", icon: <Search size={14} />, query: "What are people searching for?" });
        }

        return actions.slice(0, 4);
    }, [location.pathname]);

    if (!currentAccount) return null;

    return (
        <>
            {/* Trigger Button */}
            {!isOpen && (
                <button
                    onClick={() => setIsOpen(true)}
                    className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 hover:bg-blue-700 text-white rounded-full shadow-xl flex items-center justify-center transition-all hover:scale-105 z-50 group"
                >
                    <Sparkles size={24} className="group-hover:animate-pulse" />
                </button>
            )}

            {/* Chat Window - Glassmorphism */}
            {isOpen && (
                <div className="fixed bottom-6 right-6 w-[400px] h-[650px] flex flex-col z-50 overflow-hidden animate-in slide-in-from-bottom-5 fade-in duration-300 font-sans rounded-3xl shadow-2xl border border-white/20 backdrop-blur-xl bg-white/70">

                    {/* Header */}
                    <div className="bg-white/40 backdrop-blur-md p-4 flex justify-between items-center border-b border-white/20">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-full bg-linear-to-br from-blue-500 to-violet-600 flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
                                <Bot size={18} />
                            </div>
                            <div>
                                <h3 className="font-bold text-slate-800 text-sm leading-tight">OverSeek AI</h3>
                                <p className="text-[10px] text-slate-500 font-medium">Context-Aware Analyst</p>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-black/5 transition-colors text-slate-500">
                            <ChevronDown size={18} />
                        </button>
                    </div>

                    {/* Messages */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-6">
                        {messages.map(msg => (
                            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] px-5 py-3 shadow-sm ${msg.role === 'user'
                                    ? 'bg-linear-to-br from-blue-600 to-indigo-600 text-white rounded-2xl rounded-tr-sm'
                                    : 'bg-white/60 backdrop-blur-sm border border-white/40 text-slate-800 rounded-2xl rounded-tl-sm'
                                    }`}>

                                    <div className={`prose prose-sm max-w-none ${msg.role === 'user' ? 'prose-invert' : 'prose-slate'}`}>
                                        <ReactMarkdown remarkPlugins={[remarkGfm]}>
                                            {msg.content}
                                        </ReactMarkdown>
                                    </div>

                                    {/* Sources / Context Data */}
                                    {msg.sources && msg.sources.length > 0 && (
                                        <div className="mt-3 pt-3 border-t border-dashed border-white/20">
                                            <p className="text-[10px] uppercase font-bold opacity-60 mb-2 flex items-center gap-1">
                                                <Sparkles size={10} /> Analyzed Data
                                            </p>
                                            <div className="flex flex-wrap gap-2">
                                                {msg.sources.map((s: any, idx) => (
                                                    <span key={idx} className="text-[10px] bg-black/5 px-2 py-1 rounded-full truncate max-w-[150px] border border-black/5" title={JSON.stringify(s)}>
                                                        {s.name || s.title || s.term || `Item #${idx + 1}`}
                                                    </span>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}

                        {isThinking && (
                            <div className="flex justify-start">
                                <div className="bg-white border border-gray-100 rounded-2xl rounded-bl-none px-4 py-3 shadow-xs flex items-center gap-2">
                                    <Loader2 size={16} className="animate-spin text-blue-600" />
                                    <span className="text-xs text-slate-500 font-medium">Analyzing data...</span>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Suggestions */}
                    {messages.length < 3 && !isThinking && (
                        <div className="px-4 pb-2 bg-gray-50/50 flex gap-2 overflow-x-auto no-scrollbar">
                            {suggestedActions.map((action, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => handleSend(undefined, action.query)}
                                    className="flex items-center gap-2 whitespace-nowrap px-3 py-2 bg-white border border-gray-200 rounded-lg text-xs font-medium text-slate-600 hover:bg-blue-50 hover:border-blue-200 hover:text-blue-700 transition-colors shadow-xs"
                                >
                                    {action.icon}
                                    {action.label}
                                </button>
                            ))}
                        </div>
                    )}

                    {/* Input */}
                    <div className="p-3 bg-white/40 backdrop-blur-md border-t border-white/20">
                        <form onSubmit={(e) => handleSend(e)} className="flex gap-2">
                            <input
                                type="text"
                                placeholder="Ask about sales, visitors, forecasts..."
                                className="flex-1 px-4 py-3 bg-white/60 backdrop-blur-xl rounded-xl text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500/50 focus:bg-white/80 transition-all text-slate-800 placeholder:text-slate-500 shadow-inner border border-white/40"
                                value={input}
                                onChange={e => setInput(e.target.value)}
                                disabled={isThinking}
                            />
                            <button
                                type="submit"
                                disabled={!input.trim() || isThinking}
                                className="w-10 h-10 bg-blue-600 text-white rounded-xl flex items-center justify-center hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-md hover:shadow-lg active:scale-95"
                            >
                                <Send size={18} />
                            </button>
                        </form>
                    </div>
                </div>
            )}
        </>
    );
}

