                    </tbody>
                </table>
            </div>
        </div>
    );
};

import { useEffect, useState, useMemo } from 'react';
import { Loader2, Package, TrendingUp, AlertCircle, CheckCircle, Clock, ArrowUp, ArrowDown } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { cn } from '../../utils/cn';

interface VelocityItem {
    id: string;
    name: string;
    sku: string;
    image: string | null;
    stock: number;
    soldLast30d: number;
    dailyVelocity: number;
    daysRemaining: number;
}

type SortColumn = 'name' | 'stock' | 'soldLast30d' | 'dailyVelocity' | 'daysRemaining';
type SortDirection = 'asc' | 'desc';

export function StockVelocityReport() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [isLoading, setIsLoading] = useState(true);
    const [data, setData] = useState<VelocityItem[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [sortColumn, setSortColumn] = useState<SortColumn>('daysRemaining');
    const [sortDirection, setSortDirection] = useState<SortDirection>('asc');

    /**
     * Toggles sort on a column. If same column, flip direction; otherwise, default to ascending.
     */
    const handleSort = (column: SortColumn) => {
        if (sortColumn === column) {
            setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
        } else {
            setSortColumn(column);
            setSortDirection('asc');
        }
    };

    const sortedData = useMemo(() => {
        return [...data].sort((a, b) => {
            let aVal: string | number = a[sortColumn];
            let bVal: string | number = b[sortColumn];

            // String comparison for name
            if (sortColumn === 'name') {
                aVal = (aVal as string).toLowerCase();
                bVal = (bVal as string).toLowerCase();
                if (aVal < bVal) return sortDirection === 'asc' ? -1 : 1;
                if (aVal > bVal) return sortDirection === 'asc' ? 1 : -1;
                return 0;
            }

            // Numeric comparison
            const diff = (aVal as number) - (bVal as number);
            return sortDirection === 'asc' ? diff : -diff;
        });
    }, [data, sortColumn, sortDirection]);

    const SortableHeader = ({ column, label, align = 'left' }: { column: SortColumn; label: string; align?: 'left' | 'right' }) => (
        <th
            onClick={() => handleSort(column)}
            className={cn(
                "px-4 py-3 font-semibold text-gray-700 cursor-pointer hover:bg-gray-100 transition-colors select-none",
                align === 'right' && 'text-right'
            )}
        >
            <span className="inline-flex items-center gap-1">
                {label}
                {sortColumn === column && (
                    sortDirection === 'asc'
                        ? <ArrowUp size={14} className="text-blue-600" />
                        : <ArrowDown size={14} className="text-blue-600" />
                )}
            </span>
        </th>
    );

    useEffect(() => {
        if (currentAccount && token) {
            fetchData();
        }
    }, [currentAccount, token]);

    const fetchData = async () => {
        if (!currentAccount || !token) return;
        setIsLoading(true);
        try {
            const res = await fetch('/api/analytics/inventory/stock-velocity', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (!res.ok) throw new Error('Failed to fetch data');
            const json = await res.json();
            setData(json);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className="h-96 flex flex-col items-center justify-center text-gray-400">
                <Loader2 className="animate-spin mb-4" size={32} />
                <p>Calculating inventory velocity...</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="p-8 text-center text-red-500 bg-red-50 rounded-xl">
                <p className="font-bold">Error loading report</p>
                <p className="text-sm">{error}</p>
            </div>
        );
    }

    if (data.length === 0) {
        return (
            <div className="h-96 flex flex-col items-center justify-center text-gray-400 bg-white rounded-xl border border-gray-200">
                <Package size={48} className="mb-4 text-gray-300" />
                <p className="text-lg font-medium">No stock data available</p>
                <p className="text-sm">Ensure your products have "Manage Stock" enabled.</p>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h2 className="text-xl font-bold text-gray-900">Stock Velocity</h2>
                        <p className="text-sm text-gray-500">Predicted days of inventory remaining based on last 30 days performance.</p>
                    </div>
                    <div className="text-right">
                        <span className="text-sm font-medium text-gray-500">Products Tracked</span>
                        <p className="text-2xl font-bold text-gray-900">{data.length}</p>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-gray-50 border-b border-gray-200">
                            <tr>
                                <SortableHeader column="name" label="Product" />
                                <SortableHeader column="stock" label="Stock" align="right" />
                                <SortableHeader column="soldLast30d" label="30d Sales" align="right" />
                                <SortableHeader column="dailyVelocity" label="Velocity" align="right" />
                                <SortableHeader column="daysRemaining" label="Days Left" align="right" />
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {sortedData.map((item) => {
                                let statusColor = "bg-gray-100 text-gray-600";
                                let Icon = Clock;

                                if (item.daysRemaining < 7 && item.daysRemaining > 0) {
                                    statusColor = "bg-red-100 text-red-700";
                                    Icon = AlertCircle;
                                } else if (item.daysRemaining < 21 && item.daysRemaining > 0) {
                                    statusColor = "bg-orange-100 text-orange-700";
                                    Icon = Clock;
                                } else if (item.daysRemaining >= 21 && item.daysRemaining < 999) {
                                    statusColor = "bg-green-100 text-green-700";
                                    Icon = CheckCircle;
                                } else if (item.stock === 0) {
                                    statusColor = "bg-slate-100 text-slate-500";
                                }

                                return (
                                    <tr key={item.id} className="hover:bg-gray-50 transition-colors group">
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-sm bg-gray-100 border border-gray-200 flex items-center justify-center overflow-hidden shrink-0">
                                                    {item.image ? (
                                                        <img src={item.image} alt={item.name} className="w-full h-full object-cover" loading="lazy" />
                                                    ) : (
                                                        <Package size={16} className="text-gray-400" />
                                                    )}
                                                </div>
                                                <div className="min-w-0">
                                                    <p className="font-medium text-gray-900 truncate max-w-[200px] md:max-w-xs">{item.name}</p>
                                                    <p className="text-xs text-gray-500">{item.sku || 'No SKU'}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3 text-right font-medium text-gray-700">
                                            {item.stock}
                                        </td>
                                        <td className="px-4 py-3 text-right text-gray-600">
                                            {item.soldLast30d}
                                        </td>
                                        <td className="px-4 py-3 text-right text-gray-600">
                                            {item.dailyVelocity > 0 ? (
                                                <span className="flex items-center justify-end gap-1">
                                                    {item.dailyVelocity} <TrendingUp size={12} className="text-gray-400" />
                                                </span>
                                            ) : '-'}
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            <div className={cn("inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium w-full max-w-[120px] justify-center", statusColor)}>
                                                <Icon size={12} />
                                                {item.daysRemaining >= 999 ? '> 1 Year' : `${item.daysRemaining} Days`}
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

/**
 * AttachmentDisplay - Renders file attachments with appropriate icons and thumbnails.
 * Extracted from MessageBubble.tsx for reusability.
 */
import React from 'react';
import { FileText, Download, Image as ImageIcon, File, Eye, Paperclip } from 'lucide-react';
import { cn } from '../../utils/cn';

export interface AttachmentInfo {
    type: 'image' | 'pdf' | 'document' | 'file';
    url: string;
    filename: string;
    isInline?: boolean;
}

/** Returns true for filenames that look like signature/branding images rather than real attachments. */
function isSignatureLikeFilename(filename: string): boolean {
    return /^(logo|signature|sig|banner|brand|header|footer|icon|avatar|divider|spacer|separator|bullet|pixel|tracker|tracking|beacon|dot|arrow)\d*[-_]?\w*\.(png|jpe?g|gif|webp|bmp)$/i.test(filename);
}

/**
 * Extracts attachment info from message content.
 * Handles inline images, linked files, markdown links, and email attachment references.
 */
export function extractAttachments(content: string): AttachmentInfo[] {
    const attachments: AttachmentInfo[] = [];
    const seenUrls = new Set<string>();

    // Extract inline images
    const imgRegex = /<img[^>]+src=["']([^"']+)["'][^>]*>/gi;
    let match;
    while ((match = imgRegex.exec(content)) !== null) {
        const url = match[1];
        if (!seenUrls.has(url)) {
            seenUrls.add(url);
            const filename = url.split('/').pop() || 'image';
            attachments.push({ type: 'image', url, filename, isInline: true });
        }
    }

    // Extract HTML linked files
    const linkRegex = /<a[^>]+href=["']([^"']+)["'][^>]*>([^<]*)<\/a>/gi;
    while ((match = linkRegex.exec(content)) !== null) {
        const url = match[1];
        const text = match[2];
        if (seenUrls.has(url)) continue;

        const ext = url.split('.').pop()?.toLowerCase() || '';

        if (['pdf'].includes(ext)) {
            seenUrls.add(url);
            attachments.push({ type: 'pdf', url, filename: text || url.split('/').pop() || 'document.pdf' });
        } else if (['doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx'].includes(ext)) {
            seenUrls.add(url);
            attachments.push({ type: 'document', url, filename: text || url.split('/').pop() || 'document' });
        } else if (['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(ext)) {
            seenUrls.add(url);
            attachments.push({ type: 'image', url, filename: text || url.split('/').pop() || 'image' });
        }
    }

    // Extract markdown-style links: [filename](url)
    // Matches: [55466 - Yvonne McKay.pdf](/uploads/attachments/...)
    const markdownLinkRegex = /\[([^\]]+)\]\(([^)]+)\)/gi;
    while ((match = markdownLinkRegex.exec(content)) !== null) {
        const text = match[1];
        const url = match[2];
        if (seenUrls.has(url)) continue;

        // Get extension from either URL or link text (filename)
        // Be careful to only extract extensions from actual file-like patterns
        const urlExt = url.split('.').pop()?.toLowerCase().split(/[?#]/)[0] || '';
        const textExt = text.split('.').pop()?.toLowerCase() || '';

        // Valid file extensions for attachments
        const validExtensions = ['pdf', 'doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx', 'jpg', 'jpeg', 'png', 'gif', 'webp', 'txt', 'csv', 'zip'];
        const ext = validExtensions.includes(urlExt) ? urlExt : (validExtensions.includes(textExt) ? textExt : '');

        // Only count as attachment if:
        // 1. The URL looks like an attachment path (explicit attachment directories)
        // 2. AND has a valid file extension
        // This prevents random markdown links from being detected as attachments
        const isAttachmentPath = url.includes('/uploads/attachments/') ||
            url.includes('/attachment/') ||
            url.includes('/files/');

        // Only match if we have BOTH a valid extension AND an attachment-like path
        // OR if the link text itself looks like a filename with extension (e.g., "document.pdf")
        const hasFileExtensionInText = validExtensions.some(e => text.toLowerCase().endsWith('.' + e));
        const isAttachment = ext && (isAttachmentPath || hasFileExtensionInText);

        if (isAttachment) {
            seenUrls.add(url);

            let type: AttachmentInfo['type'] = 'file';
            if (ext === 'pdf') type = 'pdf';
            else if (['doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx'].includes(ext)) type = 'document';
            else if (['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(ext)) type = 'image';

            const filename = text || url.split('/').pop() || 'file';
            // Skip images that look like signature/branding content (server-side safety net)
            if (type === 'image' && isSignatureLikeFilename(filename)) continue;

            attachments.push({ type, url, filename });
        }
    }

    // Extract email attachment references like "<55340 - Jules Denslow.pdf>"
    const emailAttachmentRegex = /<([^>]+\.(pdf|docx?|xlsx?|pptx?|jpe?g|png|gif|webp))>/gi;
    while ((match = emailAttachmentRegex.exec(content)) !== null) {
        const filename = match[1].trim();
        const ext = match[2].toLowerCase();

        let type: AttachmentInfo['type'] = 'file';
        if (ext === 'pdf') type = 'pdf';
        else if (['doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx'].includes(ext)) type = 'document';
        else if (['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(ext)) type = 'image';

        if (!attachments.some(a => a.filename === filename)) {
            attachments.push({ type, url: '', filename });
        }
    }

    return attachments;
}

/**
 * Icon component for rendering appropriate file type icons.
 */
export function AttachmentIcon({ type }: { type: 'image' | 'pdf' | 'document' | 'file' }) {
    switch (type) {
        case 'image':
            return <ImageIcon size={16} />;
        case 'pdf':
            return <FileText size={16} className="text-red-500" />;
        case 'document':
            return <FileText size={16} className="text-blue-500" />;
        default:
            return <File size={16} />;
    }
}

export interface AttachmentGalleryProps {
    attachments: AttachmentInfo[];
    onImageClick?: (src: string) => void;
}

/**
 * Renders a gallery of file attachments as compact pills.
 */
export function AttachmentGallery({ attachments, onImageClick }: AttachmentGalleryProps) {
    // Inline images are already rendered in the message HTML body — skip them here.
    const visibleAttachments = attachments.filter(a => !a.isInline);

    if (visibleAttachments.length === 0) return null;

    return (
        <div className="flex flex-wrap gap-2 mt-2">
            {visibleAttachments.map((attachment, idx) => (
                attachment.type === 'image' && attachment.url ? (
                    // Image thumbnail pill
                    <button
                        key={idx}
                        onClick={() => onImageClick?.(attachment.url)}
                        className="group flex items-center gap-2 pl-1 pr-3 py-1 bg-gradient-to-r from-gray-50 to-white border border-gray-200 rounded-full shadow-sm hover:shadow hover:border-gray-300 transition-all"
                    >
                        <img
                            src={attachment.url}
                            alt={attachment.filename}
                            className="w-6 h-6 object-cover rounded-full ring-1 ring-gray-200"
                        />
                        <span className="text-xs text-gray-600 max-w-[100px] truncate group-hover:text-gray-900">
                            {attachment.filename}
                        </span>
                        <Eye size={12} className="text-gray-400 group-hover:text-blue-500 transition-colors" />
                    </button>
                ) : (
                    // File attachment pill
                    <a
                        key={idx}
                        href={attachment.url || '#'}
                        target="_blank"
                        rel="noopener noreferrer"
                        download={attachment.filename}
                        className={cn(
                            "group inline-flex items-center gap-2 px-3 py-1.5 rounded-full shadow-sm transition-all",
                            attachment.type === 'pdf'
                                ? "bg-gradient-to-r from-red-50 to-white border border-red-200 hover:border-red-300 hover:shadow"
                                : attachment.type === 'document'
                                    ? "bg-gradient-to-r from-blue-50 to-white border border-blue-200 hover:border-blue-300 hover:shadow"
                                    : "bg-gradient-to-r from-gray-50 to-white border border-gray-200 hover:border-gray-300 hover:shadow",
                            !attachment.url && "opacity-60 pointer-events-none"
                        )}
                    >
                        <span className={cn(
                            "p-1 rounded-full",
                            attachment.type === 'pdf' ? "bg-red-100" : attachment.type === 'document' ? "bg-blue-100" : "bg-gray-100"
                        )}>
                            <AttachmentIcon type={attachment.type} />
                        </span>
                        <span className="text-xs text-gray-700 max-w-[120px] truncate font-medium group-hover:text-gray-900">
                            {attachment.filename}
                        </span>
                        {attachment.url ? (
                            <Download size={12} className="text-gray-400 group-hover:text-green-500 transition-colors" />
                        ) : (
                            <Paperclip size={12} className="text-gray-400" />
                        )}
                    </a>
                )
            ))}
        </div>
    );
}

/**
 * BulkActionToolbar
 * 
 * Floating toolbar that appears when conversations are selected.
 * Provides bulk actions: Close, Assign, Add Label, Merge.
 */

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { X, CheckCircle, UserPlus, Tag, Loader2, XCircle, FolderOpen, Merge } from 'lucide-react';
import { cn } from '../../utils/cn';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useClickOutside } from '../../hooks/useClickOutside';

interface BulkActionToolbarProps {
    selectedIds: string[];
    onClearSelection: () => void;
    onActionComplete: () => void;
    users?: { id: string; fullName: string }[];
    labels?: { id: string; name: string; color: string }[];
}

type BulkAction = 'close' | 'open' | 'assign' | 'addLabel';

export function BulkActionToolbar({
    selectedIds,
    onClearSelection,
    onActionComplete,
    users = [],
    labels = [],
}: BulkActionToolbarProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [isLoading, setIsLoading] = useState(false);
    const [showAssignDropdown, setShowAssignDropdown] = useState(false);
    const [showLabelDropdown, setShowLabelDropdown] = useState(false);
    const [showMergeConfirm, setShowMergeConfirm] = useState(false);
    const [mergeTargetId, setMergeTargetId] = useState<string | null>(null);

    // Click-outside refs for dropdowns
    const assignDropdownRef = useClickOutside<HTMLDivElement>(() => setShowAssignDropdown(false));
    const labelDropdownRef = useClickOutside<HTMLDivElement>(() => setShowLabelDropdown(false));

    // Escape key to close merge confirm modal
    useEffect(() => {
        if (!showMergeConfirm) return;
        const handleKey = (e: KeyboardEvent) => {
            if (e.key === 'Escape') {
                setShowMergeConfirm(false);
                setMergeTargetId(null);
            }
        };
        document.addEventListener('keydown', handleKey);
        return () => document.removeEventListener('keydown', handleKey);
    }, [showMergeConfirm]);

    const performBulkAction = async (
        action: BulkAction,
        options?: { labelId?: string; assignToUserId?: string }
    ) => {
        setIsLoading(true);
        try {
            const res = await fetch('/api/chat/conversations/bulk', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || '',
                },
                body: JSON.stringify({
                    conversationIds: selectedIds,
                    action,
                    ...options,
                }),
            });

            if (res.ok) {
                onActionComplete();
                onClearSelection();
            } else {
                const data = await res.json();
                Logger.error('Bulk action failed', { error: data.error });
            }
        } catch (error) {
            Logger.error('Bulk action error:', { error: error });
        } finally {
            setIsLoading(false);
            setShowAssignDropdown(false);
            setShowLabelDropdown(false);
        }
    };

    const performBulkMerge = async () => {
        if (!mergeTargetId) return;

        setIsLoading(true);
        try {
            const sourceIds = selectedIds.filter(id => id !== mergeTargetId);
            const res = await fetch('/api/chat/conversations/bulk-merge', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || '',
                },
                body: JSON.stringify({
                    targetId: mergeTargetId,
                    sourceIds,
                }),
            });

            if (res.ok) {
                onActionComplete();
                onClearSelection();
            } else {
                const data = await res.json();
                Logger.error('Bulk merge failed', { error: data.error });
            }
        } catch (error) {
            Logger.error('Bulk merge error:', { error: error });
        } finally {
            setIsLoading(false);
            setShowMergeConfirm(false);
            setMergeTargetId(null);
        }
    };

    if (selectedIds.length === 0) return null;

    return (
        <>
            <div className="fixed bottom-4 left-1/2 transform -translate-x-1/2 z-50">
                <div className="flex items-center gap-2 px-4 py-3 bg-gray-900 border border-gray-700 rounded-xl shadow-2xl">
                    {/* Selection Count */}
                    <div className="flex items-center gap-2 pr-3 border-r border-gray-700">
                        <span className="text-sm font-medium text-white">
                            {selectedIds.length} selected
                        </span>
                        <button
                            onClick={onClearSelection}
                            className="p-1 text-gray-400 hover:text-white rounded-lg hover:bg-gray-700 transition-colors"
                            aria-label="Clear selection"
                        >
                            <X className="w-4 h-4" />
                        </button>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center gap-1">
                        {/* Close */}
                        <button
                            onClick={() => performBulkAction('close')}
                            disabled={isLoading}
                            className={cn(
                                'flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium',
                                'bg-gray-800 text-gray-300 hover:bg-gray-700 hover:text-white transition-colors',
                                'disabled:opacity-50 disabled:cursor-not-allowed'
                            )}
                        >
                            {isLoading ? (
                                <Loader2 className="w-4 h-4 animate-spin" />
                            ) : (
                                <XCircle className="w-4 h-4" />
                            )}
                            Close
                        </button>

                        {/* Reopen */}
                        <button
                            onClick={() => performBulkAction('open')}
                            disabled={isLoading}
                            className={cn(
                                'flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium',
                                'bg-gray-800 text-gray-300 hover:bg-gray-700 hover:text-white transition-colors',
                                'disabled:opacity-50 disabled:cursor-not-allowed'
                            )}
                        >
                            <FolderOpen className="w-4 h-4" />
                            Reopen
                        </button>

                        {/* Merge - only show when 2+ selected */}
                        {selectedIds.length >= 2 && (
                            <button
                                onClick={() => {
                                    setMergeTargetId(selectedIds[0]);
                                    setShowMergeConfirm(true);
                                }}
                                disabled={isLoading}
                                className={cn(
                                    'flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium',
                                    'bg-indigo-700 text-white hover:bg-indigo-600 transition-colors',
                                    'disabled:opacity-50 disabled:cursor-not-allowed'
                                )}
                            >
                                <Merge className="w-4 h-4" />
                                Merge
                            </button>
                        )}

                        {/* Assign */}
                        <div className="relative" ref={assignDropdownRef}>
                            <button
                                onClick={() => {
                                    setShowAssignDropdown(!showAssignDropdown);
                                    setShowLabelDropdown(false);
                                }}
                                disabled={isLoading}
                                className={cn(
                                    'flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium',
                                    'bg-gray-800 text-gray-300 hover:bg-gray-700 hover:text-white transition-colors',
                                    'disabled:opacity-50 disabled:cursor-not-allowed',
                                    showAssignDropdown && 'bg-gray-700 text-white'
                                )}
                            >
                                <UserPlus className="w-4 h-4" />
                                Assign
                            </button>

                            {/* Assign Dropdown */}
                            {showAssignDropdown && (
                                <div className="absolute bottom-full left-0 mb-2 w-48 bg-gray-800 border border-gray-700 rounded-lg shadow-xl py-1">
                                    {users.length === 0 ? (
                                        <div className="px-3 py-2 text-sm text-gray-500">No users available</div>
                                    ) : (
                                        users.map((user) => (
                                            <button
                                                key={user.id}
                                                onClick={() => performBulkAction('assign', { assignToUserId: user.id })}
                                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-left text-gray-200 hover:bg-gray-700 transition-colors"
                                            >
                                                <div className="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center text-xs text-white">
                                                    {user.fullName?.charAt(0) || '?'}
                                                </div>
                                                {user.fullName || 'Unknown'}
                                            </button>
                                        ))
                                    )}
                                </div>
                            )}
                        </div>

                        {/* Add Label */}
                        <div className="relative" ref={labelDropdownRef}>
                            <button
                                onClick={() => {
                                    setShowLabelDropdown(!showLabelDropdown);
                                    setShowAssignDropdown(false);
                                }}
                                disabled={isLoading}
                                className={cn(
                                    'flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium',
                                    'bg-gray-800 text-gray-300 hover:bg-gray-700 hover:text-white transition-colors',
                                    'disabled:opacity-50 disabled:cursor-not-allowed',
                                    showLabelDropdown && 'bg-gray-700 text-white'
                                )}
                            >
                                <Tag className="w-4 h-4" />
                                Label
                            </button>

                            {/* Label Dropdown */}
                            {showLabelDropdown && (
                                <div className="absolute bottom-full left-0 mb-2 w-48 bg-gray-800 border border-gray-700 rounded-lg shadow-xl py-1">
                                    {labels.length === 0 ? (
                                        <div className="px-3 py-2 text-sm text-gray-500">No labels created</div>
                                    ) : (
                                        labels.map((label) => (
                                            <button
                                                key={label.id}
                                                onClick={() => performBulkAction('addLabel', { labelId: label.id })}
                                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-left text-gray-200 hover:bg-gray-700 transition-colors"
                                            >
                                                <span
                                                    className="w-3 h-3 rounded-full"
                                                    style={{ backgroundColor: label.color }}
                                                />
                                                {label.name}
                                            </button>
                                        ))
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Merge Confirmation Modal */}
            {showMergeConfirm && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60]">
                    <div className="bg-white rounded-xl shadow-2xl p-6 max-w-md w-full mx-4">
                        <div className="flex items-center gap-3 mb-4">
                            <div className="p-2 bg-indigo-100 rounded-lg">
                                <Merge className="w-5 h-5 text-indigo-600" />
                            </div>
                            <h3 className="text-lg font-semibold text-gray-900">Merge Conversations</h3>
                        </div>

                        <p className="text-sm text-gray-600 mb-4">
                            Select the target conversation. All messages from the other {selectedIds.length - 1} conversation(s)
                            will be moved into the target.
                        </p>

                        <p className="text-xs text-amber-600 bg-amber-50 p-2 rounded-lg mb-4">
                            ⚠️ This action cannot be undone. The source conversations will be closed.
                        </p>

                        <div className="space-y-2 max-h-48 overflow-y-auto mb-4">
                            {selectedIds.map((id, index) => (
                                <label
                                    key={id}
                                    className={cn(
                                        "flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-colors",
                                        mergeTargetId === id
                                            ? "border-indigo-500 bg-indigo-50"
                                            : "border-gray-200 hover:border-gray-300"
                                    )}
                                >
                                    <input
                                        type="radio"
                                        name="mergeTarget"
                                        checked={mergeTargetId === id}
                                        onChange={() => setMergeTargetId(id)}
                                        className="text-indigo-600"
                                    />
                                    <span className="text-sm text-gray-700">
                                        Conversation #{index + 1}
                                        {mergeTargetId === id && (
                                            <span className="ml-2 text-xs text-indigo-600 font-medium">(Target)</span>
                                        )}
                                    </span>
                                </label>
                            ))}
                        </div>

                        <div className="flex gap-3">
                            <button
                                onClick={() => {
                                    setShowMergeConfirm(false);
                                    setMergeTargetId(null);
                                }}
                                className="flex-1 px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={performBulkMerge}
                                disabled={!mergeTargetId || isLoading}
                                className={cn(
                                    "flex-1 px-4 py-2 text-sm font-medium text-white rounded-lg transition-colors",
                                    "bg-indigo-600 hover:bg-indigo-700",
                                    "disabled:opacity-50 disabled:cursor-not-allowed"
                                )}
                            >
                                {isLoading ? 'Merging...' : 'Merge Conversations'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

/**
 * CannedResponsesManager - Modal for quickly managing canned responses from inbox.
 * Includes rich text editing and label support.
 */
import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { X, Plus, Trash2, Zap, Tag } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { RichTextEditor } from '../common/RichTextEditor';
import DOMPurify from 'dompurify';

interface CannedResponseLabel {
    id: string;
    name: string;
    color: string;
}

interface CannedResponse {
    id: string;
    shortcut: string;
    content: string;
    labelId: string | null;
    label: CannedResponseLabel | null;
}

interface CannedResponsesManagerProps {
    isOpen: boolean;
    onClose: () => void;
    onUpdate?: () => void;
}

export function CannedResponsesManager({ isOpen, onClose, onUpdate }: CannedResponsesManagerProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [responses, setResponses] = useState<CannedResponse[]>([]);
    const [labels, setLabels] = useState<CannedResponseLabel[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [newShortcut, setNewShortcut] = useState('');
    const [newContent, setNewContent] = useState('');
    const [newLabelId, setNewLabelId] = useState('');
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (isOpen && currentAccount && token) {
            fetchResponses();
            fetchLabels();
        }
    }, [isOpen, currentAccount, token]);

    // Close on Escape key
    useEffect(() => {
        if (!isOpen) return;
        const handleKey = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
        };
        document.addEventListener('keydown', handleKey);
        return () => document.removeEventListener('keydown', handleKey);
    }, [isOpen, onClose]);

    const fetchLabels = async () => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch('/api/chat/canned-labels', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                setLabels(await res.json());
            }
        } catch (e) {
            Logger.error('Failed to fetch labels', { error: e });
        }
    };

    const fetchResponses = async () => {
        if (!currentAccount || !token) return;
        setIsLoading(true);
        try {
            const res = await fetch('/api/chat/canned-responses', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                setResponses(await res.json());
            }
        } finally {
            setIsLoading(false);
        }
    };

    const handleAdd = async () => {
        if (!newShortcut.trim() || !newContent.trim() || !currentAccount || !token) return;

        setIsSaving(true);
        try {
            const res = await fetch('/api/chat/canned-responses', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                },
                body: JSON.stringify({
                    shortcut: newShortcut.trim(),
                    content: newContent.trim(),
                    labelId: newLabelId || null,
                    accountId: currentAccount.id
                })
            });

            if (res.ok) {
                const newResponse = await res.json();
                setResponses(prev => [...prev, newResponse]);
                setNewShortcut('');
                setNewContent('');
                setNewLabelId('');
                onUpdate?.();
            }
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!token) return;

        try {
            const res = await fetch(`/api/chat/canned-responses/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });

            if (res.ok) {
                setResponses(prev => prev.filter(r => r.id !== id));
                onUpdate?.();
            }
        } catch (e) {
            Logger.error('Failed to delete', { error: e });
        }
    };

    if (!isOpen) return null;

    // Group by label
    const grouped = responses.reduce((acc, r) => {
        const key = r.label?.name || 'Uncategorized';
        if (!acc[key]) acc[key] = { label: r.label, items: [] };
        acc[key].items.push(r);
        return acc;
    }, {} as Record<string, { label: CannedResponseLabel | null; items: CannedResponse[] }>);

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200">
                    <div className="flex items-center gap-2">
                        <Zap className="text-blue-600" size={20} />
                        <h2 className="text-lg font-semibold text-gray-900">Canned Responses</h2>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 rounded-lg hover:bg-gray-100 text-gray-500 transition-colors"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Add New Form */}
                <div className="px-6 py-4 border-b border-gray-100 bg-gray-50">
                    <h3 className="text-sm font-medium text-gray-700 mb-3">Add New Response</h3>
                    <div className="flex gap-3 mb-3">
                        <div className="w-32">
                            <label className="block text-xs text-gray-500 mb-1">Shortcut</label>
                            <div className="flex items-center">
                                <span className="text-gray-400 mr-1">/</span>
                                <input
                                    type="text"
                                    value={newShortcut}
                                    onChange={(e) => setNewShortcut(e.target.value.replace(/\s/g, ''))}
                                    placeholder="hi"
                                    className="flex-1 px-2 py-1.5 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-400"
                                />
                            </div>
                        </div>
                        <div className="w-40">
                            <label className="block text-xs text-gray-500 mb-1">Label</label>
                            <select
                                value={newLabelId}
                                onChange={(e) => setNewLabelId(e.target.value)}
                                className="w-full px-2 py-1.5 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-400"
                            >
                                <option value="">No Label</option>
                                {labels.map(label => (
                                    <option key={label.id} value={label.id}>{label.name}</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex items-end">
                            <button
                                onClick={handleAdd}
                                disabled={!newShortcut.trim() || !newContent.trim() || isSaving}
                                className="flex items-center gap-1.5 px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <Plus size={16} />
                                {isSaving ? 'Adding...' : 'Add'}
                            </button>
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Content (Rich Text)</label>
                        <RichTextEditor
                            value={newContent}
                            onChange={setNewContent}
                            placeholder="Hello! How can I help you today?"
                            variant="compact"
                        />
                    </div>
                </div>

                {/* List */}
                <div className="flex-1 overflow-y-auto">
                    {isLoading ? (
                        <div className="p-8 text-center text-gray-500">Loading...</div>
                    ) : responses.length === 0 ? (
                        <div className="p-8 text-center text-gray-500">
                            <Zap size={32} className="mx-auto mb-2 opacity-50" />
                            <p>No canned responses yet</p>
                            <p className="text-sm">Add your first one above!</p>
                        </div>
                    ) : (
                        <div className="divide-y divide-gray-100">
                            {Object.entries(grouped).map(([name, { label, items }]) => (
                                <div key={name} className="px-6 py-3">
                                    <div className="flex items-center gap-2 mb-2">
                                        {label ? (
                                            <div
                                                className="w-3 h-3 rounded-full"
                                                style={{ backgroundColor: label.color }}
                                            />
                                        ) : (
                                            <Tag size={12} className="text-gray-400" />
                                        )}
                                        <span className="text-xs font-medium text-gray-500 uppercase">{name}</span>
                                    </div>
                                    {items.map(response => (
                                        <div key={response.id} className="flex items-start gap-4 py-2 hover:bg-gray-50 rounded-lg px-2 -mx-2">
                                            <div className="shrink-0 pt-0.5">
                                                <span className="font-mono text-sm bg-gray-100 px-2 py-1 rounded-sm text-gray-600">
                                                    /{response.shortcut}
                                                </span>
                                            </div>
                                            <div
                                                className="flex-1 min-w-0 text-sm text-gray-700 prose prose-sm max-w-none line-clamp-2"
                                                dangerouslySetInnerHTML={{
                                                    __html: DOMPurify.sanitize(response.content, {
                                                        ALLOWED_TAGS: ['b', 'i', 'u', 'strong', 'em', 'p', 'br'],
                                                        ALLOWED_ATTR: []
                                                    })
                                                }}
                                            />
                                            <button
                                                onClick={() => handleDelete(response.id)}
                                                className="shrink-0 p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-sm transition-colors"
                                                title="Delete"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="px-6 py-3 border-t border-gray-200 bg-gray-50 text-xs text-gray-500">
                    Type <code className="bg-gray-200 px-1 rounded-sm">/shortcut</code> in the reply box to use a canned response
                </div>
            </div>
        </div>
    );
}

/**
 * ChatComposer - Message composition area with toolbar and canned responses.
 * Handles the reply/private note toggle, channel selector, and send controls.
 */
import { useState, memo } from 'react';
import { Loader2, Paperclip, X } from 'lucide-react';
import { cn } from '../../utils/cn';
import { InboxRichTextEditor } from './InboxRichTextEditor';
import { ChannelSelector, ConversationChannel } from './ChannelSelector';
import { CannedResponse } from '../../hooks/useCannedResponses';
import { ComposerToolbar } from './ComposerToolbar';

interface ChannelOption {
    channel: ConversationChannel;
    identifier: string;
    available: boolean;
}

interface EmailAccountOption {
    id: string;
    name: string;
    email: string;
}

interface ChatComposerProps {
    conversationId: string;
    recipientEmail?: string;
    // Input state
    input: string;
    onInputChange: (value: string) => void;
    // Internal note toggle
    isInternal: boolean;
    onInternalChange: (value: boolean) => void;
    // Send controls
    isSending: boolean;
    onSend: (e?: React.FormEvent, channel?: ConversationChannel) => void;
    pendingSend: { content: string; timeout: NodeJS.Timeout } | null;
    onCancelSend: () => void;
    UNDO_DELAY_MS: number;
    // Signature
    signatureEnabled: boolean;
    onSignatureChange: (value: boolean) => void;
    // Quote reply
    quotedMessage: { id: string; content: string; senderType: string } | null;
    onClearQuote: () => void;
    recipientName?: string;
    // Canned responses
    showCanned: boolean;
    filteredCanned: CannedResponse[];
    cannedResponses: CannedResponse[];
    onSelectCanned: (response: CannedResponse) => void;
    onOpenCannedManager: () => void;
    // AI Draft
    isGeneratingDraft: boolean;
    onGenerateAIDraft: () => void;
    // File upload
    isUploading: boolean;
    uploadProgress?: number;
    onFileUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    fileInputRef: React.RefObject<HTMLInputElement | null>;
    // Staged attachments
    stagedAttachments?: File[];
    onRemoveAttachment?: (index: number) => void;
    /** Error from file staging (size/count limit exceeded) */
    attachmentError?: string | null;
    // Scheduling
    onOpenSchedule: () => void;
    // Channel selection
    availableChannels?: ChannelOption[];
    currentChannel?: ConversationChannel;
    // Email account selection (From dropdown)
    emailAccounts?: EmailAccountOption[];
    selectedEmailAccountId?: string;
    onEmailAccountChange?: (accountId: string) => void;
}

/**
 * Renders the message composition area including toolbar and controls.
 */
export const ChatComposer = memo(function ChatComposer({
    recipientEmail,
    input,
    onInputChange,
    isInternal,
    onInternalChange,
    isSending,
    onSend,
    pendingSend,
    onCancelSend,
    UNDO_DELAY_MS,
    signatureEnabled,
    onSignatureChange,
    quotedMessage,
    onClearQuote,
    recipientName,
    showCanned,
    filteredCanned,
    cannedResponses,
    onSelectCanned,
    onOpenCannedManager,
    isGeneratingDraft,
    onGenerateAIDraft,
    isUploading,
    uploadProgress = 0,
    onFileUpload,
    fileInputRef,
    stagedAttachments = [],
    onRemoveAttachment,
    attachmentError,
    onOpenSchedule,
    availableChannels,
    currentChannel,
    emailAccounts,
    selectedEmailAccountId,
    onEmailAccountChange
}: ChatComposerProps) {
    const [selectedChannel, setSelectedChannel] = useState<ConversationChannel>(currentChannel || 'CHAT');

    const MAX_SMS_LENGTH = 1600;
    const plainTextLength = input.replace(/<[^>]*>/g, '').length;
    const isSmsTooLong = selectedChannel === 'SMS' && plainTextLength > MAX_SMS_LENGTH;

    return (
        <div className="border-t border-gray-200 bg-white">
            {/* Canned Responses Dropdown */}
            {showCanned && (
                <div className="border-b border-gray-200 bg-white max-h-48 overflow-y-auto">
                    <div className="p-2 text-xs text-gray-500 border-b bg-gray-50 flex items-center justify-between">
                        <span>Canned Responses (type to filter)</span>
                        <button
                            onClick={() => {
                                onOpenCannedManager();
                                onInputChange('');
                            }}
                            className="flex items-center gap-1 text-blue-600 hover:text-blue-700"
                        >
                            <span className="sr-only">Manage</span>
                            Manage
                        </button>
                    </div>
                    {filteredCanned.length > 0 ? (
                        filteredCanned.map(r => (
                            <button
                                key={r.id}
                                onClick={() => onSelectCanned(r)}
                                className="w-full text-left px-3 py-2 hover:bg-blue-50 transition-colors border-b border-gray-50 last:border-0"
                            >
                                <span className="text-xs font-mono bg-gray-100 px-1.5 py-0.5 rounded-sm text-gray-600">
                                    /{r.shortcut}
                                </span>
                                <p className="text-sm text-gray-700 mt-1 line-clamp-1">{r.content}</p>
                            </button>
                        ))
                    ) : (
                        <div className="px-3 py-4 text-center text-gray-500 text-sm">
                            {cannedResponses.length === 0 ? (
                                <>No canned responses yet. <button onClick={onOpenCannedManager} className="text-blue-600 hover:underline">Add one</button></>
                            ) : (
                                'No matches found'
                            )}
                        </div>
                    )}
                </div>
            )}

            {/* Reply Mode Toggle */}
            <div className="flex border-b border-gray-100">
                <button
                    onClick={() => onInternalChange(false)}
                    className={cn(
                        "px-4 py-2 text-sm font-medium border-b-2 transition-colors",
                        !isInternal
                            ? "border-blue-600 text-blue-600"
                            : "border-transparent text-gray-500 hover:text-gray-700"
                    )}
                >
                    Reply
                </button>
                <button
                    onClick={() => onInternalChange(true)}
                    className={cn(
                        "px-4 py-2 text-sm font-medium border-b-2 transition-colors",
                        isInternal
                            ? "border-yellow-500 text-yellow-600"
                            : "border-transparent text-gray-500 hover:text-gray-700"
                    )}
                >
                    Private Note
                </button>
            </div>

            {/* Quote Reply Preview */}
            {quotedMessage && (
                <div className="px-4 py-2 border-b border-gray-100 bg-blue-50 flex items-start gap-2">
                    <div className="flex-1 min-w-0">
                        <div className="text-xs text-blue-600 font-medium mb-0.5">
                            Replying to {quotedMessage.senderType === 'AGENT' ? 'yourself' : (recipientName || 'customer')}
                        </div>
                        <div className="text-sm text-gray-600 truncate">
                            {quotedMessage.content.replace(/<[^>]*>/g, '').substring(0, 80)}
                            {quotedMessage.content.length > 80 ? '...' : ''}
                        </div>
                    </div>
                    <button
                        onClick={onClearQuote}
                        className="p-1 rounded-sm hover:bg-blue-100 text-blue-400"
                    >
                        <X size={14} />
                    </button>
                </div>
            )}

            {/* Channel Selector for replies */}
            {!isInternal && availableChannels && availableChannels.length > 0 && (
                <div className="px-4 py-2 border-b border-gray-100">
                    <ChannelSelector
                        channels={availableChannels}
                        selectedChannel={selectedChannel}
                        onChannelChange={setSelectedChannel}
                        disabled={isSending}
                    />
                </div>
            )}

            {/* From field (Email Account Selector) - show when using EMAIL channel */}
            {!isInternal && recipientEmail && emailAccounts && emailAccounts.length > 1 && (
                <div className="px-4 py-2 border-b border-gray-100 text-sm">
                    <div className="flex items-center gap-2">
                        <span className="text-gray-400 w-12">FROM</span>
                        <select
                            value={selectedEmailAccountId}
                            onChange={(e) => onEmailAccountChange?.(e.target.value)}
                            className="flex-1 text-gray-700 bg-transparent border-none outline-none cursor-pointer hover:text-blue-600 text-sm"
                        >
                            {emailAccounts.map(account => (
                                <option key={account.id} value={account.id}>
                                    {account.name} ({account.email})
                                </option>
                            ))}
                        </select>
                    </div>
                </div>
            )}

            {/* Fallback: Simple TO field when no channel options */}
            {!isInternal && (!availableChannels || availableChannels.length === 0) && recipientEmail && (
                <div className="px-4 py-2 border-b border-gray-100 text-sm">
                    <div className="flex items-center gap-2">
                        <span className="text-gray-400 w-12">TO</span>
                        <span className="text-gray-700">{recipientEmail}</span>
                    </div>
                </div>
            )}

            {/* Compose Area */}
            <div className={cn("p-4", isInternal && "bg-yellow-50")}>
                <InboxRichTextEditor
                    value={input}
                    onChange={onInputChange}
                    onSubmit={() => {
                        if (!showCanned) {
                            onSend(undefined, selectedChannel);
                        } else if (filteredCanned.length > 0) {
                            onSelectCanned(filteredCanned[0]);
                        }
                    }}
                    placeholder={isInternal
                        ? "Add a private note (only visible to team)..."
                        : "Type your reply... (/ for canned responses)"}
                    isInternal={isInternal}
                    cannedPickerOpen={showCanned}
                />

                {/* Staged Attachments Pills */}
                {stagedAttachments.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-2 px-1">
                        {stagedAttachments.map((file, index) => (
                            <div
                                key={`${file.name}-${index}`}
                                className="group inline-flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-blue-50 to-white border border-blue-200 rounded-full text-sm shadow-sm"
                            >
                                <Paperclip size={14} className="text-blue-500" />
                                <span className="text-gray-700 max-w-[150px] truncate">{file.name}</span>
                                <span className="text-xs text-gray-400">
                                    ({(file.size / 1024).toFixed(0)}KB)
                                </span>
                                {onRemoveAttachment && (
                                    <button
                                        type="button"
                                        onClick={() => onRemoveAttachment(index)}
                                        disabled={isUploading}
                                        className="text-gray-400 hover:text-red-500 transition-colors disabled:opacity-50"
                                        title="Remove attachment"
                                    >
                                        <X size={14} />
                                    </button>
                                )}
                            </div>
                        ))}
                    </div>
                )}

                {/* Attachment Error */}
                {attachmentError && (
                    <div className="mt-2 px-3 py-2 text-xs font-medium text-red-700 bg-red-50 border border-red-200 rounded-lg">
                        ⚠️ {attachmentError}
                    </div>
                )}

                {/* Upload Progress Bar */}
                {isUploading && uploadProgress > 0 && (
                    <div className="mt-2 px-1 space-y-1">
                        <div className="flex items-center justify-between text-xs text-gray-600">
                            <span>Uploading attachments...</span>
                            <span className="font-medium">{uploadProgress}%</span>
                        </div>
                        <div className="w-full h-1.5 bg-gray-200 rounded-full overflow-hidden">
                            <div
                                className="h-full bg-gradient-to-r from-blue-500 to-blue-600 rounded-full transition-all duration-200"
                                style={{ width: `${uploadProgress}%` }}
                            />
                        </div>
                    </div>
                )}

                {/* Toolbar */}
                <ComposerToolbar
                    input={input}
                    isInternal={isInternal}
                    isSending={isSending}
                    showCanned={showCanned}
                    pendingSend={pendingSend}
                    recipientEmail={recipientEmail}
                    signatureEnabled={signatureEnabled}
                    onSignatureChange={onSignatureChange}
                    isGeneratingDraft={isGeneratingDraft}
                    onGenerateAIDraft={onGenerateAIDraft}
                    isUploading={isUploading}
                    onInputChange={onInputChange}
                    fileInputRef={fileInputRef}
                    onFileUpload={onFileUpload}
                    stagedAttachments={stagedAttachments}
                    selectedChannel={selectedChannel}
                    isSmsTooLong={isSmsTooLong}
                    plainTextLength={plainTextLength}
                    maxSmsLength={MAX_SMS_LENGTH}
                    onSend={onSend}
                    onOpenSchedule={onOpenSchedule}
                />
            </div>
        </div >
    );
});

/**
 * ChatHeader Component
 * Extracted from ChatWindow for better maintainability.
 * Displays conversation recipient info and action buttons.
 */

import { useState, useEffect, useCallback } from 'react';
import { ChevronDown, Clock, CheckCircle, RotateCcw, MoreHorizontal, MoreVertical, Search, Users, Merge, Ban, Eye } from 'lucide-react';
import { cn } from '../../utils/cn';
import { useClickOutside } from '../../hooks/useClickOutside';
import { MacrosDropdown } from './MacrosDropdown';
import { RecipientList, MergedRecipient } from './RecipientList';

interface Viewer {
    userId: string;
    name: string;
    avatarUrl?: string;
}

interface ChatHeaderProps {
    conversationId: string;
    recipientName?: string;
    recipientEmail?: string;
    status?: string;
    isUpdatingStatus: boolean;
    showSearch: boolean;
    onToggleSearch: () => void;
    onStatusChange: (status: string) => void;
    onShowSnooze: () => void;
    onShowAssign: () => void;
    onShowMerge: () => void;
    onBlock?: () => Promise<void>;
    /** Other users currently viewing this conversation */
    otherViewers?: Viewer[];
    /** Merged recipients from merged conversations */
    mergedRecipients?: MergedRecipient[];
    /** Primary channel of this conversation */
    primaryChannel?: string;
}

export function ChatHeader({
    conversationId,
    recipientName,
    recipientEmail,
    status,
    isUpdatingStatus,
    showSearch,
    onToggleSearch,
    onStatusChange,
    onShowSnooze,
    onShowAssign,
    onShowMerge,
    onBlock,
    otherViewers = [],
    mergedRecipients = [],
    primaryChannel = 'EMAIL'
}: ChatHeaderProps) {
    const [showActionsMenu, setShowActionsMenu] = useState(false);
    const [showMoreMenu, setShowMoreMenu] = useState(false);
    const [showBlockConfirm, setShowBlockConfirm] = useState(false);

    // Close dropdowns on outside click
    const actionsMenuRef = useClickOutside<HTMLDivElement>(
        useCallback(() => setShowActionsMenu(false), []),
        showActionsMenu
    );
    const moreMenuRef = useClickOutside<HTMLDivElement>(
        useCallback(() => setShowMoreMenu(false), []),
        showMoreMenu
    );

    // Close block-confirm modal on Escape key
    useEffect(() => {
        if (!showBlockConfirm) return;
        const handleKey = (e: KeyboardEvent) => {
            if (e.key === 'Escape') setShowBlockConfirm(false);
        };
        document.addEventListener('keydown', handleKey);
        return () => document.removeEventListener('keydown', handleKey);
    }, [showBlockConfirm]);

    const isOpen = status === 'OPEN';
    const hasOtherViewers = otherViewers.length > 0;

    return (
        <div className="flex items-center justify-between px-4 py-2 border-b border-gray-200 bg-white">
            {/* Left - Sender Info */}
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white text-xs font-medium">
                    {recipientName ? recipientName.charAt(0).toUpperCase() : 'C'}
                </div>
                <RecipientList
                    primaryEmail={recipientEmail}
                    primaryName={recipientName}
                    primaryChannel={primaryChannel}
                    mergedRecipients={mergedRecipients}
                />
            </div>

            {/* Center - Other Viewers Indicator */}
            {hasOtherViewers && (
                <div className="flex items-center gap-2 px-3 py-1 bg-amber-50 border border-amber-200 rounded-full">
                    <Eye size={14} className="text-amber-600" />
                    <div className="flex -space-x-2">
                        {otherViewers.slice(0, 3).map((viewer, i) => (
                            <div
                                key={viewer.userId}
                                className="w-6 h-6 rounded-full bg-amber-500 flex items-center justify-center text-white text-[10px] font-medium border-2 border-white"
                                title={viewer.name}
                            >
                                {viewer.avatarUrl ? (
                                    <img src={viewer.avatarUrl} alt={viewer.name} className="w-full h-full rounded-full object-cover" />
                                ) : (
                                    viewer.name.charAt(0).toUpperCase()
                                )}
                            </div>
                        ))}
                    </div>
                    <span className="text-xs font-medium text-amber-700">
                        {otherViewers.length === 1
                            ? `${otherViewers[0].name} is viewing`
                            : `${otherViewers.length} others viewing`
                        }
                    </span>
                </div>
            )}

            {/* Right - Actions */}
            <div className="flex items-center gap-2">
                {/* Macros Quick Actions */}
                <MacrosDropdown conversationId={conversationId} />

                {/* Resolve/Reopen Button with Dropdown */}
                <div className="relative" ref={actionsMenuRef}>
                    <div className="flex">
                        <button
                            onClick={() => onStatusChange(isOpen ? 'CLOSED' : 'OPEN')}
                            disabled={isUpdatingStatus}
                            aria-label={isOpen ? 'Resolve conversation' : 'Reopen conversation'}
                            className={cn(
                                "flex items-center gap-1.5 px-3 py-1.5 rounded-l-lg text-sm font-medium transition-colors",
                                isOpen
                                    ? "bg-green-600 text-white hover:bg-green-700"
                                    : "bg-blue-600 text-white hover:bg-blue-700",
                                isUpdatingStatus && "opacity-50 cursor-not-allowed"
                            )}
                        >
                            {isOpen ? <CheckCircle size={14} /> : <RotateCcw size={14} />}
                            {isUpdatingStatus ? '...' : (isOpen ? 'Resolve' : 'Reopen')}
                        </button>
                        <button
                            onClick={() => setShowActionsMenu(!showActionsMenu)}
                            aria-label="More status options"
                            className={cn(
                                "px-2 py-1.5 rounded-r-lg border-l transition-colors",
                                isOpen
                                    ? "bg-green-600 text-white hover:bg-green-700 border-green-700"
                                    : "bg-blue-600 text-white hover:bg-blue-700 border-blue-700"
                            )}
                        >
                            <ChevronDown size={14} />
                        </button>
                    </div>

                    {/* Dropdown Menu */}
                    {showActionsMenu && (
                        <div className="absolute right-0 top-full mt-1 w-48 bg-white border border-gray-200 rounded-lg shadow-lg z-20">
                            <button
                                onClick={() => {
                                    setShowActionsMenu(false);
                                    onShowSnooze();
                                }}
                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors"
                            >
                                <Clock size={14} />
                                Snooze
                            </button>
                            <button
                                onClick={() => {
                                    setShowActionsMenu(false);
                                    onStatusChange('PENDING');
                                }}
                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors"
                            >
                                <MoreHorizontal size={14} />
                                Mark as pending
                            </button>
                        </div>
                    )}
                </div>

                {/* Search Button */}
                <button
                    onClick={onToggleSearch}
                    aria-label="Search messages"
                    className={cn(
                        "p-1.5 rounded-sm transition-colors",
                        showSearch ? "bg-blue-100 text-blue-600" : "hover:bg-gray-100 text-gray-500"
                    )}
                    title="Search messages"
                >
                    <Search size={16} />
                </button>

                {/* More Options */}
                <div className="relative" ref={moreMenuRef}>
                    <button
                        onClick={() => setShowMoreMenu(!showMoreMenu)}
                        aria-label="More options"
                        className="p-1.5 rounded-sm hover:bg-gray-100 text-gray-500"
                    >
                        <MoreVertical size={16} />
                    </button>

                    {/* More Options Dropdown */}
                    {showMoreMenu && (
                        <div className="absolute right-0 top-full mt-1 w-56 bg-white border border-gray-200 rounded-lg shadow-lg z-20">
                            <button
                                onClick={() => {
                                    setShowMoreMenu(false);
                                    onShowAssign();
                                }}
                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors rounded-t-lg"
                            >
                                <Users size={14} />
                                Assign to team member
                            </button>
                            <button
                                onClick={() => {
                                    setShowMoreMenu(false);
                                    onShowMerge();
                                }}
                                className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors"
                            >
                                <Merge size={14} />
                                Merge with another conversation
                            </button>
                            {recipientEmail && onBlock && (
                                <button
                                    onClick={() => {
                                        setShowMoreMenu(false);
                                        setShowBlockConfirm(true);
                                    }}
                                    className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors rounded-b-lg border-t border-gray-100"
                                >
                                    <Ban size={14} />
                                    Block customer
                                </button>
                            )}
                        </div>
                    )}
                </div>
            </div>
            {/* Block Customer Confirmation Modal */}
            {showBlockConfirm && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
                    <div className="bg-white rounded-xl shadow-xl max-w-sm w-full mx-4 p-6 animate-in fade-in zoom-in-95 duration-150">
                        <div className="flex items-center gap-3 mb-3">
                            <div className="w-10 h-10 rounded-full bg-red-100 flex items-center justify-center">
                                <Ban size={20} className="text-red-600" />
                            </div>
                            <h3 className="text-lg font-semibold text-gray-900">Block Customer</h3>
                        </div>
                        <p className="text-sm text-gray-600 mb-5">
                            Block <span className="font-medium text-gray-900">{recipientEmail}</span>? Their future messages will be auto-resolved without notifications.
                        </p>
                        <div className="flex justify-end gap-2">
                            <button
                                onClick={() => setShowBlockConfirm(false)}
                                className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={async () => {
                                    setShowBlockConfirm(false);
                                    await onBlock?.();
                                }}
                                className="px-4 py-2 text-sm font-medium text-white bg-red-600 hover:bg-red-700 rounded-lg transition-colors"
                            >
                                Block
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect } from 'react';
import { useSocket } from '../../context/SocketContext';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useLocation, useNavigate } from 'react-router-dom';

/** Auto-dismiss timeout for notifications (10 minutes) */
const NOTIFICATION_AUTO_DISMISS_MS = 10 * 60 * 1000;

/**
 * Headless component to handle global chat notifications via browser API.
 * Filters notifications to only show for the user's currently active account.
 */
export function ChatNotifications() {
    const { socket } = useSocket();
    const { user } = useAuth();
    const { currentAccount } = useAccount();
    const location = useLocation();
    const navigate = useNavigate();

    // Check permission on mount
    useEffect(() => {
        if ('Notification' in window && Notification.permission === 'default') {
            Notification.requestPermission();
        }
    }, []);

    useEffect(() => {
        if (!socket) return;

        const handleNewMessage = (msg: any) => {
            // CRITICAL: Account Isolation - only show notifications for current account
            // Prevents cross-account notification leakage for multi-account users
            if (msg.accountId && currentAccount?.id && msg.accountId !== currentAccount.id) {
                return;
            }

            const isCustomerMessage = msg.type === 'CUSTOMER' || msg.senderType === 'CUSTOMER';
            const isAssignedToMe = !msg.assignedTo || msg.assignedTo === user?.id;

            if (isCustomerMessage && isAssignedToMe) {
                // If we are currently ON the inbox page AND looking at this specific conversation, maybe don't notify?
                // Or simply always notify if window is blurred? 
                // Let's rely on standard browser behavior (sometimes they mute notification if focused).
                // But generally users like a 'ding' even if open.

                // However, if we are active on that specific chat, it might be annoying.
                // InboxPage route is usually /inbox. 
                const isOnInbox = location.pathname.startsWith('/inbox');
                // We don't easily know the "active" conversation ID here without accessing InboxPage state.
                // But generally, a notification is safe.

                if (Notification.permission === 'granted') {
                    const n = new Notification('New Message', {
                        body: msg.content || 'You have a new message',
                        icon: '/favicon.ico',
                        tag: `conversation-${msg.conversationId}`
                    });

                    // Auto-dismiss after 10 minutes
                    setTimeout(() => n.close(), NOTIFICATION_AUTO_DISMISS_MS);

                    n.onclick = function () {
                        window.focus();
                        n.close();
                    };
                }
            }
        };

        /**
         * Handle snooze expiry notifications.
         * When a snoozed conversation reopens, notify the assigned agent.
         */
        const handleSnoozeExpired = (data: {
            conversationId: string;
            assignedToId?: string;
            customerName?: string;
            accountId?: string;
        }) => {
            // Account isolation check
            if (data.accountId && currentAccount?.id && data.accountId !== currentAccount.id) {
                return;
            }

            // Only notify if assigned to current user
            if (data.assignedToId && data.assignedToId !== user?.id) {
                return;
            }

            if (Notification.permission === 'granted') {
                const customerName = data.customerName || 'Customer';
                const n = new Notification('⏰ Snooze Ended', {
                    body: `Conversation with ${customerName} has reopened`,
                    icon: '/favicon.ico',
                    tag: `snooze-${data.conversationId}`,
                });

                // Auto-dismiss after 10 minutes
                setTimeout(() => n.close(), NOTIFICATION_AUTO_DISMISS_MS);

                n.onclick = function () {
                    window.focus();
                    navigate(`/inbox?conversationId=${data.conversationId}`);
                    n.close();
                };
            }
        };

        socket.on('message:new', handleNewMessage);
        socket.on('snooze:expired', handleSnoozeExpired);

        return () => {
            socket.off('message:new', handleNewMessage);
            socket.off('snooze:expired', handleSnoozeExpired);
        };
    }, [socket, location.pathname, user, navigate, currentAccount?.id]);

    return null; // Headless
}

/**
 * ChatWindow - Orchestration component for chat conversations.
 * Delegates compose, typing, and send logic to extracted hooks and components.
 * Memoized to prevent re-renders from parent state changes (e.g. conversation list updates).
 */
import { useState, useEffect, useRef, useMemo, useCallback, memo } from 'react';
import DOMPurify from 'dompurify';
import { Logger } from '../../utils/logger';
import { Loader2 } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

// Extracted hooks (canned + email accounts are passed in as props from InboxPage)
import { useTypingIndicator } from '../../hooks/useTypingIndicator';
import { useMessageSend } from '../../hooks/useMessageSend';
import { useConversationPresence } from '../../hooks/useConversationPresence';
import { useAttachments } from '../../hooks/useAttachments';
import { useAIDraft } from '../../hooks/useAIDraft';
import type { CannedResponse, CustomerContext } from '../../hooks/useCannedResponses';

// Sub-components
import { MessageBubble } from './MessageBubble';
import { TypingIndicator } from './TypingIndicator';
import { ChatHeader } from './ChatHeader';
import { ChatSearchBar } from './ChatSearchBar';
import { ChatComposer } from './ChatComposer';
import { ChatModals } from './ChatModals';
import { ConversationChannel } from './ChannelSelector';

interface Message {
    id: string;
    content: string;
    senderType: 'AGENT' | 'CUSTOMER' | 'SYSTEM';
    createdAt: string;
    isInternal: boolean;
    senderId?: string;
    readAt?: string | null;
    status?: 'SENT' | 'DELIVERED' | 'READ' | 'FAILED';
    reactions?: Record<string, Array<{ userId: string; userName: string | null }>>;
}

interface ChannelOption {
    channel: ConversationChannel;
    identifier: string;
    available: boolean;
}

import type { MergedRecipient } from './RecipientList';

interface CustomerData {
    firstName?: string;
    lastName?: string;
    email?: string;
    ordersCount?: number;
    totalSpent?: number;
    wooId?: number;
}

interface ChatWindowProps {
    conversationId: string;
    messages: Message[];
    onSendMessage: (content: string, type: 'AGENT' | 'SYSTEM', isInternal: boolean, channel?: ConversationChannel, emailAccountId?: string) => Promise<void>;
    recipientEmail?: string;
    recipientName?: string;
    status?: string;
    onStatusChange?: (newStatus: string, snoozeUntil?: Date) => Promise<void>;
    onAssign?: (userId: string) => Promise<void>;
    onMerge?: (targetConversationId: string) => Promise<void>;
    onBlock?: () => Promise<void>;
    assigneeId?: string;
    availableChannels?: ChannelOption[];
    currentChannel?: ConversationChannel;
    mergedRecipients?: MergedRecipient[];
    customerData?: CustomerData;
    // Lifted from hooks — passed in from InboxPage to avoid re-fetching per switch
    cannedResponses: CannedResponse[];
    filteredCanned: CannedResponse[];
    showCanned: boolean;
    setShowCanned: (show: boolean) => void;
    showCannedManager: boolean;
    setShowCannedManager: (show: boolean) => void;
    handleInputForCanned: (input: string) => void;
    selectCanned: (response: CannedResponse, context?: CustomerContext) => string;
    refetchCanned: () => Promise<void>;
    emailAccounts: Array<{ id: string; name: string; email: string; isDefault?: boolean }>;
    selectedEmailAccountId: string;
    onEmailAccountChange: (id: string) => void;
}

export const ChatWindow = memo(function ChatWindow({
    conversationId,
    messages,
    onSendMessage,
    recipientEmail,
    recipientName,
    status,
    onStatusChange,
    onAssign,
    onMerge,
    onBlock,
    assigneeId,
    availableChannels,
    currentChannel,
    mergedRecipients = [],
    customerData,
    // Canned responses (lifted from hook)
    cannedResponses,
    filteredCanned,
    showCanned,
    setShowCanned,
    showCannedManager,
    setShowCannedManager,
    handleInputForCanned,
    selectCanned,
    refetchCanned,
    // Email accounts (lifted from hook)
    emailAccounts,
    selectedEmailAccountId,
    onEmailAccountChange
}: ChatWindowProps) {
    const bottomRef = useRef<HTMLDivElement>(null);
    const { user } = useAuth();

    // === HOOKS (only per-conversation ones remain here) ===
    const attachments = useAttachments({
        conversationId,
        onSendMessage
    });

    const messageSend = useMessageSend({
        conversationId,
        onSendMessage: attachments.sendMessageWithAttachments,
        recipientEmail,
        isLiveChat: currentChannel === 'CHAT',
        emailAccountId: selectedEmailAccountId
    });

    const { isCustomerTyping } = useTypingIndicator({ conversationId, input: messageSend.input });
    const { otherViewers } = useConversationPresence(conversationId);

    const aiDraft = useAIDraft({
        conversationId,
        currentInput: messageSend.input,
        onDraftGenerated: messageSend.setInput
    });

    // === LOCAL STATE ===
    const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

    // Modal states
    const [showSnoozeModal, setShowSnoozeModal] = useState(false);
    const [showAssignModal, setShowAssignModal] = useState(false);
    const [showMergeModal, setShowMergeModal] = useState(false);
    const [showScheduleModal, setShowScheduleModal] = useState(false);

    // Search state
    const [showSearch, setShowSearch] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');

    // Lightbox state
    const [lightboxImage, setLightboxImage] = useState<string | null>(null);

    // Reset search when changing conversations
    useEffect(() => {
        setShowSearch(false);
        setSearchQuery('');
    }, [conversationId]);

    // Track previous conversationId to distinguish switch vs new message
    const prevConversationIdRef = useRef(conversationId);

    // Scroll to bottom — instant on switch, smooth for new messages
    useEffect(() => {
        const isSwitching = prevConversationIdRef.current !== conversationId;
        prevConversationIdRef.current = conversationId;
        bottomRef.current?.scrollIntoView({ behavior: isSwitching ? 'instant' : 'smooth' });
    }, [messages, conversationId]);

    // Detect '/' trigger for canned responses
    useEffect(() => {
        handleInputForCanned(messageSend.input);
    }, [messageSend.input, handleInputForCanned]);

    // === FILTERED MESSAGES FOR SEARCH ===
    const filteredMessages = useMemo(() => {
        if (!searchQuery.trim()) return messages;
        const query = searchQuery.toLowerCase();
        return messages.filter(msg => msg.content.toLowerCase().includes(query));
    }, [messages, searchQuery]);

    // NOTE: Reaction toggle API is not yet implemented.
    // When ready, add a callback here and pass it to MessageBubble via onReactionToggle.

    // === STATUS CHANGE ===
    const handleStatusChange = async (newStatus: string) => {
        if (!onStatusChange || isUpdatingStatus) return;
        setIsUpdatingStatus(true);
        try {
            await onStatusChange(newStatus);
        } finally {
            setIsUpdatingStatus(false);
        }
    };

    return (
        <div className="flex flex-col h-full bg-white relative">
            {/* Header Bar with Actions */}
            <ChatHeader
                conversationId={conversationId}
                recipientName={recipientName}
                recipientEmail={recipientEmail}
                status={status}
                isUpdatingStatus={isUpdatingStatus}
                showSearch={showSearch}
                onToggleSearch={() => setShowSearch(!showSearch)}
                onStatusChange={handleStatusChange}
                onShowSnooze={() => setShowSnoozeModal(true)}
                onShowAssign={() => setShowAssignModal(true)}
                onShowMerge={() => setShowMergeModal(true)}
                onBlock={onBlock}
                otherViewers={otherViewers}
                mergedRecipients={mergedRecipients}
                primaryChannel={currentChannel}
            />

            {/* Search Bar */}
            {showSearch && (
                <ChatSearchBar
                    searchQuery={searchQuery}
                    onSearchChange={setSearchQuery}
                    onClose={() => {
                        setShowSearch(false);
                        setSearchQuery('');
                    }}
                    matchCount={filteredMessages.length}
                    totalCount={messages.length}
                />
            )}

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-gray-100">
                {filteredMessages.map((msg) => (
                    <MessageBubble
                        key={msg.id}
                        message={msg}
                        recipientName={recipientName}
                        recipientEmail={recipientEmail}
                        onImageClick={(src) => setLightboxImage(src)}
                        onQuoteReply={(msg) => messageSend.setQuotedMessage(msg)}
                    />
                ))}

                {/* Typing Indicator */}
                {isCustomerTyping && <TypingIndicator name={recipientName} />}

                {/* Pending Message Bubble with Undo */}
                {messageSend.pendingSend && (
                    <div className="mb-3 flex justify-end">
                        <div className="flex gap-2 max-w-[85%] flex-row-reverse">
                            {/* Avatar placeholder */}
                            <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center self-end">
                                <Loader2 size={16} className="animate-spin text-blue-600" />
                            </div>
                            {/* Pending bubble */}
                            <div className="flex flex-col">
                                <div className="rounded-2xl px-4 py-2.5 relative shadow-sm bg-blue-600/70 text-white rounded-br-md border-2 border-dashed border-blue-400">
                                    <div
                                        className="text-sm leading-relaxed opacity-90"
                                        dangerouslySetInnerHTML={{
                                            __html: DOMPurify.sanitize(messageSend.pendingSend.content, {
                                                ALLOWED_TAGS: ['b', 'i', 'strong', 'em', 'p', 'br', 'a', 'span', 'div', 'img'],
                                                ALLOWED_ATTR: ['href', 'target', 'rel', 'src', 'alt', 'class', 'style']
                                            })
                                        }}
                                    />
                                    <div className="flex items-center justify-between mt-2 pt-2 border-t border-blue-400/40">
                                        <span className="text-xs text-blue-200">
                                            Sending in {messageSend.pendingSend.remainingSeconds}s...
                                        </span>
                                        <button
                                            onClick={messageSend.cancelPendingSend}
                                            className="text-sm font-semibold text-white bg-white/20 hover:bg-white/30 px-3 py-1 rounded-full transition-colors"
                                        >
                                            Undo
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                <div ref={bottomRef} />
            </div>

            {/* Reply Composer */}
            <ChatComposer
                conversationId={conversationId}
                recipientEmail={recipientEmail}
                recipientName={recipientName}
                input={messageSend.input}
                onInputChange={messageSend.setInput}
                isInternal={messageSend.isInternal}
                onInternalChange={messageSend.setIsInternal}
                isSending={messageSend.isSending}
                onSend={messageSend.handleSend}
                pendingSend={messageSend.pendingSend}
                onCancelSend={messageSend.cancelPendingSend}
                UNDO_DELAY_MS={messageSend.UNDO_DELAY_MS}
                signatureEnabled={messageSend.signatureEnabled}
                onSignatureChange={messageSend.setSignatureEnabled}
                quotedMessage={messageSend.quotedMessage}
                onClearQuote={() => messageSend.setQuotedMessage(null)}
                showCanned={showCanned}
                filteredCanned={filteredCanned}
                cannedResponses={cannedResponses}
                onSelectCanned={(r) => {
                    const context = {
                        firstName: customerData?.firstName,
                        lastName: customerData?.lastName,
                        email: customerData?.email || recipientEmail,
                        ordersCount: customerData?.ordersCount,
                        totalSpent: customerData?.totalSpent,
                        wooCustomerId: customerData?.wooId,
                        agentFirstName: user?.fullName?.split(' ')[0],
                        agentFullName: user?.fullName || undefined
                    };
                    messageSend.setInput(selectCanned(r, context));
                }}
                onOpenCannedManager={() => setShowCannedManager(true)}
                isGeneratingDraft={aiDraft.isGeneratingDraft}
                onGenerateAIDraft={aiDraft.handleGenerateAIDraft}
                isUploading={attachments.isUploading}
                uploadProgress={attachments.uploadProgress}
                onFileUpload={attachments.handleFileUpload}
                fileInputRef={attachments.fileInputRef}
                stagedAttachments={attachments.stagedAttachments}
                onRemoveAttachment={attachments.handleRemoveAttachment}
                attachmentError={attachments.attachmentError}
                onOpenSchedule={() => setShowScheduleModal(true)}
                availableChannels={availableChannels}
                currentChannel={currentChannel}
                emailAccounts={emailAccounts}
                selectedEmailAccountId={selectedEmailAccountId}
                onEmailAccountChange={onEmailAccountChange}
            />

            {/* All Modals */}
            <ChatModals
                conversationId={conversationId}
                assigneeId={assigneeId}
                showCannedManager={showCannedManager}
                onCloseCannedManager={() => setShowCannedManager(false)}
                onCannedUpdate={refetchCanned}
                showSnoozeModal={showSnoozeModal}
                onCloseSnooze={() => setShowSnoozeModal(false)}
                onSnooze={async (snoozeUntil) => {
                    if (onStatusChange) {
                        await onStatusChange('SNOOZED', snoozeUntil);
                    }
                }}
                showAssignModal={showAssignModal}
                onCloseAssign={() => setShowAssignModal(false)}
                onAssign={onAssign}
                showMergeModal={showMergeModal}
                onCloseMerge={() => setShowMergeModal(false)}
                onMerge={onMerge}
                lightboxImage={lightboxImage}
                onCloseLightbox={() => setLightboxImage(null)}
                showScheduleModal={showScheduleModal}
                onCloseSchedule={() => setShowScheduleModal(false)}
                onSchedule={messageSend.handleScheduleMessage}
                isScheduling={messageSend.isScheduling}
            />
        </div>
    );
});

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import {
    User, Mail,
    MoreVertical,
    ChevronDown, ChevronRight,
    ShoppingBag, Package, ExternalLink
} from 'lucide-react';
import { cn } from '../../utils/cn';
import { format } from 'date-fns';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { NotesSection } from './NotesSection';
import { OrdersSection } from './OrdersSection';
import { PreviousConversationsSection } from './PreviousConversationsSection';



interface Order {
    id: string;
    wooId: number;
    number: string;
    status: string;
    total: number;
    currency: string;
    dateCreated: string;
}

interface ContactPanelProps {
    conversation?: {
        id: string;
        status: string;
        priority?: string;
        createdAt: string;
        updatedAt: string;
        snoozedUntil?: string | null;
        wooCustomer?: {
            id: string;
            wooId: number;
            firstName?: string;
            lastName?: string;
            email?: string;
            totalSpent?: number;
            ordersCount?: number;
        };
        guestEmail?: string;
        guestName?: string;
        assignee?: {
            id: string;
            fullName?: string;
            avatarUrl?: string;
        };
        _count?: {
            messages: number;
        };
    };
    onSelectConversation?: (conversationId: string) => void;
}

interface SectionProps {
    title: string;
    defaultOpen?: boolean;
    children: React.ReactNode;
}

function Section({ title, defaultOpen = true, children }: SectionProps) {
    const [isOpen, setIsOpen] = useState(defaultOpen);

    return (
        <div className="border-b border-gray-100">
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="w-full flex items-center justify-between px-4 py-3 hover:bg-gray-50 transition-colors"
            >
                <span className="text-xs font-semibold text-gray-500 uppercase tracking-wide">{title}</span>
                {isOpen ? <ChevronDown size={14} className="text-gray-400" /> : <ChevronRight size={14} className="text-gray-400" />}
            </button>
            {isOpen && (
                <div className="px-4 pb-4">
                    {children}
                </div>
            )}
        </div>
    );
}

interface PreviousConversation {
    id: string;
    status: string;
    updatedAt: string;
    channel: string;
    messages?: { content: string }[];
}

export function ContactPanel({ conversation, onSelectConversation }: ContactPanelProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [recentOrders, setRecentOrders] = useState<Order[]>([]);
    const [previousConversations, setPreviousConversations] = useState<PreviousConversation[]>([]);
    const [isLoadingOrders, setIsLoadingOrders] = useState(false);

    const customer = conversation?.wooCustomer;


    // Fetch recent orders when customer changes or for guest emails
    useEffect(() => {
        const controller = new AbortController();
        if (customer?.wooId && token && currentAccount?.id) {
            fetchCustomerOrders(customer.wooId, controller.signal);
        } else if (conversation?.guestEmail && token && currentAccount?.id) {
            fetchOrdersByEmail(conversation.guestEmail, controller.signal);
        } else {
            setRecentOrders([]);
            setPreviousConversations([]);
        }
        return () => controller.abort();
    }, [customer?.wooId, conversation?.guestEmail, token, currentAccount?.id]);

    const fetchCustomerOrders = async (wooCustomerId: number, signal?: AbortSignal) => {
        setIsLoadingOrders(true);
        try {
            const headers = {
                'Authorization': `Bearer ${token}`,
                'x-account-id': currentAccount?.id || '',
            };

            // Fetch orders and conversations in parallel
            const [ordersRes, convsRes] = await Promise.all([
                fetch(`/api/orders?customerId=${wooCustomerId}&limit=5`, { headers, signal }),
                fetch(`/api/chat/conversations?wooCustomerId=${wooCustomerId}`, { headers, signal })
            ]);

            if (ordersRes.ok) {
                const ordersData = await ordersRes.json();
                setRecentOrders(ordersData.orders || []);
            }

            if (convsRes.ok) {
                const convsData = await convsRes.json();
                const otherConvs = Array.isArray(convsData)
                    ? convsData.filter((c: PreviousConversation) => c.id !== conversation?.id)
                    : [];
                setPreviousConversations(otherConvs);
            }
        } catch (error: any) {
            if (error.name === 'AbortError') return;
            Logger.error('Failed to fetch customer data:', { error: error });
        } finally {
            setIsLoadingOrders(false);
        }
    };

    const fetchOrdersByEmail = async (email: string, signal?: AbortSignal) => {
        setIsLoadingOrders(true);
        try {
            const ordersRes = await fetch(`/api/orders?billingEmail=${encodeURIComponent(email)}&limit=5`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || '',
                },
                signal,
            });
            if (ordersRes.ok) {
                const ordersData = await ordersRes.json();
                setRecentOrders(ordersData.orders || []);
            }
        } catch (error: any) {
            if (error.name === 'AbortError') return;
            Logger.error('Failed to fetch orders by email:', { error: error });
        } finally {
            setIsLoadingOrders(false);
        }
    };

    const getOrderStatusColor = (status: string) => {
        switch (status.toLowerCase()) {
            case 'completed': return 'bg-green-100 text-green-700';
            case 'processing': return 'bg-blue-100 text-blue-700';
            case 'on-hold': return 'bg-yellow-100 text-yellow-700';
            case 'cancelled':
            case 'refunded': return 'bg-red-100 text-red-700';
            default: return 'bg-gray-100 text-gray-700';
        }
    };

    if (!conversation) return null;

    const name = customer
        ? `${customer.firstName || ''} ${customer.lastName || ''}`.trim() || customer.email || 'Anonymous'
        : conversation.guestName || conversation.guestEmail || 'Anonymous';
    const email = customer?.email || conversation.guestEmail;
    const initials = (name || 'A').split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '?';

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'OPEN': return 'bg-green-100 text-green-700';
            case 'CLOSED': return 'bg-gray-100 text-gray-700';
            case 'SNOOZED': return 'bg-yellow-100 text-yellow-700';
            default: return 'bg-gray-100 text-gray-700';
        }
    };

    const getPriorityColor = (priority?: string) => {
        switch (priority) {
            case 'HIGH': return 'text-red-600';
            case 'MEDIUM': return 'text-yellow-600';
            case 'LOW': return 'text-green-600';
            default: return 'text-gray-500';
        }
    };

    return (
        <div className="w-80 border-l border-gray-200 bg-white hidden lg:flex flex-col overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100">
                <span className="text-sm font-medium text-gray-700">Contact</span>
                <button className="p-1 rounded-sm hover:bg-gray-100 text-gray-400">
                    <MoreVertical size={16} />
                </button>
            </div>

            {/* Contact Card */}
            <div className="p-4 border-b border-gray-100">
                <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-full bg-blue-600 flex items-center justify-center text-white font-medium">
                        {initials}
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="font-semibold text-gray-900 truncate">{name}</h3>
                        {email && (
                            <a href={`mailto:${email}`} className="text-sm text-blue-600 hover:underline flex items-center gap-1 truncate">
                                <Mail size={12} />
                                {email}
                            </a>
                        )}
                    </div>
                </div>

                {/* Quick Stats for WooCustomer */}
                {customer && (
                    <div className="grid grid-cols-3 gap-2 mt-4">
                        <div className="bg-gray-50 rounded-lg p-2 text-center">
                            <div className="text-lg font-semibold text-gray-900">{customer.ordersCount || 0}</div>
                            <div className="text-xs text-gray-500">Orders</div>
                        </div>
                        <div className="bg-gray-50 rounded-lg p-2 text-center">
                            <div className="text-lg font-semibold text-gray-900">
                                ${(customer.totalSpent || 0).toLocaleString()}
                            </div>
                            <div className="text-xs text-gray-500">Spent</div>
                        </div>
                        <div className="bg-gray-50 rounded-lg p-2 text-center">
                            <div className="text-lg font-semibold text-gray-900">{previousConversations.length + 1}</div>
                            <div className="text-xs text-gray-500">Convos</div>
                        </div>
                    </div>
                )}

                {/* Not a customer indicator */}
                {!customer && (
                    <div className="mt-3 text-xs text-gray-500 flex items-center gap-1">
                        <User size={12} />
                        Not linked to a customer
                    </div>
                )}
            </div>


            {/* Scrollable Sections */}
            <div className="flex-1 overflow-y-auto">

                {/* Order History - show for linked customers OR guests with orders */}
                {(customer || (conversation?.guestEmail && recentOrders.length > 0) || isLoadingOrders) && (
                    <Section title={customer ? "Recent Orders" : "Orders by Email"} defaultOpen={true}>
                        <OrdersSection
                            orders={recentOrders}
                            isLoading={isLoadingOrders}
                            customerId={customer?.id}
                            ordersCount={customer?.ordersCount}
                        />
                    </Section>
                )}


                {/* Conversation Info */}
                <Section title="Conversation Information" defaultOpen={true}>
                    <div className="space-y-3 text-sm">
                        <div className="flex justify-between">
                            <span className="text-gray-500">Status</span>
                            <span className={cn("px-2 py-0.5 rounded-sm text-xs font-medium", getStatusColor(conversation.status))}>
                                {conversation.status}
                            </span>
                        </div>
                        {conversation.status === 'SNOOZED' && conversation.snoozedUntil && (
                            <div className="flex justify-between">
                                <span className="text-gray-500">Snooze until</span>
                                <span className="text-yellow-600 text-xs">
                                    {format(new Date(conversation.snoozedUntil), 'MMM d, h:mm a')}
                                </span>
                            </div>
                        )}
                        <div className="flex justify-between">
                            <span className="text-gray-500">Priority</span>
                            <span className={cn("font-medium", getPriorityColor(conversation.priority))}>
                                {conversation.priority || 'Normal'}
                            </span>
                        </div>
                        <div className="flex justify-between">
                            <span className="text-gray-500">Assignee</span>
                            <span className="text-gray-900">
                                {conversation.assignee?.fullName || 'Unassigned'}
                            </span>
                        </div>
                        <div className="flex justify-between">
                            <span className="text-gray-500">Messages</span>
                            <span className="text-gray-900">{conversation._count?.messages || 0}</span>
                        </div>
                        <div className="flex justify-between">
                            <span className="text-gray-500">Created</span>
                            <span className="text-gray-900 text-xs">
                                {format(new Date(conversation.createdAt), 'MMM d, yyyy')}
                            </span>
                        </div>
                    </div>
                </Section>

                {/* Auto-reopen notice */}
                <div className="px-4 py-3 bg-blue-50 text-xs text-blue-700">
                    <strong>Note:</strong> Resolved conversations will automatically reopen when the customer replies.
                </div>

                {/* Contact Attributes for WooCustomer */}
                {customer && (
                    <Section title="Contact Attributes" defaultOpen={false}>
                        <div className="space-y-2 text-sm">
                            <div className="flex justify-between">
                                <span className="text-gray-500">Customer ID</span>
                                <span className="text-gray-900 font-mono text-xs">{customer.id?.slice(0, 8) || 'N/A'}...</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-gray-500">WooCommerce ID</span>
                                <span className="text-gray-900 font-mono text-xs">{customer.wooId}</span>
                            </div>
                        </div>
                    </Section>
                )}

                {/* Contact Notes */}
                <Section title="Notes" defaultOpen={true}>
                    <NotesSection conversationId={conversation.id} />
                </Section>

                {/* Previous Conversations */}
                <Section title="Previous Conversations" defaultOpen={false}>
                    <PreviousConversationsSection
                        conversations={previousConversations}
                        onSelectConversation={onSelectConversation}
                    />
                </Section>
            </div>
        </div>
    );
}

import { formatDistanceToNow } from 'date-fns';
import { Virtuoso } from 'react-virtuoso';
import { Logger } from '../../utils/logger';
import { Filter, ChevronDown, Eye, EyeOff, Plus, Search, X, Loader2, Tag, Square, CheckSquare } from 'lucide-react';
import { cn } from '../../utils/cn';
import { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { useDrafts } from '../../hooks/useDrafts';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useClickOutside } from '../../hooks/useClickOutside';
import { BulkActionToolbar } from './BulkActionToolbar';
import { ConversationItem, type Conversation } from './ConversationItem';


interface Label {
    id: string;
    name: string;
    color: string;
    _count?: { conversations: number };
}

interface ConversationListProps {
    conversations: Conversation[];
    selectedId: string | null;
    onSelect: (id: string) => void;
    onPreload?: (id: string) => void;
    currentUserId?: string;
    onCompose?: () => void;
    onRefresh?: () => void;
    users?: { id: string; fullName: string }[];
    // Pagination props
    hasMore?: boolean;
    isLoadingMore?: boolean;
    onLoadMore?: () => void;
}

type FilterType = 'all' | 'mine' | 'unassigned';

export function ConversationList({ conversations, selectedId, onSelect, onPreload, currentUserId, onCompose, onRefresh, users = [], hasMore = false, isLoadingMore = false, onLoadMore }: ConversationListProps) {
    const [filter, setFilter] = useState<FilterType>('all');
    const [showFilterMenu, setShowFilterMenu] = useState(false);
    const [showResolved, setShowResolved] = useState(false);
    const { hasDraft } = useDrafts();
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    // Bulk Selection
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isSelectionMode, setIsSelectionMode] = useState(false);

    // Label filter
    const [allLabels, setAllLabels] = useState<Label[]>([]);
    const [selectedLabelId, setSelectedLabelId] = useState<string | null>(null);
    const [showLabelFilter, setShowLabelFilter] = useState(false);

    // Close dropdowns on outside click
    const labelFilterRef = useClickOutside<HTMLDivElement>(
        useCallback(() => setShowLabelFilter(false), []),
        showLabelFilter
    );
    const filterMenuRef = useClickOutside<HTMLDivElement>(
        useCallback(() => setShowFilterMenu(false), []),
        showFilterMenu
    );

    // Search state
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResults, setSearchResults] = useState<Conversation[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const isSearchMode = searchQuery.trim().length >= 2;

    // Fetch available labels
    useEffect(() => {
        if (!token || !currentAccount) return;
        fetch('/api/labels', {
            headers: {
                'Authorization': `Bearer ${token}`,
                'x-account-id': currentAccount.id
            }
        })
            .then(res => res.json())
            .then(data => setAllLabels(data.labels || []))
            .catch(e => Logger.error('Failed to fetch labels', { error: e }));
    }, [token, currentAccount]);

    // Clear selection when conversations change
    useEffect(() => {
        setSelectedIds(new Set());
        setIsSelectionMode(false);
    }, [conversations]);

    const toggleSelection = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSelected = new Set(selectedIds);
        if (newSelected.has(id)) {
            newSelected.delete(id);
        } else {
            newSelected.add(id);
        }
        setSelectedIds(newSelected);
        setIsSelectionMode(newSelected.size > 0);
    };

    const toggleSelectAll = () => {
        if (selectedIds.size === filteredConversations.length) {
            setSelectedIds(new Set());
            setIsSelectionMode(false);
        } else {
            setSelectedIds(new Set(filteredConversations.map(c => c.id)));
            setIsSelectionMode(true);
        }
    };

    // Debounced search
    useEffect(() => {
        if (!isSearchMode || !token || !currentAccount) {
            setSearchResults([]);
            return;
        }

        const timeout = setTimeout(async () => {
            setIsSearching(true);
            try {
                const res = await fetch(`/api/chat/conversations/search?q=${encodeURIComponent(searchQuery)}`, {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const data = await res.json();
                    setSearchResults(data.results || []);
                }
            } catch (e) {
                Logger.error('Search failed', { error: e });
            } finally {
                setIsSearching(false);
            }
        }, 300);

        return () => clearTimeout(timeout);
    }, [searchQuery, token, currentAccount, isSearchMode]);

    // Memoized: Use search results when searching, otherwise normal filtered list
    const filteredConversations = useMemo(() => {
        if (isSearchMode) return searchResults;

        return conversations.filter(conv => {
            // Status filter: only show OPEN by default
            if (!showResolved && conv.status !== 'OPEN') return false;

            // Label filter
            if (selectedLabelId) {
                if (!conv.labels?.some(l => l.id === selectedLabelId)) return false;
            }

            // Assignment filter
            if (filter === 'mine') return conv.assignedTo === currentUserId;
            if (filter === 'unassigned') return !conv.assignedTo;
            return true;
        });
    }, [isSearchMode, searchResults, conversations, showResolved, selectedLabelId, filter, currentUserId]);

    // Precompute which conversations have drafts — avoids per-item localStorage reads
    const draftIds = useMemo(() => {
        const ids = new Set<string>();
        for (const c of filteredConversations) {
            if (hasDraft(c.id)) ids.add(c.id);
        }
        return ids;
    }, [filteredConversations, hasDraft]);

    // Memoized counts - only recalculates when conversations or filters change
    const counts = useMemo(() => {
        const getFilteredCount = (filterFn: (c: Conversation) => boolean) => {
            return conversations.filter(c => {
                if (!showResolved && c.status !== 'OPEN') return false;
                return filterFn(c);
            }).length;
        };

        return {
            all: getFilteredCount(() => true),
            mine: getFilteredCount(c => c.assignedTo === currentUserId),
            unassigned: getFilteredCount(c => !c.assignedTo)
        };
    }, [conversations, showResolved, currentUserId]);

    const getDisplayName = useCallback((conv: Conversation) => {
        if (conv.wooCustomer) {
            const name = `${conv.wooCustomer.firstName || ''} ${conv.wooCustomer.lastName || ''}`.trim();
            return name || conv.wooCustomer.email || 'Customer';
        }
        // For guests: prefer name, fall back to email address, last resort is generic text
        return conv.guestName || conv.guestEmail || 'Unknown Contact';
    }, []);

    const getInitials = useCallback((name: string) => {
        return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '?';
    }, []);

    /**
     * Gets the timestamp of the last CUSTOMER message for display.
     * Falls back to last message or updatedAt if no customer message found.
     */
    const getLastCustomerMessageTime = useCallback((conv: Conversation): string => {
        const lastCustomerMsg = conv.messages.find(m => m.senderType === 'CUSTOMER');
        return lastCustomerMsg?.createdAt || conv.messages[0]?.createdAt || conv.updatedAt;
    }, []);

    /** Detects whether message content contains attachment links. */
    const hasAttachments = useCallback((content: string): boolean => {
        return /\[Attachment:/.test(content) || /\[[^\]]+\]\(\/uploads\/attachments\//.test(content);
    }, []);

    const getPreview = useCallback((conv: Conversation) => {
        const lastMsg = conv.messages[0];
        if (!lastMsg) return { subject: conv.title || null, preview: 'No messages', showPaperclip: false };

        let content = lastMsg.content;
        const showPaperclip = hasAttachments(content);
        // Use stored conversation title if available, otherwise extract from message
        let subject: string | null = conv.title || null;

        // Extract subject from message content if not using stored title
        if (!subject && content.startsWith('Subject:')) {
            const lines = content.split('\n');
            subject = lines[0].replace('Subject:', '').trim();
            content = lines.length > 2 ? lines.slice(2).join(' ') : '';
        } else if (content.startsWith('Subject:')) {
            // Still strip Subject: prefix from content for preview
            const lines = content.split('\n');
            content = lines.length > 2 ? lines.slice(2).join(' ') : '';
        }

        // Strip attachment markdown links and headers before preview
        content = content.replace(/\[Attachment:\s*[^\]]*\]\([^)]*\)/gi, '');
        content = content.replace(/\[[^\]]+\]\(\/uploads\/[^)]+\)/gi, '');
        content = content.replace(/\*\*Attachments:\*\*\s*/gi, '');

        // Strip HTML tags, then decode common entities
        let preview = content
            .replace(/<[^>]*>/g, '')
            .replace(/&nbsp;/g, ' ')
            .replace(/&amp;/g, '&')
            .replace(/&lt;/g, '<')
            .replace(/&gt;/g, '>')
            .replace(/\s+/g, ' ')
            .trim()
            .slice(0, 80);
        return { subject, preview, showPaperclip };
    }, [hasAttachments]);

    return (
        <div className="flex flex-col h-full bg-white border-r border-gray-200 w-80">
            {/* Header with Filters */}
            <div className="p-3 border-b border-gray-100">
                <div className="flex items-center justify-between mb-3">
                    <h2 className="font-semibold text-gray-800 text-lg">Conversations</h2>
                    <div className="flex items-center gap-1">{onCompose && (
                        <button
                            onClick={onCompose}
                            className="p-1.5 rounded-md bg-blue-600 text-white hover:bg-blue-700 transition-colors"
                            title="Compose new email"
                        >
                            <Plus size={16} />
                        </button>
                    )}
                        {/* Label Filter */}
                        <div className="relative" ref={labelFilterRef}>
                            <button
                                onClick={() => setShowLabelFilter(!showLabelFilter)}
                                className={cn(
                                    "p-1.5 rounded-sm hover:bg-gray-100",
                                    selectedLabelId ? "text-indigo-600 bg-indigo-50" : "text-gray-500"
                                )}
                                title="Filter by label"
                            >
                                <Tag size={16} />
                            </button>
                            {showLabelFilter && (
                                <div className="absolute right-0 top-full mt-1 w-48 bg-white border border-gray-200 rounded-lg shadow-xl z-20 py-1">
                                    <button
                                        onClick={() => { setSelectedLabelId(null); setShowLabelFilter(false); }}
                                        className={cn(
                                            "w-full flex items-center gap-2 px-3 py-2 text-sm text-left hover:bg-gray-50",
                                            !selectedLabelId && "bg-gray-50 font-medium"
                                        )}
                                    >
                                        All Labels
                                    </button>
                                    {allLabels.map(label => (
                                        <button
                                            key={label.id}
                                            onClick={() => { setSelectedLabelId(label.id); setShowLabelFilter(false); }}
                                            className={cn(
                                                "w-full flex items-center gap-2 px-3 py-2 text-sm text-left hover:bg-gray-50",
                                                selectedLabelId === label.id && "bg-gray-50 font-medium"
                                            )}
                                        >
                                            <span className="w-3 h-3 rounded-full" style={{ backgroundColor: label.color }} />
                                            {label.name}
                                            {label._count?.conversations != null && (
                                                <span className="ml-auto text-xs text-gray-400">{label._count.conversations}</span>
                                            )}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                        <div className="relative" ref={filterMenuRef}>
                            <button
                                onClick={() => setShowFilterMenu(!showFilterMenu)}
                                className="p-1.5 rounded-sm hover:bg-gray-100 text-gray-500"
                            >
                                <Filter size={16} />
                            </button>
                        </div>
                    </div>
                </div>

                {/* Search Input */}
                <div className="relative mb-3">
                    <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search conversations..."
                        className="w-full pl-9 pr-8 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                    {isSearching && (
                        <Loader2 size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 animate-spin" />
                    )}
                    {searchQuery && !isSearching && (
                        <button
                            onClick={() => setSearchQuery('')}
                            className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                        >
                            <X size={14} />
                        </button>
                    )}
                </div>

                {/* Search mode indicator */}
                {isSearchMode && (
                    <div className="mb-2 text-xs text-gray-500 flex items-center gap-1">
                        <Search size={12} />
                        {isSearching ? 'Searching...' : `${filteredConversations.length} results for "${searchQuery}"`}
                    </div>
                )}

                {/* Filter Tabs - hide when searching */}
                {!isSearchMode && (
                    <>
                        <div className="flex gap-1 bg-gray-100 rounded-lg p-1">
                            <button
                                onClick={() => setFilter('mine')}
                                className={cn(
                                    "flex-1 text-xs font-medium py-1.5 px-2 rounded-md transition-colors",
                                    filter === 'mine' ? "bg-white text-blue-600 shadow-xs" : "text-gray-600 hover:text-gray-900"
                                )}
                            >
                                Mine {counts.mine > 0 && <span className="ml-1 text-gray-400">{counts.mine}</span>}
                            </button>
                            <button
                                onClick={() => setFilter('unassigned')}
                                className={cn(
                                    "flex-1 text-xs font-medium py-1.5 px-2 rounded-md transition-colors",
                                    filter === 'unassigned' ? "bg-white text-blue-600 shadow-xs" : "text-gray-600 hover:text-gray-900"
                                )}
                            >
                                Unassigned {counts.unassigned > 0 && <span className="ml-1 text-gray-400">{counts.unassigned}</span>}
                            </button>
                            <button
                                onClick={() => setFilter('all')}
                                className={cn(
                                    "flex-1 text-xs font-medium py-1.5 px-2 rounded-md transition-colors",
                                    filter === 'all' ? "bg-white text-blue-600 shadow-xs" : "text-gray-600 hover:text-gray-900"
                                )}
                            >
                                All {counts.all > 0 && <span className="ml-1 text-gray-400">{counts.all}</span>}
                            </button>
                        </div>

                        {/* Show Resolved Toggle */}
                        <button
                            onClick={() => setShowResolved(!showResolved)}
                            className={cn(
                                "flex items-center justify-center gap-1.5 w-full mt-2 py-1.5 text-xs rounded-md transition-colors",
                                showResolved
                                    ? "bg-gray-200 text-gray-700"
                                    : "text-gray-500 hover:bg-gray-100"
                            )}
                        >
                            {showResolved ? <EyeOff size={12} /> : <Eye size={12} />}
                            {showResolved ? 'Hide Resolved' : 'Show Resolved'}
                        </button>
                    </>
                )}
            </div>

            {/* Conversations List - Virtualized for performance */}
            <div className="flex-1 overflow-hidden">
                {filteredConversations.length === 0 ? (
                    <div className="p-8 text-center text-gray-500 text-sm">
                        No conversations found
                    </div>
                ) : (
                    <Virtuoso
                        style={{ height: '100%' }}
                        data={filteredConversations}
                        overscan={5}
                        components={{
                            Footer: () => (!isSearchMode && hasMore && onLoadMore) ? (
                                <button
                                    onClick={onLoadMore}
                                    disabled={isLoadingMore}
                                    className="w-full py-3 text-sm text-indigo-600 hover:bg-indigo-50 disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {isLoadingMore ? (
                                        <><Loader2 size={14} className="animate-spin" />Loading...</>
                                    ) : (
                                        'Load more conversations'
                                    )}
                                </button>
                            ) : null
                        }}
                        itemContent={(index: number, conv: Conversation) => {
                            const name = getDisplayName(conv);
                            const { subject, preview, showPaperclip } = getPreview(conv);
                            const initials = getInitials(name);

                            return (
                                <ConversationItem
                                    key={conv.id}
                                    conv={conv}
                                    isSelected={selectedId === conv.id}
                                    isSelectionMode={isSelectionMode}
                                    isBulkSelected={selectedIds.has(conv.id)}
                                    hasDraft={draftIds.has(conv.id)}
                                    onSelect={onSelect}
                                    onPreload={onPreload}
                                    onToggleSelection={toggleSelection}
                                    displayName={name}
                                    initials={initials}
                                    subject={subject}
                                    preview={preview}
                                    showPaperclip={showPaperclip}
                                    lastCustomerTime={getLastCustomerMessageTime(conv)}
                                />
                            );
                        }}
                    />
                )}
            </div>

            {/* Bulk Action Toolbar */}
            <BulkActionToolbar
                selectedIds={Array.from(selectedIds)}
                onClearSelection={() => {
                    setSelectedIds(new Set());
                    setIsSelectionMode(false);
                }}
                onActionComplete={() => {
                    onRefresh?.();
                }}
                users={users}
                labels={allLabels}
            />
        </div >
    );
}

/**
 * LabelSelector
 * 
 * Dropdown component for selecting and assigning labels to conversations.
 * Shows current labels as colored chips with ability to add/remove.
 */

import { useState, useEffect, useRef } from 'react';
import { Logger } from '../../utils/logger';
import { Tag, Plus, X, Check, Loader2 } from 'lucide-react';
import { cn } from '../../utils/cn';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface Label {
    id: string;
    name: string;
    color: string;
}

interface LabelSelectorProps {
    conversationId: string;
    currentLabels: Label[];
    onLabelsChange?: (labels: Label[]) => void;
    compact?: boolean;
}

export function LabelSelector({
    conversationId,
    currentLabels,
    onLabelsChange,
    compact = false,
}: LabelSelectorProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [isOpen, setIsOpen] = useState(false);
    const [allLabels, setAllLabels] = useState<Label[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [actionLoading, setActionLoading] = useState<string | null>(null);
    const dropdownRef = useRef<HTMLDivElement>(null);

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    // Fetch all available labels when dropdown opens
    useEffect(() => {
        if (isOpen && allLabels.length === 0) {
            fetchLabels();
        }
    }, [isOpen]);

    const fetchLabels = async () => {
        setIsLoading(true);
        try {
            const res = await fetch('/api/labels', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || '',
                },
            });
            if (res.ok) {
                const data = await res.json();
                setAllLabels(data.labels || []);
            }
        } catch (error) {
            Logger.error('Failed to fetch labels:', { error: error });
        } finally {
            setIsLoading(false);
        }
    };

    const isLabelAssigned = (labelId: string) => {
        return currentLabels.some((l) => l.id === labelId);
    };

    const handleToggleLabel = async (label: Label) => {
        const isAssigned = isLabelAssigned(label.id);
        setActionLoading(label.id);

        try {
            const method = isAssigned ? 'DELETE' : 'POST';
            const res = await fetch(`/api/chat/${conversationId}/labels/${label.id}`, {
                method,
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || '',
                },
            });

            if (res.ok) {
                const newLabels = isAssigned
                    ? currentLabels.filter((l) => l.id !== label.id)
                    : [...currentLabels, label];
                onLabelsChange?.(newLabels);
            }
        } catch (error) {
            Logger.error('Failed to toggle label:', { error: error });
        } finally {
            setActionLoading(null);
        }
    };

    const handleRemoveLabel = async (labelId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const label = currentLabels.find((l) => l.id === labelId);
        if (label) {
            await handleToggleLabel(label);
        }
    };

    return (
        <div className="relative" ref={dropdownRef}>
            {/* Current Labels Display */}
            <div className="flex flex-wrap items-center gap-1">
                {currentLabels.map((label) => (
                    <span
                        key={label.id}
                        className={cn(
                            'inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium',
                            compact ? 'text-[10px]' : 'text-xs'
                        )}
                        style={{
                            backgroundColor: `${label.color}20`,
                            color: label.color,
                            border: `1px solid ${label.color}40`,
                        }}
                    >
                        {label.name}
                        <button
                            onClick={(e) => handleRemoveLabel(label.id, e)}
                            className="ml-0.5 hover:opacity-70 transition-opacity"
                            aria-label={`Remove ${label.name} label`}
                        >
                            <X className="w-3 h-3" />
                        </button>
                    </span>
                ))}

                {/* Add Label Button */}
                <button
                    onClick={() => setIsOpen(!isOpen)}
                    className={cn(
                        'inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium',
                        'bg-gray-700/50 text-gray-400 border border-gray-600/50',
                        'hover:bg-gray-700 hover:text-gray-300 transition-colors'
                    )}
                    aria-label="Add label"
                >
                    <Plus className="w-3 h-3" />
                    {!compact && <span>Label</span>}
                </button>
            </div>

            {/* Dropdown */}
            {isOpen && (
                <div className="absolute top-full left-0 mt-1 z-50 w-48 bg-gray-800 border border-gray-700 rounded-lg shadow-xl py-1">
                    {isLoading ? (
                        <div className="flex items-center justify-center py-4">
                            <Loader2 className="w-5 h-5 text-gray-400 animate-spin" />
                        </div>
                    ) : allLabels.length === 0 ? (
                        <div className="px-3 py-2 text-sm text-gray-500">
                            No labels created yet
                        </div>
                    ) : (
                        <>
                            <div className="px-3 py-1.5 text-xs font-medium text-gray-500 uppercase">
                                Labels
                            </div>
                            {allLabels.map((label) => {
                                const isAssigned = isLabelAssigned(label.id);
                                const isLoadingThis = actionLoading === label.id;

                                return (
                                    <button
                                        key={label.id}
                                        onClick={() => handleToggleLabel(label)}
                                        disabled={isLoadingThis}
                                        className={cn(
                                            'w-full flex items-center gap-2 px-3 py-2 text-sm text-left',
                                            'hover:bg-gray-700 transition-colors',
                                            isAssigned && 'bg-gray-700/50'
                                        )}
                                    >
                                        <span
                                            className="w-3 h-3 rounded-full"
                                            style={{ backgroundColor: label.color }}
                                        />
                                        <span className="flex-1 text-gray-200">{label.name}</span>
                                        {isLoadingThis ? (
                                            <Loader2 className="w-4 h-4 text-gray-400 animate-spin" />
                                        ) : isAssigned ? (
                                            <Check className="w-4 h-4 text-green-400" />
                                        ) : null}
                                    </button>
                                );
                            })}
                        </>
                    )}

                    {/* Create New Label Link */}
                    <div className="border-t border-gray-700 mt-1 pt-1">
                        <button
                            onClick={() => {
                                setIsOpen(false);
                                // Could open label manager modal here
                                window.location.href = '/settings?tab=labels';
                            }}
                            className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-400 hover:text-gray-200 hover:bg-gray-700 transition-colors"
                        >
                            <Tag className="w-4 h-4" />
                            Manage Labels
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

/**
 * MacrosDropdown - Quick action buttons for inbox automations.
 * Displays available macros and executes on click.
 */
import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Zap, ChevronDown, Play } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { cn } from '../../utils/cn';

interface Macro {
    id: string;
    name: string;
    icon?: string;
    color?: string;
    actions: Array<{ type: string; userId?: string; labelId?: string }>;
}

interface MacrosDropdownProps {
    conversationId: string;
    onExecuted?: () => void;
}

export function MacrosDropdown({ conversationId, onExecuted }: MacrosDropdownProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [macros, setMacros] = useState<Macro[]>([]);
    const [isOpen, setIsOpen] = useState(false);
    const [isExecuting, setIsExecuting] = useState<string | null>(null);

    useEffect(() => {
        fetchMacros();
    }, [currentAccount?.id]);

    const fetchMacros = async () => {
        if (!currentAccount?.id || !token) return;
        try {
            const res = await fetch('/api/chat/macros', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) setMacros(await res.json());
        } catch (e) {
            Logger.error('Failed to fetch macros:', { error: e });
        }
    };

    const executeMacro = async (macroId: string) => {
        setIsExecuting(macroId);
        try {
            const res = await fetch(`/api/chat/macros/${macroId}/execute`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({ conversationId })
            });
            if (res.ok) {
                setIsOpen(false);
                onExecuted?.();
            }
        } catch (e) {
            Logger.error('Failed to execute macro:', { error: e });
        } finally {
            setIsExecuting(null);
        }
    };

    if (macros.length === 0) return null;

    return (
        <div className="relative">
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center gap-1 px-2 py-1.5 text-sm text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                title="Quick Actions"
            >
                <Zap size={14} />
                <ChevronDown size={12} />
            </button>

            {isOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsOpen(false)} />
                    <div className="absolute right-0 top-full mt-1 w-56 bg-white border border-gray-200 rounded-lg shadow-lg z-20 py-1">
                        <div className="px-3 py-1.5 text-xs font-medium text-gray-500 uppercase tracking-wide">
                            Quick Actions
                        </div>
                        {macros.map((macro) => (
                            <button
                                key={macro.id}
                                onClick={() => executeMacro(macro.id)}
                                disabled={isExecuting === macro.id}
                                className={cn(
                                    "w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50 transition-colors",
                                    isExecuting === macro.id && "opacity-50"
                                )}
                            >
                                <div
                                    className="w-5 h-5 rounded flex items-center justify-center text-white text-[10px]"
                                    style={{ backgroundColor: macro.color || '#6366f1' }}
                                >
                                    <Play size={10} />
                                </div>
                                <span className="flex-1 text-left">{macro.name}</span>
                                <span className="text-[10px] text-gray-400">
                                    {macro.actions.length} action{macro.actions.length !== 1 ? 's' : ''}
                                </span>
                            </button>
                        ))}
                    </div>
                </>
            )}
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import DOMPurify from 'dompurify';
import { Logger } from '../../utils/logger';
import { X, Send, Loader2, ChevronDown, ChevronUp, Zap, Paperclip, Sparkles } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { InboxRichTextEditor } from './InboxRichTextEditor';
import { useCannedResponses } from '../../hooks/useCannedResponses';

interface EmailAccount {
    id: string;
    name: string;
    email: string;
    isDefault?: boolean;
}

interface NewEmailModalProps {
    onClose: () => void;
    onSent: (conversationId: string) => void;
}

const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

export function NewEmailModal({ onClose, onSent }: NewEmailModalProps) {
    const { token, user } = useAuth();
    const { currentAccount } = useAccount();

    const [to, setTo] = useState('');
    const [cc, setCc] = useState('');
    const [subject, setSubject] = useState('');
    const [body, setBody] = useState('');
    const [emailAccountId, setEmailAccountId] = useState('');
    const [emailAccounts, setEmailAccounts] = useState<EmailAccount[]>([]);
    const [showCc, setShowCc] = useState(false);
    const [isSending, setIsSending] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [attachments, setAttachments] = useState<File[]>([]);
    const [uploadProgress, setUploadProgress] = useState<number>(0);
    const [isGeneratingAI, setIsGeneratingAI] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Close on Escape key
    useEffect(() => {
        const handleKey = (e: KeyboardEvent) => {
            if (e.key === 'Escape' && !isSending) onClose();
        };
        document.addEventListener('keydown', handleKey);
        return () => document.removeEventListener('keydown', handleKey);
    }, [onClose, isSending]);

    // Canned responses integration
    const {
        cannedResponses,
        filteredCanned,
        showCanned,
        handleInputForCanned,
        selectCanned,
        setShowCanned
    } = useCannedResponses();

    // Handle body change and check for canned response trigger
    const handleBodyChange = (value: string) => {
        setBody(value);
        handleInputForCanned(value);
    };

    // Select a canned response and replace the body
    const handleSelectCanned = (response: { id: string; shortcut: string; content: string }) => {
        const context = {
            agentFirstName: user?.fullName?.split(' ')[0],
            agentFullName: user?.fullName ?? undefined
        };
        const content = selectCanned(response as any, context);
        setBody(content);
    };

    // Fetch available email accounts
    useEffect(() => {
        const fetchAccounts = async () => {
            if (!currentAccount || !token) return;
            try {
                const res = await fetch('/api/chat/email-accounts', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const accounts = await res.json();
                    setEmailAccounts(accounts);
                    if (accounts.length > 0) {
                        const defaultAccount = accounts.find((a: EmailAccount) => a.isDefault) || accounts[0];
                        setEmailAccountId(defaultAccount.id);
                    }
                }
            } catch (err) {
                Logger.error('Failed to fetch email accounts', { error: err });
            }
        };
        fetchAccounts();
    }, [currentAccount, token]);

    // Get user's email signature
    const signature = user?.emailSignature || '';

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            setAttachments(prev => [...prev, ...Array.from(e.target.files!)]);
        }
        // Reset input so same file can be selected again
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    /** Handle AI assist for email composition. */
    const handleAIAssist = async () => {
        if (!to.trim() || !subject.trim()) {
            setError('Please enter recipient and subject before using AI assist');
            return;
        }
        if (!token || !currentAccount || isGeneratingAI) return;

        setIsGeneratingAI(true);
        setError(null);
        try {
            const res = await fetch('/api/chat/compose-ai', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    recipient: to.trim(),
                    subject: subject.trim(),
                    currentDraft: body || ''
                })
            });

            if (!res.ok) {
                const errData = await res.json();
                setError(errData.error || 'Failed to generate AI draft');
                return;
            }

            const data = await res.json();
            if (data.draft) {
                setBody(data.draft);
            }
        } catch (err) {
            Logger.error('AI compose assist failed:', { error: err });
            setError('Failed to generate AI draft. Please try again.');
        } finally {
            setIsGeneratingAI(false);
        }
    };

    const removeAttachment = (index: number) => {
        setAttachments(prev => prev.filter((_, i) => i !== index));
    };

    const handleSend = async () => {
        if (!to.trim() || !subject.trim() || !body.trim()) {
            setError('Please fill in all required fields');
            return;
        }

        // Basic email format validation
        const emails = to.split(',').map(e => e.trim()).filter(Boolean);
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        const invalidEmails = emails.filter(e => !emailRegex.test(e));
        if (invalidEmails.length > 0) {
            setError(`Invalid email address: ${invalidEmails.join(', ')}`);
            return;
        }

        if (!emailAccountId) {
            setError('Please select an email account');
            return;
        }

        setIsSending(true);
        setError(null);
        setUploadProgress(0);

        try {
            const formData = new FormData();
            formData.append('to', to.trim());
            formData.append('cc', cc.trim());
            formData.append('subject', subject.trim());
            formData.append('body', body + (signature ? `<br><br>${signature}` : ''));
            formData.append('emailAccountId', emailAccountId);

            attachments.forEach(file => {
                formData.append('attachments', file);
            });

            // Use XMLHttpRequest to track upload progress
            const xhr = new XMLHttpRequest();

            const result = await new Promise<{ success: boolean; conversationId?: string; error?: string }>((resolve, reject) => {
                xhr.upload.onprogress = (event) => {
                    if (event.lengthComputable) {
                        const percent = Math.round((event.loaded / event.total) * 100);
                        setUploadProgress(percent);
                    }
                };

                xhr.onload = () => {
                    try {
                        const data = JSON.parse(xhr.responseText);
                        if (xhr.status >= 200 && xhr.status < 300) {
                            resolve({ success: true, conversationId: data.conversationId });
                        } else {
                            resolve({ success: false, error: data.error || 'Failed to send email' });
                        }
                    } catch {
                        // Provide more debug info when parsing fails
                        const preview = xhr.responseText?.substring(0, 100) || '(empty response)';
                        resolve({ success: false, error: `Failed to parse response (status ${xhr.status}): ${preview}` });
                    }
                };

                xhr.onerror = () => {
                    reject(new Error('Network error'));
                };

                xhr.open('POST', '/api/chat/compose');
                xhr.setRequestHeader('Authorization', `Bearer ${token}`);
                xhr.setRequestHeader('x-account-id', currentAccount?.id || '');
                xhr.send(formData);
            });

            if (!result.success) {
                throw new Error(result.error);
            }

            onSent(result.conversationId!);
        } catch (err: any) {
            setError(err.message || 'Failed to send email');
            setIsSending(false);
            setUploadProgress(0);
        }
    };


    const selectedAccount = emailAccounts.find(a => a.id === emailAccountId);

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col">
                {/* Header */}
                <div className="flex items-center justify-between px-4 py-3 border-b border-gray-200">
                    <h2 className="text-lg font-semibold text-gray-900">New Email</h2>
                    <button
                        onClick={onClose}
                        className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Form */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {/* To Field */}
                    <div className="flex items-center gap-2">
                        <label className="w-16 text-sm font-medium text-gray-600">To:</label>
                        <input
                            type="email"
                            value={to}
                            onChange={(e) => setTo(e.target.value)}
                            placeholder="recipient@example.com"
                            className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                        />
                    </div>

                    {/* Via (Email Account) */}
                    <div className="flex items-center gap-2">
                        <label className="w-16 text-sm font-medium text-gray-600">Via:</label>
                        <select
                            value={emailAccountId}
                            onChange={(e) => setEmailAccountId(e.target.value)}
                            className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white"
                        >
                            {emailAccounts.length === 0 ? (
                                <option value="">No email accounts configured</option>
                            ) : (
                                emailAccounts.map(account => (
                                    <option key={account.id} value={account.id}>
                                        {account.name} ({account.email})
                                    </option>
                                ))
                            )}
                        </select>
                    </div>

                    {/* Subject */}
                    <div className="flex items-center gap-2">
                        <label className="w-16 text-sm font-medium text-gray-600">Subject:</label>
                        <input
                            type="text"
                            value={subject}
                            onChange={(e) => setSubject(e.target.value)}
                            placeholder="Enter your email subject here"
                            className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                        />
                    </div>

                    {/* CC Toggle */}
                    <div className="flex items-center gap-2">
                        <button
                            type="button"
                            onClick={() => setShowCc(!showCc)}
                            className="flex items-center gap-1 text-sm text-gray-500 hover:text-gray-700"
                        >
                            {showCc ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                            Cc
                        </button>
                    </div>

                    {/* CC Field (collapsible) */}
                    {showCc && (
                        <div className="flex items-center gap-2">
                            <label className="w-16 text-sm font-medium text-gray-600">Cc:</label>
                            <input
                                type="text"
                                value={cc}
                                onChange={(e) => setCc(e.target.value)}
                                placeholder="email1@example.com, email2@example.com"
                                className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                            />
                        </div>
                    )}

                    {/* Canned Responses Dropdown */}
                    {showCanned && (
                        <div className="border border-gray-200 rounded-lg bg-white max-h-48 overflow-y-auto">
                            <div className="p-2 text-xs text-gray-500 border-b bg-gray-50 flex items-center justify-between">
                                <span>Canned Responses (type to filter)</span>
                            </div>
                            {filteredCanned.length > 0 ? (
                                filteredCanned.map(r => (
                                    <button
                                        key={r.id}
                                        onClick={() => handleSelectCanned(r)}
                                        className="w-full text-left px-3 py-2 hover:bg-blue-50 transition-colors border-b border-gray-50 last:border-0"
                                    >
                                        <span className="text-xs font-mono bg-gray-100 px-1.5 py-0.5 rounded-sm text-gray-600">
                                            /{r.shortcut}
                                        </span>
                                        <p className="text-sm text-gray-700 mt-1 line-clamp-1">{r.content}</p>
                                    </button>
                                ))
                            ) : (
                                <div className="px-3 py-4 text-center text-gray-500 text-sm">
                                    {cannedResponses.length === 0 ? (
                                        'No canned responses yet.'
                                    ) : (
                                        'No matches found'
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Body - Rich Text Editor with Canned Response trigger */}
                    <div className="border border-gray-300 rounded-lg overflow-hidden">
                        <div className="p-3">
                            <InboxRichTextEditor
                                value={body}
                                onChange={handleBodyChange}
                                placeholder="Type your message... (/ for canned responses)"
                                cannedPickerOpen={showCanned}
                            />
                        </div>
                        {/* Toolbar with AI Assist and Canned Response buttons */}
                        <div className="flex items-center gap-1 px-3 py-2 border-t border-gray-100 bg-gray-50">
                            {/* AI Assist Button */}
                            <button
                                type="button"
                                onClick={handleAIAssist}
                                disabled={isGeneratingAI}
                                className="p-2 rounded-sm hover:bg-purple-50 text-purple-500 hover:text-purple-600 transition-colors disabled:opacity-50"
                                title="Generate AI Draft"
                                aria-label="Generate AI draft email"
                            >
                                {isGeneratingAI ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
                            </button>
                            {/* Canned Responses Button */}
                            <button
                                type="button"
                                onClick={() => setBody('/')}
                                className="p-2 rounded-sm hover:bg-gray-200 text-gray-400 hover:text-gray-600 transition-colors"
                                title="Canned Responses"
                                aria-label="Insert canned response"
                            >
                                <Zap size={18} />
                            </button>
                            <div className="w-px h-4 bg-gray-300 mx-1" />
                            <button
                                type="button"
                                onClick={() => fileInputRef.current?.click()}
                                className="p-2 rounded-sm hover:bg-gray-200 text-gray-400 hover:text-gray-600 transition-colors"
                                title="Attach File"
                                aria-label="Attach File"
                            >
                                <Paperclip size={18} />
                            </button>
                            <input
                                type="file"
                                ref={fileInputRef}
                                onChange={handleFileSelect}
                                className="hidden"
                                multiple
                                accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.xls,.xlsx,.txt,.csv,.zip"
                            />
                        </div>
                    </div>

                    {/* Attachments List */}
                    {attachments.length > 0 && (
                        <div className="flex flex-wrap gap-2">
                            {attachments.map((file, index) => (
                                <div key={index} className="flex items-center gap-2 px-3 py-1.5 bg-gray-100 rounded-full text-sm text-gray-700 border border-gray-200">
                                    <span className="truncate max-w-[200px]">{file.name}</span>
                                    <span className="text-xs text-gray-500 whitespace-nowrap">({formatFileSize(file.size)})</span>
                                    <button
                                        onClick={() => removeAttachment(index)}
                                        disabled={isSending}
                                        className="text-gray-400 hover:text-red-500 transition-colors disabled:opacity-50"
                                    >
                                        <X size={14} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Upload Progress Bar */}
                    {isSending && attachments.length > 0 && (
                        <div className="space-y-1">
                            <div className="flex items-center justify-between text-xs text-gray-600">
                                <span>Uploading attachments...</span>
                                <span className="font-medium">{uploadProgress}%</span>
                            </div>
                            <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-gradient-to-r from-blue-500 to-blue-600 rounded-full transition-all duration-200"
                                    style={{ width: `${uploadProgress}%` }}
                                />
                            </div>
                        </div>
                    )}


                    {/* Signature Preview */}
                    {signature && (
                        <div className="text-xs text-gray-400 border-t border-gray-100 pt-2">
                            <span className="font-medium">Signature will be appended:</span>
                            <div
                                className="mt-1 text-gray-500 line-clamp-2"
                                dangerouslySetInnerHTML={{
                                    __html: DOMPurify.sanitize(signature, {
                                        ALLOWED_TAGS: ['p', 'br', 'strong', 'b', 'em', 'i', 'u', 'a', 'div', 'span'],
                                        ALLOWED_ATTR: ['href', 'target', 'style']
                                    })
                                }}
                            />
                        </div>
                    )}

                    {/* Error Message */}
                    {error && (
                        <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
                            {error}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="flex items-center justify-between px-4 py-3 border-t border-gray-200 bg-gray-50">
                    <button
                        onClick={onClose}
                        disabled={isSending}
                        className="px-4 py-2 text-gray-600 hover:text-gray-800 hover:bg-gray-100 rounded-lg transition-colors disabled:opacity-50"
                    >
                        Discard
                    </button>
                    <button
                        onClick={handleSend}
                        disabled={isSending || emailAccounts.length === 0}
                        className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {isSending ? (
                            <>
                                <Loader2 size={16} className="animate-spin" />
                                Sending...
                            </>
                        ) : (
                            <>
                                <Send size={16} />
                                Send
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

