/**
 * SchedulePickerModal
 * 
 * Modal for scheduling messages to be sent later.
 * Provides preset options and a custom date/time picker.
 */

import { useState, useMemo } from 'react';
import { Clock, Calendar, Send } from 'lucide-react';
import { Modal } from '../ui/Modal';
import { cn } from '../../utils/cn';

interface SchedulePickerModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSchedule: (scheduledFor: Date) => void;
    isLoading?: boolean;
}

/**
 * Get preset schedule options based on current time.
 */
function getPresetOptions(): { label: string; value: Date }[] {
    const now = new Date();
    const presets: { label: string; value: Date }[] = [];

    // In 1 hour
    const inOneHour = new Date(now.getTime() + 60 * 60 * 1000);
    presets.push({ label: 'In 1 hour', value: inOneHour });

    // In 2 hours
    const inTwoHours = new Date(now.getTime() + 2 * 60 * 60 * 1000);
    presets.push({ label: 'In 2 hours', value: inTwoHours });

    // Tomorrow 9 AM
    const tomorrow9am = new Date(now);
    tomorrow9am.setDate(tomorrow9am.getDate() + 1);
    tomorrow9am.setHours(9, 0, 0, 0);
    presets.push({ label: 'Tomorrow 9:00 AM', value: tomorrow9am });

    // Next Monday 9 AM
    const nextMonday = new Date(now);
    const currentDay = nextMonday.getDay();
    const daysUntilMonday = currentDay === 0 ? 1 : 8 - currentDay;
    nextMonday.setDate(nextMonday.getDate() + daysUntilMonday);
    nextMonday.setHours(9, 0, 0, 0);
    if (nextMonday > now) {
        presets.push({ label: 'Monday 9:00 AM', value: nextMonday });
    }

    return presets;
}

/**
 * Format date for display.
 */
function formatScheduleTime(date: Date): string {
    return date.toLocaleString(undefined, {
        weekday: 'short',
        month: 'short',
        day: 'numeric',
        hour: 'numeric',
        minute: '2-digit',
    });
}

export function SchedulePickerModal({
    isOpen,
    onClose,
    onSchedule,
    isLoading = false,
}: SchedulePickerModalProps) {
    const [selectedPreset, setSelectedPreset] = useState<Date | null>(null);
    const [customDate, setCustomDate] = useState('');
    const [customTime, setCustomTime] = useState('');
    const [useCustom, setUseCustom] = useState(false);

    // Memoize presets to avoid impure function call during render
    const presets = useMemo(() => getPresetOptions(), []);

    // Memoize minimum date calculation to avoid impure Date.now() call during render
    const { minDateString } = useMemo(() => {
        const minDate = new Date(Date.now() + 5 * 60 * 1000);
        return {
            minDateString: minDate.toISOString().split('T')[0],
        };
    }, []);

    const handlePresetSelect = (date: Date) => {
        setSelectedPreset(date);
        setUseCustom(false);
    };

    const handleCustomChange = () => {
        setUseCustom(true);
        setSelectedPreset(null);
    };

    const getScheduledTime = (): Date | null => {
        if (useCustom && customDate && customTime) {
            const combined = new Date(`${customDate}T${customTime}`);
            if (combined > new Date()) {
                return combined;
            }
        }
        return selectedPreset;
    };

    const scheduledTime = getScheduledTime();

    const handleSubmit = () => {
        if (scheduledTime) {
            onSchedule(scheduledTime);
        }
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-2 text-white">
                    <Clock className="w-5 h-5 text-indigo-400" />
                    <span>Schedule Message</span>
                </div>
            }
            maxWidth="max-w-md"
        >
            <div className="space-y-4">
                {/* Preset Options */}
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-400">Quick Options</label>
                    <div className="grid grid-cols-2 gap-2">
                        {presets.map((preset, index) => (
                            <button
                                key={index}
                                onClick={() => handlePresetSelect(preset.value)}
                                className={cn(
                                    'px-3 py-2 rounded-lg text-sm font-medium transition-all',
                                    'border',
                                    selectedPreset === preset.value && !useCustom
                                        ? 'bg-indigo-600 border-indigo-500 text-white'
                                        : 'bg-gray-800 border-gray-700 text-gray-300 hover:bg-gray-700 hover:border-gray-600'
                                )}
                            >
                                {preset.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Divider */}
                <div className="flex items-center gap-3">
                    <div className="flex-1 h-px bg-gray-700" />
                    <span className="text-xs text-gray-500 uppercase">or</span>
                    <div className="flex-1 h-px bg-gray-700" />
                </div>

                {/* Custom Date/Time */}
                <div className="space-y-3">
                    <label className="text-sm font-medium text-gray-400">Custom Time</label>
                    <div className="flex gap-2">
                        <div className="flex-1">
                            <div className="flex items-center gap-2 px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg focus-within:border-indigo-500">
                                <Calendar className="w-4 h-4 text-gray-400" />
                                <input
                                    type="date"
                                    value={customDate}
                                    onChange={(e) => {
                                        setCustomDate(e.target.value);
                                        handleCustomChange();
                                    }}
                                    min={minDateString}
                                    className="flex-1 bg-transparent text-white text-sm outline-none"
                                />
                            </div>
                        </div>
                        <div className="flex-1">
                            <div className="flex items-center gap-2 px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg focus-within:border-indigo-500">
                                <Clock className="w-4 h-4 text-gray-400" />
                                <input
                                    type="time"
                                    value={customTime}
                                    onChange={(e) => {
                                        setCustomTime(e.target.value);
                                        handleCustomChange();
                                    }}
                                    className="flex-1 bg-transparent text-white text-sm outline-none"
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Selected Time Preview */}
                {scheduledTime && (
                    <div className="p-3 bg-indigo-900/30 border border-indigo-700/50 rounded-lg">
                        <div className="flex items-center gap-2 text-indigo-300">
                            <Send className="w-4 h-4" />
                            <span className="text-sm">
                                Message will be sent: <strong>{formatScheduleTime(scheduledTime)}</strong>
                            </span>
                        </div>
                    </div>
                )}
            </div>

            {/* Footer */}
            <div className="flex justify-end gap-2 pt-4 mt-4 border-t border-gray-700">
                <button
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-300 bg-gray-700 rounded-lg hover:bg-gray-600 transition-colors"
                >
                    Cancel
                </button>
                <button
                    onClick={handleSubmit}
                    disabled={!scheduledTime || isLoading}
                    className={cn(
                        'px-4 py-2 text-sm font-medium rounded-lg transition-colors flex items-center gap-2',
                        scheduledTime && !isLoading
                            ? 'bg-indigo-600 text-white hover:bg-indigo-500'
                            : 'bg-gray-700 text-gray-500 cursor-not-allowed'
                    )}
                >
                    <Clock className="w-4 h-4" />
                    {isLoading ? 'Scheduling...' : 'Schedule'}
                </button>
            </div>
        </Modal>
    );
}

/**
 * InitialValuePlugin - Syncs external HTML value to Lexical state.
 * Handles initial load, canned response insertion, and clearing after send.
 * 
 * Uses a flag to track whether updates are internal (from the editor itself)
 * or external (from props like canned response selection or clearing).
 */
import { useEffect, useRef } from 'react';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { $generateNodesFromDOM, $generateHtmlFromNodes } from '@lexical/html';
import { $getRoot, $insertNodes, $createParagraphNode, LexicalEditor } from 'lexical';

interface InitialValuePluginProps {
    initialValue: string;
}

/**
 * Normalizes HTML for comparison by stripping whitespace and empty tags.
 */
function normalizeHtml(html: string): string {
    return html
        .replace(/<p><br><\/p>/g, '')
        .replace(/\s+/g, ' ')
        .trim();
}

export function InitialValuePlugin({ initialValue }: InitialValuePluginProps) {
    const [editor] = useLexicalComposerContext();
    const lastExternalValueRef = useRef<string>('');

    useEffect(() => {
        // Normalize for comparison
        const normalizedExternal = normalizeHtml(initialValue || '');

        // Check if we actually need to update
        let currentEditorHtml = '';
        (editor as any).getEditorState().read(() => {
            currentEditorHtml = $generateHtmlFromNodes(editor, null);
        });
        const normalizedCurrent = normalizeHtml(currentEditorHtml);

        // Skip if external value matches what's already in editor
        if (normalizedExternal === normalizedCurrent) {
            lastExternalValueRef.current = initialValue || '';
            return;
        }

        // Update the editor with the new external value
        lastExternalValueRef.current = initialValue || '';

        editor.update(() => {
            const root = $getRoot();

            // Handle empty value (clearing the editor)
            if (!initialValue || initialValue.trim() === '') {
                root.clear();
                const paragraph = $createParagraphNode();
                root.append(paragraph);
                return;
            }

            // Parse and insert HTML content
            const parser = new DOMParser();
            const dom = parser.parseFromString(initialValue, 'text/html');
            const nodes = $generateNodesFromDOM(editor, dom);

            root.clear();
            $insertNodes(nodes);
        });
    }, [editor, initialValue]);

    return null;
}

/**
 * ToolbarPlugin - Configurable toolbar with formatting buttons.
 * Renders buttons based on enabled features.
 */
import { useCallback, useEffect, useState, useRef } from 'react';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import {
    $getSelection,
    $isRangeSelection,
    FORMAT_TEXT_COMMAND,
    SELECTION_CHANGE_COMMAND,
    COMMAND_PRIORITY_CRITICAL,
} from 'lexical';
import { $isLinkNode, TOGGLE_LINK_COMMAND } from '@lexical/link';
import {
    INSERT_ORDERED_LIST_COMMAND,
    INSERT_UNORDERED_LIST_COMMAND,
    $isListNode,
    ListNode,
} from '@lexical/list';
import { $getNearestNodeOfType } from '@lexical/utils';
import {
    Bold,
    Italic,
    Underline,
    Link,
    List,
    ListOrdered,
    Smile,
} from 'lucide-react';

export type ToolbarFeature =
    | 'bold'
    | 'italic'
    | 'underline'
    | 'link'
    | 'list'
    | 'heading'
    | 'emoji'
    | 'image';

interface ToolbarPluginProps {
    features: ToolbarFeature[];
}

// Common emojis for quick access
const EMOJI_LIST = [
    '😊', '😂', '❤️', '👍', '🙏', '🎉', '🔥', '✨',
    '👏', '💯', '🤝', '💪', '🙌', '✅', '⭐', '💡',
    '📦', '🚚', '💳', '📧', '📞', '🛒', '💰', '🎁',
];

export function ToolbarPlugin({ features }: ToolbarPluginProps) {
    const [editor] = useLexicalComposerContext();
    const [isBold, setIsBold] = useState(false);
    const [isItalic, setIsItalic] = useState(false);
    const [isUnderline, setIsUnderline] = useState(false);
    const [isLink, setIsLink] = useState(false);
    const [listType, setListType] = useState<'bullet' | 'number' | null>(null);
    const [showLinkModal, setShowLinkModal] = useState(false);
    const [linkUrl, setLinkUrl] = useState('');
    const [showEmojiPicker, setShowEmojiPicker] = useState(false);
    const emojiPickerRef = useRef<HTMLDivElement>(null);

    const updateToolbar = useCallback(() => {
        const selection = $getSelection();
        if ($isRangeSelection(selection)) {
            setIsBold(selection.hasFormat('bold'));
            setIsItalic(selection.hasFormat('italic'));
            setIsUnderline(selection.hasFormat('underline'));

            // Check for link
            const node = selection.anchor.getNode();
            const parent = node.getParent();
            setIsLink($isLinkNode(parent) || $isLinkNode(node));

            // Check for list
            const anchorNode = selection.anchor.getNode();
            const element = anchorNode.getKey() === 'root'
                ? anchorNode
                : anchorNode.getTopLevelElementOrThrow();
            const elementDOM = editor.getElementByKey(element.getKey());

            if (elementDOM !== null) {
                const listNode = $getNearestNodeOfType<ListNode>(anchorNode, ListNode);
                if (listNode) {
                    setListType(listNode.getListType() === 'bullet' ? 'bullet' : 'number');
                } else {
                    setListType(null);
                }
            }
        }
    }, [editor]);

    useEffect(() => {
        return editor.registerCommand(
            SELECTION_CHANGE_COMMAND,
            () => {
                updateToolbar();
                return false;
            },
            COMMAND_PRIORITY_CRITICAL
        );
    }, [editor, updateToolbar]);

    // Close emoji picker when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (emojiPickerRef.current && !emojiPickerRef.current.contains(event.target as Node)) {
                setShowEmojiPicker(false);
            }
        };
        if (showEmojiPicker) {
            document.addEventListener('mousedown', handleClickOutside);
            return () => document.removeEventListener('mousedown', handleClickOutside);
        }
    }, [showEmojiPicker]);

    const formatBold = () => editor.dispatchCommand(FORMAT_TEXT_COMMAND, 'bold');
    const formatItalic = () => editor.dispatchCommand(FORMAT_TEXT_COMMAND, 'italic');
    const formatUnderline = () => editor.dispatchCommand(FORMAT_TEXT_COMMAND, 'underline');

    const insertLink = () => {
        if (isLink) {
            editor.dispatchCommand(TOGGLE_LINK_COMMAND, null);
        } else {
            setLinkUrl('https://');
            setShowLinkModal(true);
        }
    };

    const confirmLink = () => {
        if (linkUrl && linkUrl !== 'https://') {
            editor.dispatchCommand(TOGGLE_LINK_COMMAND, linkUrl);
        }
        setShowLinkModal(false);
        setLinkUrl('');
    };

    const insertBulletList = () => editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
    const insertNumberedList = () => editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);

    // Insert emoji at cursor position
    const insertEmoji = (emoji: string) => {
        editor.update(() => {
            const selection = $getSelection();
            if ($isRangeSelection(selection)) {
                selection.insertText(emoji);
            }
        });
        setShowEmojiPicker(false);
    };

    const has = (feature: ToolbarFeature) => features.includes(feature);

    return (
        <>
            <div className="rte-toolbar">
                {/* Text Formatting Group */}
                {(has('bold') || has('italic') || has('underline')) && (
                    <div className="rte-toolbar-group">
                        {has('bold') && (
                            <button
                                type="button"
                                onClick={formatBold}
                                className={`rte-toolbar-btn ${isBold ? 'active' : ''}`}
                                title="Bold (Ctrl+B)"
                                aria-label="Format Bold"
                            >
                                <Bold size={16} />
                            </button>
                        )}
                        {has('italic') && (
                            <button
                                type="button"
                                onClick={formatItalic}
                                className={`rte-toolbar-btn ${isItalic ? 'active' : ''}`}
                                title="Italic (Ctrl+I)"
                                aria-label="Format Italic"
                            >
                                <Italic size={16} />
                            </button>
                        )}
                        {has('underline') && (
                            <button
                                type="button"
                                onClick={formatUnderline}
                                className={`rte-toolbar-btn ${isUnderline ? 'active' : ''}`}
                                title="Underline (Ctrl+U)"
                                aria-label="Format Underline"
                            >
                                <Underline size={16} />
                            </button>
                        )}
                    </div>
                )}

                {/* Link */}
                {has('link') && (
                    <div className="rte-toolbar-group">
                        <button
                            type="button"
                            onClick={insertLink}
                            className={`rte-toolbar-btn ${isLink ? 'active' : ''}`}
                            title="Insert Link"
                            aria-label="Insert Link"
                        >
                            <Link size={16} />
                        </button>
                    </div>
                )}

                {/* Lists */}
                {has('list') && (
                    <div className="rte-toolbar-group">
                        <button
                            type="button"
                            onClick={insertBulletList}
                            className={`rte-toolbar-btn ${listType === 'bullet' ? 'active' : ''}`}
                            title="Bullet List"
                            aria-label="Insert Bullet List"
                        >
                            <List size={16} />
                        </button>
                        <button
                            type="button"
                            onClick={insertNumberedList}
                            className={`rte-toolbar-btn ${listType === 'number' ? 'active' : ''}`}
                            title="Numbered List"
                            aria-label="Insert Numbered List"
                        >
                            <ListOrdered size={16} />
                        </button>
                    </div>
                )}

                {/* Emoji Picker */}
                {has('emoji') && (
                    <div className="rte-toolbar-group" style={{ position: 'relative' }} ref={emojiPickerRef}>
                        <button
                            type="button"
                            onClick={() => setShowEmojiPicker(!showEmojiPicker)}
                            className={`rte-toolbar-btn ${showEmojiPicker ? 'active' : ''}`}
                            title="Insert Emoji"
                            aria-label="Insert Emoji"
                        >
                            <Smile size={16} />
                        </button>
                        {showEmojiPicker && (
                            <div className="rte-emoji-picker">
                                {EMOJI_LIST.map((emoji) => (
                                    <button
                                        key={emoji}
                                        type="button"
                                        className="rte-emoji-btn"
                                        onClick={() => insertEmoji(emoji)}
                                        title={emoji}
                                    >
                                        {emoji}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Link Modal */}
            {showLinkModal && (
                <div className="rte-link-modal-overlay" onClick={() => setShowLinkModal(false)}>
                    <div className="rte-link-modal" onClick={(e) => e.stopPropagation()}>
                        <h3>Insert Link</h3>
                        <input
                            type="url"
                            value={linkUrl}
                            onChange={(e) => setLinkUrl(e.target.value)}
                            placeholder="Enter URL..."
                            autoFocus
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') confirmLink();
                                if (e.key === 'Escape') setShowLinkModal(false);
                            }}
                        />
                        <div className="rte-link-modal-actions">
                            <button
                                type="button"
                                className="rte-link-modal-btn cancel"
                                onClick={() => setShowLinkModal(false)}
                            >
                                Cancel
                            </button>
                            <button
                                type="button"
                                className="rte-link-modal-btn confirm"
                                onClick={confirmLink}
                            >
                                Insert
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

/**
 * MergeCustomerModal - Find and merge duplicate customer records.
 */
import { useState, useEffect } from 'react';
import { Users, ArrowRight, AlertTriangle, Check, X } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Modal } from '../ui/Modal';
import { formatCurrency } from '../../utils/format';

interface Customer {
    id: string;
    wooId: number;
    firstName: string;
    lastName: string;
    email: string;
    ordersCount: number;
    totalSpent: number;
}

interface MergeCustomerModalProps {
    isOpen: boolean;
    onClose: () => void;
    customerId: string;
    onMergeComplete: () => void;
}

export function MergeCustomerModal({ isOpen, onClose, customerId, onMergeComplete }: MergeCustomerModalProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [target, setTarget] = useState<Customer | null>(null);
    const [duplicates, setDuplicates] = useState<Customer[]>([]);
    const [selectedSource, setSelectedSource] = useState<Customer | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isMerging, setIsMerging] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (isOpen && customerId) {
            fetchDuplicates();
        }
    }, [isOpen, customerId]);

    const fetchDuplicates = async () => {
        setIsLoading(true);
        setError('');
        try {
            const res = await fetch(`/api/customers/${customerId}/duplicates`, {
                headers: { 'Authorization': `Bearer ${token}`, 'x-account-id': currentAccount?.id || '' }
            });
            if (res.ok) {
                const data = await res.json();
                setTarget(data.target);
                setDuplicates(data.duplicates || []);
            }
        } catch (e) {
            setError('Failed to load duplicates');
        } finally {
            setIsLoading(false);
        }
    };

    const handleMerge = async () => {
        if (!selectedSource || !target) return;

        setIsMerging(true);
        try {
            const res = await fetch(`/api/customers/${target.id}/merge`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({ sourceId: selectedSource.id })
            });

            if (res.ok) {
                onMergeComplete();
                onClose();
            } else {
                const err = await res.json();
                setError(err.error || 'Merge failed');
            }
        } catch (e) {
            setError('Failed to merge customers');
        } finally {
            setIsMerging(false);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Merge Duplicate Customers" maxWidth="max-w-2xl">
            <div className="space-y-4">
                {isLoading ? (
                    <div className="flex justify-center py-8">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600" />
                    </div>
                ) : duplicates.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                        <Users size={48} className="mx-auto mb-3 text-gray-300" />
                        <p className="font-medium">No Duplicates Found</p>
                        <p className="text-sm mt-1">No other customers match this email or phone.</p>
                    </div>
                ) : (
                    <>
                        {/* Target Customer */}
                        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                            <div className="text-xs font-medium text-blue-600 uppercase mb-2">Keep This Customer</div>
                            <div className="flex items-center justify-between">
                                <div>
                                    <div className="font-medium text-gray-900">{target?.firstName} {target?.lastName}</div>
                                    <div className="text-sm text-gray-500">{target?.email}</div>
                                </div>
                                <div className="text-right text-sm">
                                    <div>{target?.ordersCount} orders</div>
                                    <div className="font-medium text-green-600">{formatCurrency(target?.totalSpent || 0)}</div>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center justify-center">
                            <ArrowRight className="text-gray-400" />
                        </div>

                        {/* Duplicate Customers */}
                        <div className="space-y-2">
                            <div className="text-xs font-medium text-gray-500 uppercase">Select Customer to Merge Into Above</div>
                            {duplicates.map((dup) => (
                                <button
                                    key={dup.id}
                                    onClick={() => setSelectedSource(dup)}
                                    className={`w-full border rounded-lg p-4 text-left transition-colors ${selectedSource?.id === dup.id
                                        ? 'border-red-300 bg-red-50'
                                        : 'border-gray-200 hover:border-gray-300'
                                        }`}
                                >
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            {selectedSource?.id === dup.id && (
                                                <div className="w-5 h-5 rounded-full bg-red-500 flex items-center justify-center">
                                                    <Check size={12} className="text-white" />
                                                </div>
                                            )}
                                            <div>
                                                <div className="font-medium text-gray-900">{dup.firstName} {dup.lastName}</div>
                                                <div className="text-sm text-gray-500">{dup.email}</div>
                                            </div>
                                        </div>
                                        <div className="text-right text-sm">
                                            <div>{dup.ordersCount} orders</div>
                                            <div className="font-medium">{formatCurrency(dup.totalSpent)}</div>
                                        </div>
                                    </div>
                                </button>
                            ))}
                        </div>

                        {selectedSource && (
                            <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 flex items-start gap-2">
                                <AlertTriangle size={16} className="text-amber-500 mt-0.5 flex-shrink-0" />
                                <div className="text-sm text-amber-800">
                                    <strong>Warning:</strong> This will transfer all orders and conversations from
                                    <span className="font-medium"> {selectedSource.firstName} {selectedSource.lastName}</span> to
                                    <span className="font-medium"> {target?.firstName} {target?.lastName}</span>, then delete the merged customer.
                                </div>
                            </div>
                        )}

                        {error && (
                            <div className="text-red-600 text-sm">{error}</div>
                        )}

                        <div className="flex justify-end gap-2 pt-2">
                            <button onClick={onClose} className="btn-white">
                                Cancel
                            </button>
                            <button
                                onClick={handleMerge}
                                disabled={!selectedSource || isMerging}
                                className="btn-primary bg-red-600 hover:bg-red-700 disabled:opacity-50"
                            >
                                {isMerging ? 'Merging...' : 'Merge & Delete'}
                            </button>
                        </div>
                    </>
                )}
            </div>
        </Modal>
    );
}

/**
 * Internal Products List Component
 * 
 * Displays and manages internal-only products (components not synced to WooCommerce).
 * Used as a tab within the InventoryPage.
 */

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { usePermissions } from '../../hooks/usePermissions';
import { Logger } from '../../utils/logger';
import {
    Package, Plus, Search, Loader2, Trash2, Edit2, Box,
    AlertTriangle, Building2
} from 'lucide-react';
import { Pagination } from '../ui/Pagination';
import { Toast, ToastType } from '../ui/Toast';

interface InternalProduct {
    id: string;
    accountId: string;
    name: string;
    sku: string | null;
    description: string | null;
    stockQuantity: number;
    cogs: number | null;
    binLocation: string | null;
    mainImage: string | null;
    images: string[];
    supplierId: string | null;
    supplier: { id: string; name: string } | null;
    bomUsageCount?: number;
    createdAt: string;
    updatedAt: string;
}

interface InternalProductFormData {
    name: string;
    sku: string;
    description: string;
    stockQuantity: number;
    cogs: number | string;
    binLocation: string;
    supplierId: string;
}

export function InternalProductsList() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');

    const [products, setProducts] = useState<InternalProduct[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [debouncedQuery, setDebouncedQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [total, setTotal] = useState(0);

    // Modal state
    const [showModal, setShowModal] = useState(false);
    const [editingProduct, setEditingProduct] = useState<InternalProduct | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [formData, setFormData] = useState<InternalProductFormData>({
        name: '',
        sku: '',
        description: '',
        stockQuantity: 0,
        cogs: '',
        binLocation: '',
        supplierId: ''
    });

    // Suppliers for dropdown
    const [suppliers, setSuppliers] = useState<Array<{ id: string; name: string }>>([]);

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    // Debounce search
    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedQuery(searchQuery);
            setPage(1);
        }, 500);
        return () => clearTimeout(timer);
    }, [searchQuery]);

    // Fetch products
    useEffect(() => {
        fetchProducts();
    }, [currentAccount, token, debouncedQuery, page, limit]);

    // Fetch suppliers on mount
    useEffect(() => {
        fetchSuppliers();
    }, [currentAccount, token]);

    async function fetchProducts() {
        if (!currentAccount || !token) return;

        setIsLoading(true);
        try {
            const params = new URLSearchParams({
                limit: limit.toString(),
                offset: ((page - 1) * limit).toString(),
                ...(debouncedQuery && { search: debouncedQuery })
            });

            const res = await fetch(`/api/inventory/internal-products?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setProducts(data.items);
                setTotal(data.total);
            }
        } catch (err) {
            Logger.error('Failed to fetch internal products', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    async function fetchSuppliers() {
        if (!currentAccount || !token) return;

        try {
            const res = await fetch('/api/inventory/suppliers', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setSuppliers(data.map((s: any) => ({ id: s.id, name: s.name })));
            }
        } catch (err) {
            Logger.error('Failed to fetch suppliers', { error: err });
        }
    }

    function openCreateModal() {
        setEditingProduct(null);
        setFormData({
            name: '',
            sku: '',
            description: '',
            stockQuantity: 0,
            cogs: '',
            binLocation: '',
            supplierId: ''
        });
        setShowModal(true);
    }

    function openEditModal(product: InternalProduct) {
        setEditingProduct(product);
        setFormData({
            name: product.name,
            sku: product.sku || '',
            description: product.description || '',
            stockQuantity: product.stockQuantity,
            cogs: product.cogs?.toString() || '',
            binLocation: product.binLocation || '',
            supplierId: product.supplierId || ''
        });
        setShowModal(true);
    }

    async function handleSave() {
        if (!currentAccount || !token) return;
        if (!formData.name.trim()) { showToast('Component name is required'); return; }

        setIsSaving(true);
        try {
            const payload = {
                name: formData.name.trim(),
                sku: formData.sku.trim() || undefined,
                description: formData.description.trim() || undefined,
                stockQuantity: Number(formData.stockQuantity) || 0,
                cogs: formData.cogs ? Number(formData.cogs) : undefined,
                binLocation: formData.binLocation.trim() || undefined,
                supplierId: formData.supplierId || undefined
            };

            const url = editingProduct
                ? `/api/inventory/internal-products/${editingProduct.id}`
                : '/api/inventory/internal-products';

            const res = await fetch(url, {
                method: editingProduct ? 'PUT' : 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                setShowModal(false);
                fetchProducts();
                showToast(editingProduct ? 'Component updated' : 'Component created', 'success');
            } else {
                const err = await res.json().catch(() => null);
                showToast(err?.error || 'Failed to save');
            }
        } catch (err) {
            Logger.error('Failed to save internal product', { error: err });
            showToast('Failed to save — network error');
        } finally {
            setIsSaving(false);
        }
    }

    async function handleDelete(product: InternalProduct) {
        if (!currentAccount || !token) return;

        const message = product.bomUsageCount && product.bomUsageCount > 0
            ? `This component is used in ${product.bomUsageCount} BOM(s). Delete anyway?`
            : `Delete "${product.name}"?`;

        if (!confirm(message)) return;

        try {
            const force = product.bomUsageCount && product.bomUsageCount > 0 ? '?force=true' : '';
            const res = await fetch(`/api/inventory/internal-products/${product.id}${force}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                fetchProducts();
                showToast('Component deleted', 'success');
            } else {
                const err = await res.json().catch(() => null);
                showToast(err?.error || 'Failed to delete');
            }
        } catch (err) {
            Logger.error('Failed to delete internal product', { error: err });
            showToast('Failed to delete — network error');
        }
    }

    const totalPages = Math.ceil(total / limit);

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex justify-between items-center">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input
                        type="text"
                        placeholder="Search components..."
                        className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500 w-64"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                <button
                    onClick={openCreateModal}
                    className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg hover:from-blue-700 hover:to-indigo-700 transition-all shadow-sm"
                >
                    <Plus size={18} />
                    Add Component
                </button>
            </div>

            {/* Table */}
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold">
                            <th className="px-6 py-4 w-16">Image</th>
                            <th className="px-6 py-4">Name</th>
                            <th className="px-6 py-4">SKU</th>
                            <th className="px-6 py-4">Stock</th>
                            {canViewCogs && <th className="px-6 py-4">COGS</th>}
                            <th className="px-6 py-4">Supplier</th>
                            <th className="px-6 py-4">BOM Usage</th>
                            <th className="px-6 py-4 text-center">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {isLoading ? (
                            <tr>
                                <td colSpan={8} className="p-12 text-center">
                                    <Loader2 className="animate-spin inline text-blue-600" />
                                </td>
                            </tr>
                        ) : products.length === 0 ? (
                            <tr>
                                <td colSpan={8} className="p-12 text-center text-gray-500">
                                    <div className="flex flex-col items-center gap-2">
                                        <Box size={48} className="text-gray-300" />
                                        <p>No internal components found.</p>
                                        <p className="text-sm">These are components used in BOMs that are not sold on WooCommerce.</p>
                                    </div>
                                </td>
                            </tr>
                        ) : (
                            products.map((product) => (
                                <tr key={product.id} className="hover:bg-gray-50 transition-colors">
                                    <td className="px-6 py-4">
                                        <div className="w-10 h-10 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 flex items-center justify-center">
                                            {product.mainImage ? (
                                                <img src={product.mainImage} alt="" className="w-full h-full object-cover" />
                                            ) : (
                                                <Package size={16} className="text-gray-400" />
                                            )}
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="font-medium text-gray-900">{product.name}</div>
                                        {product.binLocation && (
                                            <div className="text-xs text-gray-500">📍 {product.binLocation}</div>
                                        )}
                                    </td>
                                    <td className="px-6 py-4 text-sm font-mono text-gray-500">
                                        {product.sku || '-'}
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={`text-lg font-bold ${product.stockQuantity === 0 ? 'text-red-600' :
                                            product.stockQuantity < 10 ? 'text-amber-600' : 'text-gray-900'
                                            }`}>
                                            {product.stockQuantity}
                                        </span>
                                    </td>
                                    {canViewCogs && (
                                        <td className="px-6 py-4 text-sm text-gray-600">
                                            {product.cogs ? `$${product.cogs.toFixed(2)}` : '-'}
                                        </td>
                                    )}
                                    <td className="px-6 py-4 text-sm text-gray-600">
                                        {product.supplier ? (
                                            <span className="flex items-center gap-1">
                                                <Building2 size={14} className="text-gray-400" />
                                                {product.supplier.name}
                                            </span>
                                        ) : '-'}
                                    </td>
                                    <td className="px-6 py-4">
                                        {product.bomUsageCount && product.bomUsageCount > 0 ? (
                                            <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-purple-100 text-purple-700">
                                                {product.bomUsageCount} BOM{product.bomUsageCount > 1 ? 's' : ''}
                                            </span>
                                        ) : (
                                            <span className="text-xs text-gray-400">Unused</span>
                                        )}
                                    </td>
                                    <td className="px-6 py-4 text-center">
                                        <div className="flex items-center justify-center gap-1">
                                            <button
                                                onClick={() => openEditModal(product)}
                                                className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                                title="Edit"
                                            >
                                                <Edit2 size={16} />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(product)}
                                                className="p-2 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                                title="Delete"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
                {!isLoading && products.length > 0 && (
                    <Pagination
                        currentPage={page}
                        totalPages={totalPages}
                        onPageChange={setPage}
                        itemsPerPage={limit}
                        onItemsPerPageChange={(newLimit) => {
                            setLimit(newLimit);
                            setPage(1);
                        }}
                        allowItemsPerPage={true}
                    />
                )}
            </div>

            {/* Create/Edit Modal */}
            {showModal && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg mx-4 animate-in fade-in zoom-in-95 duration-200">
                        <div className="px-6 py-4 border-b border-gray-100">
                            <h2 className="text-lg font-semibold text-gray-900">
                                {editingProduct ? 'Edit Component' : 'Add Component'}
                            </h2>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Name *</label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                    placeholder="Component name"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">SKU</label>
                                    <input
                                        type="text"
                                        value={formData.sku}
                                        onChange={(e) => setFormData({ ...formData, sku: e.target.value })}
                                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                        placeholder="INT-001"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Bin Location</label>
                                    <input
                                        type="text"
                                        value={formData.binLocation}
                                        onChange={(e) => setFormData({ ...formData, binLocation: e.target.value })}
                                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                        placeholder="A1-B2"
                                    />
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Stock Quantity</label>
                                    <input
                                        type="number"
                                        value={formData.stockQuantity}
                                        onChange={(e) => setFormData({ ...formData, stockQuantity: Number(e.target.value) })}
                                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                        min="0"
                                    />
                                </div>
                                {canViewCogs && (
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">COGS ($)</label>
                                        <input
                                            type="number"
                                            value={formData.cogs}
                                            onChange={(e) => setFormData({ ...formData, cogs: e.target.value })}
                                            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                            min="0"
                                            step="0.01"
                                            placeholder="0.00"
                                        />
                                    </div>
                                )}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Supplier</label>
                                <select
                                    value={formData.supplierId}
                                    onChange={(e) => setFormData({ ...formData, supplierId: e.target.value })}
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                >
                                    <option value="">No supplier</option>
                                    {suppliers.map((s) => (
                                        <option key={s.id} value={s.id}>{s.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                                <textarea
                                    value={formData.description}
                                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                    rows={3}
                                    placeholder="Optional description..."
                                />
                            </div>
                        </div>
                        <div className="px-6 py-4 border-t border-gray-100 flex justify-end gap-3">
                            <button
                                onClick={() => setShowModal(false)}
                                className="px-4 py-2 text-gray-600 hover:text-gray-800 font-medium"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleSave}
                                disabled={isSaving || !formData.name.trim()}
                                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 flex items-center gap-2"
                            >
                                {isSaving && <Loader2 size={16} className="animate-spin" />}
                                {editingProduct ? 'Save Changes' : 'Create Component'}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </div>
    );
}

/**
 * POStatusStepper - Visual progress indicator for Purchase Order workflow
 * 
 * Shows the current status and progression through the PO lifecycle.
 */

import { FileText, ShoppingCart, Truck, CheckCircle2 } from 'lucide-react';

type POStatus = 'DRAFT' | 'ORDERED' | 'RECEIVED' | 'CANCELLED';

interface POStatusStepperProps {
    status: POStatus;
    onStatusChange?: (newStatus: POStatus) => void;
    disabled?: boolean;
}

const STEPS: { key: POStatus; label: string; icon: React.ReactNode }[] = [
    { key: 'DRAFT', label: 'Draft', icon: <FileText size={18} /> },
    { key: 'ORDERED', label: 'Ordered', icon: <ShoppingCart size={18} /> },
    { key: 'RECEIVED', label: 'Received', icon: <CheckCircle2 size={18} /> },
];

const STATUS_ORDER: POStatus[] = ['DRAFT', 'ORDERED', 'RECEIVED'];

export function POStatusStepper({ status, onStatusChange, disabled = false }: POStatusStepperProps) {
    const currentIndex = STATUS_ORDER.indexOf(status);
    const isCancelled = status === 'CANCELLED';

    if (isCancelled) {
        return (
            <div className="flex items-center gap-2 px-4 py-3 bg-red-50 border border-red-200 rounded-lg">
                <span className="text-red-600 font-medium">Order Cancelled</span>
            </div>
        );
    }

    return (
        <div
            className="flex items-center justify-between bg-gray-50 p-4 rounded-xl border border-gray-200"
            role="navigation"
            aria-label="Purchase order status progression"
        >
            {STEPS.map((step, index) => {
                const isCompleted = index < currentIndex;
                const isCurrent = index === currentIndex;
                const isUpcoming = index > currentIndex;
                const isClickable = !disabled && onStatusChange && (index === currentIndex + 1 || index === currentIndex);

                return (
                    <div key={step.key} className="flex items-center flex-1">
                        {/* Step Circle */}
                        <button
                            type="button"
                            disabled={!isClickable}
                            onClick={() => isClickable && onStatusChange?.(step.key)}
                            className={`
                                relative flex items-center justify-center w-10 h-10 rounded-full border-2 transition-all
                                ${isCompleted ? 'bg-green-500 border-green-500 text-white' : ''}
                                ${isCurrent ? 'bg-blue-500 border-blue-500 text-white ring-4 ring-blue-100' : ''}
                                ${isUpcoming ? 'bg-white border-gray-300 text-gray-400' : ''}
                                ${isClickable ? 'cursor-pointer hover:scale-110' : 'cursor-default'}
                            `}
                            title={isClickable ? `Change to ${step.label}` : undefined}
                            aria-label={`${step.label} ${isCurrent ? '(current)' : isCompleted ? '(completed)' : ''}`}
                            aria-current={isCurrent ? 'step' : undefined}
                        >
                            {step.icon}
                        </button>

                        {/* Label */}
                        <div className="ml-3 mr-4">
                            <p className={`text-sm font-medium ${isCurrent ? 'text-gray-900' : isCompleted ? 'text-green-600' : 'text-gray-400'}`}>
                                {step.label}
                            </p>
                            {isCurrent && (
                                <p className="text-xs text-blue-600">Current Status</p>
                            )}
                            {isCompleted && (
                                <p className="text-xs text-green-600">Completed</p>
                            )}
                        </div>

                        {/* Connector Line */}
                        {index < STEPS.length - 1 && (
                            <div className={`flex-1 h-1 rounded-full ${isCompleted ? 'bg-green-400' : 'bg-gray-200'}`} />
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { X, Save, Box, Loader2 } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface ProductEditorProps {
    productId: string | number; // WooId
    onClose: () => void;
}

export function ProductEditor({ productId, onClose }: ProductEditorProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [product, setProduct] = useState<any>(null);
    const [binLocation, setBinLocation] = useState('');

    useEffect(() => {
        if (!currentAccount) return;

        fetch(`/api/products/${productId}`, {
            headers: {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount.id
            }
        })
            .then(res => res.json())
            .then(data => {
                setProduct(data);
                setBinLocation(data.binLocation || '');
                setLoading(false);
            })
            .catch(err => {
                Logger.error('An error occurred', { error: err });
                setLoading(false);
                alert('Failed to load product');
                onClose();
            });
    }, [productId, currentAccount, token]);

    const handleSave = async () => {
        setSaving(true);
        try {
            const res = await fetch(`/api/products/${productId}`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify({ binLocation })
            });

            if (res.ok) {
                alert('Product saved!');
                onClose();
            } else {
                throw new Error('Failed to save');
            }
        } catch (error) {
            alert('Failed to save product');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 flex justify-end z-50">
            <div className="w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">

                {/* Header */}
                <div className="p-6 border-b flex justify-between items-center bg-gray-50">
                    <div>
                        <h2 className="text-xl font-bold text-gray-900">Edit Product</h2>
                        <p className="text-sm text-gray-500">Update product details and warehouse location</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full"><X size={20} /></button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                    {loading ? (
                        <div className="flex justify-center p-12">
                            <Loader2 className="animate-spin text-blue-600" size={32} />
                        </div>
                    ) : (
                        <>
                            {/* Product Info Card */}
                            <div className="flex gap-4 p-4 bg-gray-50 rounded-xl border border-gray-100">
                                <div className="w-16 h-16 bg-white rounded-lg border border-gray-200 flex items-center justify-center overflow-hidden">
                                    {product?.mainImage ? (
                                        <img src={product.mainImage} alt="" className="w-full h-full object-cover" referrerPolicy="no-referrer" />
                                    ) : (
                                        <Box className="text-gray-300" />
                                    )}
                                </div>
                                <div>
                                    <h3 className="font-semibold text-gray-900">{product?.name}</h3>
                                    <p className="text-sm text-gray-500 font-mono">SKU: {product?.sku || 'N/A'}</p>
                                    <p className="text-sm text-gray-500">ID: {product?.wooId}</p>
                                </div>
                            </div>

                            {/* Warehouse / Bin Location */}
                            <div className="space-y-2">
                                <label className="block text-sm font-medium text-gray-700">Bin Location</label>
                                <div className="relative">
                                    <Box className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                    <input
                                        type="text"
                                        value={binLocation}
                                        onChange={(e) => setBinLocation(e.target.value)}
                                        placeholder="e.g. A-12-3"
                                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500"
                                    />
                                </div>
                                <p className="text-xs text-gray-500">Enter the shelf or bin number where this product is stored.</p>
                            </div>

                        </>
                    )}
                </div>

                {/* Footer */}
                <div className="p-6 border-t bg-white flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-6 py-2 text-gray-600 font-medium hover:bg-gray-100 rounded-lg"
                        disabled={saving}
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={saving}
                        className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 shadow-md disabled:opacity-50"
                    >
                        {saving ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                        Save Changes
                    </button>
                </div>

            </div>
        </div>
    );
}

import { useState, useEffect, useMemo } from 'react';
import { Logger } from '../../utils/logger';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Plus, Loader2, FileText, Package, Clock, CheckCircle2, AlertCircle, ExternalLink } from 'lucide-react';

interface PurchaseOrder {
    id: string;
    orderNumber: string | null;
    status: string;
    totalAmount: string;
    supplier: {
        name: string;
    };
    orderDate: string | null;
    expectedDate: string | null;
    createdAt: string;
    trackingLink: string | null;
    items?: any[];
}

type StatusFilter = 'ALL' | 'DRAFT' | 'ORDERED' | 'RECEIVED' | 'CANCELLED';

const STATUS_TABS: { key: StatusFilter; label: string; icon: React.ReactNode }[] = [
    { key: 'ALL', label: 'All Orders', icon: <Package size={16} /> },
    { key: 'DRAFT', label: 'Drafts', icon: <FileText size={16} /> },
    { key: 'ORDERED', label: 'Ordered', icon: <Clock size={16} /> },
    { key: 'RECEIVED', label: 'Received', icon: <CheckCircle2 size={16} /> },
];

export function PurchaseOrderList() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [orders, setOrders] = useState<PurchaseOrder[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState<StatusFilter>('ALL');

    useEffect(() => {
        if (currentAccount) {
            fetchOrders();
        }
    }, [currentAccount, token]);

    async function fetchOrders() {
        if (!currentAccount || !token) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/inventory/purchase-orders`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setOrders(data);
            }
        } catch (error) {
            Logger.error('An error occurred', { error: error });
        } finally {
            setIsLoading(false);
        }
    }

    // Compute stats
    const stats = useMemo(() => {
        const now = new Date();
        const thisMonth = now.getMonth();
        const thisYear = now.getFullYear();

        const drafts = orders.filter(o => o.status === 'DRAFT').length;
        const ordered = orders.filter(o => o.status === 'ORDERED');
        const pendingValue = ordered.reduce((sum, o) => sum + (parseFloat(o.totalAmount) || 0), 0);
        const receivedThisMonth = orders.filter(o => {
            if (o.status !== 'RECEIVED') return false;
            const date = new Date(o.createdAt);
            return date.getMonth() === thisMonth && date.getFullYear() === thisYear;
        }).length;

        return { drafts, pendingOrders: ordered.length, pendingValue, receivedThisMonth };
    }, [orders]);

    /** Status priority: ORDERED first, DRAFT second, everything else last */
    const STATUS_PRIORITY: Record<string, number> = { ORDERED: 0, DRAFT: 1, RECEIVED: 2, CANCELLED: 3 };

    // Filter then sort by status priority → newest date first within each group
    const filteredOrders = useMemo(() => {
        const base = statusFilter === 'ALL' ? orders : orders.filter(o => o.status === statusFilter);

        return [...base].sort((a, b) => {
            const priorityA = STATUS_PRIORITY[a.status] ?? 99;
            const priorityB = STATUS_PRIORITY[b.status] ?? 99;
            if (priorityA !== priorityB) return priorityA - priorityB;

            // Within the same status group, sort by date descending
            const dateA = new Date(a.orderDate ?? a.createdAt).getTime();
            const dateB = new Date(b.orderDate ?? b.createdAt).getTime();
            return dateB - dateA;
        });
    }, [orders, statusFilter]);

    return (
        <div className="space-y-6">
            {/* Summary Cards */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="bg-gradient-to-br from-gray-50 to-white p-4 rounded-xl border border-gray-200 shadow-sm">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-gray-100 rounded-lg">
                            <FileText size={20} className="text-gray-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-gray-900">{stats.drafts}</p>
                            <p className="text-xs text-gray-500">Draft Orders</p>
                        </div>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-blue-50 to-white p-4 rounded-xl border border-blue-100 shadow-sm">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-100 rounded-lg">
                            <Clock size={20} className="text-blue-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-blue-900">{stats.pendingOrders}</p>
                            <p className="text-xs text-blue-600">Pending Delivery</p>
                        </div>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-amber-50 to-white p-4 rounded-xl border border-amber-100 shadow-sm">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-amber-100 rounded-lg">
                            <AlertCircle size={20} className="text-amber-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-amber-900">${stats.pendingValue.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 })}</p>
                            <p className="text-xs text-amber-600">Pending Value</p>
                        </div>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-green-50 to-white p-4 rounded-xl border border-green-100 shadow-sm">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-green-100 rounded-lg">
                            <CheckCircle2 size={20} className="text-green-600" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-green-900">{stats.receivedThisMonth}</p>
                            <p className="text-xs text-green-600">Received This Month</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Header with Tabs and Action */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div className="flex gap-1 bg-gray-100 p-1 rounded-lg">
                    {STATUS_TABS.map(tab => (
                        <button
                            key={tab.key}
                            onClick={() => setStatusFilter(tab.key)}
                            className={`flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium rounded-md transition-all ${statusFilter === tab.key
                                ? 'bg-white text-gray-900 shadow-sm'
                                : 'text-gray-600 hover:text-gray-900'
                                }`}
                        >
                            {tab.icon}
                            {tab.label}
                        </button>
                    ))}
                </div>

                <button
                    onClick={() => navigate('/inventory/purchase-orders/new')}
                    className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    <Plus size={18} />
                    New Purchase Order
                </button>
            </div>

            {/* Table */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold">
                            <th className="px-6 py-4">PO Number</th>
                            <th className="px-6 py-4">Supplier</th>
                            <th className="px-6 py-4">Status</th>
                            <th className="px-6 py-4">Date</th>
                            <th className="px-6 py-4">Expected</th>
                            <th className="px-6 py-4">Total</th>
                            <th className="px-6 py-4 text-center">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {isLoading ? (
                            <tr><td colSpan={7} className="p-12 text-center"><Loader2 className="animate-spin inline text-blue-600" /></td></tr>
                        ) : filteredOrders.length === 0 ? (
                            <tr><td colSpan={7} className="p-12 text-center text-gray-500">
                                <div className="flex flex-col items-center gap-2">
                                    <FileText size={48} className="text-gray-300" />
                                    <p>No {statusFilter !== 'ALL' ? statusFilter.toLowerCase() : ''} purchase orders found.</p>
                                </div>
                            </td></tr>
                        ) : (
                            filteredOrders.map((po) => (
                                <tr key={po.id} className="hover:bg-gray-50 transition-colors">
                                    <td className="px-6 py-4 font-medium text-gray-900">{po.orderNumber || po.id.substring(0, 8).toUpperCase()}</td>
                                    <td className="px-6 py-4 text-gray-600">{po.supplier?.name || 'Unknown'}</td>
                                    <td className="px-6 py-4">
                                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                                            ${po.status === 'DRAFT' ? 'bg-gray-100 text-gray-800' :
                                                po.status === 'ORDERED' ? 'bg-blue-100 text-blue-800' :
                                                    po.status === 'RECEIVED' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                                            {po.status}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-sm text-gray-500">
                                        {po.orderDate ? new Date(po.orderDate).toLocaleDateString() : '-'}
                                    </td>
                                    <td className="px-6 py-4 text-sm text-gray-500">
                                        {po.expectedDate ? new Date(po.expectedDate).toLocaleDateString() : '-'}
                                    </td>
                                    <td className="px-6 py-4 font-medium text-gray-900">
                                        {po.totalAmount ? `$${Number(po.totalAmount).toFixed(2)}` : '-'}
                                    </td>
                                    <td className="px-6 py-4 text-center">
                                        <div className="flex items-center justify-center gap-2">
                                            {po.trackingLink && (
                                                <a
                                                    href={po.trackingLink}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    onClick={(e) => e.stopPropagation()}
                                                    className="p-1.5 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-md transition-colors"
                                                    title="Track Shipment"
                                                >
                                                    <ExternalLink size={16} />
                                                </a>
                                            )}
                                            <button
                                                onClick={() => navigate(`/inventory/purchase-orders/${po.id}`)}
                                                className="text-blue-600 hover:text-blue-800 font-medium text-sm"
                                            >
                                                View
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Plus, Loader2, ChevronDown, ChevronRight, Pencil, Trash2, X, Check } from 'lucide-react';

interface SupplierItem {
    id: string;
    name: string;
    sku: string;
    cost: number;
    leadTime: number;
    moq: number;
}

interface Supplier {
    id: string;
    name: string;
    contactName?: string;
    email?: string;
    phone?: string;
    currency: string;
    leadTimeDefault?: number;
    leadTimeMin?: number;
    leadTimeMax?: number;
    paymentTerms?: string;
    items?: SupplierItem[];
}

/** Available currency options for suppliers */
const CURRENCY_OPTIONS = ['USD', 'EUR', 'GBP', 'AUD', 'CAD', 'NZD', 'CNY', 'JPY'] as const;

export function SuppliersList() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [loading, setLoading] = useState(true);
    const [expandedSupplier, setExpandedSupplier] = useState<string | null>(null);
    const [isCreating, setIsCreating] = useState(false);
    const [newSupplier, setNewSupplier] = useState({
        name: '', contactName: '', email: '', phone: '', currency: 'USD',
        leadTimeMin: '', leadTimeMax: '', paymentTerms: ''
    });

    // Edit State
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editData, setEditData] = useState<Partial<Supplier>>({});
    const [isSaving, setIsSaving] = useState(false);

    // Item Creation State
    const [addingItemTo, setAddingItemTo] = useState<string | null>(null);
    const [newItem, setNewItem] = useState({ name: '', sku: '', cost: '0', leadTime: '7', moq: '1' });

    useEffect(() => {
        if (currentAccount) fetchSuppliers();
    }, [currentAccount]);

    async function fetchSuppliers() {
        if (!currentAccount) return;
        setLoading(true);
        try {
            const res = await fetch('/api/inventory/suppliers', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            setSuppliers(data);
        } catch (error) {
            Logger.error('An error occurred', { error: error });
        } finally {
            setLoading(false);
        }
    }

    async function handleCreateSupplier(e: React.FormEvent) {
        e.preventDefault();
        try {
            const res = await fetch('/api/inventory/suppliers', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(newSupplier)
            });
            if (res.ok) {
                setIsCreating(false);
                setNewSupplier({
                    name: '', contactName: '', email: '', phone: '', currency: 'USD',
                    leadTimeMin: '', leadTimeMax: '', paymentTerms: ''
                });
                fetchSuppliers();
            }
        } catch (error) {
            alert('Failed to create supplier');
        }
    }

    async function handleUpdateSupplier() {
        if (!editingId) return;
        setIsSaving(true);
        try {
            const res = await fetch(`/api/inventory/suppliers/${editingId}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(editData)
            });
            if (res.ok) {
                setEditingId(null);
                setEditData({});
                fetchSuppliers();
            } else {
                alert('Failed to update supplier');
            }
        } catch (error) {
            alert('Failed to update supplier');
        } finally {
            setIsSaving(false);
        }
    }

    async function handleDeleteSupplier(id: string, name: string) {
        if (!confirm(`Delete supplier "${name}"? This action cannot be undone.`)) return;
        try {
            const res = await fetch(`/api/inventory/suppliers/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                }
            });
            if (res.ok) {
                fetchSuppliers();
            } else {
                alert('Failed to delete supplier. It may have linked items.');
            }
        } catch (error) {
            alert('Failed to delete supplier');
        }
    }

    function startEdit(supplier: Supplier) {
        setEditingId(supplier.id);
        setEditData({
            name: supplier.name,
            contactName: supplier.contactName || '',
            email: supplier.email || '',
            phone: supplier.phone || '',
            currency: supplier.currency,
            leadTimeMin: supplier.leadTimeMin,
            leadTimeMax: supplier.leadTimeMax,
            paymentTerms: supplier.paymentTerms || ''
        });
    }

    function cancelEdit() {
        setEditingId(null);
        setEditData({});
    }

    async function handleAddItem(e: React.FormEvent) {
        e.preventDefault();
        if (!addingItemTo) return;

        try {
            const res = await fetch(`/api/inventory/suppliers/${addingItemTo}/items`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(newItem)
            });
            if (res.ok) {
                setAddingItemTo(null);
                setNewItem({ name: '', sku: '', cost: '0', leadTime: '7', moq: '1' });
                fetchSuppliers();
            }
        } catch (error) {
            alert('Failed to add item');
        }
    }

    if (loading) return <div className="p-8 text-center"><Loader2 className="animate-spin inline text-blue-600" /></div>;

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center bg-gray-50 p-4 rounded-lg border border-gray-200">
                <h2 className="text-lg font-semibold text-gray-800">Supply Chain</h2>
                <button
                    onClick={() => setIsCreating(true)}
                    className="bg-blue-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition"
                >
                    <Plus size={16} /> Add Supplier
                </button>
            </div>

            {isCreating && (
                <div className="bg-white p-6 border border-blue-200 rounded-xl shadow-xs mb-6">
                    <h3 className="font-semibold mb-4">New Supplier</h3>
                    <form onSubmit={handleCreateSupplier} className="grid grid-cols-2 gap-4">
                        <input type="text" placeholder="Supplier Name" required className="border p-2 rounded-sm"
                            value={newSupplier.name} onChange={e => setNewSupplier({ ...newSupplier, name: e.target.value })} />
                        <input type="text" placeholder="Contact Name" className="border p-2 rounded-sm"
                            value={newSupplier.contactName} onChange={e => setNewSupplier({ ...newSupplier, contactName: e.target.value })} />
                        <input type="email" placeholder="Email" className="border p-2 rounded-sm"
                            value={newSupplier.email} onChange={e => setNewSupplier({ ...newSupplier, email: e.target.value })} />
                        <input type="tel" placeholder="Phone" className="border p-2 rounded-sm"
                            value={newSupplier.phone} onChange={e => setNewSupplier({ ...newSupplier, phone: e.target.value })} />
                        <select className="border p-2 rounded-sm" value={newSupplier.currency} onChange={e => setNewSupplier({ ...newSupplier, currency: e.target.value })}>
                            {CURRENCY_OPTIONS.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>

                        <div className="col-span-2 grid grid-cols-3 gap-4">
                            <input type="number" placeholder="Min Lead Time (Days)" className="border p-2 rounded-sm"
                                value={newSupplier.leadTimeMin} onChange={e => setNewSupplier({ ...newSupplier, leadTimeMin: e.target.value })} />
                            <input type="number" placeholder="Max Lead Time (Days)" className="border p-2 rounded-sm"
                                value={newSupplier.leadTimeMax} onChange={e => setNewSupplier({ ...newSupplier, leadTimeMax: e.target.value })} />
                            <input type="text" placeholder="Payment Terms (e.g. Net 30)" className="border p-2 rounded-sm"
                                value={newSupplier.paymentTerms} onChange={e => setNewSupplier({ ...newSupplier, paymentTerms: e.target.value })} />
                        </div>

                        <div className="col-span-2 flex justify-end gap-2 mt-2">
                            <button type="button" onClick={() => setIsCreating(false)} className="px-4 py-2 text-gray-500">Cancel</button>
                            <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-sm">CREATE</button>
                        </div>
                    </form>
                </div>
            )}

            <div className="space-y-4">
                {suppliers.map(supplier => (
                    <div key={supplier.id} className="bg-white border rounded-xl overflow-hidden shadow-xs">
                        <div
                            className="p-4 flex items-center justify-between cursor-pointer hover:bg-gray-50"
                            onClick={() => setExpandedSupplier(expandedSupplier === supplier.id ? null : supplier.id)}
                        >
                            <div className="flex items-center gap-3">
                                {expandedSupplier === supplier.id ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                                <div>
                                    <div className="font-medium text-gray-900">{supplier.name}</div>
                                    <div className="text-xs text-gray-500 mt-0.5 flex gap-3">
                                        <span>{supplier.currency}</span>
                                        <span>• {supplier.items?.length || 0} items</span>
                                        {supplier.paymentTerms && <span>• {supplier.paymentTerms}</span>}
                                        {(supplier.leadTimeMin || supplier.leadTimeMax) && (
                                            <span>• Lead: {supplier.leadTimeMin || 0} - {supplier.leadTimeMax || '?'} days</span>
                                        )}
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <span className="text-sm text-gray-500">{supplier.email || '-'}</span>
                                <button
                                    onClick={(e) => { e.stopPropagation(); startEdit(supplier); }}
                                    className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded transition"
                                    title="Edit Supplier"
                                >
                                    <Pencil size={16} />
                                </button>
                                <button
                                    onClick={(e) => { e.stopPropagation(); handleDeleteSupplier(supplier.id, supplier.name); }}
                                    className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded transition"
                                    title="Delete Supplier"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>

                        {/* Edit Form (inline) */}
                        {editingId === supplier.id && (
                            <div className="bg-blue-50 border-t border-blue-200 p-4">
                                <div className="flex items-center justify-between mb-3">
                                    <h4 className="font-semibold text-blue-900">Edit Supplier</h4>
                                    <button onClick={cancelEdit} className="text-gray-500 hover:text-gray-700">
                                        <X size={18} />
                                    </button>
                                </div>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                    <input type="text" placeholder="Name" className="border p-2 rounded-sm"
                                        value={editData.name || ''} onChange={e => setEditData({ ...editData, name: e.target.value })} />
                                    <input type="text" placeholder="Contact" className="border p-2 rounded-sm"
                                        value={editData.contactName || ''} onChange={e => setEditData({ ...editData, contactName: e.target.value })} />
                                    <input type="email" placeholder="Email" className="border p-2 rounded-sm"
                                        value={editData.email || ''} onChange={e => setEditData({ ...editData, email: e.target.value })} />
                                    <input type="tel" placeholder="Phone" className="border p-2 rounded-sm"
                                        value={editData.phone || ''} onChange={e => setEditData({ ...editData, phone: e.target.value })} />
                                    <select className="border p-2 rounded-sm" value={editData.currency || 'USD'} onChange={e => setEditData({ ...editData, currency: e.target.value })}>
                                        {CURRENCY_OPTIONS.map(c => <option key={c} value={c}>{c}</option>)}
                                    </select>
                                    <input type="number" placeholder="Min Lead (days)" className="border p-2 rounded-sm"
                                        value={editData.leadTimeMin || ''} onChange={e => setEditData({ ...editData, leadTimeMin: e.target.value ? parseInt(e.target.value) : undefined })} />
                                    <input type="number" placeholder="Max Lead (days)" className="border p-2 rounded-sm"
                                        value={editData.leadTimeMax || ''} onChange={e => setEditData({ ...editData, leadTimeMax: e.target.value ? parseInt(e.target.value) : undefined })} />
                                    <input type="text" placeholder="Payment Terms" className="border p-2 rounded-sm"
                                        value={editData.paymentTerms || ''} onChange={e => setEditData({ ...editData, paymentTerms: e.target.value })} />
                                </div>
                                <div className="flex justify-end gap-2 mt-3">
                                    <button onClick={cancelEdit} className="px-3 py-1.5 text-gray-600 text-sm">Cancel</button>
                                    <button
                                        onClick={handleUpdateSupplier}
                                        disabled={isSaving}
                                        className="px-4 py-1.5 bg-blue-600 text-white rounded-sm text-sm flex items-center gap-1 disabled:opacity-50"
                                    >
                                        {isSaving ? <Loader2 size={14} className="animate-spin" /> : <Check size={14} />}
                                        Save
                                    </button>
                                </div>
                            </div>
                        )}

                        {expandedSupplier === supplier.id && (
                            <div className="bg-gray-50 border-t p-4">
                                <table className="w-full text-sm">
                                    <thead>
                                        <tr className="text-left text-gray-500 border-b">
                                            <th className="pb-2">Material / Component</th>
                                            <th className="pb-2">SKU</th>
                                            <th className="pb-2">Cost</th>
                                            <th className="pb-2">Lead Time</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {supplier.items?.map(item => (
                                            <tr key={item.id} className="border-b last:border-0 border-gray-100">
                                                <td className="py-2 font-medium">{item.name}</td>
                                                <td className="py-2 font-mono text-xs">{item.sku || '-'}</td>
                                                <td className="py-2">{supplier.currency} {Number(item.cost).toFixed(2)}</td>
                                                <td className="py-2">{item.leadTime} days</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>

                                {addingItemTo === supplier.id ? (
                                    <form onSubmit={handleAddItem} className="mt-4 bg-white p-4 border rounded-sm shadow-xs">
                                        <h4 className="font-semibold mb-2">Add Material</h4>
                                        <div className="grid grid-cols-5 gap-2">
                                            <input className="border p-2 rounded-sm col-span-2" placeholder="Item Name" required
                                                value={newItem.name} onChange={e => setNewItem({ ...newItem, name: e.target.value })} />
                                            <input className="border p-2 rounded-sm" placeholder="SKU"
                                                value={newItem.sku} onChange={e => setNewItem({ ...newItem, sku: e.target.value })} />
                                            <input className="border p-2 rounded-sm" type="number" step="0.01" placeholder="Cost" required
                                                value={newItem.cost} onChange={e => setNewItem({ ...newItem, cost: e.target.value })} />
                                            <input className="border p-2 rounded-sm" type="number" placeholder="Lead Time (days)" required
                                                value={newItem.leadTime} onChange={e => setNewItem({ ...newItem, leadTime: e.target.value })} />
                                        </div>
                                        <div className="flex justify-end gap-2 mt-2">
                                            <button type="button" onClick={() => setAddingItemTo(null)} className="text-gray-500 text-sm">Cancel</button>
                                            <button type="submit" className="bg-green-600 text-white px-3 py-1 rounded-sm text-sm">Save Item</button>
                                        </div>
                                    </form>
                                ) : (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); setAddingItemTo(supplier.id); }}
                                        className="mt-4 text-blue-600 text-sm font-medium flex items-center gap-1 hover:underline"
                                    >
                                        <Plus size={14} /> Add Material to Catalog
                                    </button>
                                )}
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </div>
    );
}

