                                    src={user?.avatarUrl || (user?.email ? `https://api.dicebear.com/7.x/avataaars/svg?seed=${user.email}` : "https://api.dicebear.com/7.x/avataaars/svg?seed=fallback")}
                                    alt="User"
                                    className="w-full h-full object-cover"
                                />
