];

/** Why memo: Sidebar subscribes to many contexts; wrapping in memo ensures
 *  it only re-renders when its own props (`isOpen`, `onClose`, `isMobile`) change
 *  rather than on every parent re-render from DashboardLayout. */
export const Sidebar = memo(function Sidebar({ isOpen = true, onClose, isMobile = false }: SidebarProps) {
    const [collapsed, setCollapsed] = useState(false);
    const { currentAccount } = useAccount();
    const { user, token } = useAuth();
    const { socket } = useSocket();
    const { hasPermission } = usePermissions(); // Permission hook
    const { prefetch } = usePrefetch(); // Route prefetching for faster navigation
    const location = useLocation();

    /** Why useMemo: Permission filtering was running on every render (every route change).
     *  Permissions and nav items rarely change — only when user role or account changes. */
    const filteredNavItems = useMemo(() => {
        return navItems.filter(item => {
            if (item.label === 'Commerce') {
                const hasChild = item.children?.some(child => {
                    if (child.path === '/orders') return hasPermission('view_orders');
                    if (child.path === '/inventory' || child.path === '/inventory/forecasts' || child.path === '/inventory/bom-sync') return hasPermission('view_products');
                    if (child.path === '/customers' || child.path === '/customers/segments') return hasPermission('view_orders');
                    return true;
                });
                return hasChild;
            }
            if (item.label === 'Analytics') return hasPermission('view_finance');
            if (item.label === 'Growth') return hasPermission('view_marketing');
            if (item.label === 'Team') return hasPermission('view_orders');
            return true;
        }).map(item => {
            if (item.children) {
                return {
                    ...item,
                    children: item.children.filter(child => {
                        if (child.path === '/orders') return hasPermission('view_orders');
                        if (child.path === '/inventory' || child.path === '/inventory/forecasts' || child.path === '/inventory/bom-sync') return hasPermission('view_products');
                        if (child.path === '/customers' || child.path === '/customers/segments') return hasPermission('view_orders');
                        if (item.label === 'Analytics') return hasPermission('view_finance');
                        if (item.label === 'Growth') return hasPermission('view_marketing');
                        return true;
                    })
                };
            }
            return item;
        });
    }, [hasPermission]);

    // State for expanded groups
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);

    // State for unread inbox count
    const [hasUnread, setHasUnread] = useState(false);

    // Fetch unread conversations count and listen for new messages
    useEffect(() => {
        if (!currentAccount || !token) return;

        // Check for unread conversations count
        const checkUnread = async () => {
            try {
                const res = await fetch('/api/chat/unread-count', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const data = await res.json();
                    setHasUnread(data.count > 0);
                }
            } catch {
                // Silently fail
            }
        };

        checkUnread();

        // Listen for new messages via socket
        if (socket) {
            const handleNewMessage = () => {
                // Only set unread if not on inbox page
                if (!location.pathname.startsWith('/inbox')) {
                    setHasUnread(true);
                }
            };

            const handleConversationRead = () => {
                // Re-check unread count when a conversation is marked as read
                checkUnread();
            };

            socket.on('conversation:updated', handleNewMessage);
            socket.on('message:new', handleNewMessage);
            socket.on('conversation:read', handleConversationRead);

            return () => {
                socket.off('conversation:updated', handleNewMessage);
                socket.off('message:new', handleNewMessage);
                socket.off('conversation:read', handleConversationRead);
            };
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentAccount?.id, token, socket]);

    // Clear unread when on inbox page
    useEffect(() => {
        if (location.pathname.startsWith('/inbox')) {
            // Defer state update to avoid cascading renders
            const timeoutId = setTimeout(() => {
                setHasUnread(false);
            }, 0);
            return () => clearTimeout(timeoutId);
        }
    }, [location.pathname]);

    // Auto-expand groups based on active route
    useEffect(() => {
        const activeGroup = navItems.find(item =>
            item.type === 'group' && item.children?.some(child => location.pathname.startsWith(child.path))
        );
        if (activeGroup && !collapsed) {
            // Defer state update to avoid cascading renders
            const timeoutId = setTimeout(() => {
                // Use functional update to avoid dependency on expandedGroups
                setExpandedGroups(prev => {
                    if (!prev.includes(activeGroup.label)) {
                        return [...prev, activeGroup.label];
                    }
                    return prev;
                });
            }, 0);
            return () => clearTimeout(timeoutId);
        }
    }, [location.pathname, collapsed]);

    // Close drawer on navigation (mobile only)
    useEffect(() => {
        if (isMobile && onClose) {
            // Defer the close to avoid cascading renders
            const timeoutId = setTimeout(() => {
                onClose();
            }, 0);
            return () => clearTimeout(timeoutId);
        }
    }, [location.pathname, isMobile, onClose]);


    const toggleGroup = (label: string) => {
        if (collapsed && !isMobile) {
            setCollapsed(false);
            setExpandedGroups([label]);
        } else {
            setExpandedGroups(prev =>
                prev.includes(label)
                    ? prev.filter(l => l !== label)
                    : [...prev, label]
            );
        }
    };

    const logoUrl = currentAccount?.appearance?.logoUrl;
    const appName = currentAccount?.appearance?.appName || 'OverSeek';
    const primaryColor = currentAccount?.appearance?.primaryColor || '#2563eb';

    // Shared sidebar content - extracted to avoid duplication
    const sidebarContent = (
        <>
            <div className="flex-col px-3 pt-4 pb-2">
                {/* Whitelabel Logo */}
                {logoUrl && (
                    <div className={cn("mb-4 flex justify-center", (collapsed && !isMobile) ? "px-0" : "px-2")}>
                        <img src={logoUrl} alt={appName} className="max-h-8 object-contain" />
                    </div>
                )}

                {/* Account Switcher or Default Logo */}
                {(!collapsed || isMobile) ? (
                    <AccountSwitcher />
                ) : (
                    // Only show default 'O' if no logo is provided
                    !logoUrl && (
                        <div
                            className="h-10 w-10 rounded-sm flex items-center justify-center text-white font-bold mx-auto mb-4"
                            style={{ backgroundColor: primaryColor }}
                        >
                            {appName.charAt(0)}
                        </div>
                    )
                )}
            </div>

            <div className="flex-1 overflow-y-auto py-4 px-3 space-y-1 no-scrollbar">
                {filteredNavItems.map((item, index) => {
                    if (item.type === 'link') {
                        const isInbox = item.label === 'Inbox';
                        return (
                            <NavLink
                                key={item.path}
                                to={item.path!}
                                onMouseEnter={() => prefetch(item.path!)}
                                onFocus={() => prefetch(item.path!)}
                                className={({ isActive }) => cn(
                                    "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                                    isActive
                                        ? "bg-gradient-to-r from-blue-500/10 to-violet-500/10 text-blue-600 font-medium shadow-sm dark:from-blue-500/20 dark:to-violet-500/20"
                                        : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                                )}
                            >
                                <div className="relative">
                                    <item.icon size={22} strokeWidth={1.5} />
                                    {/* Notification dot for Inbox */}
                                    {isInbox && hasUnread && (
                                        <span className="absolute -top-1 -right-1 h-2.5 w-2.5 bg-red-500 rounded-full ring-2 ring-white" />
                                    )}
                                </div>
                                {(!collapsed || isMobile) && <span>{item.label}</span>}
                                {collapsed && !isMobile && (
                                    <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                                        {item.label}
                                        {isInbox && hasUnread && <span className="ml-1 text-red-400">•</span>}
                                    </div>
                                )}
                            </NavLink>
                        );
                    }


                    // Group Item
                    const isExpanded = expandedGroups.includes(item.label);
                    const isActiveGroup = item.children?.some(child => location.pathname.startsWith(child.path));

                    return (
                        <div key={item.label} className="mb-1">
                            <button
                                onClick={() => toggleGroup(item.label)}
                                className={cn(
                                    "w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                                    isActiveGroup && !isExpanded
                                        ? "bg-gradient-to-r from-blue-500/10 to-violet-500/10 text-blue-600 dark:from-blue-500/20 dark:to-violet-500/20"
                                        : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                                )}
                            >
                                <item.icon size={22} strokeWidth={1.5} className={cn(isActiveGroup ? "text-blue-600" : "")} />
                                {(!collapsed || isMobile) && (
                                    <>
                                        <span className="flex-1 text-left font-medium text-sm">{item.label}</span>
                                        <ChevronDown
                                            size={16}
                                            className={cn("transition-transform duration-200", isExpanded ? "transform rotate-180" : "")}
                                        />
                                    </>
                                )}

                                {/* Collapsed Tooltip/Popover preview */}
                                {collapsed && !isMobile && (
                                    <div className="absolute left-full ml-2 top-0 bg-white border border-gray-200 shadow-lg rounded-lg p-2 min-w-[160px] opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none group-hover:pointer-events-auto">
                                        <div className="font-semibold text-xs text-gray-400 mb-2 px-2 uppercase">{item.label}</div>
                                        {item.children?.map(child => (
                                            <div key={child.path} className="flex items-center gap-2 px-2 py-1.5 text-sm text-gray-600">
                                                <child.icon size={16} />
                                                <span>{child.label}</span>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </button>

                            {/* Expanded Children (Only when not collapsed or on mobile) */}
                            {(!collapsed || isMobile) && isExpanded && (
                                <div className="mt-1 ml-4 border-l-2 border-slate-200/60 dark:border-slate-600/40 pl-2 space-y-0.5">
                                    {item.children?.map(child => (
                                        <NavLink
                                            key={child.path}
                                            to={child.path}
                                            end
                                            className={({ isActive }) => cn(
                                                "flex items-center gap-3 px-3 py-2 rounded-lg transition-all duration-200 text-sm",
                                                isActive
                                                    ? "bg-blue-500/10 text-blue-600 font-medium dark:bg-blue-500/20"
                                                    : "text-slate-500 hover:bg-slate-100/80 hover:text-slate-800 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                                            )}
                                        >
                                            <child.icon size={18} strokeWidth={1.5} />
                                            <span>{child.label}</span>
                                        </NavLink>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}

                {user?.isSuperAdmin && (
                    <div className="mt-4 pt-4 border-t border-slate-200/60 dark:border-slate-600/40 space-y-1">
                        <NavLink
                            to="/admin"
                            className={({ isActive }) => cn(
                                "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative",
                                isActive
                                    ? "bg-gradient-to-r from-slate-800 to-slate-700 text-white font-medium shadow-lg shadow-slate-800/25"
                                    : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                            )}
                        >
                            <ShieldAlert size={22} strokeWidth={1.5} />
                            {(!collapsed || isMobile) && <span>Super Admin</span>}

                            {collapsed && !isMobile && (
                                <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                                    Super Admin
                                </div>
                            )}
                        </NavLink>
                        <NavLink
                            to="/admin/diagnostics"
                            className={({ isActive }) => cn(
                                "flex items-center gap-3 px-3 py-2 rounded-xl transition-all duration-200 group relative text-sm",
                                isActive
                                    ? "bg-gradient-to-r from-emerald-500/10 to-teal-500/10 text-emerald-600 font-medium"
                                    : "text-slate-500 hover:bg-slate-100/80 hover:text-slate-700 dark:text-slate-500 dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                            )}
                        >
                            <Activity size={18} strokeWidth={1.5} />
                            {(!collapsed || isMobile) && <span>System Health</span>}

                            {collapsed && !isMobile && (
                                <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                                    System Health
                                </div>
                            )}
                        </NavLink>
                    </div>
                )}
            </div>

            <div className="mt-auto px-3 pb-3 space-y-2 border-t border-slate-200/60 dark:border-slate-600/40 pt-3">
                {/* Settings Link (Pinned Bottom) */}
                <NavLink
                    to="/settings"
                    className={({ isActive }) => cn(
                        "flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group relative mb-2",
                        isActive
                            ? "bg-gradient-to-r from-blue-500/10 to-violet-500/10 text-blue-600 font-medium dark:from-blue-500/20 dark:to-violet-500/20"
                            : "text-slate-600 hover:bg-slate-100/80 hover:text-slate-900 dark:text-slate-400 dark:hover:bg-slate-700/50 dark:hover:text-slate-200"
                    )}
                >
                    <Settings size={22} strokeWidth={1.5} />
                    {(!collapsed || isMobile) && <span>Settings</span>}
                    {collapsed && !isMobile && (
                        <div className="absolute left-full ml-2 px-2 py-1 bg-gray-900 text-white text-xs rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-50 pointer-events-none">
                            Settings
                        </div>
                    )}
                </NavLink>

                <SidebarSyncStatus collapsed={collapsed && !isMobile} />

                {/* Collapse button (desktop only) */}
                {!isMobile && (
                    <button
                        onClick={() => setCollapsed(!collapsed)}
                        className="w-full flex items-center justify-center gap-2 p-2 text-slate-400 hover:bg-slate-100/80 hover:text-slate-600 rounded-xl transition-all duration-200 text-sm dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                    >
                        {collapsed ? <ChevronRight size={18} /> : <><ChevronLeft size={18} /><span>Collapse</span></>}
                    </button>
                )}
            </div>
        </>
    );

    // Mobile: render as fixed overlay drawer
    if (isMobile) {
        return (
            <>
                {/* Backdrop with blur */}
                {isOpen && (
                    <div
                        className="fixed inset-0 bg-slate-900/30 backdrop-blur-sm z-40 transition-opacity duration-300"
                        onClick={onClose}
                    />
                )}
                <aside
                    className={cn(
                        "fixed inset-y-0 left-0 w-72 flex flex-col z-50 transition-transform duration-300 ease-out",
                        "bg-gradient-to-b from-white to-slate-50 dark:from-slate-900 dark:to-slate-950",
                        "border-r border-slate-200/80 dark:border-slate-700/50",
                        "shadow-2xl shadow-slate-900/10 dark:shadow-slate-900/50",
                        isOpen ? "translate-x-0" : "-translate-x-full"
                    )}
                >
                    {/* Close button for mobile */}
                    <button
                        onClick={onClose}
                        className="absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-xl z-10 transition-all duration-200 dark:hover:bg-slate-700/50 dark:hover:text-slate-300"
                    >
                        <X size={20} />
                    </button>
                    {sidebarContent}
                </aside>
            </>
        );
    }

    // Desktop: render as sticky sidebar (CSS hides on mobile via hidden lg:flex)
    return (
        <aside
            className={cn(
                "h-screen sticky top-0 transition-all duration-300 flex-col z-50",
                "bg-gradient-to-b from-white via-white to-slate-50/80 dark:from-slate-900 dark:via-slate-900 dark:to-slate-950",
                "border-r border-slate-200/80 dark:border-slate-700/50",
                "hidden lg:flex", // Critical: CSS-hide on mobile
                collapsed ? "w-20" : "w-64"
            )}
        >
            {sidebarContent}
        </aside>
    );
});

/**
 * Actionable Change Card
 * 
 * Displays detailed actionable recommendations in the bottom grid section.
 * Shows platform, campaign type, score, headline, metrics, and action buttons.
 */

import {
    ArrowRight,
    Eye,
    CheckCircle2
} from 'lucide-react';
import { ActionableRecommendation, isBudgetAction, isKeywordAction } from '../../types/ActionableTypes';

interface ActionableChangeCardProps {
    recommendation: ActionableRecommendation;
    onImplementationGuide: () => void;
    onApply: () => void;
}

/**
 * Get platform badge configuration
 */
function getPlatformConfig(platform: string): { letter: string; bg: string; text: string } {
    switch (platform) {
        case 'google':
            return { letter: 'G', bg: 'bg-gray-100', text: 'text-gray-700' };
        case 'meta':
            return { letter: 'M', bg: 'bg-blue-100', text: 'text-blue-700' };
        default:
            return { letter: 'G', bg: 'bg-gray-100', text: 'text-gray-600' };
    }
}

/**
 * Get campaign type from recommendation
 */
function getCampaignType(rec: ActionableRecommendation): string {
    if (rec.tags?.includes('search')) return 'SEARCH';
    if (rec.tags?.includes('shopping')) return 'SHOPPING';
    if (rec.tags?.includes('pmax')) return 'PMAX';
    if (rec.category === 'creative') return 'CREATIVE';
    if (rec.category === 'budget') return 'BUDGET';
    if (rec.category === 'audience') return 'AUDIENCE';
    return rec.category.toUpperCase();
}

/**
 * Get score color based on value
 */
function getScoreColor(score: number): string {
    if (score >= 80) return 'text-emerald-600';
    if (score >= 60) return 'text-blue-600';
    if (score >= 40) return 'text-amber-600';
    return 'text-gray-500';
}

/**
 * Extract key metrics from recommendation for display
 */
function extractMetrics(rec: ActionableRecommendation): { label: string; value: string; highlight?: boolean }[] {
    const metrics: { label: string; value: string; highlight?: boolean }[] = [];
    const action = rec.action;
    const details = rec.implementationDetails;

    if (isBudgetAction(action)) {
        if (action.actionType === 'budget_increase' || action.actionType === 'budget_decrease') {
            metrics.push({ label: 'Current Budget', value: `$${action.currentBudget.toFixed(0)}` });
            metrics.push({ label: 'Suggested Budget', value: `$${action.suggestedBudget.toFixed(0)}`, highlight: true });
            metrics.push({ label: 'Change', value: `${action.changePercent > 0 ? '+' : ''}${action.changePercent}%` });
        }
    }

    if (isKeywordAction(action)) {
        metrics.push({ label: 'Keyword', value: `"${action.keyword}"` });
        metrics.push({ label: 'Match Type', value: action.matchType });
        metrics.push({ label: 'Suggested CPC', value: `$${action.suggestedCpc.toFixed(2)}`, highlight: true });
    }

    // Add from implementation details
    if (details?.budgetSpec) {
        if (metrics.length === 0) {
            metrics.push({ label: 'Daily Budget', value: `$${details.budgetSpec.dailyBudget}` });
        }
        if (details.budgetSpec.targetRoas) {
            metrics.push({ label: 'Target ROAS', value: `${details.budgetSpec.targetRoas}x`, highlight: true });
        }
    }

    if (details?.suggestedKeywords && details.suggestedKeywords.length > 0) {
        metrics.push({ label: 'Keywords', value: `${details.suggestedKeywords.length} suggested` });
    }

    if (details?.difficulty) {
        const diffLabel = details.difficulty.charAt(0).toUpperCase() + details.difficulty.slice(1);
        metrics.push({ label: 'Difficulty', value: diffLabel });
    }

    // Fill remaining slots with data points
    if (metrics.length < 3 && rec.dataPoints.length > 0) {
        for (const dp of rec.dataPoints) {
            if (metrics.length >= 3) break;
            const parts = dp.split(':');
            if (parts.length === 2) {
                metrics.push({ label: parts[0].trim(), value: parts[1].trim() });
            }
        }
    }

    return metrics.slice(0, 4);
}

export function ActionableChangeCard({
    recommendation,
    onImplementationGuide,
    onApply
}: ActionableChangeCardProps) {
    const platformConfig = getPlatformConfig(recommendation.platform === 'both' ? 'google' : recommendation.platform);
    const campaignType = getCampaignType(recommendation);
    const metrics = extractMetrics(recommendation);
    const hasGuide = !!recommendation.implementationDetails;

    return (
        <div className="bg-white rounded-2xl border border-gray-200 p-5 hover:shadow-lg hover:border-gray-300 transition-all">
            {/* Header */}
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <span className={`w-6 h-6 rounded-full ${platformConfig.bg} flex items-center justify-center text-xs font-bold ${platformConfig.text}`}>
                        {platformConfig.letter}
                    </span>
                    <span className="text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {campaignType}
                    </span>
                </div>
                <span className={`text-sm font-bold ${getScoreColor(recommendation.confidence)}`}>
                    Score: {recommendation.confidence}
                </span>
            </div>

            {/* Headline */}
            <h3 className="font-bold text-gray-900 mb-4 line-clamp-2">
                {recommendation.headline.replace(/^[^\w]+/, '')}
            </h3>

            {/* Metrics Grid */}
            {metrics.length > 0 && (
                <div className="grid grid-cols-2 gap-x-4 gap-y-2 mb-5">
                    {metrics.map((metric, idx) => (
                        <div key={idx} className="flex justify-between items-baseline">
                            <span className="text-sm text-gray-500">{metric.label}</span>
                            <span className={`text-sm font-semibold ${metric.highlight ? 'text-emerald-600' : 'text-gray-900'}`}>
                                {metric.value}
                            </span>
                        </div>
                    ))}
                </div>
            )}

            {/* Action Button - Always opens guide modal, which handles both cases */}
            <button
                onClick={onImplementationGuide}
                className="w-full py-3 px-4 rounded-xl bg-gray-100 hover:bg-gray-200 text-gray-700 font-medium transition-colors flex items-center justify-center gap-2"
            >
                {hasGuide ? 'Implementation Guide' : 'View Details'}
                {hasGuide ? <ArrowRight className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
        </div>
    );
}

import {
    TrendingUp,
    TrendingDown,
    DollarSign,
    Search,
    ShoppingBag,
    Target,
    ArrowRight,
    Check,
    X,
    Calendar,
    AlertTriangle,
    MinusCircle
} from 'lucide-react';
import {
    ActionableRecommendation,
    BudgetAction,
    KeywordAction,
    ProductAction,
    isBudgetAction,
    isKeywordAction,
    isProductAction
} from '../../types/ActionableTypes';

interface ActionableRecommendationCardProps {
    recommendation: ActionableRecommendation;
    onApply?: (recommendation: ActionableRecommendation) => void;
    onDismiss?: (recommendation: ActionableRecommendation) => void;
    onSchedule?: (recommendation: ActionableRecommendation) => void;
}

export function ActionableRecommendationCard({
    recommendation,
    onApply,
    onDismiss,
    onSchedule
}: ActionableRecommendationCardProps) {
    const { action, headline, explanation, dataPoints, priority } = recommendation;

    const getIcon = () => {
        if (isBudgetAction(action)) return <DollarSign className="w-5 h-5" />;
        if (isKeywordAction(action)) return <Search className="w-5 h-5" />;
        if (isProductAction(action)) return <ShoppingBag className="w-5 h-5" />;
        return <Target className="w-5 h-5" />;
    };

    const getColors = () => {
        if (priority === 1) return 'bg-red-50 border-red-200 text-red-700 hover:bg-red-100';
        if (isBudgetAction(action) && action.changeAmount > 0) return 'bg-green-50 border-green-200 text-green-700 hover:bg-green-100';
        if (isBudgetAction(action) && action.changeAmount < 0) return 'bg-amber-50 border-amber-200 text-amber-700 hover:bg-amber-100';
        return 'bg-blue-50 border-blue-200 text-blue-700 hover:bg-blue-100';
    };

    const getImpactText = () => {
        if (!recommendation.estimatedImpact) return null;
        const { revenueChange, roasChange, spendChange } = recommendation.estimatedImpact;

        if (revenueChange) return `+${revenueChange.toLocaleString('en-US', { style: 'currency', currency: 'USD' })} est. revenue`;
        if (roasChange) return `+${roasChange.toFixed(1)}x est. ROAS`;
        if (spendChange && spendChange < 0) return `${spendChange.toLocaleString('en-US', { style: 'currency', currency: 'USD' })} spend savings`;
        return null;
    };

    const renderActionDetails = () => {
        if (isBudgetAction(action)) {
            return (
                <div className="mt-3 flex items-center gap-4 text-sm">
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Current</span>
                        <span className="font-mono text-gray-700">${action.currentBudget.toFixed(2)}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Suggested</span>
                        <span className="font-mono font-bold text-green-600">${action.suggestedBudget.toFixed(2)}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Change</span>
                        <span className={`font-mono font-bold ${action.changeAmount > 0 ? 'text-green-600' : 'text-amber-600'}`}>
                            {action.changeAmount > 0 ? '+' : ''}{action.changeAmount.toFixed(0)} (${Math.abs(action.changePercent)}%)
                        </span>
                    </div>
                </div>
            );
        }

        if (isKeywordAction(action)) {
            return (
                <div className="mt-3 flex items-center gap-4 text-sm">
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Keyword</span>
                        <span className="font-mono text-gray-700 border px-1 rounded bg-gray-50">{action.keyword}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Match</span>
                        <span className="text-gray-700">{action.matchType}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Max CPC</span>
                        <span className="font-mono font-bold text-blue-600">${action.suggestedCpc.toFixed(2)}</span>
                    </div>
                </div>
            );
        }

        if (isProductAction(action)) {
            return (
                <div className="mt-3 flex items-center gap-4 text-sm">
                    <div className="flex flex-col">
                        <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Velocity</span>
                        <span className="font-mono text-gray-700">{action.salesVelocity?.toFixed(1)}/day</span>
                    </div>
                    {action.margin && (
                        <div className="flex flex-col">
                            <span className="text-gray-500 uppercase text-xs font-bold tracking-wider">Margin</span>
                            <span className="font-mono text-green-600">{action.margin.toFixed(0)}%</span>
                        </div>
                    )}
                </div>
            );
        }
        return null;
    };

    return (
        <div className="group relative bg-white/80 backdrop-blur-xl border border-white/20 shadow-sm hover:shadow-md rounded-2xl p-5 transition-all duration-300">
            {/* Glassmorphism gradient glow on hover */}
            <div className={`absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-5 transition-opacity duration-300 ${getColors().split(' ')[0]}`}></div>

            <div className="relative flex justify-between items-start gap-4">
                <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                        <div className={`p-2 rounded-lg ${getColors()}`}>
                            {getIcon()}
                        </div>
                        <span className="text-xs font-bold uppercase tracking-wider text-gray-400">
                            {recommendation.platform} • {recommendation.category}
                        </span>
                        {priority === 1 && (
                            <span className="bg-red-100 text-red-700 text-xs px-2 py-0.5 rounded-full font-bold flex items-center gap-1">
                                <AlertTriangle className="w-3 h-3" /> Urgent
                            </span>
                        )}
                        {getImpactText() && (
                            <span className="bg-green-100 text-green-700 text-xs px-2 py-0.5 rounded-full font-bold flex items-center gap-1">
                                <TrendingUp className="w-3 h-3" /> {getImpactText()}
                            </span>
                        )}
                    </div>

                    <h3 className="text-lg font-bold text-gray-900 leading-tight mb-1">
                        {headline}
                    </h3>

                    <p className="text-gray-600 text-sm leading-relaxed mb-3">
                        {explanation}
                    </p>

                    {/* Data Points */}
                    {dataPoints.length > 0 && (
                        <div className="flex flex-wrap gap-2 mt-2">
                            {dataPoints.map((dp, idx) => (
                                <span key={idx} className="inline-flex items-center px-2 py-1 rounded bg-gray-100 text-gray-600 text-xs font-medium">
                                    {dp}
                                </span>
                            ))}
                        </div>
                    )}

                    {renderActionDetails()}
                </div>

                {/* Action Buttons */}
                <div className="flex flex-col gap-2 min-w-[120px]">
                    <button
                        onClick={() => onApply?.(recommendation)}
                        className="w-full py-2 px-3 bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold rounded-lg shadow-sm transition-colors flex items-center justify-center gap-2"
                    >
                        <Check className="w-4 h-4" /> Apply
                    </button>
                    {isBudgetAction(action) && (
                        <button
                            onClick={() => onSchedule?.(recommendation)}
                            className="w-full py-2 px-3 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 text-sm font-medium rounded-lg transition-colors flex items-center justify-center gap-2"
                        >
                            <Calendar className="w-4 h-4" /> Schedule
                        </button>
                    )}
                    <button
                        onClick={() => onDismiss?.(recommendation)}
                        className="w-full py-2 px-3 text-gray-400 hover:text-gray-600 hover:bg-gray-50 text-sm font-medium rounded-lg transition-colors flex items-center justify-center gap-2"
                    >
                        <X className="w-4 h-4" /> Dismiss
                    </button>
                </div>
            </div>

            {/* Confidence indicator */}
            <div className="absolute top-4 right-4" title={`Confidence: ${recommendation.confidence}%`}>
                <div className="relative w-8 h-8 flex items-center justify-center">
                    <svg className="w-full h-full transform -rotate-90">
                        <circle
                            cx="16"
                            cy="16"
                            r="14"
                            className="stroke-gray-100"
                            strokeWidth="3"
                            fill="none"
                        />
                        <circle
                            cx="16"
                            cy="16"
                            r="14"
                            className={`${recommendation.confidence > 80 ? 'stroke-green-500' : 'stroke-blue-500'}`}
                            strokeWidth="3"
                            fill="none"
                            strokeDasharray={88}
                            strokeDashoffset={88 - (88 * recommendation.confidence) / 100}
                        />
                    </svg>
                    <span className="absolute text-[10px] font-bold text-gray-500">
                        {recommendation.confidence}
                    </span>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Lightbulb, Loader2 } from 'lucide-react';
import { Modal } from '../ui/Modal';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface AdContextModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSaved?: () => void;
}

/**
 * Modal for providing additional business context to AI ad suggestions.
 * Context is saved per-account and used by the AdOptimizer.
 */
export function AdContextModal({ isOpen, onClose, onSaved }: AdContextModalProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [context, setContext] = useState('');
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (isOpen && currentAccount) {
            fetchContext();
        }
    }, [isOpen, currentAccount]);

    async function fetchContext() {
        setLoading(true);
        setError(null);
        try {
            const res = await fetch('/api/dashboard/ad-suggestions/context', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                setContext(data.context || '');
            }
        } catch (err) {
            Logger.error('Failed to fetch context', { error: err });
        } finally {
            setLoading(false);
        }
    }

    async function handleSave() {
        setSaving(true);
        setError(null);
        try {
            const res = await fetch('/api/dashboard/ad-suggestions/context', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({ context })
            });

            if (res.ok) {
                onSaved?.();
                onClose();
            } else {
                const data = await res.json();
                setError(data.error || 'Failed to save');
            }
        } catch (err) {
            setError('Failed to save context');
        } finally {
            setSaving(false);
        }
    }

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-purple-500 rounded-lg">
                        <Lightbulb size={20} className="text-white" />
                    </div>
                    <div>
                        <div className="font-semibold text-gray-900">Add Business Context</div>
                        <p className="text-sm text-gray-500 font-normal">Help AI give smarter suggestions</p>
                    </div>
                </div>
            }
            maxWidth="max-w-lg"
        >
            {loading ? (
                <div className="flex justify-center py-8">
                    <Loader2 className="w-8 h-8 animate-spin text-purple-500" />
                </div>
            ) : (
                <>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                        Your Notes & Context
                    </label>
                    <textarea
                        value={context}
                        onChange={(e) => setContext(e.target.value)}
                        placeholder="E.g., We're running a 30% off sale next week on summer products. Focus on our new arrivals. Our best margin is on jewelry..."
                        className="w-full h-40 px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-purple-500 resize-none text-gray-800 placeholder:text-gray-400"
                        maxLength={1000}
                    />
                    <p className="text-xs text-gray-400 mt-2 text-right">
                        {context.length}/1000 characters
                    </p>

                    <div className="mt-4 p-4 bg-purple-50 rounded-lg border border-purple-100">
                        <h4 className="text-sm font-medium text-purple-800 mb-2">💡 Tips for better suggestions</h4>
                        <ul className="text-sm text-purple-700 space-y-1">
                            <li>• Mention upcoming sales or promotions</li>
                            <li>• Note seasonal priorities (e.g., "Push winter coats")</li>
                            <li>• Share margin preferences ("Focus on high-margin items")</li>
                            <li>• Flag products to avoid ("Don't promote discontinued line")</li>
                        </ul>
                    </div>

                    {error && (
                        <p className="mt-4 text-sm text-red-600">{error}</p>
                    )}
                </>
            )}

            {/* Footer */}
            <div className="flex justify-end gap-3 pt-4 mt-4 border-t">
                <button
                    onClick={onClose}
                    className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                    disabled={saving}
                >
                    Cancel
                </button>
                <button
                    onClick={handleSave}
                    disabled={loading || saving}
                    className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                >
                    {saving && <Loader2 size={16} className="animate-spin" />}
                    Save Context
                </button>
            </div>
        </Modal>
    );
}

/**
 * Ad Intelligence Panel
 *
 * Displays the SC↔Ads correlation data: cannibalization, organic-only
 * keywords, and negative keyword suggestions. Uses skeleton-first rendering
 * for instant perceived load.
 */

import { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Skeleton, SkeletonText } from '../ui/Skeleton';
import {
    AlertTriangle,
    TrendingUp,
    Ban,
    Zap,
    ArrowRight,
    ChevronDown,
    ChevronUp,
    Loader2,
    Search,
    DollarSign
} from 'lucide-react';
import { Logger } from '../../utils/logger';

/* ────────── Types (mirrors server response shapes) ────────── */

interface IntelligenceSummary {
    overlapCount: number;
    organicOnlyCount: number;
    estimatedWastedSpend: number;
    estimatedUntappedValue: number;
    cannibalizationCount: number;
    negativeCandidates: number;
    estimatedMonthlySavings: number;
    hasData: boolean;
}

interface OverlapQuery {
    query: string;
    organic: { clicks: number; impressions: number; ctr: number; position: number };
    paid: { clicks: number; impressions: number; spend: number; cpc: number; conversions: number; roas: number };
    estimatedWastedSpend: number;
    cannibalizationScore: number;
}

interface OrganicOnlyQuery {
    query: string;
    clicks: number;
    impressions: number;
    ctr: number;
    position: number;
    estimatedPaidValue: number;
}

interface Correlation {
    overlap: OverlapQuery[];
    organicOnly: OrganicOnlyQuery[];
    paidOnlyCount: number;
    summary: {
        totalOrganicQueries: number;
        totalPaidKeywords: number;
        overlapCount: number;
        organicOnlyCount: number;
        estimatedTotalWastedSpend: number;
        estimatedUntappedValue: number;
    };
}

/* ────────── Sub-components ───────────────────────────────── */

function SummaryCards({ data }: { data: IntelligenceSummary }) {
    const cards = [
        { label: 'Cannibalized Keywords', value: data.cannibalizationCount, icon: AlertTriangle, color: 'text-amber-400', bg: 'bg-amber-500/10' },
        { label: 'Est. Wasted Spend/mo', value: `$${data.estimatedWastedSpend.toFixed(0)}`, icon: DollarSign, color: 'text-red-400', bg: 'bg-red-500/10' },
        { label: 'Organic Opportunities', value: data.organicOnlyCount, icon: TrendingUp, color: 'text-emerald-400', bg: 'bg-emerald-500/10' },
        { label: 'Neg Keyword Candidates', value: data.negativeCandidates, icon: Ban, color: 'text-blue-400', bg: 'bg-blue-500/10' }
    ];

    return (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-6">
            {cards.map(c => (
                <div key={c.label} className={`${c.bg} rounded-xl p-4 border border-white/5`}>
                    <div className="flex items-center gap-2 mb-2">
                        <c.icon className={`w-4 h-4 ${c.color}`} />
                        <span className="text-xs text-white/50 uppercase tracking-wide">{c.label}</span>
                    </div>
                    <div className="text-2xl font-bold text-white">{c.value}</div>
                </div>
            ))}
        </div>
    );
}

function SummaryCardsSkeleton() {
    return (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-6">
            {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="bg-white/5 rounded-xl p-4 border border-white/5">
                    <Skeleton className="h-4 w-24 mb-3" />
                    <Skeleton className="h-8 w-16" />
                </div>
            ))}
        </div>
    );
}

/** Expandable section wrapper */
function Section({ title, icon: Icon, count, color, children, defaultOpen = false }: {
    title: string; icon: any; count: number; color: string; children: React.ReactNode; defaultOpen?: boolean;
}) {
    const [open, setOpen] = useState(defaultOpen);

    return (
        <div className="bg-white/[0.03] border border-white/5 rounded-xl mb-4 overflow-hidden">
            <button
                onClick={() => setOpen(!open)}
                className="w-full flex items-center justify-between px-5 py-4 hover:bg-white/[0.02] transition-colors"
            >
                <div className="flex items-center gap-3">
                    <Icon className={`w-5 h-5 ${color}`} />
                    <span className="font-semibold text-white">{title}</span>
                    <span className="text-xs bg-white/10 text-white/70 px-2 py-0.5 rounded-full">{count}</span>
                </div>
                {open ? <ChevronUp className="w-4 h-4 text-white/40" /> : <ChevronDown className="w-4 h-4 text-white/40" />}
            </button>
            {open && <div className="px-5 pb-4">{children}</div>}
        </div>
    );
}

/* ────────── Main Component ──────────────────────────────── */

export function AdIntelligencePanel() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [summary, setSummary] = useState<IntelligenceSummary | null>(null);
    const [correlation, setCorrelation] = useState<Correlation | null>(null);
    const [loadingSummary, setLoadingSummary] = useState(true);
    const [loadingCorrelation, setLoadingCorrelation] = useState(false);
    const [error, setError] = useState<string | null>(null);

    /** Build auth headers fresh on each request to avoid stale closures */
    function getHeaders() {
        return {
            'Authorization': `Bearer ${token}`,
            'X-Account-ID': currentAccount?.id || ''
        };
    }

    /** Load summary immediately, correlation lazily */
    useEffect(() => {
        loadSummary();
    }, [currentAccount?.id]);

    async function loadSummary() {
        setLoadingSummary(true);
        setError(null);
        try {
            const res = await fetch(`/api/ads/intelligence/summary`, { headers: getHeaders() });
            if (!res.ok) throw new Error('Failed to load intelligence summary');
            const data = await res.json();
            setSummary(data);

            // Auto-load full correlation after summary renders
            if (data.hasData) loadCorrelation();
        } catch (err: any) {
            Logger.error('Intelligence summary load failed', err);
            setError(err.message);
        } finally {
            setLoadingSummary(false);
        }
    }

    async function loadCorrelation() {
        setLoadingCorrelation(true);
        try {
            const res = await fetch(`/api/ads/intelligence/correlation`, { headers: getHeaders() });
            if (!res.ok) throw new Error('Failed to load correlation data');
            setCorrelation(await res.json());
        } catch (err: any) {
            Logger.error('Intelligence correlation load failed', err);
        } finally {
            setLoadingCorrelation(false);
        }
    }

    /* ── No data ── */
    if (!loadingSummary && summary && !summary.hasData) {
        return (
            <div className="bg-white/[0.03] border border-white/5 rounded-xl p-8 text-center">
                <Search className="w-10 h-10 text-white/20 mx-auto mb-3" />
                <p className="text-white/60 text-sm">
                    No search intelligence data yet. Connect both Search Console and Google Ads to see organic↔paid insights.
                </p>
            </div>
        );
    }

    return (
        <div>
            {/* Header */}
            <div className="flex items-center gap-3 mb-5">
                <Zap className="w-5 h-5 text-violet-400" />
                <h2 className="text-lg font-semibold text-white">Search Intelligence</h2>
                {loadingSummary && <Loader2 className="w-4 h-4 animate-spin text-white/40" />}
            </div>

            {/* Summary Cards — skeleton first */}
            {loadingSummary ? <SummaryCardsSkeleton /> : summary && <SummaryCards data={summary} />}

            {/* Correlation sections — load progressively */}
            {loadingCorrelation && (
                <div className="space-y-4 mb-4">
                    {Array.from({ length: 3 }).map((_, i) => (
                        <div key={i} className="bg-white/[0.03] border border-white/5 rounded-xl p-5">
                            <Skeleton className="h-5 w-48 mb-3" />
                            <SkeletonText lines={3} />
                        </div>
                    ))}
                </div>
            )}

            {correlation && (
                <>
                    {/* Cannibalization */}
                    {(() => {
                        const cannibalized = correlation.overlap.filter(o => o.cannibalizationScore >= 50);
                        if (cannibalized.length === 0) return null;
                        return (
                            <Section
                                title="Cannibalized Keywords"
                                icon={AlertTriangle}
                                count={cannibalized.length}
                                color="text-amber-400"
                                defaultOpen
                            >
                                <div className="space-y-2">
                                    {cannibalized.slice(0, 10).map(o => (
                                        <CannibalizationRow key={o.query} data={o} />
                                    ))}
                                </div>
                            </Section>
                        );
                    })()}

                    {/* Organic Keyword Opportunities */}
                    {correlation.organicOnly.length > 0 && (
                        <Section
                            title="Organic Keyword Opportunities"
                            icon={TrendingUp}
                            count={correlation.organicOnly.length}
                            color="text-emerald-400"
                        >
                            <div className="space-y-2">
                                {correlation.organicOnly.slice(0, 10).map(o => (
                                    <OrganicOpportunityRow key={o.query} data={o} />
                                ))}
                            </div>
                        </Section>
                    )}
                </>
            )}

            {/* Error state */}
            {error && (
                <div className="bg-red-500/10 border border-red-500/30 rounded-xl p-4 text-red-300 text-sm">
                    {error}
                </div>
            )}
        </div>
    );
}

/* ────────── Row Components ──────────────────────────────── */

function CannibalizationRow({ data }: { data: OverlapQuery }) {
    return (
        <div className="bg-white/[0.03] rounded-lg p-3 flex items-center justify-between gap-4 hover:bg-white/[0.05] transition-colors">
            <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-white truncate">"{data.query}"</p>
                <div className="flex items-center gap-3 mt-1 text-xs text-white/50">
                    <span>Organic #{data.organic.position.toFixed(0)} · {data.organic.ctr.toFixed(1)}% CTR</span>
                    <ArrowRight className="w-3 h-3" />
                    <span>Paid ${data.paid.spend.toFixed(0)} · {data.paid.roas.toFixed(1)}x ROAS</span>
                </div>
            </div>
            <div className="text-right shrink-0">
                <p className="text-sm font-medium text-amber-400">~${data.estimatedWastedSpend.toFixed(0)}/mo</p>
                <p className="text-xs text-white/40">{data.cannibalizationScore}% confidence</p>
            </div>
        </div>
    );
}

function OrganicOpportunityRow({ data }: { data: OrganicOnlyQuery }) {
    return (
        <div className="bg-white/[0.03] rounded-lg p-3 flex items-center justify-between gap-4 hover:bg-white/[0.05] transition-colors">
            <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-white truncate">"{data.query}"</p>
                <div className="flex items-center gap-3 mt-1 text-xs text-white/50">
                    <span>Position #{data.position.toFixed(0)}</span>
                    <span>·</span>
                    <span>{data.clicks} organic clicks</span>
                    <span>·</span>
                    <span>{data.ctr.toFixed(1)}% CTR</span>
                </div>
            </div>
            <div className="text-right shrink-0">
                <p className="text-sm font-medium text-emerald-400">~${data.estimatedPaidValue.toFixed(0)}/mo</p>
                <p className="text-xs text-white/40">est. paid value</p>
            </div>
        </div>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { GoogleAdsCampaigns } from './GoogleAdsCampaigns';
import { Loader2, Megaphone, Plus, RefreshCw, AlertCircle } from 'lucide-react';

interface AdAccount {
    id: string;
    platform: string;
    name: string;
    externalId: string;
}

/**
 * AdPerformanceView displays campaign performance for connected ad accounts.
 * Each account is shown as a sub-tab, with the campaign breakdown displayed below.
 */
export function AdPerformanceView() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [accounts, setAccounts] = useState<AdAccount[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedAccountId, setSelectedAccountId] = useState<string | null>(null);

    /**
     * Initiate OAuth for reconnecting an expired ad account.
     * Why separate from settings: users land on /ads from the sidebar and
     * need to reconnect without navigating to settings first.
     */
    const handleReconnect = useCallback(async (accountId: string, platform: string) => {
        if (!currentAccount) return;
        try {
            const endpoint = platform === 'GOOGLE'
                ? '/api/oauth/google/authorize'
                : '/api/oauth/meta/ads/authorize';
            const params = new URLSearchParams({
                redirect: '/ads',
                reconnectId: accountId
            });
            const res = await fetch(`${endpoint}?${params.toString()}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            if (data.authUrl) window.location.href = data.authUrl;
        } catch (err) {
            Logger.error('Failed to initiate reconnect', { error: err });
        }
    }, [currentAccount, token]);

    useEffect(() => {
        fetchAccounts();
    }, [currentAccount, token]);

    async function fetchAccounts() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/ads', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            // Filter out accounts with pending setup
            const activeAccounts = Array.isArray(data)
                ? data.filter((acc: AdAccount) => acc.externalId !== 'PENDING_SETUP')
                : [];
            setAccounts(activeAccounts);
            // Auto-select first account if none selected
            if (activeAccounts.length > 0 && !selectedAccountId) {
                setSelectedAccountId(activeAccounts[0].id);
            }
        } catch (err) {
            Logger.error('Failed to fetch ad accounts:', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
            </div>
        );
    }

    if (accounts.length === 0) {
        return (
            <div className="text-center py-16 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
                    <Megaphone className="w-8 h-8 text-gray-400" />
                </div>
                <h3 className="text-lg font-semibold text-gray-900 mb-2">No Ad Accounts Connected</h3>
                <p className="text-gray-500 mb-4">Connect your ad accounts to see campaign performance data.</p>
                <a
                    href="/marketing?tab=ads"
                    className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                >
                    <Plus size={18} />
                    Connect Ad Account
                </a>
            </div>
        );
    }

    const selectedAccount = accounts.find(acc => acc.id === selectedAccountId);

    return (
        <div className="space-y-6">
            {/* Sub-tabs for each ad account */}
            <div className="flex gap-2 overflow-x-auto pb-2">
                {accounts.map(acc => {
                    const isActive = selectedAccountId === acc.id;
                    return (
                        <button
                            key={acc.id}
                            onClick={() => setSelectedAccountId(acc.id)}
                            className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm whitespace-nowrap transition-all ${isActive
                                ? 'bg-blue-600 text-white shadow-md'
                                : 'bg-white text-gray-700 border border-gray-200 hover:bg-gray-50 hover:border-gray-300'
                                }`}
                        >
                            {/* Platform icon */}
                            <span className={`w-5 h-5 flex items-center justify-center rounded ${isActive ? 'bg-white/20' : acc.platform === 'META' ? 'bg-blue-100' : 'bg-red-100'
                                }`}>
                                {acc.platform === 'META' ? (
                                    <svg className={`w-3 h-3 ${isActive ? 'text-white' : 'text-blue-600'}`} fill="currentColor" viewBox="0 0 24 24">
                                        <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
                                    </svg>
                                ) : (
                                    <svg className={`w-3 h-3 ${isActive ? 'text-white' : 'text-red-600'}`} fill="currentColor" viewBox="0 0 24 24">
                                        <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                                        <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                                        <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                                        <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                                    </svg>
                                )}
                            </span>
                            {acc.name}
                        </button>
                    );
                })}
            </div>

            {/* Campaign breakdown for selected account */}
            {selectedAccount && (
                <GoogleAdsCampaigns
                    adAccountId={selectedAccount.id}
                    accountName={selectedAccount.name}
                    onBack={() => { }} // No back behavior needed in sub-tab mode
                    hideBackButton
                    onReconnect={() => handleReconnect(selectedAccount.id, selectedAccount.platform)}
                />
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { CheckCircle, Sparkles } from 'lucide-react';
import { Modal } from '../ui/Modal';
import { ActionableRecommendation } from '../../types/ActionableTypes';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface AddKeywordModalProps {
    isOpen: boolean;
    onClose: () => void;
    recommendation: ActionableRecommendation;
    onConfirm: (data: { keyword: string; matchType: 'BROAD' | 'PHRASE' | 'EXACT'; bid: number; adGroupId: string }) => Promise<void>;
}

interface AdGroup {
    id: string;
    name: string;
    campaignId: string;
}

export function AddKeywordModal({ isOpen, onClose, recommendation, onConfirm }: AddKeywordModalProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [matches, setMatches] = useState<'BROAD' | 'PHRASE' | 'EXACT'>('PHRASE');
    const [keyword, setKeyword] = useState('');
    const [bid, setBid] = useState(0);
    const [adGroupId, setAdGroupId] = useState<string>('');
    const [loading, setLoading] = useState(false);
    const [adGroups, setAdGroups] = useState<AdGroup[]>([]);
    const [fetchingGroups, setFetchingGroups] = useState(false);

    // Initialize from recommendation
    useEffect(() => {
        if (isOpen && recommendation) {
            const action = recommendation.action as any;
            if (action.actionType === 'add_keyword') {
                setKeyword(action.keyword || '');
                setMatches(action.matchType || 'PHRASE');
                setBid(action.suggestedCpc || 1.00);

                if (action.campaignId && token && currentAccount) {
                    setFetchingGroups(true);
                    fetch(`/api/ads/campaigns/${action.campaignId}/adgroups`, {
                        headers: {
                            'Authorization': `Bearer ${token}`,
                            'x-account-id': currentAccount.id
                        }
                    })
                        .then(res => {
                            if (!res.ok) throw new Error('Failed to fetch ad groups');
                            return res.json();
                        })
                        .then(data => {
                            setAdGroups(data);
                        })
                        .catch(err => {
                            Logger.error('An error occurred', { error: err });
                            setAdGroups([]);
                        })
                        .finally(() => {
                            setFetchingGroups(false);
                        });
                }
            }
        }
    }, [isOpen, recommendation, token, currentAccount]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!adGroupId) {
            alert('Please select an Ad Group');
            return;
        }

        setLoading(true);
        try {
            await onConfirm({
                keyword,
                matchType: matches,
                bid,
                adGroupId
            });
            onClose();
        } catch (error) {
            Logger.error('Failed to add keyword', { error: error });
        } finally {
            setLoading(false);
        }
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div className="flex items-center gap-2">
                    <Sparkles size={18} className="text-blue-600" />
                    <span>Add New Keyword</span>
                </div>
            }
            maxWidth="max-w-md"
        >
            <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Keyword</label>
                    <input
                        type="text"
                        value={keyword}
                        onChange={(e) => setKeyword(e.target.value)}
                        className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all"
                        required
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Match Type</label>
                        <select
                            value={matches}
                            onChange={(e) => setMatches(e.target.value as any)}
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all bg-white"
                        >
                            <option value="BROAD">Broad</option>
                            <option value="PHRASE">Phrase</option>
                            <option value="EXACT">Exact</option>
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Max CPC ($)</label>
                        <input
                            type="number"
                            step="0.01"
                            value={bid}
                            onChange={(e) => setBid(parseFloat(e.target.value))}
                            className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all"
                            required
                        />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Ad Group</label>
                    <select
                        value={adGroupId}
                        onChange={(e) => setAdGroupId(e.target.value)}
                        className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all bg-white"
                        required
                    >
                        <option value="" disabled>Select Ad Group...</option>
                        {adGroups.map(group => (
                            <option key={group.id} value={group.id}>{group.name}</option>
                        ))}
                    </select>
                    <p className="text-xs text-gray-500 mt-1">Select the ad group to add this keyword to.</p>
                </div>

                <div className="pt-2 flex gap-3">
                    <button
                        type="button"
                        onClick={onClose}
                        className="flex-1 px-4 py-2 rounded-xl border border-gray-200 text-gray-600 font-medium hover:bg-gray-50 transition-colors"
                    >
                        Cancel
                    </button>
                    <button
                        type="submit"
                        disabled={loading}
                        className="flex-1 px-4 py-2 rounded-xl bg-blue-600 text-white font-medium hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/20 disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        {loading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <CheckCircle size={18} />}
                        Confirm Add
                    </button>
                </div>
            </form>
        </Modal>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Plus, Facebook, Loader2, Trash2, ExternalLink, AlertCircle, RefreshCw, BarChart2 } from 'lucide-react';
import { GoogleAdsCampaigns } from './GoogleAdsCampaigns';

interface AdAccount {
    id: string;
    platform: string;
    name: string;
    externalId: string;
}

interface AdInsights {
    spend: number;
    impressions: number;
    clicks: number;
    roas: number;
    currency: string;
}

interface AdsViewProps {
    onSelectAccount?: (account: AdAccount) => void;
}

/**
 * AdsView component for managing connected ad platform accounts.
 * Supports Meta Ads (manual token) and Google Ads (OAuth flow).
 */
export function AdsView({ onSelectAccount }: AdsViewProps = {}) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [accounts, setAccounts] = useState<AdAccount[]>([]);
    const [insights, setInsights] = useState<Record<string, AdInsights>>({});
    const [loadingInsights, setLoadingInsights] = useState<Record<string, boolean>>({});
    const [insightErrors, setInsightErrors] = useState<Record<string, string>>({});
    const [isLoading, setIsLoading] = useState(true);
    const [showConnect, setShowConnect] = useState(false);

    // Form State
    const [formData, setFormData] = useState({ platform: 'META', externalId: '', accessToken: '', name: '' });
    const [isConnecting, setIsConnecting] = useState(false);

    // Pending Google Ads setup state
    const [pendingSetup, setPendingSetup] = useState<{ show: boolean; pendingId: string; customerId: string; isSubmitting: boolean }>({
        show: false,
        pendingId: '',
        customerId: '',
        isSubmitting: false
    });

    // Selected account for campaign breakdown view (only when no onSelectAccount prop)
    const [selectedAccount, setSelectedAccount] = useState<AdAccount | null>(null);

    // Server-sourced callback URL for display (avoids mismatch with API_URL)
    const [googleCallbackUrl, setGoogleCallbackUrl] = useState(`${window.location.origin}/api/oauth/google/callback`);

    useEffect(() => {
        fetchAccounts();
    }, [currentAccount, token]);

    useEffect(() => {
        /** Fetch the actual callback URL the server uses, so the displayed URL matches. */
        async function fetchCallbackUrl() {
            try {
                const res = await fetch('/api/oauth/callback-urls', {
                    headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount?.id || '' }
                });
                if (res.ok) {
                    const data = await res.json();
                    if (data.google) setGoogleCallbackUrl(data.google);
                }
            } catch {
                // Fallback already set via useState default
            }
        }
        if (token) fetchCallbackUrl();
    }, [token, currentAccount]);

    async function fetchAccounts() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/ads', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            setAccounts(data);

            // Lazy fetch insights for each (skip pending accounts)
            if (Array.isArray(data)) {
                data.forEach((acc: AdAccount) => {
                    if (acc.externalId !== 'PENDING_SETUP') {
                        fetchInsights(acc.id);
                    }
                });
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    async function fetchInsights(adAccountId: string) {
        setLoadingInsights(prev => ({ ...prev, [adAccountId]: true }));
        setInsightErrors(prev => ({ ...prev, [adAccountId]: '' })); // Clear previous error
        try {
            const res = await fetch(`/api/ads/${adAccountId}/insights`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount?.id || '' }
            });
            const data = await res.json();
            if (!data.error) {
                setInsights(prev => ({ ...prev, [adAccountId]: data }));
            } else {
                Logger.error(`Insights fetch error for ${adAccountId}`, { error: data.error });
                setInsightErrors(prev => ({ ...prev, [adAccountId]: data.error }));
            }
        } catch (err: any) {
            Logger.error('Failed to fetch insights', { error: err });
            setInsightErrors(prev => ({ ...prev, [adAccountId]: err.message || 'Connection error' }));
        } finally {
            setLoadingInsights(prev => ({ ...prev, [adAccountId]: false }));
        }
    }

    async function handleConnect(e: React.FormEvent) {
        e.preventDefault();
        if (!currentAccount) return;

        setIsConnecting(true);
        try {
            const res = await fetch('/api/ads/connect', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                },
                body: JSON.stringify(formData)
            });

            if (res.ok) {
                setShowConnect(false);
                setFormData({ platform: 'META', externalId: '', accessToken: '', name: '' });
                fetchAccounts();
            } else {
                const err = await res.json();
                alert(err.error || 'Failed to connect');
            }
        } catch (err) {
            alert('Error connecting account');
        } finally {
            setIsConnecting(false);
        }
    }

    /**
     * Initiate Google OAuth. When existingAccountId is provided, the server
     * will update that account's tokens instead of creating a new one.
     */
    async function handleGoogleOAuth(existingAccountId?: string) {
        if (!currentAccount) return;

        try {
            const params = new URLSearchParams({
                redirect: '/marketing?tab=ads',
                ...(existingAccountId && { reconnectId: existingAccountId })
            });
            const res = await fetch(`/api/oauth/google/authorize?${params.toString()}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();

            if (data.authUrl) {
                window.location.href = data.authUrl;
            } else {
                alert('Failed to initiate Google OAuth');
            }
        } catch (err) {
            alert('Error initiating Google OAuth');
        }
    }

    /**
     * Initiate Meta OAuth for reconnection.
     */
    async function handleMetaOAuth(existingAccountId?: string) {
        if (!currentAccount) return;

        try {
            const params = new URLSearchParams({
                redirect: '/marketing?tab=ads',
                ...(existingAccountId && { reconnectId: existingAccountId })
            });
            const res = await fetch(`/api/oauth/meta/ads/authorize?${params.toString()}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();

            if (data.authUrl) {
                window.location.href = data.authUrl;
            } else {
                alert('Failed to initiate Meta OAuth');
            }
        } catch (err) {
            alert('Error initiating Meta OAuth');
        }
    }

    /** Reconnect dispatches to the correct platform OAuth flow. */
    function handleReconnect(acc: AdAccount) {
        if (acc.platform === 'GOOGLE') handleGoogleOAuth(acc.id);
        else handleMetaOAuth(acc.id);
    }

    async function handleDisconnect(adAccountId: string) {
        if (!confirm('Are you sure you want to disconnect this ad account?')) return;

        try {
            const res = await fetch(`/api/ads/${adAccountId}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount?.id || '' }
            });

            if (res.ok) {
                fetchAccounts();
            } else {
                alert('Failed to disconnect');
            }
        } catch (err) {
            alert('Error disconnecting account');
        }
    }

    async function handleCompletePendingSetup() {
        if (!currentAccount || !pendingSetup.customerId.trim()) return;

        setPendingSetup(prev => ({ ...prev, isSubmitting: true }));
        try {
            const res = await fetch(`/api/ads/${pendingSetup.pendingId}/complete-setup`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                },
                body: JSON.stringify({ customerId: pendingSetup.customerId.trim() })
            });

            if (res.ok) {
                alert('Google Ads account configured successfully!');
                setPendingSetup({ show: false, pendingId: '', customerId: '', isSubmitting: false });
                fetchAccounts();
            } else {
                const err = await res.json();
                alert(err.error || 'Failed to complete setup');
            }
        } catch (err) {
            alert('Error completing setup');
        } finally {
            setPendingSetup(prev => ({ ...prev, isSubmitting: false }));
        }
    }

    // Check for OAuth callback status
    useEffect(() => {
        const params = new URLSearchParams(window.location.search);
        const success = params.get('success');
        if (success === 'google_connected') {
            alert('Google Ads account connected successfully!');
            window.history.replaceState({}, '', '/marketing?tab=ads');
            fetchAccounts();
        } else if (success === 'google_reconnected') {
            alert('Google Ads account reconnected successfully!');
            window.history.replaceState({}, '', '/marketing?tab=ads');
            fetchAccounts();
        } else if (success === 'meta_ads_reconnected') {
            alert('Meta Ads account reconnected successfully!');
            window.history.replaceState({}, '', '/marketing?tab=ads');
            fetchAccounts();
        } else if (success === 'google_pending') {
            const pendingId = params.get('pendingId') || '';
            setPendingSetup({ show: true, pendingId, customerId: '', isSubmitting: false });
            window.history.replaceState({}, '', '/marketing?tab=ads');
            fetchAccounts();
        } else if (params.get('error')) {
            const errorType = params.get('error');
            const errorMessage = params.get('message');
            alert(`OAuth Error: ${errorType}${errorMessage ? ` - ${errorMessage}` : ''}`);
            window.history.replaceState({}, '', '/marketing?tab=ads');
        }
    }, []);

    return (
        <div className="space-y-6">
            {/* Pending Setup Modal */}
            {pendingSetup.show && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-xl shadow-xl p-6 max-w-md w-full mx-4">
                        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                            <AlertCircle className="text-amber-500" size={20} />
                            Complete Google Ads Setup
                        </h3>
                        <p className="text-sm text-gray-600 mb-4">
                            Your Google account has been connected. Please enter your Google Ads Customer ID to complete the setup.
                        </p>
                        <div className="mb-4">
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Google Ads Customer ID
                            </label>
                            <input
                                type="text"
                                className="w-full p-3 border rounded-lg"
                                placeholder="123-456-7890"
                                value={pendingSetup.customerId}
                                onChange={e => setPendingSetup(prev => ({ ...prev, customerId: e.target.value }))}
                            />
                            <p className="text-xs text-gray-500 mt-2">
                                Find your Customer ID in the top-right corner of{' '}
                                <a href="https://ads.google.com" target="_blank" rel="noopener noreferrer" className="text-blue-600 underline">
                                    Google Ads
                                </a>
                                . It looks like: 123-456-7890
                            </p>
                        </div>
                        <div className="flex gap-3 justify-end">
                            <button
                                onClick={() => {
                                    // Delete the pending account
                                    handleDisconnect(pendingSetup.pendingId);
                                    setPendingSetup({ show: false, pendingId: '', customerId: '', isSubmitting: false });
                                }}
                                className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleCompletePendingSetup}
                                disabled={!pendingSetup.customerId.trim() || pendingSetup.isSubmitting}
                                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center gap-2"
                            >
                                {pendingSetup.isSubmitting ? <Loader2 className="animate-spin" size={16} /> : null}
                                Complete Setup
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Campaign Breakdown View */}
            {selectedAccount ? (
                <GoogleAdsCampaigns
                    adAccountId={selectedAccount.id}
                    accountName={selectedAccount.name}
                    onBack={() => setSelectedAccount(null)}
                />
            ) : (
                <>
                    <div className="flex justify-between items-center">
                        <h2 className="text-xl font-semibold text-gray-900">Ad Accounts</h2>
                        <button
                            onClick={() => setShowConnect(!showConnect)}
                            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
                        >
                            <Plus size={18} /> Connect Account
                        </button>
                    </div>

                    {/* Connect Form */}
                    {showConnect && (
                        <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200 mb-6">
                            <h3 className="font-semibold mb-4">Connect Ad Platform</h3>
                            <form onSubmit={handleConnect} className="grid gap-4 max-w-md">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Platform</label>
                                    <select
                                        className="w-full p-2 border rounded-lg"
                                        value={formData.platform}
                                        onChange={e => setFormData({ ...formData, platform: e.target.value })}
                                    >
                                        <option value="META">Meta Ads (Facebook/Instagram)</option>
                                        <option value="GOOGLE">Google Ads</option>
                                    </select>
                                </div>

                                {formData.platform === 'GOOGLE' ? (
                                    /* Google Ads - OAuth Flow */
                                    <div className="space-y-4">
                                        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                                            <p className="text-sm text-blue-800">
                                                Google Ads requires OAuth authentication. Click the button below to connect your account securely.
                                            </p>
                                        </div>
                                        <div className="bg-amber-50 border border-amber-200 rounded-lg p-4">
                                            <p className="text-sm text-amber-800 font-medium mb-2">
                                                ⚠️ Google Cloud Console Setup Required
                                            </p>
                                            <p className="text-xs text-amber-700 mb-2">
                                                Add this redirect URI to your Google Cloud OAuth credentials:
                                            </p>
                                            <code className="block bg-white border border-amber-300 rounded-sm px-3 py-2 text-xs font-mono text-gray-800 break-all select-all">
                                                {googleCallbackUrl}
                                            </code>
                                        </div>
                                        <button
                                            type="button"
                                            onClick={() => handleGoogleOAuth()}
                                            className="w-full flex items-center justify-center gap-2 bg-white border border-gray-300 px-4 py-3 rounded-lg hover:bg-gray-50 font-medium"
                                        >
                                            <svg className="w-5 h-5" viewBox="0 0 24 24">
                                                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                                                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                                                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                                                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                                            </svg>
                                            Connect with Google
                                        </button>
                                    </div>
                                ) : (
                                    /* Meta Ads - Manual Token Entry */
                                    <>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Account Name (Optional)</label>
                                            <input
                                                type="text"
                                                className="w-full p-2 border rounded-lg"
                                                placeholder="e.g. Summer Campaign Account"
                                                value={formData.name}
                                                onChange={e => setFormData({ ...formData, name: e.target.value })}
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Ad Account ID</label>
                                            <input
                                                type="text"
                                                className="w-full p-2 border rounded-lg"
                                                placeholder="act_123456789"
                                                value={formData.externalId}
                                                onChange={e => setFormData({ ...formData, externalId: e.target.value })}
                                                required
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Access Token</label>
                                            <input
                                                type="password"
                                                className="w-full p-2 border rounded-lg"
                                                placeholder="EAA..."
                                                value={formData.accessToken}
                                                onChange={e => setFormData({ ...formData, accessToken: e.target.value })}
                                                required
                                            />
                                            <p className="text-xs text-gray-500 mt-1 flex items-center gap-1">
                                                Get a token from{' '}
                                                <a
                                                    href="https://developers.facebook.com/tools/explorer/"
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="text-blue-600 underline inline-flex items-center gap-0.5"
                                                >
                                                    Graph API Explorer <ExternalLink size={12} />
                                                </a>
                                            </p>
                                        </div>
                                        <div className="flex justify-end gap-2 mt-2">
                                            <button
                                                type="button"
                                                onClick={() => setShowConnect(false)}
                                                className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                                            >
                                                Cancel
                                            </button>
                                            <button
                                                type="submit"
                                                disabled={isConnecting}
                                                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
                                            >
                                                {isConnecting ? <Loader2 className="animate-spin" size={18} /> : 'Save'}
                                            </button>
                                        </div>
                                    </>
                                )}
                            </form>
                        </div>
                    )
                    }

                    {/* List */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {isLoading ? (
                            <div className="col-span-full text-center py-12"><Loader2 className="animate-spin inline text-gray-400" /></div>
                        ) : accounts.length === 0 ? (
                            <div className="col-span-full text-center py-12 text-gray-500 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                                No ad accounts connected.
                            </div>
                        ) : (
                            accounts.map(acc => {
                                const ins = insights[acc.id];
                                const isPending = acc.externalId === 'PENDING_SETUP';
                                const hasError = !!insightErrors[acc.id];
                                return (
                                    <div key={acc.id} className={`bg-white rounded-xl shadow-xs border p-6 space-y-4 ${isPending ? 'border-amber-300' : hasError ? 'border-red-200' : 'border-gray-200'}`}>
                                        <div className="flex justify-between items-start">
                                            <div className="flex items-center gap-3">
                                                <div className={`p-2 rounded-lg ${acc.platform === 'META' ? 'bg-blue-50 text-blue-600' : 'bg-red-50 text-red-600'}`}>
                                                    {acc.platform === 'META' ? <Facebook size={24} /> : (
                                                        <svg className="w-6 h-6" viewBox="0 0 24 24" fill="currentColor">
                                                            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
                                                            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                                                            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                                                            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                                                        </svg>
                                                    )}
                                                </div>
                                                <div>
                                                    <h3 className="font-semibold text-gray-900">{acc.name}</h3>
                                                    <p className="text-xs text-gray-500 font-mono">{isPending ? 'Setup not complete' : acc.externalId}</p>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {isPending ? (
                                                    <>
                                                        <button
                                                            onClick={() => setPendingSetup({ show: true, pendingId: acc.id, customerId: '', isSubmitting: false })}
                                                            className="bg-amber-100 text-amber-800 text-xs px-2 py-1 rounded-full hover:bg-amber-200"
                                                        >
                                                            Complete Setup
                                                        </button>
                                                    </>
                                                ) : hasError ? (
                                                    <>
                                                        <span className="bg-red-100 text-red-800 text-xs px-2 py-1 rounded-full">Error</span>
                                                        <button
                                                            onClick={() => handleReconnect(acc)}
                                                            className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 text-white text-xs font-medium rounded-lg hover:bg-blue-700"
                                                        >
                                                            <RefreshCw size={14} />
                                                            Reconnect
                                                        </button>
                                                    </>
                                                ) : (
                                                    <>
                                                        <span className="bg-green-100 text-green-800 text-xs px-2 py-1 rounded-full">Active</span>
                                                        <button
                                                            onClick={() => fetchInsights(acc.id)}
                                                            disabled={loadingInsights[acc.id]}
                                                            className="p-1 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-sm disabled:opacity-50"
                                                            title="Refresh data"
                                                        >
                                                            <RefreshCw size={16} className={loadingInsights[acc.id] ? 'animate-spin' : ''} />
                                                        </button>
                                                        {(acc.platform === 'GOOGLE' || acc.platform === 'META') && !isPending && (
                                                            <button
                                                                onClick={() => onSelectAccount ? onSelectAccount(acc) : setSelectedAccount(acc)}
                                                                className="p-1 text-gray-400 hover:text-purple-600 hover:bg-purple-50 rounded-sm"
                                                                title="View campaign breakdown"
                                                            >
                                                                <BarChart2 size={16} />
                                                            </button>
                                                        )}
                                                    </>
                                                )}
                                                <button
                                                    onClick={() => handleDisconnect(acc.id)}
                                                    className="p-1 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-sm"
                                                    title="Disconnect"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>

                                        <div className="border-t pt-4 grid grid-cols-2 gap-4">
                                            <div>
                                                <p className="text-xs text-gray-500 uppercase">Spend (30d)</p>
                                                <p className="text-xl font-bold text-gray-900">
                                                    {ins?.spend != null ? new Intl.NumberFormat('en-US', { style: 'currency', currency: ins.currency || 'USD' }).format(ins.spend) : '...'}
                                                </p>
                                            </div>
                                            <div>
                                                <p className="text-xs text-gray-500 uppercase">ROAS</p>
                                                <p className="text-xl font-bold text-gray-900">
                                                    {ins?.roas != null ? ins.roas.toFixed(2) + 'x' : '...'}
                                                </p>
                                            </div>
                                            <div>
                                                <p className="text-xs text-gray-500 uppercase">Impressions</p>
                                                <p className="font-medium text-gray-700">
                                                    {ins?.impressions != null ? new Intl.NumberFormat('en-US', { notation: "compact" }).format(ins.impressions) : '...'}
                                                </p>
                                            </div>
                                            <div>
                                                <p className="text-xs text-gray-500 uppercase">Clicks</p>
                                                <p className="font-medium text-gray-700">
                                                    {ins?.clicks != null ? new Intl.NumberFormat('en-US').format(ins.clicks) : '...'}
                                                </p>
                                            </div>
                                        </div>

                                        {/* Error Detail */}
                                        {hasError && (
                                            <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
                                                <div className="flex items-start gap-2">
                                                    <AlertCircle className="text-red-500 shrink-0 mt-0.5" size={16} />
                                                    <div className="text-sm text-red-700">
                                                        <p className="font-medium">Failed to load data</p>
                                                        <p className="text-xs mt-1 text-red-600">{insightErrors[acc.id]}</p>
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                );
                            })
                        )}
                    </div>
                </>
            )}
        </div>
    );
}

/**
 * FlowsList - Displays and manages automation flows.
 * Simplified creation: just name, then visual builder handles triggers/actions.
 */
import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Plus, Zap, Play, Pause, Trash2, Loader2, GitBranch } from 'lucide-react';
import { Toast, ToastType } from '../ui/Toast';

export function AutomationsList({ onEdit }: { onEdit: (id: string, name: string) => void }) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [flows, setFlows] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    // Create Modal - simplified: name only
    const [showCreate, setShowCreate] = useState(false);
    const [newFlowName, setNewFlowName] = useState('');

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    useEffect(() => {
        fetchData();
    }, [currentAccount, token]);

    async function fetchData() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/marketing/automations', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                if (Array.isArray(data)) setFlows(data);
                else setFlows([]);
            } else {
                Logger.error('Failed to fetch flows', { status: res.status });
                setFlows([]);
            }
        } catch (err) { Logger.error('An error occurred', { error: err }); setFlows([]); }
        finally { setIsLoading(false); }
    }

    async function handleCreate(e: React.FormEvent) {
        e.preventDefault();
        if (!newFlowName.trim()) { showToast('Flow name is required'); return; }

        try {
            const res = await fetch('/api/marketing/automations', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({
                    name: newFlowName.trim(),
                    triggerType: 'NONE',
                    isActive: false,
                    flowDefinition: { nodes: [], edges: [] }
                })
            });

            if (res.ok) {
                const data = await res.json();
                setShowCreate(false);
                setNewFlowName('');
                onEdit(data.id, data.name);
            } else {
                const err = await res.json().catch(() => null);
                showToast(err?.error || 'Failed to create flow');
            }
        } catch (err) { Logger.error('Failed to create flow', { error: err }); showToast('Failed to create flow — network error'); }
    }

    async function toggleActive(flow: any) {
        try {
            const detailRes = await fetch(`/api/marketing/automations/${flow.id}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            const detail = await detailRes.json();

            await fetch('/api/marketing/automations', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify({ ...detail, isActive: !flow.isActive })
            });

            fetchData();
        } catch (err) { Logger.error('Failed to toggle flow', { error: err }); showToast('Failed to toggle flow'); }
    }

    async function handleDelete(id: string) {
        if (!confirm('Delete this flow?')) return;
        try {
            await fetch(`/api/marketing/automations/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            fetchData();
        } catch (err) { Logger.error('Failed to delete flow', { error: err }); showToast('Failed to delete flow'); }
    }

    // Trigger type display labels
    const triggers: Record<string, string> = {
        'ORDER_CREATED': 'Order Created',
        'ORDER_COMPLETED': 'Order Completed',
        'REVIEW_LEFT': 'Review Left',
        'ABANDONED_CART': 'Abandoned Cart',
        'NONE': 'No Trigger'
    };

    return (
        <>
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-semibold text-gray-900">Flows</h2>
                    <button
                        onClick={() => setShowCreate(true)}
                        className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
                    >
                        <Plus size={18} /> New Flow
                    </button>
                </div>

                {showCreate && (
                    <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 mb-4">
                        <form onSubmit={handleCreate} className="flex items-end gap-4">
                            <div className="flex-1">
                                <label className="block text-sm font-medium mb-1">Flow Name</label>
                                <input
                                    className="w-full p-2 border rounded-sm"
                                    placeholder="e.g., Post-Purchase Follow Up"
                                    value={newFlowName}
                                    onChange={e => setNewFlowName(e.target.value)}
                                    autoFocus
                                    required
                                />
                            </div>
                            <div className="flex gap-2">
                                <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-sm">Create & Edit</button>
                                <button type="button" onClick={() => { setShowCreate(false); setNewFlowName(''); }} className="px-4 py-2 text-gray-500">Cancel</button>
                            </div>
                        </form>
                    </div>
                )}

                {isLoading ? <Loader2 className="animate-spin" /> : (
                    <div className="grid gap-4">
                        {flows.map(flow => (
                            <div key={flow.id} className="bg-white p-4 rounded-xl border border-gray-200 shadow-xs flex items-center justify-between">
                                <div className="flex items-center gap-4">
                                    <div className={`p-3 rounded-lg ${flow.isActive ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                                        <Zap size={24} />
                                    </div>
                                    <div>
                                        <h3 className="font-semibold text-gray-900">{flow.name}</h3>
                                        <div className="flex items-center gap-2 text-sm text-gray-500">
                                            {flow.triggerType && flow.triggerType !== 'NONE' && (
                                                <>
                                                    <span className="font-medium text-gray-700">Trigger:</span> {triggers[flow.triggerType] || flow.triggerType}
                                                    <span className="text-gray-300">|</span>
                                                </>
                                            )}
                                            <span className="flex items-center gap-1"><GitBranch size={14} /> {flow.enrollments?.length || 0} active</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center gap-3">
                                    <button
                                        onClick={() => toggleActive(flow)}
                                        className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-colors ${flow.isActive
                                            ? 'bg-green-100 text-green-800 hover:bg-green-200'
                                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                                            }`}
                                    >
                                        {flow.isActive ? <><Pause size={14} /> Active</> : <><Play size={14} /> Paused</>}
                                    </button>
                                    <button onClick={() => onEdit(flow.id, flow.name)} className="text-blue-600 hover:text-blue-800 p-2 font-medium text-sm">
                                        Edit Flow
                                    </button>
                                    <button onClick={() => handleDelete(flow.id)} className="p-2 text-gray-400 hover:text-red-600">
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            </div>
                        ))}
                        {flows.length === 0 && (
                            <div className="text-center py-12 text-gray-500">No flows created yet. Create your first flow to automate customer engagement.</div>
                        )}
                    </div>
                )
                }
            </div >

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </>);
}

/**
 * Campaign Products Panel
 * 
 * Displays products for an expanded campaign row.
 * Fetches products on demand when campaign is expanded.
 */

import { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Loader2, Package, TrendingUp, TrendingDown } from 'lucide-react';
import { formatCurrency, formatCompact } from '../../utils/format';

interface ShoppingProduct {
    campaignId: string;
    campaignName: string;
    productId: string;
    productTitle: string;
    productBrand: string;
    productCategory: string;
    spend: number;
    impressions: number;
    clicks: number;
    conversions: number;
    conversionsValue: number;
    roas: number;
    ctr: number;
    cpc: number;
    currency: string;
}

interface CampaignProductsPanelProps {
    adAccountId: string;
    campaignId: string;
    days: number;
}

export function CampaignProductsPanel({ adAccountId, campaignId, days }: CampaignProductsPanelProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [products, setProducts] = useState<ShoppingProduct[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        fetchProducts();
    }, [adAccountId, campaignId, days]);

    async function fetchProducts() {
        setIsLoading(true);
        setError(null);
        try {
            const headers = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount?.id || ''
            };
            const res = await fetch(
                `/api/ads/${adAccountId}/campaigns/${campaignId}/products?days=${days}`,
                { headers }
            );
            if (!res.ok) {
                const err = await res.json();
                throw new Error(err.error || 'Failed to load products');
            }
            const data = await res.json();
            setProducts(data);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    }

    const formatNumber = (v: number) =>
        formatCompact(v);

    if (isLoading) {
        return (
            <div className="flex items-center justify-center py-6 bg-gray-50">
                <Loader2 className="w-5 h-5 animate-spin text-blue-500 mr-2" />
                <span className="text-sm text-gray-500">Loading products...</span>
            </div>
        );
    }

    if (error) {
        return (
            <div className="py-4 px-6 bg-red-50 text-red-600 text-sm">
                {error}
            </div>
        );
    }

    if (products.length === 0) {
        return (
            <div className="py-6 px-6 bg-gray-50 text-center">
                <Package className="w-8 h-8 text-gray-400 mx-auto mb-2" />
                <p className="text-sm text-gray-500">No products in this campaign</p>
                <p className="text-xs text-gray-400 mt-1">
                    This may be a non-Shopping campaign or no product data is available.
                </p>
            </div>
        );
    }

    // Sort by spend descending
    const sortedProducts = [...products].sort((a, b) => b.spend - a.spend);

    return (
        <div className="bg-gray-50 border-t">
            <div className="px-6 py-3 border-b bg-gray-100">
                <span className="text-sm font-medium text-gray-700">
                    {products.length} Product{products.length !== 1 ? 's' : ''} in Campaign
                </span>
            </div>
            <div className="divide-y divide-gray-200">
                {sortedProducts.slice(0, 10).map((product, idx) => (
                    <div key={`${product.productId}-${idx}`} className="px-6 py-3 flex items-center justify-between hover:bg-gray-100 transition-colors">
                        <div className="flex-1 min-w-0">
                            <p className="font-medium text-gray-900 truncate" title={product.productTitle}>
                                {product.productTitle}
                            </p>
                            <p className="text-xs text-gray-500">
                                {product.productBrand && `${product.productBrand} • `}
                                ID: {product.productId}
                            </p>
                        </div>
                        <div className="flex items-center gap-6 text-sm">
                            <div className="text-right">
                                <p className="text-gray-900 font-medium">
                                    {formatCurrency(product.spend, product.currency)}
                                </p>
                                <p className="text-xs text-gray-500">Spend</p>
                            </div>
                            <div className="text-right">
                                <p className="text-gray-700">{formatNumber(product.clicks)}</p>
                                <p className="text-xs text-gray-500">Clicks</p>
                            </div>
                            <div className="text-right">
                                <p className="text-gray-700">{product.conversions.toFixed(0)}</p>
                                <p className="text-xs text-gray-500">Conv.</p>
                            </div>
                            <div className="text-right w-16">
                                <p className={`font-medium flex items-center justify-end gap-1 ${product.roas >= 3 ? 'text-green-600' :
                                    product.roas >= 1 ? 'text-yellow-600' : 'text-red-600'
                                    }`}>
                                    {product.roas >= 3 ? <TrendingUp size={12} /> :
                                        product.roas < 1 ? <TrendingDown size={12} /> : null}
                                    {product.roas.toFixed(2)}x
                                </p>
                                <p className="text-xs text-gray-500">ROAS</p>
                            </div>
                        </div>
                    </div>
                ))}
                {products.length > 10 && (
                    <div className="px-6 py-2 text-center text-xs text-gray-500 bg-gray-100">
                        Showing top 10 of {products.length} products
                    </div>
                )}
            </div>
        </div>
    );
}

/**
 * Campaign Wizard
 * 
 * Multi-step modal for creating Google Ads campaigns with AI assistance.
 * Guides users through goal selection, product selection, ad copy, and budget.
 */

import React, { useState, useCallback, useMemo } from 'react';
import { X, CheckCircle, ArrowRight } from 'lucide-react';
import { WizardStepIndicator } from './WizardStepIndicator';
import { StepGoalType } from './steps/StepGoalType';
import { StepProductSelection } from './steps/StepProductSelection';
import { StepAdCopy } from './steps/StepAdCopy';
import { StepBudgetReview } from './steps/StepBudgetReview';
import { useAuth } from '../../../context/AuthContext';
import { useAccount } from '../../../context/AccountContext';
import { Logger } from '../../../utils/logger';
import {
    CampaignDraft,
    WIZARD_STEPS,
    validateStep,
    createInitialDraft
} from './types';

interface CampaignWizardProps {
    isOpen: boolean;
    onClose: () => void;
    /** Optional callback when campaign is successfully created */
    onSuccess?: (campaignName: string) => void;
}

/**
 * Campaign Creation Wizard Component
 * 
 * Provides a 4-step guided flow for creating Google Ads campaigns:
 * 1. Goal & Type selection
 * 2. Product selection (optional)
 * 3. AI-generated ad copy (editable)
 * 4. Budget & final review
 */
export function CampaignWizard({ isOpen, onClose, onSuccess }: CampaignWizardProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [currentStep, setCurrentStep] = useState<number>(WIZARD_STEPS.GOAL);
    const [draft, setDraft] = useState<CampaignDraft>(createInitialDraft);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Memoized validation for current step
    const stepValidation = useMemo(
        () => validateStep(currentStep, draft),
        [currentStep, draft]
    );

    // Navigation handlers with validation
    const handleNext = useCallback(() => {
        const validation = validateStep(currentStep, draft);
        if (!validation.isValid) {
            setError(validation.error || 'Please complete all required fields');
            return;
        }
        setError(null);
        setCurrentStep(curr => Math.min(curr + 1, WIZARD_STEPS.TOTAL));
    }, [currentStep, draft]);

    const handleBack = useCallback(() => {
        setError(null);
        setCurrentStep(curr => Math.max(curr - 1, WIZARD_STEPS.GOAL));
    }, []);

    // Reset wizard state when closing
    const handleClose = useCallback(() => {
        setCurrentStep(WIZARD_STEPS.GOAL);
        setDraft(createInitialDraft());
        setError(null);
        onClose();
    }, [onClose]);

    // Launch campaign via API
    const handleLaunch = useCallback(async () => {
        if (!token || !currentAccount) {
            setError('Authentication required');
            return;
        }

        // Final validation
        const validation = validateStep(WIZARD_STEPS.BUDGET, draft);
        if (!validation.isValid) {
            setError(validation.error || 'Invalid configuration');
            return;
        }

        setLoading(true);
        setError(null);

        try {
            Logger.info('[CampaignWizard] Launching campaign', {
                name: draft.name,
                type: draft.type
            });

            // Generate keywords from products if none provided
            const keywords = draft.keywords.length > 0
                ? draft.keywords
                : draft.selectedProducts.map(p => ({
                    text: p.name,
                    matchType: 'PHRASE' as const
                }));

            const res = await fetch('/api/ads/create-campaign', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                },
                body: JSON.stringify({
                    type: draft.type,
                    name: draft.name,
                    budget: draft.budget,
                    keywords,
                    adCopy: draft.adCopy,
                    productIds: draft.selectedProducts.map(p => p.id)
                })
            });

            if (!res.ok) {
                const errData = await res.json();
                throw new Error(errData.error || 'Failed to create campaign');
            }

            Logger.info('[CampaignWizard] Campaign created successfully', { name: draft.name });
            onSuccess?.(draft.name);
            handleClose();

        } catch (e: any) {
            Logger.error('[CampaignWizard] Failed to launch campaign', { error: e.message });
            setError(e.message || 'An unexpected error occurred');
        } finally {
            setLoading(false);
        }
    }, [token, currentAccount, draft, onSuccess, handleClose]);

    // Don't render if not open
    if (!isOpen) return null;

    // Render step content based on current step
    const renderStepContent = () => {
        switch (currentStep) {
            case WIZARD_STEPS.GOAL:
                return <StepGoalType draft={draft} setDraft={setDraft} />;
            case WIZARD_STEPS.PRODUCTS:
                return <StepProductSelection draft={draft} setDraft={setDraft} />;
            case WIZARD_STEPS.AD_COPY:
                return <StepAdCopy draft={draft} setDraft={setDraft} />;
            case WIZARD_STEPS.BUDGET:
                return <StepBudgetReview draft={draft} setDraft={setDraft} />;
            default:
                return null;
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl h-[80vh] flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-200">

                {/* Header */}
                <div className="px-8 py-5 border-b border-gray-100 flex items-center justify-between bg-white z-10">
                    <div>
                        <h2 className="text-xl font-bold text-gray-900">Create New Campaign</h2>
                        <p className="text-sm text-gray-500">AI-Powered Setup</p>
                    </div>
                    <button
                        onClick={handleClose}
                        className="p-2 hover:bg-gray-100 rounded-lg transition-colors text-gray-400 hover:text-gray-600"
                        aria-label="Close wizard"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Body */}
                <div className="flex-1 flex overflow-hidden">
                    {/* Sidebar / Progress */}
                    <div className="w-64 bg-gray-50 border-r border-gray-100 p-6 hidden md:block">
                        <WizardStepIndicator currentStep={currentStep} />
                    </div>

                    {/* Content */}
                    <div className="flex-1 overflow-y-auto p-8 relative">
                        {error && (
                            <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl text-red-700 text-sm">
                                {error}
                            </div>
                        )}
                        {renderStepContent()}
                    </div>
                </div>

                {/* Footer */}
                <div className="px-8 py-5 border-t border-gray-100 bg-white flex justify-between items-center">
                    <button
                        onClick={handleBack}
                        disabled={currentStep === WIZARD_STEPS.GOAL}
                        className="px-6 py-2.5 rounded-xl border border-gray-200 text-gray-600 font-medium hover:bg-gray-50 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        Back
                    </button>

                    {currentStep < WIZARD_STEPS.TOTAL ? (
                        <button
                            onClick={handleNext}
                            className="flex items-center gap-2 px-6 py-2.5 bg-gray-900 text-white font-medium rounded-xl hover:bg-gray-800 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5"
                        >
                            Next Step
                            <ArrowRight size={18} />
                        </button>
                    ) : (
                        <button
                            onClick={handleLaunch}
                            disabled={loading}
                            className="flex items-center gap-2 px-8 py-2.5 bg-green-600 text-white font-bold rounded-xl hover:bg-green-700 transition-all shadow-lg shadow-green-500/30 hover:shadow-xl hover:-translate-y-0.5 disabled:opacity-70 disabled:cursor-not-allowed"
                        >
                            {loading ? (
                                <>
                                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                    Launching...
                                </>
                            ) : (
                                <>
                                    <CheckCircle size={20} />
                                    Launch Campaign
                                </>
                            )}
                        </button>
                    )}
                </div>

            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Plus, Loader2, Trash2, AlertTriangle } from 'lucide-react';
import { useToast } from '../../context/ToastContext';
import { Modal } from '../ui/Modal';

export function CampaignsList({ onEdit }: { onEdit: (id: string, name: string, subject?: string) => void }) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const toast = useToast();
    const [campaigns, setCampaigns] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    // Create Modal state
    const [showCreate, setShowCreate] = useState(false);
    const [newItem, setNewItem] = useState({ name: '', subject: '' });

    const [segments, setSegments] = useState<any[]>([]);
    const [deletingId, setDeletingId] = useState<string | null>(null);

    useEffect(() => {
        fetchData();
        fetchSegments();
    }, [currentAccount, token]);

    async function fetchSegments() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/segments', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                setSegments(await res.json());
            } else {
                Logger.error('Failed to fetch segments', { status: res.status });
            }
        } catch (e) { Logger.error('An error occurred', { error: e }); }
    }

    async function fetchData() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/marketing/campaigns', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                if (Array.isArray(data)) {
                    setCampaigns(data);
                } else {
                    Logger.error('Campaigns data is not an array:', { error: data });
                    setCampaigns([]);
                }
            } else {
                Logger.error('Failed to fetch campaigns', { status: res.status });
                setCampaigns([]);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
            setCampaigns([]);
        } finally {
            setIsLoading(false);
        }
    }

    async function handleCreate(e: React.FormEvent) {
        e.preventDefault();
        try {
            const res = await fetch('/api/marketing/campaigns', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify(newItem)
            });
            if (res.ok) {
                const data = await res.json();
                setShowCreate(false);
                setNewItem({ name: '', subject: '' });
                // fetchData(); // No need if we switch view
                onEdit(data.id, data.name, data.subject);
            } else {
                const errorData = await res.json().catch(() => ({}));
                Logger.error('Campaign create error:', { error: errorData });
                toast.error(`Failed to create campaign: ${errorData.error || 'Unknown error'}`);
            }
        } catch (err) { toast.error('Error creating campaign'); }
    }

    async function handleDelete(id: string) {
        if (!currentAccount) return;
        try {
            await fetch(`/api/marketing/campaigns/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            setDeletingId(null);
            fetchData();
            toast.success('Campaign deleted');
        } catch (err) { toast.error('Failed to delete campaign'); }
    }

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-semibold text-gray-900">Email Broadcasts</h2>
                <button
                    onClick={() => setShowCreate(true)}
                    className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
                >
                    <Plus size={18} /> New Campaign
                </button>
            </div>

            {showCreate && (
                <div className="bg-gray-50 p-4 rounded-lg border border-gray-200 mb-4">
                    <form onSubmit={handleCreate} className="flex flex-col gap-4">
                        <div className="flex gap-4 items-end">
                            <div className="flex-1">
                                <label className="block text-sm font-medium mb-1">Campaign Name</label>
                                <input
                                    className="w-full p-2 border rounded-sm"
                                    value={newItem.name}
                                    onChange={e => setNewItem({ ...newItem, name: e.target.value })}
                                    required
                                />
                            </div>
                            <div className="flex-1">
                                <label className="block text-sm font-medium mb-1">Subject Line</label>
                                <input
                                    className="w-full p-2 border rounded-sm"
                                    value={newItem.subject}
                                    onChange={e => setNewItem({ ...newItem, subject: e.target.value })}
                                    required
                                />
                            </div>
                            <div className="w-64">
                                <label className="block text-sm font-medium mb-1">Recipient Segment</label>
                                <select
                                    className="w-full p-2 border rounded-sm"
                                    value={(newItem as any).segmentId || ''}
                                    onChange={e => setNewItem({ ...newItem, segmentId: e.target.value } as any)}
                                >
                                    <option value="">All Customers</option>
                                    {segments.map(s => (
                                        <option key={s.id} value={s.id}>{s.name} ({s._count?.campaigns || 0} used)</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="flex gap-2 justify-end">
                            <button type="button" onClick={() => setShowCreate(false)} className="px-4 py-2 text-gray-500">Cancel</button>
                            <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-sm">Create & Edit Design</button>
                        </div>
                    </form>
                </div>
            )}

            {isLoading ? <Loader2 className="animate-spin" /> : (
                <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 border-b">
                            <tr>
                                <th className="p-4 font-medium text-gray-500">Name</th>
                                <th className="p-4 font-medium text-gray-500">Status</th>
                                <th className="p-4 font-medium text-gray-500">Sent / Opened</th>
                                <th className="p-4 font-medium text-gray-500">Schedule</th>
                                <th className="p-4 font-medium text-gray-500 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {campaigns.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="p-8 text-center text-gray-500">No campaigns found.</td>
                                </tr>
                            ) : campaigns.map(c => (
                                <tr key={c.id} className="border-b last:border-0 hover:bg-gray-50">
                                    <td className="p-4">
                                        <div className="font-medium text-gray-900">{c.name}</div>
                                        <div className="text-sm text-gray-500">{c.subject}</div>
                                    </td>
                                    <td className="p-4">
                                        <span className={`px-2 py-1 rounded-full text-xs font-medium ${c.status === 'SENT' ? 'bg-green-100 text-green-800' :
                                            c.status === 'DRAFT' ? 'bg-gray-100 text-gray-800' :
                                                'bg-blue-100 text-blue-800'
                                            }`}>
                                            {c.status}
                                        </span>
                                    </td>
                                    <td className="p-4 text-sm text-gray-600">
                                        <span
                                            title={c.sentCount > 0 ? `Open rate: ${((c.openedCount / c.sentCount) * 100).toFixed(1)}%` : 'No sends yet'}
                                            className="cursor-default"
                                        >
                                            {c.sentCount} sent · {c.openedCount} opened
                                            {c.sentCount > 0 && (
                                                <span className="ml-1 text-xs text-gray-400">
                                                    ({((c.openedCount / c.sentCount) * 100).toFixed(0)}%)
                                                </span>
                                            )}
                                        </span>
                                    </td>
                                    <td className="p-4 text-sm text-gray-600">
                                        {c.scheduledAt ? (
                                            <div>
                                                <div>{new Date(c.scheduledAt).toLocaleDateString()}</div>
                                                <div className="text-xs text-gray-400">{new Date(c.scheduledAt).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })}</div>
                                            </div>
                                        ) : '-'}
                                    </td>
                                    <td className="p-4 text-right">
                                        <button onClick={() => setDeletingId(c.id)} className="text-red-500 hover:text-red-700 p-2">
                                            <Trash2 size={16} />
                                        </button>
                                        <button onClick={() => onEdit(c.id, c.name, c.subject)} className="text-blue-600 hover:text-blue-800 p-2 font-medium text-sm">
                                            Edit
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            <Modal
                isOpen={!!deletingId}
                onClose={() => setDeletingId(null)}
                title="Delete Campaign"
                maxWidth="max-w-sm"
            >
                <div className="space-y-4">
                    <div className="flex items-start gap-3">
                        <div className="p-2 bg-red-100 dark:bg-red-500/10 rounded-lg">
                            <AlertTriangle size={20} className="text-red-600 dark:text-red-400" />
                        </div>
                        <p className="text-sm text-gray-600 dark:text-gray-300">
                            Are you sure you want to delete this campaign? This action cannot be undone.
                        </p>
                    </div>
                    <div className="flex justify-end gap-3">
                        <button
                            onClick={() => setDeletingId(null)}
                            className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-lg transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={() => deletingId && handleDelete(deletingId)}
                            className="px-4 py-2 text-sm font-medium text-white bg-red-600 hover:bg-red-700 rounded-lg transition-colors"
                        >
                            Delete
                        </button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

/**
 * ExperimentsPanel - A/B Testing Experiments Management
 * 
 * Displays and manages creative A/B experiments for ad accounts.
 * Part of AI Co-Pilot v2 - Phase 4: Creative A/B Engine.
 */

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Logger } from '../../utils/logger';
import {
    FlaskConical, Plus, RefreshCw, Play, Pause, Trophy, BarChart3,
    ChevronRight, AlertCircle, CheckCircle2, Clock, Loader2
} from 'lucide-react';

interface Experiment {
    id: string;
    name: string;
    status: string;
    platform: string;
    primaryMetric: string;
    minSampleSize: number;
    confidenceLevel: number;
    createdAt: string;
    variants?: Variant[];
}

interface Variant {
    id: string;
    variantLabel: string;
    isControl: boolean;
    status: string;
    impressions: number;
    clicks: number;
    ctr: number;
    conversions: number;
    pValue: number | null;
    isSignificant: boolean;
}

interface SignificanceResult {
    hasWinner: boolean;
    winnerId?: string;
    recommendation: string;
    variants: {
        id: string;
        label: string;
        metricValue: number;
        pValue: number | null;
        isSignificant: boolean;
    }[];
}

export function ExperimentsPanel() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [experiments, setExperiments] = useState<Experiment[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [analysis, setAnalysis] = useState<SignificanceResult | null>(null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [showCreate, setShowCreate] = useState(false);

    const headers = useCallback(() => ({
        'Authorization': `Bearer ${token}`,
        'X-Account-ID': currentAccount?.id || '',
        'Content-Type': 'application/json'
    }), [token, currentAccount?.id]);

    const fetchExperiments = useCallback(async () => {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/ads/experiments', { headers: headers() });
            const data = await res.json();
            setExperiments(data.experiments || []);
        } catch (err) {
            Logger.error('Failed to fetch experiments', { error: err });
        } finally {
            setIsLoading(false);
        }
    }, [currentAccount, headers]);

    useEffect(() => {
        fetchExperiments();
    }, [fetchExperiments]);

    const handleAnalyze = async (id: string) => {
        setIsAnalyzing(true);
        setSelectedId(id);
        try {
            const res = await fetch(`/api/ads/experiments/${id}/analyze`, {
                method: 'POST',
                headers: headers()
            });
            const data = await res.json();
            setAnalysis(data.analysis);
        } catch (err) {
            Logger.error('Failed to analyze experiment', { error: err });
        } finally {
            setIsAnalyzing(false);
        }
    };

    const handlePause = async (id: string) => {
        try {
            await fetch(`/api/ads/experiments/${id}/pause`, {
                method: 'POST',
                headers: headers()
            });
            fetchExperiments();
        } catch (err) {
            Logger.error('Failed to pause experiment', { error: err });
        }
    };

    const handleResume = async (id: string) => {
        try {
            await fetch(`/api/ads/experiments/${id}/resume`, {
                method: 'POST',
                headers: headers()
            });
            fetchExperiments();
        } catch (err) {
            Logger.error('Failed to resume experiment', { error: err });
        }
    };

    const getStatusBadge = (status: string) => {
        const styles: Record<string, string> = {
            'RUNNING': 'bg-green-100 text-green-700',
            'PAUSED': 'bg-amber-100 text-amber-700',
            'CONCLUDED': 'bg-blue-100 text-blue-700',
            'DRAFT': 'bg-gray-100 text-gray-600'
        };
        const icons: Record<string, React.ReactNode> = {
            'RUNNING': <Play size={12} />,
            'PAUSED': <Pause size={12} />,
            'CONCLUDED': <Trophy size={12} />,
            'DRAFT': <Clock size={12} />
        };
        return (
            <span className={`inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium rounded-full ${styles[status] || styles['DRAFT']}`}>
                {icons[status] || icons['DRAFT']}
                {status}
            </span>
        );
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-xl font-semibold text-gray-900 flex items-center gap-2">
                        <FlaskConical className="text-indigo-600" />
                        A/B Experiments
                    </h2>
                    <p className="text-sm text-gray-500 mt-1">Test creative variants and find winners automatically</p>
                </div>
                <div className="flex gap-2">
                    <button
                        onClick={() => fetchExperiments()}
                        className="p-2 text-gray-500 hover:bg-gray-100 rounded-lg"
                        title="Refresh"
                    >
                        <RefreshCw size={18} />
                    </button>
                    <button
                        onClick={() => setShowCreate(true)}
                        className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700"
                    >
                        <Plus size={18} />
                        New Experiment
                    </button>
                </div>
            </div>

            {/* Experiments List */}
            {experiments.length === 0 ? (
                <div className="text-center py-16 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                    <FlaskConical className="w-12 h-12 mx-auto text-gray-400 mb-4" />
                    <h3 className="text-lg font-semibold text-gray-900 mb-2">No Experiments Yet</h3>
                    <p className="text-gray-500 mb-4">Create your first A/B test to optimize ad performance</p>
                    <button
                        onClick={() => setShowCreate(true)}
                        className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
                    >
                        <Plus size={18} />
                        Create Experiment
                    </button>
                </div>
            ) : (
                <div className="grid gap-4">
                    {experiments.map(exp => (
                        <div
                            key={exp.id}
                            className="bg-white rounded-xl border border-gray-200 shadow-xs p-5 hover:border-indigo-300 transition-colors"
                        >
                            <div className="flex items-start justify-between">
                                <div className="flex-1">
                                    <div className="flex items-center gap-3 mb-2">
                                        <h3 className="font-semibold text-gray-900">{exp.name}</h3>
                                        {getStatusBadge(exp.status)}
                                        <span className="text-xs text-gray-500 bg-gray-100 px-2 py-0.5 rounded">
                                            {exp.platform.toUpperCase()}
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-4 text-sm text-gray-500">
                                        <span>Metric: <strong className="text-gray-700">{exp.primaryMetric.toUpperCase()}</strong></span>
                                        <span>Variants: <strong className="text-gray-700">{exp.variants?.length || 0}</strong></span>
                                        <span>Created: {new Date(exp.createdAt).toLocaleDateString()}</span>
                                    </div>
                                </div>

                                <div className="flex items-center gap-2">
                                    <button
                                        onClick={() => handleAnalyze(exp.id)}
                                        disabled={isAnalyzing && selectedId === exp.id}
                                        className="flex items-center gap-1 px-3 py-1.5 text-sm bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100"
                                    >
                                        {isAnalyzing && selectedId === exp.id ? (
                                            <Loader2 size={14} className="animate-spin" />
                                        ) : (
                                            <BarChart3 size={14} />
                                        )}
                                        Analyze
                                    </button>
                                    {exp.status === 'RUNNING' ? (
                                        <button
                                            onClick={() => handlePause(exp.id)}
                                            className="p-1.5 text-amber-600 hover:bg-amber-50 rounded-lg"
                                            title="Pause"
                                        >
                                            <Pause size={16} />
                                        </button>
                                    ) : exp.status === 'PAUSED' ? (
                                        <button
                                            onClick={() => handleResume(exp.id)}
                                            className="p-1.5 text-green-600 hover:bg-green-50 rounded-lg"
                                            title="Resume"
                                        >
                                            <Play size={16} />
                                        </button>
                                    ) : null}
                                    <ChevronRight className="text-gray-400" size={18} />
                                </div>
                            </div>

                            {/* Analysis Results */}
                            {analysis && selectedId === exp.id && (
                                <div className="mt-4 pt-4 border-t border-gray-100">
                                    <div className={`p-3 rounded-lg ${analysis.hasWinner ? 'bg-green-50 border border-green-200' : 'bg-gray-50'}`}>
                                        {analysis.hasWinner ? (
                                            <div className="flex items-center gap-2 text-green-700">
                                                <CheckCircle2 size={18} />
                                                <span className="font-medium">Winner Found!</span>
                                            </div>
                                        ) : (
                                            <div className="flex items-center gap-2 text-gray-600">
                                                <AlertCircle size={18} />
                                                <span>No significant winner yet</span>
                                            </div>
                                        )}
                                        <p className="text-sm mt-2 text-gray-600">{analysis.recommendation}</p>
                                    </div>

                                    {/* Variant Results */}
                                    <div className="mt-4 grid gap-2">
                                        {analysis.variants.map(v => (
                                            <div
                                                key={v.id}
                                                className={`flex items-center justify-between p-3 rounded-lg ${v.isSignificant ? 'bg-green-50' : 'bg-gray-50'
                                                    }`}
                                            >
                                                <span className="font-medium text-gray-900">Variant {v.label}</span>
                                                <div className="flex items-center gap-4 text-sm">
                                                    <span>Value: <strong>{v.metricValue.toFixed(2)}%</strong></span>
                                                    <span>p-value: <strong>{v.pValue?.toFixed(4) || '—'}</strong></span>
                                                    {v.isSignificant && (
                                                        <span className="text-green-600 font-medium flex items-center gap-1">
                                                            <CheckCircle2 size={14} />
                                                            Significant
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            {/* Create Modal Placeholder */}
            {showCreate && (
                <CreateExperimentModal
                    onClose={() => setShowCreate(false)}
                    onCreated={() => {
                        setShowCreate(false);
                        fetchExperiments();
                    }}
                />
            )}
        </div>
    );
}


interface CreateModalProps {
    onClose: () => void;
    onCreated: () => void;
}

function CreateExperimentModal({ onClose, onCreated }: CreateModalProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [name, setName] = useState('');
    const [platform, setPlatform] = useState<'google' | 'meta'>('google');
    const [primaryMetric, setPrimaryMetric] = useState<'ctr' | 'conversions' | 'roas'>('ctr');
    const [adAccountId, setAdAccountId] = useState('');
    const [adAccounts, setAdAccounts] = useState<{ id: string; name: string; platform: string }[]>([]);
    const [isSubmitting, setIsSubmitting] = useState(false);

    useEffect(() => {
        fetchAdAccounts();
    }, []);

    const fetchAdAccounts = async () => {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/ads', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            const data = await res.json();
            const active = data.filter((a: any) => a.externalId !== 'PENDING_SETUP');
            setAdAccounts(active);
            if (active.length > 0) setAdAccountId(active[0].id);
        } catch (err) {
            Logger.error('Failed to fetch ad accounts', { error: err });
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim() || !adAccountId) return;

        setIsSubmitting(true);
        try {
            const res = await fetch('/api/ads/experiments', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || '',
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    name: name.trim(),
                    platform,
                    adAccountId,
                    primaryMetric
                })
            });

            if (res.ok) {
                onCreated();
            } else {
                const err = await res.json();
                alert(err.error || 'Failed to create experiment');
            }
        } catch (err) {
            alert('Error creating experiment');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <div className="bg-white rounded-xl shadow-xl p-6 max-w-md w-full mx-4">
                <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                    <FlaskConical className="text-indigo-600" />
                    Create A/B Experiment
                </h3>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                            Experiment Name
                        </label>
                        <input
                            type="text"
                            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                            placeholder="e.g. Holiday Headlines Test"
                            value={name}
                            onChange={e => setName(e.target.value)}
                            required
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                            Ad Account
                        </label>
                        <select
                            className="w-full p-3 border border-gray-300 rounded-lg"
                            value={adAccountId}
                            onChange={e => {
                                setAdAccountId(e.target.value);
                                const acc = adAccounts.find(a => a.id === e.target.value);
                                if (acc) setPlatform(acc.platform.toLowerCase() as 'google' | 'meta');
                            }}
                            required
                        >
                            {adAccounts.map(acc => (
                                <option key={acc.id} value={acc.id}>
                                    {acc.name} ({acc.platform})
                                </option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                            Primary Metric
                        </label>
                        <select
                            className="w-full p-3 border border-gray-300 rounded-lg"
                            value={primaryMetric}
                            onChange={e => setPrimaryMetric(e.target.value as any)}
                        >
                            <option value="ctr">Click-Through Rate (CTR)</option>
                            <option value="conversions">Conversion Rate</option>
                            <option value="roas">Return on Ad Spend (ROAS)</option>
                        </select>
                    </div>

                    <div className="flex gap-3 justify-end pt-2">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={isSubmitting || !name.trim() || !adAccountId}
                            className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2"
                        >
                            {isSubmitting && <Loader2 size={16} className="animate-spin" />}
                            Create Experiment
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

