/**
 * FlowBuilder - Visual automation flow builder using ReactFlow.
 * Popup-driven canvas experience with modal selectors for triggers, steps, and actions.
 */
import React, { useState, useCallback, useRef, useEffect } from 'react';
import {
    ReactFlow,
    ReactFlowProvider,
    addEdge,
    useNodesState,
    useEdgesState,
    Controls,
    Background,
    Connection,
    Edge,
    Node,
    Panel,
    useReactFlow,
    NodeTypes,
    MarkerType,
} from '@xyflow/react';
import '@xyflow/react/dist/style.css';

// Custom edge styles for solid connected lines
const defaultEdgeOptions = {
    type: 'smoothstep',
    animated: false,
    style: { stroke: '#3b82f6', strokeWidth: 2 },
    markerEnd: {
        type: MarkerType.ArrowClosed,
        color: '#3b82f6',
        width: 20,
        height: 20,
    },
};
import { TriggerNode, ActionNode, DelayNode, ConditionNode } from './FlowNodes';
import { NodeConfigPanel } from './NodeConfigPanel';
import {
    StartingPointCard,
    EventSelectorModal,
    StepTypePopup,
    ActionSelectorModal,
    RecipeSelectorModal,
    StepType,
    AutomationRecipe,
} from './flow';

// Define Node Types - Cast needed for React 19 compatibility with @xyflow/react types
const nodeTypes = {
    trigger: TriggerNode,
    action: ActionNode,
    delay: DelayNode,
    condition: ConditionNode,
} as NodeTypes;

let id = 0;
const getId = () => `node_${Date.now()}_${id++}`;

interface ControlsProps {
    onSave: (nodes: Node[], edges: Edge[]) => void;
    onCancel: () => void;
}

const FlowControls: React.FC<ControlsProps> = ({ onSave, onCancel }) => {
    const { getNodes, getEdges } = useReactFlow();

    return (
        <div className="flex gap-2 bg-white p-2 rounded-sm shadow-xs border">
            <button
                className="px-3 py-1.5 text-sm font-medium text-gray-600 bg-gray-100 rounded-sm hover:bg-gray-200"
                onClick={onCancel}
            >
                Cancel
            </button>
            <button
                className="px-3 py-1.5 text-sm font-medium text-white bg-blue-600 rounded-sm hover:bg-blue-700"
                onClick={() => onSave(getNodes(), getEdges())}
            >
                Save Flow
            </button>
        </div>
    );
};

interface Props {
    initialFlow?: { nodes: Node[], edges: Edge[] } | null;
    onSave: (flow: { nodes: Node[], edges: Edge[] }) => void;
    onCancel: () => void;
}

const FlowBuilderContent: React.FC<Props> = ({ initialFlow, onSave, onCancel }) => {
    const reactFlowWrapper = useRef<HTMLDivElement>(null);
    const [nodes, setNodes, onNodesChange] = useNodesState<Node>([]);
    const [edges, setEdges, onEdgesChange] = useEdgesState<Edge>([]);
    const [selectedNode, setSelectedNode] = useState<Node | null>(null);
    const { getViewport } = useReactFlow();

    // Modal states
    const [showEventSelector, setShowEventSelector] = useState(false);
    const [showStepPopup, setShowStepPopup] = useState(false);
    const [showActionSelector, setShowActionSelector] = useState(false);
    const [showRecipeSelector, setShowRecipeSelector] = useState(false);
    const [stepPopupPosition, setStepPopupPosition] = useState({ x: 0, y: 0 });
    const [pendingNodeParent, setPendingNodeParent] = useState<string | null>(null);


    // Stable callback refs for node operations (to avoid circular deps in node data)
    const copyNodeRef = useRef<(nodeId: string) => void>(() => { });
    const deleteNodeRef = useRef<(nodeId: string) => void>(() => { });

    // Load initial flow - start with empty canvas if no existing flow
    useEffect(() => {
        if (initialFlow && initialFlow.nodes && initialFlow.nodes.length > 0) {
            setNodes(initialFlow.nodes);
            setEdges(initialFlow.edges || []);
        } else {
            // Empty canvas - show starting point card
            setNodes([]);
            setEdges([]);
        }
    }, [initialFlow, setNodes, setEdges]);

    const onConnect = useCallback(
        (params: Connection) => setEdges((eds) => addEdge(params, eds)),
        [setEdges],
    );

    // Handle node click to open config panel
    const onNodeClick = useCallback((_event: React.MouseEvent, node: Node) => {
        setSelectedNode(node);
    }, []);

    // Handle pane click to close config panel
    const onPaneClick = useCallback(() => {
        setSelectedNode(null);
    }, []);

    // Update node data from config panel
    const updateNodeData = useCallback((nodeId: string, newData: any) => {
        setNodes((nds) =>
            nds.map((node) => {
                if (node.id === nodeId) {
                    return { ...node, data: newData };
                }
                return node;
            })
        );
        // Update selected node reference
        setSelectedNode((prev) => prev?.id === nodeId ? { ...prev, data: newData } : prev);
    }, [setNodes]);

    // Delete node from config panel
    const deleteNode = useCallback((nodeId: string) => {
        setNodes((nds) => nds.filter((node) => node.id !== nodeId));
        setEdges((eds) => eds.filter((edge) => edge.source !== nodeId && edge.target !== nodeId));
        setSelectedNode(null);
    }, [setNodes, setEdges]);

    // --- Node Copy/Move Operations ---
    const [clipboard, setClipboard] = useState<Node | null>(null);

    const handleCopyNode = useCallback((nodeId: string) => {
        const nodeToCopy = nodes.find(n => n.id === nodeId);
        if (nodeToCopy) {
            // Deep clone the node with a new ID
            setClipboard({
                ...nodeToCopy,
                id: getId(),
                data: { ...nodeToCopy.data }
            });
        }
    }, [nodes]);

    const handleDeleteNode = useCallback((nodeId: string) => {
        if (confirm('Delete this node?')) {
            deleteNode(nodeId);
        }
    }, [deleteNode]);

    // Keep refs in sync with callbacks
    useEffect(() => {
        copyNodeRef.current = handleCopyNode;
        deleteNodeRef.current = handleDeleteNode;
    }, [handleCopyNode, handleDeleteNode]);

    // Wrapper functions that use refs (stable references for node data)
    const onNodeCopy = useCallback((nodeId: string) => copyNodeRef.current(nodeId), []);
    const onNodeDelete = useCallback((nodeId: string) => deleteNodeRef.current(nodeId), []);

    // --- Step Type Selection (+ button) ---
    const handleOpenStepPopup = useCallback((nodeId: string, buttonPosition: { x: number; y: number }) => {
        setPendingNodeParent(nodeId);
        setStepPopupPosition(buttonPosition);
        setShowStepPopup(true);
    }, []);

    // --- Event (Trigger) Selection ---
    const handleEventSelect = useCallback((event: { triggerType: string; label: string }) => {
        const newNode: Node = {
            id: getId(),
            type: 'trigger',
            position: { x: 250, y: 100 },
            data: {
                label: event.label,
                config: { triggerType: event.triggerType },
                onAddStep: handleOpenStepPopup,
                onCopy: onNodeCopy,
                onDelete: onNodeDelete,
            },
        };
        setNodes([newNode]);
        setEdges([]);
    }, [setNodes, setEdges, handleOpenStepPopup, onNodeCopy, onNodeDelete]);

    // --- Recipe Selection ---
    const handleRecipeSelect = useCallback((recipe: AutomationRecipe) => {
        // Generate positions for nodes
        const nodesWithPositions = recipe.nodes.map((node, index) => ({
            ...node,
            id: `recipe_${node.id}_${getId()}`,
            position: { x: 250, y: 100 + index * 180 },
            data: {
                ...node.data,
                onAddStep: handleOpenStepPopup,
                onCopy: onNodeCopy,
                onDelete: onNodeDelete,
            },
        }));

        // Update edge references to new node IDs
        const edgesWithIds = recipe.edges.map((edge, index) => {
            const sourceNode = nodesWithPositions.find(n => n.id.includes(`_${edge.source}_`));
            const targetNode = nodesWithPositions.find(n => n.id.includes(`_${edge.target}_`));
            return {
                ...edge,
                id: `recipe_edge_${index}_${getId()}`,
                source: sourceNode?.id || edge.source,
                target: targetNode?.id || edge.target,
            };
        });

        setNodes(nodesWithPositions);
        setEdges(edgesWithIds);
    }, [setNodes, setEdges, handleOpenStepPopup, onNodeCopy, onNodeDelete]);

    const handleStepSelect = useCallback((stepType: StepType) => {
        if (!pendingNodeParent) return;

        // Find parent node to position new node below it
        const parentNode = nodes.find(n => n.id === pendingNodeParent);
        if (!parentNode) return;

        const newPosition = {
            x: parentNode.position.x,
            y: parentNode.position.y + 200,
        };

        if (stepType === 'action') {
            // Open action selector for action type
            setShowActionSelector(true);
        } else if (stepType === 'delay') {
            // Add delay node directly
            const newNode: Node = {
                id: getId(),
                type: 'delay',
                position: newPosition,
                data: {
                    label: 'Delay',
                    config: { duration: 1, unit: 'hours' },
                    onAddStep: handleOpenStepPopup,
                    onCopy: onNodeCopy,
                    onDelete: onNodeDelete,
                },
            };
            addNodeAndConnect(newNode, pendingNodeParent);
        } else if (stepType === 'condition') {
            // Add condition node
            const newNode: Node = {
                id: getId(),
                type: 'condition',
                position: newPosition,
                data: {
                    label: 'Condition',
                    config: {},
                    onAddStep: handleOpenStepPopup,
                    onCopy: onNodeCopy,
                    onDelete: onNodeDelete,
                },
            };
            addNodeAndConnect(newNode, pendingNodeParent);
        } else if (stepType === 'goal') {
            // Goal node - track when contact reaches a goal
            const newNode: Node = {
                id: getId(),
                type: 'action',
                position: newPosition,
                data: {
                    label: 'Goal',
                    config: { actionType: 'GOAL', goalName: 'Conversion' },
                    onAddStep: handleOpenStepPopup,
                    onCopy: onNodeCopy,
                    onDelete: onNodeDelete,
                },
            };
            addNodeAndConnect(newNode, pendingNodeParent);
        } else if (stepType === 'jump') {
            // Jump to another step
            const newNode: Node = {
                id: getId(),
                type: 'action',
                position: newPosition,
                data: {
                    label: 'Jump',
                    config: { actionType: 'JUMP', targetNodeId: '' },
                    onAddStep: handleOpenStepPopup,
                    onCopy: onNodeCopy,
                    onDelete: onNodeDelete,
                },
            };
            addNodeAndConnect(newNode, pendingNodeParent);
        } else if (stepType === 'exit') {
            // Exit automation
            const newNode: Node = {
                id: getId(),
                type: 'action',
                position: newPosition,
                data: {
                    label: 'Exit',
                    config: { actionType: 'EXIT' },
                    onCopy: onNodeCopy,
                    onDelete: onNodeDelete,
                },
            };
            addNodeAndConnect(newNode, pendingNodeParent);
        }
    }, [pendingNodeParent, nodes]);

    // --- Action Selection ---
    const handleActionSelect = useCallback((action: { actionType: string; label: string }) => {
        if (!pendingNodeParent) return;

        const parentNode = nodes.find(n => n.id === pendingNodeParent);
        if (!parentNode) return;

        const newNode: Node = {
            id: getId(),
            type: 'action',
            position: {
                x: parentNode.position.x,
                y: parentNode.position.y + 200,
            },
            data: {
                label: action.label,
                config: { actionType: action.actionType },
                onAddStep: handleOpenStepPopup,
                onCopy: onNodeCopy,
                onDelete: onNodeDelete,
            },
        };
        addNodeAndConnect(newNode, pendingNodeParent);
        setShowActionSelector(false);
    }, [pendingNodeParent, nodes]);

    // Helper to add a node and connect it to parent
    const addNodeAndConnect = useCallback((newNode: Node, parentId: string) => {
        setNodes((nds) => [...nds, newNode]);
        setEdges((eds) => [
            ...eds,
            {
                id: `e_${parentId}_${newNode.id}`,
                source: parentId,
                target: newNode.id,
                ...defaultEdgeOptions,
            },
        ]);
        setPendingNodeParent(null);
    }, [setNodes, setEdges]);

    // Check if canvas is empty
    const isEmptyCanvas = nodes.length === 0;

    return (
        <div className="h-full w-full relative">
            {/* Canvas */}
            <div className="flex-1 h-full relative" ref={reactFlowWrapper}>
                <ReactFlow
                    nodes={nodes}
                    edges={edges}
                    onNodesChange={onNodesChange}
                    onEdgesChange={onEdgesChange}
                    onConnect={onConnect}
                    onNodeClick={onNodeClick}
                    onPaneClick={onPaneClick}
                    nodeTypes={nodeTypes}
                    fitView
                    defaultEdgeOptions={defaultEdgeOptions}
                    snapToGrid
                >
                    <Controls />
                    <Background color="#e2e8f0" gap={16} />
                    <Panel position="top-right">
                        <FlowControls
                            onSave={(n, e) => onSave({ nodes: n, edges: e })}
                            onCancel={onCancel}
                        />
                    </Panel>
                </ReactFlow>

                {/* Starting Point Card (empty canvas) */}
                {isEmptyCanvas && (
                    <StartingPointCard
                        onClick={() => setShowEventSelector(true)}
                        onRecipeClick={() => setShowRecipeSelector(true)}
                    />
                )}
            </div>

            {/* Node Configuration Panel */}
            {selectedNode && (
                <NodeConfigPanel
                    node={selectedNode}
                    onClose={() => setSelectedNode(null)}
                    onUpdate={updateNodeData}
                    onDelete={deleteNode}
                />
            )}

            {/* Event Selector Modal */}
            <EventSelectorModal
                isOpen={showEventSelector}
                onClose={() => setShowEventSelector(false)}
                onSelect={handleEventSelect}
            />

            {/* Step Type Popup */}
            <StepTypePopup
                isOpen={showStepPopup}
                position={stepPopupPosition}
                onClose={() => {
                    setShowStepPopup(false);
                    setPendingNodeParent(null);
                }}
                onSelect={handleStepSelect}
            />

            {/* Action Selector Modal */}
            <ActionSelectorModal
                isOpen={showActionSelector}
                onClose={() => {
                    setShowActionSelector(false);
                    setPendingNodeParent(null);
                }}
                onSelect={handleActionSelect}
            />

            {/* Recipe Selector Modal */}
            <RecipeSelectorModal
                isOpen={showRecipeSelector}
                onClose={() => setShowRecipeSelector(false)}
                onSelect={handleRecipeSelect}
            />
        </div>
    );
};

export const FlowBuilder: React.FC<Props> = (props) => {
    return (
        <ReactFlowProvider>
            <FlowBuilderContent {...props} />
        </ReactFlowProvider>
    );
};

import { Fragment, useEffect, useState } from 'react';
import DOMPurify from 'dompurify';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import {
    TrendingUp,
    TrendingDown,
    Loader2,
    ChevronLeft,
    ChevronRight,
    DollarSign,
    MousePointerClick,
    Eye,
    Target,
    RefreshCw,
    Lightbulb,
    ChevronDown,
    ChevronUp,
    MessageCirclePlus,
    AlertCircle
} from 'lucide-react';
import { AdContextModal } from './AdContextModal';
import { CampaignProductsPanel } from './CampaignProductsPanel';
import { formatCurrency, formatCompact } from '../../utils/format';

interface CampaignInsight {
    campaignId: string;
    campaignName: string;
    status: string;
    spend: number;
    impressions: number;
    clicks: number;
    conversions: number;
    conversionsValue: number;
    roas: number;
    ctr: number;
    cpc: number;
    cpa: number;
    currency: string;
    dateStart: string;
    dateStop: string;
}

interface DailyTrend {
    date: string;
    spend: number;
    impressions: number;
    clicks: number;
    conversions: number;
    conversionsValue: number;
}

interface GoogleAdsCampaignsProps {
    adAccountId: string;
    accountName: string;
    onBack: () => void;
    hideBackButton?: boolean;
    /** Callback to initiate OAuth reconnection when tokens are expired */
    onReconnect?: () => void;
}

export function GoogleAdsCampaigns({ adAccountId, accountName, onBack, hideBackButton, onReconnect }: GoogleAdsCampaignsProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [campaigns, setCampaigns] = useState<CampaignInsight[]>([]);
    const [trends, setTrends] = useState<DailyTrend[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [sortBy, setSortBy] = useState<keyof CampaignInsight>('spend');
    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
    const [days, setDays] = useState(30);

    // AI Suggestions state
    const [suggestions, setSuggestions] = useState<any>(null);
    const [loadingSuggestions, setLoadingSuggestions] = useState(false);
    const [showSuggestions, setShowSuggestions] = useState(true);
    const [showContextModal, setShowContextModal] = useState(false);

    // Expanded campaigns for product view
    const [expandedCampaigns, setExpandedCampaigns] = useState<Set<string>>(new Set());

    useEffect(() => {
        fetchData();
    }, [adAccountId, days]);

    async function fetchData() {
        setIsLoading(true);
        setError(null);
        try {
            const headers = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount?.id || ''
            };

            const [campaignsRes, trendsRes] = await Promise.all([
                fetch(`/api/ads/${adAccountId}/campaigns?days=${days}`, { headers }),
                fetch(`/api/ads/${adAccountId}/trends?days=${days}`, { headers })
            ]);

            if (!campaignsRes.ok) {
                const err = await campaignsRes.json();
                throw new Error(err.error || 'Failed to load campaigns');
            }

            const campaignsData = await campaignsRes.json();
            const trendsData = trendsRes.ok ? await trendsRes.json() : [];

            setCampaigns(campaignsData);
            setTrends(trendsData);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
    }

    async function fetchSuggestions() {
        setLoadingSuggestions(true);
        try {
            const headers = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount?.id || ''
            };
            const res = await fetch(`/api/ads/${adAccountId}/analysis`, { headers });
            if (res.ok) {
                const data = await res.json();
                setSuggestions(data);
            }
        } catch (err) {
            Logger.error('Failed to fetch suggestions', { error: err });
        } finally {
            setLoadingSuggestions(false);
        }
    }

    useEffect(() => {
        fetchSuggestions();
    }, [adAccountId]);

    function handleSort(column: keyof CampaignInsight) {
        if (sortBy === column) {
            setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
        } else {
            setSortBy(column);
            setSortOrder('desc');
        }
    }

    const sortedCampaigns = [...campaigns].sort((a, b) => {
        const aVal = a[sortBy];
        const bVal = b[sortBy];
        if (typeof aVal === 'number' && typeof bVal === 'number') {
            return sortOrder === 'asc' ? aVal - bVal : bVal - aVal;
        }
        return sortOrder === 'asc'
            ? String(aVal).localeCompare(String(bVal))
            : String(bVal).localeCompare(String(aVal));
    });

    const totals = campaigns.reduce((acc, c) => ({
        spend: acc.spend + (c.spend || 0),
        impressions: acc.impressions + (c.impressions || 0),
        clicks: acc.clicks + (c.clicks || 0),
        conversions: acc.conversions + (c.conversions || 0),
        conversionsValue: acc.conversionsValue + (c.conversionsValue || 0)
    }), { spend: 0, impressions: 0, clicks: 0, conversions: 0, conversionsValue: 0 });

    const formatNumber = (v: number) => formatCompact(v);

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    {!hideBackButton && (
                        <button
                            onClick={onBack}
                            className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                        >
                            <ChevronLeft size={20} />
                        </button>
                    )}
                    <div>
                        <h2 className="text-xl font-bold text-gray-900">{accountName}</h2>
                        <p className="text-sm text-gray-500">Campaign Performance Breakdown</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <select
                        value={days}
                        onChange={(e) => setDays(Number(e.target.value))}
                        className="px-3 py-2 border border-gray-300 rounded-lg text-sm"
                    >
                        <option value={7}>Last 7 days</option>
                        <option value={14}>Last 14 days</option>
                        <option value={30}>Last 30 days</option>
                        <option value={60}>Last 60 days</option>
                        <option value={90}>Last 90 days</option>
                    </select>
                    <button
                        onClick={fetchData}
                        className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-lg"
                    >
                        <RefreshCw size={18} />
                    </button>
                </div>
            </div>

            {error && (
                <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-start justify-between gap-3">
                    <div className="flex items-start gap-2">
                        <AlertCircle className="text-red-500 shrink-0 mt-0.5" size={18} />
                        <div>
                            <p className="font-medium text-red-700">Failed to load campaign data</p>
                            <p className="text-sm text-red-600 mt-0.5">{error}</p>
                        </div>
                    </div>
                    {onReconnect && (
                        <button
                            onClick={onReconnect}
                            className="flex items-center gap-1.5 px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 shrink-0"
                        >
                            <RefreshCw size={14} />
                            Reconnect
                        </button>
                    )}
                </div>
            )}

            {/* AI Suggestions Panel - at top for prominence */}
            <div className="bg-linear-to-r from-purple-50 to-indigo-50 rounded-xl border border-purple-200 shadow-xs overflow-hidden">
                <div className="p-4 flex items-center justify-between">
                    <button
                        onClick={() => setShowSuggestions(!showSuggestions)}
                        className="flex items-center gap-3 hover:opacity-80 transition-opacity"
                    >
                        <div className="p-2 bg-purple-500 rounded-lg">
                            <Lightbulb size={20} className="text-white" />
                        </div>
                        <div className="text-left">
                            <h3 className="font-semibold text-gray-900">AI Optimization Suggestions</h3>
                            <p className="text-sm text-gray-600">Smart recommendations based on your campaign data</p>
                        </div>
                    </button>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={() => setShowContextModal(true)}
                            className="p-2 text-purple-600 hover:bg-purple-100 rounded-lg transition-colors"
                            title="Add business context"
                        >
                            <MessageCirclePlus size={18} />
                        </button>
                        <button
                            onClick={fetchSuggestions}
                            disabled={loadingSuggestions}
                            className="p-2 text-purple-600 hover:bg-purple-100 rounded-lg transition-colors disabled:opacity-50"
                            title="Refresh suggestions"
                        >
                            <RefreshCw size={18} className={loadingSuggestions ? 'animate-spin' : ''} />
                        </button>
                        <button
                            onClick={() => setShowSuggestions(!showSuggestions)}
                            className="p-2 text-gray-500 hover:bg-purple-100 rounded-lg transition-colors"
                        >
                            {showSuggestions ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
                        </button>
                    </div>
                </div>

                {showSuggestions && suggestions && (
                    <div className="px-4 pb-4 space-y-3">
                        {suggestions.suggestions?.map((suggestion: string, i: number) => (
                            <div key={i} className="bg-white p-4 rounded-lg border border-purple-100">
                                <p className="text-gray-800" dangerouslySetInnerHTML={{
                                    __html: DOMPurify.sanitize(
                                        suggestion.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>'),
                                        { ALLOWED_TAGS: ['strong', 'b', 'em', 'i'] }
                                    )
                                }} />
                            </div>
                        ))}

                        {suggestions.action_items && suggestions.action_items.length > 0 && (
                            <div className="bg-white p-4 rounded-lg border border-purple-100">
                                <h4 className="font-medium text-gray-900 mb-2">Quick Action Items:</h4>
                                <ul className="space-y-1">
                                    {suggestions.action_items.map((item: string, i: number) => (
                                        <li key={i} className="text-sm text-gray-700 flex items-start gap-2">
                                            <span className="text-purple-500 mt-1">•</span>
                                            {item}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        )}
                    </div>
                )}

                {showSuggestions && !suggestions && !loadingSuggestions && (
                    <div className="px-4 pb-4">
                        <p className="text-gray-500 text-sm">No suggestions available. Try refreshing the data.</p>
                    </div>
                )}
            </div>

            {/* Context Modal */}
            <AdContextModal
                isOpen={showContextModal}
                onClose={() => setShowContextModal(false)}
                onSaved={fetchSuggestions}
            />

            {/* Summary Stats */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                <div className="bg-white p-4 rounded-xl border shadow-xs">
                    <div className="flex items-center gap-2 text-gray-500 text-xs uppercase mb-1">
                        <DollarSign size={14} />
                        Total Spend
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                        {formatCurrency(totals.spend, campaigns[0]?.currency)}
                    </div>
                </div>
                <div className="bg-white p-4 rounded-xl border shadow-xs">
                    <div className="flex items-center gap-2 text-gray-500 text-xs uppercase mb-1">
                        <Eye size={14} />
                        Impressions
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                        {formatNumber(totals.impressions)}
                    </div>
                </div>
                <div className="bg-white p-4 rounded-xl border shadow-xs">
                    <div className="flex items-center gap-2 text-gray-500 text-xs uppercase mb-1">
                        <MousePointerClick size={14} />
                        Clicks
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                        {formatNumber(totals.clicks)}
                    </div>
                </div>
                <div className="bg-white p-4 rounded-xl border shadow-xs">
                    <div className="flex items-center gap-2 text-gray-500 text-xs uppercase mb-1">
                        <Target size={14} />
                        Conversions
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                        {formatNumber(totals.conversions)}
                    </div>
                </div>
                <div className="bg-white p-4 rounded-xl border shadow-xs">
                    <div className="flex items-center gap-2 text-gray-500 text-xs uppercase mb-1">
                        <TrendingUp size={14} />
                        ROAS
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                        {totals.spend > 0 ? (totals.conversionsValue / totals.spend).toFixed(2) : '0.00'}x
                    </div>
                </div>
            </div>

            {/* Campaigns Table */}
            <div className="bg-white rounded-xl border shadow-xs overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-gray-50 border-b">
                            <tr>
                                <th className="w-8"></th>
                                {[
                                    { key: 'campaignName', label: 'Campaign' },
                                    { key: 'status', label: 'Status' },
                                    { key: 'spend', label: 'Spend' },
                                    { key: 'impressions', label: 'Impressions' },
                                    { key: 'clicks', label: 'Clicks' },
                                    { key: 'ctr', label: 'CTR' },
                                    { key: 'cpc', label: 'CPC' },
                                    { key: 'conversions', label: 'Conv.' },
                                    { key: 'roas', label: 'ROAS' }
                                ].map(col => (
                                    <th
                                        key={col.key}
                                        onClick={() => handleSort(col.key as keyof CampaignInsight)}
                                        className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer hover:bg-gray-100"
                                    >
                                        <div className="flex items-center gap-1">
                                            {col.label}
                                            {sortBy === col.key && (
                                                sortOrder === 'desc' ? <TrendingDown size={12} /> : <TrendingUp size={12} />
                                            )}
                                        </div>
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                            {sortedCampaigns.length === 0 ? (
                                <tr>
                                    <td colSpan={10} className="px-4 py-8 text-center text-gray-500">
                                        No campaigns found for this period
                                    </td>
                                </tr>
                            ) : sortedCampaigns.map(campaign => {
                                const isExpanded = expandedCampaigns.has(campaign.campaignId);
                                return (
                                    <Fragment key={campaign.campaignId}>
                                        <tr
                                            className={`hover:bg-gray-50 cursor-pointer ${isExpanded ? 'bg-blue-50' : ''}`}
                                            onClick={() => {
                                                const newExpanded = new Set(expandedCampaigns);
                                                if (isExpanded) {
                                                    newExpanded.delete(campaign.campaignId);
                                                } else {
                                                    newExpanded.add(campaign.campaignId);
                                                }
                                                setExpandedCampaigns(newExpanded);
                                            }}
                                        >
                                            <td className="px-2 py-3 text-gray-400">
                                                <ChevronRight
                                                    size={16}
                                                    className={`transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                                                />
                                            </td>
                                            <td className="px-4 py-3">
                                                <div className="font-medium text-gray-900 truncate max-w-xs" title={campaign.campaignName}>
                                                    {campaign.campaignName}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3">
                                                <span className={`px-2 py-1 text-xs rounded-full ${campaign.status === 'ENABLED'
                                                    ? 'bg-green-100 text-green-800'
                                                    : 'bg-gray-100 text-gray-600'
                                                    }`}>
                                                    {campaign.status}
                                                </span>
                                            </td>
                                            <td className="px-4 py-3 font-medium">
                                                {formatCurrency(campaign.spend, campaign.currency)}
                                            </td>
                                            <td className="px-4 py-3 text-gray-600">
                                                {formatNumber(campaign.impressions)}
                                            </td>
                                            <td className="px-4 py-3 text-gray-600">
                                                {formatNumber(campaign.clicks)}
                                            </td>
                                            <td className="px-4 py-3 text-gray-600">
                                                {(campaign.ctr || 0).toFixed(2)}%
                                            </td>
                                            <td className="px-4 py-3 text-gray-600">
                                                {formatCurrency(campaign.cpc || 0, campaign.currency)}
                                            </td>
                                            <td className="px-4 py-3 text-gray-600">
                                                {(campaign.conversions || 0).toFixed(0)}
                                            </td>
                                            <td className="px-4 py-3">
                                                <span className={`font-medium ${(campaign.roas || 0) >= 3 ? 'text-green-600' :
                                                    (campaign.roas || 0) >= 1 ? 'text-yellow-600' :
                                                        'text-red-600'
                                                    }`}>
                                                    {(campaign.roas || 0).toFixed(2)}x
                                                </span>
                                            </td>
                                        </tr>
                                        {isExpanded && (
                                            <tr key={`${campaign.campaignId}-products`}>
                                                <td colSpan={10} className="p-0">
                                                    <CampaignProductsPanel
                                                        adAccountId={adAccountId}
                                                        campaignId={campaign.campaignId}
                                                        days={days}
                                                    />
                                                </td>
                                            </tr>
                                        )}
                                    </Fragment>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Daily Trend Chart (Simple Bar Chart) */}
            {trends.length > 0 && (
                <div className="bg-white rounded-xl border shadow-xs p-6">
                    <h3 className="text-lg font-semibold mb-4">Daily Spend Trend</h3>
                    <div className="flex items-end gap-1 h-40">
                        {trends.map((day, i) => {
                            const maxSpend = Math.max(...trends.map(t => t.spend));
                            const height = maxSpend > 0 ? (day.spend / maxSpend) * 100 : 0;
                            return (
                                <div
                                    key={i}
                                    className="flex-1 bg-blue-500 rounded-t hover:bg-blue-600 transition-colors cursor-pointer group relative"
                                    style={{ height: `${height}%`, minHeight: day.spend > 0 ? '4px' : '0' }}
                                    title={`${day.date}: ${formatCurrency(day.spend, campaigns[0]?.currency)}`}
                                >
                                    <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 bg-gray-900 text-white text-xs px-2 py-1 rounded-sm opacity-0 group-hover:opacity-100 whitespace-nowrap z-10">
                                        {day.date}<br />
                                        {formatCurrency(day.spend, campaigns[0]?.currency)}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                    <div className="flex justify-between text-xs text-gray-500 mt-2">
                        <span>{trends[0]?.date}</span>
                        <span>{trends[trends.length - 1]?.date}</span>
                    </div>
                </div>
            )}
        </div>
    );
}

