interface ActionItem {
    id: string;
    label: string;
    icon: string;
}

interface ActionSelectorModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSelect: (action: { actionType: string; label: string }) => void;
}

export const ActionSelectorModal: React.FC<ActionSelectorModalProps> = ({
    isOpen,
    onClose,
    onSelect,
}) => {
    const [activeCategory, setActiveCategory] = useState<string>('messaging');
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedAction, setSelectedAction] = useState<ActionItem | null>(null);

    // Filter actions by search query
    const filteredActions = useMemo(() => {
        const categoryActions = ACTIONS_BY_CATEGORY[activeCategory] || [];
        if (!searchQuery.trim()) return categoryActions;

        const query = searchQuery.toLowerCase();
        return categoryActions.map(group => ({
            ...group,
            actions: group.actions.filter(a => a.label.toLowerCase().includes(query))
        })).filter(g => g.actions.length > 0);
    }, [activeCategory, searchQuery]);

    const handleDone = () => {
        if (selectedAction) {
            onSelect({ actionType: selectedAction.id, label: selectedAction.label });
            onClose();
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-xs">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b">
                    <h2 className="text-lg font-semibold text-gray-900">Select an Action</h2>
                    <div className="flex items-center gap-3">
                        <div className="relative">
                            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                            <input
                                type="text"
                                placeholder="Search..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="pl-9 pr-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:outline-hidden focus:ring-2 focus:ring-blue-500 focus:border-transparent w-40"
                            />
                        </div>
                        <button
                            onClick={onClose}
                            className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                        >
                            <X size={18} />
                        </button>
                    </div>
                </div>

                {/* Content */}
                <div className="flex flex-1 overflow-hidden">
                    {/* Category Sidebar */}
                    <div className="w-44 bg-gray-50 border-r py-2 overflow-y-auto">
                        {ACTION_CATEGORIES.map((cat) => {
                            const Icon = cat.icon;
                            return (
                                <button
                                    key={cat.id}
                                    onClick={() => {
                                        setActiveCategory(cat.id);
                                        setSelectedAction(null);
                                    }}
                                    className={`w-full flex items-center gap-2.5 px-4 py-2.5 text-sm text-left transition-colors ${activeCategory === cat.id
                                        ? 'bg-white text-blue-600 font-medium border-r-2 border-blue-600'
                                        : 'text-gray-600 hover:bg-gray-100'
                                        }`}
                                >
                                    <Icon size={16} />
                                    {cat.label}
                                </button>
                            );
                        })}
                    </div>

                    {/* Actions List */}
                    <div className="flex-1 p-5 overflow-y-auto">
                        {filteredActions.map((group, idx) => (
                            <div key={idx} className="mb-5 last:mb-0">
                                {group.subcategory && (
                                    <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-2">
                                        {group.subcategory}
                                    </h3>
                                )}
                                <div className="flex flex-wrap gap-2">
                                    {group.actions.map((action) => (
                                        <button
                                            key={action.id}
                                            onClick={() => setSelectedAction(action)}
                                            className={`inline-flex items-center gap-1.5 px-3 py-1.5 text-sm border rounded-full transition-all ${selectedAction?.id === action.id
                                                ? 'bg-blue-50 border-blue-400 text-blue-700 ring-2 ring-blue-200'
                                                : 'bg-white border-gray-200 text-gray-700 hover:border-gray-300 hover:bg-gray-50'
                                                }`}
                                        >
                                            <span>{action.icon}</span>
                                            {action.label}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        ))}
                        {filteredActions.length === 0 && (
                            <div className="text-center text-gray-500 py-8">
                                No actions found matching "{searchQuery}"
                            </div>
                        )}
                    </div>
                </div>

                {/* Footer */}
                <div className="flex items-center justify-end gap-3 px-6 py-4 border-t bg-gray-50">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-gray-800 transition-colors"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleDone}
                        disabled={!selectedAction}
                        className="px-5 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
                    >
                        Done
                    </button>
                </div>
            </div>
        </div>
    );
};

/**
 * EmailTemplateSelectorModal - Modal for selecting saved email templates
 */
import { useState, useEffect } from 'react';
import { X, Search, Layout, FileText, Loader2 } from 'lucide-react';
import { useAuth } from '../../../context/AuthContext';
import { useAccount } from '../../../context/AccountContext';

interface EmailTemplate {
    id: string;
    name: string;
    subject: string | null;
    content: string;
    designJson: any;
    createdAt: string;
    updatedAt: string;
}

interface Props {
    onSelect: (template: EmailTemplate) => void;
    onClose: () => void;
}

export function EmailTemplateSelectorModal({ onSelect, onClose }: Props) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [templates, setTemplates] = useState<EmailTemplate[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');

    useEffect(() => {
        const fetchTemplates = async () => {
            if (!currentAccount) return;
            try {
                const res = await fetch('/api/marketing/templates', {
                    headers: { Authorization: `Bearer ${token}`, 'x-account-id': currentAccount.id }
                });
                if (res.ok) {
                    const data = await res.json();
                    setTemplates(data);
                }
            } catch (err) {
                console.error('Failed to fetch templates:', err);
            } finally {
                setLoading(false);
            }
        };
        fetchTemplates();
    }, [token]);

    const filtered = templates.filter(t =>
        t.name.toLowerCase().includes(search.toLowerCase()) ||
        (t.subject && t.subject.toLowerCase().includes(search.toLowerCase()))
    );

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/40 backdrop-blur-xs">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-indigo-100">
                            <Layout size={18} className="text-indigo-600" />
                        </div>
                        <div>
                            <h3 className="font-semibold text-gray-900">Email Templates</h3>
                            <p className="text-sm text-gray-500">Select a template to use</p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                    >
                        <X size={18} className="text-gray-500" />
                    </button>
                </div>

                {/* Search */}
                <div className="px-6 py-3 border-b">
                    <div className="relative">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            placeholder="Search templates..."
                            className="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                        />
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6">
                    {loading ? (
                        <div className="flex items-center justify-center py-12">
                            <Loader2 size={24} className="animate-spin text-indigo-500" />
                        </div>
                    ) : filtered.length === 0 ? (
                        <div className="text-center py-12">
                            <FileText size={48} className="mx-auto text-gray-300 mb-3" />
                            <p className="text-gray-500">
                                {search ? 'No templates match your search' : 'No templates saved yet'}
                            </p>
                            <p className="text-sm text-gray-400 mt-1">
                                Create an email and save it as a template
                            </p>
                        </div>
                    ) : (
                        <div className="grid grid-cols-2 gap-4">
                            {filtered.map((template) => (
                                <button
                                    key={template.id}
                                    onClick={() => onSelect(template)}
                                    className="p-4 border border-gray-200 rounded-lg hover:border-indigo-300 hover:bg-indigo-50/50 transition-colors text-left group"
                                >
                                    <div className="flex items-start justify-between mb-2">
                                        <div className="p-2 bg-gray-100 rounded group-hover:bg-indigo-100 transition-colors">
                                            <Layout size={16} className="text-gray-600 group-hover:text-indigo-600" />
                                        </div>
                                    </div>
                                    <h4 className="font-medium text-gray-900 truncate">{template.name}</h4>
                                    {template.subject && (
                                        <p className="text-sm text-gray-500 truncate mt-1">{template.subject}</p>
                                    )}
                                    <p className="text-xs text-gray-400 mt-2">
                                        Updated {new Date(template.updatedAt).toLocaleDateString()}
                                    </p>
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="px-6 py-4 border-t bg-gray-50">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-gray-800 transition-colors"
                    >
                        Cancel
                    </button>
                </div>
            </div>
        </div>
    );
}

