/**
 * Handles Google Ads OAuth and Meta Ads token configuration.
 */
export function AdsStep({ draft, setDraft, onNext, onBack, onSkip, isSubmitting }: OnboardingStepProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [googleLoading, setGoogleLoading] = useState(false);
    const [metaLoading, setMetaLoading] = useState(false);
    const [metaToken, setMetaToken] = useState(draft.ads.metaAccessToken || '');
    const [metaAccountId, setMetaAccountId] = useState(draft.ads.metaAdAccountId || '');
    const [metaError, setMetaError] = useState<string | null>(null);
    const [metaSuccess, setMetaSuccess] = useState(false);

    const handleGoogleOAuth = async () => {
        setGoogleLoading(true);
        try {
            // Request OAuth URL from backend
            const res = await fetch('/api/ads/google/auth-url', {
                method: 'GET',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-Id': currentAccount?.id || ''
                }
            });

            if (!res.ok) throw new Error('Failed to get auth URL');

            const data = await res.json();

            // Open OAuth window
            if (data.authUrl) {
                const popup = window.open(data.authUrl, 'google-ads-auth', 'width=600,height=700');

                // Poll for completion
                const checkInterval = setInterval(() => {
                    if (popup?.closed) {
                        clearInterval(checkInterval);
                        // Check if connection was successful
                        checkGoogleConnection();
                    }
                }, 500);
            }
        } catch (error) {
            Logger.error('Google OAuth failed', { error });
        } finally {
            setGoogleLoading(false);
        }
    };

    const checkGoogleConnection = async () => {
        try {
            const res = await fetch('/api/ads/accounts', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-Id': currentAccount?.id || ''
                }
            });

            if (res.ok) {
                const accounts = await res.json();
                const googleAccount = accounts.find((a: { platform: string }) => a.platform === 'GOOGLE_ADS');
                if (googleAccount) {
                    setDraft(prev => ({
                        ...prev,
                        ads: {
                            ...prev.ads,
                            googleConnected: true,
                            googleAccountId: googleAccount.externalId,
                            googleAccountName: googleAccount.name
                        }
                    }));
                }
            }
        } catch (error) {
            Logger.error('Failed to check Google connection', { error });
        }
    };

    const handleMetaConnect = async () => {
        if (!metaToken.trim() || !metaAccountId.trim()) {
            setMetaError('Both access token and account ID are required');
            return;
        }

        setMetaLoading(true);
        setMetaError(null);

        try {
            const res = await fetch('/api/ads/accounts', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-Id': currentAccount?.id || ''
                },
                body: JSON.stringify({
                    platform: 'META_ADS',
                    accessToken: metaToken,
                    externalId: metaAccountId
                })
            });

            if (res.ok) {
                setMetaSuccess(true);
                setDraft(prev => ({
                    ...prev,
                    ads: {
                        ...prev.ads,
                        metaConnected: true,
                        metaAccessToken: metaToken,
                        metaAdAccountId: metaAccountId
                    }
                }));
            } else {
                const data = await res.json();
                setMetaError(data.error || 'Failed to connect Meta Ads');
            }
        } catch (error) {
            Logger.error('Meta Ads connection failed', { error });
            setMetaError('Failed to connect to Meta Ads');
        } finally {
            setMetaLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="text-center pb-4 border-b border-gray-100">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-green-100 text-green-600 mb-4">
                    <TrendingUp size={32} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Connect Ad Accounts</h2>
                <p className="text-gray-500 mt-2">
                    Link Google Ads and Meta Ads for AI-powered campaign management
                </p>
            </div>

            {/* Google Ads */}
            <div className="bg-white rounded-xl p-5 border border-gray-200 shadow-sm">
                <div className="flex items-start gap-4">
                    <div className="flex-shrink-0 w-12 h-12 rounded-xl bg-blue-50 flex items-center justify-center">
                        <GoogleIcon className="w-6 h-6 text-blue-600" />
                    </div>
                    <div className="flex-1">
                        <h3 className="text-base font-semibold text-gray-900">Google Ads</h3>
                        <p className="text-sm text-gray-500 mt-0.5">
                            Connect via OAuth for secure access to your campaigns
                        </p>

                        {draft.ads.googleConnected ? (
                            <div className="mt-3 flex items-center gap-2 text-sm text-green-600">
                                <CheckCircle size={16} />
                                Connected: {draft.ads.googleAccountName || draft.ads.googleAccountId}
                            </div>
                        ) : (
                            <button
                                onClick={handleGoogleOAuth}
                                disabled={googleLoading}
                                className="mt-3 inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 disabled:opacity-50 transition-colors"
                            >
                                {googleLoading ? (
                                    <Loader2 size={16} className="animate-spin" />
                                ) : (
                                    <GoogleIcon className="w-4 h-4" />
                                )}
                                {googleLoading ? 'Connecting...' : 'Connect Google Ads'}
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Meta Ads */}
            <div className="bg-white rounded-xl p-5 border border-gray-200 shadow-sm">
                <div className="flex items-start gap-4">
                    <div className="flex-shrink-0 w-12 h-12 rounded-xl bg-blue-50 flex items-center justify-center">
                        <MetaIcon className="w-6 h-6 text-blue-700" />
                    </div>
                    <div className="flex-1">
                        <h3 className="text-base font-semibold text-gray-900">Meta Ads</h3>
                        <p className="text-sm text-gray-500 mt-0.5">
                            Enter your access token and ad account ID
                        </p>

                        {draft.ads.metaConnected ? (
                            <div className="mt-3 flex items-center gap-2 text-sm text-green-600">
                                <CheckCircle size={16} />
                                Connected: {draft.ads.metaAdAccountId}
                            </div>
                        ) : (
                            <div className="mt-3 space-y-3">
                                <div>
                                    <label className="block text-xs font-medium text-gray-600 mb-1">
                                        Access Token
                                    </label>
                                    <input
                                        type="password"
                                        value={metaToken}
                                        onChange={(e) => setMetaToken(e.target.value)}
                                        placeholder="EAAxxxxxxx..."
                                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-sm font-mono"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-600 mb-1">
                                        Ad Account ID
                                    </label>
                                    <input
                                        type="text"
                                        value={metaAccountId}
                                        onChange={(e) => setMetaAccountId(e.target.value)}
                                        placeholder="act_123456789"
                                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-sm font-mono"
                                    />
                                </div>

                                <button
                                    onClick={handleMetaConnect}
                                    disabled={metaLoading || !metaToken.trim() || !metaAccountId.trim()}
                                    className="inline-flex items-center gap-2 px-4 py-2 bg-blue-700 text-white rounded-lg text-sm font-medium hover:bg-blue-800 disabled:opacity-50 transition-colors"
                                >
                                    {metaLoading ? (
                                        <Loader2 size={16} className="animate-spin" />
                                    ) : (
                                        <MetaIcon className="w-4 h-4" />
                                    )}
                                    {metaLoading ? 'Connecting...' : 'Connect Meta Ads'}
                                </button>

                                {metaError && (
                                    <p className="text-sm text-red-600 flex items-center gap-1.5">
                                        <AlertCircle size={14} />
                                        {metaError}
                                    </p>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Skip Hint */}
            <div className="bg-gray-50 border border-gray-200 rounded-lg p-4 text-sm text-gray-600">
                <p>
                    Ad accounts are optional during setup. You can connect them later in Settings → Ad Accounts.
                </p>
            </div>

            {/* Navigation */}
            <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                <button
                    type="button"
                    onClick={onBack}
                    className="flex items-center gap-2 px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors font-medium"
                >
                    <ArrowLeft size={18} />
                    Back
                </button>

                <div className="flex items-center gap-3">
                    <button
                        type="button"
                        onClick={onSkip}
                        className="flex items-center gap-2 px-4 py-2 text-gray-500 hover:text-gray-700 transition-colors text-sm"
                    >
                        <SkipForward size={16} />
                        Skip for now
                    </button>
                    <button
                        type="button"
                        onClick={onNext}
                        disabled={isSubmitting}
                        className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors font-semibold shadow-lg shadow-blue-500/25"
                    >
                        Continue
                        <ArrowRight size={18} />
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
 * Email Step
 * 
 * Third step in onboarding: Configure default email account for notifications.
 * Simplified SMTP setup with test functionality.
 */

import React, { useState } from 'react';
import { Mail, ArrowRight, ArrowLeft, SkipForward, CheckCircle, AlertCircle, Loader2, ChevronDown, ChevronUp } from 'lucide-react';
import { OnboardingStepProps } from '../types';
import { useAuth } from '../../../context/AuthContext';
import { Logger } from '../../../utils/logger';

/**
 * Handles email configuration with SMTP settings and test functionality.
 */
export function EmailStep({ draft, setDraft, onNext, onBack, onSkip, isSubmitting }: OnboardingStepProps) {
    const { token } = useAuth();
    const [testStatus, setTestStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [testError, setTestError] = useState<string | null>(null);
    const [showAdvanced, setShowAdvanced] = useState(false);

    const handleChange = (field: keyof typeof draft.email, value: string | number | boolean) => {
        setDraft(prev => ({
            ...prev,
            email: { ...prev.email, [field]: value }
        }));
        // Reset test status when settings change
        if (field !== 'enabled' && field !== 'verified') {
            setTestStatus('idle');
            setTestError(null);
        }
    };

    const toggleEnabled = () => {
        const newEnabled = !draft.email.enabled;
        handleChange('enabled', newEnabled);
        if (!newEnabled) {
            // Reset verification when disabling
            handleChange('verified', false);
        }
    };

    const testSmtp = async () => {
        setTestStatus('loading');
        setTestError(null);

        try {
            const res = await fetch('/api/email/test-smtp', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({
                    host: draft.email.smtpHost,
                    port: draft.email.smtpPort,
                    username: draft.email.smtpUsername,
                    password: draft.email.smtpPassword,
                    secure: draft.email.smtpSecure
                })
            });

            const data = await res.json();

            if (res.ok && data.success) {
                setTestStatus('success');
                handleChange('verified', true);
            } else {
                setTestStatus('error');
                setTestError(data.error || 'Could not connect to SMTP server');
            }
        } catch (error) {
            Logger.error('SMTP test failed', { error });
            setTestStatus('error');
            setTestError('Failed to test SMTP connection');
        }
    };

    const canTest = draft.email.smtpHost.trim() &&
        draft.email.smtpUsername.trim() &&
        draft.email.smtpPassword.trim();

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="text-center pb-4 border-b border-gray-100">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-amber-100 text-amber-600 mb-4">
                    <Mail size={32} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Email Setup</h2>
                <p className="text-gray-500 mt-2">
                    Configure outbound email for notifications and customer communication
                </p>
            </div>

            {/* Enable Toggle */}
            <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl border border-gray-200">
                <div>
                    <h3 className="text-sm font-semibold text-gray-900">Enable Email Integration</h3>
                    <p className="text-xs text-gray-500 mt-0.5">Set up SMTP to send emails from OverSeek</p>
                </div>
                <button
                    type="button"
                    onClick={toggleEnabled}
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${draft.email.enabled ? 'bg-blue-600' : 'bg-gray-300'
                        }`}
                >
                    <span
                        className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${draft.email.enabled ? 'translate-x-6' : 'translate-x-1'
                            }`}
                    />
                </button>
            </div>

            {/* Email Configuration */}
            {draft.email.enabled && (
                <div className="space-y-5 animate-in fade-in duration-200">
                    {/* Basic Info */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1.5">
                                Display Name
