                        onClick={onNext}
                        disabled={isSubmitting}
                        className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors font-semibold shadow-lg shadow-blue-500/25"
                    >
                        Continue
                        <ArrowRight size={18} />
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
 * Plugin Step
 * 
 * Second step in onboarding: Download and configure the OverSeek WooCommerce plugin.
 * Includes plugin download, configuration copy, and verification.
 */

import React, { useState } from 'react';
import { Plug, ArrowRight, ArrowLeft, SkipForward, Download, Copy, Check, Store, ExternalLink, AlertCircle, Loader2 } from 'lucide-react';
import { OnboardingStepProps } from '../types';
import { useAuth } from '../../../context/AuthContext';
import { useAccount } from '../../../context/AccountContext';
import { api } from '../../../services/api';
import { Logger } from '../../../utils/logger';
import { getPublicApiUrl } from '../../../utils/url';

interface StoreVerificationResult {
    success: boolean;
    storeUrl?: string;
    storeName?: string;
    storeReachable: boolean;
    pluginInstalled: boolean;
    pluginVersion?: string;
    configured?: boolean;
    accountMatch?: boolean;
    trackingEnabled?: boolean;
    chatEnabled?: boolean;
    error?: string;
}

/**
 * Handles plugin download, configuration copy, and store verification.
 */
export function PluginStep({ draft, setDraft, onNext, onBack, onSkip, isSubmitting }: OnboardingStepProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [configCopied, setConfigCopied] = useState(false);
    const [webhookCopied, setWebhookCopied] = useState(false);
    const [verifyStatus, setVerifyStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [verifyResult, setVerifyResult] = useState<StoreVerificationResult | null>(null);

    // Public API URL for external clients (derived from browser location)
    const publicApiUrl = getPublicApiUrl();

    // Guard: Account must exist before showing plugin config
    // Previously, accountId fallback used store name or 'pending' which broke APIs
    const hasValidAccount = Boolean(currentAccount?.id);

    // Generate the configuration JSON that users paste into the plugin
    // Only valid when account exists (accountId must be a UUID, not store name)
    const connectionConfig = hasValidAccount ? JSON.stringify({
        apiUrl: publicApiUrl,
        accountId: currentAccount!.id
    }, null, 2) : '';

    const handleDownload = () => {
        setDraft(prev => ({
            ...prev,
            plugin: { ...prev.plugin, downloaded: true }
        }));
    };

    const handleCopyConfig = () => {
        navigator.clipboard.writeText(connectionConfig);
        setConfigCopied(true);
        setDraft(prev => ({
            ...prev,
            plugin: { ...prev.plugin, configCopied: true }
        }));
        setTimeout(() => setConfigCopied(false), 2000);
    };

    const verifyStore = async () => {
        setVerifyStatus('loading');
        setVerifyResult(null);

        try {
            const result = await api.get<StoreVerificationResult>(
                '/api/tracking/verify-store',
                token || undefined,
                currentAccount?.id || ''
            );

            setVerifyResult(result);
            setVerifyStatus(result.success ? 'success' : 'error');

            if (result.success) {
                setDraft(prev => ({
                    ...prev,
                    plugin: {
                        ...prev.plugin,
                        verified: true,
                        pluginVersion: result.pluginVersion
                    }
                }));
            }
        } catch (error) {
            Logger.error('Store verification failed', { error });
            setVerifyStatus('error');
            setVerifyResult({
                success: false,
                storeReachable: false,
                pluginInstalled: false,
                error: 'Failed to verify store connection'
            });
        }
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="text-center pb-4 border-b border-gray-100">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-purple-100 text-purple-600 mb-4">
                    <Plug size={32} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Install the Plugin</h2>
                <p className="text-gray-500 mt-2">
                    The OverSeek plugin enables live tracking, chat, and order sync
                </p>
            </div>

            {/* Steps */}
            <div className="space-y-6">
                {/* Step 1: Download */}
                <div className="bg-blue-50 rounded-xl p-5 border border-blue-200">
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center text-sm font-bold">
                            1
                        </div>
                        <div className="flex-1">
                            <h3 className="text-sm font-semibold text-gray-900 mb-1">Download the Plugin</h3>
                            <p className="text-xs text-gray-600 mb-3">
                                Download the OverSeek plugin ZIP file and install it on your WordPress site via Plugins → Add New → Upload Plugin.
                            </p>
                            <a
                                href={`${publicApiUrl}/uploads/plugins/overseek-wc-plugin.zip`}
                                download
                                onClick={handleDownload}
                                className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors"
                            >
                                <Download size={16} />
                                Download Plugin
                            </a>
                            {draft.plugin.downloaded && (
                                <span className="ml-3 text-sm text-green-600 inline-flex items-center gap-1">
                                    <Check size={14} /> Downloaded
                                </span>
                            )}
                        </div>
                    </div>
                </div>

                {/* Step 2: Configure */}
                <div className="bg-slate-50 rounded-xl p-5 border border-slate-200">
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-slate-600 text-white flex items-center justify-center text-sm font-bold">
                            2
                        </div>
                        <div className="flex-1">
                            <h3 className="text-sm font-semibold text-gray-900 mb-1">Configure the Plugin</h3>
                            <p className="text-xs text-gray-600 mb-3">
                                After activating the plugin, go to OverSeek settings and paste this configuration:
                            </p>

                            {/* Guard: Only show config when account exists */}
                            {hasValidAccount ? (
                                <div className="relative group">
                                    <button
                                        onClick={handleCopyConfig}
                                        className={`absolute top-2 right-2 flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${configCopied
                                            ? 'bg-green-100 text-green-700 border border-green-200'
                                            : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                                            }`}
                                    >
                                        {configCopied ? <Check size={14} /> : <Copy size={14} />}
                                        {configCopied ? 'Copied!' : 'Copy'}
                                    </button>
                                    <pre className="bg-slate-900 text-slate-100 p-4 pr-24 rounded-lg overflow-x-auto font-mono text-sm">
                                        <code>{connectionConfig}</code>
                                    </pre>
                                </div>
                            ) : (
                                <div className="p-4 bg-amber-50 border border-amber-200 rounded-lg">
                                    <div className="flex items-center gap-2 text-amber-800">
                                        <AlertCircle size={16} />
                                        <span className="text-sm font-medium">Store setup required</span>
                                    </div>
                                    <p className="text-xs text-amber-700 mt-1">
                                        Please complete the Store Setup step first to generate your configuration.
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Webhook URL Info */}
                {hasValidAccount && (
                    <div className="bg-indigo-50 rounded-xl p-5 border border-indigo-200">
                        <div className="flex items-start gap-4">
                            <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center text-sm font-bold">
                                ↻
                            </div>
                            <div className="flex-1">
                                <h3 className="text-sm font-semibold text-gray-900 mb-1">Webhook URL</h3>
                                <p className="text-xs text-gray-600 mb-3">
                                    To receive real-time order updates, add a webhook in WooCommerce → Settings → Advanced → Webhooks → Add Webhook. Use this URL as the <strong>Delivery URL</strong>:
                                </p>
                                <div className="relative group">
                                    <button
                                        onClick={() => {
                                            navigator.clipboard.writeText(`${publicApiUrl}/api/webhooks/${currentAccount!.id}`);
                                            setWebhookCopied(true);
                                            setTimeout(() => setWebhookCopied(false), 2000);
                                        }}
                                        className={`absolute top-2 right-2 flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${webhookCopied
                                            ? 'bg-green-100 text-green-700 border border-green-200'
                                            : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                                            }`}
                                    >
                                        {webhookCopied ? <Check size={14} /> : <Copy size={14} />}
                                        {webhookCopied ? 'Copied!' : 'Copy'}
                                    </button>
                                    <pre className="bg-slate-900 text-slate-100 p-4 pr-24 rounded-lg overflow-x-auto font-mono text-xs break-all whitespace-pre-wrap">
                                        <code>{`${publicApiUrl}/api/webhooks/${currentAccount!.id}`}</code>
                                    </pre>
                                </div>
                                <p className="text-xs text-indigo-600 mt-2">
                                    Set topics to <strong>Order created</strong> and <strong>Order updated</strong> for real-time sync.
                                </p>
                            </div>
                        </div>
                    </div>
                )}

                {/* Step 3: Verify */}
                <div className="bg-green-50 rounded-xl p-5 border border-green-200">
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-green-600 text-white flex items-center justify-center text-sm font-bold">
                            3
                        </div>
                        <div className="flex-1">
                            <h3 className="text-sm font-semibold text-gray-900 mb-1">Verify Installation</h3>
                            <p className="text-xs text-gray-600 mb-3">
                                Click below to check if the plugin is installed and configured correctly.
                            </p>
                            <button
                                onClick={verifyStore}
                                disabled={verifyStatus === 'loading' || !hasValidAccount}
                                className="inline-flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg text-sm font-medium hover:bg-green-700 disabled:opacity-50 transition-colors"
                            >
                                {verifyStatus === 'loading' ? (
                                    <Loader2 size={16} className="animate-spin" />
                                ) : (
                                    <Store size={16} />
                                )}
                                {verifyStatus === 'loading' ? 'Verifying...' : 'Verify Store Plugin'}
                            </button>

                            {/* Verification Result */}
                            {verifyResult && (
                                <div className={`mt-4 p-4 rounded-lg border ${verifyResult.success
                                    ? 'bg-green-100 border-green-300'
                                    : 'bg-amber-100 border-amber-300'
                                    }`}>
                                    <div className="flex items-start gap-3">
                                        {verifyResult.success ? (
                                            <Check className="w-5 h-5 text-green-600 shrink-0" />
                                        ) : (
                                            <AlertCircle className="w-5 h-5 text-amber-600 shrink-0" />
                                        )}
                                        <div className="text-sm">
                                            <p className={`font-semibold ${verifyResult.success ? 'text-green-800' : 'text-amber-800'}`}>
                                                {verifyResult.success ? 'Plugin Verified!' : 'Setup Required'}
                                            </p>
                                            {verifyResult.error && (
                                                <p className="text-amber-700 mt-1">{verifyResult.error}</p>
                                            )}
                                            {verifyResult.success && (
                                                <div className="grid grid-cols-2 gap-2 mt-2 text-xs">
                                                    <div className="flex items-center gap-2">
                                                        <span className="w-2 h-2 rounded-full bg-green-500" />
                                                        Plugin: {verifyResult.pluginVersion || 'Installed'}
                                                    </div>
                                                    <div className="flex items-center gap-2">
                                                        <span className={`w-2 h-2 rounded-full ${verifyResult.trackingEnabled ? 'bg-green-500' : 'bg-amber-500'}`} />
                                                        Tracking: {verifyResult.trackingEnabled ? 'Enabled' : 'Disabled'}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Navigation */}
            <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                <button
                    type="button"
                    onClick={onBack}
                    className="flex items-center gap-2 px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors font-medium"
                >
                    <ArrowLeft size={18} />
                    Back
                </button>

                <div className="flex items-center gap-3">
                    <button
                        type="button"
                        onClick={onSkip}
                        className="flex items-center gap-2 px-4 py-2 text-gray-500 hover:text-gray-700 transition-colors text-sm"
                    >
                        <SkipForward size={16} />
                        Skip for now
                    </button>
                    <button
                        type="button"
                        onClick={onNext}
                        disabled={isSubmitting}
                        className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition-colors font-semibold shadow-lg shadow-blue-500/25"
                    >
                        Continue
                        <ArrowRight size={18} />
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
 * Review Step
 * 
 * Final step in onboarding: Review configured integrations and launch.
 * Shows summary of completed/skipped steps with ability to go back.
 */

import React from 'react';
import { CheckCircle, SkipForward, ArrowLeft, Rocket, Store, Plug, Mail, TrendingUp, AlertCircle } from 'lucide-react';
import { OnboardingStepProps, ONBOARDING_STEPS, STEP_CONFIG } from '../types';

interface IntegrationStatus {
    step: number;
    label: string;
    icon: React.ElementType;
    isCompleted: boolean;
    isSkipped: boolean;
    details?: string;
}

/**
 * Shows a summary of all configured integrations and allows final confirmation.
 */
export function ReviewStep({ draft, setDraft, onNext, onBack, isSubmitting }: OnboardingStepProps) {
    // Build integration status list
    const integrations: IntegrationStatus[] = [
        {
            step: ONBOARDING_STEPS.STORE,
            label: 'WooCommerce Store',
            icon: Store,
            isCompleted: !!draft.store.name && !!draft.store.wooConsumerKey,
            isSkipped: false,
            details: draft.store.name || undefined
        },
        {
            step: ONBOARDING_STEPS.PLUGIN,
            label: 'OverSeek Plugin',
            icon: Plug,
            isCompleted: draft.plugin.verified,
            isSkipped: draft.skippedSteps.includes(ONBOARDING_STEPS.PLUGIN),
            details: draft.plugin.verified ? `v${draft.plugin.pluginVersion || 'Installed'}` : undefined
        },
        {
            step: ONBOARDING_STEPS.EMAIL,
            label: 'Email (SMTP)',
            icon: Mail,
            isCompleted: draft.email.enabled && draft.email.verified,
            isSkipped: draft.skippedSteps.includes(ONBOARDING_STEPS.EMAIL) || !draft.email.enabled,
            details: draft.email.verified ? draft.email.email : undefined
        },
        {
            step: ONBOARDING_STEPS.ADS,
            label: 'Ad Accounts',
            icon: TrendingUp,
            isCompleted: draft.ads.googleConnected || draft.ads.metaConnected,
            isSkipped: draft.skippedSteps.includes(ONBOARDING_STEPS.ADS),
            details: [
                draft.ads.googleConnected ? 'Google Ads' : null,
                draft.ads.metaConnected ? 'Meta Ads' : null
            ].filter(Boolean).join(', ') || undefined
        }
    ];

    const completedCount = integrations.filter(i => i.isCompleted).length;
    const skippedCount = integrations.filter(i => i.isSkipped && !i.isCompleted).length;

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="text-center pb-4 border-b border-gray-100">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-br from-blue-500 to-purple-600 text-white mb-4">
                    <Rocket size={32} />
                </div>
                <h2 className="text-2xl font-bold text-gray-900">Ready to Launch!</h2>
                <p className="text-gray-500 mt-2">
                    Review your setup and start using OverSeek
                </p>
            </div>

            {/* Summary Stats */}
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-green-50 rounded-xl p-4 border border-green-200 text-center">
                    <div className="text-3xl font-bold text-green-600">{completedCount}</div>
                    <div className="text-sm text-green-700">Integrations Ready</div>
                </div>
                <div className="bg-amber-50 rounded-xl p-4 border border-amber-200 text-center">
                    <div className="text-3xl font-bold text-amber-600">{skippedCount}</div>
                    <div className="text-sm text-amber-700">Skipped (Optional)</div>
                </div>
            </div>

            {/* Integration List */}
            <div className="space-y-3">
                <h3 className="text-sm font-semibold text-gray-700 uppercase tracking-wide">Your Setup</h3>

                {integrations.map((integration) => {
                    const Icon = integration.icon;

                    return (
                        <div
                            key={integration.step}
                            className={`flex items-center gap-4 p-4 rounded-xl border transition-colors ${integration.isCompleted
                                ? 'bg-green-50 border-green-200'
                                : integration.isSkipped
                                    ? 'bg-amber-50 border-amber-200'
                                    : 'bg-gray-50 border-gray-200'
                                }`}
                        >
                            {/* Status Icon */}
                            <div className={`flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center ${integration.isCompleted
                                ? 'bg-green-100 text-green-600'
                                : integration.isSkipped
                                    ? 'bg-amber-100 text-amber-600'
                                    : 'bg-gray-100 text-gray-400'
                                }`}>
                                {integration.isCompleted ? (
                                    <CheckCircle size={20} />
                                ) : integration.isSkipped ? (
                                    <SkipForward size={18} />
                                ) : (
                                    <Icon size={20} />
                                )}
                            </div>

                            {/* Label & Details */}
                            <div className="flex-1 min-w-0">
                                <div className={`text-sm font-semibold ${integration.isCompleted ? 'text-green-800' :
                                    integration.isSkipped ? 'text-amber-800' :
                                        'text-gray-600'
                                    }`}>
                                    {integration.label}
                                </div>
                                {integration.details && (
                                    <div className="text-xs text-gray-500 truncate mt-0.5">
                                        {integration.details}
                                    </div>
                                )}
                            </div>

                            {/* Status Badge */}
                            <div className={`flex-shrink-0 px-2.5 py-1 rounded-full text-xs font-medium ${integration.isCompleted
                                ? 'bg-green-100 text-green-700'
                                : integration.isSkipped
                                    ? 'bg-amber-100 text-amber-700'
                                    : 'bg-gray-100 text-gray-500'
                                }`}>
                                {integration.isCompleted ? 'Ready' : integration.isSkipped ? 'Skipped' : 'Pending'}
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Skipped Items Notice */}
            {skippedCount > 0 && (
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 flex gap-3">
                    <AlertCircle className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                    <div className="text-sm text-blue-800">
                        <p className="font-medium">Some integrations were skipped</p>
                        <p className="mt-1 opacity-90">
                            You can complete these anytime from Settings. All features will work,
                            but some functionality may be limited until configured.
                        </p>
                    </div>
                </div>
            )}

            {/* Navigation */}
            <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                <button
                    type="button"
                    onClick={onBack}
                    className="flex items-center gap-2 px-4 py-2 text-gray-600 hover:text-gray-800 transition-colors font-medium"
                >
                    <ArrowLeft size={18} />
                    Back
                </button>

                <button
                    type="button"
                    onClick={onNext}
                    disabled={isSubmitting}
                    className="flex items-center gap-2 px-8 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg hover:from-blue-700 hover:to-purple-700 disabled:opacity-50 transition-all font-bold shadow-lg shadow-purple-500/25"
                >
                    {isSubmitting ? (
                        <>
                            <span className="animate-spin">⏳</span>
                            Completing Setup...
                        </>
                    ) : (
                        <>
                            <Rocket size={18} />
                            Complete Setup
                        </>
                    )}
                </button>
            </div>
        </div>
    );
}

/**
 * FraudBadge - Displays fraud risk score with color-coded indicator.
 */
import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { ShieldAlert, ShieldCheck, ShieldQuestion, AlertTriangle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { cn } from '../../utils/cn';

interface FraudResult {
    score: number;
    level: 'low' | 'medium' | 'high';
    factors: string[];
}

interface FraudBadgeProps {
    orderId: string;
    className?: string;
}

export function FraudBadge({ orderId, className }: FraudBadgeProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [result, setResult] = useState<FraudResult | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [showTooltip, setShowTooltip] = useState(false);

    useEffect(() => {
        fetchFraudScore();
    }, [orderId, currentAccount]);

    const fetchFraudScore = async () => {
        if (!orderId || !token || !currentAccount) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}/fraud-score`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                setResult(await res.json());
            }
        } catch (e) {
            Logger.error('Failed to fetch fraud score:', { error: e });
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className={cn("animate-pulse w-20 h-6 bg-gray-200 rounded", className)} />
        );
    }

    if (!result) return null;

    const config = {
        low: {
            bg: 'bg-green-100',
            text: 'text-green-700',
            border: 'border-green-200',
            icon: ShieldCheck,
            label: 'Low Risk'
        },
        medium: {
            bg: 'bg-yellow-100',
            text: 'text-yellow-700',
            border: 'border-yellow-200',
            icon: ShieldQuestion,
            label: 'Medium Risk'
        },
        high: {
            bg: 'bg-red-100',
            text: 'text-red-700',
            border: 'border-red-200',
            icon: ShieldAlert,
            label: 'High Risk'
        }
    };

    const { bg, text, border, icon: Icon, label } = config[result.level];

    return (
        <div className={cn("relative inline-block", className)}>
            <button
                onMouseEnter={() => setShowTooltip(true)}
                onMouseLeave={() => setShowTooltip(false)}
                className={cn(
                    "flex items-center gap-1.5 px-2.5 py-1 rounded-full border text-xs font-medium transition-colors",
                    bg, text, border
                )}
            >
                <Icon size={14} />
                <span>{label}</span>
                <span className="opacity-70">({result.score})</span>
            </button>

            {showTooltip && result.factors.length > 0 && (
                <div className="absolute z-50 top-full left-0 mt-1 w-64 p-3 bg-white border border-gray-200 rounded-lg shadow-lg text-left">
                    <p className="text-xs font-semibold text-gray-700 mb-2">Risk Factors:</p>
                    <ul className="space-y-1">
                        {result.factors.map((factor, i) => (
                            <li key={i} className="flex items-start gap-2 text-xs text-gray-600">
                                <AlertTriangle size={12} className="text-amber-500 mt-0.5 flex-shrink-0" />
                                {factor}
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>
    );
}

/**
 * FraudIcon - Compact fraud risk indicator for order lists.
 * Shows a small shield icon that fetches and displays risk level on hover.
 */
import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { ShieldAlert, ShieldCheck, ShieldQuestion } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { cn } from '../../utils/cn';

interface FraudResult {
    score: number;
    level: 'low' | 'medium' | 'high';
    factors: string[];
}

interface FraudIconProps {
    orderId: number | string;
    className?: string;
}

export function FraudIcon({ orderId, className }: FraudIconProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [result, setResult] = useState<FraudResult | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [hasFetched, setHasFetched] = useState(false);
    const [showTooltip, setShowTooltip] = useState(false);

    // Fetch on first hover to avoid loading all at once
    const handleMouseEnter = () => {
        setShowTooltip(true);
        if (!hasFetched && !isLoading) {
            fetchFraudScore();
        }
    };

    const fetchFraudScore = async () => {
        if (!orderId || !token || !currentAccount) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}/fraud-score`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                setResult(await res.json());
            }
        } catch (e) {
            Logger.error('Failed to fetch fraud score:', { error: e });
        } finally {
            setIsLoading(false);
            setHasFetched(true);
        }
    };

    const config = {
        low: {
            color: 'text-green-500',
            icon: ShieldCheck,
            label: 'Low Risk'
        },
        medium: {
            color: 'text-yellow-500',
            icon: ShieldQuestion,
            label: 'Medium Risk'
        },
        high: {
            color: 'text-red-500',
            icon: ShieldAlert,
            label: 'High Risk'
        }
    };

    // Default to neutral before fetching
    const level = result?.level || 'low';
    const { color, icon: Icon, label } = config[level];

    return (
        <div
            className={cn("relative inline-flex items-center", className)}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={() => setShowTooltip(false)}
        >
            <Icon
                size={16}
                className={cn(
                    "transition-colors cursor-pointer",
                    hasFetched ? color : "text-gray-300"
                )}
            />

            {showTooltip && (
                <div className="absolute z-50 bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-xs rounded whitespace-nowrap">
                    {isLoading ? 'Loading...' : (
                        result ? `${label} (${result.score})` : 'Hover to check'
                    )}
                    <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-900" />
                </div>
            )}
        </div>
    );
}

/**
 * OrderCOGSPanel - Displays COGS breakdown on order detail pages.
 *
 * Why gated client AND server side: The component returns null when the
 * user lacks `view_cogs`, and the API endpoint returns 403 independently.
 * Belt-and-braces for sensitive financial data.
 */

import { useState, useEffect } from 'react';
import { DollarSign, ChevronDown, ChevronUp, Loader2 } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { usePermissions } from '../../hooks/usePermissions';
import { formatCurrency } from '../../utils/format';
import { Logger } from '../../utils/logger';

interface COGSLineItem {
    productId: number;
    variationId: number;
    name: string;
    sku: string;
    quantity: number;
    unitCOGS: number;
    lineCOGS: number;
    lineRevenue: number;
}

interface COGSData {
    items: COGSLineItem[];
    totalCOGS: number;
    totalRevenue: number;
    paymentFees: number;
    grossProfit: number;
    margin: number;
}

interface OrderCOGSPanelProps {
    orderId: string;
    currency?: string;
}

/** Collapsible COGS breakdown card for order detail pages */
export function OrderCOGSPanel({ orderId, currency }: OrderCOGSPanelProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');

    const [data, setData] = useState<COGSData | null>(null);
    const [loading, setLoading] = useState(false);
    const [expanded, setExpanded] = useState(true);

    useEffect(() => {
        if (!canViewCogs || !orderId || !currentAccount || !token) return;
        fetchCOGS();
    }, [orderId, currentAccount, token, canViewCogs]);

    async function fetchCOGS() {
        setLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}/cogs`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                setData(await res.json());
            }
        } catch (err) {
            Logger.error('Failed to fetch order COGS', { error: err });
        } finally {
            setLoading(false);
        }
    }

    // Permission gate — nothing rendered for unauthorized users
    if (!canViewCogs) return null;

    const fmt = (v: number) => formatCurrency(v, currency || currentAccount?.currency || 'USD');

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
            {/* Header */}
            <button
                onClick={() => setExpanded(!expanded)}
                className="w-full flex items-center justify-between p-4 border-b border-gray-100 hover:bg-gray-50/50 transition-colors"
            >
                <div className="flex items-center gap-2 font-semibold text-gray-900">
                    <DollarSign size={18} className="text-emerald-500" />
                    COGS Breakdown
                </div>
                {expanded ? <ChevronUp size={16} className="text-gray-400" /> : <ChevronDown size={16} className="text-gray-400" />}
            </button>

            {expanded && (
                <div className="p-4">
                    {loading ? (
                        <div className="flex items-center justify-center py-6 text-gray-400 text-sm">
                            <Loader2 size={16} className="animate-spin mr-2" /> Loading…
                        </div>
                    ) : !data || data.items.length === 0 ? (
                        <p className="text-sm text-gray-500 italic py-4 text-center">No COGS data available</p>
                    ) : (
                        <>
                            {/* Per-item breakdown */}
                            <div className="space-y-2 mb-4">
                                {data.items.map((item, idx) => (
                                    <div key={idx} className="flex items-start justify-between text-sm gap-2">
                                        <div className="min-w-0 flex-1">
                                            <div className="font-medium text-gray-800 truncate">{item.name}</div>
                                            <div className="text-xs text-gray-400">
                                                {item.sku ? `SKU: ${item.sku} · ` : ''}
                                                {item.quantity} × {fmt(item.unitCOGS)}
                                            </div>
                                        </div>
                                        <span className="text-gray-700 font-medium whitespace-nowrap">{fmt(item.lineCOGS)}</span>
                                    </div>
                                ))}
                            </div>

                            {/* Summary */}
                            <div className="border-t border-gray-100 pt-3 space-y-1.5 text-sm">
                                <div className="flex justify-between">
                                    <span className="text-gray-500">Total COGS</span>
                                    <span className="font-medium text-gray-800">{fmt(data.totalCOGS)}</span>
                                </div>
                                {data.paymentFees > 0 && (
                                    <div className="flex justify-between">
                                        <span className="text-gray-500">Payment Fees</span>
                                        <span className="font-medium text-gray-800">{fmt(data.paymentFees)}</span>
                                    </div>
                                )}
                                <div className="flex justify-between pt-1.5 border-t border-dashed border-gray-200">
                                    <span className="font-semibold text-gray-900">Gross Profit</span>
                                    <div className="flex items-center gap-2">
                                        <span className={`font-bold ${data.grossProfit >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                                            {fmt(data.grossProfit)}
                                        </span>
                                        <span className={`text-xs px-1.5 py-0.5 rounded-full font-medium ${data.margin >= 0
                                                ? 'bg-emerald-50 text-emerald-700 border border-emerald-200'
                                                : 'bg-red-50 text-red-700 border border-red-200'
                                            }`}>
                                            {data.margin >= 0 ? '+' : ''}{data.margin.toFixed(1)}%
                                        </span>
                                    </div>
                                </div>
                            </div>
                        </>
                    )}
                </div>
            )}
        </div>
    );
}

/**
 * OrderMetaSection Component
 * 
 * Displays categorized metadata from WooCommerce order line items.
 * Categories: Product Options (variations), Custom Fields, and Uploaded Files (images).
 * Extracted from OrderDetailPage for reusability.
 */

import { useState } from 'react';
import { ChevronDown, ChevronUp, Palette, FileText, Image as ImageIcon, Settings } from 'lucide-react';
import { fixMojibake } from '../../utils/format';


interface MetaCategory {
    id: string;
    label: string;
    icon: React.ReactNode;
    color: string;
    bgColor: string;
    items: Array<{ key: string; value: string; imageUrl?: string | null }>;
}

interface OrderMetaSectionProps {
    metaData: Array<{ key: string; value: string; display_key?: string; display_value?: string }>;
    onImageClick: (url: string) => void;
}

interface ImageThumbnailProps {
    item: { key: string; value: string; imageUrl?: string | null };
    onImageClick: (url: string) => void;
}


/**
 * Extracts an image URL from a meta value.
 * Handles compound values like "filename.webp | https://example.com/path/to/image.webp"
 * @returns The URL if found, null otherwise.
 */
export function extractImageUrl(value: string): string | null {
    if (typeof value !== 'string') return null;

    const imagePattern = /\.(jpg|jpeg|png|gif|webp|svg|bmp)/i;

    // Check if the value itself is a direct image URL
    if (imagePattern.test(value) && value.startsWith('http')) {
        return value;
    }

    // Look for URLs within the value (handles "filename | url" format)
    const urlMatch = value.match(/(https?:\/\/[^\s|]+)/g);
    if (urlMatch) {
        for (const url of urlMatch) {
            if (imagePattern.test(url)) {
                return url.trim();
            }
        }
    }

    return null;
}

/**
 * Extracts ALL image URLs from a meta value.
 * WooCommerce can store multiple images per meta entry (newline or pipe separated).
 * @returns An array of all found image URLs.
 */
export function extractAllImageUrls(value: string): string[] {
    if (typeof value !== 'string') return [];

    const imagePattern = /\.(jpg|jpeg|png|gif|webp|svg|bmp)/i;
    const urls: string[] = [];

    const urlMatches = value.match(/(https?:\/\/[^\s|,\n]+)/g);
    if (urlMatches) {
        for (const url of urlMatches) {
            const cleanUrl = url.trim();
            if (imagePattern.test(cleanUrl) && !urls.includes(cleanUrl)) {
                urls.push(cleanUrl);
            }
        }
    }

    return urls;
}


/**
 * Displays a clickable thumbnail image with hover label.
 * Falls back to a text badge if the image fails to load.
 */
export function ImageThumbnail({ item, onImageClick }: ImageThumbnailProps) {
    const [imgError, setImgError] = useState(false);

    if (!item.imageUrl || imgError) {
        return (
            <div className="flex items-center gap-1 px-2 py-1 bg-gray-100 rounded text-xs text-gray-500">
                <FileText size={12} />
                <span>{item.key}</span>
            </div>
        );
    }

    return (
        <div className="group relative">
            <div
                className="cursor-zoom-in rounded-lg overflow-hidden border-2 border-transparent hover:border-purple-400 transition-all shadow-sm hover:shadow-md"
                onClick={() => onImageClick(item.imageUrl!)}
            >
                <img
                    src={item.imageUrl}
                    alt={item.key}
                    onError={() => setImgError(true)}
                    className="h-16 w-16 object-cover hover:scale-105 transition-transform"
                />
            </div>
            <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 px-1.5 py-0.5 bg-gray-900/80 text-white text-[9px] rounded capitalize opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                {item.key}
            </div>
        </div>
    );
}

/**
 * Displays WooCommerce order item metadata in categorized sections.
 * Categories are collapsible and display data in appropriate formats (key-value or image gallery).
 */
export function OrderMetaSection({ metaData, onImageClick }: OrderMetaSectionProps) {
    const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set(['variations', 'custom']));

    // Filter out hidden meta and categorize
    const filteredMeta = metaData.filter(m => !m.key.startsWith('_'));

    if (filteredMeta.length === 0) return null;

    // Categorize metadata
    const categories: MetaCategory[] = [];

    // Variations/Attributes (pa_ prefix or common variation keys)
    const variations = filteredMeta.filter(m =>
        m.key.startsWith('pa_') ||
        ['size', 'color', 'colour', 'variant', 'style', 'material', 'weight'].some(k =>
            m.key.toLowerCase().includes(k)
        )
    );

    // Uploads/Images
    const uploads = filteredMeta.filter(m => {
        const url = extractImageUrl(m.value);
        return url !== null;
    });

    // Custom fields (everything else)
    const customFields = filteredMeta.filter(m =>
        !variations.includes(m) && !uploads.includes(m)
    );

    if (variations.length > 0) {
        categories.push({
            id: 'variations',
            label: 'Product Options',
            icon: <Palette size={12} />,
            color: 'text-purple-700',
            bgColor: 'bg-purple-50 border-purple-200',
            items: variations.map(m => ({
                key: fixMojibake(m.display_key || m.key.replace('pa_', '').replace(/_/g, ' ')),
                value: fixMojibake(m.display_value || m.value),
                imageUrl: null
            }))
        });
    }

    if (customFields.length > 0) {
        categories.push({
            id: 'custom',
            label: 'Custom Fields',
            icon: <Settings size={12} />,
            color: 'text-blue-700',
            bgColor: 'bg-blue-50 border-blue-200',
            items: customFields.map(m => ({
                key: fixMojibake(m.display_key || m.key.replace(/_/g, ' ')),
                value: fixMojibake(m.display_value || m.value),
                imageUrl: null
            }))
        });
    }

    if (uploads.length > 0) {
        // Flatten uploads: each image URL becomes its own item
        const uploadItems: Array<{ key: string; value: string; imageUrl: string | null }> = [];
        for (const m of uploads) {
            const imageUrls = extractAllImageUrls(m.value);
            const baseKey = fixMojibake(m.display_key || m.key.replace(/_/g, ' '));
            if (imageUrls.length > 0) {
                imageUrls.forEach((url, idx) => {
                    uploadItems.push({
                        key: imageUrls.length > 1 ? `${baseKey} (${idx + 1})` : baseKey,
                        value: fixMojibake(m.display_value || m.value),
                        imageUrl: url
                    });
                });
            } else {
                uploadItems.push({
                    key: baseKey,
                    value: fixMojibake(m.display_value || m.value),
                    imageUrl: extractImageUrl(m.value)
                });
            }
        }
        categories.push({
            id: 'uploads',
            label: 'Uploaded Files',
            icon: <ImageIcon size={12} />,
            color: 'text-amber-700',
            bgColor: 'bg-amber-50 border-amber-200',
            items: uploadItems
        });
    }

    const toggleCategory = (id: string) => {
        setExpandedCategories(prev => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
            }
            return next;
        });
    };

    return (
        <div className="mt-3 space-y-2">
            {categories.map(category => {
                const isExpanded = expandedCategories.has(category.id);

                return (
                    <div key={category.id} className={`rounded-lg border overflow-hidden ${category.bgColor}`}>
                        {/* Category Header */}
                        <button
                            onClick={() => toggleCategory(category.id)}
                            className="w-full px-3 py-2 flex items-center justify-between hover:bg-white/30 transition-colors"
                        >
                            <div className={`flex items-center gap-2 text-xs font-semibold ${category.color}`}>
                                {category.icon}
                                <span className="capitalize">{category.label}</span>
                                <span className="px-1.5 py-0.5 rounded-full bg-white/60 text-[10px] font-bold">
                                    {category.items.length}
                                </span>
                            </div>
                            {isExpanded ? (
                                <ChevronUp size={14} className={category.color} />
                            ) : (
                                <ChevronDown size={14} className={category.color} />
                            )}
                        </button>

                        {/* Category Content */}
                        {isExpanded && (
                            <div className="px-3 pb-3 bg-white/40">
                                {category.id === 'uploads' ? (
                                    // Image Gallery View
                                    <div className="flex flex-wrap gap-2 pt-2">
                                        {category.items.map((item, idx) => (
                                            <ImageThumbnail
                                                key={idx}
                                                item={item}
                                                onImageClick={onImageClick}
                                            />
                                        ))}
                                    </div>
                                ) : (
                                    // Key-Value List View
                                    <div className="grid gap-1.5 pt-2">
                                        {category.items.map((item, idx) => (
                                            <div key={idx} className="flex items-baseline gap-2 text-xs">
                                                <span className="font-medium text-gray-600 capitalize min-w-[80px]">
                                                    {item.key}:
                                                </span>
                                                <span className="text-gray-900 break-all whitespace-pre-line">
                                                    {item.value.startsWith('http') ? (
                                                        <a
                                                            href={item.value}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="text-blue-600 hover:underline"
                                                        >
                                                            {item.value.length > 40 ? item.value.slice(0, 40) + '...' : item.value}
                                                        </a>
                                                    ) : (
                                                        item.value
                                                    )}
                                                </span>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { ExternalLink, Package, X } from 'lucide-react';
import { Logger } from '../../utils/logger';
import { formatDate, formatCurrency } from '../../utils/format';
import { Modal } from '../ui/Modal';
import { useNavigate } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface OrderPreviewModalProps {
    orderId: number | null;
    isOpen: boolean;
    onClose: () => void;
}

export function OrderPreviewModal({ orderId, isOpen, onClose }: OrderPreviewModalProps) {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [order, setOrder] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(false);

    useEffect(() => {
        if (isOpen && orderId && currentAccount && token) {
            fetchOrderDetails();
        } else {
            setOrder(null);
        }
    }, [isOpen, orderId, currentAccount, token]);

    async function fetchOrderDetails() {
        setIsLoading(true);
        try {
            const res = await fetch(`/api/orders/${orderId}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                setOrder(data);
            }
        } catch (error) {
            Logger.error('Failed to load order', { error: error });
        } finally {
            setIsLoading(false);
        }
    }

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={
                <div>
                    <div className="text-xl font-bold text-gray-900">Order #{orderId}</div>
                    <p className="text-sm text-gray-500 font-normal">Quick Preview</p>
                </div>
            }
            maxWidth="max-w-lg"
