                            </div>

                            {/* Total Row */}
                            <div className="px-4 py-3.5 bg-linear-to-r from-gray-800 to-slate-900 flex items-center justify-between">
                                <span className="text-sm font-medium text-gray-300 uppercase tracking-wide">Total</span>
                                <span className="text-xl font-bold text-white">
                                    {formatCurrency(Number(order.total), order.currency || 'USD')}
                                </span>
                            </div>
                        </div>
                    </>
                ) : (
                    <div className="text-center py-8">
                        <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-3">
                            <X size={24} className="text-red-500" />
                        </div>
                        <p className="text-gray-600 font-medium">Failed to load order data</p>
                        <p className="text-sm text-gray-400 mt-1">Please try again later</p>
                    </div>
                )}
            </div>

            {/* Footer Actions */}
            <div className="pt-5 mt-5 border-t border-gray-100 flex justify-end gap-3 -mx-6 px-6">
                <button onClick={onClose} className="px-4 py-2 text-gray-600 font-medium hover:bg-gray-200 rounded-lg transition-colors">
                    Close
                </button>
                <button
                    onClick={() => navigate(`/orders/${orderId}`)}
                    className="flex items-center gap-2 px-5 py-2 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg shadow-xs shadow-blue-200 transition-all hover:shadow-md"
                >
                    View Full Details
                    <ExternalLink size={16} />
                </button>
            </div>
        </Modal>
    );
}

/**
 * OrderStatusTabs - A modern horizontal tab filter for order statuses.
 * 
 * Why: Replaces the basic dropdown with a premium horizontal pill/tab filter
 * matching the WooCommerce-style "All | Processing | Completed | ..." design
 * but with OverSeek's glassmorphism aesthetic.
 */

import { useEffect, useState, useMemo } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { ORDER_STATUS_CONFIG, getStatusConfig } from '../../utils/orderStatus';
import { Loader2 } from 'lucide-react';

interface StatusCounts {
    total: number;
    counts: Record<string, number>;
}

interface OrderStatusTabsProps {
    selectedStatus: string;
    onStatusChange: (status: string) => void;
}

/** Ordered list of statuses to display in the tabs */
const TAB_STATUSES = [
    'all',
    'pending',
    'processing',
    'on-hold',
    'completed',
    'cancelled',
    'refunded',
    'failed'
] as const;

export function OrderStatusTabs({ selectedStatus, onStatusChange }: OrderStatusTabsProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [statusCounts, setStatusCounts] = useState<StatusCounts | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        if (!currentAccount || !token) return;

        const fetchCounts = async () => {
            try {
                const res = await fetch('/api/sync/orders/status-counts', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'X-Account-ID': currentAccount.id
                    }
                });

                if (res.ok) {
                    const data = await res.json();
                    setStatusCounts(data);
                }
            } catch {
                // Silent fail - tabs still work without counts
            } finally {
                setIsLoading(false);
            }
        };

        fetchCounts();
    }, [currentAccount, token]);

    const tabs = useMemo(() => {
        return TAB_STATUSES.map(status => {
            if (status === 'all') {
                return {
                    value: 'all',
                    label: 'All',
                    count: statusCounts?.total ?? null,
                    color: 'gray'
                };
            }

            const config = getStatusConfig(status);
            return {
                value: status,
                label: config.label,
                count: statusCounts?.counts[status] ?? null,
                color: status
            };
        });
    }, [statusCounts]);

    const getTabStyles = (status: string, isActive: boolean) => {
        const baseStyles = 'group relative flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-lg transition-all duration-200 cursor-pointer select-none whitespace-nowrap';

        if (isActive) {
            // Active state - filled with status color
            const colorMap: Record<string, string> = {
                all: 'bg-slate-800 text-white shadow-md',
                pending: 'bg-amber-500 text-white shadow-md shadow-amber-200/50',
                processing: 'bg-blue-500 text-white shadow-md shadow-blue-200/50',
                'on-hold': 'bg-orange-500 text-white shadow-md shadow-orange-200/50',
                completed: 'bg-emerald-500 text-white shadow-md shadow-emerald-200/50',
                cancelled: 'bg-red-500 text-white shadow-md shadow-red-200/50',
                refunded: 'bg-purple-500 text-white shadow-md shadow-purple-200/50',
                failed: 'bg-red-600 text-white shadow-md shadow-red-200/50'
            };
            return `${baseStyles} ${colorMap[status] || colorMap.all}`;
        }

        // Inactive state - subtle with hover effect
        return `${baseStyles} text-gray-600 hover:text-gray-900 hover:bg-gray-100`;
    };

    const getCountStyles = (status: string, isActive: boolean) => {
        if (isActive) {
            return 'bg-white/25 text-white/90 text-xs px-1.5 py-0.5 rounded-md font-medium tabular-nums';
        }

        // Inactive - subtle badge
        return 'bg-gray-200/70 text-gray-500 text-xs px-1.5 py-0.5 rounded-md font-medium tabular-nums group-hover:bg-gray-300/70';
    };

    if (isLoading) {
        return (
            <div className="flex items-center gap-2 px-4 py-3 bg-white/60 backdrop-blur-sm rounded-xl border border-gray-200/60 shadow-sm">
                <Loader2 size={16} className="animate-spin text-gray-400" />
                <span className="text-sm text-gray-500">Loading statuses...</span>
            </div>
        );
    }

    return (
        <div className="bg-white/60 backdrop-blur-sm rounded-xl border border-gray-200/60 shadow-sm overflow-hidden">
            <div className="flex items-center gap-1 p-1.5 overflow-x-auto scrollbar-thin scrollbar-thumb-gray-300" role="tablist">
                {tabs.map((tab) => {
                    const isActive = selectedStatus === tab.value;
                    return (
                        <button
                            key={tab.value}
                            role="tab"
                            aria-selected={isActive}
                            onClick={() => onStatusChange(tab.value)}
                            className={getTabStyles(tab.value, isActive)}
                        >
                            <span>{tab.label}</span>
                            {tab.count !== null && (
                                <span className={getCountStyles(tab.value, isActive)}>
                                    {tab.count.toLocaleString()}
                                </span>
                            )}
                        </button>
                    );
                })}
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { Tag, Plus, X, ChevronDown, Search, Loader2 } from 'lucide-react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface TagMapping {
    productTag: string;
    orderTag: string;
    enabled: boolean;
    color?: string;
}

interface OrderTagPanelProps {
    orderId: string;
    currentTags: string[];
    lastUpdate?: string;
    onTagsChange: (tags: string[]) => void;
    onRefresh?: () => void;
}

/**
 * Sidebar panel for managing order tags.
 * Displays current tags with single-click removal and a dropdown to add available tags.
 */
export function OrderTagPanel({ orderId, currentTags, lastUpdate, onTagsChange, onRefresh }: OrderTagPanelProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [mappings, setMappings] = useState<TagMapping[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isUpdating, setIsUpdating] = useState(false);
    const [showAddDropdown, setShowAddDropdown] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (currentAccount && token) {
            loadMappings();
        }
    }, [currentAccount, token]);

    // Close dropdown on outside click
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setShowAddDropdown(false);
                setSearchQuery('');
            }
        }
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    async function loadMappings() {
        if (!currentAccount || !token) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/accounts/${currentAccount.id}/tag-mappings`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setMappings((data.mappings || []).filter((m: TagMapping) => m.enabled));
            }
        } catch (error) {
            Logger.error('Failed to load tag mappings', { error });
        } finally {
            setIsLoading(false);
        }
    }

    /** Gets available tags that aren't already applied to this order */
    function getAvailableTags(): TagMapping[] {
        const appliedTags = new Set(currentTags.map(t => t.toLowerCase()));
        return mappings.filter(m => !appliedTags.has(m.orderTag.toLowerCase()));
    }

    /** Filtered available tags based on search */
    function getFilteredAvailableTags(): TagMapping[] {
        const available = getAvailableTags();
        if (!searchQuery.trim()) return available;
        return available.filter(m =>
            m.orderTag.toLowerCase().includes(searchQuery.toLowerCase())
        );
    }

    /** Gets color for a tag from mappings */
    function getTagColor(tagName: string): string {
        const mapping = mappings.find(m => m.orderTag.toLowerCase() === tagName.toLowerCase());
        return mapping?.color || '#6B7280';
    }

    async function addTag(tagName: string) {
        if (!currentAccount || !token || isUpdating) return;
        setIsUpdating(true);
        setShowAddDropdown(false);
        setSearchQuery('');

        try {
            const headers: HeadersInit = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount.id,
                'Content-Type': 'application/json'
            };

            if (lastUpdate) {
                headers['X-Order-Version'] = lastUpdate;
            }

            const res = await fetch(`/api/orders/${orderId}/tags`, {
                method: 'POST',
                headers,
                body: JSON.stringify({ tag: tagName })
            });

            if (res.status === 409) {
                Logger.warn('Order conflict detected, refreshing...');
                alert('This order has been modified by another user. Refreshing...');
                if (onRefresh) onRefresh();
                return;
            }

            if (res.ok) {
                const data = await res.json();
                onTagsChange(data.tags);
            }
        } catch (error) {
            Logger.error('Failed to add tag', { error });
        } finally {
            setIsUpdating(false);
        }
    }

    async function removeTag(tagName: string) {
        if (!currentAccount || !token || isUpdating) return;
        setIsUpdating(true);

        try {
            const headers: HeadersInit = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount.id
            };

            if (lastUpdate) {
                headers['X-Order-Version'] = lastUpdate;
            }

            const res = await fetch(`/api/orders/${orderId}/tags/${encodeURIComponent(tagName)}`, {
                method: 'DELETE',
                headers
            });

            if (res.status === 409) {
                Logger.warn('Order conflict detected, refreshing...');
                alert('This order has been modified by another user. Refreshing...');
                if (onRefresh) onRefresh();
                return;
            }

            if (res.ok) {
                const data = await res.json();
                onTagsChange(data.tags);
            }
        } catch (error) {
            Logger.error('Failed to remove tag', { error });
        } finally {
            setIsUpdating(false);
        }
    }

    const availableTags = getFilteredAvailableTags();
    const hasAvailableTags = getAvailableTags().length > 0;

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-5 space-y-4">
            <div className="font-semibold text-gray-900 flex items-center justify-between border-b border-gray-100 pb-3">
                <div className="flex items-center gap-2">
                    <Tag size={18} className="text-blue-500" />
                    Tags
                </div>

                {/* Add Tag Button */}
                {hasAvailableTags && (
                    <div className="relative" ref={dropdownRef}>
                        <button
                            onClick={() => setShowAddDropdown(!showAddDropdown)}
                            disabled={isUpdating || isLoading}
                            className="flex items-center gap-1 text-xs bg-blue-50 text-blue-600 px-2 py-1 rounded-md hover:bg-blue-100 transition-colors disabled:opacity-50"
                        >
                            <Plus size={14} />
                            Add
                            <ChevronDown size={12} className={`transition-transform ${showAddDropdown ? 'rotate-180' : ''}`} />
                        </button>

                        {showAddDropdown && (
                            <div className="absolute right-0 mt-2 w-56 bg-white rounded-lg shadow-lg border border-gray-200 z-50">
                                {/* Search input */}
                                <div className="p-2 border-b border-gray-100">
                                    <div className="relative">
                                        <Search size={12} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-gray-400" />
                                        <input
                                            type="text"
                                            placeholder="Search tags..."
                                            value={searchQuery}
                                            onChange={(e) => setSearchQuery(e.target.value)}
                                            className="w-full pl-7 pr-2 py-1.5 text-xs border border-gray-200 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                            autoFocus
                                        />
                                    </div>
                                </div>

                                {/* Tag list */}
                                <div className="max-h-48 overflow-y-auto py-1">
                                    {availableTags.length === 0 ? (
                                        <div className="px-3 py-2 text-xs text-gray-500 text-center">
                                            {searchQuery ? 'No matching tags' : 'No tags available'}
                                        </div>
                                    ) : (
                                        availableTags.map(mapping => (
                                            <button
                                                key={mapping.orderTag}
                                                onClick={() => addTag(mapping.orderTag)}
                                                className="w-full text-left px-3 py-2 text-xs hover:bg-blue-50 flex items-center gap-2 transition-colors"
                                            >
                                                <span
                                                    className="w-3 h-3 rounded-sm flex-shrink-0"
                                                    style={{ backgroundColor: mapping.color || '#6B7280' }}
                                                />
                                                <span className="truncate">{mapping.orderTag}</span>
                                            </button>
                                        ))
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Tags Display */}
            {isLoading ? (
                <div className="flex items-center justify-center py-4">
                    <Loader2 size={20} className="animate-spin text-gray-400" />
                </div>
            ) : currentTags.length === 0 ? (
                <div className="text-sm text-gray-500 text-center py-2">
                    {mappings.length === 0 ? (
                        <span>Configure tag mappings in Settings</span>
                    ) : (
                        <span>No tags applied</span>
                    )}
                </div>
            ) : (
                <div className="flex flex-wrap gap-2">
                    {currentTags.map((tag) => {
                        const color = getTagColor(tag);
                        return (
                            <span
                                key={tag}
                                className="inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-sm text-white group"
                                style={{ backgroundColor: color }}
                            >
                                {tag}
                                <button
                                    onClick={() => removeTag(tag)}
                                    disabled={isUpdating}
                                    className="ml-0.5 p-0.5 rounded hover:bg-white/20 opacity-70 hover:opacity-100 transition-opacity disabled:opacity-50"
                                    title="Remove tag"
                                >
                                    {isUpdating ? (
                                        <Loader2 size={12} className="animate-spin" />
                                    ) : (
                                        <X size={12} />
                                    )}
                                </button>
                            </span>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

/**
 * BOMPanel - Bill of Materials configuration panel.
 * Manages composite product components, costs, and WooCommerce inventory sync.
 */
import { useState, useEffect, useImperativeHandle, forwardRef } from 'react';
import { Logger } from '../../utils/logger';
import { GitBranch, Loader2, Save } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { usePermissions } from '../../hooks/usePermissions';
import { BOMCostSummary, BOMSearchDropdown, BOMItemsTable, type BOMItem } from './bom';

interface BOMPanelProps {
    productId: string; // Internal UUID
    variants?: any[]; // Passed from parent
    fixedVariationId?: number; // If set, locks to this ID
    onSaveComplete?: () => void; // Optional callback after save completes
    onCOGSUpdate?: (cogs: number) => void; // Optional callback to update parent COGS
    onSyncComplete?: (newStock: number) => void; // Optional callback after sync completes
}

/**
 * Exposes a save() method via ref so parent can trigger BOM save.
 */
export interface BOMPanelRef {
    save: () => Promise<boolean>;
}

export const BOMPanel = forwardRef<BOMPanelRef, BOMPanelProps>(function BOMPanel({ productId, variants = [], fixedVariationId, onSaveComplete, onCOGSUpdate, onSyncComplete }, ref) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');
    const [bomItems, setBomItems] = useState<BOMItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);

    const [searchTerm, setSearchTerm] = useState('');
    const [searchResults, setSearchResults] = useState<any[]>([]);

    // BOM Inventory Sync state
    const [effectiveStock, setEffectiveStock] = useState<number | null>(null);
    const [currentWooStock, setCurrentWooStock] = useState<number | null>(null);
    const [isSyncing, setIsSyncing] = useState(false);
    const [syncStatus, setSyncStatus] = useState<'idle' | 'success' | 'error'>('idle');

    // 0 = Main Product, otherwise Variant ID
    // If fixedVariationId is defined, use it, else default to 0
    const [selectedScope, setSelectedScope] = useState<number>(fixedVariationId !== undefined ? fixedVariationId : 0);

    useEffect(() => {
        if (!currentAccount || !productId || !canViewCogs) return;
        fetchBOM();
        fetchEffectiveStock();
    }, [productId, currentAccount, token, selectedScope, canViewCogs]);

    // Search for products with debounce
    useEffect(() => {
        if (!searchTerm || searchTerm.length < 2) {
            setSearchResults([]);
            return;
        }

        const delayDebounceFn = setTimeout(async () => {
            try {
                // Fetch both WooCommerce products and internal products in parallel
                const [wooRes, internalRes] = await Promise.all([
                    fetch(`/api/products?q=${encodeURIComponent(searchTerm)}&limit=8`, {
                        headers: {
                            'Authorization': `Bearer ${token}`,
                            'x-account-id': currentAccount?.id || ''
                        }
                    }),
                    fetch(`/api/inventory/internal-products?search=${encodeURIComponent(searchTerm)}&limit=8`, {
                        headers: {
                            'Authorization': `Bearer ${token}`,
                            'x-account-id': currentAccount?.id || ''
                        }
                    })
                ]);

                let results: any[] = [];

                if (wooRes.ok) {
                    const wooData = await wooRes.json();
                    results = [...(wooData.products || [])];
                }

                if (internalRes.ok) {
                    const internalData = await internalRes.json();
                    // Mark internal products for visual distinction
                    const internalProducts = (internalData.items || []).map((ip: any) => ({
                        ...ip,
                        isInternalProduct: true,
                        name: ip.name,
                        mainImage: ip.mainImage,
                        cogs: ip.cogs,
                        stockQuantity: ip.stockQuantity,
                        price: ip.cogs // Use COGS as display price for internal
                    }));
                    results = [...results, ...internalProducts];
                }

                // Smart sorting by relevance
                const sortedResults = sortProductsByRelevance(results, searchTerm);
                setSearchResults(sortedResults);
            } catch (err) {
                Logger.error('Failed to search products', { error: err });
            }
        }, 300);

        return () => clearTimeout(delayDebounceFn);
    }, [searchTerm, token, currentAccount]);

    /**
     * Sorts products by relevance to search term.
     * Prioritizes products matching more search words.
     */
    const sortProductsByRelevance = (products: any[], term: string): any[] => {
        const searchWords = term.toLowerCase().trim().split(/\s+/).filter(w => w.length > 0);

        const getRelevanceScore = (product: any): number => {
            const nameLower = (product.name || '').toLowerCase();
            const skuLower = (product.sku || '').toLowerCase();
            const variantStrings: string[] = (product.searchableVariants || []).map((v: any) =>
                `${(v.attributeString || '')} ${(v.sku || '')}`.toLowerCase()
            );

            let matchCount = 0;
            let variantMatchCount = 0;

            for (const word of searchWords) {
                const matchesName = nameLower.includes(word);
                const matchesSku = skuLower.includes(word);
                const matchesVariant = variantStrings.some(vs => vs.includes(word));

                if (matchesName || matchesSku) matchCount++;
                if (matchesVariant) variantMatchCount++;
            }

            const totalMatches = matchCount + variantMatchCount;
            if (totalMatches === 0) return 1000;

            let score = -totalMatches * 100;
            score -= matchCount * 10;
            if (searchWords.length > 0 && nameLower.startsWith(searchWords[0])) {
                score -= 5;
            }
            return score;
        };

        const sorted = products.sort((a, b) => getRelevanceScore(a) - getRelevanceScore(b));

        // Sort variants within each product
        return sorted.map((product: any) => {
            if (!product.searchableVariants || product.searchableVariants.length === 0) {
                return product;
            }

            const sortedVariants = [...product.searchableVariants].sort((va: any, vb: any) => {
                const aStr = `${(va.attributeString || '')} ${(va.sku || '')}`.toLowerCase();
                const bStr = `${(vb.attributeString || '')} ${(vb.sku || '')}`.toLowerCase();
                const aMatches = searchWords.filter(w => aStr.includes(w)).length;
                const bMatches = searchWords.filter(w => bStr.includes(w)).length;
                return bMatches - aMatches;
            });

            return { ...product, searchableVariants: sortedVariants };
        });
    };

    const fetchBOM = async () => {
        setLoading(true);
        try {
            const res = await fetch(`/api/inventory/products/${productId}/bom?variationId=${selectedScope}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });

            if (res.ok) {
                const data = await res.json();
                if (data && data.items) {
                    const mapped = data.items.map((item: any) => mapBOMItemFromResponse(item));
                    setBomItems(mapped);
                } else {
                    setBomItems([]);
                }
            } else {
                setBomItems([]);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setLoading(false);
        }
    };

    /**
     * Maps a backend BOM item response to the UI BOMItem interface.
     */
    const mapBOMItemFromResponse = (item: any): BOMItem => {
        let displayName = 'Unknown';
        let isInternal = false;

        if (item.internalProduct) {
            displayName = `[Internal] ${item.internalProduct.name}`;
            isInternal = true;
        } else if (item.childVariation) {
            const variantRaw = item.childVariation.rawData || {};
            const attrString = (variantRaw.attributes || [])
                .map((a: any) => a.option || a.value)
                .filter(Boolean)
                .join(' / ');
            const parentName = item.childProduct?.name || item.childVariation._parentProductName;
            displayName = parentName
                ? `${parentName} - ${attrString || item.childVariation.sku || `#${item.childVariation.wooId}`}`
                : attrString || item.childVariation.sku || `Variant #${item.childVariation.wooId}`;
        } else if (item.childProduct) {
            displayName = item.childProduct.name;
        } else if (item.supplierItem) {
            displayName = item.supplierItem.name || 'Unknown';
        }

        let cost = 0;
        if (item.internalProduct?.cogs) {
            cost = Number(item.internalProduct.cogs);
        } else if (item.childVariation?.cogs) {
            cost = Number(item.childVariation.cogs);
        } else if (item.childProduct?.cogs) {
            cost = Number(item.childProduct.cogs);
        } else if (item.supplierItem?.cost) {
            cost = Number(item.supplierItem.cost);
        }

        return {
            id: item.id,
            childProductId: item.childProductId,
            childVariationId: item.childVariationId,
            internalProductId: item.internalProductId,
            supplierItemId: item.supplierItemId,
            displayName,
            quantity: Number(item.quantity),
            wasteFactor: Number(item.wasteFactor),
            cost,
            isInternal
        };
    };

    const fetchEffectiveStock = async () => {
        if (!currentAccount || !productId) return;

        try {
            const res = await fetch(`/api/inventory/products/${productId}/bom/effective-stock?variationId=${selectedScope}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setEffectiveStock(data.effectiveStock);
                setCurrentWooStock(data.currentWooStock);
            } else {
                setEffectiveStock(null);
                setCurrentWooStock(null);
            }
        } catch (err) {
            Logger.error('Failed to fetch effective stock', { error: err });
            setEffectiveStock(null);
            setCurrentWooStock(null);
        }
    };

    const handleSyncToWoo = async () => {
        if (!currentAccount || !productId) return;

        setIsSyncing(true);
        setSyncStatus('idle');

        try {
            const res = await fetch(`/api/inventory/products/${productId}/bom/sync?variationId=${selectedScope}`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setCurrentWooStock(data.newStock);
                setSyncStatus('success');
                await fetchEffectiveStock();
                onSyncComplete?.(data.newStock);
            } else {
                setSyncStatus('error');
            }
        } catch (err) {
            Logger.error('Failed to sync inventory to WooCommerce', { error: err });
            setSyncStatus('error');
        } finally {
            setIsSyncing(false);
            setTimeout(() => setSyncStatus('idle'), 3000);
        }
    };

    const handleSave = async (): Promise<boolean> => {
        setSaving(true);
        try {
            const payload = {
                variationId: selectedScope,
                items: bomItems.map(item => ({
                    childProductId: item.childProductId,
                    childVariationId: item.childVariationId,
                    internalProductId: item.internalProductId,
                    supplierItemId: item.supplierItemId,
                    quantity: item.quantity,
                    wasteFactor: item.wasteFactor
                }))
            };

            const res = await fetch(`/api/inventory/products/${productId}/bom`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                fetchBOM();
                if (bomItems.length > 0) {
                    onCOGSUpdate?.(totalCost);
                }
                onSaveComplete?.();
                return true;
            } else {
                return false;
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
            return false;
        } finally {
            setSaving(false);
        }
    };

    useImperativeHandle(ref, () => ({
        save: handleSave
    }), [bomItems, selectedScope, productId, token, currentAccount, handleSave]);

    const handleAddProduct = (product: any) => {
        // Handle internal products
        if (product.isInternalProduct) {
            const alreadyExists = bomItems.some(i => i.internalProductId === product.id);
            if (alreadyExists) {
                alert('This component is already in the BOM.');
                return;
            }

            const newItem: BOMItem = {
                internalProductId: product.id,
                displayName: `[Internal] ${product.name}`,
                quantity: 1,
                wasteFactor: 0,
                cost: Number(product.cogs) || 0,
                isInternal: true
            };

            setBomItems([...bomItems, newItem]);
            setSearchTerm('');
            setSearchResults([]);
            return;
        }

        // Check if self-linking
        if (product.id === productId && !product.isVariant) {
            alert('Cannot add the product to its own BOM.');
            return;
        }

        // Check if already exists
        const alreadyExists = bomItems.some(i => {
            if (product.isVariant) {
                return i.childProductId === product.id && i.childVariationId === Number(product.variantId);
            }
            return i.childProductId === product.id && !i.childVariationId;
        });

        if (alreadyExists) {
            alert('This component is already in the BOM.');
            return;
        }

        const newItem: BOMItem = {
            childProductId: product.id,
            childVariationId: product.isVariant ? Number(product.variantId) : undefined,
            displayName: product.name,
            quantity: 1,
            wasteFactor: 0,
            cost: Number(product.cogs) || 0
        };

        setBomItems([...bomItems, newItem]);
        setSearchTerm('');
        setSearchResults([]);
    };

    const totalCost = bomItems.reduce((sum, item) => {
        const itemCost = Number(item.cost) * Number(item.quantity) * (1 + Number(item.wasteFactor));
        return sum + itemCost;
    }, 0);

    // Hide entire panel if user doesn't have COGS permission
    if (!canViewCogs) return null;

    return (
        <div className="bg-white/70 backdrop-blur-md rounded-xl shadow-xs border border-white/50 animate-in fade-in slide-in-from-bottom-4 duration-500 delay-100">
            <div className="px-6 py-4 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
                <div className="flex items-center gap-4">
                    <h3 className="font-semibold text-gray-900">BOM Configuration</h3>

                    {/* Scope Selector - Only show if NO fixedVariationId */}
                    {fixedVariationId === undefined && (
                        <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-gray-200 text-sm">
                            <GitBranch size={16} className="text-gray-400" />
                            <select
                                value={selectedScope}
                                onChange={(e) => setSelectedScope(Number(e.target.value))}
                                className="bg-transparent border-none outline-hidden text-gray-700 font-medium cursor-pointer min-w-[150px]"
                            >
                                <option value={0}>Main Product</option>
                                {variants.map(v => (
                                    <option key={v.id} value={v.id}>
                                        Variant #{v.id} {v.sku ? `(${v.sku})` : ''}
                                    </option>
                                ))}
                            </select>
                        </div>
                    )}
                </div>
            </div>

            <div className="p-6 space-y-6">
                <BOMCostSummary
                    totalCost={totalCost}
                    effectiveStock={effectiveStock}
                    currentWooStock={currentWooStock}
                    isSyncing={isSyncing}
                    syncStatus={syncStatus}
                    onSyncToWoo={handleSyncToWoo}
                />

                {loading ? (
                    <div className="p-12 text-center text-gray-400">
                        <Loader2 className="animate-spin inline mr-2" /> Loading BOM...
                    </div>
                ) : (
                    <>
                        <BOMSearchDropdown
                            searchTerm={searchTerm}
                            onSearchChange={setSearchTerm}
                            searchResults={searchResults}
                            productId={productId}
                            onAddProduct={handleAddProduct}
                        />

                        <BOMItemsTable
                            items={bomItems}
                            selectedScope={selectedScope}
                            onItemsChange={setBomItems}
                        />

                        {/* Save Button */}
                        {bomItems.length > 0 && (
                            <div className="flex justify-end mt-4 pt-4 border-t border-gray-100">
                                <button
                                    onClick={handleSave}
                                    disabled={saving}
                                    className="flex items-center gap-2 px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all text-sm font-medium"
                                >
                                    {saving ? (
                                        <Loader2 size={14} className="animate-spin" />
                                    ) : (
                                        <Save size={14} />
                                    )}
                                    {saving ? 'Saving...' : 'Save BOM'}
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
});

import { useState } from 'react';
import { useAccountFeature } from '../../hooks/useAccountFeature';
import { useAccount } from '../../context/AccountContext';
import { usePermissions } from '../../hooks/usePermissions';
import { AlertTriangle, Scale, DollarSign, Calculator } from 'lucide-react';

interface GoldPricePanelProps {
    product: any;
    onChange: (updates: any) => void;
    hasVariants?: boolean;
}

export function GoldPricePanel({ product, onChange, hasVariants }: GoldPricePanelProps) {
    const isEnabled = useAccountFeature('GOLD_PRICE_CALCULATOR');
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');

    // Hide panel if feature is disabled OR user doesn't have COGS permission
    if (!isEnabled || !canViewCogs) return null;

    // Hide main product gold price panel if variants exist (gold price is set per-variant)
    if (hasVariants) {
        return (
            <div className="bg-amber-50/50 rounded-xl border border-amber-100 p-6">
                <div className="flex items-center gap-3">
                    <DollarSign className="text-amber-600" size={20} />
                    <div>
                        <h3 className="text-sm font-medium text-gray-900">Gold Price Calculation</h3>
                        <p className="text-sm text-gray-600 mt-1">
                            This product has variants. Gold price settings are configured per-variant in the <strong>Variations</strong> tab.
                        </p>
                    </div>
                </div>
            </div>
        );
    }

    const weight = product.weight ? parseFloat(product.weight) : 0;

    // Determine current selection
    // If goldPriceType is set, use it.
    // If not, but isGoldPriceApplied is true, treat as "Legacy/Base"
    const currentType = product.goldPriceType || (product.isGoldPriceApplied ? 'legacy' : 'none');

    // Get price based on type
    const getPrice = (type: string) => {
        switch (type) {
            case '18ct': return Number(currentAccount?.goldPrice18ct) || 0;
            case '9ct': return Number(currentAccount?.goldPrice9ct) || 0;
            case '18ctWhite': return Number(currentAccount?.goldPrice18ctWhite) || 0;
            case '9ctWhite': return Number(currentAccount?.goldPrice9ctWhite) || 0;
            case 'legacy': return Number(currentAccount?.goldPrice) || 0;
            default: return 0;
        }
    };

    const selectedPrice = getPrice(currentType);
    const calculatedCost = weight * selectedPrice;

    const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const newType = e.target.value;
        if (newType === 'none') {
            onChange({ isGoldPriceApplied: false, goldPriceType: null });
        } else if (newType === 'legacy') {
            onChange({ isGoldPriceApplied: true, goldPriceType: null });
        } else {
            onChange({ isGoldPriceApplied: true, goldPriceType: newType });
        }
    };

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
            <div className="p-6 border-b border-gray-200 flex justify-between items-center bg-amber-50/30">
                <h2 className="text-lg font-medium text-gray-900 flex items-center gap-2">
                    <DollarSign className="text-amber-600" size={20} /> Gold Price Calculation
                </h2>

                <div className="flex items-center gap-2">
                    <label className="text-sm font-medium text-gray-700">Gold Type:</label>
                    <select
                        value={currentType}
                        onChange={handleTypeChange}
                        className="block w-40 pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-hidden focus:ring-amber-500 focus:border-amber-500 sm:text-sm rounded-md bg-white"
                    >
                        <option value="none">None</option>
                        <option value="18ct">18ct Gold</option>
                        <option value="9ct">9ct Gold</option>
                        <option value="18ctWhite">18ct White Gold</option>
                        <option value="9ctWhite">9ct White Gold</option>
                        {currentType === 'legacy' && <option value="legacy">Legacy (Base Price)</option>}
                    </select>
                </div>
            </div>

            <div className="p-6 space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                        <div className="text-xs text-gray-500 uppercase font-bold mb-1">Applied Price</div>
                        <div className="text-xl font-mono text-gray-900">
                            ${selectedPrice.toFixed(2)} <span className="text-sm text-gray-500">/g</span>
                        </div>
                        {currentType !== 'none' && (
                            <div className="text-xs text-gray-500 mt-1">
                                Based on {currentType === 'legacy' ? 'Base Price' : currentType} setting
                            </div>
                        )}
                    </div>

                    <div className="p-4 bg-gray-50 border border-gray-200 rounded-lg">
                        <div className="text-xs text-gray-500 uppercase font-bold mb-1">Product Weight</div>
                        <div className="flex items-center gap-2">
                            <Scale size={16} className="text-gray-400" />
                            <div className="text-xl font-mono text-gray-900">{weight > 0 ? weight : '--'} g</div>
                        </div>
                        {!weight && <p className="text-xs text-red-500 mt-1">Missing weight from sync</p>}
                    </div>

                    <div className={`p-4 border rounded-lg ${currentType !== 'none' ? 'bg-amber-50 border-amber-200' : 'bg-gray-50 border-gray-200 opacity-50'}`}>
                        <div className="text-xs text-gray-500 uppercase font-bold mb-1">Calculated COGS</div>
                        <div className="flex items-center gap-2">
                            <Calculator size={16} className="text-gray-400" />
                            <div className="text-xl font-mono text-gray-900">
                                ${calculatedCost.toFixed(2)}
                            </div>
                        </div>
                    </div>
                </div>

                {currentType !== 'none' && (
                    <div className="flex items-start gap-2 text-sm text-amber-700 bg-amber-50 p-3 rounded-md border border-amber-100">
                        <AlertTriangle size={16} className="mt-0.5" />
                        <p>
                            This calculated cost (${calculatedCost.toFixed(2)}) will override any manual COGS or BOM cost for margin reports.
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
}

import * as React from 'react';
import { DollarSign } from 'lucide-react';
import { MiscCostsEditor, MiscCost } from './MiscCostsEditor';
import { usePermissions } from '../../hooks/usePermissions';

interface PricingPanelProps {
    formData: any;
    onChange?: (updates: any) => void;
}

export const PricingPanel: React.FC<PricingPanelProps> = ({ formData, onChange }) => {
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');

    return (
        <div className="bg-white/70 backdrop-blur-md rounded-xl shadow-xs border border-white/50 p-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h3 className="text-sm font-bold text-gray-900 uppercase tracking-wide mb-4 flex items-center gap-2">
                <DollarSign size={16} className="text-blue-600" />
                Pricing
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Regular Price</label>
                    <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">$</span>
                        <input
                            type="number"
                            step="0.01"
                            value={formData.price}
                            onChange={(e) => onChange && onChange({ price: e.target.value })}
                            className="w-full pl-8 pr-4 py-2 bg-white/50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-hidden transition-all"
                            placeholder="0.00"
                        />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Sale Price</label>
                    <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">$</span>
                        <input
                            type="number"
                            step="0.01"
                            value={formData.salePrice}
                            onChange={(e) => onChange && onChange({ salePrice: e.target.value })}
                            className="w-full pl-8 pr-4 py-2 bg-white/50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-hidden transition-all"
                            placeholder="0.00"
                        />
                    </div>
                </div>
                {canViewCogs && (
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Cost of Goods (COGS)</label>
                        <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">$</span>
                            <input
                                type="number"
                                step="0.01"
                                value={formData.cogs}
                                onChange={(e) => {
                                    // Limit input length to prevent performance issues
                                    if (e.target.value.length <= 10) {
                                        onChange && onChange({ cogs: e.target.value });
                                    }
                                }}
                                className="w-full pl-8 pr-4 py-2 bg-white/50 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-hidden transition-all"
                                placeholder="0.00"
                            />
                        </div>
                    </div>
                )}
            </div>

            {canViewCogs && (
                <div className="mb-6">
                    <MiscCostsEditor
                        value={formData.miscCosts || []}
                        onChange={(costs) => onChange && onChange({ miscCosts: costs })}
                    />
                </div>
            )}

            {/* Profit Margin Calculator - Only show when user can view COGS */}
            {canViewCogs && (() => {
                const sellingPrice = parseFloat(formData.salePrice) || parseFloat(formData.price) || 0;
                const cogs = parseFloat(formData.cogs) || 0;
                const miscTotal = (formData.miscCosts || []).reduce((sum: number, item: MiscCost) => sum + (Number(item.amount) || 0), 0);
                const totalCost = cogs + miscTotal;

                const profitDollar = sellingPrice - totalCost;
                const profitPercent = sellingPrice > 0 ? ((profitDollar / sellingPrice) * 100) : 0;
                const hasCogs = (formData.cogs && parseFloat(formData.cogs) > 0) || miscTotal > 0;
                const hasPrice = sellingPrice > 0;

                if (!hasPrice && !hasCogs) return null;

                return (
                    <div className="mt-6 pt-6 border-t border-gray-100/50">
                        {hasCogs && (
                            <div className="flex items-center justify-between mb-4">
                                <span className="text-sm font-medium text-gray-700">Total COGS</span>
                                <span className="text-sm font-bold text-gray-900">${totalCost.toFixed(2)}</span>
                            </div>
                        )}
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-medium text-gray-700">Profit Margin</span>
                            {hasCogs && hasPrice ? (
                                <div className="flex items-center gap-3">
                                    <span className={`text-lg font-bold ${profitDollar >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                                        ${profitDollar.toFixed(2)}
                                    </span>
                                    <span className={`px-2 py-0.5 rounded-full text-sm font-medium ${profitPercent >= 0
                                        ? 'bg-green-50 text-green-700 border border-green-200'
                                        : 'bg-red-50 text-red-700 border border-red-200'
                                        }`}>
                                        {profitPercent >= 0 ? '+' : ''}{profitPercent.toFixed(1)}%
                                    </span>
                                </div>
                            ) : (
                                <span className="text-sm text-gray-400 italic">
                                    {!hasCogs ? 'Enter COGS to calculate' : 'Enter price to calculate'}
                                </span>
                            )}
                        </div>
                        {hasCogs && hasPrice && (
                            <p className="text-xs text-gray-500 mt-1">
                                Based on {formData.salePrice && parseFloat(formData.salePrice) > 0 ? 'sale' : 'regular'} price of ${sellingPrice.toFixed(2)}
                            </p>
                        )}
                    </div>
                );
            })()}
        </div>
    );
};

