/**
 * Stock Management Panel - View and edit stock on hand
 * Shows calculated stock for BOM products, editable for simple products
 * For variable products, shows stock per variant
 */

import { useState, useEffect, useCallback, useRef, useImperativeHandle, forwardRef } from 'react';
import { Package, Loader2, AlertTriangle, Layers, ChevronDown, ChevronUp } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Logger } from '../../utils/logger';

interface StockManagementPanelProps {
    productWooId: number;
    variants?: Array<{
        id: number;
        sku?: string;
        attributes?: Array<{ name: string; option: string }>;
        stock_quantity?: number | null;
        stock_status?: string;
    }>;
    onStockChange?: (newStock: number, variantId?: number) => void;
}

/** Imperative handle so the parent Save button can trigger a stock save */
export interface StockManagementPanelRef {
    save(): Promise<boolean>;
}

interface StockInfo {
    stockQuantity: number | null;
    isBOMBased: boolean;
    manageStock: boolean;
    isVariable?: boolean;
    variants?: Array<{
        wooId: number;
        sku?: string;
        stockQuantity: number | null;
        stockStatus?: string;
        manageStock: boolean;
        attributes?: string;
    }>;
}

export const StockManagementPanel = forwardRef<StockManagementPanelRef, StockManagementPanelProps>(function StockManagementPanel({ productWooId, variants, onStockChange }, ref) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    // Why: refs prevent callback recreation on silent token refresh, same pattern as useProductEdit
    const tokenRef = useRef(token);
    tokenRef.current = token;
    const accountRef = useRef(currentAccount);
    accountRef.current = currentAccount;

    const [stockInfo, setStockInfo] = useState<StockInfo | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [savingVariantId, setSavingVariantId] = useState<number | null>(null);
    const [editValues, setEditValues] = useState<Record<number, string>>({});
    const [error, setError] = useState<string | null>(null);
    const [isExpanded, setIsExpanded] = useState(true);

    const fetchStock = useCallback(async () => {
        const tkn = tokenRef.current;
        const acct = accountRef.current;
        if (!tkn || !acct) return;

        try {
            const res = await fetch(`/api/products/${productWooId}/stock`, {
                headers: {
                    'Authorization': `Bearer ${tkn}`,
                    'X-Account-ID': acct.id
                }
            });

            if (res.ok) {
                const data: StockInfo = await res.json();
                setStockInfo(data);

                // Initialize edit values
                if (data.variants) {
                    const values: Record<number, string> = {};
                    data.variants.forEach(v => {
                        values[v.wooId] = v.stockQuantity?.toString() ?? '';
                    });
                    setEditValues(values);
                } else {
                    setEditValues({ 0: data.stockQuantity?.toString() ?? '' });
                }
            } else {
                setError('Failed to load stock info');
            }
        } catch (err) {
            Logger.error('Failed to fetch stock', { error: err });
            setError('Failed to load stock info');
        } finally {
            setIsLoading(false);
        }
    }, [productWooId]);

    useEffect(() => {
        fetchStock();
    }, [fetchStock]);

    /**
     * Save stock for a variant or main product.
     * Returns true on success, false on failure.
     */
    const handleSave = async (variantWooId?: number): Promise<boolean> => {
        const tkn = tokenRef.current;
        const acct = accountRef.current;
        if (!tkn || !acct) return false;

        const targetId = variantWooId ?? 0;
        const newStock = parseInt(editValues[targetId] ?? '', 10);
        if (isNaN(newStock) || newStock < 0) {
            setError('Please enter a valid stock quantity');
            return false;
        }

        setSavingVariantId(targetId);
        setError(null);

        try {
            const url = variantWooId
                ? `/api/products/${productWooId}/variants/${variantWooId}/stock`
                : `/api/products/${productWooId}/stock`;

            const res = await fetch(url, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${tkn}`,
                    'X-Account-ID': acct.id,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ stockQuantity: newStock })
            });

            if (res.ok) {
                // Update local state
                if (variantWooId && stockInfo?.variants) {
                    setStockInfo(prev => prev ? {
                        ...prev,
                        variants: prev.variants?.map(v =>
                            v.wooId === variantWooId
                                ? { ...v, stockQuantity: newStock, manageStock: true }
                                : v
                        )
                    } : prev);
                } else {
                    setStockInfo(prev => prev ? { ...prev, stockQuantity: newStock, manageStock: true } : prev);
                }
                onStockChange?.(newStock, variantWooId);
                return true;
            } else {
                const data = await res.json();
                setError(data.error || 'Failed to update stock');
                return false;
            }
        } catch (err) {
            Logger.error('Failed to save stock', { error: err });
            setError('Failed to save stock');
            return false;
        } finally {
            setSavingVariantId(null);
        }
    };

    const handleAdjust = (delta: number, variantWooId?: number) => {
        const targetId = variantWooId ?? 0;
        const current = parseInt(editValues[targetId] ?? '0', 10) || 0;
        const newValue = Math.max(0, current + delta);
        setEditValues(prev => ({ ...prev, [targetId]: newValue.toString() }));
    };

    /**
     * Why: expose save() so the page-level Save button can flush pending stock edits.
     * Returns true if save succeeded or was a no-op, false on failure.
     */
    useImperativeHandle(ref, () => ({
        async save(): Promise<boolean> {
            const targets: Array<{ variantWooId?: number; targetId: number }> = [];

            if (stockInfo?.variants) {
                for (const v of stockInfo.variants) {
                    const current = v.stockQuantity?.toString() ?? '';
                    if (editValues[v.wooId] !== current) {
                        targets.push({ variantWooId: v.wooId, targetId: v.wooId });
                    }
                }
            } else {
                const current = stockInfo?.stockQuantity?.toString() ?? '';
                if (editValues[0] !== current) {
                    targets.push({ targetId: 0 });
                }
            }

            if (targets.length === 0) return true;

            for (const t of targets) {
                const ok = await handleSave(t.variantWooId);
                if (!ok) return false;
            }
            return true;
        }
    }), [stockInfo, editValues, handleSave]);

    if (isLoading) {
        return (
            <div className="bg-gradient-to-br from-blue-50/50 to-indigo-50/50 rounded-xl border border-blue-100/50 p-6">
                <div className="flex items-center justify-center gap-2 text-gray-500">
                    <Loader2 className="animate-spin" size={18} />
                    <span className="text-sm">Loading stock...</span>
                </div>
            </div>
        );
    }

    // Variable product with variants
    const isVariable = stockInfo?.isVariable || (variants && variants.length > 0);

    return (
        <div className="bg-gradient-to-br from-blue-50/50 to-indigo-50/50 rounded-xl border border-blue-100/50 p-6">
            <button
                type="button"
                onClick={() => setIsExpanded(!isExpanded)}
                className="w-full flex items-center justify-between text-xs font-semibold text-gray-500 uppercase tracking-wider mb-4"
            >
                <span className="flex items-center gap-2">
                    <Package size={14} className="text-blue-600" />
                    Stock On Hand
                    {stockInfo?.isBOMBased && (
                        <span className="ml-2 px-2 py-0.5 bg-purple-100 text-purple-700 text-[10px] font-medium rounded-full flex items-center gap-1">
                            <Layers size={10} />
                            BOM Calculated
                        </span>
                    )}
                    {isVariable && (
                        <span className="ml-2 px-2 py-0.5 bg-indigo-100 text-indigo-700 text-[10px] font-medium rounded-full">
                            {stockInfo?.variants?.length ?? variants?.length ?? 0} Variants
                        </span>
                    )}
                </span>
                {isExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
            </button>

            {error && (
                <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2 text-red-700 text-sm">
                    <AlertTriangle size={16} />
                    {error}
                </div>
            )}

            {isExpanded && (
                <>
                    {stockInfo?.isBOMBased ? (
                        // BOM-based: Read-only display
                        <div className="space-y-3">
                            <div className="flex items-center gap-4">
                                <div className="text-4xl font-bold text-gray-900">
                                    {stockInfo.stockQuantity ?? '-'}
                                </div>
                                <div className="text-sm text-gray-500">
                                    units available
                                </div>
                            </div>
                            <p className="text-xs text-gray-500 bg-white/50 rounded-lg p-3 border border-gray-100">
                                This product has a Bill of Materials (BOM). Stock is automatically calculated
                                based on the available quantity of component items.
                            </p>
                        </div>
                    ) : isVariable ? (
                        // Variable product: Show variant stock table
                        <div className="space-y-3">
                            <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
                                <table className="w-full text-sm">
                                    <thead className="bg-gray-50 border-b border-gray-200">
                                        <tr>
                                            <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">Variant</th>
                                            <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">SKU</th>
                                            <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Stock</th>
                                            <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Actions</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-100">
                                        {(stockInfo?.variants ?? variants?.map(v => ({
                                            wooId: v.id,
                                            sku: v.sku,
                                            stockQuantity: v.stock_quantity,
                                            stockStatus: v.stock_status,
                                            manageStock: false,
                                            attributes: v.attributes?.map(a => a.option).join(' / ')
                                        })) ?? []).map((variant) => (
                                            <tr key={variant.wooId} className="hover:bg-gray-50">
                                                <td className="px-4 py-3 font-medium text-gray-900">
                                                    {variant.attributes || `Variation #${variant.wooId}`}
                                                </td>
                                                <td className="px-4 py-3 text-gray-500 font-mono text-xs">
                                                    {variant.sku || '-'}
                                                </td>
                                                <td className="px-4 py-3">
                                                    <div className="flex items-center justify-center gap-2">
                                                        <button
                                                            type="button"
                                                            onClick={() => handleAdjust(-1, variant.wooId)}
                                                            className="w-7 h-7 flex items-center justify-center bg-gray-100 border border-gray-200 rounded text-gray-600 hover:bg-gray-200 transition-colors text-sm font-bold"
                                                        >
                                                            −
                                                        </button>
                                                        <input
                                                            type="number"
                                                            min="0"
                                                            value={editValues[variant.wooId] ?? ''}
                                                            onChange={(e) => setEditValues(prev => ({ ...prev, [variant.wooId]: e.target.value }))}
                                                            className="w-16 px-2 py-1 text-center font-bold bg-white border border-gray-200 rounded focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none"
                                                        />
                                                        <button
                                                            type="button"
                                                            onClick={() => handleAdjust(1, variant.wooId)}
                                                            className="w-7 h-7 flex items-center justify-center bg-gray-100 border border-gray-200 rounded text-gray-600 hover:bg-gray-200 transition-colors text-sm font-bold"
                                                        >
                                                            +
                                                        </button>
                                                    </div>
                                                </td>
                                                <td className="px-4 py-3 text-center">
                                                    <button
                                                        type="button"
                                                        onClick={() => handleSave(variant.wooId)}
                                                        disabled={savingVariantId === variant.wooId || editValues[variant.wooId] === (variant.stockQuantity?.toString() ?? '')}
                                                        className="px-3 py-1 bg-blue-600 text-white text-xs font-medium rounded hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                                    >
                                                        {savingVariantId === variant.wooId ? <Loader2 className="animate-spin" size={12} /> : 'Save'}
                                                    </button>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                            <p className="text-xs text-gray-500">
                                Stock is managed per variant for variable products.
                            </p>
                        </div>
                    ) : (
                        // Simple product: Editable single stock
                        <div className="space-y-4">
                            <div className="flex items-center gap-3">
                                <button
                                    type="button"
                                    onClick={() => handleAdjust(-1)}
                                    className="w-10 h-10 flex items-center justify-center bg-white border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 transition-colors text-lg font-bold"
                                >
                                    −
                                </button>
                                <input
                                    type="number"
                                    min="0"
                                    value={editValues[0] ?? ''}
                                    onChange={(e) => setEditValues(prev => ({ ...prev, 0: e.target.value }))}
                                    className="w-24 px-4 py-2 text-center text-xl font-bold bg-white border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
                                />
                                <button
                                    type="button"
                                    onClick={() => handleAdjust(1)}
                                    className="w-10 h-10 flex items-center justify-center bg-white border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 transition-colors text-lg font-bold"
                                >
                                    +
                                </button>
                                <button
                                    type="button"
                                    onClick={() => handleSave()}
                                    disabled={savingVariantId === 0 || editValues[0] === (stockInfo?.stockQuantity?.toString() ?? '')}
                                    className="ml-4 px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center gap-2"
                                >
                                    {savingVariantId === 0 ? <Loader2 className="animate-spin" size={14} /> : null}
                                    Update Stock
                                </button>
                            </div>
                            {!stockInfo?.manageStock && (
                                <p className="text-xs text-amber-600 bg-amber-50 rounded-lg p-3 border border-amber-100">
                                    Stock management is currently disabled for this product.
                                    Setting a stock quantity will enable local stock tracking.
                                </p>
                            )}
                        </div>
                    )}
                </>
            )}
        </div>
    );
});

import * as React from 'react';
import { Save, DollarSign, Users, TrendingUp, Globe, Activity, Percent } from 'lucide-react';
import { DIMENSION_OPTIONS, METRIC_OPTIONS, ReportDimension, ReportMetric } from '../../types/analytics';

interface ReportConfigPanelProps {
    dateRange: string;
    setDateRange: (range: string) => void;
    dimension: string;
    setDimension: (dim: string) => void;
    metrics: string[];
    setMetrics: (metrics: string[]) => void;
    isLoading: boolean;
    onGenerate: () => void;
    onSaveOpen: () => void;
}

/** Icon mapping for metric categories */
const METRIC_ICONS: Record<string, React.ReactNode> = {
    sales: <DollarSign size={14} />,
    orders: <Activity size={14} />,
    aov: <TrendingUp size={14} />,
    quantity: <Activity size={14} />,
    new_customers: <Users size={14} />,
    sessions: <Globe size={14} />,
    visitors: <Users size={14} />,
    page_views: <Globe size={14} />,
    conversion_rate: <Percent size={14} />
};

export function ReportConfigPanel({
    dateRange,
    setDateRange,
    dimension,
    setDimension,
    metrics,
    setMetrics,
    isLoading,
    onGenerate,
    onSaveOpen
}: ReportConfigPanelProps) {

    const toggleMetric = (m: string) => {
        if (metrics.includes(m)) {
            setMetrics(metrics.filter(x => x !== m));
        } else {
            setMetrics([...metrics, m]);
        }
    };

    // Group dimensions by category
    const timeDimensions = DIMENSION_OPTIONS.filter(d => d.category === 'time');
    const salesDimensions = DIMENSION_OPTIONS.filter(d => d.category === 'sales');
    const trafficDimensions = DIMENSION_OPTIONS.filter(d => d.category === 'traffic');

    // Group metrics by category
    const salesMetrics = METRIC_OPTIONS.filter(m => m.category === 'sales');
    const trafficMetrics = METRIC_OPTIONS.filter(m => m.category === 'traffic');
    const conversionMetrics = METRIC_OPTIONS.filter(m => m.category === 'conversion');

    return (
        <div className="w-full md:w-80 shrink-0 space-y-5 border-r border-gray-100 pr-6">
            <div className="animate-in fade-in slide-in-from-left-2 space-y-5">

                {/* Header */}
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-gray-900">
                        Report Builder
                    </h3>
                    <button
                        onClick={onSaveOpen}
                        className="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-blue-600 hover:text-blue-700 hover:bg-blue-50 rounded-lg transition-all"
                    >
                        <Save size={14} /> Save
                    </button>
                </div>

                {/* Time Range */}
                <div className="bg-white/60 backdrop-blur-xs rounded-xl p-4 border border-gray-100/60 shadow-xs">
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-2">
                        Time Range
                    </label>
                    <select
                        value={dateRange}
                        onChange={(e) => setDateRange(e.target.value)}
                        className="w-full bg-gray-50/80 border border-gray-200/80 rounded-lg px-3 py-2.5 text-sm font-medium text-gray-700 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500/50 transition-all outline-hidden"
                    >
                        <option value="today">Today</option>
                        <option value="yesterday">Yesterday</option>
                        <option value="7d">Last 7 Days</option>
                        <option value="30d">Last 30 Days</option>
                        <option value="90d">Last 90 Days</option>
                        <option value="ytd">Year to Date</option>
                    </select>
                </div>

                {/* Group By Dimension */}
                <div className="bg-white/60 backdrop-blur-xs rounded-xl p-4 border border-gray-100/60 shadow-xs">
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-2">
                        Group By
                    </label>
                    <select
                        value={dimension}
                        onChange={(e) => setDimension(e.target.value)}
                        className="w-full bg-gray-50/80 border border-gray-200/80 rounded-lg px-3 py-2.5 text-sm font-medium text-gray-700 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500/50 transition-all outline-hidden"
                    >
                        <optgroup label="Time">
                            {timeDimensions.map(d => (
                                <option key={d.value} value={d.value}>{d.label}</option>
                            ))}
                        </optgroup>
                        <optgroup label="Sales">
                            {salesDimensions.map(d => (
                                <option key={d.value} value={d.value}>{d.label}</option>
                            ))}
                        </optgroup>
                        <optgroup label="Traffic">
                            {trafficDimensions.map(d => (
                                <option key={d.value} value={d.value}>{d.label}</option>
                            ))}
                        </optgroup>
                    </select>
                </div>

                {/* Metrics Selection */}
                <div className="bg-white/60 backdrop-blur-xs rounded-xl p-4 border border-gray-100/60 shadow-xs">
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-3">
                        Metrics
                    </label>

                    {/* Sales Metrics */}
                    <div className="mb-3">
                        <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1.5 flex items-center gap-1">
                            <DollarSign size={10} /> Sales
                        </div>
                        <div className="grid grid-cols-2 gap-1.5">
                            {salesMetrics.map(m => (
                                <label
                                    key={m.value}
                                    className={`flex items-center gap-2 px-2.5 py-2 rounded-lg cursor-pointer border text-sm transition-all ${metrics.includes(m.value)
                                        ? 'bg-blue-50 border-blue-200 text-blue-700 shadow-xs'
                                        : 'hover:bg-gray-50 border-gray-100 text-gray-600'
                                        }`}
                                >
                                    <input
                                        type="checkbox"
                                        checked={metrics.includes(m.value)}
                                        onChange={() => toggleMetric(m.value)}
                                        className="sr-only"
                                    />
                                    <span className="opacity-60">{METRIC_ICONS[m.value]}</span>
                                    <span className="font-medium text-xs">{m.label}</span>
                                </label>
                            ))}
                        </div>
                    </div>

                    {/* Traffic Metrics */}
                    <div className="mb-3">
                        <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1.5 flex items-center gap-1">
                            <Globe size={10} /> Traffic
                        </div>
                        <div className="grid grid-cols-2 gap-1.5">
                            {trafficMetrics.map(m => (
                                <label
                                    key={m.value}
                                    className={`flex items-center gap-2 px-2.5 py-2 rounded-lg cursor-pointer border text-sm transition-all ${metrics.includes(m.value)
                                        ? 'bg-green-50 border-green-200 text-green-700 shadow-xs'
                                        : 'hover:bg-gray-50 border-gray-100 text-gray-600'
                                        }`}
                                >
                                    <input
                                        type="checkbox"
                                        checked={metrics.includes(m.value)}
                                        onChange={() => toggleMetric(m.value)}
                                        className="sr-only"
                                    />
                                    <span className="opacity-60">{METRIC_ICONS[m.value]}</span>
                                    <span className="font-medium text-xs">{m.label}</span>
                                </label>
                            ))}
                        </div>
                    </div>

                    {/* Conversion Metrics */}
                    <div>
                        <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1.5 flex items-center gap-1">
                            <Percent size={10} /> Conversion
                        </div>
                        <div className="grid grid-cols-2 gap-1.5">
                            {conversionMetrics.map(m => (
                                <label
                                    key={m.value}
                                    className={`flex items-center gap-2 px-2.5 py-2 rounded-lg cursor-pointer border text-sm transition-all ${metrics.includes(m.value)
                                        ? 'bg-purple-50 border-purple-200 text-purple-700 shadow-xs'
                                        : 'hover:bg-gray-50 border-gray-100 text-gray-600'
                                        }`}
                                >
                                    <input
                                        type="checkbox"
                                        checked={metrics.includes(m.value)}
                                        onChange={() => toggleMetric(m.value)}
                                        className="sr-only"
                                    />
                                    <span className="opacity-60">{METRIC_ICONS[m.value]}</span>
                                    <span className="font-medium text-xs">{m.label}</span>
                                </label>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Generate Button */}
                <button
                    onClick={onGenerate}
                    disabled={isLoading || metrics.length === 0}
                    className="w-full bg-linear-to-r from-blue-600 to-blue-700 text-white py-3 rounded-xl hover:from-blue-700 hover:to-blue-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed font-semibold text-sm shadow-lg shadow-blue-500/20 hover:shadow-blue-500/30"
                >
                    {isLoading ? (
                        <span className="flex items-center justify-center gap-2">
                            <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                            Generating...
                        </span>
                    ) : 'Generate Report'}
                </button>
            </div>
        </div>
    );
}

import * as React from 'react';
import { BarChart3, Download, FileText, AlertCircle, TrendingUp, TrendingDown } from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { ReportResult, METRIC_OPTIONS } from '../../types/analytics';

interface ReportResultsProps {
    results: ReportResult[];
    metrics: string[];
    dimension: string;
    viewMode: boolean;
    error: string | null;
    hasSearched: boolean;
}

/** Format value based on metric type */
const formatValue = (metric: string, value: number | undefined): string => {
    if (value === undefined || value === null) return '-';

    const metricInfo = METRIC_OPTIONS.find(m => m.value === metric);
    const format = metricInfo?.format || 'number';

    switch (format) {
        case 'currency':
            return `$${value.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
        case 'percent':
            return `${value.toFixed(1)}%`;
        default:
            return value.toLocaleString(undefined, { maximumFractionDigits: 0 });
    }
};

/** Get dimension display label */
const getDimensionLabel = (dimension: string): string => {
    const labels: Record<string, string> = {
        day: 'Date',
        month: 'Month',
        product: 'Product',
        category: 'Category',
        customer: 'Customer',
        customer_segment: 'Segment',
        traffic_source: 'Traffic Source',
        utm_source: 'UTM Source',
        device: 'Device',
        country: 'Country',
        order_status: 'Order Status'
    };
    return labels[dimension] || dimension.toUpperCase();
};

/** Get metric display label */
const getMetricLabel = (metric: string): string => {
    const metricInfo = METRIC_OPTIONS.find(m => m.value === metric);
    return metricInfo?.label || metric.toUpperCase();
};

export function ReportResults({
    results,
    metrics,
    dimension,
    viewMode,
    error,
    hasSearched
}: ReportResultsProps) {

    const exportCSV = () => {
        if (results.length === 0) return;
        const headers = [getDimensionLabel(dimension), ...metrics.map(getMetricLabel)];
        const rows = results.map(row => [
            row.dimension,
            ...metrics.map(m => (row as any)[m] || 0)
        ]);

        const csvContent = "data:text/csv;charset=utf-8,"
            + headers.join(",") + "\n"
            + rows.map(e => e.join(",")).join("\n");

        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `report_${dimension}_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const exportPDF = () => {
        if (results.length === 0) return;
        const doc = new jsPDF();
        doc.setFontSize(18);
        doc.text(`Report: ${getDimensionLabel(dimension)}`, 14, 20);
        doc.setFontSize(10);
        doc.text(`Generated: ${new Date().toLocaleDateString()}`, 14, 28);

        const tableColumn = [getDimensionLabel(dimension), ...metrics.map(getMetricLabel)];
        const tableRows = results.map(row => [
            row.dimension,
            ...metrics.map(m => formatValue(m, (row as any)[m]))
        ]);

        autoTable(doc, {
            head: [tableColumn],
            body: tableRows,
            startY: 35,
            styles: { fontSize: 9 },
            headStyles: { fillColor: [59, 130, 246] }
        });

        doc.save(`report_${dimension}_${new Date().toISOString().split('T')[0]}.pdf`);
    };

    // Calculate totals for summary
    const totals = metrics.reduce((acc, m) => {
        acc[m] = results.reduce((sum, row) => sum + ((row as any)[m] || 0), 0);
        return acc;
    }, {} as Record<string, number>);

    return (
        <div className={`flex-1 min-h-[400px] flex flex-col ${viewMode ? 'bg-white/50 backdrop-blur-xl rounded-2xl border border-white/20 shadow-lg p-6' : ''}`}>

            {/* Header */}
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h3 className="text-xl font-bold text-gray-900 flex items-center gap-2">
                        {viewMode && <BarChart3 className="text-blue-600" size={24} />}
                        {viewMode ? 'Report Analysis' : 'Results'}
                    </h3>
                    {results.length > 0 && (
                        <p className="text-sm text-gray-500 mt-1">
                            {results.length} rows • Grouped by {getDimensionLabel(dimension)}
                        </p>
                    )}
                </div>
                <div className="flex gap-2">
                    <button
                        onClick={exportCSV}
                        disabled={results.length === 0}
                        className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 hover:border-gray-300 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-xs"
                    >
                        <Download size={14} /> CSV
                    </button>
                    <button
                        onClick={exportPDF}
                        disabled={results.length === 0}
                        className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 hover:border-gray-300 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-xs"
                    >
                        <FileText size={14} /> PDF
                    </button>
                </div>
            </div>

            {/* Error State */}
            {error ? (
                <div className="h-full flex flex-col items-center justify-center text-red-600 bg-red-50 rounded-xl p-10 border border-red-100">
                    <AlertCircle size={48} className="mb-4 opacity-70" />
                    <p className="font-semibold text-lg">Error generating report</p>
                    <p className="text-sm mt-2 text-red-500 max-w-md text-center">{error}</p>
                </div>
            ) : results.length === 0 ? (
                /* Empty State */
                <div className="h-full flex flex-col items-center justify-center text-gray-400 border-2 border-dashed border-gray-200 rounded-xl bg-gray-50/50 p-10">
                    <BarChart3 size={48} className="mb-4 text-gray-300" />
                    <p className="font-medium">{hasSearched ? 'No results found for the selected criteria' : 'Select metrics and generate a report'}</p>
                    {!hasSearched && <p className="text-sm mt-2">Choose your dimensions and metrics on the left, then click Generate</p>}
                </div>
            ) : (
                <>
                    {/* Summary Cards */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6">
                        {metrics.slice(0, 4).map(m => {
                            const metricInfo = METRIC_OPTIONS.find(mi => mi.value === m);
                            return (
                                <div key={m} className="bg-linear-to-br from-gray-50 to-white p-4 rounded-xl border border-gray-100 shadow-xs">
                                    <div className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">
                                        {metricInfo?.label || m}
                                    </div>
                                    <div className="text-xl font-bold text-gray-900">
                                        {formatValue(m, totals[m])}
                                    </div>
                                </div>
                            );
                        })}
                    </div>

                    {/* Data Table */}
                    <div className="overflow-x-auto border border-gray-200 rounded-xl shadow-xs flex-1">
                        <table className="min-w-full divide-y divide-gray-200">
                            <thead className="bg-gray-50/80">
                                <tr>
                                    <th className="px-6 py-3.5 text-left text-xs font-bold text-gray-600 uppercase tracking-wider">
                                        {getDimensionLabel(dimension)}
                                    </th>
                                    {metrics.map(m => (
                                        <th key={m} className="px-6 py-3.5 text-right text-xs font-bold text-gray-600 uppercase tracking-wider">
                                            {getMetricLabel(m)}
                                        </th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-gray-100">
                                {results.map((row, i) => (
                                    <tr
                                        key={i}
                                        className={`hover:bg-blue-50/30 transition-colors ${i % 2 === 0 ? 'bg-white' : 'bg-gray-50/30'}`}
                                    >
                                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                                            {row.dimension}
                                        </td>
                                        {metrics.map(m => (
                                            <td key={m} className="px-6 py-4 whitespace-nowrap text-sm text-gray-700 text-right font-mono tabular-nums">
                                                {formatValue(m, (row as any)[m])}
                                            </td>
                                        ))}
                                    </tr>
                                ))}
                            </tbody>
                            {/* Table Footer with Totals */}
                            <tfoot className="bg-gray-50 border-t-2 border-gray-200">
                                <tr>
                                    <td className="px-6 py-3.5 text-sm font-bold text-gray-900">
                                        Total
                                    </td>
                                    {metrics.map(m => (
                                        <td key={m} className="px-6 py-3.5 text-sm font-bold text-gray-900 text-right font-mono tabular-nums">
                                            {formatValue(m, totals[m])}
                                        </td>
                                    ))}
                                </tr>
                            </tfoot>
                        </table>
                    </div>
                </>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, X } from 'lucide-react';

export interface SegmentRule {
    field: string;
    operator: string;
    value: string;
}

export interface SegmentCriteria {
    type: 'AND' | 'OR';
    rules: SegmentRule[];
}

interface SegmentBuilderProps {
    initialCriteria?: SegmentCriteria;
    onSave: (criteria: SegmentCriteria) => void;
    onCancel: () => void;
    isSaving?: boolean;
}

const FIELDS = [
    { label: 'Total Spent', value: 'totalSpent', type: 'number' },
    { label: 'Orders Count', value: 'ordersCount', type: 'number' },
    { label: 'Email', value: 'email', type: 'text' },
    { label: 'First Name', value: 'firstName', type: 'text' },
    { label: 'Last Name', value: 'lastName', type: 'text' }
];

const OPERATORS = {
    number: [
        { label: 'Greater Than', value: 'gt' },
        { label: 'Less Than', value: 'lt' },
        { label: 'Equals', value: 'eq' },
        { label: 'Greater or Equal', value: 'gte' },
        { label: 'Less or Equal', value: 'lte' }
    ],
    text: [
        { label: 'Contains', value: 'contains' },
        { label: 'Equals', value: 'equals' },
        { label: 'Starts With', value: 'startsWith' }
    ]
};

export function SegmentBuilder({ initialCriteria, onSave, onCancel, isSaving }: SegmentBuilderProps) {
    const [criteria, setCriteria] = useState<SegmentCriteria>(initialCriteria || { type: 'AND', rules: [] });

    const addRule = () => {
        setCriteria({
            ...criteria,
            rules: [...criteria.rules, { field: 'totalSpent', operator: 'gt', value: '' }]
        });
    };

    const updateRule = (index: number, updates: Partial<SegmentRule>) => {
        const newRules = [...criteria.rules];
        newRules[index] = { ...newRules[index], ...updates };

        // Reset operator if field changes and type mismatch
        if (updates.field) {
            const fieldType = FIELDS.find(f => f.value === updates.field)?.type;
            const currentOp = newRules[index].operator;
            // Basic check, could be smarter
            if (fieldType === 'number' && ['contains', 'startsWith'].includes(currentOp)) {
                newRules[index].operator = 'gt';
            }
            if (fieldType === 'text' && ['gt', 'lt'].includes(currentOp)) {
                newRules[index].operator = 'contains';
            }
        }

        setCriteria({ ...criteria, rules: newRules });
    };

    const removeRule = (index: number) => {
        const newRules = criteria.rules.filter((_, i) => i !== index);
        setCriteria({ ...criteria, rules: newRules });
    };

    const getOperators = (fieldValue: string) => {
        const type = FIELDS.find(f => f.value === fieldValue)?.type || 'text';
        return OPERATORS[type as keyof typeof OPERATORS];
    };

    return (
        <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-xs space-y-6">
            <div className="flex items-center justify-between">
                <h3 className="text-lg font-medium text-gray-900">Segment Rules</h3>
                <div className="flex items-center gap-2">
                    <span className="text-sm text-gray-500">Match</span>
                    <select
                        className="bg-gray-50 border border-gray-300 rounded-sm px-2 py-1 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                        value={criteria.type}
                        onChange={(e) => setCriteria({ ...criteria, type: e.target.value as 'AND' | 'OR' })}
                    >
                        <option value="AND">All (AND)</option>
                        <option value="OR">Any (OR)</option>
                    </select>
                    <span className="text-sm text-gray-500">of the following conditions:</span>
                </div>
            </div>

            <div className="space-y-4">
                {criteria.rules.map((rule, index) => (
                    <div key={index} className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg border border-gray-100 group">
                        <select
                            className="flex-1 bg-white border border-gray-300 rounded-sm px-3 py-2 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={rule.field}
                            onChange={(e) => updateRule(index, { field: e.target.value })}
                        >
                            {FIELDS.map(f => (
                                <option key={f.value} value={f.value}>{f.label}</option>
                            ))}
                        </select>

                        <select
                            className="w-40 bg-white border border-gray-300 rounded-sm px-3 py-2 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={rule.operator}
                            onChange={(e) => updateRule(index, { operator: e.target.value })}
                        >
                            {getOperators(rule.field).map(op => (
                                <option key={op.value} value={op.value}>{op.label}</option>
                            ))}
                        </select>

                        <input
                            type="text"
                            className="flex-1 bg-white border border-gray-300 rounded-sm px-3 py-2 text-sm focus:outline-hidden focus:ring-2 focus:ring-blue-500"
                            placeholder="Value"
                            value={rule.value}
                            onChange={(e) => updateRule(index, { value: e.target.value })}
                        />

                        <button
                            onClick={() => removeRule(index)}
                            className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-sm transition-colors"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                ))}

                {criteria.rules.length === 0 && (
                    <div className="text-center py-8 text-gray-400 bg-gray-50 rounded-lg border border-dashed border-gray-200">
                        No rules defined. This segment will match all customers.
                    </div>
                )}

                <button
                    onClick={addRule}
                    className="flex items-center gap-2 text-blue-600 hover:text-blue-700 text-sm font-medium px-2 py-1 rounded-sm hover:bg-blue-50 transition-colors"
                >
                    <Plus size={16} />
                    Add Condition
                </button>
            </div>

            <div className="flex items-center justify-end gap-3 pt-4 border-t border-gray-100">
                <button
                    onClick={onCancel}
                    className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg text-sm font-medium transition-colors"
                >
                    Cancel
                </button>
                <button
                    onClick={() => onSave(criteria)}
                    disabled={isSaving}
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors disabled:opacity-50"
                >
                    {isSaving ? <span className="animate-spin">⌛</span> : <Save size={16} />}
                    Save Segment
                </button>
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { Logger } from '../../utils/logger';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { Save, Loader2, Bot, Key, ChevronDown, Check, Sparkles } from 'lucide-react';

// Available embedding models from OpenRouter
const EMBEDDING_MODELS = [
    { id: 'openai/text-embedding-3-small', name: 'OpenAI Text Embedding 3 Small', desc: 'Fast, cost-effective' },
    { id: 'openai/text-embedding-3-large', name: 'OpenAI Text Embedding 3 Large', desc: 'Higher quality' },
    { id: 'openai/text-embedding-ada-002', name: 'OpenAI Ada 002', desc: 'Legacy, widely used' },
    { id: 'voyage/voyage-large-2', name: 'Voyage Large 2', desc: 'High quality alternative' },
    { id: 'cohere/embed-english-v3.0', name: 'Cohere Embed English v3', desc: 'English optimized' },
];

export function AISettings() {
    const { currentAccount, refreshAccounts } = useAccount();
    const { token } = useAuth();

    const [apiKey, setApiKey] = useState('');
    const [selectedModel, setSelectedModel] = useState('openai/gpt-4o');
    const [selectedEmbeddingModel, setSelectedEmbeddingModel] = useState('openai/text-embedding-3-small');
    const [models, setModels] = useState<any[]>([]);
    const [isLoadingModels, setIsLoadingModels] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const [isEmbeddingOpen, setIsEmbeddingOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);
    const embeddingDropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                // Revert to selected model name on close
                if (selectedModel) {
                    const name = selectedModel === 'openai/gpt-4o'
                        ? 'GPT-4o'
                        : (models.find(m => m.id === selectedModel)?.name || selectedModel);
                    setSearchQuery(name);
                }
            }
            if (embeddingDropdownRef.current && !embeddingDropdownRef.current.contains(event.target as Node)) {
                setIsEmbeddingOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [selectedModel, models]);

    const filteredModels = models.filter(model =>
        model.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        model.id.toLowerCase().includes(searchQuery.toLowerCase())
    );

    useEffect(() => {
        const name = selectedModel === 'openai/gpt-4o'
            ? 'GPT-4o'
            : (models.find(m => m.id === selectedModel)?.name || selectedModel);
        setSearchQuery(name);
    }, [selectedModel, models]);



    useEffect(() => {
        if (currentAccount) {
            setApiKey(currentAccount.openRouterApiKey || '');
            if (currentAccount.aiModel) {
                setSelectedModel(currentAccount.aiModel);
            }
            if (currentAccount.embeddingModel) {
                setSelectedEmbeddingModel(currentAccount.embeddingModel);
            }
        }
    }, [currentAccount]);

    useEffect(() => {
        const fetchModels = async () => {
            if (!currentAccount || !token) return;
            // Only fetch if we have a key saved (or maybe standard list?)
            // If the user hasn't saved a key yet, we might not get models unless we use a default key on backend.
            // But let's try fetching anyway.
            setIsLoadingModels(true);
            try {
                const res = await fetch('/api/ai/models', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const data = await res.json();
                    if (Array.isArray(data)) {
                        const sorted = data.sort((a: any, b: any) => a.id.localeCompare(b.id));
                        setModels(sorted);
                    }
                }
            } catch (e) {
                Logger.error('Failed to fetch models', { error: e });
            } finally {
                setIsLoadingModels(false);
            }
        };

        // Fetch on mount
        fetchModels();
    }, [currentAccount?.id, token]); // Only re-fetch if account changes

    const handleSave = async () => {
        if (!currentAccount || !token) return;
        setIsSaving(true);
        try {
            const res = await fetch(`/api/accounts/${currentAccount.id}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({
                    openRouterApiKey: apiKey,
                    aiModel: selectedModel,
                    embeddingModel: selectedEmbeddingModel
                })
            });

            if (!res.ok) throw new Error('Failed to save');

            await refreshAccounts();
            alert('AI Settings Saved');

        } catch (e) {
            Logger.error('An error occurred', { error: e });
            alert('Failed to save');
        } finally {
            setIsSaving(false);
        }
    };

    const getEmbeddingModelName = () => {
        const model = EMBEDDING_MODELS.find(m => m.id === selectedEmbeddingModel);
        return model?.name || selectedEmbeddingModel;
    };

    return (
        <div className="space-y-6">
            <div className="grid gap-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1 flex items-center gap-2">
                        <Key size={16} /> OpenRouter API Key
                    </label>
                    <input
                        type="password"
                        value={apiKey}
                        onChange={(e) => setApiKey(e.target.value)}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden font-mono text-sm"
                        placeholder="sk-or-v1-..."
                    />
                    <p className="text-xs text-gray-500 mt-1">
                        Get your key from <a href="https://openrouter.ai/keys" target="_blank" rel="noreferrer" className="text-blue-600 hover:underline">openrouter.ai</a>
                    </p>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1 flex items-center gap-2">
                        <Bot size={16} /> AI Chat Model
                    </label>
                    <div className="relative" ref={dropdownRef}>
                        <div className="relative">
                            <input
                                ref={inputRef}
                                type="text"
                                value={searchQuery}
                                onChange={(e) => {
                                    setSearchQuery(e.target.value);
                                    if (!isOpen) setIsOpen(true);
                                }}
                                onFocus={() => setIsOpen(true)}
                                disabled={isLoadingModels}
                                className={`w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden transition-colors pr-10 ${isOpen ? 'border-blue-500' : 'border-gray-300'
                                    } ${isLoadingModels ? 'opacity-50 cursor-not-allowed' : ''}`}
                                placeholder="Select or search model..."
                            />

                            <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                                {isLoadingModels ? (
                                    <Loader2 size={16} className="animate-spin" />
                                ) : (
                                    <ChevronDown size={16} className={`transition-transform ${isOpen ? 'rotate-180' : ''}`} />
                                )}
                            </div>
                        </div>

                        {isOpen && (
                            <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-[300px] flex flex-col overflow-hidden">
                                <div className="overflow-y-auto flex-1 p-1">
                                    <div
                                        onClick={() => {
                                            setSelectedModel('openai/gpt-4o');
                                            setIsOpen(false);
                                        }}
                                        className={`px-3 py-2 text-sm rounded-md cursor-pointer flex items-center justify-between group ${selectedModel === 'openai/gpt-4o' ? 'bg-blue-50 text-blue-700' : 'hover:bg-gray-50 text-gray-700'
                                            }`}
                                    >
                                        <div className="flex flex-col">
                                            <span className="font-medium">GPT-4o</span>
                                            <span className="text-xs opacity-70">Default – supports tool use</span>
                                        </div>
                                        {selectedModel === 'openai/gpt-4o' && <Check size={14} />}
                                    </div>

                                    {filteredModels.map(model => (
                                        <div
                                            key={model.id}
                                            onClick={() => {
                                                setSelectedModel(model.id);
                                                setIsOpen(false);
                                            }}
                                            className={`px-3 py-2 text-sm rounded-md cursor-pointer flex items-center justify-between group ${selectedModel === model.id ? 'bg-blue-50 text-blue-700' : 'hover:bg-gray-50 text-gray-700'
                                                }`}
                                        >
                                            <div className="flex flex-col truncate pr-2">
                                                <span className="font-medium truncate">{model.name}</span>
                                                <span className="text-xs opacity-60 font-mono truncate">{model.id}</span>
                                            </div>
                                            {selectedModel === model.id && <Check size={14} className="shrink-0" />}
                                        </div>
                                    ))}

                                    {filteredModels.length === 0 && (
                                        <div className="px-4 py-8 text-center text-sm text-gray-500">
                                            No models found matching "{searchQuery}"
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* Embedding Model Selector */}
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1 flex items-center gap-2">
                        <Sparkles size={16} /> Embedding Model
                        <span className="text-xs font-normal text-gray-400">(for semantic search)</span>
                    </label>
                    <div className="relative" ref={embeddingDropdownRef}>
                        <button
                            type="button"
                            onClick={() => setIsEmbeddingOpen(!isEmbeddingOpen)}
                            className={`w-full px-4 py-2 border rounded-lg text-left flex items-center justify-between transition-colors ${isEmbeddingOpen ? 'border-blue-500 ring-2 ring-blue-500' : 'border-gray-300'}`}
                        >
                            <span>{getEmbeddingModelName()}</span>
                            <ChevronDown size={16} className={`text-gray-400 transition-transform ${isEmbeddingOpen ? 'rotate-180' : ''}`} />
                        </button>

                        {isEmbeddingOpen && (
                            <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg overflow-hidden">
                                <div className="p-1">
                                    {EMBEDDING_MODELS.map(model => (
                                        <div
                                            key={model.id}
                                            onClick={() => {
                                                setSelectedEmbeddingModel(model.id);
                                                setIsEmbeddingOpen(false);
                                            }}
                                            className={`px-3 py-2 text-sm rounded-md cursor-pointer flex items-center justify-between ${selectedEmbeddingModel === model.id ? 'bg-purple-50 text-purple-700' : 'hover:bg-gray-50 text-gray-700'}`}
                                        >
                                            <div className="flex flex-col">
                                                <span className="font-medium">{model.name}</span>
                                                <span className="text-xs opacity-60">{model.desc}</span>
                                            </div>
                                            {selectedEmbeddingModel === model.id && <Check size={14} />}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                    <p className="text-xs text-gray-500 mt-1">
                        Used for semantic product search and finding similar items
                    </p>
                </div>
            </div>

            <div className="flex justify-end pt-4">
                <button
                    onClick={handleSave}
                    disabled={isSaving}
                    className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium disabled:opacity-50"
                >
                    {isSaving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                    {isSaving ? 'Saving...' : 'Save AI Settings'}
                </button>
            </div>
        </div>
    );
}

/**
 * AdAccountCard
 * 
 * Individual ad account display card with insights and actions.
 */
import { Facebook, Loader2, Trash2, RefreshCw, Pencil, AlertCircle } from 'lucide-react';
import { formatCurrency, formatCompact, formatNumber } from '../../utils/format';

interface AdAccount {
    id: string;
    platform: string;
    name: string;
    externalId: string;
}

interface AdInsights {
    spend: number;
    impressions: number;
    clicks: number;
    roas: number;
    currency: string;
}

interface AdAccountCardProps {
    account: AdAccount;
    insights?: AdInsights;
    isLoadingInsights: boolean;
    error?: string;
    onRefresh: () => void;
    onEdit: () => void;
    onDisconnect: () => void;
    onCompleteSetup: () => void;
    onReconnect: () => void;
}

/**
 * Google icon SVG component.
 */
function GoogleIcon({ className }: { className?: string }) {
    return (
        <svg className={className} viewBox="0 0 24 24" fill="currentColor">
            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
