/**
 * AdAccountSettings
 * 
 * Settings panel for managing ad account connections.
 * Includes edit functionality to fix broken connections without removing/re-adding.
 */
import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useAccountFeature } from '../../hooks/useAccountFeature';
import { Plus, Loader2 } from 'lucide-react';
import { AdAccountCard, AdAccount, AdInsights } from './AdAccountCard';
import { EditAdAccountModal, PendingSetupModal } from './AdAccountModals';
import { AdConnectForm } from './AdConnectForm';
import { Toast, ToastType } from '../ui/Toast';

export function AdAccountSettings() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const isMetaEnabled = useAccountFeature('META_ADS');
    const isGoogleEnabled = useAccountFeature('GOOGLE_ADS');

    const [accounts, setAccounts] = useState<AdAccount[]>([]);
    const [insights, setInsights] = useState<Record<string, AdInsights>>({});
    const [loadingInsights, setLoadingInsights] = useState<Record<string, boolean>>({});
    const [insightErrors, setInsightErrors] = useState<Record<string, string>>({});
    const [isLoading, setIsLoading] = useState(true);
    const [showConnect, setShowConnect] = useState(false);
    const [formPlatform, setFormPlatform] = useState('META');

    const [editingAccount, setEditingAccount] = useState<AdAccount | null>(null);
    const [editForm, setEditForm] = useState({ name: '', externalId: '', accessToken: '', refreshToken: '' });
    const [isSavingEdit, setIsSavingEdit] = useState(false);

    const [pendingSetup, setPendingSetup] = useState({ show: false, pendingId: '', customerId: '', isSubmitting: false });

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    useEffect(() => { fetchAccounts(); }, [currentAccount, token]);

    async function fetchAccounts() {
        if (!currentAccount) return;
        try {
            const res = await fetch('/api/ads', { headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id } });
            const data = await res.json();
            setAccounts(data);
            if (Array.isArray(data)) {
                data.forEach((acc: AdAccount) => { if (acc.externalId !== 'PENDING_SETUP') fetchInsights(acc.id); });
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    async function fetchInsights(adAccountId: string) {
        setLoadingInsights(prev => ({ ...prev, [adAccountId]: true }));
        setInsightErrors(prev => ({ ...prev, [adAccountId]: '' }));
        try {
            const res = await fetch(`/api/ads/${adAccountId}/insights`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount?.id || '' }
            });
            if (!res.ok) throw new Error(`Failed to load insights (${res.status})`);
            const data = await res.json();
            if (!data.error) setInsights(prev => ({ ...prev, [adAccountId]: data }));
            else setInsightErrors(prev => ({ ...prev, [adAccountId]: data.error }));
        } catch (err: any) {
            setInsightErrors(prev => ({ ...prev, [adAccountId]: err.message || 'Connection error' }));
            setInsights(prev => { const n = { ...prev }; delete n[adAccountId]; return n; });
        } finally {
            setLoadingInsights(prev => ({ ...prev, [adAccountId]: false }));
        }
    }

    async function handleGoogleOAuth(existingAccountId?: string) {
        if (!currentAccount) return;
        try {
            const params = new URLSearchParams({ redirect: '/settings?tab=ads', ...(existingAccountId && { reconnectId: existingAccountId }) });
            const res = await fetch(`/api/oauth/google/authorize?${params.toString()}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            if (data.authUrl) window.location.href = data.authUrl;
            else showToast('Failed to initiate Google OAuth');
        } catch { showToast('Error initiating Google OAuth'); }
    }

    async function handleMetaOAuth(existingAccountId?: string) {
        if (!currentAccount) return;
        try {
            const params = new URLSearchParams({ redirect: '/settings?tab=ads', ...(existingAccountId && { reconnectId: existingAccountId }) });
            const res = await fetch(`/api/oauth/meta/ads/authorize?${params.toString()}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            const data = await res.json();
            if (data.authUrl) window.location.href = data.authUrl;
            else showToast('Failed to initiate Meta OAuth');
        } catch { showToast('Error initiating Meta OAuth'); }
    }

    async function handleDisconnect(adAccountId: string) {
        if (!confirm('Are you sure you want to disconnect this ad account?')) return;
        try {
            const res = await fetch(`/api/ads/${adAccountId}`, {
                method: 'DELETE', headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount?.id || '' }
            });
            if (res.ok) { fetchAccounts(); showToast('Account disconnected', 'success'); } else showToast('Failed to disconnect');
        } catch { showToast('Error disconnecting account'); }
    }

    function openEditModal(account: AdAccount) {
        setEditingAccount(account);
        setEditForm({ name: account.name || '', externalId: account.externalId || '', accessToken: '', refreshToken: '' });
    }

    async function handleSaveEdit() {
        if (!editingAccount || !currentAccount) return;
        setIsSavingEdit(true);
        try {
            const payload: Record<string, string> = {};
            if (editForm.name && editForm.name !== editingAccount.name) payload.name = editForm.name;
            if (editForm.externalId && editForm.externalId !== editingAccount.externalId) payload.externalId = editForm.externalId;
            if (editForm.accessToken) payload.accessToken = editForm.accessToken;
            if (editForm.refreshToken) payload.refreshToken = editForm.refreshToken;
            if (Object.keys(payload).length === 0) { setEditingAccount(null); return; }

            const res = await fetch(`/api/ads/${editingAccount.id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id },
                body: JSON.stringify(payload)
            });
            if (res.ok) { setEditingAccount(null); fetchAccounts(); showToast('Account updated', 'success'); }
            else { const err = await res.json(); showToast(err.error || 'Failed to update'); }
        } catch { showToast('Error updating account'); }
        finally { setIsSavingEdit(false); }
    }

    async function handleCompletePendingSetup() {
        if (!currentAccount || !pendingSetup.customerId.trim()) return;
        setPendingSetup(prev => ({ ...prev, isSubmitting: true }));
        try {
            const res = await fetch(`/api/ads/${pendingSetup.pendingId}/complete-setup`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id },
                body: JSON.stringify({ customerId: pendingSetup.customerId.trim() })
            });
            if (res.ok) {
                showToast('Google Ads account configured successfully!', 'success');
                setPendingSetup({ show: false, pendingId: '', customerId: '', isSubmitting: false });
                fetchAccounts();
            } else { const err = await res.json(); showToast(err.error || 'Failed to complete setup'); }
        } catch { showToast('Error completing setup'); }
        finally { setPendingSetup(prev => ({ ...prev, isSubmitting: false })); }
    }

    // Handle OAuth callback
    useEffect(() => {
        const params = new URLSearchParams(window.location.search);
        const success = params.get('success');
        if (success === 'google_connected') { showToast('Google Ads account connected successfully!', 'success'); window.history.replaceState({}, '', '/settings?tab=ads'); fetchAccounts(); }
        else if (success === 'google_reconnected') { showToast('Google Ads account reconnected successfully!', 'success'); window.history.replaceState({}, '', '/settings?tab=ads'); fetchAccounts(); }
        else if (success === 'meta_ads_connected') { showToast('Meta Ads account connected successfully!', 'success'); window.history.replaceState({}, '', '/settings?tab=ads'); fetchAccounts(); }
        else if (success === 'meta_ads_reconnected') { showToast('Meta Ads account reconnected successfully!', 'success'); window.history.replaceState({}, '', '/settings?tab=ads'); fetchAccounts(); }
        else if (success === 'google_pending') {
            const pendingId = params.get('pendingId') || '';
            setPendingSetup({ show: true, pendingId, customerId: '', isSubmitting: false });
            window.history.replaceState({}, '', '/settings?tab=ads'); fetchAccounts();
        } else if (params.get('error')) {
            showToast(`OAuth Error: ${params.get('error')}${params.get('message') ? ` - ${params.get('message')}` : ''}`);
            window.history.replaceState({}, '', '/settings?tab=ads');
        }
    }, []);

    return (
        <div className="space-y-6">
            <EditAdAccountModal
                account={editingAccount}
                form={editForm}
                onFormChange={setEditForm}
                onClose={() => setEditingAccount(null)}
                onSave={handleSaveEdit}
                isSaving={isSavingEdit}
            />
            <PendingSetupModal
                isOpen={pendingSetup.show}
                pendingId={pendingSetup.pendingId}
                customerId={pendingSetup.customerId}
                isSubmitting={pendingSetup.isSubmitting}
                onCustomerIdChange={(v) => setPendingSetup(prev => ({ ...prev, customerId: v }))}
                onClose={() => setPendingSetup({ show: false, pendingId: '', customerId: '', isSubmitting: false })}
                onComplete={handleCompletePendingSetup}
                onCancel={() => { handleDisconnect(pendingSetup.pendingId); setPendingSetup({ show: false, pendingId: '', customerId: '', isSubmitting: false }); }}
            />

            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-lg font-semibold text-gray-900">Connected Ad Accounts</h2>
                    <p className="text-sm text-gray-500">Manage your Meta and Google Ads integrations</p>
                </div>
                <button onClick={() => setShowConnect(!showConnect)} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 text-sm">
                    <Plus size={16} />Connect Account
                </button>
            </div>

            {showConnect && (
                <AdConnectForm
                    platform={formPlatform}
                    onPlatformChange={setFormPlatform}
                    isMetaEnabled={isMetaEnabled}
                    isGoogleEnabled={isGoogleEnabled}
                    onGoogleOAuth={() => handleGoogleOAuth()}
                    onMetaOAuth={() => handleMetaOAuth()}
                />
            )}

            <div className="space-y-4">
                {isLoading ? (
                    <div className="text-center py-12"><Loader2 className="animate-spin inline text-gray-400" /></div>
                ) : accounts.length === 0 ? (
                    <div className="text-center py-12 text-gray-500 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                        No ad accounts connected. Click "Connect Account" to get started.
                    </div>
                ) : (
                    accounts.map(acc => (
                        <AdAccountCard
                            key={acc.id}
                            account={acc}
                            insights={insights[acc.id]}
                            isLoadingInsights={loadingInsights[acc.id] || false}
                            error={insightErrors[acc.id]}
                            onRefresh={() => fetchInsights(acc.id)}
                            onEdit={() => openEditModal(acc)}
                            onDisconnect={() => handleDisconnect(acc.id)}
                            onCompleteSetup={() => setPendingSetup({ show: true, pendingId: acc.id, customerId: '', isSubmitting: false })}
                            onReconnect={() => acc.platform === 'GOOGLE' ? handleGoogleOAuth(acc.id) : handleMetaOAuth(acc.id)}
                        />
                    ))
                )}
            </div>

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Palette, Check, RefreshCw } from 'lucide-react';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';

export function AppearanceSettings() {
    const { currentAccount, refreshAccounts } = useAccount();
    const { token } = useAuth();
    const [isSaving, setIsSaving] = useState(false);

    // Default appearance settings
    const [settings, setSettings] = useState({
        appName: 'OverSeek',
        primaryColor: '#2563eb', // Default blue-600
        logoUrl: ''
    });

    useEffect(() => {
        if (currentAccount?.appearance) {
            const app = currentAccount.appearance as any;
            setSettings({
                appName: app.appName || 'OverSeek',
                primaryColor: app.primaryColor || '#2563eb',
                logoUrl: app.logoUrl || ''
            });
        }
    }, [currentAccount]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setSettings({ ...settings, [e.target.name]: e.target.value });
    };

    const handleSave = async () => {
        if (!currentAccount || !token) return;
        setIsSaving(true);
        try {
            const res = await fetch(`/api/accounts/${currentAccount.id}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({
                    appearance: settings
                })
            });

            if (!res.ok) throw new Error('Failed to update appearance');

            await refreshAccounts();
            alert('Appearance settings saved successfully');
        } catch (error) {
            Logger.error('An error occurred', { error: error });
            alert('Failed to save appearance settings');
        } finally {
            setIsSaving(false);
        }
    };

    const handleReset = () => {
        setSettings({
            appName: 'OverSeek',
            primaryColor: '#2563eb',
            logoUrl: ''
        });
    };

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Application Name</label>
                    <input
                        type="text"
                        name="appName"
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                        value={settings.appName}
                        onChange={handleChange}
                        placeholder="OverSeek"
                    />
                    <p className="text-xs text-gray-500 mt-1">Replaces "OverSeek" in the sidebar and browser title.</p>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Primary Color</label>
                    <div className="flex items-center gap-3">
                        <input
                            type="color"
                            name="primaryColor"
                            value={settings.primaryColor}
                            onChange={handleChange}
                            className="h-10 w-20 p-1 border border-gray-300 rounded-sm cursor-pointer"
                        />
                        <input
                            type="text"
                            name="primaryColor"
                            value={settings.primaryColor}
                            onChange={handleChange}
                            className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden font-mono uppercase"
                        />
                    </div>
                    <p className="text-xs text-gray-500 mt-1">Main brand color used for buttons and highlights.</p>
                </div>

                <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-gray-700 mb-1">Custom Logo URL</label>
                    <input
                        type="url"
                        name="logoUrl"
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                        value={settings.logoUrl}
                        onChange={handleChange}
                        placeholder="https://example.com/logo.png"
                    />
                    <p className="text-xs text-gray-500 mt-1">Enter a direct URL to your logo image (PNG/SVG recommended). Leave empty to use default.</p>
                </div>
            </div>

            <div className="flex justify-between items-center pt-4 border-t border-gray-100">
                <button
                    onClick={handleReset}
                    className="text-sm text-gray-500 hover:text-gray-700 flex items-center gap-1"
                >
                    <RefreshCw size={14} /> Reset to Default
                </button>

                <button
                    onClick={handleSave}
                    disabled={isSaving}
                    className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium disabled:opacity-50"
                    style={{ backgroundColor: settings.primaryColor }} // Instant preview
                >
                    {isSaving ? <RefreshCw size={18} className="animate-spin" /> : <Check size={18} />}
                    {isSaving ? 'Saving...' : 'Save Appearance'}
                </button>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { Server, CheckCircle, XCircle, Loader2, Save, ChevronDown, ChevronUp, Send, Inbox, Globe } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

/**
 * Unified Email Account - combines SMTP and IMAP in one record.
 */
export interface EmailAccount {
    id: string;
    accountId: string;
    name: string;
    email: string;
    // SMTP
    smtpEnabled: boolean;
    smtpHost?: string;
    smtpPort?: number;
    smtpUsername?: string;
    smtpPassword?: string;
    smtpSecure?: boolean;
    // IMAP
    imapEnabled: boolean;
    imapHost?: string;
    imapPort?: number;
    imapUsername?: string;
    imapPassword?: string;
    imapSecure?: boolean;
    // HTTP Relay (WooCommerce Plugin)
    relayEndpoint?: string;
    relayApiKey?: string;
    // Meta
    isDefault?: boolean;
}

interface EmailAccountFormProps {
    initialData: Partial<EmailAccount>;
    onSave: (data: Partial<EmailAccount>) => Promise<void>;
    onCancel: () => void;
    onTest: (data: { protocol: 'SMTP' | 'IMAP'; host: string; port: number; username: string; password: string; isSecure: boolean; id?: string }) => Promise<{ success: boolean; message?: string }>;
    isSaving: boolean;
    isTesting: boolean;
    testResult: { success: boolean; message?: string } | null;
}

export function EmailAccountForm({
    initialData,
    onSave,
    onCancel,
    onTest,
    isSaving,
    isTesting,
    testResult
}: EmailAccountFormProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [formData, setFormData] = useState<Partial<EmailAccount>>({
        smtpEnabled: false,
        imapEnabled: false,
        smtpSecure: true,
        imapSecure: true,
        smtpPort: 587,
        imapPort: 993,
        ...initialData
    });
    const [smtpExpanded, setSmtpExpanded] = useState(formData.smtpEnabled);
    const [imapExpanded, setImapExpanded] = useState(formData.imapEnabled);
    const [relayExpanded, setRelayExpanded] = useState(!!formData.relayEndpoint);
    const [testingProtocol, setTestingProtocol] = useState<'SMTP' | 'IMAP' | null>(null);

    // Determine if using relay (endpoint configured) or SMTP
    const useRelay = !!formData.relayEndpoint;

    const handleChange = (field: keyof EmailAccount, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleTestConnection = async (protocol: 'SMTP' | 'IMAP') => {
        setTestingProtocol(protocol);
        const isSmtp = protocol === 'SMTP';
        await onTest({
            protocol,
            id: formData.id,
            host: (isSmtp ? formData.smtpHost : formData.imapHost) || '',
            port: (isSmtp ? formData.smtpPort : formData.imapPort) || (isSmtp ? 587 : 993),
            username: (isSmtp ? formData.smtpUsername : formData.imapUsername) || formData.email || '',
            password: (isSmtp ? formData.smtpPassword : formData.imapPassword) || '',
            isSecure: (isSmtp ? formData.smtpSecure : formData.imapSecure) ?? true
        });
        setTestingProtocol(null);
    };

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
            <div className="p-6 border-b border-gray-200 flex justify-between items-center">
                <h2 className="text-lg font-medium text-gray-900">
                    {formData.id ? 'Edit Email Account' : 'New Email Account'}
                </h2>
                <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">
                    <XCircle size={24} />
                </button>
            </div>

            <div className="p-6 space-y-6">
                {/* Basic Info */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Account Name</label>
                        <input
                            type="text"
                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                            placeholder="e.g. Support Inbox"
                            value={formData.name || ''}
                            onChange={(e) => handleChange('name', e.target.value)}
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
                        <input
                            type="email"
                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                            placeholder="support@example.com"
                            value={formData.email || ''}
                            onChange={(e) => handleChange('email', e.target.value)}
                        />
                    </div>
                </div>

                {/* Outgoing Email Section - with Mode Toggle */}
                <div className="border border-gray-200 rounded-xl overflow-hidden">
                    <button
                        type="button"
                        onClick={() => setSmtpExpanded(!smtpExpanded)}
                        className="w-full flex items-center justify-between p-4 bg-gray-50 hover:bg-gray-100 transition-colors"
                    >
                        <div className="flex items-center gap-3">
                            <div className={`p-2 rounded-lg ${(formData.smtpEnabled || formData.relayEndpoint) ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                                <Send size={18} />
                            </div>
                            <div className="text-left">
                                <h3 className="font-medium text-gray-900">Outgoing Email</h3>
                                <p className="text-sm text-gray-500">
                                    {formData.relayEndpoint ? 'Via WooCommerce Relay' : formData.smtpEnabled ? 'Via SMTP Server' : 'Not configured'}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-3">
                            {(formData.smtpEnabled || formData.relayEndpoint) && (
                                <span className={`text-xs px-2 py-1 rounded-full ${formData.relayEndpoint ? 'bg-purple-100 text-purple-700' : 'bg-green-100 text-green-700'}`}>
                                    {formData.relayEndpoint ? 'Relay' : 'SMTP'}
                                </span>
                            )}
                            {smtpExpanded ? <ChevronUp size={20} className="text-gray-400" /> : <ChevronDown size={20} className="text-gray-400" />}
                        </div>
                    </button>

                    {smtpExpanded && (
                        <div className="p-4 space-y-4 border-t border-gray-200">
                            {/* Send Method Toggle */}
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-2">Send Method</label>
                                <div className="flex gap-2">
                                    <button
                                        type="button"
                                        onClick={() => {
                                            handleChange('smtpEnabled', true);
                                            handleChange('relayEndpoint', '');
                                            handleChange('relayApiKey', '');
                                        }}
                                        className={`flex-1 py-3 px-4 rounded-lg border-2 transition-all ${formData.smtpEnabled && !formData.relayEndpoint
                                            ? 'border-blue-500 bg-blue-50 text-blue-700'
                                            : 'border-gray-200 bg-white text-gray-600 hover:border-gray-300'
                                            }`}
                                    >
                                        <div className="flex items-center justify-center gap-2">
                                            <Server size={18} />
                                            <span className="font-medium">SMTP Server</span>
                                        </div>
                                        <p className="text-xs mt-1 opacity-75">Direct connection</p>
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => {
                                            handleChange('smtpEnabled', false);
                                            setRelayExpanded(true);
                                        }}
                                        className={`flex-1 py-3 px-4 rounded-lg border-2 transition-all ${formData.relayEndpoint
                                            ? 'border-purple-500 bg-purple-50 text-purple-700'
                                            : !formData.smtpEnabled && !formData.relayEndpoint
                                                ? 'border-gray-300 bg-gray-50 text-gray-600'
                                                : 'border-gray-200 bg-white text-gray-600 hover:border-gray-300'
                                            }`}
                                    >
                                        <div className="flex items-center justify-center gap-2">
                                            <Globe size={18} />
                                            <span className="font-medium">WooCommerce Relay</span>
                                        </div>
                                        <p className="text-xs mt-1 opacity-75">Via WordPress plugin</p>
                                    </button>
                                </div>
                            </div>

                            {/* SMTP Fields - shown when SMTP is selected */}
                            {formData.smtpEnabled && !formData.relayEndpoint && (
                                <div className="space-y-4 pt-2">
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        <div className="md:col-span-2">
                                            <label className="block text-sm font-medium text-gray-700 mb-1">SMTP Host</label>
                                            <input
                                                type="text"
                                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                                placeholder="smtp.gmail.com"
                                                value={formData.smtpHost || ''}
                                                onChange={(e) => handleChange('smtpHost', e.target.value)}
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Port</label>
                                            <input
                                                type="number"
                                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                                placeholder="587"
                                                value={formData.smtpPort || ''}
                                                onChange={(e) => handleChange('smtpPort', parseInt(e.target.value))}
                                            />
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Username</label>
                                            <input
                                                type="text"
                                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                                placeholder="Same as email if blank"
                                                value={formData.smtpUsername || ''}
                                                onChange={(e) => handleChange('smtpUsername', e.target.value)}
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                                            <input
                                                type="password"
                                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                                placeholder="••••••••"
                                                value={formData.smtpPassword || ''}
                                                onChange={(e) => handleChange('smtpPassword', e.target.value)}
                                            />
                                        </div>
                                    </div>
                                    <div className="flex items-center justify-between">
                                        <label className="flex items-center gap-2">
                                            <input
                                                type="checkbox"
                                                checked={formData.smtpSecure ?? true}
                                                onChange={(e) => handleChange('smtpSecure', e.target.checked)}
                                                className="rounded border-gray-300 text-blue-600"
                                            />
                                            <span className="text-sm text-gray-700">Use TLS/SSL</span>
                                        </label>
                                        <button
                                            type="button"
                                            onClick={() => handleTestConnection('SMTP')}
                                            disabled={isTesting || !formData.smtpHost}
                                            className="text-sm text-blue-600 hover:text-blue-700 disabled:opacity-50"
                                        >
                                            {testingProtocol === 'SMTP' ? 'Testing...' : 'Test Connection'}
                                        </button>
                                    </div>
                                </div>
                            )}

                            {/* WooCommerce Relay Fields - shown when Relay is selected */}
                            {(!formData.smtpEnabled || formData.relayEndpoint) && (
                                <div className="space-y-4 pt-2">
                                    <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 text-sm text-blue-800">
                                        <strong>How it works:</strong> Emails are sent via your WooCommerce store's WordPress plugin instead of direct SMTP.
                                        Use this if your server blocks outbound SMTP ports (e.g., DigitalOcean).
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Relay Endpoint URL</label>
                                        <input
                                            type="url"
                                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-hidden"
                                            placeholder="https://yourstore.com/wp-json/overseek/v1/email-relay"
                                            value={formData.relayEndpoint || ''}
                                            onChange={(e) => handleChange('relayEndpoint', e.target.value)}
                                        />
                                        <p className="text-xs text-gray-500 mt-1">Found in WordPress: WooCommerce → OverSeek → Email Relay Settings</p>
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700 mb-1">Relay API Key</label>
                                        <input
                                            type="password"
                                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-hidden"
                                            placeholder="••••••••"
                                            value={formData.relayApiKey || ''}
                                            onChange={(e) => handleChange('relayApiKey', e.target.value)}
                                        />
                                        <p className="text-xs text-gray-500 mt-1">Must match the key set in your WordPress plugin</p>
                                    </div>
                                    <div className="flex items-center justify-between">
                                        <div></div>
                                        <button
                                            type="button"
                                            onClick={async () => {
                                                if (!formData.relayEndpoint || !formData.relayApiKey) return;
                                                try {
                                                    const response = await fetch('/api/email/test-relay', {
                                                        method: 'POST',
                                                        headers: {
                                                            'Content-Type': 'application/json',
                                                            'Authorization': `Bearer ${token}`,
                                                            'x-account-id': currentAccount?.id || ''
                                                        },
                                                        body: JSON.stringify({
                                                            relayEndpoint: formData.relayEndpoint,
                                                            relayApiKey: formData.relayApiKey,
                                                            emailAccountId: formData.id
                                                        })
                                                    });
                                                    const result = await response.json();
                                                    if (result.success) {
                                                        alert('✓ ' + result.message);
                                                    } else {
                                                        alert('✗ ' + (result.error || 'Unknown error'));
                                                    }
                                                } catch (err: any) {
                                                    alert('Cannot test relay: ' + err.message);
                                                }
                                            }}
                                            disabled={!formData.relayEndpoint || !formData.relayApiKey}
                                            className="text-sm text-purple-600 hover:text-purple-700 disabled:opacity-50"
                                        >
                                            Test Relay Connection
                                        </button>
                                    </div>
                                    {formData.relayEndpoint && formData.relayApiKey && (
                                        <div className="flex items-center gap-2 text-sm text-green-700 bg-green-50 p-3 rounded-lg">
                                            <CheckCircle size={16} />
                                            <span>Relay configured. Emails will be sent via WooCommerce.</span>
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    )}
                </div>


                {/* IMAP Section */}
                <div className="border border-gray-200 rounded-xl overflow-hidden">
                    <button
                        type="button"
                        onClick={() => setImapExpanded(!imapExpanded)}
                        className="w-full flex items-center justify-between p-4 bg-gray-50 hover:bg-gray-100 transition-colors"
                    >
                        <div className="flex items-center gap-3">
                            <div className={`p-2 rounded-lg ${formData.imapEnabled ? 'bg-blue-100 text-blue-600' : 'bg-gray-100 text-gray-400'}`}>
                                <Inbox size={18} />
                            </div>
                            <div className="text-left">
                                <h3 className="font-medium text-gray-900">Incoming (IMAP)</h3>
                                <p className="text-sm text-gray-500">For receiving emails</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-3">
                            <label className="flex items-center gap-2" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    checked={formData.imapEnabled}
                                    onChange={(e) => {
                                        handleChange('imapEnabled', e.target.checked);
                                        if (e.target.checked) setImapExpanded(true);
                                    }}
                                    className="rounded border-gray-300 text-blue-600"
                                />
                                <span className="text-sm text-gray-600">Enable</span>
                            </label>
                            {imapExpanded ? <ChevronUp size={20} className="text-gray-400" /> : <ChevronDown size={20} className="text-gray-400" />}
                        </div>
                    </button>

                    {imapExpanded && (
                        <div className="p-4 space-y-4 border-t border-gray-200">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <div className="md:col-span-2">
                                    <label className="block text-sm font-medium text-gray-700 mb-1">IMAP Host</label>
                                    <input
                                        type="text"
                                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                        placeholder="imap.gmail.com"
                                        value={formData.imapHost || ''}
                                        onChange={(e) => handleChange('imapHost', e.target.value)}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Port</label>
                                    <input
                                        type="number"
                                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                        placeholder="993"
                                        value={formData.imapPort || ''}
                                        onChange={(e) => handleChange('imapPort', parseInt(e.target.value))}
                                    />
                                </div>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Username</label>
                                    <input
                                        type="text"
                                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                        placeholder="Same as email if blank"
                                        value={formData.imapUsername || ''}
                                        onChange={(e) => handleChange('imapUsername', e.target.value)}
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                                    <input
                                        type="password"
                                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                                        placeholder="••••••••"
                                        value={formData.imapPassword || ''}
                                        onChange={(e) => handleChange('imapPassword', e.target.value)}
                                    />
                                </div>
                            </div>
                            <div className="flex items-center justify-between">
                                <label className="flex items-center gap-2">
                                    <input
                                        type="checkbox"
                                        checked={formData.imapSecure ?? true}
                                        onChange={(e) => handleChange('imapSecure', e.target.checked)}
                                        className="rounded border-gray-300 text-blue-600"
                                    />
                                    <span className="text-sm text-gray-700">Use TLS/SSL</span>
                                </label>
                                <button
                                    type="button"
                                    onClick={() => handleTestConnection('IMAP')}
                                    disabled={isTesting || !formData.imapHost}
                                    className="text-sm text-blue-600 hover:text-blue-700 disabled:opacity-50"
                                >
                                    {testingProtocol === 'IMAP' ? 'Testing...' : 'Test IMAP'}
                                </button>
                            </div>
                        </div>
                    )}
                </div>

                {/* Test Results */}
                {testResult && (
                    <div className={`p-4 rounded-lg flex items-center gap-3 ${testResult.success ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {testResult.success ? <CheckCircle size={20} /> : <XCircle size={20} />}
                        <span className="text-sm font-medium">{testResult.success ? 'Connection Successful!' : `Connection Failed: ${testResult.message}`}</span>
                    </div>
                )}

                {/* Footer */}
                <div className="bg-gray-50 -mx-6 -mb-6 px-6 py-4 flex justify-between items-center rounded-b-xl border-t border-gray-100 mt-6">
                    <div className="text-sm text-gray-500">
                        {!formData.smtpEnabled && !formData.imapEnabled && !formData.relayEndpoint && 'Configure outgoing email or receiving'}
                    </div>
                    <div className="flex gap-3">
                        <button
                            onClick={onCancel}
                            className="px-4 py-2 text-gray-700 hover:text-gray-900 font-medium"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={() => onSave(formData)}
                            disabled={isSaving || (!formData.smtpEnabled && !formData.imapEnabled && !formData.relayEndpoint)}
                            className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium disabled:opacity-50"
                        >
                            {isSaving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                            {isSaving ? 'Saving...' : 'Save Account'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { CheckCircle, XCircle, ChevronDown, ChevronUp, RefreshCw, Mail } from 'lucide-react';

interface EmailLog {
    id: string;
    to: string;
    subject: string;
    status: 'SUCCESS' | 'FAILED';
    errorMessage?: string;
    errorCode?: string;
    source?: string;
    sourceId?: string;
    messageId?: string;
    createdAt: string;
    emailAccount?: {
        name: string;
        email: string;
    };
}

interface EmailLogsResponse {
    logs: EmailLog[];
    total: number;
    limit: number;
    offset: number;
}

export function EmailLogPanel() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [logs, setLogs] = useState<EmailLog[]>([]);
    const [total, setTotal] = useState(0);
    const [isLoading, setIsLoading] = useState(true);
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [offset, setOffset] = useState(0);
    const limit = 20;

    const fetchLogs = async () => {
        if (!currentAccount || !token) return;
        setIsLoading(true);

        try {
            const res = await fetch(`/api/email/logs?limit=${limit}&offset=${offset}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });

            if (res.ok) {
                const data: EmailLogsResponse = await res.json();
                setLogs(data.logs);
                setTotal(data.total);
            }
        } catch (error) {
            Logger.error('Failed to fetch email logs:', { error: error });
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchLogs();
    }, [currentAccount, token, offset]);

    const formatDate = (dateStr: string) => {
        const date = new Date(dateStr);
        return date.toLocaleString();
    };

    const getSourceLabel = (source?: string) => {
        if (!source) return null;
        const labels: Record<string, string> = {
            'AUTOMATION': 'Automation',
            'REPORT': 'Scheduled Report',
            'INVENTORY_ALERT': 'Inventory Alert',
            'MANUAL': 'Manual'
        };
        return labels[source] || source;
    };

    const totalPages = Math.ceil(total / limit);
    const currentPage = Math.floor(offset / limit) + 1;

    if (isLoading && logs.length === 0) {
        return (
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-6">
                <div className="flex items-center gap-2 text-gray-500">
                    <RefreshCw size={16} className="animate-spin" />
                    <span>Loading email logs...</span>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200">
            {/* Header */}
            <div className="px-4 py-3 border-b border-gray-200 flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <Mail size={18} className="text-gray-500" />
                    <h3 className="font-medium text-gray-900">Email Logs</h3>
                    <span className="text-sm text-gray-500">({total} total)</span>
                </div>
                <button
                    onClick={fetchLogs}
                    disabled={isLoading}
                    className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                    title="Refresh"
                >
                    <RefreshCw size={16} className={isLoading ? 'animate-spin' : ''} />
                </button>
            </div>

            {/* Logs Table */}
            {logs.length === 0 ? (
                <div className="p-6 text-center text-gray-500">
                    <Mail size={32} className="mx-auto mb-2 opacity-50" />
                    <p>No email logs yet</p>
                    <p className="text-sm">Sent emails will appear here</p>
                </div>
            ) : (
                <div className="divide-y divide-gray-100">
                    {logs.map((log) => (
                        <div key={log.id} className="hover:bg-gray-50 transition-colors">
                            {/* Main Row */}
                            <div
                                className="px-4 py-3 flex items-center gap-4 cursor-pointer"
                                onClick={() => setExpandedId(expandedId === log.id ? null : log.id)}
                            >
                                {/* Status Icon */}
                                {log.status === 'SUCCESS' ? (
                                    <CheckCircle size={18} className="text-green-500 flex-shrink-0" />
                                ) : (
                                    <XCircle size={18} className="text-red-500 flex-shrink-0" />
                                )}

                                {/* Content */}
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-2">
                                        <span className="font-medium text-gray-900 truncate">
                                            {log.to}
                                        </span>
                                        {log.source && (
                                            <span className="text-xs px-2 py-0.5 bg-gray-100 text-gray-600 rounded">
                                                {getSourceLabel(log.source)}
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-sm text-gray-500 truncate">{log.subject}</p>
                                </div>

                                {/* Timestamp */}
                                <span className="text-xs text-gray-400 flex-shrink-0">
                                    {formatDate(log.createdAt)}
                                </span>

                                {/* Expand Icon */}
                                {expandedId === log.id ? (
                                    <ChevronUp size={16} className="text-gray-400" />
                                ) : (
                                    <ChevronDown size={16} className="text-gray-400" />
                                )}
                            </div>

                            {/* Expanded Details */}
                            {expandedId === log.id && (
                                <div className="px-4 pb-4 pt-1 bg-gray-50 border-t border-gray-100">
                                    <div className="grid grid-cols-2 gap-4 text-sm">
                                        <div>
                                            <span className="text-gray-500">From Account:</span>
                                            <p className="font-medium">
                                                {log.emailAccount?.name || 'Unknown'} ({log.emailAccount?.email || 'N/A'})
                                            </p>
                                        </div>
                                        <div>
                                            <span className="text-gray-500">Status:</span>
                                            <p className={`font-medium ${log.status === 'SUCCESS' ? 'text-green-600' : 'text-red-600'}`}>
                                                {log.status}
                                            </p>
                                        </div>
                                        {log.messageId && (
                                            <div className="col-span-2">
                                                <span className="text-gray-500">Message ID:</span>
                                                <p className="font-mono text-xs break-all">{log.messageId}</p>
                                            </div>
                                        )}
                                        {log.errorMessage && (
                                            <div className="col-span-2">
                                                <span className="text-gray-500">Error:</span>
                                                <div className="mt-1 p-2 bg-red-50 border border-red-200 rounded text-red-700">
                                                    {log.errorCode && (
                                                        <span className="font-mono text-xs mr-2">[{log.errorCode}]</span>
                                                    )}
                                                    {log.errorMessage}
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="px-4 py-3 border-t border-gray-200 flex items-center justify-between">
                    <span className="text-sm text-gray-500">
                        Page {currentPage} of {totalPages}
                    </span>
                    <div className="flex gap-2">
                        <button
                            onClick={() => setOffset(Math.max(0, offset - limit))}
                            disabled={offset === 0}
                            className="px-3 py-1 text-sm border border-gray-300 rounded hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            Previous
                        </button>
                        <button
                            onClick={() => setOffset(offset + limit)}
                            disabled={offset + limit >= total}
                            className="px-3 py-1 text-sm border border-gray-300 rounded hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            Next
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Save, Loader2, Mail, AlertTriangle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

export function InventoryAlertsSettings() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    const [isEnabled, setIsEnabled] = useState(false);
    const [threshold, setThreshold] = useState(14);
    const [emailInput, setEmailInput] = useState('');
    const [emails, setEmails] = useState<string[]>([]);

    useEffect(() => {
        if (!currentAccount) return;
        fetchSettings();
    }, [currentAccount, token]);

    const fetchSettings = async () => {
        try {
            // Need a backend endpoint for settings. 
            // Assuming GET /api/inventory/settings
            const res = await fetch('/api/inventory/settings', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount!.id }
            });
            if (res.ok) {
                const data = await res.json();
                setIsEnabled(data.isEnabled || false);
                setThreshold(data.lowStockThresholdDays || 14);
                setEmails(data.alertEmails || []);
            }
        } catch (error) {
            Logger.error('An error occurred', { error: error });
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        if (!currentAccount) return;
        setIsSaving(true);
        try {
            const res = await fetch('/api/inventory/settings', {
                method: 'POST', // or PUT
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                },
                body: JSON.stringify({
                    isEnabled,
                    lowStockThresholdDays: Number(threshold),
                    alertEmails: emails
                })
            });
            if (!res.ok) throw new Error('Failed to save');
            alert('Settings saved successfully');
        } catch (error) {
            Logger.error('An error occurred', { error: error });
            alert('Failed to save settings');
        } finally {
            setIsSaving(false);
        }
    };

    const addEmail = () => {
        if (emailInput && !emails.includes(emailInput)) {
            setEmails([...emails, emailInput]);
            setEmailInput('');
        }
    };

    const removeEmail = (email: string) => {
        setEmails(emails.filter(e => e !== email));
    };

    if (isLoading) return <div className="p-4 text-center">Loading...</div>;

    return (
        <div className="space-y-6 max-w-2xl">
            <div className="flex items-center justify-between">
                <div>
                    <h3 className="text-lg font-medium text-gray-900">Low Stock Alerts</h3>
                    <p className="text-sm text-gray-500">Get notified when products are running low based on sales velocity.</p>
                </div>
                <label className="relative inline-flex items-center cursor-pointer">
                    <input type="checkbox" checked={isEnabled} onChange={e => setIsEnabled(e.target.checked)} className="sr-only peer" />
                    <div className="w-11 h-6 bg-gray-200 peer-focus:outline-hidden peer-focus:ring-4 peer-focus:ring-blue-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
                </label>
            </div>

            {isEnabled && (
                <div className="space-y-6 animate-in fade-in slide-in-from-top-2">
                    <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 flex gap-3">
                        <AlertTriangle className="text-amber-600 shrink-0" size={20} />
                        <p className="text-sm text-amber-800">
                            We calculate "Days Remaining" by dividing current stock by the average daily sales over the last 30 days.
                        </p>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                            Alert Threshold (Days)
                        </label>
                        <div className="flex items-center gap-2">
                            <input
                                type="number"
                                value={threshold}
                                onChange={e => setThreshold(Number(e.target.value))}
                                className="w-24 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-hidden"
                            />
                            <span className="text-gray-500">days remaining</span>
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                            Email Recipients
                        </label>
                        <div className="flex gap-2 mb-2">
                            <input
                                type="email"
                                value={emailInput}
                                onChange={e => setEmailInput(e.target.value)}
                                placeholder="colleague@example.com"
                                className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-hidden"
                                onKeyDown={e => e.key === 'Enter' && addEmail()}
                            />
                            <button
                                onClick={addEmail}
                                type="button"
                                className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200"
                            >
                                Add
                            </button>
                        </div>
                        <div className="space-y-2">
                            {emails.map(email => (
                                <div key={email} className="flex items-center justify-between bg-white border border-gray-200 rounded-lg px-3 py-2">
                                    <div className="flex items-center gap-2 text-sm text-gray-700">
                                        <Mail size={16} className="text-gray-400" />
                                        {email}
                                    </div>
                                    <button onClick={() => removeEmail(email)} className="text-red-500 hover:text-red-700 text-sm">
                                        Remove
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            <div className="pt-4 border-t border-gray-200">
                <button
                    onClick={handleSave}
                    disabled={isSaving}
                    className="flex items-center gap-2 px-6 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 shadow-md shadow-blue-500/20 disabled:opacity-50 transition-all"
                >
                    {isSaving ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                    Save Settings
                </button>
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Loader2, Save, Tag, Plus, X, ChevronDown, Search } from 'lucide-react';

interface TagMapping {
    productTag: string;
    orderTag: string;
    enabled: boolean;
    color?: string;  // Hex color for display (e.g. "#3B82F6")
}

/**
 * Settings component for configuring product tag to order tag mappings.
 * Compact UI: shows only added mappings with an "Add" button to add more.
 */
export function OrderTagSettings() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [productTags, setProductTags] = useState<string[]>([]);
    const [mappings, setMappings] = useState<TagMapping[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    // Add tag dropdown state
    const [showAddDropdown, setShowAddDropdown] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!currentAccount || !token) return;
        loadData();
    }, [currentAccount, token]);

    // Close dropdown on outside click
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setShowAddDropdown(false);
                setSearchQuery('');
            }
        }
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    async function loadData() {
        if (!currentAccount || !token) return;
        setIsLoading(true);

        try {
            const [tagsRes, mappingsRes] = await Promise.all([
                fetch(`/api/accounts/${currentAccount.id}/product-tags`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                }),
                fetch(`/api/accounts/${currentAccount.id}/tag-mappings`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                })
            ]);

            const tagsData = await tagsRes.json();
            const mappingsData = await mappingsRes.json();

            setProductTags(tagsData.tags || []);
            setMappings(mappingsData.mappings || []);
        } catch (error) {
            Logger.error('Failed to load tag settings', { error: error });
        } finally {
            setIsLoading(false);
        }
    }

    /** Product tags not yet added as mappings */
    function getAvailableTags(): string[] {
        const mappedTags = new Set(mappings.map(m => m.productTag.toLowerCase()));
        return productTags.filter(tag => !mappedTags.has(tag.toLowerCase()));
    }

    /** Filtered available tags based on search */
    function getFilteredAvailableTags(): string[] {
        const available = getAvailableTags();
        if (!searchQuery.trim()) return available;
        return available.filter(tag =>
            tag.toLowerCase().includes(searchQuery.toLowerCase())
        );
    }

    function addTagMapping(productTag: string) {
        setMappings(prev => [
            ...prev,
            { productTag, orderTag: productTag, enabled: true, color: '#3B82F6' }
        ]);
        setShowAddDropdown(false);
        setSearchQuery('');
    }

    function removeTagMapping(productTag: string) {
        setMappings(prev => prev.filter(m => m.productTag.toLowerCase() !== productTag.toLowerCase()));
    }

    function updateMapping(productTag: string, updates: Partial<TagMapping>) {
        setMappings(prev => prev.map(m =>
            m.productTag.toLowerCase() === productTag.toLowerCase()
                ? { ...m, ...updates }
                : m
        ));
    }

    async function handleSave() {
        if (!currentAccount || !token) return;
        setIsSaving(true);
        setMessage(null);

        try {
            const res = await fetch(`/api/accounts/${currentAccount.id}/tag-mappings`, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ mappings })
            });

            if (res.ok) {
                setMessage({ type: 'success', text: 'Tag mappings saved! Re-sync orders to apply changes.' });
            } else {
                throw new Error('Save failed');
            }
        } catch (error) {
            setMessage({ type: 'error', text: 'Failed to save tag mappings' });
        } finally {
            setIsSaving(false);
        }
    }

    if (isLoading) {
        return (
            <div className="flex items-center justify-center p-8">
                <Loader2 className="animate-spin text-blue-600" size={24} />
            </div>
        );
    }

    const availableTags = getFilteredAvailableTags();
    const hasUnmappedTags = getAvailableTags().length > 0;

    return (
        <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
            <div className="p-6 border-b border-gray-200">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <Tag className="text-blue-600" size={20} />
                        <div>
                            <h2 className="text-lg font-medium text-gray-900">Order Tag Mappings</h2>
                            <p className="text-sm text-gray-500 mt-1">
                                Configure which product tags should be applied to orders.
                            </p>
                        </div>
                    </div>

                    {/* Add Tag Button with Dropdown */}
                    {hasUnmappedTags && (
                        <div className="relative" ref={dropdownRef}>
                            <button
                                onClick={() => setShowAddDropdown(!showAddDropdown)}
                                className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors text-sm"
                            >
                                <Plus size={16} />
                                Add Tag
                                <ChevronDown size={14} className={`transition-transform ${showAddDropdown ? 'rotate-180' : ''}`} />
                            </button>

                            {showAddDropdown && (
                                <div className="absolute right-0 mt-2 w-72 bg-white rounded-lg shadow-lg border border-gray-200 z-50">
                                    {/* Search input */}
                                    <div className="p-2 border-b border-gray-100">
                                        <div className="relative">
                                            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                                            <input
                                                type="text"
                                                placeholder="Search tags..."
                                                value={searchQuery}
                                                onChange={(e) => setSearchQuery(e.target.value)}
                                                className="w-full pl-9 pr-3 py-2 text-sm border border-gray-200 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                                autoFocus
                                            />
                                        </div>
                                    </div>

                                    {/* Tag list */}
                                    <div className="max-h-60 overflow-y-auto py-1">
                                        {availableTags.length === 0 ? (
                                            <div className="px-4 py-3 text-sm text-gray-500 text-center">
                                                {searchQuery ? 'No matching tags' : 'All tags have been added'}
                                            </div>
                                        ) : (
                                            availableTags.map(tag => (
                                                <button
                                                    key={tag}
                                                    onClick={() => addTagMapping(tag)}
                                                    className="w-full text-left px-4 py-2 text-sm hover:bg-blue-50 flex items-center gap-2 transition-colors"
                                                >
                                                    <Tag size={14} className="text-gray-400" />
                                                    <span className="truncate">{tag}</span>
                                                </button>
                                            ))
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            <div className="p-6">
                {mappings.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                        <Tag size={32} className="mx-auto mb-2 opacity-50" />
                        <p className="font-medium">No tag mappings configured</p>
                        <p className="text-sm mt-1">
                            {productTags.length > 0
                                ? 'Click "Add Tag" to map product tags to order tags.'
                                : 'Sync your products to see available tags.'}
                        </p>
                    </div>
                ) : (
                    <div className="space-y-3">
                        {/* Header */}
                        <div className="grid grid-cols-12 gap-4 text-xs font-semibold text-gray-500 uppercase px-2">
                            <div className="col-span-1">Active</div>
                            <div className="col-span-3">Product Tag</div>
                            <div className="col-span-1 text-center">→</div>
                            <div className="col-span-4">Order Tag Name</div>
                            <div className="col-span-2">Color</div>
                            <div className="col-span-1"></div>
                        </div>

                        {/* Mapping rows */}
                        {mappings.map(mapping => (
                            <div
                                key={mapping.productTag}
                                className={`grid grid-cols-12 gap-4 items-center p-3 rounded-lg border transition-colors ${mapping.enabled ? 'border-blue-200 bg-blue-50/50' : 'border-gray-200 bg-gray-50/50'
                                    }`}
                            >
                                <div className="col-span-1">
                                    <input
                                        type="checkbox"
                                        checked={mapping.enabled}
                                        onChange={(e) => updateMapping(mapping.productTag, { enabled: e.target.checked })}
                                        className="rounded-sm border-gray-300 text-blue-600 focus:ring-blue-500"
                                    />
                                </div>
                                <div className="col-span-3">
                                    <span className="inline-flex items-center px-2.5 py-1 rounded-full text-sm bg-gray-100 text-gray-700">
                                        {mapping.productTag}
                                    </span>
                                </div>
                                <div className="col-span-1 text-center text-gray-400">→</div>
                                <div className="col-span-4">
                                    <input
                                        type="text"
                                        value={mapping.orderTag}
                                        onChange={(e) => updateMapping(mapping.productTag, { orderTag: e.target.value })}
                                        placeholder="Order tag name"
                                        className="w-full px-3 py-1.5 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white border-gray-300"
                                    />
                                </div>
                                <div className="col-span-2 flex items-center gap-2">
                                    <input
                                        type="color"
                                        value={mapping.color || '#6B7280'}
                                        onChange={(e) => updateMapping(mapping.productTag, { color: e.target.value })}
                                        className="w-8 h-8 rounded-sm cursor-pointer border border-gray-300"
                                        title="Tag color"
                                    />
                                    <span
                                        className="inline-flex items-center px-2 py-0.5 rounded-sm text-xs text-white"
                                        style={{ backgroundColor: mapping.color || '#6B7280' }}
                                    >
                                        {mapping.orderTag || 'Preview'}
                                    </span>
                                </div>
                                <div className="col-span-1 flex justify-end">
                                    <button
                                        onClick={() => removeTagMapping(mapping.productTag)}
                                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-md transition-colors"
                                        title="Remove mapping"
                                    >
                                        <X size={16} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {message && (
                    <div className={`mt-4 p-3 rounded-lg text-sm ${message.type === 'success' ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'
                        }`}>
                        {message.text}
                    </div>
                )}

                <div className="mt-6 flex justify-end">
                    <button
                        onClick={handleSave}
                        disabled={isSaving}
                        className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
                    >
                        {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                        Save Mappings
                    </button>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { api } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import './SessionManager.css';

interface Session {
    id: string;
    createdAt: string;
    expiresAt: string;
    ipAddress: string | null;
    userAgent: string | null;
    isCurrent?: boolean;
}

export const SessionManager: React.FC = () => {
    const { token } = useAuth();
    const [sessions, setSessions] = useState<Session[]>([]);
    const [loading, setLoading] = useState(true);
    const [revoking, setRevoking] = useState<string | null>(null);

    const fetchSessions = async () => {
        if (!token) return; // Don't fetch without auth token
        try {
            setLoading(true);
            const data = await api.get<Session[]>('/api/sessions', token);
            setSessions(data);
        } catch (error) {
            Logger.error('Failed to fetch sessions:', { error: error });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchSessions();
    }, [token]); // Re-fetch when token becomes available

    const revokeSession = async (id: string) => {
        if (!token) return;
        if (!confirm('Are you sure you want to revoke this session?')) return;

        try {
            setRevoking(id);
            await api.delete(`/api/sessions/${id}`, token);
            setSessions(prev => prev.filter(s => s.id !== id));
        } catch (error) {
            Logger.error('Failed to revoke session:', { error: error });
        } finally {
            setRevoking(null);
        }
    };

    const revokeAllSessions = async () => {
        if (!token) return;
        if (!confirm('This will sign you out of all other devices. Continue?')) return;

        try {
            setRevoking('all');
            await api.delete('/api/sessions', token);
            await fetchSessions();
        } catch (error) {
            Logger.error('Failed to revoke sessions:', { error: error });
        } finally {
            setRevoking(null);
        }
    };

    const formatDate = (dateStr: string) => {
        return new Date(dateStr).toLocaleString();
    };

    const parseUserAgent = (ua: string | null): string => {
        if (!ua) return 'Unknown Device';

        if (ua.includes('Chrome')) return 'Chrome Browser';
        if (ua.includes('Firefox')) return 'Firefox Browser';
        if (ua.includes('Safari')) return 'Safari Browser';
        if (ua.includes('Edge')) return 'Edge Browser';

        return 'Unknown Browser';
    };

    if (loading) {
        return <div className="session-manager loading">Loading sessions...</div>;
    }

    return (
        <div className="session-manager">
            <div className="session-header">
                <h3>Active Sessions</h3>
                {sessions.length > 1 && (
                    <button
                        className="btn-danger"
                        onClick={revokeAllSessions}
                        disabled={revoking === 'all'}
                    >
                        {revoking === 'all' ? 'Revoking...' : 'Revoke All Sessions'}
                    </button>
                )}
            </div>

            <p className="session-description">
                These are devices that are currently signed into your account.
                Revoke any sessions you don't recognize.
            </p>

            <div className="session-list">
                {sessions.length === 0 ? (
                    <div className="no-sessions">No active sessions found</div>
                ) : (
                    sessions.map(session => (
                        <div key={session.id} className={`session-item ${session.isCurrent ? 'session-current' : ''}`}>
                            <div className="session-info">
                                <div className="session-device">
                                    <span className="device-icon">💻</span>
                                    <span className="device-name">{parseUserAgent(session.userAgent)}</span>
                                    {session.isCurrent && (
                                        <span className="current-badge">Current Session</span>
                                    )}
                                </div>
                                <div className="session-details">
                                    <span className="session-ip">
                                        IP: {session.ipAddress || 'Unknown'}
                                    </span>
                                    <span className="session-date">
                                        Signed in: {formatDate(session.createdAt)}
                                    </span>
                                    <span className="session-expires">
                                        Expires: {formatDate(session.expiresAt)}
                                    </span>
                                </div>
                            </div>
                            {!session.isCurrent && (
                                <button
                                    className="btn-revoke"
                                    onClick={() => revokeSession(session.id)}
                                    disabled={revoking === session.id}
                                >
                                    {revoking === session.id ? 'Revoking...' : 'Revoke'}
                                </button>
                            )}
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

export default SessionManager;

/**
 * Social Channels Settings Component
 * Allows users to connect/disconnect Facebook, Instagram, and TikTok
 * for direct messaging integration with the Inbox.
 */

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Facebook, Instagram, Music2, Link2, Unlink, Loader2, AlertCircle, CheckCircle, MessageSquare, Save } from 'lucide-react';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';

interface SocialAccount {
    id: string;
    platform: 'FACEBOOK' | 'INSTAGRAM' | 'TIKTOK';
    name: string;
    externalId: string;
    tokenExpiry: string | null;
    createdAt: string;
}

/**
 * Why: Centralizes social messaging channel management, allowing users
 * to connect their FB Pages, IG accounts, and TikTok for inbox DMs.
 */
export function SocialChannelsSettings() {
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const [accounts, setAccounts] = useState<SocialAccount[]>([]);
    const [loading, setLoading] = useState(true);
    const [connecting, setConnecting] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    // SMS Settings State
    const [smsSettings, setSmsSettings] = useState({
        accountSid: '',
        authToken: '',
        fromNumber: '',
        enabled: true
    });
    const [smsLoading, setSmsLoading] = useState(false);

    // Check URL params for OAuth callback status
    useEffect(() => {
        const params = new URLSearchParams(window.location.search);
        const success = params.get('success');
        const errorParam = params.get('error');
        const message = params.get('message');

        if (success) {
            if (success === 'meta_connected') {
                setSuccessMessage('Facebook page connected successfully!' +
                    (params.get('instagram') === 'connected' ? ' Instagram also linked.' : ''));
            } else if (success === 'tiktok_connected') {
                setSuccessMessage('TikTok account connected successfully!');
            }
            // Clear params from URL
            window.history.replaceState({}, '', window.location.pathname + '?tab=channels');
            if (token && currentAccount) {
                fetchAccounts();
                fetchSmsSettings();
            }
        }

        if (errorParam) {
            const errorMessages: Record<string, string> = {
                oauth_denied: 'Authorization was denied.',
                no_pages: 'No Facebook Pages found. Please create a Page first.',
                not_configured: 'Platform not configured. Contact your administrator.',
                token_exchange_failed: 'Failed to connect account. Please try again.',
            };
            setError(errorMessages[errorParam] || message || 'Connection failed.');
            window.history.replaceState({}, '', window.location.pathname + '?tab=channels');
        }
    }, [token, currentAccount]);

    const fetchAccounts = async () => {
        if (!token || !currentAccount) return;

        try {
            setLoading(true);
            const response = await api.get<{ socialAccounts: SocialAccount[] }>(
                '/api/oauth/social-accounts',
                token,
                currentAccount.id
            );
            setAccounts(response.socialAccounts || []);
        } catch (err: any) {
            setError(err.message || 'Failed to load connected accounts.');
        } finally {
            setLoading(false);
        }
    };

    const fetchSmsSettings = async () => {
        if (!token || !currentAccount) return;
        try {
            const data = await api.get<any>('/api/sms/settings', token, currentAccount.id);
            if (data && data.accountSid) {
                setSmsSettings({
                    accountSid: data.accountSid,
                    authToken: data.authToken, // Usually masked or encrypted, but for now...
                    fromNumber: data.fromNumber,
                    enabled: data.enabled
                });
            }
        } catch (err) {
            Logger.error('Failed to fetch SMS settings', { error: err });
        }
    };

    const saveSmsSettings = async () => {
        if (!token || !currentAccount) return;
        try {
            setSmsLoading(true);
            await api.post('/api/sms/settings', smsSettings, token, currentAccount.id);
            setSuccessMessage('SMS settings saved successfully.');
            setTimeout(() => setSuccessMessage(null), 3000);
        } catch (err: any) {
            setError(err.message || 'Failed to save SMS settings.');
        } finally {
            setSmsLoading(false);
        }
    };

    useEffect(() => {
        if (token && currentAccount) {
            fetchAccounts();
            fetchSmsSettings();
        }
    }, [currentAccount, token]);

    const connectPlatform = async (platform: 'meta' | 'tiktok') => {
        if (!token || !currentAccount) return;

        try {
            setConnecting(platform);
            setError(null);

            const endpoint = platform === 'meta'
                ? '/api/oauth/meta/messaging/authorize?redirect=/settings?tab=channels'
                : '/api/oauth/tiktok/authorize?redirect=/settings?tab=channels';

            const response = await api.get<{ authUrl: string }>(
                endpoint,
                token,
                currentAccount.id
            );

            // Redirect to OAuth consent screen
            window.location.href = response.authUrl;
        } catch (err: any) {
            setError(err.message || `Failed to start ${platform} connection.`);
            setConnecting(null);
        }
    };

    const disconnectAccount = async (accountId: string, platform: string) => {
        if (!token || !currentAccount) return;

        if (!confirm(`Disconnect ${platform}? You will no longer receive messages from this account.`)) {
            return;
        }

        try {
            await api.delete(
                `/api/oauth/social-accounts/${accountId}`,
                token,
                currentAccount.id
            );
            setAccounts(prev => prev.filter(a => a.id !== accountId));
            setSuccessMessage(`${platform} disconnected.`);
        } catch (err: any) {
            setError(err.response?.data?.error || 'Failed to disconnect.');
        }
    };

    const getPlatformIcon = (platform: string) => {
        switch (platform) {
            case 'FACEBOOK': return <Facebook className="text-blue-600" size={20} />;
            case 'INSTAGRAM': return <Instagram className="text-pink-600" size={20} />;
            case 'TIKTOK': return <Music2 className="text-gray-900" size={20} />;
            default: return null;
        }
    };

    const getPlatformLabel = (platform: string) => {
        switch (platform) {
            case 'FACEBOOK': return 'Facebook Messenger';
            case 'INSTAGRAM': return 'Instagram DMs';
            case 'TIKTOK': return 'TikTok Messages';
            default: return platform;
        }
    };

    const isConnected = (platform: string) => accounts.some(a => a.platform === platform);

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="animate-spin text-gray-400" size={24} />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Status Messages */}
            {error && (
                <div className="flex items-center gap-2 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700">
                    <AlertCircle size={18} />
                    <span>{error}</span>
                    <button onClick={() => setError(null)} className="ml-auto text-red-500 hover:text-red-700">×</button>
                </div>
            )}
            {successMessage && (
                <div className="flex items-center gap-2 p-4 bg-green-50 border border-green-200 rounded-lg text-green-700">
                    <CheckCircle size={18} />
                    <span>{successMessage}</span>
                    <button onClick={() => setSuccessMessage(null)} className="ml-auto text-green-500 hover:text-green-700">×</button>
                </div>
            )}

            {/* Connected Accounts */}
            {accounts.length > 0 && (
                <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                    <div className="p-4 border-b border-gray-200">
                        <h3 className="font-medium text-gray-900">Connected Channels</h3>
                    </div>
                    <ul className="divide-y divide-gray-200">
                        {accounts.map(account => (
                            <li key={account.id} className="p-4 flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    {getPlatformIcon(account.platform)}
                                    <div>
                                        <p className="font-medium text-gray-900">{account.name}</p>
                                        <p className="text-sm text-gray-500">{getPlatformLabel(account.platform)}</p>
                                    </div>
                                </div>
                                <button
                                    onClick={() => disconnectAccount(account.id, account.platform)}
                                    className="flex items-center gap-1 text-sm text-red-600 hover:text-red-700"
                                >
                                    <Unlink size={14} />
                                    Disconnect
                                </button>
                            </li>
                        ))}
                    </ul>
                </div>
            )}

            {/* SMS Settings (Twilio) */}
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                <div className="p-4 border-b border-gray-200 flex items-center justify-between">
                    <div>
                        <h3 className="font-medium text-gray-900">SMS Integration (Twilio)</h3>
                        <p className="text-sm text-gray-500 mt-1">
                            Connect your Twilio account to send and receive SMS messages.
                        </p>
                    </div>
                    <MessageSquare className="text-gray-400" size={20} />
                </div>
                <div className="p-6 space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Account SID</label>
                            <input
                                type="text"
                                value={smsSettings.accountSid}
                                onChange={(e) => setSmsSettings({ ...smsSettings, accountSid: e.target.value })}
                                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                placeholder="AC..."
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Auth Token</label>
                            <input
                                type="password"
                                value={smsSettings.authToken}
                                onChange={(e) => setSmsSettings({ ...smsSettings, authToken: e.target.value })}
                                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                placeholder="••••••••••••••••••••••••"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">From Number</label>
                            <input
                                type="text"
                                value={smsSettings.fromNumber}
                                onChange={(e) => setSmsSettings({ ...smsSettings, fromNumber: e.target.value })}
                                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                                placeholder="+1234567890"
                            />
                            <p className="text-xs text-gray-500 mt-1">Must be a valid Twilio number in E.164 format.</p>
                        </div>
                        <div className="flex items-center pt-6">
                            <label className="flex items-center gap-2 cursor-pointer">
                                <input
                                    type="checkbox"
                                    checked={smsSettings.enabled}
                                    onChange={(e) => setSmsSettings({ ...smsSettings, enabled: e.target.checked })}
                                    className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
                                />
                                <span className="text-sm text-gray-700">Enable SMS Channel</span>
                            </label>
                        </div>
                    </div>
                    <div className="pt-2 flex justify-end">
                        <button
                            onClick={saveSmsSettings}
                            disabled={smsLoading}
                            className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
                        >
                            {smsLoading ? <Loader2 className="animate-spin" size={16} /> : <Save size={16} />}
                            Save Twilio Settings
                        </button>
                    </div>
                </div>
            </div>

            {/* Available Platforms */}
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                <div className="p-4 border-b border-gray-200">
                    <h3 className="font-medium text-gray-900">Connect Messaging Channels</h3>
                    <p className="text-sm text-gray-500 mt-1">
                        Link your social accounts to receive and respond to messages in your inbox.
                    </p>
                </div>

                <div className="p-4 space-y-3">
                    {/* Meta (Facebook + Instagram) */}
                    <div className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                        <div className="flex items-center gap-3">
                            <div className="flex items-center gap-1">
                                <Facebook className="text-blue-600" size={20} />
                                <span className="text-gray-400">/</span>
                                <Instagram className="text-pink-600" size={20} />
                            </div>
                            <div>
                                <p className="font-medium text-gray-900">Facebook & Instagram</p>
                                <p className="text-sm text-gray-500">Connect your Facebook Page to receive Messenger & IG DMs</p>
                            </div>
                        </div>
                        {isConnected('FACEBOOK') || isConnected('INSTAGRAM') ? (
                            <span className="flex items-center gap-1 text-sm text-green-600">
                                <CheckCircle size={14} />
                                Connected
                            </span>
                        ) : (
                            <button
                                onClick={() => connectPlatform('meta')}
                                disabled={!!connecting}
                                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
                            >
                                {connecting === 'meta' ? (
                                    <Loader2 className="animate-spin" size={16} />
                                ) : (
                                    <Link2 size={16} />
                                )}
                                Connect
                            </button>
                        )}
                    </div>

                    {/* TikTok */}
                    <div className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                        <div className="flex items-center gap-3">
                            <Music2 className="text-gray-900" size={20} />
                            <div>
                                <p className="font-medium text-gray-900">TikTok Business</p>
                                <p className="text-sm text-gray-500">Receive TikTok DMs (48-hour reply window)</p>
                            </div>
                        </div>
                        {isConnected('TIKTOK') ? (
                            <span className="flex items-center gap-1 text-sm text-green-600">
                                <CheckCircle size={14} />
                                Connected
                            </span>
                        ) : (
                            <button
                                onClick={() => connectPlatform('tiktok')}
                                disabled={!!connecting}
                                className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-white rounded-lg hover:bg-gray-800 disabled:opacity-50"
                            >
                                {connecting === 'tiktok' ? (
                                    <Loader2 className="animate-spin" size={16} />
                                ) : (
                                    <Link2 size={16} />
                                )}
                                Connect
                            </button>
                        )}
                    </div>
                </div>

                {/* Info Note */}
                <div className="p-4 bg-blue-50 border-t border-blue-100">
                    <p className="text-sm text-blue-700">
                        <strong>Note:</strong> Facebook/Instagram requires a Facebook Page. TikTok messaging is not available in EEA, Switzerland, or UK regions.
                    </p>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Trash2, UserPlus, Shield, User, Edit2, Check, X, ChevronDown } from 'lucide-react';

interface CustomRole {
    id: string;
    name: string;
    permissions: Record<string, boolean>;
}

interface Member {
    userId: string;
    role: 'OWNER' | 'ADMIN' | 'STAFF' | 'VIEWER';
    roleId: string | null;
    maxRole: CustomRole | null;
    user: {
        id: string;
        fullName: string;
        email: string;
        avatarUrl: string | null;
    };
}

const BASE_ROLES = [
    { value: 'OWNER', label: 'Owner', description: 'Full access, can transfer ownership' },
    { value: 'ADMIN', label: 'Admin', description: 'Full access, cannot transfer ownership' },
    { value: 'STAFF', label: 'Staff', description: 'Access based on custom role' },
    { value: 'VIEWER', label: 'Viewer', description: 'Read-only access' },
] as const;

/**
 * Team management component for Settings page.
 * Allows adding/removing/editing team members and managing roles.
 */
export function TeamSettings() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [members, setMembers] = useState<Member[]>([]);
    const [customRoles, setCustomRoles] = useState<CustomRole[]>([]);
    const [email, setEmail] = useState('');
    const [role, setRole] = useState<string>('STAFF');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState('');
    const [editingUserId, setEditingUserId] = useState<string | null>(null);
    const [editValues, setEditValues] = useState<{ role: string; roleId: string | null }>({ role: 'STAFF', roleId: null });
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (currentAccount && token) {
            fetchMembers();
            fetchCustomRoles();
        }
    }, [currentAccount, token]);

    const fetchMembers = async () => {
        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) setMembers(await res.json());
        } catch (e) {
            Logger.error('Failed to fetch members', { error: e });
        } finally {
            setIsLoading(false);
        }
    };

    const fetchCustomRoles = async () => {
        try {
            const res = await fetch('/api/roles', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                setCustomRoles(data);
            }
        } catch (e) {
            Logger.error('Failed to fetch custom roles', { error: e });
        }
    };

    const handleInvite = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        if (!email) return;

        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                body: JSON.stringify({ email, role })
            });

            if (!res.ok) {
                let errorMessage = 'Failed to add user';
                try {
                    const data = await res.json();
                    errorMessage = data.error || errorMessage;
                } catch {
                    // Response body is not valid JSON, use status text
                    errorMessage = res.statusText || `Error ${res.status}`;
                }
                throw new Error(errorMessage);
            }

            setEmail('');
            fetchMembers();
        } catch (err: any) {
            setError(err.message);
        }
    };

    const handleRemove = async (userId: string) => {
        if (!confirm('Are you sure you want to remove this member?')) return;
        try {
            await fetch(`/api/accounts/${currentAccount?.id}/users/${userId}`, {
                method: 'DELETE',
                headers: { Authorization: `Bearer ${token}` }
            });
            fetchMembers();
        } catch (e) {
            Logger.error('Failed to remove member', { error: e });
        }
    };

    const startEdit = (member: Member) => {
        setEditingUserId(member.userId);
        setEditValues({ role: member.role, roleId: member.roleId });
    };

    const cancelEdit = () => {
        setEditingUserId(null);
        setEditValues({ role: 'STAFF', roleId: null });
    };

    const saveEdit = async (userId: string) => {
        setIsSaving(true);
        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users/${userId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                body: JSON.stringify({
                    role: editValues.role,
                    roleId: editValues.roleId
                })
            });

            if (!res.ok) {
                let errorMessage = 'Failed to update user';
                try {
                    const data = await res.json();
                    errorMessage = data.error || errorMessage;
                } catch {
                    // Response body is not valid JSON, use status text
                    errorMessage = res.statusText || `Error ${res.status}`;
                }
                throw new Error(errorMessage);
            }

            setEditingUserId(null);
            fetchMembers();
        } catch (err: any) {
            alert(err.message);
        } finally {
            setIsSaving(false);
        }
    };

    const getRoleBadgeClass = (role: string) => {
        switch (role) {
            case 'OWNER': return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300';
            case 'ADMIN': return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300';
            case 'STAFF': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300';
            case 'VIEWER': return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    if (isLoading) return <div className="p-4 text-gray-500">Loading members...</div>;

    return (
        <div className="space-y-6">
            {/* Invite Card */}
            <div className="bg-white dark:bg-gray-800 p-6 rounded-xl border border-gray-200 dark:border-gray-700 shadow-xs">
                <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-gray-900 dark:text-white">
                    <UserPlus size={20} className="text-blue-600" />
                    Add New Member
                </h2>
                <form onSubmit={handleInvite} className="flex flex-col sm:flex-row gap-4 items-start">
                    <div className="flex-1 w-full">
                        <input
                            type="email"
                            placeholder="Enter user email address"
                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden dark:bg-gray-900 dark:border-gray-600 dark:text-white"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                        />
                        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">User must already be registered with this email.</p>
                        {error && <p className="text-xs text-red-500 mt-1 font-medium">{error}</p>}
                    </div>

                    <select
                        className="px-4 py-2 border rounded-lg bg-white dark:bg-gray-900 dark:border-gray-600 dark:text-white"
                        value={role}
                        onChange={e => setRole(e.target.value)}
                    >
                        <option value="STAFF">Staff</option>
                        <option value="ADMIN">Admin</option>
                        <option value="VIEWER">Viewer</option>
                    </select>

                    <button type="submit" className="px-6 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition-colors whitespace-nowrap">
                        Add User
                    </button>
                </form>
            </div>

            {/* Members List */}
            <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-xs overflow-hidden">
                <div className="p-4 border-b border-gray-200 dark:border-gray-700">
                    <h3 className="font-medium text-gray-900 dark:text-white">Team Members</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400">Manage who has access to {currentAccount?.name}</p>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-700">
                            <tr>
                                <th className="px-6 py-3 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">User</th>
                                <th className="px-6 py-3 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Base Role</th>
                                <th className="px-6 py-3 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">Custom Role</th>
                                <th className="px-6 py-3 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {members.map(member => {
                                const isEditing = editingUserId === member.userId;
                                const isOwner = member.role === 'OWNER';

                                return (
                                    <tr key={member.userId} className="hover:bg-gray-50 dark:hover:bg-gray-700/50">
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full bg-gray-200 dark:bg-gray-700 flex items-center justify-center text-gray-500 overflow-hidden">
                                                    {member.user.avatarUrl ? (
                                                        <img src={member.user.avatarUrl} alt="" className="w-full h-full object-cover" />
                                                    ) : (
                                                        <User size={16} />
                                                    )}
                                                </div>
                                                <div>
                                                    <div className="font-medium text-gray-900 dark:text-white">{member.user.fullName || 'No Name'}</div>
                                                    <div className="text-sm text-gray-500 dark:text-gray-400">{member.user.email}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            {isEditing && !isOwner ? (
                                                <select
                                                    value={editValues.role}
                                                    onChange={e => setEditValues({ ...editValues, role: e.target.value })}
                                                    className="px-3 py-1.5 text-sm border rounded-lg bg-white dark:bg-gray-900 dark:border-gray-600 dark:text-white"
                                                >
                                                    {BASE_ROLES.filter(r => r.value !== 'OWNER').map(r => (
                                                        <option key={r.value} value={r.value}>{r.label}</option>
                                                    ))}
                                                </select>
                                            ) : (
                                                <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleBadgeClass(member.role)}`}>
                                                    {isOwner && <Shield size={12} />}
                                                    {member.role}
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">
                                            {isEditing && !isOwner ? (
                                                <select
                                                    value={editValues.roleId || ''}
                                                    onChange={e => setEditValues({ ...editValues, roleId: e.target.value || null })}
                                                    className="px-3 py-1.5 text-sm border rounded-lg bg-white dark:bg-gray-900 dark:border-gray-600 dark:text-white"
                                                >
                                                    <option value="">None</option>
                                                    {customRoles.map(r => (
                                                        <option key={r.id} value={r.id}>{r.name}</option>
                                                    ))}
                                                </select>
                                            ) : (
                                                member.maxRole ? (
                                                    <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 dark:bg-indigo-900/30 dark:text-indigo-300">
                                                        {member.maxRole.name}
                                                    </span>
                                                ) : (
                                                    <span className="text-gray-400 dark:text-gray-500 text-sm">—</span>
                                                )
                                            )}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                {isEditing ? (
                                                    <>
                                                        <button
                                                            onClick={() => saveEdit(member.userId)}
                                                            disabled={isSaving}
                                                            className="p-1.5 text-green-600 hover:bg-green-100 dark:hover:bg-green-900/30 rounded transition-colors"
                                                            title="Save"
                                                        >
                                                            <Check size={16} />
                                                        </button>
                                                        <button
                                                            onClick={cancelEdit}
                                                            className="p-1.5 text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors"
                                                            title="Cancel"
                                                        >
                                                            <X size={16} />
                                                        </button>
                                                    </>
                                                ) : (
                                                    <>
                                                        {!isOwner && (
                                                            <button
                                                                onClick={() => startEdit(member)}
                                                                className="p-1.5 text-blue-600 hover:bg-blue-100 dark:hover:bg-blue-900/30 rounded transition-colors"
                                                                title="Edit Role"
                                                            >
                                                                <Edit2 size={16} />
                                                            </button>
                                                        )}
                                                        {!isOwner && (
                                                            <button
                                                                onClick={() => handleRemove(member.userId)}
                                                                className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-100 dark:hover:bg-red-900/30 rounded transition-colors"
                                                                title="Remove User"
                                                            >
                                                                <Trash2 size={16} />
                                                            </button>
                                                        )}
                                                    </>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Custom Roles Info */}
            {customRoles.length === 0 && (
                <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-xl p-4">
                    <p className="text-sm text-amber-800 dark:text-amber-300">
                        <strong>Tip:</strong> Create custom roles in the "Roles" tab to define granular permissions for STAFF members.
                    </p>
                </div>
            )}
        </div>
    );
}

