import { useState } from 'react';
import { Logger } from '../../utils/logger';
import { getPublicApiUrl } from '../../utils/url';
import { Copy, Check, Info, Monitor, RefreshCw, AlertCircle, Zap, Store, ExternalLink } from 'lucide-react';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';

// Type for store verification response
interface StoreVerificationResult {
    success: boolean;
    storeUrl?: string;
    storeName?: string;
    storeReachable: boolean;
    pluginInstalled: boolean;
    pluginVersion?: string;
    configured?: boolean;
    accountMatch?: boolean;
    trackingEnabled?: boolean;
    chatEnabled?: boolean;
    woocommerceActive?: boolean;
    woocommerceVersion?: string;
    error?: string;
}

export function TrackingScriptHelper() {
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const [copied, setCopied] = useState(false);

    // Status Check State
    const [checkStatus, setCheckStatus] = useState<'idle' | 'loading' | 'connected' | 'inactive' | 'error'>('idle');
    const [lastSignal, setLastSignal] = useState<string | null>(null);

    // Test Event State
    const [testStatus, setTestStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');

    // Store Verification State
    const [storeStatus, setStoreStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
    const [storeResult, setStoreResult] = useState<StoreVerificationResult | null>(null);

    // Internal API URL for direct requests (may be Docker container name)
    const apiUrl = import.meta.env.VITE_API_URL || window.location.origin;

    // Public API URL for external clients (derived from browser location)
    const publicApiUrl = getPublicApiUrl();

    const sendTestEvent = async () => {
        setTestStatus('loading');
        try {
            // Generate a test visitor ID
            const testVisitorId = `test-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;

            // Send a test pageview event directly to the tracking endpoint
            await fetch(`${apiUrl}/api/tracking/events`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    accountId: currentAccount?.id,
                    visitorId: testVisitorId,
                    type: 'pageview',
                    url: 'https://test.overseek.internal/diagnostic-check',
                    pageTitle: 'OverSeek Connection Test',
                    payload: { source: 'dashboard-diagnostic', timestamp: new Date().toISOString() }
                })
            });

            setTestStatus('success');

            // After sending test event, check connection status
            setTimeout(() => {
                checkConnection();
            }, 1000);
        } catch (error) {
            Logger.error('Test Event Failed:', { error: error });
            setTestStatus('error');
        }
    };

    const checkConnection = async () => {
        setCheckStatus('loading');
        try {
            // Using the api helper which expects: (endpoint, token, accountId)
            // It returns the data directly, not { data }
            const result = await api.get<{ connected: boolean; lastSignal: string | null }>(
                '/api/tracking/status',
                token || undefined,
                currentAccount?.id || ''
            );

            if (result.connected) {
                setCheckStatus('connected');
                setLastSignal(result.lastSignal);
            } else {
                setCheckStatus('inactive');
                setLastSignal(null);
            }
        } catch (error) {
            Logger.error('Connection Check Failed:', { error: error });
            setCheckStatus('error');
        }
    };

    const verifyStore = async () => {
        setStoreStatus('loading');
        setStoreResult(null);
        try {
            const result = await api.get<StoreVerificationResult>(
                '/api/tracking/verify-store',
                token || undefined,
                currentAccount?.id || ''
            );

            setStoreResult(result);
            setStoreStatus(result.success ? 'success' : 'error');
        } catch (error) {
            Logger.error('Store Verification Failed:', { error: error });
            setStoreStatus('error');
            setStoreResult({
                success: false,
                storeReachable: false,
                pluginInstalled: false,
                error: 'Failed to verify store connection'
            });
        }
    };

    // We'll use a "loader" pattern where they copy a snippet that loads our tracking.js from the server.
    // OR we provide the full inline script as described in the plan.


    const [configCopied, setConfigCopied] = useState(false);

    const connectionConfig = JSON.stringify({
        apiUrl: publicApiUrl,
        accountId: currentAccount?.id || ''
    }, null, 2);

    const handleCopyConfig = () => {
        navigator.clipboard.writeText(connectionConfig);
        setConfigCopied(true);
        setTimeout(() => setConfigCopied(false), 2000);
    };

    return (
        <div className="space-y-8">
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 flex gap-3">
                <Info className="shrink-0 w-5 h-5 text-blue-600 mt-0.5" />
                <div className="text-sm text-blue-800">
                    <p className="font-medium mb-1">WooCommerce Plugin Setup</p>
                    <p>To enable Live View and abandoned cart tracking, install the OverSeek plugin and paste the configuration below.</p>
                    <div className="mt-3">
                        <a
                            href={`${publicApiUrl}/uploads/plugins/overseek-wc-plugin.zip`}
                            download
                            className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-md text-sm font-medium hover:bg-blue-700 transition-colors"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" /><polyline points="7 10 12 15 17 10" /><line x1="12" x2="12" y1="15" y2="3" /></svg>
                            Download Plugin
                        </a>
                    </div>
                </div>
            </div>

            <div className="space-y-3">
                <div className="flex items-center justify-between">
                    <label className="block text-sm font-medium text-gray-700">Connection Configuration (JSON)</label>
                    <span className="text-xs text-gray-500">Paste this into the plugin settings</span>
                </div>
                <div className="relative group">
                    <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button
                            onClick={handleCopyConfig}
                            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors shadow-xs ${configCopied
                                ? 'bg-green-100 text-green-700 border border-green-200'
                                : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                                }`}
                        >
                            {configCopied ? <Check size={14} /> : <Copy size={14} />}
                            {configCopied ? 'Copied' : 'Copy'}
                        </button>
                    </div>
                    <pre className="bg-slate-950 text-slate-50 p-4 rounded-lg overflow-x-auto font-mono text-sm leading-relaxed border border-slate-800 shadow-xs relative">
                        <code>{connectionConfig || 'Loading configuration...'}</code>
                    </pre>
                </div>
            </div>

            {/* Status Checker */}
            <div className="border-t border-gray-100 pt-6">
                <h3 className="text-sm font-medium text-gray-900 mb-3 flex items-center gap-2">
                    <Monitor size={16} className="text-gray-500" />
                    Connection Diagnosis
                </h3>

                <div className="bg-gray-50 rounded-lg p-4 border border-gray-200 space-y-4">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-700 font-medium">Verify Installation</p>
                            <p className="text-xs text-gray-500 mt-1">Check if OverSeek is receiving data from your store.</p>
                        </div>
                        <div className="flex items-center gap-2">
                            <button
                                onClick={sendTestEvent}
                                disabled={testStatus === 'loading'}
                                className="flex items-center gap-2 px-3 py-1.5 bg-purple-600 text-white rounded-md text-sm hover:bg-purple-700 disabled:opacity-50 transition-colors shadow-xs"
                            >
                                <Zap size={14} className={testStatus === 'loading' ? 'animate-pulse' : ''} />
                                {testStatus === 'loading' ? 'Sending...' : 'Send Test Event'}
                            </button>
                            <button
                                onClick={checkConnection}
                                disabled={checkStatus === 'loading'}
                                className="flex items-center gap-2 px-3 py-1.5 bg-white border border-gray-300 text-gray-700 rounded-md text-sm hover:bg-gray-50 disabled:opacity-50 transition-colors shadow-xs"
                            >
                                <RefreshCw size={14} className={checkStatus === 'loading' ? 'animate-spin' : ''} />
                                Check Status
                            </button>
                        </div>
                    </div>

                    {/* Test Event Feedback */}
                    {testStatus === 'success' && (
                        <div className="p-3 rounded-md text-sm border bg-purple-50 border-purple-200 text-purple-800 flex items-start gap-3">
                            <Zap className="w-5 h-5 text-purple-600 shrink-0" />
                            <div>
                                <p className="font-semibold">Test Event Sent!</p>
                                <p className="mt-1 opacity-90">A test pageview was sent directly to your analytics. Checking connection status...</p>
                            </div>
                        </div>
                    )}

                    {testStatus === 'error' && (
                        <div className="p-3 rounded-md text-sm border bg-red-50 border-red-200 text-red-800 flex items-start gap-3">
                            <AlertCircle className="w-5 h-5 text-red-600 shrink-0" />
                            <div>
                                <p className="font-semibold">Test Event Failed</p>
                                <p className="mt-1 opacity-90">Could not send test event. Check your network connection.</p>
                            </div>
                        </div>
                    )}

                    {/* Status Feedback */}
                    {checkStatus !== 'idle' && (
                        <div className={`p-3 rounded-md text-sm border flex items-start gap-3 ${checkStatus === 'connected' ? 'bg-green-50 border-green-200 text-green-800' :
                            checkStatus === 'inactive' ? 'bg-amber-50 border-amber-200 text-amber-800' :
                                'bg-red-50 border-red-200 text-red-800'
                            }`}>
                            {checkStatus === 'connected' && <Check className="w-5 h-5 text-green-600 shrink-0" />}
                            {checkStatus === 'inactive' && <AlertCircle className="w-5 h-5 text-amber-600 shrink-0" />}
                            {checkStatus === 'error' && <AlertCircle className="w-5 h-5 text-red-600 shrink-0" />}

                            <div>
                                <p className="font-semibold">
                                    {checkStatus === 'connected' ? 'Connection Active' :
                                        checkStatus === 'inactive' ? 'No Recent Activity' : 'Connection Error'}
                                </p>
                                <p className="mt-1 opacity-90">
                                    {checkStatus === 'connected' ? (
                                        <>We received a signal from your store. Last activity: <span className="font-mono">{new Date(lastSignal!).toLocaleString()}</span></>
                                    ) : checkStatus === 'inactive' ? (
                                        <>No events received yet. Click <strong>"Send Test Event"</strong> to verify the connection, or visit your store with the plugin installed.</>
                                    ) : (
                                        "Could not check status. Ensure your internet is connected."
                                    )}
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Store Plugin Verification */}
            <div className="border-t border-gray-100 pt-6">
                <h3 className="text-sm font-medium text-gray-900 mb-3 flex items-center gap-2">
                    <Store size={16} className="text-gray-500" />
                    Store Plugin Verification
                </h3>

                <div className="bg-gray-50 rounded-lg p-4 border border-gray-200 space-y-4">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-700 font-medium">Verify WooCommerce Plugin</p>
                            <p className="text-xs text-gray-500 mt-1">Check if the OverSeek plugin is installed and configured on your store.</p>
                        </div>
                        <button
                            onClick={verifyStore}
                            disabled={storeStatus === 'loading'}
                            className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 text-white rounded-md text-sm hover:bg-blue-700 disabled:opacity-50 transition-colors shadow-xs"
                        >
                            <Store size={14} className={storeStatus === 'loading' ? 'animate-pulse' : ''} />
                            {storeStatus === 'loading' ? 'Verifying...' : 'Verify Store Plugin'}
                        </button>
                    </div>

                    {/* Store Verification Result */}
                    {storeResult && (
                        <div className={`p-4 rounded-md text-sm border ${storeResult.success ? 'bg-green-50 border-green-200' : 'bg-amber-50 border-amber-200'
                            }`}>
                            <div className="flex items-start gap-3">
                                {storeResult.success ? (
                                    <Check className="w-5 h-5 text-green-600 shrink-0 mt-0.5" />
                                ) : (
                                    <AlertCircle className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
                                )}
                                <div className="flex-1 space-y-2">
                                    <p className={`font-semibold ${storeResult.success ? 'text-green-800' : 'text-amber-800'}`}>
                                        {storeResult.success ? 'Plugin Verified!' : 'Plugin Issue Detected'}
                                    </p>

                                    {storeResult.storeUrl && (
                                        <p className="text-gray-700 text-xs flex items-center gap-1">
                                            Store: <a href={storeResult.storeUrl} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline flex items-center gap-1">
                                                {storeResult.storeUrl} <ExternalLink size={10} />
                                            </a>
                                        </p>
                                    )}

                                    {storeResult.error && (
                                        <p className="text-amber-700">{storeResult.error}</p>
                                    )}

                                    {storeResult.success && (
                                        <div className="grid grid-cols-2 gap-2 mt-3 text-xs">
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${storeResult.pluginInstalled ? 'bg-green-500' : 'bg-red-500'}`}></span>
                                                Plugin: {storeResult.pluginVersion || 'Installed'}
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${storeResult.configured ? 'bg-green-500' : 'bg-amber-500'}`}></span>
                                                Configured: {storeResult.configured ? 'Yes' : 'No'}
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${storeResult.trackingEnabled ? 'bg-green-500' : 'bg-amber-500'}`}></span>
                                                Tracking: {storeResult.trackingEnabled ? 'Enabled' : 'Disabled'}
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${storeResult.accountMatch ? 'bg-green-500' : 'bg-red-500'}`}></span>
                                                Account Match: {storeResult.accountMatch ? 'Yes' : 'No'}
                                            </div>
                                            {storeResult.woocommerceVersion && (
                                                <div className="flex items-center gap-2 col-span-2">
                                                    <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                                                    WooCommerce: v{storeResult.woocommerceVersion}
                                                </div>
                                            )}
                                        </div>
                                    )}

                                    {!storeResult.pluginInstalled && storeResult.storeReachable && (
                                        <p className="text-xs text-amber-700 mt-2">
                                            Your store is reachable but the OverSeek plugin is not detected. Please install and activate the plugin.
                                        </p>
                                    )}

                                    {!storeResult.storeReachable && (
                                        <p className="text-xs text-amber-700 mt-2">
                                            Could not reach your store. Ensure the store URL is correct and the site is online.
                                        </p>
                                    )}
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useMemo } from 'react';
import { useSyncStatus, SyncLog } from '../../context/SyncStatusContext';
import { formatRelativeTime, getStalenessLevel } from '../../utils/relativeTime';
import {
    RefreshCw, CheckCircle, XCircle, Clock, Package,
    ShoppingCart, Users, Star, Layers, Filter,
    ChevronDown, ChevronUp, AlertTriangle, Loader2,
    Pause, Play, X, RotateCcw, Database, Activity,
    TrendingDown, Zap, WifiOff, PlayCircle
} from 'lucide-react';
import { Logger } from '../../utils/logger';

/** Entity types available for sync */
const SYNC_ENTITIES = [
    { key: 'orders', label: 'Orders', icon: ShoppingCart, color: 'blue' },
    { key: 'products', label: 'Products', icon: Package, color: 'violet' },
    { key: 'customers', label: 'Customers', icon: Users, color: 'emerald' },
    { key: 'reviews', label: 'Reviews', icon: Star, color: 'amber' },
] as const;

/** BOM is handled separately — always full sync via dedicated queue */
const BOM_ENTITY = { key: 'bom', label: 'BOM Inventory', icon: Layers, color: 'teal' } as const;

type SyncEntityKey = typeof SYNC_ENTITIES[number]['key'];

/** Staleness → dot color mapping */
const STALENESS_COLORS = {
    fresh: 'bg-green-500',
    stale: 'bg-amber-500',
    critical: 'bg-red-500',
    never: 'bg-slate-400 dark:bg-slate-500',
} as const;

const STALENESS_LABELS = {
    fresh: 'Up to date',
    stale: 'Getting stale',
    critical: 'Needs sync',
    never: 'Never synced',
} as const;

/**
 * Full-featured sync dashboard used in the Settings → Sync tab.
 *
 * Why separate from the sidebar indicator: the sidebar shows health-at-a-glance,
 * while this panel gives full control over sync operations, queue management,
 * retry logic, and search reindexing.
 */
export function SyncStatus() {
    const {
        isSyncing, syncState, logs, activeJobs, healthSummary,
        runSync, controlSync, retrySync, resetCircuit, reindexOrders, refreshStatus
    } = useSyncStatus();

    // Per-entity full-sync toggles
    const [fullSyncTypes, setFullSyncTypes] = useState<Record<SyncEntityKey, boolean>>({
        orders: false, products: false, customers: false, reviews: false,
    });
    const [syncBOM, setSyncBOM] = useState(false);
    const [logFilter, setLogFilter] = useState<string | null>(null);
    const [expandedLogId, setExpandedLogId] = useState<string | null>(null);
    const [syncTriggered, setSyncTriggered] = useState(false);
    const [isPaused, setIsPaused] = useState(false);
    const [reindexState, setReindexState] = useState<'idle' | 'running' | 'done' | 'error'>('idle');
    const [reindexResult, setReindexResult] = useState<string | null>(null);

    /** Build a fast lookup: entityType → lastSyncedAt */
    const lastSyncMap = useMemo(() => {
        const map: Record<string, string | null> = {};
        (syncState || []).forEach(s => { map[s.entityType] = s.lastSyncedAt; });
        return map;
    }, [syncState]);

    /** Which jobs are active, keyed by queue name */
    const activeJobMap = useMemo(() => {
        const map: Record<string, typeof activeJobs[number]> = {};
        (activeJobs || []).forEach(j => { map[j.queue.replace('sync-', '')] = j; });
        return map;
    }, [activeJobs]);

    const toggleFullSync = (key: SyncEntityKey) => {
        setFullSyncTypes(prev => ({ ...prev, [key]: !prev[key] }));
    };

    const allSelected = Object.values(fullSyncTypes).every(Boolean);

    const handleSelectToggle = () => {
        const next = !allSelected;
        setFullSyncTypes({ orders: next, products: next, customers: next, reviews: next });
    };

    const handleSync = async () => {
        setSyncTriggered(true);
        const fullSyncList = SYNC_ENTITIES.filter(e => fullSyncTypes[e.key]).map(e => e.key);
        const incrementalList = SYNC_ENTITIES.filter(e => !fullSyncTypes[e.key]).map(e => e.key);

        if (fullSyncList.length > 0) await runSync(fullSyncList, false);
        if (incrementalList.length > 0) await runSync(incrementalList, true);
        if (syncBOM) await runSync(['bom'], false);

        setTimeout(() => setSyncTriggered(false), 2000);
    };

    const handlePauseResume = async () => {
        try {
            if (isPaused) {
                await controlSync('resume');
                setIsPaused(false);
            } else {
                await controlSync('pause');
                setIsPaused(true);
            }
        } catch (err) {
            Logger.error('Pause/resume failed', { error: err });
        }
    };

    const handleCancelJob = async (queueName: string, jobId: string) => {
        try {
            await controlSync('cancel', queueName, jobId);
        } catch (err) {
            Logger.error('Cancel failed', { error: err });
        }
    };

    const handleRetry = async (entityType: string, logId?: string) => {
        try {
            await retrySync(entityType, logId);
        } catch (err) {
            Logger.error('Retry failed', { error: err });
        }
    };

    const handleReindex = async () => {
        setReindexState('running');
        setReindexResult(null);
        try {
            const result = await reindexOrders();
            setReindexState('done');
            setReindexResult(`Reindexed ${result.totalIndexed} orders`);
            setTimeout(() => { setReindexState('idle'); setReindexResult(null); }, 5000);
        } catch (err) {
            setReindexState('error');
            setReindexResult(err instanceof Error ? err.message : 'Reindex failed');
            setTimeout(() => { setReindexState('idle'); setReindexResult(null); }, 5000);
        }
    };

    const filteredLogs = useMemo(() => {
        if (!logFilter) return logs || [];
        return (logs || []).filter(l => l.entityType === logFilter);
    }, [logs, logFilter]);

    return (
        <div className="space-y-6">
            {/* ── Circuit Breaker Banner ───────────────────── */}
            {healthSummary?.circuitBreaker?.isOpen && (
                <CircuitBreakerBanner
                    byEntity={healthSummary.circuitBreaker.byEntity}
                    onReset={() => resetCircuit()}
                />
            )}

            {/* ── Health Summary Bar ──────────────────────── */}
            {healthSummary && <HealthSummaryBar summary={healthSummary} />}

            {/* ── Controls Toolbar ────────────────────────── */}
            <div className="flex items-center justify-between flex-wrap gap-3">
                <div className="flex items-center gap-2">
                    <button
                        onClick={handleSelectToggle}
                        className="text-xs text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium transition-colors"
                    >
                        {allSelected ? 'Deselect All' : 'Select All Full Sync'}
                    </button>
                </div>

                <div className="flex items-center gap-2">
                    {/* Pause / Resume */}
                    {isSyncing && (
                        <button
                            onClick={handlePauseResume}
                            className={`
                                flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all
                                ${isPaused
                                    ? 'bg-green-100 dark:bg-green-500/15 text-green-700 dark:text-green-400 hover:bg-green-200 dark:hover:bg-green-500/25'
                                    : 'bg-amber-100 dark:bg-amber-500/15 text-amber-700 dark:text-amber-400 hover:bg-amber-200 dark:hover:bg-amber-500/25'
                                }
                            `}
                        >
                            {isPaused ? <><Play size={12} /> Resume</> : <><Pause size={12} /> Pause</>}
                        </button>
                    )}

                    {/* Refresh */}
                    <button
                        onClick={refreshStatus}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium bg-slate-100 dark:bg-slate-700/50 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-600/50 transition-colors"
                        title="Refresh status"
                    >
                        <RefreshCw size={12} />
                    </button>

                    {/* Sync Now — always enabled so users can enqueue additional entity types */}
                    <button
                        onClick={handleSync}
                        disabled={syncTriggered}
                        className={`
                            flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all duration-300
                            ${syncTriggered
                                ? 'bg-blue-500/20 dark:bg-blue-500/30 text-blue-600 dark:text-blue-400 ring-2 ring-blue-500/30 dark:ring-blue-400/20'
                                : 'bg-blue-600 dark:bg-blue-500 text-white hover:bg-blue-700 dark:hover:bg-blue-600 shadow-sm shadow-blue-500/20'
                            }
                            disabled:opacity-50 disabled:cursor-not-allowed
                        `}
                    >
                        <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                        {syncTriggered ? 'Queued…' : isSyncing ? 'Sync More' : 'Sync Now'}
                    </button>
                </div>
            </div>

            {/* ── Entity Cards ───────────────────────────── */}
            <div>
                <h3 className="text-sm font-semibold text-slate-700 dark:text-slate-300 uppercase tracking-wider mb-3">
                    Data Sources
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                    {SYNC_ENTITIES.map(({ key, label, icon: Icon }) => (
                        <EntityCard
                            key={key}
                            label={label}
                            Icon={Icon}
                            staleness={getStalenessLevel(lastSyncMap[key])}
                            lastSyncedAt={lastSyncMap[key]}
                            activeJob={activeJobMap[key]}
                            onCancel={activeJobMap[key] ? () => handleCancelJob(activeJobMap[key].queue, activeJobMap[key].id) : undefined}
                            onSyncIncremental={() => runSync([key], true)}
                            onSyncFull={() => runSync([key], false)}
                        />
                    ))}

                    <EntityCard
                        label={BOM_ENTITY.label}
                        Icon={BOM_ENTITY.icon}
                        staleness={getStalenessLevel(lastSyncMap['bom'])}
                        lastSyncedAt={lastSyncMap['bom']}
                        activeJob={activeJobMap['bom'] || activeJobMap['bom-inventory']}
                        onCancel={
                            (activeJobMap['bom'] || activeJobMap['bom-inventory'])
                                ? () => {
                                    const job = activeJobMap['bom'] || activeJobMap['bom-inventory'];
                                    handleCancelJob(job.queue, job.id);
                                }
                                : undefined
                        }
                        onSyncFull={() => runSync(['bom'], false)}
                    />
                </div>
            </div>

            {/* ── Sync Log ───────────────────────────────── */}
            <div className="border-t border-slate-200 dark:border-slate-700 pt-5">
                <div className="flex items-center justify-between mb-3">
                    <h3 className="text-sm font-semibold text-slate-700 dark:text-slate-300 uppercase tracking-wider flex items-center gap-2">
                        <Clock size={14} />
                        Recent Activity
                    </h3>
                    <LogFilterPills activeFilter={logFilter} onFilter={setLogFilter} />
                </div>

                <div className="space-y-2 max-h-72 overflow-y-auto pr-1 custom-scrollbar">
                    {filteredLogs.length === 0 && (
                        <p className="text-sm text-slate-400 dark:text-slate-500 py-4 text-center">
                            No sync activity yet.
                        </p>
                    )}
                    {filteredLogs.map(log => (
                        <LogEntry
                            key={log.id}
                            log={log}
                            isExpanded={expandedLogId === log.id}
                            onToggle={() => setExpandedLogId(prev => prev === log.id ? null : log.id)}
                            onRetry={() => handleRetry(log.entityType, log.id)}
                        />
                    ))}
                </div>
            </div>

            {/* ── Utilities ──────────────────────────────── */}
            <div className="border-t border-slate-200 dark:border-slate-700 pt-5">
                <h3 className="text-sm font-semibold text-slate-700 dark:text-slate-300 uppercase tracking-wider mb-3 flex items-center gap-2">
                    <Database size={14} />
                    Utilities
                </h3>
                <div className="flex items-center justify-between bg-slate-50 dark:bg-slate-800/60 rounded-xl border border-slate-200 dark:border-slate-700 p-4">
                    <div>
                        <p className="text-sm font-medium text-slate-800 dark:text-slate-200">Rebuild Search Index</p>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                            Re-index all orders from the database into Elasticsearch. Use when search results are stale or missing.
                        </p>
                    </div>
                    <div className="flex items-center gap-3 shrink-0 ml-4">
                        {reindexResult && (
                            <span className={`text-xs font-medium ${reindexState === 'done' ? 'text-green-600 dark:text-green-400' : 'text-red-600 dark:text-red-400'}`}>
                                {reindexResult}
                            </span>
                        )}
                        <button
                            onClick={handleReindex}
                            disabled={reindexState === 'running'}
                            className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-600 transition-colors disabled:opacity-50"
                        >
                            {reindexState === 'running'
                                ? <><Loader2 size={14} className="animate-spin" /> Reindexing…</>
                                : <><Database size={14} /> Reindex</>
                            }
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

/* ─── Sub-components ─────────────────────────────────────────────── */

/**
 * Circuit Breaker Banner — shown when scheduled syncs are suppressed
 * due to consecutive failures. Gives the user a clear explanation and
 * a single "Resume Syncing" action.
 */
function CircuitBreakerBanner({
    byEntity,
    onReset
}: {
    byEntity: Record<string, boolean>;
    onReset: () => void;
}) {
    const [resetting, setResetting] = useState(false);
    const [done, setDone] = useState(false);

    const brokenEntities = Object.entries(byEntity)
        .filter(([, open]) => open)
        .map(([type]) => type);

    const handleReset = async () => {
        setResetting(true);
        try {
            await onReset();
            setDone(true);
            setTimeout(() => setDone(false), 4000);
        } catch (err) {
            Logger.error('Circuit breaker reset failed', { error: err });
        } finally {
            setResetting(false);
        }
    };

    return (
        <div className="rounded-xl border border-red-200 dark:border-red-500/30 bg-red-50/60 dark:bg-red-500/8 p-4">
            <div className="flex items-start gap-3">
                <div className="w-9 h-9 rounded-lg bg-red-100 dark:bg-red-500/20 flex items-center justify-center shrink-0">
                    <WifiOff size={18} className="text-red-600 dark:text-red-400" />
                </div>
                <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-red-800 dark:text-red-300">
                        Scheduled syncs paused — store unreachable
                    </p>
                    <p className="text-xs text-red-600 dark:text-red-400 mt-0.5">
                        {brokenEntities.length > 0
                            ? <>Consecutive failures on: <span className="font-medium capitalize">{brokenEntities.join(', ')}</span>. Scheduler is holding off to prevent memory pressure.</>
                            : 'Too many consecutive failures. Scheduler is holding off to prevent memory pressure.'
                        }
                    </p>
                    {done && (
                        <p className="text-xs text-green-600 dark:text-green-400 mt-1 font-medium">
                            ✓ Resume requested — syncs will begin shortly
                        </p>
                    )}
                </div>
                <button
                    id="resume-syncing-btn"
                    onClick={handleReset}
                    disabled={resetting || done}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold shrink-0 bg-red-600 dark:bg-red-500 text-white hover:bg-red-700 dark:hover:bg-red-600 transition-colors disabled:opacity-60 disabled:cursor-not-allowed"
                >
                    {resetting
                        ? <><Loader2 size={12} className="animate-spin" /> Resuming…</>
                        : done
                            ? <>✓ Done</>
                            : <><PlayCircle size={12} /> Resume Syncing</>
                    }
                </button>
            </div>
        </div>
    );
}

/** Health summary bar showing 24h stats */
function HealthSummaryBar({ summary }: { summary: { lastSuccessAt: string | null; lastFailureAt: string | null; failureRate24h: number; activeJobs: number } }) {
    const failurePercent = Math.round(summary.failureRate24h * 100);
    const isHealthy = failurePercent < 5;
    const isWarning = failurePercent >= 5 && failurePercent < 25;

    return (
        <div className={`
            rounded-xl border p-4 flex items-center gap-4 flex-wrap
            ${isHealthy
                ? 'bg-green-50/50 dark:bg-green-500/5 border-green-200 dark:border-green-500/20'
                : isWarning
                    ? 'bg-amber-50/50 dark:bg-amber-500/5 border-amber-200 dark:border-amber-500/20'
                    : 'bg-red-50/50 dark:bg-red-500/5 border-red-200 dark:border-red-500/20'
            }
        `}>
            <div className="flex items-center gap-2">
                <Activity size={16} className={
                    isHealthy ? 'text-green-600 dark:text-green-400'
                        : isWarning ? 'text-amber-600 dark:text-amber-400'
                            : 'text-red-600 dark:text-red-400'
                } />
                <span className="text-sm font-semibold text-slate-800 dark:text-slate-200">
                    {isHealthy ? 'Healthy' : isWarning ? 'Degraded' : 'Unhealthy'}
                </span>
            </div>

            <div className="h-4 w-px bg-slate-200 dark:bg-slate-700" />

            <div className="flex items-center gap-4 text-xs text-slate-600 dark:text-slate-400">
                <span className="flex items-center gap-1">
                    <TrendingDown size={12} />
                    {failurePercent}% failure rate (24h)
                </span>
                <span>
                    {summary.activeJobs} active {summary.activeJobs === 1 ? 'job' : 'jobs'}
                </span>
                {summary.lastSuccessAt && (
                    <span>
                        Last success: {formatRelativeTime(summary.lastSuccessAt)}
                    </span>
                )}
                {summary.lastFailureAt && (
                    <span className="text-red-500 dark:text-red-400">
                        Last failure: {formatRelativeTime(summary.lastFailureAt)}
                    </span>
                )}
            </div>
        </div>
    );
}

interface EntityCardProps {
    label: string;
    Icon: React.ElementType;
    staleness: 'fresh' | 'stale' | 'critical' | 'never';
    lastSyncedAt: string | null | undefined;
    activeJob?: { id: string; queue: string; progress: number };
    onCancel?: () => void;
    /** Trigger an incremental sync for this entity (omit for full-only entities like BOM) */
    onSyncIncremental?: () => void;
    /** Trigger a full sync for this entity */
    onSyncFull?: () => void;
}

/**
 * Individual data-source card showing sync freshness and
 * direct Incremental / Full sync trigger buttons.
 */
function EntityCard({
    label, Icon, staleness, lastSyncedAt,
    activeJob, onCancel, onSyncIncremental, onSyncFull
}: EntityCardProps) {
    const dotColor = STALENESS_COLORS[staleness];
    const stalenessLabel = STALENESS_LABELS[staleness];
    const isActive = !!activeJob;

    return (
        <div className={`
            relative overflow-hidden rounded-xl border p-4 transition-all duration-300
            ${isActive
                ? 'border-blue-300 dark:border-blue-500/40 bg-blue-50/50 dark:bg-blue-500/5 ring-1 ring-blue-200 dark:ring-blue-500/20'
                : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800/60 hover:border-slate-300 dark:hover:border-slate-600'
            }
        `}>
            {/* Active job progress background fill */}
            {isActive && (
                <div
                    className="absolute inset-y-0 left-0 bg-blue-100/60 dark:bg-blue-500/10 transition-all duration-500"
                    style={{ width: `${activeJob.progress}%` }}
                />
            )}

            <div className="relative z-10">
                <div className="flex items-start justify-between mb-3">
                    <div className="flex items-center gap-2.5">
                        <div className={`
                            w-9 h-9 rounded-lg flex items-center justify-center
                            ${isActive ? 'bg-blue-100 dark:bg-blue-500/20' : 'bg-slate-100 dark:bg-slate-700/60'}
                        `}>
                            {isActive
                                ? <Loader2 size={18} className="animate-spin text-blue-600 dark:text-blue-400" />
                                : <Icon size={18} className="text-slate-600 dark:text-slate-400" />
                            }
                        </div>
                        <div>
                            <p className="text-sm font-semibold text-slate-800 dark:text-slate-200">{label}</p>
                            <div className="flex items-center gap-1.5 mt-0.5">
                                <div className={`w-1.5 h-1.5 rounded-full ${dotColor}`} />
                                <span className="text-[11px] text-slate-500 dark:text-slate-400">
                                    {isActive ? `${activeJob.progress}%` : stalenessLabel}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Cancel button for active jobs */}
                    {isActive && onCancel && (
                        <button
                            onClick={onCancel}
                            className="text-slate-400 hover:text-red-500 dark:hover:text-red-400 transition-colors p-1 rounded-md hover:bg-red-50 dark:hover:bg-red-500/10"
                            title="Cancel sync"
                        >
                            <X size={14} />
                        </button>
                    )}
                </div>

                <div className="flex items-center justify-between">
                    <span className="text-xs text-slate-400 dark:text-slate-500 font-mono">
                        {formatRelativeTime(lastSyncedAt)}
                    </span>
                    {/* Per-entity sync triggers — hidden when already syncing */}
                    {!isActive && (
                        <div className="flex items-center gap-1.5">
                            {onSyncIncremental && (
                                <button
                                    onClick={onSyncIncremental}
                                    className="text-[11px] font-medium px-2.5 py-1 rounded-md transition-all duration-200 bg-slate-100 dark:bg-slate-700/50 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-600/50"
                                    title={`Incremental sync — only fetch changes since last sync`}
                                >
                                    <span className="flex items-center gap-1"><Zap size={10} /> Incremental</span>
                                </button>
                            )}
                            {onSyncFull && (
                                <button
                                    onClick={onSyncFull}
                                    className="text-[11px] font-medium px-2.5 py-1 rounded-md transition-all duration-200 bg-blue-50 dark:bg-blue-500/10 text-blue-600 dark:text-blue-400 hover:bg-blue-100 dark:hover:bg-blue-500/20"
                                    title={`Full sync — re-fetch all data from WooCommerce`}
                                >
                                    <span className="flex items-center gap-1"><RefreshCw size={10} /> Full</span>
                                </button>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Inline progress bar */}
            {isActive && (
                <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-slate-200 dark:bg-slate-700">
                    <div
                        className="h-full bg-blue-500 dark:bg-blue-400 transition-all duration-500 rounded-full"
                        style={{ width: `${activeJob.progress}%` }}
                    />
                </div>
            )}
        </div>
    );
}

/** Filter pills for the log section */
function LogFilterPills({ activeFilter, onFilter }: { activeFilter: string | null; onFilter: (f: string | null) => void }) {
    const filters = [
        { key: null, label: 'All' },
        { key: 'orders', label: 'Orders' },
        { key: 'products', label: 'Products' },
        { key: 'customers', label: 'Customers' },
        { key: 'reviews', label: 'Reviews' },
        { key: 'bom', label: 'BOM' },
    ];

    return (
        <div className="flex items-center gap-1">
            <Filter size={12} className="text-slate-400 dark:text-slate-500 mr-1" />
            {filters.map(f => (
                <button
                    key={f.key ?? 'all'}
                    onClick={() => onFilter(f.key)}
                    className={`
                        text-[11px] font-medium px-2 py-0.5 rounded-md transition-colors
                        ${activeFilter === f.key
                            ? 'bg-blue-100 dark:bg-blue-500/20 text-blue-700 dark:text-blue-400'
                            : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700/50'
                        }
                    `}
                >
                    {f.label}
                </button>
            ))}
        </div>
    );
}

/**
 * Compute a human-readable duration string from two ISO timestamps.
 * Why: helps users tell at a glance whether a sync was fast (< 1s) or
 * suspiciously long, and spot redundant zero-item syncs.
 */
function formatDuration(startedAt: string, completedAt?: string | null): string {
    if (!completedAt) return 'In progress';
    const ms = new Date(completedAt).getTime() - new Date(startedAt).getTime();
    if (ms < 1000) return `${ms}ms`;
    const totalSec = Math.floor(ms / 1000);
    if (totalSec < 60) return `${totalSec}s`;
    const min = Math.floor(totalSec / 60);
    const sec = totalSec % 60;
    return sec > 0 ? `${min}m ${sec}s` : `${min}m`;
}

/** Map trigger source codes to user-friendly labels */
function formatTriggerSource(source?: string): string {
    switch (source) {
        case 'MANUAL': return 'Manual';
        case 'RETRY': return 'Retry';
        case 'WEBHOOK': return 'Webhook';
        case 'SYSTEM':
        default: return 'Scheduled';
    }
}

/** Single log entry row with expandable detail accordion */
function LogEntry({ log, isExpanded, onToggle, onRetry }: {
    log: SyncLog; isExpanded: boolean; onToggle: () => void; onRetry: () => void;
}) {
    const statusConfig = {
        SUCCESS: { icon: CheckCircle, color: 'text-green-500 dark:text-green-400', bg: 'bg-green-50 dark:bg-green-500/10' },
        FAILED: { icon: XCircle, color: 'text-red-500 dark:text-red-400', bg: 'bg-red-50 dark:bg-red-500/10' },
        IN_PROGRESS: { icon: Loader2, color: 'text-blue-500 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-500/10' },
    };

    const cfg = statusConfig[log.status] || statusConfig.SUCCESS;
    const StatusIcon = cfg.icon;
    const hasError = !!log.errorMessage;
    const isFailed = log.status === 'FAILED';

    return (
        <div className={`
            rounded-lg border transition-all duration-200
            ${isFailed
                ? 'border-red-200 dark:border-red-500/20 bg-red-50/30 dark:bg-red-500/5'
                : 'border-slate-100 dark:border-slate-700/50 bg-white dark:bg-slate-800/40'
            }
        `}>
            <div className="flex items-center gap-3 p-3">
                {/* Entire row is clickable to expand detail accordion */}
                <button
                    onClick={onToggle}
                    className="flex items-center gap-3 flex-1 min-w-0 text-left cursor-pointer"
                >
                    <div className={`w-7 h-7 rounded-md flex items-center justify-center shrink-0 ${cfg.bg}`}>
                        <StatusIcon
                            size={14}
                            className={`${cfg.color} ${log.status === 'IN_PROGRESS' ? 'animate-spin' : ''}`}
                        />
                    </div>

                    <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                            <span className="text-sm font-medium text-slate-800 dark:text-slate-200 capitalize">
                                {log.entityType}
                            </span>
                            <span className="text-[11px] text-slate-400 dark:text-slate-500">
                                {formatRelativeTime(log.startedAt)}
                            </span>
                            {log.willRetry && log.nextRetryAt && (
                                <span className="text-[10px] text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-500/10 px-1.5 py-0.5 rounded">
                                    Retry {formatRelativeTime(log.nextRetryAt)}
                                </span>
                            )}
                        </div>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                            {log.itemsProcessed} items
                            {log.completedAt && (
                                <span className="text-slate-400 dark:text-slate-500 ml-1">• {formatDuration(log.startedAt, log.completedAt)}</span>
                            )}
                            {log.friendlyError
                                ? <span className="text-red-500 dark:text-red-400 ml-1">• {log.friendlyError}</span>
                                : isFailed && <span className="text-red-500 dark:text-red-400 ml-1">• Failed</span>
                            }
                        </p>
                    </div>
                </button>

                {/* Action buttons */}
                <div className="flex items-center gap-1 shrink-0">
                    {isFailed && (
                        <button
                            onClick={onRetry}
                            className="flex items-center gap-1 px-2 py-1 text-[11px] font-medium text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-500/10 hover:bg-blue-100 dark:hover:bg-blue-500/20 rounded-md transition-colors"
                            title="Retry this sync"
                        >
                            <RotateCcw size={11} />
                            Retry
                        </button>
                    )}
                    <button onClick={onToggle} className="p-1">
                        {isExpanded
                            ? <ChevronUp size={14} className="text-slate-400 dark:text-slate-500" />
                            : <ChevronDown size={14} className="text-slate-400 dark:text-slate-500" />
                        }
                    </button>
                </div>
            </div>

            {/* Expanded detail accordion — shows for ALL statuses, not just errors */}
            {isExpanded && (
                <div className={`border-t px-3 py-2.5 space-y-2 ${isFailed
                    ? 'border-red-100 dark:border-red-500/10 bg-red-50/30 dark:bg-red-500/5'
                    : 'border-slate-100 dark:border-slate-700/50 bg-slate-50/50 dark:bg-slate-800/30'
                    }`}>
                    {/* Sync details grid */}
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                        <div>
                            <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wider">Items</p>
                            <p className="text-xs font-semibold text-slate-700 dark:text-slate-300">{log.itemsProcessed}</p>
                        </div>
                        <div>
                            <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wider">Duration</p>
                            <p className="text-xs font-semibold text-slate-700 dark:text-slate-300">{formatDuration(log.startedAt, log.completedAt)}</p>
                        </div>
                        <div>
                            <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wider">Trigger</p>
                            <p className="text-xs font-semibold text-slate-700 dark:text-slate-300">{formatTriggerSource(log.triggerSource)}</p>
                        </div>
                        {(log.retryCount ?? 0) > 0 && (
                            <div>
                                <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wider">Attempt</p>
                                <p className="text-xs font-semibold text-slate-700 dark:text-slate-300">{(log.retryCount ?? 0) + 1}{log.maxAttempts ? ` / ${log.maxAttempts}` : ''}</p>
                            </div>
                        )}
                    </div>

                    {/* Timestamps */}
                    <div className="flex items-center gap-4 text-[10px] text-slate-400 dark:text-slate-500 font-mono">
                        <span>Started: {new Date(log.startedAt).toLocaleTimeString()}</span>
                        {log.completedAt && <span>Finished: {new Date(log.completedAt).toLocaleTimeString()}</span>}
                    </div>

                    {/* Error details (only for failed syncs) */}
                    {hasError && (
                        <div className="flex items-start gap-2 mt-1 pt-2 border-t border-red-100 dark:border-red-500/10">
                            <AlertTriangle size={12} className="text-red-500 dark:text-red-400 mt-0.5 shrink-0" />
                            <pre className="text-xs text-red-700 dark:text-red-300 font-mono whitespace-pre-wrap break-all">
                                {log.errorMessage}
                            </pre>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

import { ReactNode, useEffect, useRef, useState } from 'react';
import { X } from 'lucide-react';

/**
 * BottomSheet - iOS-style bottom sheet component.
 * 
 * Features:
 * - Slide up animation
 * - Drag to dismiss
 * - Backdrop click to close
 * - snap points support
 */

interface BottomSheetProps {
    isOpen: boolean;
    onClose: () => void;
    title?: string;
    children: ReactNode;
    snapPoints?: number[];
}

export function BottomSheet({ isOpen, onClose, title, children, snapPoints = [0.5] }: BottomSheetProps) {
    const sheetRef = useRef<HTMLDivElement>(null);
    const [dragY, setDragY] = useState(0);
    const [startY, setStartY] = useState(0);
    const [isDragging, setIsDragging] = useState(false);

    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
        }
        return () => {
            document.body.style.overflow = '';
        };
    }, [isOpen]);

    const handleTouchStart = (e: React.TouchEvent) => {
        setStartY(e.touches[0].clientY);
        setIsDragging(true);
    };

    const handleTouchMove = (e: React.TouchEvent) => {
        if (!isDragging) return;
        const currentY = e.touches[0].clientY;
        const diff = currentY - startY;
        if (diff > 0) {
            setDragY(diff);
        }
    };

    const handleTouchEnd = () => {
        setIsDragging(false);
        if (dragY > 100) {
            // Haptic feedback
            if ('vibrate' in navigator) {
                navigator.vibrate(10);
            }
            onClose();
        }
        setDragY(0);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100]">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/50 transition-opacity"
                style={{ opacity: Math.max(0, 1 - dragY / 200) }}
                onClick={onClose}
            />

            {/* Sheet */}
            <div
                ref={sheetRef}
                className="absolute bottom-0 left-0 right-0 bg-white rounded-t-3xl max-h-[90vh] overflow-hidden"
                style={{
                    transform: `translateY(${dragY}px)`,
                    transition: isDragging ? 'none' : 'transform 0.3s ease-out',
                    paddingBottom: 'env(safe-area-inset-bottom)'
                }}
            >
                {/* Handle */}
                <div
                    className="flex justify-center pt-3 pb-2 cursor-grab active:cursor-grabbing"
                    onTouchStart={handleTouchStart}
                    onTouchMove={handleTouchMove}
                    onTouchEnd={handleTouchEnd}
                >
                    <div className="w-10 h-1 bg-gray-300 rounded-full" />
                </div>

                {/* Header */}
                {title && (
                    <div className="flex items-center justify-between px-4 pb-3 border-b border-gray-100">
                        <h2 className="text-lg font-bold text-gray-900">{title}</h2>
                        <button
                            onClick={onClose}
                            className="p-2 -mr-2 rounded-full hover:bg-gray-100 active:bg-gray-200"
                        >
                            <X size={20} className="text-gray-500" />
                        </button>
                    </div>
                )}

                {/* Content */}
                <div className="overflow-y-auto max-h-[70vh] p-4">
                    {children}
                </div>
            </div>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { Command } from 'cmdk';
import { useNavigate } from 'react-router-dom';
import { Search, Package, FileText, Settings, LayoutDashboard, Truck, Users, BarChart2, Sparkles } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useCommandPalette } from '../../hooks/useCommandPalette';

interface SearchResult {
    id: string | number;
    title: string;
    subtitle?: string;
    type: 'product' | 'order' | 'customer' | 'semantic';
    similarity?: number;
}

export function CommandPalette() {
    const { isOpen, close } = useCommandPalette();
    const [query, setQuery] = useState('');
    const [results, setResults] = useState<SearchResult[]>([]);
    const [semanticResults, setSemanticResults] = useState<SearchResult[]>([]);
    const [loading, setLoading] = useState(false);
    const [semanticMode, setSemanticMode] = useState(false);
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === 'k' && (e.metaKey || e.ctrlKey)) {
                e.preventDefault();
                // Toggle handled by context - we just need to import toggle
                const event = new CustomEvent('commandpalette:toggle');
                window.dispatchEvent(event);
            }
        };

        document.addEventListener('keydown', down);
        return () => document.removeEventListener('keydown', down);
    }, []);

    // Reset query when closing
    useEffect(() => {
        if (!isOpen) {
            setQuery('');
            setResults([]);
            setSemanticResults([]);
        }
    }, [isOpen]);

    useEffect(() => {
        if (!query || !token || !currentAccount) {
            setResults([]);
            setSemanticResults([]);
            return;
        }

        const timer = setTimeout(async () => {
            setLoading(true);
            try {
                if (query.length < 2) return;

                const searches: Promise<Response>[] = [
                    // Use unified global search endpoint
                    fetch(`/api/search/global?q=${encodeURIComponent(query)}`, {
                        headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
                    })
                ];

                // Add semantic search if mode is enabled and query is descriptive
                if (semanticMode && query.length >= 3) {
                    searches.push(
                        fetch(`/api/search/semantic?q=${encodeURIComponent(query)}&limit=5`, {
                            headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
                        })
                    );
                }

                const [globalRes, semanticRes] = await Promise.allSettled(searches);

                const newResults: SearchResult[] = [];

                // Parse unified global search results
                if (globalRes.status === 'fulfilled' && globalRes.value.ok) {
                    const data = await globalRes.value.json();

                    // Products
                    if (data.products) {
                        newResults.push(...data.products.slice(0, 5).map((p: any) => ({
                            id: p.id,
                            title: p.name,
                            subtitle: p.sku ? `SKU: ${p.sku}` : undefined,
                            type: 'product' as const
                        })));
                    }

                    // Orders
                    if (data.orders) {
                        newResults.push(...data.orders.slice(0, 5).map((o: any) => ({
                            id: o.id,
                            title: `Order #${o.number || o.id}`,
                            subtitle: o.status,
                            type: 'order' as const
                        })));
                    }

                    // Customers
                    if (data.customers) {
                        newResults.push(...data.customers.slice(0, 5).map((c: any) => ({
                            id: c.id,
                            title: `${c.firstName || ''} ${c.lastName || ''}`.trim() || c.email,
                            subtitle: c.email,
                            type: 'customer' as const
                        })));
                    }
                }

                setResults(newResults);

                // Handle semantic results separately
                if (semanticRes && semanticRes.status === 'fulfilled' && semanticRes.value.ok) {
                    const data = await semanticRes.value.json();
                    if (Array.isArray(data)) {
                        setSemanticResults(data.map((r: any) => ({
                            id: r.id,
                            title: r.name,
                            subtitle: `${Math.round(r.similarity * 100)}% match`,
                            type: 'semantic' as const,
                            similarity: r.similarity
                        })));
                    }
                } else {
                    setSemanticResults([]);
                }
            } catch (err) {
                Logger.error('Search failed', { error: err });
            } finally {
                setLoading(false);
            }
        }, 300);

        return () => clearTimeout(timer);
    }, [query, token, currentAccount, semanticMode]);

    const runCommand = (command: () => void) => {
        close();
        command();
    };


    if (!isOpen) return null;

    return (
        <Command.Dialog
            open={isOpen}
            onOpenChange={(open) => !open && close()}
            label="Global Command Menu"
            shouldFilter={false}
            className="fixed inset-0 z-[100] flex items-start justify-center pt-[15vh] bg-slate-900/40 backdrop-blur-sm transition-all animate-in fade-in duration-200"
            onClick={(e) => {
                if (e.target === e.currentTarget) close();
            }}
        >
            <div className="w-full max-w-2xl bg-white/95 dark:bg-slate-900/95 backdrop-blur-2xl rounded-2xl shadow-2xl shadow-black/20 border border-slate-200/50 dark:border-slate-800 overflow-hidden animate-in zoom-in-95 duration-200 ring-1 ring-black/5 dark:ring-white/5 relative transform">
                {/* Gradient accent top line */}
                <div className={`absolute top-0 left-0 right-0 h-1 bg-gradient-to-r transition-all duration-500 ${semanticMode ? 'from-purple-500 via-fuchsia-500 to-purple-500' : 'from-blue-500 via-cyan-500 to-blue-500'}`} />

                <div className="flex items-center border-b border-slate-200/60 dark:border-slate-800 px-5 pt-3 pb-2">
                    <Search className={`w-5 h-5 mr-3 transition-colors ${semanticMode ? 'text-purple-500' : 'text-slate-400'}`} />
                    <Command.Input
                        value={query}
                        onValueChange={setQuery}
                        placeholder={semanticMode ? "Ask AI to find anything..." : "Type a command or search..."}
                        className="flex-1 h-12 bg-transparent outline-none text-lg text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-slate-500 font-medium w-full border-none focus:ring-0"
                    />
                    <div className="flex gap-2 items-center">
                        <button
                            type="button"
                            onClick={() => setSemanticMode(!semanticMode)}
                            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold transition-all duration-300 ${semanticMode
                                ? 'bg-purple-100 dark:bg-purple-500/20 text-purple-700 dark:text-purple-300 border border-purple-200 dark:border-purple-500/30'
                                : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 border border-slate-200 dark:border-slate-700 hover:bg-slate-200 dark:hover:bg-slate-700'
                                }`}
                            title="Toggle AI Smart Search"
                        >
                            <Sparkles size={12} className={semanticMode ? 'animate-pulse' : ''} />
                            AI
                        </button>
                        <kbd className="hidden sm:inline-flex h-6 select-none items-center gap-1 rounded-md border border-slate-200 dark:border-slate-700 bg-slate-100 dark:bg-slate-800 px-2 font-mono text-[10px] font-medium text-slate-500 dark:text-slate-400 pointer-events-none">
                            <span className="text-xs">
                                {navigator.platform.indexOf('Mac') > -1 ? '⌘' : 'Ctrl'}
                            </span>K
                        </kbd>
                    </div>
                </div>

                <Command.List className="max-h-[60vh] overflow-y-auto p-2 scroll-py-2 custom-scrollbar">
                    {loading && (
                        <div className="py-8 text-center text-sm text-slate-500 dark:text-slate-400 flex items-center justify-center gap-2">
                            <div className={`w-5 h-5 border-2 rounded-full animate-spin border-t-transparent ${semanticMode ? 'border-purple-500' : 'border-blue-500'}`} />
                            {semanticMode ? 'AI Searching...' : 'Searching...'}
                        </div>
                    )}

                    {!loading && results.length === 0 && semanticResults.length === 0 && query !== '' && (
                        <Command.Empty className="py-8 text-center text-sm text-slate-500 dark:text-slate-400">
                            {semanticMode ? 'No AI matches found. Try described it differently.' : 'No results found.'}
                        </Command.Empty>
                    )}

                    {query === '' && (
                        <Command.Group heading="Navigation" className="text-xs font-semibold text-slate-400 dark:text-slate-500 mb-2 px-2 uppercase tracking-wider py-2">
                            <div className="space-y-1">
                                <CommandItem onSelect={() => runCommand(() => navigate('/dashboard'))}>
                                    <LayoutDashboard className="w-4 h-4 mr-3" />
                                    <span>Dashboard</span>
                                </CommandItem>

                                <CommandItem onSelect={() => runCommand(() => navigate('/inventory'))}>
                                    <Package className="w-4 h-4 mr-3" />
                                    <span>Inventory</span>
                                </CommandItem>

                                <CommandItem onSelect={() => runCommand(() => navigate('/orders'))}>
                                    <FileText className="w-4 h-4 mr-3" />
                                    <span>Orders</span>
                                </CommandItem>

                                <CommandItem onSelect={() => runCommand(() => navigate('/customers'))}>
                                    <Users className="w-4 h-4 mr-3" />
                                    <span>Customers</span>
                                </CommandItem>

                                <CommandItem onSelect={() => runCommand(() => navigate('/reports'))}>
                                    <BarChart2 className="w-4 h-4 mr-3" />
                                    <span>Reports</span>
                                </CommandItem>

                                <CommandItem onSelect={() => runCommand(() => navigate('/settings'))}>
                                    <Settings className="w-4 h-4 mr-3" />
                                    <span>Settings</span>
                                </CommandItem>
                            </div>
                        </Command.Group>
                    )}

                    {results.length > 0 && (
                        <Command.Group heading="Top Results" className="text-xs font-semibold text-slate-400 dark:text-slate-500 mt-2 px-2 uppercase tracking-wider py-2">
                            <div className="space-y-1">
                                {results.map((result) => (
                                    <CommandItem
                                        key={`${result.type}-${result.id}`}
                                        onSelect={() => runCommand(() => {
                                            if (result.type === 'product') {
                                                navigate(`/inventory/product/${result.id}`);
                                            } else if (result.type === 'customer') {
                                                navigate(`/customers/${result.id}`);
                                            } else {
                                                navigate(`/orders/${result.id}`);
                                            }
                                        })}
                                    >
                                        {result.type === 'product' ? (
                                            <Package className="w-4 h-4 mr-3 text-blue-500 dark:text-blue-400" />
                                        ) : result.type === 'customer' ? (
                                            <Users className="w-4 h-4 mr-3 text-amber-500 dark:text-amber-400" />
                                        ) : (
                                            <FileText className="w-4 h-4 mr-3 text-emerald-500 dark:text-emerald-400" />
                                        )}
                                        <div className="flex flex-col">
                                            <span className="font-medium text-slate-900 dark:text-white">{result.title}</span>
                                            {result.subtitle && <span className="text-xs text-slate-500 dark:text-slate-400 font-normal">{result.subtitle}</span>}
                                        </div>
                                    </CommandItem>
                                ))}
                            </div>
                        </Command.Group>
                    )}

                    {semanticResults.length > 0 && (
                        <Command.Group heading="AI Smart Matches" className="text-xs font-semibold text-purple-600 dark:text-purple-400 mt-2 px-2 uppercase tracking-wider py-2">
                            <div className="space-y-1">
                                {semanticResults.map((result) => (
                                    <CommandItem
                                        key={`semantic-${result.id}`}
                                        onSelect={() => runCommand(() => navigate(`/inventory/product/${result.id}`))}
                                    >
                                        <Sparkles className="w-4 h-4 mr-3 text-purple-500 dark:text-purple-400" />
                                        <div className="flex flex-col flex-1">
                                            <span className="font-medium text-slate-900 dark:text-white">{result.title}</span>
                                            <span className="text-xs text-purple-600 dark:text-purple-300 font-normal">{result.subtitle}</span>
                                        </div>
                                    </CommandItem>
                                ))}
                            </div>
                        </Command.Group>
                    )}
                </Command.List>
            </div>
        </Command.Dialog>
    );
}

// Wrapper for Command.Item with consistent styling
function CommandItem({ children, onSelect }: { children: React.ReactNode, onSelect: () => void }) {
    return (
        <Command.Item
            onSelect={onSelect}
            className="flex items-center px-4 py-3.5 rounded-xl text-sm text-slate-700 dark:text-slate-300 cursor-pointer select-none aria-selected:bg-blue-50 dark:aria-selected:bg-blue-900/20 aria-selected:text-blue-700 dark:aria-selected:text-blue-400 data-[selected=true]:bg-blue-50 dark:data-[selected=true]:bg-blue-900/20 data-[selected=true]:text-blue-700 dark:data-[selected=true]:text-blue-400 transition-colors"
        >
            <>{children}</>
        </Command.Item>
    );
}

import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';
import { cn } from '../../utils/cn';

interface PaginationProps {
    currentPage: number;
    totalPages: number;
    onPageChange: (page: number) => void;
    itemsPerPage?: number;
    onItemsPerPageChange?: (limit: number) => void;
    allowItemsPerPage?: boolean;
    className?: string;
}

export function Pagination({
    currentPage,
    totalPages,
    onPageChange,
    itemsPerPage,
    onItemsPerPageChange,
    allowItemsPerPage = false,
    className
}: PaginationProps) {
    const isFirstPage = currentPage <= 1;
    const isLastPage = currentPage >= totalPages;

    const Button = ({
        onClick,
        disabled,
        children,
        title
    }: {
        onClick: () => void;
        disabled: boolean;
        children: React.ReactNode;
        title: string;
    }) => (
        <button
            onClick={onClick}
            disabled={disabled}
            title={title}
            className={cn(
                "p-2 border border-slate-200 rounded-lg text-slate-600 bg-white hover:bg-slate-50 transition-colors disabled:opacity-50 disabled:cursor-not-allowed",
                "focus:outline-hidden focus:ring-2 focus:ring-blue-500/20"
            )}
        >
            {children}
        </button>
    );

    return (
        <div className={cn("flex flex-wrap items-center justify-between gap-4 p-4 pr-24 bg-slate-50 border-t border-slate-100", className)}>
            {/* Items Per Page Selector */}
            <div className="flex items-center gap-2 text-sm text-slate-600">
                {allowItemsPerPage && itemsPerPage && onItemsPerPageChange && (
                    <>
                        <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Rows:</span>
                        <select
                            value={itemsPerPage}
                            onChange={(e) => onItemsPerPageChange(Number(e.target.value))}
                            className="bg-white border border-slate-200 text-slate-700 text-sm rounded-md focus:ring-blue-500 focus:border-blue-500 block p-1.5 outline-hidden"
                        >
                            {[15, 25, 50, 100].map((pageSize) => (
                                <option key={pageSize} value={pageSize}>
                                    {pageSize}
                                </option>
                            ))}
                        </select>
                    </>
                )}
            </div>

            {/* Pagination Controls */}
            <div className="flex items-center gap-2">
                <Button
                    onClick={() => onPageChange(1)}
                    disabled={isFirstPage}
                    title="First Page"
                >
                    <ChevronsLeft size={16} />
                </Button>

                <Button
                    onClick={() => onPageChange(currentPage - 1)}
                    disabled={isFirstPage}
                    title="Previous Page"
                >
                    <ChevronLeft size={16} />
                </Button>

                <span className="text-sm font-medium text-slate-600 min-w-[100px] text-center">
                    Page <span className="text-slate-900">{currentPage}</span> of <span className="text-slate-900">{Math.max(1, totalPages)}</span>
                </span>

                <Button
                    onClick={() => onPageChange(currentPage + 1)}
                    disabled={isLastPage}
                    title="Next Page"
                >
                    <ChevronRight size={16} />
                </Button>

                <Button
                    onClick={() => onPageChange(totalPages)}
                    disabled={isLastPage}
                    title="Last Page"
                >
                    <ChevronsRight size={16} />
                </Button>
            </div>
        </div>
    );
}

import { useState, useRef, useEffect, useCallback } from 'react';
import { Bookmark, ChevronDown, Plus, Trash2, X, Check } from 'lucide-react';
import { cn } from '../../utils/cn';
import { useSavedViews, SavedView } from '../../hooks/useSavedViews';
import { Toast, ToastType } from './Toast';

interface SavedViewsDropdownProps {
    /** Context for the saved views (e.g., 'orders', 'customers') */
    context: string;
    /** Current filter state to save when creating a new view */
    currentFilters: Record<string, unknown>;
    /** Callback when a view is applied */
    onApplyView: (filters: Record<string, unknown>) => void;
    /** Additional CSS classes */
    className?: string;
}

/**
 * SavedViewsDropdown - UI for managing saved filter presets.
 * Allows users to save, select, rename, and delete filter views.
 * 
 * @example
 * <SavedViewsDropdown
 *   context="orders"
 *   currentFilters={{ status: 'processing', tags: ['priority'] }}
 *   onApplyView={(filters) => setFilters(filters)}
 * />
 */
export function SavedViewsDropdown({
    context,
    currentFilters,
    onApplyView,
    className
}: SavedViewsDropdownProps) {
    const { views, activeView, saveCurrentView, applyView, removeView, clearActiveView } = useSavedViews(context);

    const [isOpen, setIsOpen] = useState(false);
    const [isCreating, setIsCreating] = useState(false);
    const [newViewName, setNewViewName] = useState('');
    const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    const dropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    // Close dropdown when clicking outside
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                setIsCreating(false);
                setConfirmDeleteId(null);
            }
        }

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    // Focus input when creating
    useEffect(() => {
        if (isCreating && inputRef.current) {
            inputRef.current.focus();
        }
    }, [isCreating]);

    const handleSaveView = () => {
        if (!newViewName.trim()) { showToast('View name is required'); return; }

        const savedView = saveCurrentView(newViewName.trim(), currentFilters);
        setNewViewName('');
        setIsCreating(false);
        showToast('View saved', 'success');
    };

    const handleApplyView = (view: SavedView) => {
        applyView(view.id);
        onApplyView(view.filters);
        setIsOpen(false);
    };

    const handleClearView = () => {
        clearActiveView();
        setIsOpen(false);
    };

    const handleDeleteView = (viewId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (confirmDeleteId === viewId) {
            removeView(viewId);
            setConfirmDeleteId(null);
        } else {
            setConfirmDeleteId(viewId);
        }
    };

    const hasActiveFilters = Object.values(currentFilters).some(
        (v) => v !== null && v !== undefined && v !== '' && v !== 'all' &&
            !(Array.isArray(v) && v.length === 0)
    );

    return (
        <>
            <div ref={dropdownRef} className={cn("relative", className)}>
                {/* Trigger Button */}
                <button
                    onClick={() => setIsOpen(!isOpen)}
                    className={cn(
                        "flex items-center gap-2 px-3 py-2 rounded-lg border transition-all text-sm font-medium",
                        activeView
                            ? "bg-blue-50 border-blue-200 text-blue-700 hover:bg-blue-100"
                            : "bg-white border-gray-300 text-gray-700 hover:bg-gray-50"
                    )}
                >
                    <Bookmark size={16} className={activeView ? "fill-blue-600" : ""} />
                    <span className="hidden sm:inline">
                        {activeView ? activeView.name : 'Saved Views'}
                    </span>
                    {views.length > 0 && !activeView && (
                        <span className="bg-gray-200 text-gray-600 text-xs px-1.5 py-0.5 rounded-full">
                            {views.length}
                        </span>
                    )}
                    <ChevronDown
                        size={14}
                        className={cn("transition-transform", isOpen && "rotate-180")}
                    />
                </button>

                {/* Dropdown Menu */}
                {isOpen && (
                    <div className="absolute right-0 mt-2 w-72 bg-white border border-gray-200 rounded-xl shadow-lg z-30 overflow-hidden">
                        {/* Header */}
                        <div className="px-4 py-3 border-b border-gray-100 bg-gray-50">
                            <div className="flex items-center justify-between">
                                <span className="text-xs font-semibold text-gray-500 uppercase tracking-wide">
                                    Saved Views
                                </span>
                                {activeView && (
                                    <button
                                        onClick={handleClearView}
                                        className="text-xs text-blue-600 hover:underline"
                                    >
                                        Clear filter
                                    </button>
                                )}
                            </div>
                        </div>

                        {/* Views List */}
                        <div className="max-h-64 overflow-y-auto">
                            {views.length === 0 && !isCreating ? (
                                <div className="px-4 py-6 text-center text-gray-500">
                                    <Bookmark size={24} className="mx-auto mb-2 text-gray-300" />
                                    <p className="text-sm">No saved views yet</p>
                                    <p className="text-xs text-gray-400 mt-1">
                                        Save your current filters for quick access
                                    </p>
                                </div>
                            ) : (
                                views.map((view) => (
                                    <div
                                        key={view.id}
                                        onClick={() => handleApplyView(view)}
                                        className={cn(
                                            "flex items-center justify-between px-4 py-3 cursor-pointer transition-colors group",
                                            activeView?.id === view.id
                                                ? "bg-blue-50"
                                                : "hover:bg-gray-50"
                                        )}
                                    >
                                        <div className="flex items-center gap-3 min-w-0">
                                            {activeView?.id === view.id && (
                                                <Check size={14} className="text-blue-600 shrink-0" />
                                            )}
                                            <div className="min-w-0">
                                                <p className={cn(
                                                    "text-sm font-medium truncate",
                                                    activeView?.id === view.id ? "text-blue-700" : "text-gray-900"
                                                )}>
                                                    {view.name}
                                                </p>
                                                {view.isDefault && (
                                                    <span className="text-xs text-gray-400">Default</span>
                                                )}
                                            </div>
                                        </div>

                                        {!view.isDefault && (
                                            <button
                                                onClick={(e) => handleDeleteView(view.id, e)}
                                                className={cn(
                                                    "p-1.5 rounded transition-colors shrink-0",
                                                    confirmDeleteId === view.id
                                                        ? "bg-red-100 text-red-600"
                                                        : "text-gray-400 hover:text-red-500 hover:bg-red-50 opacity-0 group-hover:opacity-100"
                                                )}
                                                title={confirmDeleteId === view.id ? "Click again to confirm" : "Delete view"}
                                            >
                                                <Trash2 size={14} />
                                            </button>
                                        )}
                                    </div>
                                ))
                            )}
                        </div>

                        {/* Create New View */}
                        <div className="border-t border-gray-100">
                            {isCreating ? (
                                <div className="px-4 py-3">
                                    <div className="flex items-center gap-2">
                                        <input
                                            ref={inputRef}
                                            type="text"
                                            value={newViewName}
                                            onChange={(e) => setNewViewName(e.target.value)}
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter') handleSaveView();
                                                if (e.key === 'Escape') {
                                                    setIsCreating(false);
                                                    setNewViewName('');
                                                }
                                            }}
                                            placeholder="View name..."
                                            className="flex-1 px-3 py-2 text-sm border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                        />
                                        <button
                                            onClick={handleSaveView}
                                            disabled={!newViewName.trim()}
                                            className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                                        >
                                            <Check size={16} />
                                        </button>
                                        <button
                                            onClick={() => {
                                                setIsCreating(false);
                                                setNewViewName('');
                                            }}
                                            className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                                        >
                                            <X size={16} />
                                        </button>
                                    </div>
                                </div>
                            ) : (
                                <button
                                    onClick={() => setIsCreating(true)}
                                    disabled={!hasActiveFilters}
                                    className={cn(
                                        "w-full flex items-center gap-2 px-4 py-3 text-sm font-medium transition-colors",
                                        hasActiveFilters
                                            ? "text-blue-600 hover:bg-blue-50"
                                            : "text-gray-400 cursor-not-allowed"
                                    )}
                                >
                                    <Plus size={16} />
                                    Save current view
                                </button>
                            )}
                        </div>
                    </div>
                )}
            </div>

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </>);
}

import { cn } from '../../utils/cn';

interface SkeletonProps {
    /** Additional CSS classes */
    className?: string;
    /** Width (e.g., 'w-24', '100px') */
    width?: string;
    /** Height (e.g., 'h-4', '20px') */
    height?: string;
    /** Whether to use rounded corners */
    rounded?: 'none' | 'sm' | 'md' | 'lg' | 'full';
}

/**
 * Skeleton - Base animated placeholder for loading states.
 * Use instead of spinners for data-heavy screens to improve perceived performance.
 * 
 * @example
 * <Skeleton className="w-32 h-4" />
 */
export function Skeleton({
    className,
    width,
    height,
    rounded = 'md'
}: SkeletonProps) {
    const roundedClasses = {
        none: '',
        sm: 'rounded-sm',
        md: 'rounded-md',
        lg: 'rounded-lg',
        full: 'rounded-full'
    };

    return (
        <div
            className={cn(
                "animate-pulse bg-gradient-to-r from-slate-200 via-slate-100 to-slate-200 dark:from-slate-700 dark:via-slate-600 dark:to-slate-700 bg-[length:200%_100%]",
                roundedClasses[rounded],
                className
            )}
            style={{
                width: width || undefined,
                height: height || undefined
            }}
        />
    );
}

/**
 * SkeletonText - Text line placeholder with realistic proportions
 */
export function SkeletonText({
    lines = 1,
    className
}: {
    lines?: number;
    className?: string;
}) {
    return (
        <div className={cn("space-y-2", className)}>
            {Array.from({ length: lines }).map((_, i) => (
                <Skeleton
                    key={i}
                    className={cn(
                        "h-4",
                        // Last line is shorter for realism
                        i === lines - 1 && lines > 1 ? "w-3/4" : "w-full"
                    )}
                />
            ))}
        </div>
    );
}

/**
 * SkeletonAvatar - Circular avatar placeholder
 */
export function SkeletonAvatar({
    size = 'md',
    className
}: {
    size?: 'sm' | 'md' | 'lg';
    className?: string;
}) {
    const sizeClasses = {
        sm: 'w-8 h-8',
        md: 'w-10 h-10',
        lg: 'w-12 h-12'
    };

    return (
        <Skeleton
            className={cn(sizeClasses[size], className)}
            rounded="full"
        />
    );
}

/**
 * TableRowSkeleton - Complete table row skeleton for data tables
 */
export function TableRowSkeleton({
    columns = 5,
    className,
    showAvatar = false
}: {
    columns?: number;
    className?: string;
    showAvatar?: boolean;
}) {
    return (
        <tr className={cn("animate-pulse", className)}>
            {Array.from({ length: columns }).map((_, i) => (
                <td key={i} className="px-6 py-4">
                    {i === 0 && showAvatar ? (
                        <div className="flex items-center gap-3">
                            <SkeletonAvatar size="md" />
                            <div className="space-y-2">
                                <Skeleton className="h-4 w-24" />
                                <Skeleton className="h-3 w-32" />
                            </div>
                        </div>
                    ) : (
                        <Skeleton
                            className="h-4"
                            width={`${60 + Math.random() * 40}%`}
                        />
                    )}
                </td>
            ))}
        </tr>
    );
}

/**
 * TableSkeleton - Multiple rows of table skeletons
 */
export function TableSkeleton({
    rows = 5,
    columns = 5,
    showAvatar = false
}: {
    rows?: number;
    columns?: number;
    showAvatar?: boolean;
}) {
    return (
        <>
            {Array.from({ length: rows }).map((_, i) => (
                <TableRowSkeleton
                    key={i}
                    columns={columns}
                    showAvatar={showAvatar}
                />
            ))}
        </>
    );
}

/**
 * CardSkeleton - Dashboard card loading state
 */
export function CardSkeleton({ className }: { className?: string }) {
    return (
        <div className={cn(
            "bg-white dark:bg-slate-800/90 rounded-2xl border border-slate-200/80 dark:border-slate-700/50 p-6 animate-pulse",
            "shadow-[0_1px_3px_rgba(0,0,0,0.05),0_1px_2px_rgba(0,0,0,0.03)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)]",
            className
        )}>
            <div className="flex items-center justify-between mb-4">
                <Skeleton className="h-5 w-32" />
                <Skeleton className="h-10 w-10" rounded="lg" />
            </div>
            <Skeleton className="h-8 w-24 mb-2" />
            <Skeleton className="h-4 w-28" />
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';
import { Globe, Monitor, Smartphone, Tablet, Clock } from 'lucide-react';
import { WidgetProps } from './WidgetRegistry';

interface StatsData {
    countries: { country: string; sessions: number }[];
    devices: { type: string; sessions: number }[];
    browsers: { name: string; sessions: number }[];
    totalSessions: number;
    avgSessionDuration: number;
}

interface AnalyticsStatsWidgetProps {
    days?: number;
}

export const AnalyticsStatsWidget = ({ className, dateRange }: WidgetProps) => {
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const [stats, setStats] = useState<StatsData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            if (!currentAccount || !token) return;
            try {
                const data = await api.get<StatsData>(`/api/tracking/stats?startDate=${dateRange.startDate}&endDate=${dateRange.endDate}`, token, currentAccount.id);
                setStats(data);
            } catch (error) {
                Logger.error('Failed to fetch stats:', { error: error });
            } finally {
                setLoading(false);
            }
        };
        fetchStats();
    }, [currentAccount, token, dateRange]);

    if (loading) {
        return <div className={`p-4 text-sm text-slate-500 dark:text-slate-400 ${className}`}>Loading stats...</div>;
    }

    if (!stats) {
        return <div className={`p-4 text-sm text-slate-500 dark:text-slate-400 ${className}`}>No data available</div>;
    }

    const formatDuration = (seconds: number) => {
        if (seconds < 60) return `${seconds}s`;
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}m ${secs}s`;
    };

    const getDeviceIcon = (type: string) => {
        switch (type) {
            case 'mobile': return <Smartphone className="w-4 h-4" />;
            case 'tablet': return <Tablet className="w-4 h-4" />;
            default: return <Monitor className="w-4 h-4" />;
        }
    };

    return (
        <div className={`p-4 space-y-4 ${className}`}>
            {/* Summary Stats */}
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg p-3">
                    <div className="text-xs text-blue-600 dark:text-blue-400 font-medium">Total Sessions</div>
                    <div className="text-2xl font-bold text-blue-700 dark:text-blue-300">{stats.totalSessions.toLocaleString()}</div>
                </div>
                <div className="bg-purple-50 dark:bg-purple-900/20 rounded-lg p-3">
                    <div className="text-xs text-purple-600 dark:text-purple-400 font-medium flex items-center gap-1">
                        <Clock className="w-3 h-3" /> Avg Duration
                    </div>
                    <div className="text-2xl font-bold text-purple-700 dark:text-purple-300">{formatDuration(stats.avgSessionDuration)}</div>
                </div>
            </div>

            {/* Top Countries */}
            <div>
                <div className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2 flex items-center gap-1">
                    <Globe className="w-3 h-3" /> Top Countries
                </div>
                <div className="space-y-1">
                    {stats.countries.slice(0, 5).map((c, i) => (
                        <div key={c.country} className="flex items-center justify-between text-sm">
                            <span className="text-slate-700 dark:text-slate-300">{c.country}</span>
                            <span className="text-slate-500 dark:text-slate-400">{c.sessions}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Devices */}
            <div>
                <div className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2">Devices</div>
                <div className="flex gap-2">
                    {stats.devices.map(d => (
                        <div key={d.type} className="flex items-center gap-1 px-2 py-1 bg-slate-100 dark:bg-slate-700 rounded-sm text-xs text-slate-600 dark:text-slate-300">
                            {getDeviceIcon(d.type)}
                            <span className="capitalize">{d.type}</span>
                            <span className="text-slate-400 dark:text-slate-500">({d.sessions})</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Top Browsers */}
            <div>
                <div className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase mb-2">Browsers</div>
                <div className="flex flex-wrap gap-1">
                    {stats.browsers.slice(0, 5).map(b => (
                        <span key={b.name} className="px-2 py-0.5 bg-slate-100 dark:bg-slate-700 rounded-sm text-xs text-slate-600 dark:text-slate-300">
                            {b.name} ({b.sessions})
                        </span>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default AnalyticsStatsWidget;

