import { useState, useCallback } from 'react';
import { useVisibilityPolling } from '../../hooks/useVisibilityPolling';
import { Logger } from '../../utils/logger';
import { ShoppingCart, CreditCard, LogOut, CheckCircle } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface AnalyticsEvent {
    id: string;
    type: string;
    createdAt: string;
    payload?: any;
    pageTitle?: string;
    session?: {
        visitorId: string;
        email?: string;
        city?: string;
        country?: string;
    };
}

const EcommerceLogWidget = () => {
    const [events, setEvents] = useState<AnalyticsEvent[]>([]);
    const [loading, setLoading] = useState(true);

    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const fetchLog = useCallback(async () => {
        if (!token || !currentAccount) return;

        try {
            const res = await fetch('/api/analytics/ecommerce/log?limit=20&live=true', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const json = await res.json();
                setEvents(json.data);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setLoading(false);
        }
    }, [token, currentAccount]);

    // Use visibility-aware polling with tab coordination
    useVisibilityPolling(fetchLog, 15000, [fetchLog], 'ecommerce-log');

    const getIcon = (type: string) => {
        switch (type) {
            case 'add_to_cart': return <ShoppingCart className="w-4 h-4 text-emerald-500" />;
            case 'remove_from_cart': return <LogOut className="w-4 h-4 text-rose-400" />;
            case 'cart_view': return <ShoppingCart className="w-4 h-4 text-amber-500" />;
            case 'checkout_view': return <CreditCard className="w-4 h-4 text-amber-500" />;
            case 'checkout_start': return <CreditCard className="w-4 h-4 text-blue-500" />;
            case 'checkout_success':
            case 'purchase': return <CheckCircle className="w-4 h-4 text-green-600" />;
            default: return <ShoppingCart className="w-4 h-4 text-slate-400 dark:text-slate-500" />;
        }
    };

    const getLabel = (e: AnalyticsEvent) => {
        const who = e.session?.email || 'Guest';
        switch (e.type) {
            case 'add_to_cart':
                const products = e.payload?.items?.map((item: any) => item.name).filter(Boolean).slice(0, 2);
                const productLabel = products?.length
                    ? products.join(', ') + (e.payload?.items?.length > 2 ? ` +${e.payload.items.length - 2} more` : '')
                    : 'items';
                const total = e.payload?.total ? ` ($${e.payload.total})` : '';
                return <span><span className="font-semibold text-slate-800 dark:text-slate-200">{who}</span> added <span className="text-slate-700 dark:text-slate-300">{productLabel}</span>{total}</span>;
            case 'remove_from_cart':
                return <span><span className="font-semibold text-slate-800 dark:text-slate-200">{who}</span> removed items from cart</span>;
            case 'checkout_start':
                return <span><span className="font-semibold text-slate-800 dark:text-slate-200">{who}</span> started checkout</span>;
            case 'checkout_success':
            case 'purchase':
                return <span><span className="font-semibold text-emerald-700 dark:text-emerald-400">{who} completed a purchase!</span></span>;
            case 'cart_view':
                const cartTotal = e.payload?.total ? ` ($${e.payload.total})` : '';
                return <span><span className="font-semibold text-slate-800 dark:text-slate-200">{who}</span> viewed cart{cartTotal}</span>;
            case 'checkout_view':
                const checkoutTotal = e.payload?.total ? ` ($${e.payload.total})` : '';
                return <span><span className="font-semibold text-slate-800 dark:text-slate-200">{who}</span> viewing checkout{checkoutTotal}</span>;
            default:
                return <span>{who} performed {e.type}</span>;
        }
    };

    if (loading && events.length === 0) return <div className="p-4 text-xs text-slate-500 dark:text-slate-400">Loading stream...</div>;

    return (
        <div className="h-full overflow-y-auto custom-scrollbar p-2 space-y-2">
            {events.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-slate-400 dark:text-slate-500">
                    <ShoppingCart className="w-6 h-6 mb-2 opacity-50" />
                    <span className="text-xs">No recent commerce activity</span>
                </div>
            ) : (
                events.map(e => (
                    <div key={e.id} className="flex gap-3 p-3 bg-white dark:bg-slate-800/60 border border-slate-100 dark:border-slate-700/50 rounded-lg shadow-xs">
                        <div className="mt-0.5 shrink-0 bg-slate-50 dark:bg-slate-700/50 p-2 rounded-full h-fit">
                            {getIcon(e.type)}
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="text-sm text-slate-600 dark:text-slate-300 truncate">
                                {getLabel(e)}
                            </div>
                            <div className="flex items-center gap-2 mt-1 text-[10px] text-slate-400 dark:text-slate-500">
                                <span>{formatDistanceToNow(new Date(e.createdAt), { addSuffix: true })}</span>
                                {e.session?.country && (
                                    <>
                                        <span>•</span>
                                        <span>{e.session.city ? `${e.session.city}, ` : ''}{e.session.country}</span>
                                    </>
                                )}
                            </div>
                        </div>
                    </div>
                ))
            )}
        </div>
    );
};

export default EcommerceLogWidget;

/**
 * Gold Price Margin Widget
 * 
 * Displays a summary of gold-priced products and their profit margins.
 * Links to the full Gold Price Margin Report page.
 */

import { useCallback, useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Gem, ArrowRight, TrendingDown, Loader2, AlertTriangle, RefreshCw } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { Logger } from '../../utils/logger';
import { WidgetProps } from './WidgetRegistry';

// Margin thresholds for color coding (aligned with report page)
const MARGIN_THRESHOLD_LOW = 20;
const MARGIN_THRESHOLD_MEDIUM = 40;

interface GoldPriceSummary {
    totalCount: number;
    productCount: number;
    variationCount: number;
    lowestMarginItems: { name: string; margin: number }[];
}

/**
 * Dashboard widget showing gold price product margin summary.
 * Clickable to navigate to full report.
 */
export function GoldPriceMarginWidget({ className }: WidgetProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const navigate = useNavigate();
    const [summary, setSummary] = useState<GoldPriceSummary | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchSummary = useCallback(async () => {
        if (!currentAccount || !token) return;

        setError(null);
        try {
            const res = await fetch('/api/reports/gold-price/summary', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (!res.ok) {
                throw new Error(`HTTP ${res.status}`);
            }
            setSummary(await res.json());
        } catch (err) {
            const message = err instanceof Error ? err.message : 'Failed to load';
            Logger.error('Failed to load gold price summary', { error: err });
            setError(message);
        } finally {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentAccount?.id, token]);

    useEffect(() => {
        fetchSummary();
    }, [fetchSummary]);

    if (loading) {
        return (
            <div className="h-full flex items-center justify-center">
                <Loader2 className="animate-spin text-amber-500" size={20} />
            </div>
        );
    }

    if (error) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 p-4">
                <div className="bg-red-50 dark:bg-red-900/20 p-3 rounded-full mb-2">
                    <AlertTriangle className="w-5 h-5 text-red-400" />
                </div>
                <p className="text-sm font-medium text-gray-600 dark:text-gray-300 mb-2">Failed to Load</p>
                <button
                    onClick={() => { setLoading(true); fetchSummary(); }}
                    className="text-xs text-amber-600 hover:text-amber-700 flex items-center gap-1"
                >
                    <RefreshCw size={12} />
                    Retry
                </button>
            </div>
        );
    }

    if (!summary || summary.totalCount === 0) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 p-4">
                <div className="bg-amber-50 dark:bg-amber-900/20 p-3 rounded-full mb-2">
                    <Gem className="w-5 h-5 text-amber-400" />
                </div>
                <p className="text-sm font-medium text-gray-600 dark:text-gray-300">No Gold Products</p>
                <p className="text-xs text-center">Enable gold pricing on products to see margin analysis.</p>
            </div>
        );
    }

    return (
        <div
            className="flex flex-col h-full cursor-pointer group"
            onClick={() => navigate('/reports/gold-price-margin')}
            role="button"
            tabIndex={0}
            onKeyDown={(e) => e.key === 'Enter' && navigate('/reports/gold-price-margin')}
        >
            {/* Header */}
            <div className="flex items-center justify-between mb-3 px-1">
                <h3 className="font-semibold text-gray-900 dark:text-white flex items-center gap-2">
                    <Gem size={16} className="text-amber-500" />
                    Gold Price Margins
                </h3>
                <span className="text-xs font-mono bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300 px-2 py-0.5 rounded-full">
                    {summary.totalCount} Items
                </span>
            </div>

            {/* Lowest Margins */}
            <div className="flex-1 overflow-hidden">
                <p className="text-xs text-gray-500 dark:text-gray-400 mb-2 px-1 flex items-center gap-1">
                    <TrendingDown size={12} />
                    Lowest Margins
                </p>
                <div className="space-y-2">
                    {summary.lowestMarginItems.map((item, idx) => (
                        <div
                            key={idx}
                            className="flex items-center justify-between p-2 rounded-lg bg-gray-50 dark:bg-slate-800/50 border border-transparent group-hover:border-amber-200 dark:group-hover:border-amber-500/30 transition-colors"
                        >
                            <span className="text-sm text-gray-800 dark:text-gray-200 truncate flex-1 mr-2">
                                {item.name}
                            </span>
                            <span className={`text-xs font-mono font-bold ${item.margin < MARGIN_THRESHOLD_LOW ? 'text-red-600 dark:text-red-400' :
                                item.margin < MARGIN_THRESHOLD_MEDIUM ? 'text-amber-600 dark:text-amber-400' :
                                    'text-green-600 dark:text-green-400'
                                }`}>
                                {item.margin.toFixed(1)}%
                            </span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Footer Link */}
            <div className="mt-3 pt-2 border-t border-gray-100 dark:border-slate-700">
                <span className="flex items-center justify-center gap-1 text-xs font-medium text-amber-600 group-hover:text-amber-700 transition-colors">
                    View Full Report <ArrowRight size={12} className="group-hover:translate-x-0.5 transition-transform" />
                </span>
            </div>
        </div>
    );
}

/**
 * HotCacheWidget - Shows Hot Tier cache status and controls
 * 
 * Displays cached data counts and provides refresh controls.
 */

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Database, RefreshCw, HardDrive, Trash2 } from 'lucide-react';
import { useAccount } from '../../context/AccountContext';
import { getCacheStats, clearAccountCache, hotTierDB } from '../../services/db';
import { WidgetProps } from './WidgetRegistry';

interface CacheStats {
    orders: number;
    products: number;
    customers: number;
    lastSync: {
        orders: number | null;
        products: number | null;
        customers: number | null;
    };
}

export function HotCacheWidget({ className }: WidgetProps) {
    const { currentAccount } = useAccount();
    const [stats, setStats] = useState<CacheStats | null>(null);
    const [loading, setLoading] = useState(true);
    const [clearing, setClearing] = useState(false);
    const [confirmClear, setConfirmClear] = useState(false);

    const loadStats = async () => {
        if (!currentAccount?.id) return;
        setLoading(true);
        try {
            const data = await getCacheStats(currentAccount.id);
            setStats(data);
        } catch (error) {
            Logger.error('Failed to load cache stats', { error: error });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadStats();
    }, [currentAccount?.id]);

    /** Two-step clear: first click shows confirmation, second click executes */
    const handleClear = async () => {
        if (!currentAccount?.id) return;

        if (!confirmClear) {
            setConfirmClear(true);
            // Auto-dismiss after 3 seconds
            setTimeout(() => setConfirmClear(false), 3000);
            return;
        }

        setClearing(true);
        setConfirmClear(false);
        try {
            await clearAccountCache(currentAccount.id);
            await loadStats();
        } catch (error) {
            Logger.error('Failed to clear cache', { error: error });
        } finally {
            setClearing(false);
        }
    };

    const formatTime = (timestamp: number | null) => {
        if (!timestamp) return 'Never';
        const diff = Date.now() - timestamp;
        const minutes = Math.floor(diff / 60000);
        if (minutes < 1) return 'Just now';
        if (minutes < 60) return `${minutes}m ago`;
        const hours = Math.floor(minutes / 60);
        if (hours < 24) return `${hours}h ago`;
        return `${Math.floor(hours / 24)}d ago`;
    };

    const totalItems = stats ? stats.orders + stats.products + stats.customers : 0;

    return (
        <div className={`bg-white dark:bg-slate-800/90 rounded-2xl border border-slate-200/80 dark:border-slate-700/50 p-4 h-full shadow-[0_1px_3px_rgba(0,0,0,0.05)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)] transition-all duration-300 hover:shadow-[0_10px_40px_rgba(0,0,0,0.08)] dark:hover:shadow-[0_10px_40px_rgba(0,0,0,0.3)] ${className}`}>
            <div className="flex items-center justify-between mb-4">
