import { useState, useCallback, useRef, useMemo } from 'react';
import { Logger } from '../../utils/logger';
import { formatCurrency } from '../../utils/format';
import { useVisibilityPolling } from '../../hooks/useVisibilityPolling';
import { Users, ShoppingCart, Activity, ArrowRight } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { WidgetProps } from './WidgetRegistry';

interface LiveSession {
    country: string;
    city: string;
    lastActiveAt: string;
    cartValue: number;
}

export function LiveAnalyticsWidget({ className }: WidgetProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const navigate = useNavigate();

    const [visitors, setVisitors] = useState<LiveSession[]>([]);
    const [loading, setLoading] = useState(true);
    const prevCountRef = useRef<number | null>(null);

    const fetchLiveStats = useCallback(async () => {
        if (!currentAccount || !token) return;

        try {
            const res = await fetch('/api/tracking/live', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                /* Track previous count before updating for trend micro-copy */
                if (prevCountRef.current === null) {
                    prevCountRef.current = (data || []).length;
                } else {
                    prevCountRef.current = visitors.length;
                }
                setVisitors(data || []);
            }
        } catch (error) {
            Logger.error('Failed to fetch live stats', { error: error });
        } finally {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentAccount?.id, token]);

    // Use visibility-aware polling with tab coordination
    useVisibilityPolling(fetchLiveStats, 10000, [fetchLiveStats], 'live-analytics');

    const activeCarts = visitors.filter(v => Number(v.cartValue) > 0);
    const totalCartValue = activeCarts.reduce((acc, curr) => acc + Number(curr.cartValue), 0);

    /** Top 3 countries from the live visitors array. */
    const topCountries = useMemo(() => {
        const counts: Record<string, number> = {};
        for (const v of visitors) {
            const key = v.country || 'Unknown';
            counts[key] = (counts[key] || 0) + 1;
        }
        return Object.entries(counts)
            .sort((a, b) => b[1] - a[1])
            .slice(0, 3);
    }, [visitors]);

    /** Build trend text comparing current count vs previous poll. */
    const trendText = useMemo(() => {
        if (prevCountRef.current === null) return 'Active Visitors';
        const diff = visitors.length - prevCountRef.current;
        if (diff > 0) return `${diff} more since last check`;
        if (diff < 0) return `${Math.abs(diff)} fewer since last check`;
        return 'Active Visitors';
    }, [visitors.length]);

    return (
        <div className={`bg-white dark:bg-slate-800/90 p-6 rounded-2xl shadow-[0_1px_3px_rgba(0,0,0,0.05),0_1px_2px_rgba(0,0,0,0.03)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)] border border-slate-200/80 dark:border-slate-700/50 flex flex-col h-full relative overflow-hidden transition-all duration-300 hover:shadow-[0_10px_40px_rgba(0,0,0,0.08)] dark:hover:shadow-[0_10px_40px_rgba(0,0,0,0.3)] ${className}`}>
            {/* Header */}
            <div className="flex justify-between items-start mb-4 relative z-10">
                <div>
                    <h3 className="text-slate-500 dark:text-slate-400 text-sm font-medium">Live Now</h3>
                    <div className="flex items-baseline gap-2 mt-1">
                        <span className="text-3xl font-bold text-slate-900 dark:text-white">{visitors.length}</span>
                        <span className="text-sm text-green-600 flex items-center gap-1 font-medium animate-pulse">
                            <span className="w-2 h-2 rounded-full bg-green-500"></span>
                            {trendText}
                        </span>
                    </div>
                </div>
                <div className="p-2 bg-gradient-to-br from-blue-400 to-indigo-600 rounded-lg text-white shadow-md shadow-blue-500/20">
                    <Activity className="w-5 h-5" />
                </div>
            </div>

            {/* Cart Stats */}
            <div className="grid grid-cols-2 gap-4 mb-4 relative z-10">
                <div className="bg-slate-50 dark:bg-slate-700/50 rounded-lg p-3">
                    <div className="flex items-center gap-2 mb-1">
                        <ShoppingCart className="w-4 h-4 text-orange-500" />
                        <span className="text-xs font-medium text-slate-600 dark:text-slate-400">Active Carts</span>
                    </div>
                    <p className="text-lg font-bold text-slate-900 dark:text-white">{activeCarts.length}</p>
                </div>
                <div className="bg-slate-50 dark:bg-slate-700/50 rounded-lg p-3">
                    <div className="flex items-center gap-2 mb-1">
                        <span className="text-xs font-medium text-slate-600 dark:text-slate-400">Potential Revenue</span>
                    </div>
                    <p className="text-lg font-bold text-slate-900 dark:text-white">
                        {formatCurrency(totalCartValue)}
                    </p>
                </div>
            </div>

            {/* Top Locations Strip */}
            {topCountries.length > 0 && (
                <div className="mb-4 relative z-10">
                    <div className="text-xs text-slate-500 dark:text-slate-400 font-medium mb-1.5">Top Locations</div>
                    <div className="flex items-center gap-2">
                        {topCountries.map(([country, count]) => {
                            /* Country-code → flag emoji */
                            const flag = country.length === 2
                                ? String.fromCodePoint(...country.toUpperCase().split('').map(c => 127397 + c.charCodeAt(0)))
                                : '🌍';
                            return (
                                <span key={country} className="inline-flex items-center gap-1 px-2 py-1 bg-slate-50 dark:bg-slate-700/50 rounded-md text-xs text-slate-600 dark:text-slate-300">
                                    <span className="text-sm">{flag}</span>
                                    {country}
                                    <span className="text-slate-400 dark:text-slate-500">({count})</span>
                                </span>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* Footer / CTA */}
            <div className="mt-auto relative z-10">
                <button
                    onClick={() => navigate('/analytics/live')}
                    className="text-sm text-blue-600 font-medium hover:text-blue-700 flex items-center gap-1 transition-colors"
                >
                    View Real-time Report <ArrowRight size={16} />
                </button>
            </div>

            {/* Background Decoration */}
            <div className="absolute -bottom-6 -right-6 opacity-[0.06] dark:opacity-[0.08] z-0">
                <Users size={120} className="text-blue-600 dark:text-blue-400" />
            </div>
        </div>
    );
}

import { useState, useCallback } from 'react';
import { useVisibilityPolling } from '../../hooks/useVisibilityPolling';
import { Logger } from '../../utils/logger';
import { formatCurrency } from '../../utils/format';
import { ShoppingCart, Clock, User as UserIcon, Loader2, Package, Flame } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { WidgetProps } from './WidgetRegistry';

interface CartItem {
    productId: number;
    variationId?: number;
    name: string;
    sku?: string;
    thumbnail?: string;
    quantity: number;
    price: number;
    total: number;
}

interface CartSession {
    id: string;
    visitorId: string;
    email?: string | null;
    cartValue: number;
    cartItems: CartItem[];
    itemCount: number;
    currency: string;
    lastActiveAt: string;
    country?: string | null;
    city?: string | null;
    customerName?: string | null;
    customerId?: number | null;
    purchaseIntentScore: number;
    minutesSinceActivity: number;
}

/**
 * Get intent level and color based on purchase intent score.
 */
function getIntentLevel(score: number): { label: string; color: string; bgColor: string } {
    if (score >= 70) return { label: 'Hot', color: 'text-red-600', bgColor: 'bg-red-100' };
    if (score >= 40) return { label: 'Warm', color: 'text-orange-500', bgColor: 'bg-orange-100' };
    return { label: 'Cold', color: 'text-blue-500', bgColor: 'bg-blue-100' };
}

const LiveCartsWidget = ({ className }: WidgetProps) => {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [carts, setCarts] = useState<CartSession[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchCarts = useCallback(async () => {
        if (!currentAccount || !token) return;

        try {
            const res = await fetch('/api/tracking/carts', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setCarts(Array.isArray(data) ? data : []);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentAccount?.id, token]);

    // Use visibility-aware polling with tab coordination
    useVisibilityPolling(fetchCarts, 30000, [fetchCarts], 'live-carts');

    if (loading && carts.length === 0) {
        return (
            <div className={`bg-white dark:bg-slate-800/90 h-full w-full p-4 flex flex-col rounded-2xl shadow-[0_1px_3px_rgba(0,0,0,0.05)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)] border border-slate-200/80 dark:border-slate-700/50 overflow-hidden ${className}`}>
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-semibold text-slate-900 dark:text-white">Live Carts</h3>
                    <ShoppingCart size={18} className="text-slate-400 dark:text-slate-500" />
                </div>
                <div className="flex-1 flex justify-center items-center">
                    <Loader2 className="animate-spin text-slate-400 dark:text-slate-500" />
                </div>
            </div>
        );
    }

    return (
        <div className={`bg-white dark:bg-slate-800/90 h-full w-full p-4 flex flex-col rounded-2xl shadow-[0_1px_3px_rgba(0,0,0,0.05)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)] border border-slate-200/80 dark:border-slate-700/50 overflow-hidden transition-all duration-300 hover:shadow-[0_10px_40px_rgba(0,0,0,0.08)] dark:hover:shadow-[0_10px_40px_rgba(0,0,0,0.3)] ${className}`}>
            <div className="flex justify-between items-center mb-4">
                <div className="flex items-center gap-2">
                    <h3 className="font-semibold text-slate-900 dark:text-white">Live Carts</h3>
                    {carts.length > 0 && (
                        <span className="text-xs bg-blue-100 dark:bg-blue-500/15 text-blue-700 dark:text-blue-400 px-1.5 py-0.5 rounded-full font-medium">
                            {carts.length}
                        </span>
                    )}
                </div>
                <ShoppingCart size={18} className="text-slate-400 dark:text-slate-500" />
            </div>
            <div className="flex-1 overflow-y-auto">
                {carts.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-slate-400 dark:text-slate-500">
                        <ShoppingCart className="w-8 h-8 mb-2 opacity-50" />
                        <span className="text-xs">No active carts</span>
                    </div>
                ) : (
                    <div className="space-y-2">
                        {carts.map(cart => {
                            const intent = getIntentLevel(cart.purchaseIntentScore);
                            const firstItem = cart.cartItems?.[0];
                            const hasMultipleItems = cart.cartItems?.length > 1;

                            return (
                                <div key={cart.id} className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-700/40 border border-slate-100 dark:border-slate-600/50 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700/60 transition-colors cursor-pointer">
                                    <div className="flex items-center space-x-3">
                                        {/* Product thumbnail or placeholder */}
                                        <div className="relative">
                                            {firstItem?.thumbnail ? (
                                                <img
                                                    src={firstItem.thumbnail}
                                                    alt={firstItem.name}
                                                    className="w-10 h-10 rounded-lg object-cover bg-slate-100 dark:bg-slate-600"
                                                    onError={(e) => {
                                                        (e.target as HTMLImageElement).style.display = 'none';
                                                    }}
                                                />
                                            ) : (
                                                <div className="w-10 h-10 rounded-lg bg-blue-50 dark:bg-blue-500/10 flex items-center justify-center">
                                                    <Package className="w-5 h-5 text-blue-400" />
                                                </div>
                                            )}
                                            {/* Item count badge */}
                                            {cart.itemCount > 1 && (
                                                <span className="absolute -top-1 -right-1 bg-slate-700 dark:bg-slate-500 text-white text-[10px] font-medium w-4 h-4 rounded-full flex items-center justify-center">
                                                    {cart.itemCount > 9 ? '9+' : cart.itemCount}
                                                </span>
                                            )}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="flex items-center gap-1.5">
                                                <span className="text-sm font-semibold text-slate-900 dark:text-white">
                                                    {formatCurrency(cart.cartValue, cart.currency || 'USD')}
                                                </span>
                                                {/* Purchase intent indicator */}
                                                {cart.purchaseIntentScore >= 70 && (
                                                    <Flame className="w-3.5 h-3.5 text-red-500" />
                                                )}
                                            </div>
                                            <div className="text-xs text-slate-500 dark:text-slate-400 flex items-center gap-1 truncate">
                                                <UserIcon className="w-3 h-3 shrink-0" />
                                                <span className="truncate">
                                                    {cart.customerName || cart.email || `Visitor ${cart.visitorId?.slice(0, 6) || 'Unknown'}...`}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="text-right shrink-0">
                                        <div className="text-xs text-slate-400 dark:text-slate-500 flex items-center justify-end gap-1">
                                            <Clock className="w-3 h-3" />
                                            {cart.minutesSinceActivity < 1
                                                ? 'Just now'
                                                : cart.minutesSinceActivity < 60
                                                    ? `${cart.minutesSinceActivity}m ago`
                                                    : formatDistanceToNow(new Date(cart.lastActiveAt), { addSuffix: true })}
                                        </div>
                                        {(cart.city || cart.country) && (
                                            <div className="text-[10px] text-slate-500 dark:text-slate-400 uppercase mt-0.5">
                                                {cart.city}{cart.city && cart.country ? ', ' : ''}{cart.country}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
};

