                    </div>
                    <button
                        onClick={() => {
                            setIsLoading(true);
                            fetchStatus();
                        }}
                        className="p-2 hover:bg-white/50 dark:hover:bg-black/20 rounded-lg transition-colors text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200"
                        title="Refresh status"
