export default StatusCenterWidget;

import { WidgetProps } from './WidgetRegistry';
import { Logger } from '../../utils/logger';

import { DollarSign, Loader2, TrendingUp, TrendingDown, Minus, Zap } from 'lucide-react';
import { useEffect, useState, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useWidgetSocket } from '../../hooks/useWidgetSocket';

export function TotalSalesWidget({ className, dateRange, comparison, comparisonLabel }: WidgetProps) {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [sales, setSales] = useState<number | null>(null);
    const [orderCount, setOrderCount] = useState<number | null>(null);
    const [comparisonSales, setComparisonSales] = useState<number | null>(null);
    const [loading, setLoading] = useState(true);
    const [hasRealtimeUpdate, setHasRealtimeUpdate] = useState(false);

    const fetchSales = useCallback(async () => {
        if (!currentAccount || !token) return;

        setLoading(true);
        try {
            const currentRes = await fetch(`/api/analytics/sales?startDate=${dateRange.startDate}&endDate=${dateRange.endDate}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (!currentRes.ok) throw new Error(`HTTP ${currentRes.status}`);
            const currentData = await currentRes.json();
            setSales(currentData.total || 0);
            setOrderCount(currentData.count || 0);

            if (comparison) {
                const compRes = await fetch(`/api/analytics/sales?startDate=${comparison.startDate}&endDate=${comparison.endDate}`, {
                    headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
                });
                if (!compRes.ok) throw new Error(`HTTP ${compRes.status}`);
                const compData = await compRes.json();
                setComparisonSales(compData.total || 0);
            } else {
                setComparisonSales(null);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentAccount?.id, token, dateRange, comparison]);

    useEffect(() => {
        fetchSales();
    }, [fetchSales]);

    // Real-time: Listen for new orders and update sales
    // Using typeof check to ensure data.total is a valid number before arithmetic
    useWidgetSocket<{ total?: number }>('order:new', (data) => {
        if (typeof data.total === 'number' && !isNaN(data.total)) {
            setSales(prev => (prev ?? 0) + data.total!);
            setOrderCount(prev => (prev ?? 0) + 1);
            setHasRealtimeUpdate(true);
            // Clear the indicator after 3 seconds
            setTimeout(() => setHasRealtimeUpdate(false), 3000);
        }
    });


    // Calculate percentage change
    let percentChange = 0;
    let isPositive = false;
    const hasComparison = comparisonSales !== null;

    if (hasComparison && comparisonSales !== 0 && sales !== null) {
        percentChange = ((sales - comparisonSales!) / comparisonSales!) * 100;
        isPositive = percentChange >= 0;
    } else if (hasComparison && comparisonSales === 0 && sales !== null && sales > 0) {
        percentChange = 100; // Zero to something is 100% growth essentially
        isPositive = true;
    }

    return (
        <div className={`bg-white dark:bg-slate-800/90 h-full w-full p-6 flex flex-col justify-between rounded-2xl shadow-[0_1px_3px_rgba(0,0,0,0.05),0_1px_2px_rgba(0,0,0,0.03)] dark:shadow-[0_1px_3px_rgba(0,0,0,0.2)] border border-slate-200/80 dark:border-slate-700/50 transition-all duration-300 hover:shadow-[0_10px_40px_rgba(0,0,0,0.08)] dark:hover:shadow-[0_10px_40px_rgba(0,0,0,0.3)] hover:-translate-y-0.5 ${hasRealtimeUpdate ? 'ring-2 ring-emerald-500/30 animate-pulse-glow' : ''} ${className}`}>
            <div className="flex justify-between items-start">
                <div>
                    <h3 className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-wider">
                        Total Revenue {currentAccount?.revenueTaxInclusive !== false ? '(Inclusive)' : '(Exclusive)'}
                    </h3>
                    {loading ? (
                        <div className="flex items-center gap-2 mt-3 text-slate-400"><Loader2 className="animate-spin" size={20} /></div>
                    ) : (
                        <>
                            <p
                                className="text-3xl font-bold text-slate-900 dark:text-white mt-3 tracking-tight cursor-default"
                                title={orderCount && orderCount > 0 ? `AOV: $${((sales || 0) / orderCount).toFixed(2)}` : undefined}
                            >
                                {new Intl.NumberFormat('en-AU', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(sales || 0)}
                            </p>
                            {orderCount !== null && (
                                <p className="text-xs text-slate-400 dark:text-slate-500 mt-1.5">
                                    {orderCount.toLocaleString()} order{orderCount !== 1 ? 's' : ''} · AOV ${orderCount > 0 ? ((sales || 0) / orderCount).toFixed(2) : '0.00'}
                                </p>
                            )}
                        </>
                    )}
                </div>
                <div className="p-3 bg-gradient-to-br from-emerald-400 to-emerald-600 rounded-xl text-white shadow-lg shadow-emerald-500/25">
                    <DollarSign size={24} />
                </div>
            </div>

            {hasComparison && !loading && (
                <div className="flex items-center gap-2 mt-4 text-sm">
                    <span className={`flex items-center gap-1 font-semibold px-2 py-1 rounded-lg ${isPositive ? 'text-emerald-600 bg-emerald-50 dark:bg-emerald-500/10 dark:text-emerald-400' : 'text-rose-500 bg-rose-50 dark:bg-rose-500/10 dark:text-rose-400'}`}>
                        {isPositive ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
                        {Math.abs(percentChange).toFixed(1)}%
                    </span>
                    <span className="text-slate-400 dark:text-slate-500">{comparisonLabel || 'vs last period'}</span>
                </div>
            )}
            {!hasComparison && !loading && (
                <div className="flex items-center gap-1 mt-4 text-sm text-slate-400 dark:text-slate-500">
                    <Minus size={14} />
                    <span>No comparison</span>
                </div>
            )}
        </div>
    );
}

import { ReactNode, lazy, Suspense, ComponentType } from 'react';
import { Loader2 } from 'lucide-react';
import { WidgetErrorBoundary } from './WidgetErrorBoundary';

/**
 * Lazy-loaded widget imports for code-splitting.
 * 
 * Why: Widgets like SalesChartWidget and CustomerGrowthWidget import echarts (~617KB).
 * By lazy loading all widgets, we ensure echarts only loads when a chart widget is
 * actually on the user's dashboard, reducing initial bundle by 600KB+.
 */

// Light widgets (no heavy dependencies)
const TotalSalesWidget = lazy(() => import('./TotalSalesWidget').then(m => ({ default: m.TotalSalesWidget })));
const RecentOrdersWidget = lazy(() => import('./RecentOrdersWidget').then(m => ({ default: m.RecentOrdersWidget })));
const AdSpendWidget = lazy(() => import('./AdSpendWidget').then(m => ({ default: m.AdSpendWidget })));
const LiveAnalyticsWidget = lazy(() => import('./LiveAnalyticsWidget').then(m => ({ default: m.LiveAnalyticsWidget })));
const TopProductsWidget = lazy(() => import('./TopProductsWidget').then(m => ({ default: m.TopProductsWidget })));
const InventoryRiskWidget = lazy(() => import('./InventoryRiskWidget').then(m => ({ default: m.InventoryRiskWidget })));
const VisitorCountWidget = lazy(() => import('./VisitorCountWidget').then(m => ({ default: m.VisitorCountWidget })));
const OpenInboxWidget = lazy(() => import('./OpenInboxWidget').then(m => ({ default: m.OpenInboxWidget })));
const GoldPriceMarginWidget = lazy(() => import('./GoldPriceMarginWidget').then(m => ({ default: m.GoldPriceMarginWidget })));
const SeoKeywordsWidget = lazy(() => import('./SeoKeywordsWidget').then(m => ({ default: m.SeoKeywordsWidget })));

// Medium widgets (moderate bundle impact)
const LiveCartsWidget = lazy(() => import('./LiveCartsWidget'));
const VisitorLogWidget = lazy(() => import('./VisitorLogWidget'));
const EcommerceLogWidget = lazy(() => import('./EcommerceLogWidget'));
const HotCacheWidget = lazy(() => import('./HotCacheWidget'));
const QuickProductsWidget = lazy(() => import('./QuickProductsWidget'));
const AdSuggestionsWidget = lazy(() => import('./AdSuggestionsWidget').then(m => ({ default: m.AdSuggestionsWidget })));
const CartAbandonmentWidget = lazy(() => import('./CartAbandonmentWidget').then(m => ({ default: m.CartAbandonmentWidget })));
const StatusCenterWidget = lazy(() => import('./StatusCenterWidget').then(m => ({ default: m.StatusCenterWidget })));
const FunnelWidget = lazy(() => import('./FunnelWidget'));
const AnalyticsStatsWidget = lazy(() => import('./AnalyticsStatsWidget'));

// Heavy widgets (echarts ~617KB) - deferred until actually rendered
const CustomerGrowthWidget = lazy(() => import('./CustomerGrowthWidget').then(m => ({ default: m.CustomerGrowthWidget })));
const SalesChartWidget = lazy(() => import('./SalesChartWidget').then(m => ({ default: m.SalesChartWidget })));

export interface WidgetProps {
    settings?: any;
    className?: string;
    dateRange: { startDate: string, endDate: string };
    comparison?: { startDate: string, endDate: string } | null;
    comparisonLabel?: string;
}

type LazyWidget = React.LazyExoticComponent<ComponentType<WidgetProps>>;

/**
 * Widget skeleton shown while lazy widget chunk loads.
 */
function WidgetSkeleton() {
    return (
        <div className="card-premium h-full flex items-center justify-center bg-white dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700">
            <div className="flex flex-col items-center gap-2 text-slate-400">
                <Loader2 className="animate-spin" size={20} />
                <span className="text-xs">Loading...</span>
            </div>
        </div>
    );
}

/**
 * Widget permission requirements mapped to RBAC permissions.
 * - view_finance: Revenue, sales, analytics data
 * - view_marketing: Ad spend, ROAS, marketing AI features
 * - view_products: Inventory, product performance
 * - view_orders: Order-related data
 * - undefined: No permission required (available to all users)
 */
export const WidgetRegistry: Record<string, {
    component: LazyWidget,
    label: string,
    defaultH: number,
    defaultW: number,
    requiredPermission?: string
}> = {
    'total-sales': { component: TotalSalesWidget, label: 'Total Sales', defaultW: 4, defaultH: 4, requiredPermission: 'view_finance' },
    'recent-orders': { component: RecentOrdersWidget, label: 'Recent Orders', defaultW: 4, defaultH: 8, requiredPermission: 'view_orders' },
    'marketing-roas': { component: AdSpendWidget, label: 'Marketing ROAS', defaultW: 4, defaultH: 4, requiredPermission: 'view_marketing' },
    'live-analytics': { component: LiveAnalyticsWidget, label: 'Live Analytics', defaultW: 4, defaultH: 3 },
    'top-products': { component: TopProductsWidget, label: 'Top Products', defaultW: 4, defaultH: 6, requiredPermission: 'view_finance' },
    'customer-growth': { component: CustomerGrowthWidget, label: 'Customer Growth', defaultW: 6, defaultH: 6, requiredPermission: 'view_finance' },
    'sales-chart': { component: SalesChartWidget, label: 'Sales Trend', defaultW: 6, defaultH: 6, requiredPermission: 'view_finance' },
    'inventory-risk': { component: InventoryRiskWidget, label: 'Inventory Risk', defaultW: 4, defaultH: 4, requiredPermission: 'view_products' },
    'live-carts': { component: LiveCartsWidget, label: 'Live Carts', defaultW: 4, defaultH: 4, requiredPermission: 'view_orders' },
    'visitor-log': { component: VisitorLogWidget, label: 'Visitor Log', defaultW: 6, defaultH: 6 },
    'ecommerce-log': { component: EcommerceLogWidget, label: 'Ecommerce Stream', defaultW: 6, defaultH: 6, requiredPermission: 'view_orders' },
    'hot-cache': { component: HotCacheWidget, label: 'Hot Cache', defaultW: 4, defaultH: 5 },
    'quick-products': { component: QuickProductsWidget, label: 'Quick Products', defaultW: 4, defaultH: 6, requiredPermission: 'view_products' },
    'visitor-count': { component: VisitorCountWidget, label: 'Live Visitors', defaultW: 3, defaultH: 2 },
    'open-inbox': { component: OpenInboxWidget, label: 'Open Inbox', defaultW: 3, defaultH: 2 },
    'ad-suggestions': { component: AdSuggestionsWidget, label: 'Ad Suggestions', defaultW: 4, defaultH: 5, requiredPermission: 'view_marketing' },
    'cart-abandonment': { component: CartAbandonmentWidget, label: 'Cart Abandonment', defaultW: 4, defaultH: 6, requiredPermission: 'view_finance' },
    'gold-price-margin': { component: GoldPriceMarginWidget, label: 'Gold Price Margins', defaultW: 4, defaultH: 5, requiredPermission: 'view_finance' },
    'seo-keywords': { component: SeoKeywordsWidget, label: 'SEO Keywords', defaultW: 4, defaultH: 6 },
    'status-center': { component: StatusCenterWidget, label: 'Status Center', defaultW: 4, defaultH: 6 },
    'funnel': { component: FunnelWidget, label: 'Conversion Funnel', defaultW: 4, defaultH: 6 },
    'analytics-stats': { component: AnalyticsStatsWidget, label: 'Analytics Stats', defaultW: 4, defaultH: 6 }
};

/**
 * Renders a widget by key with Suspense boundary.
 * Each widget loads its own chunk on-demand, deferring heavy deps like echarts.
 */
export function renderWidget(key: string, props: WidgetProps): ReactNode {
    const entry = WidgetRegistry[key];
    if (!entry) return <div className="p-4 bg-red-50 text-red-500">Widget {key} not found</div>;
    const Component = entry.component;
    return (
        <WidgetErrorBoundary widgetKey={key}>
            <Suspense fallback={<WidgetSkeleton />}>
                <Component {...props} />
            </Suspense>
        </WidgetErrorBoundary>
    );
}

import { createContext, useContext, useState, useEffect, ReactNode, useCallback, useRef, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Logger } from '../utils/logger';
import { useAuth } from './AuthContext';

export interface Account {
    id: string;
    name: string;
    domain: string | null;
    currency: string;
    wooUrl: string;
    wooConsumerKey?: string;
    openRouterApiKey?: string;
    aiModel?: string;
    embeddingModel?: string;
    appearance?: {
        logoUrl?: string;
        primaryColor?: string;
        appName?: string;
    };
    goldPrice?: number;
    goldPriceCurrency?: string;
    goldPrice18ct?: number;
    goldPrice9ct?: number;
    goldPrice18ctWhite?: number;
    goldPrice9ctWhite?: number;
    goldPriceMargin?: number;
    features?: { featureKey: string; isEnabled: boolean }[];
    weightUnit?: string;
    dimensionUnit?: string;
    revenueTaxInclusive?: boolean;
}

interface AccountContextType {
    accounts: Account[];
    currentAccount: Account | null;
    isLoading: boolean;
    refreshAccounts: () => Promise<void>;
    setCurrentAccount: (account: Account) => void;
    /** Resolved permissions for the current user+account, sourced from /me */
    activePermissions: Record<string, boolean>;
}

const AccountContext = createContext<AccountContextType | undefined>(undefined);

const EMPTY_PERMISSIONS: Record<string, boolean> = Object.freeze({});

export function AccountProvider({ children }: { children: ReactNode }) {
    const { token, user, isLoading: authLoading, logout, updateUser } = useAuth();
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [currentAccount, setCurrentAccount] = useState<Account | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    const refreshAccounts = useCallback(async () => {
        if (!token) {
            setAccounts([]);
            setCurrentAccount(null);
            setIsLoading(false);
            return;
        }

        // Re-raise the loading gate so guards (e.g. AccountGuard) don't
        // see accounts=[] + isLoading=false while we fetch.
        setIsLoading(true);

        try {
            const response = await fetch('/api/accounts', {
                headers: { Authorization: `Bearer ${token}` }
            });

            // Handle expired token - force logout to redirect to login (not wizard)
            if (response.status === 401) {
                logout();
                return;
            }

            if (response.ok) {
                const data: Account[] = await response.json();
                // Why: preserve array identity when contents are unchanged so downstream
                // useEffect([accounts]) hooks don't re-fire on silent token refresh.
                setAccounts(prev => JSON.stringify(prev) === JSON.stringify(data) ? prev : data);

                // Try to find the account we should show:
                // 1. The account saved in localStorage (if we just reloaded the page)
                // 2. The first account in the list (fallback)
                // Note: We use functional update to avoid stale closure while preventing infinite loops
                setCurrentAccount(prev => {
                    const savedId = localStorage.getItem('selectedAccountId');
                    const targetId = prev?.id || savedId;
                    const accountToSelect = data.find((a: Account) => a.id === targetId) || (data.length > 0 ? data[0] : null);
                    // Why: preserve object identity when the selected account is structurally
                    // unchanged. Prevents ~40 downstream useEffect([currentAccount]) hooks
                    // from refetching (and clobbering in-progress form edits) on every
                    // silent token refresh.
                    if (prev && accountToSelect && prev.id === accountToSelect.id &&
                        JSON.stringify(prev) === JSON.stringify(accountToSelect)) {
                        return prev;
                    }
                    return accountToSelect;
                });
            }
        } catch (error) {
            Logger.error('Failed to fetch accounts', { error: error });
        } finally {
            setIsLoading(false);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [token, logout]);

    // Persist selection to localStorage whenever it changes
    useEffect(() => {
        if (currentAccount?.id) {
            localStorage.setItem('selectedAccountId', currentAccount.id);
        }
    }, [currentAccount?.id]);

    /** Why React Query: The raw fetch('/api/auth/me') on account switch was
     *  unmanaged — no abort, no dedup, no cache. RQ gives all three for free,
     *  keyed by accountId so switching back to a previous account is instant. */
    const userRef = useRef(user);
    userRef.current = user;

    const { data: meData } = useQuery({
        queryKey: ['user-permissions', currentAccount?.id],
        queryFn: async () => {
            const res = await fetch('/api/auth/me', {
                headers: {
                    Authorization: `Bearer ${token}`,
                    'x-account-id': currentAccount!.id
                }
            });
            if (!res.ok) return null;
            return res.json();
        },
        enabled: !!currentAccount?.id && !!token,
        staleTime: 5 * 60 * 1000,
        select: (userData: any) => {
            if (userData) {
                const currentUser = userRef.current;
                const changed = !currentUser ||
                    currentUser.isSuperAdmin !== userData.isSuperAdmin ||
                    currentUser.fullName !== userData.fullName ||
                    currentUser.avatarUrl !== userData.avatarUrl ||
                    currentUser.email !== userData.email;
                if (changed) {
                    updateUser(userData);
                }
            }
            return userData;
        },
    });

    useEffect(() => {
        // Don't fetch accounts until auth has finished loading
        // This prevents the race condition where we see no token during initial hydration
        if (authLoading) {
            return;
        }
        refreshAccounts();
    }, [token, authLoading, refreshAccounts]);

    // isLoading should be true if either auth is loading or accounts are loading
    const effectiveLoading = authLoading || isLoading;

    /** Why derived here: permissions live in the React Query cache, keyed by
     *  accountId. Reading them directly avoids the stale-update problem where
     *  updateUser() was skipped when basic profile fields hadn't changed. */
    // Why: stable empty-object fallback so the useMemo below isn't invalidated
    // every render when there are no permissions yet.
    const activePermissions: Record<string, boolean> = useMemo(
        () => (meData?.permissions as Record<string, boolean>) ?? EMPTY_PERMISSIONS,
        [meData?.permissions]
    );

    // Why: memoize the context value so consumers don't re-render on every parent
    // render (e.g. when AuthContext silently refreshes the token). Combined with
    // the identity-preserving updates above, this stops the cascade that wipes
    // in-progress form edits.
    const value = useMemo(() => ({
        accounts,
        currentAccount,
        isLoading: effectiveLoading,
        refreshAccounts,
        setCurrentAccount,
        activePermissions,
    }), [accounts, currentAccount, effectiveLoading, refreshAccounts, activePermissions]);

    return (
        <AccountContext.Provider value={value}>
            {children}
        </AccountContext.Provider>
    );
}

export function useAccount() {
    const context = useContext(AccountContext);
    if (context === undefined) {
        throw new Error('useAccount must be used within an AccountProvider');
    }
    return context;
}

