import { createContext, useContext, useState, useCallback, useRef, useEffect, type ReactNode } from 'react';
import { type ToastType } from '../components/ui/Toast';
import { Check, X, AlertCircle } from 'lucide-react';

interface ToastItem {
    id: number;
    message: string;
    type: ToastType;
    duration: number;
}

interface ToastContextValue {
    toast: (message: string, type?: ToastType, duration?: number) => void;
    success: (message: string) => void;
    error: (message: string) => void;
    info: (message: string) => void;
}

const ToastContext = createContext<ToastContextValue | null>(null);

const MAX_TOASTS = 5;
let nextId = 0;

/** Self-contained toast item that manages its own auto-dismiss timer */
function ToastEntry({ item, onRemove }: { item: ToastItem; onRemove: (id: number) => void }) {
    const onRemoveRef = useRef(onRemove);
    onRemoveRef.current = onRemove;

    useEffect(() => {
        const timer = setTimeout(() => onRemoveRef.current(item.id), item.duration);
        return () => clearTimeout(timer);
    }, [item.id, item.duration]);

    const bgColors = { success: 'bg-gray-900', error: 'bg-red-600', info: 'bg-blue-600' };
    const iconBgColors = { success: 'bg-green-500', error: 'bg-white/20', info: 'bg-white/20' };
    const icons = {
        success: <Check size={12} className="text-white" />,
        error: <AlertCircle size={12} className="text-white" />,
        info: <AlertCircle size={12} className="text-white" />,
    };

    return (
        <div className="animate-in slide-in-from-bottom-5 fade-in duration-300" role="alert">
            <div className={`${bgColors[item.type]} text-white px-4 py-3 rounded-lg shadow-lg flex items-center gap-3 min-w-[300px]`}>
                <div className={`${iconBgColors[item.type]} rounded-full p-1`}>
                    {icons[item.type]}
                </div>
                <span className="font-medium text-sm flex-1">{item.message}</span>
                <button onClick={() => onRemove(item.id)} className="text-gray-400 hover:text-white ml-2 transition-colors">
                    <X size={16} />
                </button>
            </div>
        </div>
    );
}

export function ToastProvider({ children }: { children: ReactNode }) {
    const [toasts, setToasts] = useState<ToastItem[]>([]);

    const toast = useCallback((message: string, type: ToastType = 'success', duration = 3000) => {
        const id = ++nextId;
        setToasts(prev => [...prev.slice(-(MAX_TOASTS - 1)), { id, message, type, duration }]);
    }, []);

    const removeToast = useCallback((id: number) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    }, []);

    const success = useCallback((message: string) => toast(message, 'success'), [toast]);
    const error = useCallback((message: string) => toast(message, 'error', 4000), [toast]);
    const info = useCallback((message: string) => toast(message, 'info'), [toast]);

    return (
        <ToastContext.Provider value={{ toast, success, error, info }}>
            {children}
            <div className="fixed bottom-6 right-6 z-50 flex flex-col-reverse gap-2 pointer-events-none">
                {toasts.map(t => (
                    <div key={t.id} className="pointer-events-auto">
                        <ToastEntry item={t} onRemove={removeToast} />
                    </div>
                ))}
            </div>
        </ToastContext.Provider>
    );
}

export function useToast(): ToastContextValue {
    const ctx = useContext(ToastContext);
    if (!ctx) throw new Error('useToast must be used within ToastProvider');
    return ctx;
}

/**
 * useBOMSync Hook
 * 
 * Manages BOM sync state, data fetching, and sync operations.
 * Extracted from BOMSyncPage.tsx for reusability and maintainability.
 */

import { useEffect, useState, useCallback, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Logger } from '../utils/logger';
import type { DeactivatedItem } from '../components/bom/DeactivatedItemsBanner';

// Types
export interface BOMComponent {
    childName: string;
    requiredQty: number;
    childStock: number;
    buildableUnits: number;
    componentType?: 'WooProduct' | 'ProductVariation' | 'InternalProduct';
    isBottleneck?: boolean;
}

export interface PendingChange {
    productId: string;
    wooId: number;
    name: string;
    sku: string | null;
    mainImage: string | null;
    variationId: number;
    currentWooStock: number | null;
    effectiveStock: number;
    needsSync: boolean;
    components: BOMComponent[];
    lastError?: string;
    lastSyncAttempt?: string;
}

export interface SyncLogEntry {
    id: string;
    productId: string;
    productName: string;
    productSku: string | null;
    previousStock: number | null;
    newStock: number | null;
    trigger: string;
    createdAt: string;
}

export interface ConsumptionEntry {
    id: string;
    orderId: number;
    orderNumber: string;
    productName: string;
    componentName: string;
    quantityDeducted: number;
    previousStock: number;
    newStock: number;
    createdAt: string;
}

export interface SyncStats {
    total: number;
    needsSync: number;
    inSync: number;
    errors: number;
}

export interface SyncProgress {
    current: number;
    total: number;
}

export interface UseBOMSyncReturn {
    // Data
    pendingChanges: PendingChange[];
    syncHistory: SyncLogEntry[];
    consumptionHistory: ConsumptionEntry[];
    deactivatedItems: DeactivatedItem[];
    stats: SyncStats;

    // Loading states
    isLoadingPending: boolean;
    isLoadingHistory: boolean;
    isSyncing: boolean;
    isPaused: boolean;
    syncingProductId: string | null;

    // Results
    syncResult: { synced: number; failed: number } | null;
    syncErrors: Record<string, string>;
    syncProgress: SyncProgress | null;
    nextSyncIn: string | null;

    // Actions
    handleSyncAll: () => Promise<void>;
    handleSyncSingle: (productId: string, variationId: number) => Promise<void>;
    handleRetryFailed: () => Promise<void>;
    handleCancelSync: () => Promise<void>;
    handleTogglePause: () => void;
    handleRefresh: () => void;
    handleReactivateItem: (itemId: string) => Promise<void>;
    fetchPendingChanges: () => Promise<void>;
    fetchSyncHistory: () => Promise<void>;
}

export function useBOMSync(): UseBOMSyncReturn {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    // Data state
    const [pendingChanges, setPendingChanges] = useState<PendingChange[]>([]);
    const [syncHistory, setSyncHistory] = useState<SyncLogEntry[]>([]);
    const [consumptionHistory, setConsumptionHistory] = useState<ConsumptionEntry[]>([]);
    const [deactivatedItems, setDeactivatedItems] = useState<DeactivatedItem[]>([]);

    // UI state
    const [isLoadingPending, setIsLoadingPending] = useState(true);
    const [isLoadingHistory, setIsLoadingHistory] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isPaused, setIsPaused] = useState(false);
    const [syncingProductId, setSyncingProductId] = useState<string | null>(null);
    const [syncResult, setSyncResult] = useState<{ synced: number; failed: number } | null>(null);
    const [syncErrors, setSyncErrors] = useState<Record<string, string>>({});
    /** Ref to break the fetchPendingChanges → syncErrors → useEffect loop */
    const syncErrorsRef = useRef(syncErrors);
    syncErrorsRef.current = syncErrors;

    /** Ref for isPaused so the polling closure always reads the latest value */
    const isPausedRef = useRef(isPaused);
    isPausedRef.current = isPaused;

    /** Track polling interval/timeout so we can clean up on unmount or re-invocation */
    const pollIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    const pollTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Stats and progress
    const [stats, setStats] = useState<SyncStats>({ total: 0, needsSync: 0, inSync: 0, errors: 0 });
    /** Why ref: handleSyncAll captures stats in its closure; without a ref
     *  the progress bar total would be stale if stats changed between click
     *  and execution. */
    const statsRef = useRef(stats);
    statsRef.current = stats;
    const [syncProgress, setSyncProgress] = useState<SyncProgress | null>(null);
    const [nextSyncIn, setNextSyncIn] = useState<string | null>(null);

    const fetchPendingChanges = useCallback(async () => {
        if (!currentAccount || !token) return;
        setIsLoadingPending(true);
        try {
            const res = await fetch('/api/inventory/bom/pending-changes', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                const products = data.products || [];
                setPendingChanges(products);

                // Read from ref to avoid adding syncErrors to deps (prevents infinite loop)
                const errorCount = Object.values(syncErrorsRef.current).filter(e => e).length;
                setStats({
                    total: data.total,
                    needsSync: data.needsSync,
                    inSync: data.inSync,
                    errors: errorCount
                });
            }
        } catch (err) {
            Logger.error('Failed to fetch pending changes', { error: err });
        } finally {
            setIsLoadingPending(false);
        }
    }, [currentAccount?.id, token]);

    const fetchSyncHistory = useCallback(async () => {
        if (!currentAccount || !token) return;
        setIsLoadingHistory(true);
        try {
            const res = await fetch('/api/inventory/bom/sync-history?limit=20', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setSyncHistory(data.logs || []);
            }
        } catch (err) {
            Logger.error('Failed to fetch sync history', { error: err });
        } finally {
            setIsLoadingHistory(false);
        }
    }, [currentAccount?.id, token]);

    /** Fetch BOM consumption history (deduction ledger entries) */
    const fetchConsumptionHistory = useCallback(async () => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch('/api/inventory/bom/consumption-history?limit=50', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setConsumptionHistory(data.entries || []);
            }
        } catch (err) {
            Logger.error('Failed to fetch consumption history', { error: err });
        }
    }, [currentAccount?.id, token]);

    const checkSyncStatus = useCallback(async () => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch('/api/inventory/bom/sync-status', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                if (data.isSyncing) {
                    setIsSyncing(true);
                    setSyncResult({ synced: -3, failed: 0 });
                    if (data.progress) {
                        setSyncProgress({ current: data.progress.current, total: data.progress.total });
                    }
                }
            }
        } catch (err) {
            Logger.error('Failed to check sync status', { error: err });
        }
    }, [currentAccount?.id, token]);

    const handleSyncSingle = useCallback(async (productId: string, variationId: number) => {
        if (!currentAccount || !token) return;
        const key = `${productId}-${variationId}`;
        setSyncingProductId(key);
        setSyncErrors(prev => ({ ...prev, [key]: '' }));

        try {
            const res = await fetch(`/api/inventory/products/${productId}/bom/sync?variationId=${variationId}`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            const data = await res.json();

            if (!res.ok) {
                const errorMsg = data.error || data.result?.error || `Sync failed (HTTP ${res.status})`;
                setSyncErrors(prev => ({ ...prev, [key]: errorMsg }));
                Logger.error('Sync failed', { productId, variationId, error: errorMsg });
            } else if (data.localDbUpdated || data.previousStock !== data.newStock) {
                setSyncErrors(prev => ({ ...prev, [key]: '' }));
                await fetchPendingChanges();
                await fetchSyncHistory();
            } else if (!data.success) {
                setSyncErrors(prev => ({ ...prev, [key]: data.error || 'Sync returned success=false' }));
            }
        } catch (err: any) {
            const errorMsg = err.message || 'Network error';
            setSyncErrors(prev => ({ ...prev, [key]: errorMsg }));
            Logger.error('Failed to sync single product', { error: err });
        } finally {
            setSyncingProductId(null);
        }
    }, [currentAccount?.id, token, fetchPendingChanges, fetchSyncHistory]);

    const handleSyncAll = useCallback(async () => {
        if (!currentAccount || !token) return;

        // Clean up any existing poll from a previous invocation
        if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
        if (pollTimeoutRef.current) clearTimeout(pollTimeoutRef.current);

        setIsSyncing(true);
        setSyncResult(null);
        setSyncProgress({ current: 0, total: statsRef.current.needsSync });

        try {
            const res = await fetch('/api/inventory/bom/sync-all', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                },
                body: JSON.stringify({})
            });

            if (res.ok) {
                const data = await res.json();

                if (data.status === 'queued' || data.status === 'started') {
                    setSyncResult({ synced: -2, failed: 0 });

                    let pollCount = 0;
                    pollIntervalRef.current = setInterval(async () => {
                        // Why ref: the closure captures stale isPaused, ref always has latest
                        if (isPausedRef.current) return;
                        pollCount++;
                        await fetchPendingChanges();
                        await fetchSyncHistory();
                        await checkSyncStatus();

                        if (pollCount >= 12) {
                            if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
                            pollIntervalRef.current = null;
                            setIsSyncing(false);
                            setSyncProgress(null);
                        }
                    }, 5000);

                    pollTimeoutRef.current = setTimeout(() => {
                        if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
                        pollIntervalRef.current = null;
                        pollTimeoutRef.current = null;
                        setIsSyncing(false);
                        setSyncProgress(null);
                    }, 60000);
                } else if (data.status === 'already_running') {
                    setSyncResult({ synced: -3, failed: 0 });
                    setIsSyncing(false);
                } else {
                    setSyncResult({ synced: data.synced || 0, failed: data.failed || 0 });
                    await fetchPendingChanges();
                    await fetchSyncHistory();
                    setIsSyncing(false);
                    setSyncProgress(null);
                }
            } else {
                setSyncResult({ synced: 0, failed: -1 });
                setIsSyncing(false);
                setSyncProgress(null);
            }
        } catch (err) {
            Logger.error('Failed to sync all', { error: err });
            setSyncResult({ synced: 0, failed: -1 });
            setIsSyncing(false);
            setSyncProgress(null);
        }
    }, [currentAccount?.id, token, fetchPendingChanges, fetchSyncHistory, checkSyncStatus]);

    const handleRetryFailed = useCallback(async () => {
        const failedItems = pendingChanges.filter(item => syncErrors[`${item.productId}-${item.variationId}`]);
        for (const item of failedItems) {
            await handleSyncSingle(item.productId, item.variationId);
        }
    }, [pendingChanges, syncErrors, handleSyncSingle]);

    const handleCancelSync = useCallback(async () => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch('/api/inventory/bom/sync-cancel', {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                setSyncResult(null);
                setIsSyncing(false);
                setSyncProgress(null);
                await fetchPendingChanges();
            }
        } catch (err) {
            Logger.error('Failed to cancel sync', { error: err });
        }
    }, [currentAccount?.id, token, fetchPendingChanges]);

    const handleTogglePause = useCallback(() => {
        setIsPaused(prev => !prev);
    }, []);

    /** Fetch deactivated BOM items for the banner */
    const fetchDeactivatedItems = useCallback(async () => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch('/api/inventory/bom/deactivated-items', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setDeactivatedItems(data.items || []);
            }
        } catch (err) {
            Logger.error('Failed to fetch deactivated items', { error: err });
        }
    }, [currentAccount?.id, token]);

    const handleRefresh = useCallback(() => {
        fetchPendingChanges();
        fetchSyncHistory();
        fetchConsumptionHistory();
        fetchDeactivatedItems();
    }, [fetchPendingChanges, fetchSyncHistory, fetchConsumptionHistory, fetchDeactivatedItems]);

    /** Reactivate a single deactivated item, then refresh the list */
    const handleReactivateItem = useCallback(async (itemId: string) => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch(`/api/inventory/bom/items/${itemId}/reactivate`, {
                method: 'PATCH',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                await fetchDeactivatedItems();
                await fetchPendingChanges();
            }
        } catch (err) {
            Logger.error('Failed to reactivate BOM item', { error: err });
        }
    }, [currentAccount?.id, token, fetchDeactivatedItems, fetchPendingChanges]);

    // Why: fires 5 concurrent fetches. Combined with other page polling,
    // this can exhaust the rate limit budget. Consider a single API endpoint
    // that returns all BOM status data if rate limits become an issue.
    useEffect(() => {
        if (currentAccount && token) {
            fetchPendingChanges();
            fetchSyncHistory();
            fetchConsumptionHistory();
            fetchDeactivatedItems();
            checkSyncStatus();

            // Calculate next sync time (assuming hourly) and keep it fresh
            const updateNextSync = () => {
                const now = new Date();
                const nextHour = new Date(now);
                nextHour.setHours(nextHour.getHours() + 1, 0, 0, 0);
                const minutesUntil = Math.round((nextHour.getTime() - now.getTime()) / 60000);
                setNextSyncIn(`${minutesUntil} min`);
            };
            updateNextSync();
            const syncTimerId = setInterval(updateNextSync, 60000);

            return () => clearInterval(syncTimerId);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentAccount?.id, token]);

    // Cleanup polling on unmount to prevent setState on unmounted component
    useEffect(() => {
        return () => {
            if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
            if (pollTimeoutRef.current) clearTimeout(pollTimeoutRef.current);
        };
    }, []);

    return {
        pendingChanges,
        syncHistory,
        consumptionHistory,
        deactivatedItems,
        stats,
        isLoadingPending,
        isLoadingHistory,
        isSyncing,
        isPaused,
        syncingProductId,
        syncResult,
        syncErrors,
        syncProgress,
        nextSyncIn,
        handleSyncAll,
        handleSyncSingle,
        handleRetryFailed,
        handleCancelSync,
        handleTogglePause,
        handleRefresh,
        handleReactivateItem,
        fetchPendingChanges,
        fetchSyncHistory,
    };
}

/**
 * Maps raw API errors to user-friendly messages with fix suggestions.
 */
export function getErrorDetails(error: string): { message: string; fix: string } {
    const errorMap: Record<string, { message: string; fix: string }> = {
        'rest_product_invalid_id': {
            message: 'Product not found in WooCommerce',
            fix: 'Re-sync products from Settings → WooCommerce'
        },
        'woocommerce_rest_cannot_edit': {
            message: 'Product is read-only in WooCommerce',
            fix: 'Check API key permissions in WooCommerce'
        },
        'ECONNREFUSED': {
            message: 'Cannot connect to store',
            fix: 'Verify store URL in Settings'
        },
        'rate_limit': {
            message: 'API rate limit reached',
            fix: 'Wait 60 seconds and retry'
        },
        'stock_quantity': {
            message: 'Component has no stock configured',
            fix: 'Set stock quantity in WooCommerce first'
        },
        'ETIMEDOUT': {
            message: 'Store connection timed out',
            fix: 'Check if store is online and accessible'
        },
        '401': {
            message: 'WooCommerce authentication failed',
            fix: 'Re-enter API credentials in Settings'
        },
        '403': {
            message: 'Permission denied by WooCommerce',
            fix: 'Check API key has read/write permissions'
        }
    };

    for (const [key, details] of Object.entries(errorMap)) {
        if (error.toLowerCase().includes(key.toLowerCase())) {
            return details;
        }
    }

    return {
        message: error.length > 80 ? error.substring(0, 80) + '...' : error,
        fix: 'Check logs for more details or contact support'
    };
}

import { useCallback, useEffect, useState } from 'react';
import { Logger } from '../utils/logger';

/**
 * Background Fetch status
 */
type BackgroundFetchStatus = 'pending' | 'success' | 'fail' | 'aborted';

interface BackgroundFetchProgress {
    id: string;
    downloaded: number;
    total: number;
    status: BackgroundFetchStatus;
}

/**
 * Hook for Background Fetch API
 *
 * Enables large file downloads/uploads that survive app close.
 * Falls back to regular fetch for unsupported browsers.
 *
 * @example
 * ```tsx
 * const { startBackgroundFetch, isSupported } = useBackgroundFetch();
 *
 * // Download large file in background
 * const result = await startBackgroundFetch(
 *   'video-export',
 *   ['/api/exports/video/123'],
 *   { title: 'Exporting video...', icons: [{ src: '/icons/icon-96.png' }] }
 * );
 * ```
 */
export function useBackgroundFetch() {
    const [isSupported] = useState(() => {
        if (typeof navigator === 'undefined') return false;
        return 'serviceWorker' in navigator;
    });

    const [activeFetches, setActiveFetches] = useState<Map<string, BackgroundFetchProgress>>(new Map());

    /**
     * Starts a background fetch operation.
     * Falls back to regular fetch on unsupported browsers.
     */
    const startBackgroundFetch = useCallback(async (
        id: string,
        requests: (string | Request)[],
        options?: {
            title?: string;
            icons?: Array<{ src: string; sizes?: string; type?: string }>;
            downloadTotal?: number;
        }
    ): Promise<Response[] | null> => {
        // Check for Background Fetch support
        const registration = await navigator.serviceWorker?.ready;

        // @ts-expect-error - backgroundFetch not in TypeScript types
        if (!registration?.backgroundFetch) {
            Logger.debug('[BackgroundFetch] Not supported, falling back to regular fetch');
            // Fallback to regular fetch
            try {
                const responses = await Promise.all(
                    requests.map(req => fetch(req))
                );
                return responses;
            } catch (err) {
                Logger.error('[BackgroundFetch] Fallback fetch failed:', { error: err });
                return null;
            }
        }

        try {
            // @ts-expect-error - backgroundFetch not in TypeScript types
            const bgFetch = await registration.backgroundFetch.fetch(id, requests, {
                title: options?.title || 'Downloading...',
                icons: options?.icons || [],
                downloadTotal: options?.downloadTotal
            });

            // Track progress
            setActiveFetches(prev => {
                const next = new Map(prev);
                next.set(id, {
                    id,
                    downloaded: 0,
                    total: options?.downloadTotal || 0,
                    status: 'pending'
                });
                return next;
            });

            // Listen for progress
            bgFetch.addEventListener('progress', () => {
                setActiveFetches(prev => {
                    const next = new Map(prev);
                    next.set(id, {
                        id,
                        downloaded: bgFetch.downloaded,
                        total: bgFetch.downloadTotal,
                        status: 'pending'
                    });
                    return next;
                });
            });

            Logger.debug('[BackgroundFetch] Started:', { id, requestCount: requests.length });

            // Wait for completion
            const result = await bgFetch.result;
            const records = await bgFetch.matchAll();
            const responses = await Promise.all(records.map((r: { responseReady: Promise<Response> }) => r.responseReady));

            // Update status
            setActiveFetches(prev => {
                const next = new Map(prev);
                next.set(id, {
                    id,
                    downloaded: bgFetch.downloaded,
                    total: bgFetch.downloadTotal,
                    status: result as BackgroundFetchStatus
                });
                return next;
            });

            return responses;
        } catch (err) {
            Logger.error('[BackgroundFetch] Failed:', { id, error: err });
            setActiveFetches(prev => {
                const next = new Map(prev);
                next.set(id, {
                    id,
                    downloaded: 0,
                    total: 0,
                    status: 'fail'
                });
                return next;
            });
            return null;
        }
    }, []);

    /**
     * Aborts an active background fetch.
     */
    const abortBackgroundFetch = useCallback(async (id: string): Promise<boolean> => {
        try {
            const registration = await navigator.serviceWorker?.ready;
            // @ts-expect-error - backgroundFetch not in TypeScript types
            const bgFetch = await registration?.backgroundFetch?.get(id);
            if (bgFetch) {
                await bgFetch.abort();
                setActiveFetches(prev => {
                    const next = new Map(prev);
                    next.delete(id);
                    return next;
                });
                return true;
            }
            return false;
        } catch (err) {
            Logger.warn('[BackgroundFetch] Abort failed:', { id, error: err });
            return false;
        }
    }, []);

    /**
     * Gets progress for a specific background fetch.
     */
    const getProgress = useCallback((id: string): BackgroundFetchProgress | undefined => {
        return activeFetches.get(id);
    }, [activeFetches]);

    return {
        startBackgroundFetch,
        abortBackgroundFetch,
        getProgress,
        activeFetches,
        isSupported
    };
}

/**
 * Hook for managing canned responses in the inbox.
 * Handles fetching, filtering, and selection of pre-saved reply templates.
 */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';

export interface CannedResponseLabel {
    id: string;
    name: string;
    color: string;
}

export interface CannedResponse {
    id: string;
    shortcut: string;
    content: string;
    labelId: string | null;
    label: CannedResponseLabel | null;
}


export interface CustomerContext {
    firstName?: string;
    lastName?: string;
    email?: string;
    // Extended context
    ordersCount?: number;
    totalSpent?: number;
    wooCustomerId?: number;
    // Agent context
    agentFirstName?: string;
    agentFullName?: string;
}

interface UseCannedResponsesReturn {
    /** All available canned responses */
    cannedResponses: CannedResponse[];
    /** Filtered responses based on current filter text */
    filteredCanned: CannedResponse[];
    /** Whether the canned dropdown is visible */
    showCanned: boolean;
    /** Current filter text (without leading /) */
    cannedFilter: string;
    /** Show/hide the canned responses manager modal */
    showCannedManager: boolean;
    /** Set dropdown visibility */
    setShowCanned: (show: boolean) => void;
    /** Set manager modal visibility */
    setShowCannedManager: (show: boolean) => void;
    /** Handle input change to detect / trigger */
    handleInputForCanned: (input: string) => void;
    /** Select a canned response and replace placeholders */
    selectCanned: (response: CannedResponse, context?: CustomerContext) => string;
    /** Refetch canned responses (after manager updates) */
    refetchCanned: () => Promise<void>;
}

/**
 * Replaces placeholders in content with actual customer values.
 * Supports customer, order, and agent placeholders.
 */
function replacePlaceholders(content: string, context?: CustomerContext): string {
    if (!context) return content;

    const fullName = [context.firstName, context.lastName].filter(Boolean).join(' ');
    const greeting = context.firstName ? `Hi ${context.firstName}` : 'Hi there';
    const formattedSpent = context.totalSpent != null
        ? `$${context.totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
        : '';

    return content
        // Customer placeholders
        .replace(/\{\{customer\.firstName\}\}/gi, context.firstName || 'there')
        .replace(/\{\{customer\.lastName\}\}/gi, context.lastName || '')
        .replace(/\{\{customer\.email\}\}/gi, context.email || '')
        .replace(/\{\{customer\.name\}\}/gi, fullName || 'there')
        .replace(/\{\{customer\.greeting\}\}/gi, greeting)
        .replace(/\{\{customer\.ordersCount\}\}/gi, context.ordersCount?.toString() || '0')
        .replace(/\{\{customer\.totalSpent\}\}/gi, formattedSpent)
        // Agent placeholders
        .replace(/\{\{agent\.firstName\}\}/gi, context.agentFirstName || '')
        .replace(/\{\{agent\.fullName\}\}/gi, context.agentFullName || '');
}


/**
 * Manages canned response state and logic.
 * Detects '/' prefix in input to show dropdown, filters by shortcut/content.
 */
export function useCannedResponses(): UseCannedResponsesReturn {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [cannedResponses, setCannedResponses] = useState<CannedResponse[]>([]);
    const [showCanned, setShowCanned] = useState(false);
    const [cannedFilter, setCannedFilter] = useState('');
    const [showCannedManager, setShowCannedManager] = useState(false);

    // Fetch canned responses on mount
    const fetchCanned = useCallback(async () => {
        if (!currentAccount || !token) return;

        try {
            const res = await fetch('/api/chat/canned-responses', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setCannedResponses(data);
            }
        } catch {
            // Silently fail - non-critical feature
        }
    }, [currentAccount, token]);

    useEffect(() => {
        fetchCanned();
    }, [fetchCanned]);

    // Filter by shortcut, content, or label name
    const filteredCanned = useMemo(() => {
        if (!cannedFilter) return cannedResponses;
        const filter = cannedFilter.toLowerCase();
        return cannedResponses.filter(r =>
            r.shortcut.toLowerCase().includes(filter) ||
            r.content.toLowerCase().includes(filter) ||
            (r.label?.name && r.label.name.toLowerCase().includes(filter))
        );
    }, [cannedResponses, cannedFilter]);

    /**
     * Detects '/' prefix in input to trigger canned dropdown.
     * Call this from onChange handler with the current input value.
     */
    const handleInputForCanned = useCallback((input: string) => {
        // Strip HTML tags to get plain text
        const plainText = input.replace(/<[^>]*>/g, '').trim();
        if (plainText.startsWith('/')) {
            setShowCanned(true);
            setCannedFilter(plainText.slice(1).toLowerCase());
        } else {
            setShowCanned(false);
            setCannedFilter('');
        }
    }, []);

    /**
     * Selects a canned response and replaces placeholders.
     * Returns the content with placeholders replaced.
     */
    const selectCanned = useCallback((response: CannedResponse, context?: CustomerContext): string => {
        setShowCanned(false);
        setCannedFilter('');
        return replacePlaceholders(response.content, context);
    }, []);

    return {
        cannedResponses,
        filteredCanned,
        showCanned,
        cannedFilter,
        showCannedManager,
        setShowCanned,
        setShowCannedManager,
        handleInputForCanned,
        selectCanned,
        refetchCanned: fetchCanned
    };
}

/**
 * useCommandPalette Hook
 * 
 * Provides global access to the CommandPalette open state.
 * Allows Header and other components to trigger the search modal.
 */

import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';

interface CommandPaletteContextValue {
    /** Whether the palette is currently open */
    isOpen: boolean;
    /** Open the command palette */
    open: () => void;
    /** Close the command palette */
    close: () => void;
    /** Toggle open state */
    toggle: () => void;
}

const CommandPaletteContext = createContext<CommandPaletteContextValue | null>(null);

interface CommandPaletteProviderProps {
    children: ReactNode;
}

/**
 * Provider component that wraps the app to provide palette state.
 * Should be placed near the root of the component tree.
 */
export function CommandPaletteProvider({ children }: CommandPaletteProviderProps) {
    const [isOpen, setIsOpen] = useState(false);

    const open = useCallback(() => setIsOpen(true), []);
    const close = useCallback(() => setIsOpen(false), []);
    const toggle = useCallback(() => setIsOpen(prev => !prev), []);

    // Listen for global toggle event (fired by Ctrl+K handler in CommandPalette)
    React.useEffect(() => {
        const handleToggle = () => toggle();
        window.addEventListener('commandpalette:toggle', handleToggle);
        return () => window.removeEventListener('commandpalette:toggle', handleToggle);
    }, [toggle]);

    return (
        <CommandPaletteContext.Provider value={{ isOpen, open, close, toggle }}>
            {children}
        </CommandPaletteContext.Provider>
    );
}

/**
 * Hook to access and control the command palette state.
 * Must be used within a CommandPaletteProvider.
 */
export function useCommandPalette(): CommandPaletteContextValue {
    const context = useContext(CommandPaletteContext);
    if (!context) {
        throw new Error('useCommandPalette must be used within a CommandPaletteProvider');
    }
    return context;
}

