/**
 * useLoadingTimeout Hook
 * 
 * EDGE CASE FIX: Handle skeleton infinite loading in offline mode.
 * Returns whether the loading timeout has been exceeded, suggesting
 * the user may be offline or experiencing connectivity issues.
 */

import { useState, useEffect } from 'react';

interface UseLoadingTimeoutOptions {
    /** Timeout in milliseconds before showing offline message (default: 10000ms) */
    timeoutMs?: number;
    /** Whether loading is currently active */
    isLoading: boolean;
}

interface UseLoadingTimeoutResult {
    /** Whether the timeout has been exceeded */
    hasTimedOut: boolean;
    /** Whether the browser reports being offline */
    isOffline: boolean;
    /** Human-readable message for the current state */
    message: string;
}

export function useLoadingTimeout({
    timeoutMs = 10000,
    isLoading
}: UseLoadingTimeoutOptions): UseLoadingTimeoutResult {
    const [hasTimedOut, setHasTimedOut] = useState(false);
    const [isOffline, setIsOffline] = useState(!navigator.onLine);

    // Track online/offline status
    useEffect(() => {
        const handleOnline = () => setIsOffline(false);
        const handleOffline = () => setIsOffline(true);

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    // Start timeout when loading begins
    useEffect(() => {
        if (!isLoading) {
            setHasTimedOut(false);
            return;
        }

        const timer = setTimeout(() => {
            setHasTimedOut(true);
        }, timeoutMs);

        return () => clearTimeout(timer);
    }, [isLoading, timeoutMs]);

    // Determine message
    let message = '';
    if (hasTimedOut) {
        if (isOffline) {
            message = 'You appear to be offline. Please check your internet connection.';
        } else {
            message = 'Loading is taking longer than expected. The server may be experiencing issues.';
        }
    }

    return {
        hasTimedOut,
        isOffline,
        message
    };
}

/**
 * Hook for managing message sending logic in chat conversations.
 * Handles undo delay, quote replies, email signatures, and scheduling.
 */
import { useState, useCallback, useRef, useEffect, type MutableRefObject } from 'react';
import { Logger } from '../utils/logger';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { useSocket } from '../context/SocketContext';
import { useDrafts } from './useDrafts';
import { ConversationChannel } from '../components/chat/ChannelSelector';

interface UseMessageSendOptions {
    conversationId: string;
    onSendMessage: (content: string, type: 'AGENT' | 'SYSTEM', isInternal: boolean, channel?: ConversationChannel, emailAccountId?: string) => Promise<void>;
    recipientEmail?: string;
    isLiveChat?: boolean;
    emailAccountId?: string;
}

interface PendingSend {
    content: string;
    timeout: NodeJS.Timeout;
    countdownInterval: NodeJS.Timeout;
    remainingSeconds: number;
}

interface UseMessageSendReturn {
    /** Current input value */
    input: string;
    /** Set input value */
    setInput: (value: string) => void;
    /** Whether sending is in progress */
    isSending: boolean;
    /** Currently pending send (for undo UI) */
    pendingSend: PendingSend | null;
    /** Whether a message is an internal note */
    isInternal: boolean;
    /** Toggle internal note mode */
    setIsInternal: (value: boolean) => void;
    /** Email signature enabled state */
    signatureEnabled: boolean;
    /** Toggle email signature */
    setSignatureEnabled: (value: boolean) => void;
    /** Quoted message for reply */
    quotedMessage: { id: string; content: string; senderType: string } | null;
    /** Set quoted message */
    setQuotedMessage: (msg: { id: string; content: string; senderType: string } | null) => void;
    /** Send the current message */
    handleSend: (e?: React.FormEvent, channel?: ConversationChannel) => void;
    /** Cancel a pending send (undo) */
    cancelPendingSend: () => void;
    /** Schedule a message for later */
    handleScheduleMessage: (scheduledFor: Date) => Promise<void>;
    /** Whether scheduling is in progress */
    isScheduling: boolean;
    /** Undo delay in milliseconds */
    UNDO_DELAY_MS: number;
}

const UNDO_DELAY_MS = 5000;

/**
 * Manages message sending with undo capability, quote replies, and scheduling.
 */
export function useMessageSend({
    conversationId,
    onSendMessage,
    recipientEmail,
    isLiveChat,
    emailAccountId
}: UseMessageSendOptions): UseMessageSendReturn {
    const { token, user } = useAuth();
    const { currentAccount } = useAccount();
    const { socket } = useSocket();
    const { getDraft, saveDraft, clearDraft } = useDrafts();

    const [input, setInput] = useState('');
    const [isInternal, setIsInternal] = useState(false);
    const [isSending, setIsSending] = useState(false);
    const [signatureEnabled, setSignatureEnabled] = useState(true);
    const [quotedMessage, setQuotedMessage] = useState<{ id: string; content: string; senderType: string } | null>(null);
    const [pendingSend, setPendingSend] = useState<PendingSend | null>(null);
    const [isScheduling, setIsScheduling] = useState(false);

    // Ref that always holds the latest pendingSend — avoids stale closure
    // when the conversation-switch effect fires.
    const pendingSendRef: MutableRefObject<PendingSend | null> = useRef(null);
    pendingSendRef.current = pendingSend;

    // Load draft when conversation changes
    useEffect(() => {
        if (conversationId) {
            const savedDraft = getDraft(conversationId);
            setInput(savedDraft);
            setQuotedMessage(null);
            // Cancel any pending send using ref to avoid stale closure
            const pending = pendingSendRef.current;
            if (pending) {
                clearTimeout(pending.timeout);
                clearInterval(pending.countdownInterval);
                setPendingSend(null);
            }
        }
    }, [conversationId, getDraft]);

    // Why: if component unmounts while a send is pending, the timeout and
    // countdownInterval keep running, firing setState on an unmounted component.
    useEffect(() => {
        return () => {
            const pending = pendingSendRef.current;
            if (pending) {
                clearTimeout(pending.timeout);
                clearInterval(pending.countdownInterval);
            }
        };
    }, []);

    // Auto-save draft on input change
    useEffect(() => {
        if (conversationId && input) {
            saveDraft(conversationId, input);
        }
    }, [input, conversationId, saveDraft]);

    /**
     * Cancel a pending send and restore input.
     */
    const cancelPendingSend = useCallback(() => {
        if (pendingSend) {
            clearTimeout(pendingSend.timeout);
            clearInterval(pendingSend.countdownInterval);
            setInput(pendingSend.content);
            setPendingSend(null);
        }
    }, [pendingSend]);

    /**
     * Prepare message content with quote and signature.
     */
    const prepareContent = useCallback((messageContent: string): string => {
        let content = messageContent;

        // Prepend quoted message if present
        if (quotedMessage) {
            const quotedText = quotedMessage.content.replace(/<[^>]*>/g, '').substring(0, 100);
            content = `<blockquote style="border-left: 2px solid #ccc; margin: 0 0 10px 0; padding-left: 10px; color: #666;">${quotedText}${quotedText.length >= 100 ? '...' : ''}</blockquote>${content}`;
        }

        // Append email signature for email replies (not internal notes)
        const shouldAppendSignature = signatureEnabled &&
            user?.emailSignature &&
            !isInternal &&
            recipientEmail &&
            !isLiveChat;

        if (shouldAppendSignature) {
            content = `${content}\n\n---\n${user!.emailSignature}`;
        }

        return content;
    }, [quotedMessage, signatureEnabled, user, isInternal, recipientEmail]);

    /**
     * Send the current message with undo delay.
     */
    const handleSend = useCallback((e?: React.FormEvent, channel?: ConversationChannel) => {
        e?.preventDefault();

        // Strip HTML to check for actual content
        const plainText = input.replace(/<[^>]*>/g, '').trim();
        if (!plainText || isSending || pendingSend) return;

        const finalContent = prepareContent(input);

        // Store content and start undo timer with countdown
        const startSeconds = Math.ceil(UNDO_DELAY_MS / 1000);

        const timeout = setTimeout(async () => {
            setIsSending(true);
            try {
                await onSendMessage(finalContent, 'AGENT', isInternal, channel, emailAccountId);
                clearDraft(conversationId);
            } finally {
                setIsSending(false);
                setPendingSend(null);
            }
        }, UNDO_DELAY_MS);

        // Start countdown interval
        const countdownInterval = setInterval(() => {
            setPendingSend(prev => {
                if (!prev || prev.remainingSeconds <= 1) return prev;
                return { ...prev, remainingSeconds: prev.remainingSeconds - 1 };
            });
        }, 1000);

        setPendingSend({ content: input, timeout, countdownInterval, remainingSeconds: startSeconds });
        setInput('');
        setQuotedMessage(null);

        // Emit typing stop
        if (socket && conversationId) {
            socket.emit('typing:stop', { conversationId });
        }
    }, [input, isSending, pendingSend, prepareContent, onSendMessage, isInternal, clearDraft, conversationId, socket, emailAccountId]);

    /**
     * Schedule a message for later delivery.
     */
    const handleScheduleMessage = useCallback(async (scheduledFor: Date) => {
        const plainText = input.replace(/<[^>]*>/g, '').trim();
        if (!plainText || !token || !currentAccount) return;

        setIsScheduling(true);
        try {
            const finalContent = prepareContent(input);

            const res = await fetch(`/api/chat/${conversationId}/messages/schedule`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount.id,
                },
                body: JSON.stringify({
                    content: finalContent,
                    scheduledFor: scheduledFor.toISOString(),
                    isInternal,
                }),
            });

            if (!res.ok) {
                const errData = await res.json();
                Logger.warn('Failed to schedule message', { error: errData.error });
                return;
            }

            // Clear input on success
            setInput('');
            clearDraft(conversationId);
            Logger.info('Message scheduled', { scheduledFor: scheduledFor.toISOString() });
        } catch (error) {
            Logger.error('Schedule message error:', { error: error });
        } finally {
            setIsScheduling(false);
        }
    }, [input, token, currentAccount, conversationId, prepareContent, isInternal, clearDraft]);

    return {
        input,
        setInput,
        isSending,
        pendingSend,
        isInternal,
        setIsInternal,
        signatureEnabled,
        setSignatureEnabled,
        quotedMessage,
        setQuotedMessage,
        handleSend,
        cancelPendingSend,
        handleScheduleMessage,
        isScheduling,
        UNDO_DELAY_MS
    };
}

import { useState, useEffect, useSyncExternalStore } from 'react';

/**
 * Get the current mobile state from window.
 * Safe for SSR - returns false on server.
 */
function getIsMobile(): boolean {
    if (typeof window === 'undefined') return false;
    return window.innerWidth < 1024;
}

/**
 * Subscribe to window resize events.
 */
function subscribe(callback: () => void): () => void {
    window.addEventListener('resize', callback);
    return () => window.removeEventListener('resize', callback);
}

/**
 * Custom hook to detect mobile/tablet viewport.
 * Returns true for viewports < 1024px (lg breakpoint in Tailwind).
 * Uses useSyncExternalStore for proper SSR/hydration handling.
 */
export function useMobile(): boolean {
    // Use useSyncExternalStore for proper hydration
    return useSyncExternalStore(
        subscribe,
        getIsMobile, // Client snapshot
        () => false  // Server snapshot (SSR fallback)
    );
}

/**
 * Get the current small mobile state from window.
 */
function getIsSmallMobile(): boolean {
    if (typeof window === 'undefined') return false;
    return window.innerWidth < 768;
}

/**
 * Hook for smaller mobile devices (< 768px / md breakpoint).
 */
export function useSmallMobile(): boolean {
    return useSyncExternalStore(
        subscribe,
        getIsSmallMobile,
        () => false
    );
}

/**
 * useOrders Hook
 *
 * Manages orders data fetching, filtering, pagination, and actions.
 * Extracted from OrdersPage.tsx for maintainability.
 */

import { useState, useEffect, useCallback, useRef } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { useDebouncedValue } from './useDebouncedValue';
import { Logger } from '../utils/logger';
import { printPicklist } from '../utils/printPicklist';

export interface Order {
    id: number;
    status: string;
    total: number;
    currency: string;
    date_created: string;
    customer_id?: number;
    tags?: string[];
    billing: {
        first_name: string;
        last_name: string;
        email: string;
    };
    payment_method_title?: string;
    line_items: Array<{
        name: string;
        quantity: number;
    }>;
}

interface OrderAttribution {
    lastTouchSource: string;
    firstTouchSource?: string;
    utmSource?: string;
    utmMedium?: string;
    utmCampaign?: string;
    referrer?: string;
}

export function useOrders() {
    const [searchParams, setSearchParams] = useSearchParams();
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    // Initialize from URL
    const tagsFromUrl = searchParams.get('tags');
    const searchFromUrl = searchParams.get('q');
    const statusFromUrl = searchParams.get('status');

    // Core state
    const [orders, setOrders] = useState<Order[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [searchQuery, setSearchQuery] = useState(searchFromUrl || '');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);
    const [selectedOrderId, setSelectedOrderId] = useState<number | null>(null);

    // Tag filtering
    const [availableTags, setAvailableTags] = useState<string[]>([]);
    const [tagColors, setTagColors] = useState<Record<string, string>>({});
    const [selectedTags, setSelectedTags] = useState<string[]>(
        tagsFromUrl ? tagsFromUrl.split(',').filter(Boolean) : []
    );
    const [showTagDropdown, setShowTagDropdown] = useState(false);
    const [attributions, setAttributions] = useState<Record<number, OrderAttribution | null>>({});

    // Status filter
    const [selectedStatus, setSelectedStatus] = useState(statusFromUrl || 'all');
    const [statusCountsKey, setStatusCountsKey] = useState(0);

    // Picklist state
    const [picklistStatus, setPicklistStatus] = useState('processing');
    const [isGeneratingPicklist, setIsGeneratingPicklist] = useState(false);

    const debouncedSearch = useDebouncedValue(searchQuery, 400);

    // Sync filter state to URL
    useEffect(() => {
        const params: Record<string, string> = {};
        if (selectedTags.length > 0) params.tags = selectedTags.join(',');
        if (debouncedSearch) params.q = debouncedSearch;
        if (selectedStatus && selectedStatus !== 'all') params.status = selectedStatus;
        setSearchParams(params, { replace: true });
    }, [selectedTags, debouncedSearch, selectedStatus, setSearchParams]);

    // Fetch available tags
    useEffect(() => {
        if (!currentAccount || !token) return;
        const controller = new AbortController();
        fetch('/api/sync/orders/tags', {
            headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id },
            signal: controller.signal
        })
            .then(res => res.json())
            .then(data => { setAvailableTags(data.tags || []); setTagColors(data.tagColors || {}); })
            .catch(err => { if (err.name !== 'AbortError') { setAvailableTags([]); setTagColors({}); } });
        return () => controller.abort();
    }, [currentAccount, token]);

    // Fetch orders
    const fetchOrders = useCallback(async (signal?: AbortSignal) => {
        if (!currentAccount || !token) return;
        setIsLoading(true);
        try {
            const params = new URLSearchParams();
            params.append('page', page.toString());
            params.append('limit', limit.toString());
            // Why debouncedSearch: using raw searchQuery causes fetches on every
            // keystroke, then re-fetches when the debounce fires (double-fetch).
            if (debouncedSearch) params.append('q', debouncedSearch);
            if (selectedTags.length > 0) params.append('tags', selectedTags.join(','));
            if (selectedStatus && selectedStatus !== 'all') params.append('status', selectedStatus);

            const res = await fetch(`/api/sync/orders/search?${params}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id },
                signal
            });
            if (!res.ok) throw new Error('Failed to fetch orders');

            const data = await res.json();
            setOrders(data.orders || data);
            setTotalPages(data.totalPages || 1);
        } catch (err) {
            if (err instanceof Error && err.name === 'AbortError') return;
            Logger.error('Failed to fetch orders', { error: err });
        } finally {
            setIsLoading(false);
        }
    }, [currentAccount, token, page, limit, debouncedSearch, selectedTags, selectedStatus]);

    useEffect(() => {
        const controller = new AbortController();
        fetchOrders(controller.signal);
        return () => controller.abort();
    }, [fetchOrders]);

    // Reset page on filter change
    useEffect(() => { setPage(1); }, [debouncedSearch, selectedTags, selectedStatus]);

    // Fetch attributions for visible orders in a single batch call
    useEffect(() => {
        if (!orders.length || !token || !currentAccount) return;

        const controller = new AbortController();

        const fetchAttributions = async () => {
            // Only fetch for orders we haven't fetched yet
            const uncachedIds = orders
                .filter(o => attributions[o.id] === undefined)
                .map(o => o.id);

            if (uncachedIds.length === 0) return;

            try {
                const res = await fetch('/api/orders/batch-attributions', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`,
                        'X-Account-ID': currentAccount.id
                    },
                    body: JSON.stringify({ orderIds: uncachedIds }),
                    signal: controller.signal
                });

                if (res.ok) {
                    const data = await res.json();
                    const batchResult: Record<number, OrderAttribution | null> = {};
                    for (const [id, attr] of Object.entries(data.attributions)) {
                        batchResult[Number(id)] = attr as OrderAttribution | null;
                    }
                    setAttributions(prev => ({ ...prev, ...batchResult }));
                }
            } catch (err) {
                if (err instanceof Error && err.name === 'AbortError') return;
                // Mark all as null on failure so we don't retry
                const fallback: Record<number, null> = {};
                uncachedIds.forEach(id => { fallback[id] = null; });
                setAttributions(prev => ({ ...prev, ...fallback }));
            }
        };

        fetchAttributions();
        return () => controller.abort();
    // Why attributions in deps: without it, the stale closure always sees
    // the initial empty object, causing redundant refetches for every page.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [orders, token, currentAccount, attributions]);

    // Ref to hold the post-sync fetch timeout for cleanup
    const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    const handleSync = useCallback(async () => {
        if (!currentAccount || !token) return;
        setIsSyncing(true);
        try {
            const res = await fetch('/api/sync/manual', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id },
                body: JSON.stringify({ accountId: currentAccount.id, types: ['orders'] })
            });
            if (!res.ok) throw new Error('Sync failed');
            const result = await res.json();
            Logger.info('Sync started', { status: result.status });
            // Why ref: so cleanup can cancel if component unmounts during 2s delay
            syncTimeoutRef.current = setTimeout(() => {
                fetchOrders();
                setStatusCountsKey(prev => prev + 1);
            }, 2000);
        } catch (err) {
            Logger.error('Sync failed', { error: err });
        } finally {
            setIsSyncing(false);
        }
    }, [currentAccount, token, fetchOrders]);

    // Cleanup sync timeout on unmount
    useEffect(() => {
        return () => {
            if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);
        };
    }, []);

    const handleGeneratePicklist = useCallback(async () => {
        if (!currentAccount || !token) return;
        setIsGeneratingPicklist(true);
        try {
            const params = new URLSearchParams({ status: picklistStatus, limit: '100' });
            const res = await fetch(`/api/inventory/picklist?${params}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (res.ok) {
                const data = await res.json();
                if (data.length === 0) alert('No items found for the selected status.');
                else printPicklist(data);
            } else {
                alert('Failed to generate picklist');
            }
        } catch (error) {
            Logger.error('Error generating picklist', { error });
            alert('Error generating picklist');
        } finally {
            setIsGeneratingPicklist(false);
        }
    }, [currentAccount, token, picklistStatus]);

    const removeTag = useCallback(async (orderId: number, tag: string) => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch(`/api/orders/${orderId}/tags/${encodeURIComponent(tag)}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (res.ok) {
                setOrders(prev => prev.map(order =>
                    order.id === orderId ? { ...order, tags: (order.tags || []).filter(t => t !== tag) } : order
                ));
            }
        } catch (err) {
            Logger.error('Failed to remove tag', { error: err });
        }
    }, [currentAccount, token]);

    return {
        // State
        orders, isLoading, isSyncing, searchQuery, setSearchQuery,
        page, setPage, limit, setLimit, totalPages,
        selectedOrderId, setSelectedOrderId,
        availableTags, tagColors, selectedTags, setSelectedTags,
        showTagDropdown, setShowTagDropdown, attributions,
        selectedStatus, setSelectedStatus, statusCountsKey,
        picklistStatus, setPicklistStatus, isGeneratingPicklist,
        currentAccount,

        // Actions
        handleSync, handleGeneratePicklist, removeTag
    };
}

