import { useEffect, useState, useRef, useCallback } from 'react';

/**
 * Unique identifier for this browser tab instance.
 * Generated once per page load to ensure consistent identity.
 */
const TAB_ID = `tab-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;

/**
 * Heartbeat interval for leader election (ms).
 * Leader broadcasts heartbeat at this interval; followers detect leader loss after 2x this value.
 */
const HEARTBEAT_INTERVAL = 2000;
const LEADER_TIMEOUT = HEARTBEAT_INTERVAL * 2.5;

interface TabMessage {
    type: 'heartbeat' | 'claim' | 'resign';
    tabId: string;
    timestamp: number;
}

/**
 * Hook for cross-tab leader election using BroadcastChannel.
 * Only ONE tab becomes the leader; others become followers.
 * 
 * Uses lowest-ID-wins algorithm with heartbeat-based failure detection.
 * 
 * @param channelName - Unique channel name for this leader election group
 * @returns { isLeader, tabId } - Whether this tab is the leader and its unique ID
 * 
 * @example
 * const { isLeader, tabId } = useTabLeader('overseek-polling');
 * if (isLeader) {
 *   // Only this tab should poll the API
 * }
 */
export function useTabLeader(channelName: string): { isLeader: boolean; tabId: string } {
    const [isLeader, setIsLeader] = useState(false);
    const channelRef = useRef<BroadcastChannel | null>(null);
    const knownTabsRef = useRef<Map<string, number>>(new Map());
    const heartbeatIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    const leaderCheckIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

    /**
     * Determines if this tab should be leader based on lowest-ID-wins algorithm.
     * Why: Deterministic election without coordination overhead.
     */
    const determineLeadership = useCallback(() => {
        const now = Date.now();
        // Filter out stale tabs (no heartbeat within timeout)
        const activeTabs: string[] = [];
        knownTabsRef.current.forEach((timestamp, tabId) => {
            if (now - timestamp < LEADER_TIMEOUT) {
                activeTabs.push(tabId);
            } else {
                knownTabsRef.current.delete(tabId);
            }
        });

        // Add self if not present
        if (!activeTabs.includes(TAB_ID)) {
            activeTabs.push(TAB_ID);
        }

        // Lowest ID wins
        activeTabs.sort();
        const shouldBeLeader = activeTabs[0] === TAB_ID;

        setIsLeader(shouldBeLeader);
    }, []);

    /**
     * Broadcasts a heartbeat message to all tabs.
     */
    const sendHeartbeat = useCallback(() => {
        if (channelRef.current) {
            const message: TabMessage = {
                type: 'heartbeat',
                tabId: TAB_ID,
                timestamp: Date.now(),
            };
            channelRef.current.postMessage(message);
        }
        // Update own timestamp
        knownTabsRef.current.set(TAB_ID, Date.now());
    }, []);

    useEffect(() => {
        // BroadcastChannel not supported in all environments (e.g., SSR, older browsers)
        if (typeof BroadcastChannel === 'undefined') {
            // Fallback: this tab is always leader
            setIsLeader(true);
            return;
        }

        const channel = new BroadcastChannel(channelName);
        channelRef.current = channel;

        // Handle incoming messages
        channel.onmessage = (event: MessageEvent<TabMessage>) => {
            const { type, tabId, timestamp } = event.data;

            if (type === 'heartbeat' || type === 'claim') {
                knownTabsRef.current.set(tabId, timestamp);
                determineLeadership();
            } else if (type === 'resign') {
                knownTabsRef.current.delete(tabId);
                determineLeadership();
            }
        };

        // Register self immediately
        knownTabsRef.current.set(TAB_ID, Date.now());

        // Claim leadership candidacy on mount
        const claimMessage: TabMessage = {
            type: 'claim',
            tabId: TAB_ID,
            timestamp: Date.now(),
        };
        channel.postMessage(claimMessage);

        // Start heartbeat
        heartbeatIntervalRef.current = setInterval(sendHeartbeat, HEARTBEAT_INTERVAL);

        // Periodically check for stale leaders
        leaderCheckIntervalRef.current = setInterval(determineLeadership, HEARTBEAT_INTERVAL);

        // Initial leadership determination
        determineLeadership();

        // Cleanup on unmount
        return () => {
            // Notify other tabs this tab is leaving
            if (channelRef.current) {
                const resignMessage: TabMessage = {
                    type: 'resign',
                    tabId: TAB_ID,
                    timestamp: Date.now(),
                };
                channelRef.current.postMessage(resignMessage);
                channelRef.current.close();
            }

            if (heartbeatIntervalRef.current) {
                clearInterval(heartbeatIntervalRef.current);
            }
            if (leaderCheckIntervalRef.current) {
                clearInterval(leaderCheckIntervalRef.current);
            }
        };
    }, [channelName, determineLeadership, sendHeartbeat]);

    return { isLeader, tabId: TAB_ID };
}

import { useCallback, useState, useEffect } from 'react';

/**
 * Hook for View Transitions API
 *
 * Provides smooth, native-like page transition animations.
 * Falls back gracefully on unsupported browsers.
 *
 * @example
 * ```tsx
 * const { startViewTransition, isSupported } = useViewTransition();
 *
 * // Wrap navigation in a transition
 * startViewTransition(() => {
 *   navigate('/new-page');
 * });
 * ```
 */
export function useViewTransition() {
    const [isSupported] = useState(() => 'startViewTransition' in document);
    const [isTransitioning, setIsTransitioning] = useState(false);

    /**
     * Starts a view transition, wrapping the DOM update callback.
     * Falls back to immediate execution on unsupported browsers.
     */
    const startViewTransition = useCallback(async (updateCallback: () => void | Promise<void>) => {
        // Unsupported browsers - execute immediately
        if (!isSupported || !('startViewTransition' in document)) {
            await updateCallback();
            return;
        }

        setIsTransitioning(true);

        try {
            const transition = document.startViewTransition(async () => {
                await updateCallback();
            });

            await transition.finished;
        } catch {
            // Transition failed - DOM update should still have occurred
        } finally {
            setIsTransitioning(false);
        }
    }, [isSupported]);

    return {
        startViewTransition,
        isSupported,
        isTransitioning
    };
}

/**
 * CSS helper to add to your stylesheets for View Transitions.
 *
 * Add these styles to enable smooth page transitions:
 *
 * ```css
 * @view-transition {
 *   navigation: auto;
 * }
 *
 * ::view-transition-old(root) {
 *   animation: 150ms ease-out fade-out;
 * }
 *
 * ::view-transition-new(root) {
 *   animation: 150ms ease-in fade-in;
 * }
 *
 * @keyframes fade-out {
 *   from { opacity: 1; }
 *   to { opacity: 0; }
 * }
 *
 * @keyframes fade-in {
 *   from { opacity: 0; }
 *   to { opacity: 1; }
 * }
 * ```
 */

import { useEffect, useCallback, useRef } from 'react';
import { useTabLeader } from './useTabLeader';

/**
 * Message format for data broadcast between tabs.
 */
interface PollingDataMessage {
    type: 'polling-complete';
    channelName: string;
    timestamp: number;
}

/**
 * Custom hook for visibility-aware polling with optional cross-tab coordination.
 * Pauses polling when the tab is hidden to save resources.
 * 
 * When `channelName` is provided, only the leader tab executes the callback.
 * Other tabs receive a notification when polling completes and can refetch from cache.
 * 
 * @param callback - The function to call on each poll
 * @param intervalMs - Polling interval in milliseconds
 * @param deps - Dependencies array for the callback
 * @param channelName - Optional channel name for cross-tab coordination
 * 
 * @example
 * // Basic usage (no tab coordination)
 * useVisibilityPolling(fetchData, 10000, [accountId]);
 * 
 * // With tab coordination (only leader polls)
 * useVisibilityPolling(fetchStats, 10000, [accountId], 'live-stats');
 */
export function useVisibilityPolling(
    callback: () => void | Promise<void>,
    intervalMs: number,
    deps: React.DependencyList = [],
    channelName?: string
): void {
    const savedCallback = useRef(callback);
    const dataChannelRef = useRef<BroadcastChannel | null>(null);

    // Only use leader election when channelName is provided
    const { isLeader } = useTabLeader(channelName ? `visibility-${channelName}` : 'unused');
    const shouldCoordinate = Boolean(channelName);

    // Update ref when callback changes
    useEffect(() => {
        savedCallback.current = callback;
    }, [callback]);

    // Set up data channel for coordination mode
    useEffect(() => {
        if (!shouldCoordinate || typeof BroadcastChannel === 'undefined') {
            return;
        }

        const channel = new BroadcastChannel(`visibility-data-${channelName}`);
        dataChannelRef.current = channel;

        // When leader completes polling, followers re-execute to get cached data
        channel.onmessage = (event: MessageEvent<PollingDataMessage>) => {
            if (event.data.type === 'polling-complete' && event.data.channelName === channelName) {
                // Only non-leaders should react to this
                if (!isLeader && document.visibilityState === 'visible') {
                    savedCallback.current();
                }
            }
        };

        return () => {
            channel.close();
        };
    }, [channelName, shouldCoordinate, isLeader]);

    useEffect(() => {
        /**
         * Execute callback if visible and (not coordinating OR is leader).
         * Broadcasts completion to other tabs when coordinating.
         */
        const executeIfVisible = async () => {
            if (document.visibilityState !== 'visible') {
                return;
            }

            // In coordination mode, only leader executes
            if (shouldCoordinate && !isLeader) {
                return;
            }

            await savedCallback.current();

            // Notify other tabs that data is fresh (they can refetch from cache)
            if (shouldCoordinate && dataChannelRef.current) {
                const message: PollingDataMessage = {
                    type: 'polling-complete',
                    channelName: channelName!,
                    timestamp: Date.now(),
                };
                dataChannelRef.current.postMessage(message);
            }
        };

        // Delay initial fetch when coordinating so leader election can settle
        let initialTimeout: ReturnType<typeof setTimeout> | null = null;
        if (shouldCoordinate) {
            initialTimeout = setTimeout(executeIfVisible, 500);
        } else {
            executeIfVisible();
        }

        // Set up polling interval
        const interval = setInterval(executeIfVisible, intervalMs);

        // Refetch when tab becomes visible again
        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                // In coordination mode, only leader refetches on visibility change
                if (!shouldCoordinate || isLeader) {
                    savedCallback.current();
                }
            }
        };
        document.addEventListener('visibilitychange', handleVisibilityChange);

        // Cleanup
        return () => {
            clearInterval(interval);
            if (initialTimeout) clearTimeout(initialTimeout);
            document.removeEventListener('visibilitychange', handleVisibilityChange);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [intervalMs, shouldCoordinate, isLeader, channelName, ...deps]);
}

import { useEffect, useRef } from 'react';
import { useSocket } from '../context/SocketContext';

/**
 * Hook for widgets to subscribe to real-time socket events.
 * Automatically handles cleanup on unmount.
 * 
 * @param eventName - The socket event to listen for (e.g., 'order:new')
 * @param onEvent - Callback when event is received
 * @param enabled - Optional flag to disable listening
 */
export function useWidgetSocket<T = any>(
    eventName: string,
    onEvent: (data: T) => void,
    enabled: boolean = true
) {
    const { socket, isConnected } = useSocket();
    const callbackRef = useRef(onEvent);

    // Keep callback reference up to date without re-subscribing
    useEffect(() => {
        callbackRef.current = onEvent;
    }, [onEvent]);

    useEffect(() => {
        if (!socket || !isConnected || !enabled) return;

        const handler = (data: T) => {
            callbackRef.current(data);
        };

        socket.on(eventName, handler);

        return () => {
            socket.off(eventName, handler);
        };
    }, [socket, isConnected, eventName, enabled]);

    return { isConnected };
}

/**
 * Hook for widgets to subscribe to multiple socket events.
 * Uses ref to prevent re-subscription on every render.
 */
export function useWidgetSocketMulti(
    events: Array<{ event: string; handler: (data: any) => void }>,
    enabled: boolean = true
) {
    const { socket, isConnected } = useSocket();
    const eventsRef = useRef(events);

    // Keep events ref up to date without re-subscribing
    useEffect(() => {
        eventsRef.current = events;
    }, [events]);

    useEffect(() => {
        if (!socket || !isConnected || !enabled) return;

        /** Stable wrappers that delegate to the latest handlers via ref */
        const wrappers = eventsRef.current.map(({ event }) => ({
            event,
            fn: (data: any) => {
                const current = eventsRef.current.find(e => e.event === event);
                current?.handler(data);
            }
        }));

        for (const { event, fn } of wrappers) {
            socket.on(event, fn);
        }

        return () => {
            for (const { event, fn } of wrappers) {
                socket.off(event, fn);
            }
        };
    // Only re-subscribe when socket connection state or enabled flag changes
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [socket, isConnected, enabled]);

    return { isConnected };
}

