    'coupon.description': '{{coupon.description}}',
};

/**
 * Get merge tags configuration for Unlayer editor
 * Enables merge tag autocomplete in the editor
 */
export function getWooCommerceMergeTags() {
    return {
        order: {
            name: 'Order',
            mergeTags: {
                number: { name: 'Order Number', value: '{{order.number}}' },
                date: { name: 'Order Date', value: '{{order.date}}' },
                status: { name: 'Order Status', value: '{{order.status}}' },
                paymentMethod: { name: 'Payment Method', value: '{{order.paymentMethod}}' },
                subtotal: { name: 'Subtotal', value: '{{order.subtotal}}' },
                shippingTotal: { name: 'Shipping Total', value: '{{order.shippingTotal}}' },
                discountTotal: { name: 'Discount Total', value: '{{order.discountTotal}}' },
                total: { name: 'Order Total', value: '{{order.total}}' },
                customerNote: { name: 'Customer Note', value: '{{order.customerNote}}' },
            },
        },
        customer: {
            name: 'Customer',
            mergeTags: {
                firstName: { name: 'First Name', value: '{{customer.firstName}}' },
                lastName: { name: 'Last Name', value: '{{customer.lastName}}' },
                email: { name: 'Email', value: '{{customer.email}}' },
                phone: { name: 'Phone', value: '{{customer.phone}}' },
            },
        },
    };
}

/**
 * Register all WooCommerce custom tools with the Unlayer editor
 */
export function registerWooCommerceTools(unlayer: UnlayerEditor) {
    // ============================================
    // 1. PRODUCT BLOCK
    // ============================================
    unlayer.registerTool({
        name: 'woo_product',
        label: 'Product',
        icon: 'fa-cube',
        supportedDisplayModes: ['email'],
        options: {
            productSettings: {
                title: 'Product Settings',
                position: 1,
                options: {
                    showImage: {
                        label: 'Show Image',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                    showPrice: {
                        label: 'Show Price',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                    showDescription: {
                        label: 'Show Description',
                        defaultValue: false,
                        widget: 'toggle',
                    },
                    imageWidth: {
                        label: 'Image Width',
                        defaultValue: '200',
                        widget: 'counter',
                    },
                },
            },
        },
        values: {},
        renderer: {
            Viewer: unlayer.createViewer({
                render(values: any) {
                    const showImage = values.showImage !== false;
                    const showPrice = values.showPrice !== false;
                    const showDescription = values.showDescription === true;
                    const imageWidth = values.imageWidth || '200';

                    return `
            <div style="text-align: center; padding: 20px; font-family: Arial, sans-serif;">
              ${showImage ? `
                <div style="margin-bottom: 15px;">
                  <img src="https://via.placeholder.com/${imageWidth}x${imageWidth}?text=Product+Image" 
                       alt="Product" 
                       style="max-width: ${imageWidth}px; border-radius: 8px;" />
                </div>
              ` : ''}
              <h3 style="margin: 0 0 8px 0; color: #333; font-size: 18px;">{{product.name}}</h3>
              ${showDescription ? `<p style="margin: 0 0 10px 0; color: #666; font-size: 14px;">{{product.description}}</p>` : ''}
              ${showPrice ? `<p style="margin: 0; color: #2563eb; font-weight: bold; font-size: 16px;">{{product.price}}</p>` : ''}
            </div>
          `;
                },
            }),
            exporters: {
                email(values: any) {
                    const showImage = values.showImage !== false;
                    const showPrice = values.showPrice !== false;
                    const showDescription = values.showDescription === true;
                    const imageWidth = values.imageWidth || '200';

                    return `
            <div style="text-align: center; padding: 20px; font-family: Arial, sans-serif;">
              ${showImage ? `
                <div style="margin-bottom: 15px;">
                  <img src="{{product.image}}" 
                       alt="{{product.name}}" 
                       style="max-width: ${imageWidth}px; border-radius: 8px;" />
                </div>
              ` : ''}
              <h3 style="margin: 0 0 8px 0; color: #333; font-size: 18px;">{{product.name}}</h3>
              ${showDescription ? `<p style="margin: 0 0 10px 0; color: #666; font-size: 14px;">{{product.description}}</p>` : ''}
              ${showPrice ? `<p style="margin: 0; color: #2563eb; font-weight: bold; font-size: 16px;">{{product.price}}</p>` : ''}
            </div>
          `;
                },
            },
            head: {
                css() { return ''; },
                js() { return ''; },
            },
        },
    });

    // ============================================
    // 2. COUPON BLOCK
    // ============================================
    unlayer.registerTool({
        name: 'woo_coupon',
        label: 'Coupon',
        icon: 'fa-ticket',
        supportedDisplayModes: ['email'],
        options: {
            couponSettings: {
                title: 'Coupon Settings',
                position: 1,
                options: {
                    backgroundColor: {
                        label: 'Background Color',
                        defaultValue: '#f3f4f6',
                        widget: 'color_picker',
                    },
                    borderStyle: {
                        label: 'Border Style',
                        defaultValue: 'dashed',
                        widget: 'dropdown',
                        data: {
                            options: [
                                { value: 'solid', label: 'Solid' },
                                { value: 'dashed', label: 'Dashed' },
                                { value: 'dotted', label: 'Dotted' },
                                { value: 'none', label: 'None' },
                            ],
                        },
                    },
                    showDiscount: {
                        label: 'Show Discount Amount',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                },
            },
        },
        values: {},
        renderer: {
            Viewer: unlayer.createViewer({
                render(values: any) {
                    const bgColor = values.backgroundColor || '#f3f4f6';
                    const borderStyle = values.borderStyle || 'dashed';
                    const showDiscount = values.showDiscount !== false;

                    return `
            <div style="text-align: center; padding: 24px; font-family: Arial, sans-serif;">
              <div style="display: inline-block; background: ${bgColor}; border: 2px ${borderStyle} #9ca3af; border-radius: 12px; padding: 20px 40px;">
                <p style="margin: 0 0 8px 0; color: #6b7280; font-size: 12px; text-transform: uppercase; letter-spacing: 1px;">Use Code</p>
                <p style="margin: 0; color: #111827; font-size: 24px; font-weight: bold; letter-spacing: 2px;">{{coupon.code}}</p>
                ${showDiscount ? `<p style="margin: 12px 0 0 0; color: #059669; font-size: 14px; font-weight: 600;">Save {{coupon.discount}}</p>` : ''}
              </div>
            </div>
          `;
                },
            }),
            exporters: {
                email(values: any) {
                    const bgColor = values.backgroundColor || '#f3f4f6';
                    const borderStyle = values.borderStyle || 'dashed';
                    const showDiscount = values.showDiscount !== false;

                    return `
            <div style="text-align: center; padding: 24px; font-family: Arial, sans-serif;">
              <div style="display: inline-block; background: ${bgColor}; border: 2px ${borderStyle} #9ca3af; border-radius: 12px; padding: 20px 40px;">
                <p style="margin: 0 0 8px 0; color: #6b7280; font-size: 12px; text-transform: uppercase; letter-spacing: 1px;">Use Code</p>
                <p style="margin: 0; color: #111827; font-size: 24px; font-weight: bold; letter-spacing: 2px;">{{coupon.code}}</p>
                ${showDiscount ? `<p style="margin: 12px 0 0 0; color: #059669; font-size: 14px; font-weight: 600;">Save {{coupon.discount}}</p>` : ''}
              </div>
            </div>
          `;
                },
            },
            head: {
                css() { return ''; },
                js() { return ''; },
            },
        },
    });

    // ============================================
    // 3. CUSTOMER ADDRESS BLOCK
    // ============================================
    unlayer.registerTool({
        name: 'woo_address',
        label: 'Customer Address',
        icon: 'fa-map-marker-alt',
        supportedDisplayModes: ['email'],
        options: {
            addressSettings: {
                title: 'Address Settings',
                position: 1,
                options: {
                    addressType: {
                        label: 'Address Type',
                        defaultValue: 'billing',
                        widget: 'dropdown',
                        data: {
                            options: [
                                { value: 'billing', label: 'Billing Address' },
                                { value: 'shipping', label: 'Shipping Address' },
                                { value: 'both', label: 'Both Addresses' },
                            ],
                        },
                    },
                    showLabel: {
                        label: 'Show Label',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                },
            },
        },
        values: {},
        renderer: {
            Viewer: unlayer.createViewer({
                render(values: any) {
                    const addressType = values.addressType || 'billing';
                    const showLabel = values.showLabel !== false;

                    const renderAddress = (type: string, label: string, placeholder: string) => `
            <div style="flex: 1; min-width: 200px;">
              ${showLabel ? `<p style="margin: 0 0 8px 0; color: #6b7280; font-size: 12px; text-transform: uppercase; font-weight: 600;">${label}</p>` : ''}
              <div style="background: #f9fafb; border-radius: 8px; padding: 16px; border: 1px solid #e5e7eb;">
                <p style="margin: 0; color: #374151; font-size: 14px; line-height: 1.6;">${placeholder}</p>
              </div>
            </div>
          `;

                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              <div style="display: flex; gap: 20px; flex-wrap: wrap;">
                ${addressType === 'billing' || addressType === 'both'
                            ? renderAddress('billing', 'Billing Address', 'John Doe<br>123 Main Street<br>Sydney, NSW 2000<br>Australia')
                            : ''}
                ${addressType === 'shipping' || addressType === 'both'
                            ? renderAddress('shipping', 'Shipping Address', 'John Doe<br>456 Delivery Lane<br>Melbourne, VIC 3000<br>Australia')
                            : ''}
              </div>
            </div>
          `;
                },
            }),
            exporters: {
                email(values: any) {
                    const addressType = values.addressType || 'billing';
                    const showLabel = values.showLabel !== false;

                    const renderAddress = (type: string, label: string, mergeTag: string) => `
            <div style="flex: 1; min-width: 200px;">
              ${showLabel ? `<p style="margin: 0 0 8px 0; color: #6b7280; font-size: 12px; text-transform: uppercase; font-weight: 600;">${label}</p>` : ''}
              <div style="background: #f9fafb; border-radius: 8px; padding: 16px; border: 1px solid #e5e7eb;">
                <p style="margin: 0; color: #374151; font-size: 14px; line-height: 1.6;">${mergeTag}</p>
              </div>
            </div>
          `;

                    // Use table layout for email compatibility
                    return `
            <table width="100%" cellpadding="0" cellspacing="0" style="font-family: Arial, sans-serif;">
              <tr>
                ${addressType === 'billing' || addressType === 'both'
                            ? `<td style="padding: 10px; vertical-align: top;">
                      ${showLabel ? `<p style="margin: 0 0 8px 0; color: #6b7280; font-size: 12px; text-transform: uppercase; font-weight: 600;">Billing Address</p>` : ''}
                      <div style="background: #f9fafb; border-radius: 8px; padding: 16px; border: 1px solid #e5e7eb;">
                        {{order.billingAddress}}
                      </div>
                    </td>`
                            : ''}
                ${addressType === 'shipping' || addressType === 'both'
                            ? `<td style="padding: 10px; vertical-align: top;">
                      ${showLabel ? `<p style="margin: 0 0 8px 0; color: #6b7280; font-size: 12px; text-transform: uppercase; font-weight: 600;">Shipping Address</p>` : ''}
                      <div style="background: #f9fafb; border-radius: 8px; padding: 16px; border: 1px solid #e5e7eb;">
                        {{order.shippingAddress}}
                      </div>
                    </td>`
                            : ''}
              </tr>
            </table>
          `;
                },
            },
            head: {
                css() { return ''; },
                js() { return ''; },
            },
        },
    });

    // ============================================
    // 4. ORDER SUMMARY BLOCK
    // ============================================
    unlayer.registerTool({
        name: 'woo_order_summary',
        label: 'Order Summary',
        icon: 'fa-file-invoice',
        supportedDisplayModes: ['email'],
        options: {
            summarySettings: {
                title: 'Summary Settings',
                position: 1,
                options: {
                    showImages: {
                        label: 'Show Product Images',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                    showShipping: {
                        label: 'Show Shipping',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                    showDiscount: {
                        label: 'Show Discount',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                    headerColor: {
                        label: 'Header Color',
                        defaultValue: '#f3f4f6',
                        widget: 'color_picker',
                    },
                },
            },
        },
        values: {},
        renderer: {
            Viewer: unlayer.createViewer({
                render(values: any) {
                    const showImages = values.showImages !== false;
                    const showShipping = values.showShipping !== false;
                    const showDiscount = values.showDiscount !== false;
                    const headerColor = values.headerColor || '#f3f4f6';

                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse: collapse;">
                <thead>
                  <tr style="background: ${headerColor};">
                    ${showImages ? '<th style="padding: 12px; text-align: left; font-size: 12px; color: #6b7280; text-transform: uppercase;"></th>' : ''}
                    <th style="padding: 12px; text-align: left; font-size: 12px; color: #6b7280; text-transform: uppercase;">Product</th>
                    <th style="padding: 12px; text-align: center; font-size: 12px; color: #6b7280; text-transform: uppercase;">Qty</th>
                    <th style="padding: 12px; text-align: right; font-size: 12px; color: #6b7280; text-transform: uppercase;">Price</th>
                  </tr>
                </thead>
                <tbody>
                  <tr style="border-bottom: 1px solid #e5e7eb;">
                    ${showImages ? '<td style="padding: 12px;"><div style="width: 50px; height: 50px; background: #e5e7eb; border-radius: 4px;"></div></td>' : ''}
                    <td style="padding: 12px; color: #374151;">Sample Product Name</td>
                    <td style="padding: 12px; text-align: center; color: #374151;">1</td>
                    <td style="padding: 12px; text-align: right; color: #374151;">$99.00</td>
                  </tr>
                  <tr style="border-bottom: 1px solid #e5e7eb;">
                    ${showImages ? '<td style="padding: 12px;"><div style="width: 50px; height: 50px; background: #e5e7eb; border-radius: 4px;"></div></td>' : ''}
                    <td style="padding: 12px; color: #374151;">Another Product</td>
                    <td style="padding: 12px; text-align: center; color: #374151;">2</td>
                    <td style="padding: 12px; text-align: right; color: #374151;">$49.00</td>
                  </tr>
                </tbody>
                <tfoot>
                  <tr>
                    <td colspan="${showImages ? 3 : 2}" style="padding: 12px; text-align: right; color: #6b7280;">Subtotal</td>
                    <td style="padding: 12px; text-align: right; color: #374151; font-weight: 500;">$197.00</td>
                  </tr>
                  ${showShipping ? `
                    <tr>
                      <td colspan="${showImages ? 3 : 2}" style="padding: 12px; text-align: right; color: #6b7280;">Shipping</td>
                      <td style="padding: 12px; text-align: right; color: #374151;">$10.00</td>
                    </tr>
                  ` : ''}
                  ${showDiscount ? `
                    <tr>
                      <td colspan="${showImages ? 3 : 2}" style="padding: 12px; text-align: right; color: #059669;">Discount</td>
                      <td style="padding: 12px; text-align: right; color: #059669;">-$20.00</td>
                    </tr>
                  ` : ''}
                  <tr style="border-top: 2px solid #111827;">
                    <td colspan="${showImages ? 3 : 2}" style="padding: 12px; text-align: right; color: #111827; font-weight: 700; font-size: 16px;">Total</td>
                    <td style="padding: 12px; text-align: right; color: #111827; font-weight: 700; font-size: 16px;">$187.00</td>
                  </tr>
                </tfoot>
              </table>
            </div>
          `;
                },
            }),
            exporters: {
                email(values: any) {
                    const showShipping = values.showShipping !== false;
                    const showDiscount = values.showDiscount !== false;
                    const headerColor = values.headerColor || '#f3f4f6';

                    // The items table merge tag renders the full table with items
                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              {{order.itemsTable}}
              <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse: collapse; margin-top: 10px;">
                <tr>
                  <td style="padding: 12px; text-align: right; color: #6b7280;">Subtotal</td>
                  <td style="padding: 12px; text-align: right; color: #374151; font-weight: 500; width: 100px;">{{order.subtotal}}</td>
                </tr>
                ${showShipping ? `
                  <tr>
                    <td style="padding: 12px; text-align: right; color: #6b7280;">Shipping</td>
                    <td style="padding: 12px; text-align: right; color: #374151; width: 100px;">{{order.shippingTotal}}</td>
                  </tr>
                ` : ''}
                ${showDiscount ? `
                  <tr>
                    <td style="padding: 12px; text-align: right; color: #059669;">Discount</td>
                    <td style="padding: 12px; text-align: right; color: #059669; width: 100px;">-{{order.discountTotal}}</td>
                  </tr>
                ` : ''}
                <tr style="border-top: 2px solid #111827;">
                  <td style="padding: 12px; text-align: right; color: #111827; font-weight: 700; font-size: 16px;">Total</td>
                  <td style="padding: 12px; text-align: right; color: #111827; font-weight: 700; font-size: 16px; width: 100px;">{{order.total}}</td>
                </tr>
              </table>
            </div>
          `;
                },
            },
            head: {
                css() { return ''; },
                js() { return ''; },
            },
        },
    });

    // ============================================
    // 5. CUSTOMER NOTES BLOCK
    // ============================================
    unlayer.registerTool({
        name: 'woo_customer_notes',
        label: 'Customer Notes',
        icon: 'fa-sticky-note',
        supportedDisplayModes: ['email'],
        options: {
            notesSettings: {
                title: 'Notes Settings',
                position: 1,
                options: {
                    showIcon: {
                        label: 'Show Icon',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                    backgroundColor: {
                        label: 'Background Color',
                        defaultValue: '#fef3c7',
                        widget: 'color_picker',
                    },
                    borderColor: {
                        label: 'Border Color',
                        defaultValue: '#f59e0b',
                        widget: 'color_picker',
                    },
                },
            },
        },
        values: {},
        renderer: {
            Viewer: unlayer.createViewer({
                render(values: any) {
                    const showIcon = values.showIcon !== false;
                    const bgColor = values.backgroundColor || '#fef3c7';
                    const borderColor = values.borderColor || '#f59e0b';

                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              <div style="background: ${bgColor}; border-left: 4px solid ${borderColor}; border-radius: 0 8px 8px 0; padding: 16px;">
                <div style="display: flex; align-items: flex-start; gap: 12px;">
                  ${showIcon ? `<span style="font-size: 20px;">📝</span>` : ''}
                  <div>
                    <p style="margin: 0 0 4px 0; color: #92400e; font-size: 12px; font-weight: 600; text-transform: uppercase;">Customer Note</p>
                    <p style="margin: 0; color: #78350f; font-size: 14px; line-height: 1.5;">Please leave the package at the front door. Thank you!</p>
                  </div>
                </div>
              </div>
            </div>
          `;
                },
            }),
            exporters: {
                email(values: any) {
                    const showIcon = values.showIcon !== false;
                    const bgColor = values.backgroundColor || '#fef3c7';
                    const borderColor = values.borderColor || '#f59e0b';

                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              <div style="background: ${bgColor}; border-left: 4px solid ${borderColor}; border-radius: 0 8px 8px 0; padding: 16px;">
                <table cellpadding="0" cellspacing="0" border="0">
                  <tr>
                    ${showIcon ? `<td style="vertical-align: top; padding-right: 12px; font-size: 20px;">📝</td>` : ''}
                    <td style="vertical-align: top;">
                      <p style="margin: 0 0 4px 0; color: #92400e; font-size: 12px; font-weight: 600; text-transform: uppercase;">Customer Note</p>
                      <p style="margin: 0; color: #78350f; font-size: 14px; line-height: 1.5;">{{order.customerNote}}</p>
                    </td>
                  </tr>
                </table>
              </div>
            </div>
          `;
                },
            },
            head: {
                css() { return ''; },
                js() { return ''; },
            },
        },
    });

    // ============================================
    // 6. ORDER DOWNLOADS BLOCK
    // ============================================
    unlayer.registerTool({
        name: 'woo_order_downloads',
        label: 'Order Downloads',
        icon: 'fa-download',
        supportedDisplayModes: ['email'],
        options: {
            downloadSettings: {
                title: 'Download Settings',
                position: 1,
                options: {
                    buttonStyle: {
                        label: 'Button Style',
                        defaultValue: 'primary',
                        widget: 'dropdown',
                        data: {
                            options: [
                                { value: 'primary', label: 'Primary (Blue)' },
                                { value: 'secondary', label: 'Secondary (Gray)' },
                                { value: 'success', label: 'Success (Green)' },
                            ],
                        },
                    },
                    showExpiry: {
                        label: 'Show Expiry Date',
                        defaultValue: true,
                        widget: 'toggle',
                    },
                },
            },
        },
        values: {},
        renderer: {
            Viewer: unlayer.createViewer({
                render(values: any) {
                    const buttonStyle = values.buttonStyle || 'primary';
                    const showExpiry = values.showExpiry !== false;

                    const buttonColors: Record<string, { bg: string; text: string }> = {
                        primary: { bg: '#2563eb', text: '#ffffff' },
                        secondary: { bg: '#6b7280', text: '#ffffff' },
                        success: { bg: '#059669', text: '#ffffff' },
                    };

                    const colors = buttonColors[buttonStyle] || buttonColors.primary;

                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              <p style="margin: 0 0 16px 0; color: #374151; font-size: 14px; font-weight: 600;">Your Downloads</p>
              <div style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">
                <div style="padding: 16px; border-bottom: 1px solid #e5e7eb; display: flex; justify-content: space-between; align-items: center;">
                  <div>
                    <p style="margin: 0 0 4px 0; color: #111827; font-size: 14px; font-weight: 500;">Digital Product Guide.pdf</p>
                    ${showExpiry ? `<p style="margin: 0; color: #6b7280; font-size: 12px;">Expires: Jan 31, 2026</p>` : ''}
                  </div>
                  <a href="#" style="display: inline-block; background: ${colors.bg}; color: ${colors.text}; padding: 8px 16px; border-radius: 6px; text-decoration: none; font-size: 13px; font-weight: 500;">Download</a>
                </div>
                <div style="padding: 16px; display: flex; justify-content: space-between; align-items: center;">
                  <div>
                    <p style="margin: 0 0 4px 0; color: #111827; font-size: 14px; font-weight: 500;">Bonus Content.zip</p>
                    ${showExpiry ? `<p style="margin: 0; color: #6b7280; font-size: 12px;">Expires: Feb 15, 2026</p>` : ''}
                  </div>
                  <a href="#" style="display: inline-block; background: ${colors.bg}; color: ${colors.text}; padding: 8px 16px; border-radius: 6px; text-decoration: none; font-size: 13px; font-weight: 500;">Download</a>
                </div>
              </div>
            </div>
          `;
                },
            }),
            exporters: {
                email(values: any) {
                    // The downloads merge tag renders the full download list
                    return `
            <div style="padding: 20px; font-family: Arial, sans-serif;">
              <p style="margin: 0 0 16px 0; color: #374151; font-size: 14px; font-weight: 600;">Your Downloads</p>
              {{order.downloads}}
            </div>
          `;
                },
            },
            head: {
                css() { return ''; },
                js() { return ''; },
            },
        },
    });

    console.log('[Unlayer] WooCommerce custom tools registered successfully');
}

import { useEffect, useState } from 'react';
import { Logger } from '../utils/logger';
import { formatCurrency } from '../utils/format';
import { Mail, ShoppingBag, Calendar, Activity, Zap, Users } from 'lucide-react';
import { Link, useParams } from 'react-router-dom';
import { Breadcrumbs } from '../components/ui/Breadcrumbs';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { MergeCustomerModal } from '../components/customers/MergeCustomerModal';

interface CustomerDetails {
    customer: {
        id: string;
        firstName: string;
        lastName: string;
        email: string;
        totalSpent: number;
        ordersCount: number;
        dateCreated: string;
        rawData: any;
    };
    orders: any[];
    automations: any[];
    activity: any[];
}

export function CustomerDetailsPage() {
    const { id } = useParams();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [data, setData] = useState<CustomerDetails | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'overview' | 'orders' | 'automations' | 'activity'>('overview');
    const [showMergeModal, setShowMergeModal] = useState(false);

    useEffect(() => {
        if (id && currentAccount && token) {
            fetchCustomerDetails();
        }
    }, [id, currentAccount, token]);

    async function fetchCustomerDetails() {
        if (!id) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/customers/${id}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const json = await res.json();
                setData(json);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    if (isLoading) return <div className="p-8 text-center text-gray-500">Loading customer profile...</div>;
    if (!data) return <div className="p-8 text-center text-red-500">Customer not found</div>;

    const { customer, orders, automations, activity } = data;
    const currency = currentAccount?.currency || 'USD';
    const fmt = (amount: number) => formatCurrency(amount, currency);

    // Helper to get initials
    const initials = (customer.firstName?.[0] || '') + (customer.lastName?.[0] || '');

    return (
        <div className="space-y-6 max-w-7xl mx-auto pb-10">
            {/* Header */}
            <div>
                <Breadcrumbs items={[
                    { label: 'Customers', href: '/customers' },
                    { label: `${customer.firstName} ${customer.lastName}` }
                ]} />
                <div className="flex justify-between items-start">
                    <div className="flex items-center gap-4">
                        <div className="w-16 h-16 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-2xl">
                            {initials}
                        </div>
                        <div>
                            <h1 className="text-3xl font-bold text-gray-900">{customer.firstName} {customer.lastName}</h1>
                            <div className="flex items-center gap-4 text-sm text-gray-500 mt-1">
                                <span className="flex items-center gap-1"><Mail size={14} /> {customer.email}</span>
                                <span className="flex items-center gap-1"><Calendar size={14} /> Joined {new Date(customer.dateCreated).toLocaleDateString()}</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <button
                            onClick={() => setShowMergeModal(true)}
                            className="px-4 py-2 border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 flex items-center gap-2"
                        >
                            <Users size={16} />
                            Merge Duplicates
                        </button>
                        <button className="px-4 py-2 border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50">Edit Profile</button>
                    </div>
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                    <p className="text-sm font-medium text-gray-500">Total Spent</p>
                    <p className="text-2xl font-bold text-gray-900 mt-1">{fmt(Number(customer.totalSpent))}</p>
                </div>
                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                    <p className="text-sm font-medium text-gray-500">Orders</p>
                    <p className="text-2xl font-bold text-gray-900 mt-1">{customer.ordersCount}</p>
                </div>
                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                    <p className="text-sm font-medium text-gray-500">Average Order</p>
                    <p className="text-2xl font-bold text-gray-900 mt-1">{fmt(customer.ordersCount > 0 ? Number(customer.totalSpent) / customer.ordersCount : 0)}</p>
                </div>
                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                    <p className="text-sm font-medium text-gray-500">Last Active</p>
                    <p className="text-2xl font-bold text-gray-900 mt-1">{activity[0] ? new Date(activity[0].lastActiveAt).toLocaleDateString() : 'N/A'}</p>
                </div>
            </div>

            {/* Content Tabs */}
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 min-h-[500px]">
                <div className="border-b border-gray-200 px-6 flex gap-6">
                    {(['overview', 'orders', 'automations', 'activity'] as const).map(tab => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`py-4 text-sm font-medium border-b-2 transition-colors capitalize ${activeTab === tab ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'
                                }`}
                        >
                            {tab}
                        </button>
                    ))}
                </div>

                <div className="p-6">
                    {activeTab === 'overview' && (
                        <div className="grid grid-cols-2 gap-8">
                            <div>
                                <h3 className="text-lg font-semibold mb-4 text-gray-900">Contact Information</h3>
                                <dl className="space-y-4">
                                    <div>
                                        <dt className="text-sm text-gray-500 mb-1">Email</dt>
                                        <dd className="font-medium">{customer.email}</dd>
                                    </div>
                                    <div>
                                        <dt className="text-sm text-gray-500 mb-1">Phone</dt>
                                        <dd className="font-medium">{customer.rawData?.billing?.phone || 'N/A'}</dd>
                                    </div>
                                </dl>
                            </div>
                            <div>
                                <h3 className="text-lg font-semibold mb-4 text-gray-900">Billing Address</h3>
                                <div className="text-gray-700 bg-gray-50 p-4 rounded-lg">
                                    {customer.rawData?.billing ? (
                                        <>
                                            <p>{customer.rawData.billing.address_1}</p>
                                            <p>{customer.rawData.billing.address_2}</p>
                                            <p>{customer.rawData.billing.city}, {customer.rawData.billing.state} {customer.rawData.billing.postcode}</p>
                                            <p>{customer.rawData.billing.country}</p>
                                        </>
                                    ) : (
                                        <p className="text-gray-400 italic">No address on file</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    )}

                    {activeTab === 'orders' && (
                        <table className="w-full text-left">
                            <thead>
                                <tr className="text-xs uppercase text-gray-500 border-b border-gray-100">
                                    <th className="pb-3">Order #</th>
                                    <th className="pb-3">Date</th>
                                    <th className="pb-3">Status</th>
                                    <th className="pb-3 text-right">Total</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {orders.map(order => (
                                    <tr key={order.id} className="hover:bg-gray-50">
                                        <td className="py-4 font-medium text-blue-600">#{order.number}</td>
                                        <td className="py-4 text-gray-600">{new Date(order.dateCreated).toLocaleDateString()}</td>
                                        <td className="py-4">
                                            <span className={`px-2 py-1 rounded text-xs font-semibold uppercase ${order.status === 'completed' ? 'bg-green-100 text-green-700' :
                                                order.status === 'processing' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-700'
                                                }`}>
                                                {order.status}
                                            </span>
                                        </td>
                                        <td className="py-4 text-right font-medium">{formatCurrency(Number(order.total), order.currency || currency)}</td>
                                    </tr>
                                ))}
                                {orders.length === 0 && (
                                    <tr><td colSpan={4} className="py-8 text-center text-gray-400">No recent orders found</td></tr>
                                )}
                            </tbody>
                        </table>
                    )}

                    {activeTab === 'automations' && (
                        <div>
                            <div className="bg-blue-50 text-blue-700 p-4 rounded-lg mb-6 text-sm flex gap-2">
                                <Activity size={18} />
                                <span>Showing <strong>Marketing Automation</strong> history. Broadcast history is not currently linked to individual profiles.</span>
                            </div>
                            <table className="w-full text-left">
                                <thead>
                                    <tr className="text-xs uppercase text-gray-500 border-b border-gray-100">
                                        <th className="pb-3">Automation</th>
                                        <th className="pb-3">Status</th>
                                        <th className="pb-3">Enrolled At</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-50">
                                    {automations.map(auto => (
                                        <tr key={auto.id} className="hover:bg-gray-50">
                                            <td className="py-4 font-medium flex items-center gap-2">
                                                <Zap size={16} className="text-amber-500" />
                                                {auto.automation?.name || 'Unknown Automation'}
                                            </td>
                                            <td className="py-4">
                                                <span className={`px-2 py-1 rounded text-xs font-semibold uppercase ${auto.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'
                                                    }`}>
                                                    {auto.status}
                                                </span>
                                            </td>
                                            <td className="py-4 text-gray-600">{new Date(auto.createdAt).toLocaleString()}</td>
                                        </tr>
                                    ))}
                                    {automations.length === 0 && (
                                        <tr><td colSpan={3} className="py-8 text-center text-gray-400">No automation history</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}

                    {activeTab === 'activity' && (
                        <div>
                            <div className="space-y-6">
                                {activity.map(session => (
                                    <div key={session.id} className="flex gap-4">
                                        <div className="flex flex-col items-center">
                                            <div className="w-2 h-2 rounded-full bg-blue-400 mt-2"></div>
                                            <div className="w-0.5 h-full bg-gray-100 my-1"></div>
                                        </div>
                                        <div className="flex-1 pb-4">
                                            <div className="flex justify-between">
                                                <h4 className="font-semibold text-gray-900">Session on {new Date(session.lastActiveAt).toLocaleDateString()}</h4>
                                                <span className="text-xs text-gray-400">{new Date(session.lastActiveAt).toLocaleTimeString()}</span>
                                            </div>
                                            <p className="text-sm text-gray-500 mb-2">
                                                Referrer: {session.referrer || 'Direct'} • Device: {session.deviceType || 'Unknown'}
                                            </p>
                                            <div className="bg-gray-50 rounded-lg p-3 space-y-2">
                                                {session.events.map((event: any, idx: number) => (
                                                    <div key={idx} className="text-sm flex gap-2 items-start">
                                                        <span className="text-gray-400 min-w-[60px]">{new Date(event.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                                        <span className={
                                                            event.type === 'purchase' ? 'text-green-600 font-medium' :
                                                                event.type === 'add_to_cart' ? 'text-blue-600 font-medium' :
                                                                    'text-gray-700'
                                                        }>
                                                            {event.type.replace(/_/g, ' ')}: {event.url}
                                                        </span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                                {activity.length === 0 && (
                                    <div className="text-center text-gray-400 py-8">No live activity recorded</div>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Merge Modal */}
            <MergeCustomerModal
                isOpen={showMergeModal}
                onClose={() => setShowMergeModal(false)}
                customerId={id || ''}
                onMergeComplete={fetchCustomerDetails}
            />
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../utils/logger';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Search, Users, Loader2, Mail, ShoppingBag, Calendar, RefreshCw } from 'lucide-react';
import { Pagination } from '../components/ui/Pagination';
import { TableSkeleton } from '../components/ui/Skeleton';
import { EmptyState } from '../components/ui/EmptyState';
import { RelativeTime } from '../components/ui/RelativeTime';
import { formatDate, formatCurrency } from '../utils/format';

interface Customer {
    id: string;
    firstName: string;
    lastName: string;
    email: string;
    totalSpent: number;
    ordersCount: number;
    dateCreated: string;
}

export function CustomersPage() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const [debouncedQuery, setDebouncedQuery] = useState('');
    const currency = currentAccount?.currency || 'USD';

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedQuery(searchQuery);
            setPage(1);
        }, 500);
        return () => clearTimeout(timer);
    }, [searchQuery]);

    useEffect(() => {
        fetchCustomers();
    }, [currentAccount, token, debouncedQuery, page, limit]);

    async function fetchCustomers() {
        if (!currentAccount || !token) return;

        setIsLoading(true);
        try {
            const params = new URLSearchParams({
                page: page.toString(),
                limit: limit.toString(),
                q: debouncedQuery
            });

            const res = await fetch(`/api/customers?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setCustomers(data.customers);
                setTotalPages(data.totalPages);
                setTotalItems(data.total);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-xl md:text-2xl font-bold text-gray-900">Customers</h1>
                    <p className="text-sm text-gray-500">View and manage your customer base</p>
                </div>
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 w-full sm:w-auto">
                    <button
                        onClick={() => navigate('/customers/segments')}
                        className="flex items-center justify-center gap-2 px-4 py-2 bg-white text-gray-700 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors font-medium text-sm"
                    >
                        <Users size={16} />
                        Segments
                    </button>
                    <div className="relative flex-1 sm:flex-none">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search customers..."
                            className="w-full sm:w-64 pl-10 pr-4 py-2 border border-gray-300 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse min-w-[600px]">
                        <thead>
                            <tr className="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold">
                                <th className="px-3 md:px-6 py-3 md:py-4">Customer</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Contact</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Orders</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Total Spent</th>
                                <th className="px-3 md:px-6 py-3 md:py-4">Joined</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {isLoading ? (
                                <TableSkeleton rows={8} columns={5} showAvatar />
                            ) : customers.length === 0 ? (
                                <tr><td colSpan={5}>
                                    <EmptyState
                                        icon={<Users size={48} />}
                                        title="No customers found"
                                        description="Customers will appear here once they place orders. Try syncing your store data."
                                    />
                                </td></tr>
                            ) : (
                                customers.map((customer) => (
                                    <tr key={customer.id} className="hover:bg-gray-50 transition-colors cursor-pointer" onClick={() => {
                                        navigate(`/customers/${encodeURIComponent(customer.id)}`)
                                    }}>

                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3" title={customer.email}>
                                                <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center font-bold text-sm">
                                                    {customer.firstName?.[0]}{customer.lastName?.[0]}
                                                </div>
                                                <div>
                                                    <div className="font-medium text-gray-900">{customer.firstName} {customer.lastName}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-gray-500">
                                            <div className="flex items-center gap-2">
                                                <Mail size={14} />
                                                {customer.email}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-gray-500">
                                            <div
                                                className="flex items-center gap-2 cursor-default"
                                                title={`Total spent: ${formatCurrency(customer.totalSpent, currency)} across ${customer.ordersCount} order${customer.ordersCount !== 1 ? 's' : ''}`}
                                            >
                                                <ShoppingBag size={14} />
                                                {customer.ordersCount} order{customer.ordersCount !== 1 ? 's' : ''}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 font-medium text-gray-900">
                                            <span
                                                title={`${customer.ordersCount} order${customer.ordersCount !== 1 ? 's' : ''} · Avg ${formatCurrency(customer.ordersCount > 0 ? customer.totalSpent / customer.ordersCount : 0, currency)}`}
                                                className="cursor-default border-b border-dotted border-gray-300"
                                            >
                                                {formatCurrency(customer.totalSpent, currency)}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-sm text-gray-500">
                                            <div className="flex items-center gap-2">
                                                <Calendar size={14} />
                                                <div>
                                                    <div>{formatDate(customer.dateCreated)}</div>
                                                    <RelativeTime date={customer.dateCreated} />
                                                </div>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
                {!isLoading && customers.length > 0 && (
                    <Pagination
                        currentPage={page}
                        totalPages={totalPages}
                        onPageChange={setPage}
                        itemsPerPage={limit}
                        onItemsPerPageChange={(newLimit) => {
                            setLimit(newLimit);
                            setPage(1);
                        }}
                        allowItemsPerPage={true}
                    />
                )}
            </div>
        </div >
    );
}

