import { Responsive, WidthProvider } from 'react-grid-layout/legacy';
import 'react-grid-layout/css/styles.css';
import 'react-resizable/css/styles.css';
import { GripVertical, Image as ImageIcon, Type, Table, DollarSign, User, LayoutTemplate, Heading, FileText, Rows, Plus } from 'lucide-react';

const ResponsiveGridLayout = WidthProvider(Responsive);

interface InvoiceItemStyle {
    fontSize?: string;
    fontWeight?: string;
    fontStyle?: string;
    textAlign?: 'left' | 'center' | 'right';
    autoFit?: boolean;
}

interface InvoiceItem {
    id: string;
    type: 'header' | 'text' | 'image' | 'order_details' | 'customer_details' | 'order_table' | 'totals' | 'footer' | 'row';
    content?: string;
    logo?: string;
    businessDetails?: string;
    style?: InvoiceItemStyle;
    children?: string[];  // IDs of nested items for 'row' type
}

// Note: layout uses any[] due to react-grid-layout/legacy type export incompatibilities
interface DesignerCanvasProps {
    layout: any[];
    items: InvoiceItem[];
    selectedId: string | null;
    onLayoutChange: (layout: any) => void;
    onSelect: (id: string | null) => void;
    onDropItem?: (type: string, targetRowId?: string) => void;
}

/**
 * DesignerCanvas - Visual drag-and-drop canvas for invoice layout.
 * Renders a paper-like preview with resizable grid items.
 */
export function DesignerCanvas({ layout, items, selectedId, onLayoutChange, onSelect, onDropItem }: DesignerCanvasProps) {

    // Handle drop on the canvas area
    const handleCanvasDrop = (e: React.DragEvent) => {
        e.preventDefault();
        const type = e.dataTransfer.getData('text/plain');
        if (type && onDropItem) {
            onDropItem(type);
        }
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'copy';
    };

    const renderItemContent = (itemConfig: InvoiceItem) => {
        if (!itemConfig) return <div className="p-3 text-red-500 text-sm">Error: Item config missing</div>;

        switch (itemConfig.type) {
            case 'header':
                return (
                    <div className="p-4 h-full bg-linear-to-br from-slate-50 to-gray-50 flex flex-col rounded-lg border border-dashed border-slate-300">
                        <div className="flex items-center gap-2 text-slate-600 mb-3">
                            <Heading size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Header Block</span>
                        </div>
                        <div className="flex-1 flex gap-4">
                            {/* Logo Section */}
                            <div className="w-1/3 flex items-center justify-center bg-white rounded-lg border border-dashed border-slate-200 overflow-hidden">
                                {itemConfig.logo ? (
                                    <img src={itemConfig.logo} alt="Logo" className="w-full h-full object-contain" />
                                ) : (
                                    <div className="text-center p-2">
                                        <ImageIcon size={24} className="mx-auto text-slate-300 mb-1" />
                                        <span className="text-[10px] text-slate-400">Logo</span>
                                    </div>
                                )}
                            </div>
                            {/* Business Details Section */}
                            <div className="flex-1 flex flex-col justify-center text-sm text-slate-600 leading-relaxed">
                                {itemConfig.businessDetails ? (
                                    <div className="whitespace-pre-wrap">{itemConfig.businessDetails}</div>
                                ) : (
                                    <div className="space-y-1">
                                        <div className="h-3 w-32 bg-slate-200/50 rounded-sm"></div>
                                        <div className="h-2.5 w-40 bg-slate-200/50 rounded-sm"></div>
                                        <div className="h-2.5 w-28 bg-slate-200/50 rounded-sm"></div>
                                        <div className="h-2.5 w-36 bg-slate-200/50 rounded-sm"></div>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                );
            case 'text':
                const style = itemConfig.style || {};
                const isAutoFit = style.autoFit !== false; // Default to true for auto-fit
                return (
                    <div className="p-4 h-full overflow-hidden flex flex-col">
                        <div className="flex items-start gap-2 text-slate-500 mb-2 shrink-0">
                            <Type size={14} className="shrink-0 mt-0.5" />
                            <span className="text-xs font-medium uppercase tracking-wider">Text Block</span>
                        </div>
                        <div
                            className={`flex-1 whitespace-pre-wrap leading-relaxed ${isAutoFit
                                ? 'overflow-hidden text-ellipsis break-words'
                                : 'overflow-auto'
                                }`}
                            style={{
                                fontSize: isAutoFit
                                    ? `clamp(10px, 2.5cqw, ${style.fontSize || '14px'})`
                                    : (style.fontSize || '14px'),
                                fontWeight: style.fontWeight || 'normal',
                                fontStyle: style.fontStyle || 'normal',
                                textAlign: style.textAlign || 'left',
                                color: '#334155',
                                containerType: isAutoFit ? 'inline-size' : undefined,
                                wordBreak: isAutoFit ? 'break-word' : undefined,
                            }}
                        >
                            {itemConfig.content || 'Click to edit text...'}
                        </div>
                    </div>
                );
            case 'image':
                return (
                    <div className="w-full h-full flex items-center justify-center overflow-hidden bg-linear-to-br from-slate-50 to-slate-100 rounded-lg relative">
                        {itemConfig.content ? (
                            <img
                                src={itemConfig.content}
                                alt="Invoice"
                                className="w-full h-full object-contain"
                                onError={(e) => {
                                    // Fallback if image fails to load
                                    (e.target as HTMLImageElement).style.display = 'none';
                                    (e.target as HTMLImageElement).parentElement?.classList.add('image-error');
                                }}
                            />
                        ) : (
                            <div className="text-slate-400 flex flex-col items-center gap-2">
                                <div className="w-12 h-12 rounded-xl bg-purple-100 flex items-center justify-center">
                                    <ImageIcon size={24} className="text-purple-500" />
                                </div>
                                <span className="text-xs font-medium">Add Image</span>
                            </div>
                        )}
                        {/* Error state overlay */}
                        <div className="hidden image-error:flex absolute inset-0 flex-col items-center justify-center text-red-400 bg-red-50">
                            <ImageIcon size={24} className="mb-2 opacity-50" />
                            <span className="text-xs font-medium">Failed to load image</span>
                        </div>
                    </div>
                );
            case 'order_details':
                return (
                    <div className="p-4 h-full bg-linear-to-br from-sky-50 to-cyan-50 flex flex-col rounded-lg border border-dashed border-sky-300">
                        <div className="flex items-center gap-2 text-sky-600 mb-3">
                            <FileText size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Order Details</span>
                        </div>
                        <div className="space-y-2">
                            <div className="flex gap-4 text-xs">
                                <span className="text-sky-500 w-28">Order Number:</span>
                                <span className="h-3 w-16 bg-sky-200/50 rounded-sm"></span>
                            </div>
                            <div className="flex gap-4 text-xs">
                                <span className="text-sky-500 w-28">Order Date:</span>
                                <span className="h-3 w-20 bg-sky-200/50 rounded-sm"></span>
                            </div>
                            <div className="flex gap-4 text-xs">
                                <span className="text-sky-500 w-28">Payment Method:</span>
                                <span className="h-3 w-16 bg-sky-200/50 rounded-sm"></span>
                            </div>
                            <div className="flex gap-4 text-xs">
                                <span className="text-sky-500 w-28">Shipping Method:</span>
                                <span className="h-3 w-20 bg-sky-200/50 rounded-sm"></span>
                            </div>
                        </div>
                    </div>
                );
            case 'customer_details':
                return (
                    <div className="p-4 h-full bg-linear-to-br from-indigo-50 to-blue-50 flex flex-col rounded-lg border border-dashed border-indigo-300">
                        <div className="flex items-center gap-2 text-indigo-600 mb-3">
                            <User size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Customer Details</span>
                        </div>
                        <div className="space-y-2">
                            <div className="h-4 w-32 bg-indigo-200/50 rounded-sm"></div>
                            <div className="h-3 w-48 bg-indigo-200/50 rounded-sm"></div>
                            <div className="h-3 w-40 bg-indigo-200/50 rounded-sm"></div>
                            <div className="h-3 w-24 bg-indigo-200/50 rounded-sm"></div>
                        </div>
                    </div>
                );
            case 'order_table':
                return (
                    <div className="p-4 h-full bg-linear-to-br from-emerald-50 to-teal-50 flex flex-col rounded-lg border border-dashed border-emerald-300">
                        <div className="flex items-center gap-2 text-emerald-600 mb-3">
                            <Table size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Order Items Table</span>
                        </div>
                        <div className="flex-1 flex flex-col justify-center">
                            <div className="space-y-2">
                                <div className="flex gap-4 text-xs text-emerald-600 font-medium pb-2 border-b border-emerald-200">
                                    <span className="flex-1">Product</span>
                                    <span className="w-12 text-center">Qty</span>
                                    <span className="w-16 text-right">Price</span>
                                </div>
                                <div className="flex gap-4 text-xs text-emerald-500">
                                    <span className="flex-1 bg-emerald-100 rounded-sm h-3"></span>
                                    <span className="w-12 bg-emerald-100 rounded-sm h-3"></span>
                                    <span className="w-16 bg-emerald-100 rounded-sm h-3"></span>
                                </div>
                                <div className="flex gap-4 text-xs text-emerald-500">
                                    <span className="flex-1 bg-emerald-100 rounded-sm h-3"></span>
                                    <span className="w-12 bg-emerald-100 rounded-sm h-3"></span>
                                    <span className="w-16 bg-emerald-100 rounded-sm h-3"></span>
                                </div>
                            </div>
                        </div>
                    </div>
                );
            case 'totals':
                return (
                    <div className="p-4 h-full bg-linear-to-br from-amber-50 to-orange-50 flex flex-col rounded-lg border border-dashed border-amber-300">
                        <div className="flex items-center gap-2 text-amber-600 mb-3">
                            <DollarSign size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Totals</span>
                        </div>
                        <div className="flex-1 flex flex-col justify-center space-y-2">
                            <div className="flex justify-between text-xs">
                                <span className="text-amber-600">Subtotal:</span>
                                <span className="w-20 bg-amber-100 rounded-sm h-3"></span>
                            </div>
                            <div className="flex justify-between text-xs">
                                <span className="text-amber-600">Shipping:</span>
                                <span className="w-16 bg-amber-100 rounded-sm h-3"></span>
                            </div>
                            <div className="flex justify-between text-xs">
                                <span className="text-amber-600">Tax:</span>
                                <span className="w-14 bg-amber-100 rounded-sm h-3"></span>
                            </div>
                            <div className="flex justify-between text-xs font-bold pt-2 border-t border-amber-200">
                                <span className="text-amber-700">Total:</span>
                                <span className="w-24 bg-amber-200 rounded-sm h-4"></span>
                            </div>
                        </div>
                    </div>
                );
            case 'footer':
                return (
                    <div className="p-4 h-full bg-linear-to-br from-slate-50 to-gray-50 flex flex-col rounded-lg border border-dashed border-slate-300">
                        <div className="flex items-center gap-2 text-slate-600 mb-2">
                            <LayoutTemplate size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Footer (Last Page Only)</span>
                        </div>
                        <div className="flex-1 flex items-center justify-center text-center">
                            <p className="text-xs text-slate-500 italic">
                                {itemConfig.content || 'Footer content goes here...'}
                            </p>
                        </div>
                    </div>
                );
            case 'row':
                // Row container - renders children horizontally
                const childItems = (itemConfig.children || []).map(childId =>
                    items.find(i => i.id === childId)
                ).filter(Boolean) as InvoiceItem[];

                return (
                    <div
                        className="p-4 h-full bg-linear-to-br from-violet-50 to-purple-50 flex flex-col rounded-lg border-2 border-dashed border-violet-300"
                        onDragOver={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            e.currentTarget.classList.add('ring-2', 'ring-violet-500');
                        }}
                        onDragLeave={(e) => {
                            e.currentTarget.classList.remove('ring-2', 'ring-violet-500');
                        }}
                        onDrop={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            e.currentTarget.classList.remove('ring-2', 'ring-violet-500');
                            const type = e.dataTransfer.getData('text/plain');
                            if (type && type !== 'row' && onDropItem) {
                                onDropItem(type, itemConfig.id);
                            }
                        }}
                    >
                        <div className="flex items-center gap-2 text-violet-600 mb-3">
                            <Rows size={16} />
                            <span className="text-xs font-semibold uppercase tracking-wider">Row Container</span>
                            <span className="text-[10px] text-violet-400 ml-auto">
                                {childItems.length} item{childItems.length !== 1 ? 's' : ''}
                            </span>
                        </div>
                        <div className="flex-1 flex gap-3 min-h-[60px]">
                            {childItems.length > 0 ? (
                                childItems.map((child, idx) => (
                                    <div
                                        key={child.id}
                                        className="flex-1 bg-white rounded-lg border border-violet-200 overflow-hidden shadow-sm p-2"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onSelect(child.id);
                                        }}
                                    >
                                        <div className="text-xs text-violet-500 font-medium mb-1 flex items-center gap-1">
                                            <span className="w-4 h-4 bg-violet-100 rounded text-center text-[10px] leading-4">{idx + 1}</span>
                                            {child.type}
                                        </div>
                                        <div className="text-[10px] text-slate-400 truncate">
                                            {child.content || child.businessDetails || `${child.type} block`}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="flex-1 flex items-center justify-center border-2 border-dashed border-violet-200 rounded-lg bg-white/50">
                                    <div className="text-center text-violet-400">
                                        <Plus size={20} className="mx-auto mb-1 opacity-50" />
                                        <span className="text-xs">Drop blocks here</span>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                );
            default:
                return <div className="p-3 text-slate-500 text-sm">{itemConfig.type}</div>;
        }
    };

    return (
        <div
            className="flex-1 overflow-y-auto p-8 bg-linear-to-br from-slate-100 via-slate-50 to-slate-100"
            onClick={() => onSelect(null)}
            onDrop={handleCanvasDrop}
            onDragOver={handleDragOver}
        >
            {/* Paper Container */}
            <div className="max-w-[210mm] mx-auto min-h-[297mm] bg-white shadow-2xl rounded-lg relative origin-top ring-1 ring-slate-200/50">
                {/* Paper Texture Overlay */}
                <div className="absolute inset-0 opacity-[0.02] pointer-events-none bg-[url('data:image/svg+xml;base64,')]" />

                {/* Grid Layout */}
                <ResponsiveGridLayout
                    className="layout"
                    layouts={{ lg: layout }}
                    breakpoints={{ lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 }}
                    cols={{ lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 }}
                    rowHeight={30}
                    onLayoutChange={onLayoutChange}
                    isDroppable={true}
                >
                    {layout.map(l => {
                        const itemConfig = items.find(i => i.id === l.i);
                        const isSelected = selectedId === l.i;
                        if (!itemConfig) return <div key={l.i}></div>;

                        return (
                            <div
                                key={l.i}
                                className={`bg-white border-2 rounded-lg group relative transition-all duration-150 ${isSelected
                                    ? 'border-indigo-500 ring-2 ring-indigo-500/20 shadow-lg z-10'
                                    : 'border-slate-200 hover:border-indigo-300 hover:shadow-md'
                                    }`}
                                onClick={(e) => {
                                    e.stopPropagation();
                                    onSelect(l.i);
                                }}
                            >
                                {/* Drag Handle */}
                                <div className={`absolute -top-px -left-px p-1.5 rounded-br-lg cursor-move z-10 transition-all ${isSelected
                                    ? 'bg-indigo-500 opacity-100'
                                    : 'bg-slate-300 opacity-0 group-hover:opacity-100'
                                    }`}>
                                    <GripVertical size={12} className={isSelected ? 'text-white' : 'text-slate-600'} />
                                </div>

                                {/* Item Content */}
                                <div className="h-full overflow-hidden">
                                    {renderItemContent(itemConfig)}
                                </div>
                            </div>
                        );
                    })}
                </ResponsiveGridLayout>

                {/* Empty State */}
                {layout.length === 0 && (
                    <div className="absolute inset-0 flex items-center justify-center">
                        <div className="text-center p-8">
                            <div className="w-20 h-20 mx-auto mb-6 rounded-2xl bg-linear-to-br from-indigo-100 to-purple-100 flex items-center justify-center">
                                <Table size={32} className="text-indigo-500" />
                            </div>
                            <h3 className="text-lg font-bold text-slate-700 mb-2">Start Building Your Invoice</h3>
                            <p className="text-sm text-slate-500 max-w-sm mx-auto">
                                Click on components in the left sidebar to add them to your invoice template.
                            </p>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useState } from 'react';
import { getHelpCollections } from '../../data/helpContent';
import { HelpSearch } from '../../components/HelpCenter/HelpSearch';
import { useNavigate } from 'react-router-dom';
import { BookOpen, Box, Settings, Map, FileText, HelpCircle, TrendingUp, Users, ShoppingCart, MessageSquare, Tag, Compass, Package, Truck, BarChart2 } from 'lucide-react';

const ICON_MAP: Record<string, any> = {
    'Box': Box,
    'Settings': Settings,
    'Map': Map,
    'FileText': FileText,
    'TrendingUp': TrendingUp,
    'Users': Users,
    'ShoppingCart': ShoppingCart,
    'MessageSquare': MessageSquare,
    'Tag': Tag,
    'Compass': Compass,
    'Package': Package,
    'Truck': Truck,
    'BarChart2': BarChart2,
    'default': BookOpen
};

export function HelpCenterHome() {
    const navigate = useNavigate();
    // Use static content - no API call needed
    const collections = getHelpCollections();

    return (
        <div className="max-w-7xl mx-auto">
            {/* Header Section */}
            <div className="text-center py-12 px-4 mb-10 bg-linear-to-b from-white to-gray-50/50 rounded-2xl border border-gray-100 shadow-xs">
                <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4 tracking-tight">How can we help you?</h1>
                <p className="text-gray-500 mb-8 max-w-lg mx-auto text-lg leading-relaxed">Search for answers or browse our help guide collections.</p>
                <div className="flex justify-center">
                    <HelpSearch />
                </div>
            </div>

            {/* Collections Grid */}
            <div className="pb-12">
                <h2 className="text-xl font-semibold text-gray-900 mb-6 px-1">Help Collections</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {collections.map(collection => {
                        const Icon = ICON_MAP[collection.icon || 'default'] || ICON_MAP['default'];
                        return (
                            <div key={collection.id} className="bg-white rounded-xl p-6 shadow-xs hover:shadow-lg transition-all border border-gray-100 flex flex-col h-full group duration-300 hover:-translate-y-1">
                                <div className="flex items-center gap-4 mb-4">
                                    <div className="p-3 bg-blue-50 text-blue-600 rounded-xl group-hover:bg-blue-600 group-hover:text-white transition-colors duration-300">
                                        <Icon size={24} strokeWidth={2} />
                                    </div>
                                    <h3 className="text-lg font-bold text-gray-900">{collection.title}</h3>
                                </div>

                                <p className="text-gray-500 text-sm mb-6 grow leading-relaxed">{collection.description}</p>

                                <div className="space-y-3 pt-4 border-t border-gray-50">
                                    {collection.articles?.length > 0 ? collection.articles.slice(0, 5).map((article) => (
                                        <div
                                            key={article.id}
                                            onClick={() => navigate(`/help/article/${article.slug}`)}
                                            className="group/item flex items-center gap-2 text-sm text-gray-600 hover:text-blue-600 cursor-pointer transition-colors"
                                        >
                                            <FileText size={14} className="opacity-40 group-hover/item:text-blue-500 group-hover/item:opacity-100 transition-all" />
                                            <span className="truncate">{article.title}</span>
                                        </div>
                                    )) : (
                                        <div className="text-sm text-gray-400 italic">No articles yet.</div>
                                    )}

                                    {collection.articles?.length > 5 && (
                                        <button className="text-xs font-semibold text-blue-500 hover:text-blue-600 mt-2 uppercase tracking-wide">
                                            View all {collection.articles.length} articles
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>

                {collections.length === 0 && (
                    <div className="text-center py-20 bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                        <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-white shadow-xs mb-4">
                            <HelpCircle className="text-gray-400" size={32} />
                        </div>
                        <h3 className="text-lg font-medium text-gray-900">No help content yet</h3>
                        <p className="text-gray-500 mt-1 max-w-sm mx-auto">We're still writing our guides. Check back soon!</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { Logger } from '../utils/logger';
import { useNavigate, Link, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { useToast } from '../context/ToastContext';
import { Search, Package, Loader2, Layers, Truck, Calculator, Plus, Box, ArrowUpDown, ArrowUp, ArrowDown, RefreshCw } from 'lucide-react';
import { SuppliersList } from '../components/inventory/SuppliersList';
// import { BOMEditor } from '../components/inventory/BOMEditor';
// import { BOMEditor } from '../components/inventory/BOMEditor';
import { ProductSeoModal } from '../components/inventory/ProductSeoModal';
import { PurchaseOrderList } from '../components/inventory/PurchaseOrderList';
import { SeoScoreBadge } from '../components/Seo/SeoScoreBadge';

import { Pagination } from '../components/ui/Pagination';
import { InternalProductsList } from '../components/inventory/InternalProductsList';
import { EmptyState } from '../components/ui/EmptyState';
import { Modal } from '../components/ui/Modal';

interface Product {
    // Updated Product Interface
    id: string;
    wooId?: number;
    name: string;
    sku: string;
    stock_status: string;
    stock_quantity?: number;
    low_stock_amount?: number;
    price: string;
    mainImage?: string;
    images?: Array<{ src: string }>;
    categories?: Array<{ name: string }>;

    // Scoring
    seoScore?: number;
    merchantCenterScore?: number;
    seoData?: any;
    merchantCenterIssues?: any;
    variations?: Array<{
        id: number;
        stock_quantity: number | null;
        stock_status: string;
        price: string;
        sku: string;
    }>;
    /** Variant data from ProductVariation table with accurate stock */
    searchableVariants?: Array<{
        id: string;
        wooId: number;
        sku: string;
        stockQuantity: number | null;
        stockStatus: string;
    }>;
}

import { ProductService } from '../services/ProductService';

export function InventoryPage() {
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const toast = useToast();

    // Read initial tab from URL query param, default to 'catalog'
    const tabFromUrl = searchParams.get('tab') as 'catalog' | 'suppliers' | 'purchasing' | 'components' | null;
    const validTabs = ['catalog', 'suppliers', 'purchasing', 'components'];
    const initialTab = (tabFromUrl && validTabs.includes(tabFromUrl)) ? tabFromUrl : 'catalog';
    const [activeTab, setActiveTab] = useState<'catalog' | 'suppliers' | 'purchasing' | 'components'>(initialTab);

    // Sync URL when tab changes
    useEffect(() => {
        const currentTabParam = searchParams.get('tab');
        if (activeTab !== 'catalog' && currentTabParam !== activeTab) {
            setSearchParams({ tab: activeTab }, { replace: true });
        } else if (activeTab === 'catalog' && currentTabParam) {
            // Remove tab param when on default catalog tab
            searchParams.delete('tab');
            setSearchParams(searchParams, { replace: true });
        }
    }, [activeTab]);

    // Catalog State
    const [products, setProducts] = useState<Product[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isCreating, setIsCreating] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [sortField, setSortField] = useState<'name' | 'price' | null>(null);
    const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);
    const [debouncedQuery, setDebouncedQuery] = useState('');

    // BOM State
    // const [editingBOM, setEditingBOM] = useState<string | null>(null);
    const [viewingSeo, setViewingSeo] = useState<Product | null>(null);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [newProductName, setNewProductName] = useState('');

    // Debounce search
    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedQuery(searchQuery);
            setPage(1); // Reset to page 1 on new search
        }, 500);
        return () => clearTimeout(timer);
    }, [searchQuery]);

    useEffect(() => {
        if (activeTab === 'catalog') {
            fetchProducts();
        }
    }, [currentAccount, token, debouncedQuery, page, limit, activeTab]);

    async function fetchProducts() {
        if (!currentAccount || !token) return;

        setIsLoading(true);
        try {
            const params = new URLSearchParams({
                page: page.toString(),
                limit: limit.toString(),
                q: debouncedQuery
            });

            const res = await fetch(`/api/products?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                const data = await res.json();
                setProducts(data.products);
                setTotalPages(data.totalPages);
                setTotalItems(data.total);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    async function handleCreateProduct() {
        if (!currentAccount || !token || !newProductName.trim()) return;

        setIsCreating(true);
        try {
            const newProduct = await ProductService.createProduct({ name: newProductName.trim() }, token, currentAccount.id);
            setShowCreateModal(false);
            setNewProductName('');
            navigate(`/inventory/product/${newProduct.id}`);
        } catch (err) {
            Logger.error('An error occurred', { error: err });
            toast.error('Failed to create product');
        } finally {
            setIsCreating(false);
        }
    }

    // Memoize sorted products to avoid re-sorting on every render
    const sortedProducts = useMemo(() => {
        if (!sortField) return products;
        return [...products].sort((a, b) => {
            if (sortField === 'name') {
                const nameA = a.name.toLowerCase();
                const nameB = b.name.toLowerCase();
                return sortDirection === 'asc'
                    ? nameA.localeCompare(nameB)
                    : nameB.localeCompare(nameA);
            }
            if (sortField === 'price') {
                const priceA = parseFloat(a.price) || 0;
                const priceB = parseFloat(b.price) || 0;
                return sortDirection === 'asc' ? priceA - priceB : priceB - priceA;
            }
            return 0;
        });
    }, [products, sortField, sortDirection]);

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-end border-b pb-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Inventory</h1>
                    <p className="text-sm text-gray-500">Manage products, materials, and suppliers</p>
                </div>

                <div className="flex gap-4">
                    <button
                        onClick={() => setShowCreateModal(true)}
                        className="flex items-center gap-2 pb-2 -mb-4 px-2 font-medium text-blue-600 hover:text-blue-800 transition-colors"
                    >
                        <Plus size={18} />
                        New Product
                    </button>
                    <button
                        onClick={() => setActiveTab('catalog')}
                        className={`flex items-center gap-2 pb-2 -mb-4 px-2 font-medium transition-colors border-b-2 ${activeTab === 'catalog' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                    >
                        <Layers size={18} /> Product Catalog
                    </button>
                    <button
                        onClick={() => setActiveTab('suppliers')}
                        className={`flex items-center gap-2 pb-2 -mb-4 px-2 font-medium transition-colors border-b-2 ${activeTab === 'suppliers' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                    >
                        <Truck size={18} /> Suppliers & Materials
                    </button>
                    <button
                        onClick={() => setActiveTab('purchasing')}
                        className={`flex items-center gap-2 pb-2 -mb-4 px-2 font-medium transition-colors border-b-2 ${activeTab === 'purchasing' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                    >
                        <Calculator size={18} /> Purchasing
                    </button>
                    <button
                        onClick={() => setActiveTab('components')}
                        className={`flex items-center gap-2 pb-2 -mb-4 px-2 font-medium transition-colors border-b-2 ${activeTab === 'components' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                    >
                        <Box size={18} /> Components
                    </button>

                </div>
            </div>

            {
                activeTab === 'suppliers' ? (
                    <SuppliersList />
                ) : activeTab === 'purchasing' ? (
                    <PurchaseOrderList />
                ) : activeTab === 'components' ? (
                    <InternalProductsList />
                ) : (
                    <>
                        <div className="flex justify-between items-center mb-4">
                            <div className="flex items-center gap-2 text-sm text-gray-500">
                                {sortField && (
                                    <>
                                        <span>Sorted by <span className="font-medium text-gray-700">{sortField === 'name' ? 'Name' : 'Price'}</span></span>
                                        <button
                                            onClick={() => setSortField(null)}
                                            className="text-xs text-blue-600 hover:text-blue-800 underline"
                                        >
                                            Clear
                                        </button>
                                    </>
                                )}
                            </div>
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    placeholder="Search products..."
                                    className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500 w-64"
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="bg-gray-50 border-b border-gray-200 text-xs uppercase text-gray-500 font-semibold">
                                        <th className="px-6 py-4 w-16">Image</th>
                                        <th className="px-6 py-4">
                                            <button
                                                onClick={() => {
                                                    if (sortField === 'name') {
                                                        setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
                                                    } else {
                                                        setSortField('name');
                                                        setSortDirection('asc');
                                                    }
                                                }}
                                                className="flex items-center gap-1 hover:text-gray-700 transition-colors group"
                                            >
                                                Product Name
                                                {sortField === 'name' ? (
                                                    sortDirection === 'asc' ? <ArrowUp size={14} className="text-blue-600" /> : <ArrowDown size={14} className="text-blue-600" />
                                                ) : (
                                                    <ArrowUpDown size={14} className="text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity" />
                                                )}
                                            </button>
                                        </th>
                                        <th className="px-6 py-4">SKU</th>
                                        <th className="px-6 py-4">Stock</th>
                                        <th className="px-6 py-4">
                                            <button
                                                onClick={() => {
                                                    if (sortField === 'price') {
                                                        setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
                                                    } else {
                                                        setSortField('price');
                                                        setSortDirection('asc');
                                                    }
                                                }}
                                                className="flex items-center gap-1 hover:text-gray-700 transition-colors group"
                                            >
                                                Price
                                                {sortField === 'price' ? (
                                                    sortDirection === 'asc' ? <ArrowUp size={14} className="text-blue-600" /> : <ArrowDown size={14} className="text-blue-600" />
                                                ) : (
                                                    <ArrowUpDown size={14} className="text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity" />
                                                )}
                                            </button>
                                        </th>
                                        <th className="px-6 py-4">SEO / GMC</th>
                                        <th className="px-6 py-4 text-center">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100">
                                    {isLoading ? (
                                        <tr><td colSpan={7} className="p-12 text-center"><Loader2 className="animate-spin inline text-blue-600" /></td></tr>
                                    ) : products.length === 0 ? (
                                        <tr><td colSpan={7}>
                                            <EmptyState
                                                icon={<Package size={48} />}
                                                title="No products found"
                                                description="Products will appear here after syncing your WooCommerce store."
                                                action={{ label: 'Create Product', onClick: handleCreateProduct, icon: <Plus size={16} /> }}
                                            />
                                        </td></tr>
                                    ) : (
                                        [...sortedProducts]
                                            .map((product) => (
                                                <tr key={product.id} className="hover:bg-gray-50 transition-colors">
                                                    <td className="px-6 py-4">
                                                        <div className="w-10 h-10 bg-gray-100 rounded-lg overflow-hidden border border-gray-200">
                                                            {(product.mainImage || product.images?.[0]?.src) ? (
                                                                <img src={product.mainImage || product.images?.[0]?.src} alt="" className="w-full h-full object-cover" referrerPolicy="no-referrer" loading="lazy" />
                                                            ) : (
                                                                <div className="w-full h-full flex items-center justify-center text-gray-400"><Package size={16} /></div>
                                                            )}
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4 font-medium text-gray-900">
                                                        <Link to={`/inventory/product/${product.wooId || product.id}`} className="hover:text-blue-600 transition-colors">
                                                            {product.name}
                                                        </Link>
                                                    </td>
                                                    <td className="px-6 py-4 text-sm font-mono text-gray-500">{product.sku || '-'}</td>
                                                    <td className="px-6 py-4">
                                                        <div className="flex flex-col gap-1">
                                                            {product.searchableVariants && product.searchableVariants.length > 0 ? (
                                                                // Variable Product Stock Logic - uses searchableVariants from ProductVariation table
                                                                (() => {
                                                                    const totalStock = product.searchableVariants.reduce((sum, v) => sum + (v.stockQuantity || 0), 0);
                                                                    const breakdown = product.searchableVariants.map(v => v.stockQuantity || 0).join(', ');
                                                                    const variantTooltip = product.searchableVariants
                                                                        .map(v => `${v.sku || `#${v.wooId}`}: ${v.stockQuantity ?? 0} (${v.stockStatus === 'instock' ? 'In Stock' : 'Out'})`)
                                                                        .join('\n');
                                                                    return (
                                                                        <div className="flex flex-col" title={variantTooltip}>
                                                                            <span className={`text-lg font-bold text-gray-900`}>
                                                                                {totalStock}
                                                                            </span>
                                                                            <span className="text-xs text-gray-500 font-mono cursor-default border-b border-dotted border-gray-300 w-fit">
                                                                                ({breakdown})
                                                                            </span>
                                                                            <span className="inline-flex items-center px-1.5 py-0.5 rounded-full text-[10px] font-medium bg-purple-50 text-purple-700 mt-1 w-fit">
                                                                                Variable
                                                                            </span>
                                                                        </div>
                                                                    );
                                                                })()
                                                            ) : (
                                                                // Simple Product Logic
                                                                <div title={[
                                                                    product.stock_quantity !== undefined && product.stock_quantity !== null && `Stock: ${product.stock_quantity}`,
                                                                    product.low_stock_amount && `Low stock threshold: ${product.low_stock_amount}`,
                                                                    product.stock_quantity !== undefined && product.stock_quantity !== null && product.stock_quantity === 0 && 'Out of stock!',
                                                                    product.low_stock_amount && product.stock_quantity !== undefined && product.stock_quantity !== null && product.stock_quantity <= product.low_stock_amount && product.stock_quantity > 0 && 'Below low stock threshold',
                                                                ].filter(Boolean).join('\n') || undefined}>
                                                                    {product.stock_quantity !== undefined && product.stock_quantity !== null && (
                                                                        <span className={`text-lg font-bold ${product.stock_quantity === 0 ? 'text-red-600' :
                                                                            (product.low_stock_amount && product.stock_quantity <= product.low_stock_amount) ? 'text-amber-600' :
                                                                                'text-gray-900'
                                                                            }`}>
                                                                            {product.stock_quantity}
                                                                        </span>
                                                                    )}
                                                                    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium capitalize w-fit
                                                                ${product.stock_status === 'instock' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                                                                        {product.stock_status === 'instock' ? 'In Stock' : 'Out of Stock'}
                                                                    </span>
                                                                </div>
                                                            )}
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4 text-sm font-medium text-gray-900">
                                                        {product.price ? `$${product.price}` : '-'}
                                                    </td>
                                                    <td className="px-6 py-4">
                                                        <button
                                                            onClick={() => setViewingSeo(product)}
                                                            className="flex flex-col gap-1 items-start hover:opacity-80 transition-opacity"
                                                        >
                                                            <SeoScoreBadge score={product.seoScore || 0} size="sm" tests={product.seoData?.tests} />
                                                            <span
                                                                className={`text-[10px] font-medium px-2 py-0.5 rounded-full border cursor-help ${(product.merchantCenterScore || 0) === 100
                                                                    ? 'bg-blue-50 text-blue-700 border-blue-100'
                                                                    : 'bg-orange-50 text-orange-700 border-orange-100'
                                                                    }`}
                                                                title={product.merchantCenterIssues?.length
                                                                    ? `Issues:\n${product.merchantCenterIssues.map((i: any) => typeof i === 'string' ? i : i.message || i.issue).join('\n')}`
                                                                    : (product.merchantCenterScore || 0) === 100 ? 'All Google Merchant Center checks passed' : 'Click to view GMC details'}
                                                            >
                                                                GMC: {product.merchantCenterScore || 0}%
                                                            </span>
                                                        </button>
                                                    </td>
                                                    <td className="px-6 py-4 text-center">
                                                        <button
                                                            onClick={() => navigate(`/inventory/product/${product.wooId || product.id}`)}
                                                            className="inline-flex items-center gap-1 text-sm text-gray-600 hover:text-gray-800 font-medium px-3 py-1.5 rounded-lg hover:bg-gray-100 transition-colors"
                                                        >
                                                            Edit
                                                        </button>
                                                    </td>
                                                </tr>
                                            ))
                                    )}
                                </tbody>
                            </table>
                            {!isLoading && products.length > 0 && (
                                <Pagination
                                    currentPage={page}
                                    totalPages={totalPages}
                                    onPageChange={setPage}
                                    itemsPerPage={limit}
                                    onItemsPerPageChange={(newLimit) => {
                                        setLimit(newLimit);
                                        setPage(1);
                                    }}
                                    allowItemsPerPage={true}
                                />
                            )}
                        </div>
                    </>
                )
            }

            {viewingSeo && (
                <ProductSeoModal
                    product={viewingSeo}
                    isOpen={!!viewingSeo}
                    onClose={() => setViewingSeo(null)}
                />
            )}

            <Modal
                isOpen={showCreateModal}
                onClose={() => { setShowCreateModal(false); setNewProductName(''); }}
                title="Create New Product"
            >
                <form onSubmit={(e) => { e.preventDefault(); handleCreateProduct(); }} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Product Name</label>
                        <input
                            type="text"
                            value={newProductName}
                            onChange={(e) => setNewProductName(e.target.value)}
                            placeholder="Enter product name..."
                            className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500 dark:bg-slate-700 dark:text-white"
                            autoFocus
                            required
                        />
                    </div>
                    <div className="flex justify-end gap-3">
                        <button
                            type="button"
                            onClick={() => { setShowCreateModal(false); setNewProductName(''); }}
                            className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-lg transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={isCreating || !newProductName.trim()}
                            className="px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors disabled:opacity-50 flex items-center gap-2"
                        >
                            {isCreating && <Loader2 size={14} className="animate-spin" />}
                            Create Product
                        </button>
                    </div>
                </form>
            </Modal>
        </div >
    );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { Logger } from '../utils/logger';
import { useNavigate } from 'react-router-dom';
import { useAccount } from '../context/AccountContext';
import { useAuth } from '../context/AuthContext';
import { Save, ArrowLeft, Loader2, CheckCircle, AlertCircle, X, FileText, Eye, ChevronDown, FileStack, File, Download, Printer, Copy } from 'lucide-react';
import { api } from '../services/api';
import { generateId } from './invoiceUtils';
import { generateInvoicePDF } from '../utils/InvoiceGenerator';
import { DesignerSidebar } from './DesignerSidebar';
import { DesignerCanvas } from './DesignerCanvas';
import { DesignerProperties } from './DesignerProperties';
import { InvoiceRenderer } from '../components/invoicing/InvoiceRenderer';

/**
 * InvoiceDesigner - Single template editor for invoice layouts.
 * Only one template per account is supported - saves always overwrite.
 */
export function InvoiceDesigner() {
    const navigate = useNavigate();
    const { currentAccount } = useAccount();
    const { token } = useAuth();

    const [templateId, setTemplateId] = useState<string | null>(null);
    const [name, setName] = useState('Invoice Template');
    const [layout, setLayout] = useState<any[]>([]);
    const [items, setItems] = useState<any[]>([]);
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [isDirty, setIsDirty] = useState(false);
    const [saveMessage, setSaveMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [showPreview, setShowPreview] = useState(false);
    const [isDownloadingPdf, setIsDownloadingPdf] = useState(false);

    // Refs for keyboard shortcut access to latest state
    const isDirtyRef = useRef(isDirty);
    isDirtyRef.current = isDirty;
    const selectedIdRef = useRef(selectedId);
    selectedIdRef.current = selectedId;
    const showPreviewRef = useRef(showPreview);
    showPreviewRef.current = showPreview;

    // Preview state
    const [recentOrders, setRecentOrders] = useState<any[]>([]);
    const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
    const [previewOrder, setPreviewOrder] = useState<any>(null);
    const [loadingOrders, setLoadingOrders] = useState(false);
    const [loadingOrder, setLoadingOrder] = useState(false);
    const [pageMode, setPageMode] = useState<'single' | 'multi'>('single');

    // Load existing template on mount
    useEffect(() => {
        const fetchTemplate = async () => {
            if (!currentAccount || !token) return;

            try {
                setIsLoading(true);
                const templates: any[] = await api.get('/api/invoices/templates', token, currentAccount.id);

                if (templates && templates.length > 0) {
                    const template = templates[0]; // Only one template per account
                    setTemplateId(template.id);
                    setName(template.name || 'Invoice Template');

                    let layoutData = template.layout;
                    if (typeof layoutData === 'string') {
                        try {
                            layoutData = JSON.parse(layoutData);
                        } catch (e) {
                            Logger.error('Failed to parse layout string', { error: e });
                        }
                    }

                    if (layoutData) {
                        setLayout(layoutData.grid || []);
                        setItems(layoutData.items || []);
                    }
                }
            } catch (err) {
                Logger.error('Failed to load template', { error: err });
            } finally {
                setIsLoading(false);
            }
        };
        fetchTemplate();
    }, [currentAccount, token]);

    // Fetch recent orders when preview opens
    useEffect(() => {
        const fetchOrders = async () => {
            if (!showPreview || !currentAccount || !token) return;
            setLoadingOrders(true);
            try {
                const res = await fetch('/api/orders?limit=20', {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const data = await res.json();
                    setRecentOrders(data.orders || []);
                }
            } catch (err) {
                Logger.error('Failed to fetch orders for preview', { error: err });
            } finally {
                setLoadingOrders(false);
            }
        };
        fetchOrders();
    }, [showPreview, currentAccount, token]);

    // Fetch selected order details
    useEffect(() => {
        const fetchOrderDetails = async () => {
            if (!selectedOrderId || !currentAccount || !token) {
                setPreviewOrder(null);
                return;
            }
            setLoadingOrder(true);
            try {
                const res = await fetch(`/api/orders/${selectedOrderId}`, {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'x-account-id': currentAccount.id
                    }
                });
                if (res.ok) {
                    const data = await res.json();
                    setPreviewOrder(data);
                }
            } catch (err) {
                Logger.error('Failed to fetch order details', { error: err });
            } finally {
                setLoadingOrder(false);
            }
        };
        fetchOrderDetails();
    }, [selectedOrderId, currentAccount, token]);

    // Demo data for when no order is selected
    const demoData = {
        number: 'DEMO-0001',
        date_created: new Date().toISOString(),
        currency: 'AUD',
        billing: {
            first_name: 'John',
            last_name: 'Doe',
            email: 'john.doe@example.com',
            address_1: '123 Example Street',
            city: 'Sydney',
            state: 'NSW',
            postcode: '2000',
            country: 'AU'
        },
        line_items: [
            { name: 'Product A', quantity: 2, price: '25.00', total: '50.00' },
            { name: 'Product B', quantity: 1, price: '75.00', total: '75.00' },
        ],
        subtotal: '125.00',
        shipping_total: '10.00',
        total_tax: '12.50',
        total: '147.50'
    };

    const addItem = (type: string, parentRowId?: string) => {
        const newItemId = generateId();
        let w = 6;
        let h = 2;

        if (type === 'order_table') {
            w = 12;
            h = 4;
        } else if (type === 'footer') {
            w = 12;
            h = 2;
        } else if (type === 'header') {
            w = 12;
            h = 3;
        } else if (type === 'order_details') {
            w = 6;
            h = 3;
        } else if (type === 'customer_details') {
            w = 6;
            h = 4;
        } else if (type === 'row') {
            w = 12;
            h = 3;
        }

        const initialItem: any = {
            id: newItemId,
            type,
            content: type === 'text' ? 'Double click to edit' : ''
        };

        if (type === 'text') {
            initialItem.style = {
                fontSize: '14px',
                fontWeight: 'normal',
                textAlign: 'left'
            };
        }

        if (type === 'row') {
            initialItem.children = [];
        }

        // If adding to a parent row, add as a child instead of to the grid
        if (parentRowId) {
            setItems(prev => {
                const newItems = [...prev, initialItem];
                // Update the parent row's children array
                return newItems.map(item =>
                    item.id === parentRowId
                        ? { ...item, children: [...(item.children || []), newItemId] }
                        : item
                );
            });
        } else {
            // Add to the grid layout
            const newLayoutItem = {
                i: newItemId,
                x: 0,
                y: Infinity,
                w,
                h,
                minW: 2,
                minH: 1
            };
            setLayout(prev => [...prev, newLayoutItem]);
            setItems(prev => [...prev, initialItem]);
        }
    };

    // Handle drag-drop from sidebar
    const handleDropItem = (type: string, targetRowId?: string) => {
        addItem(type, targetRowId);
    };

    const updateItem = (updates: any) => {
        setItems(prev => prev.map(i => i.id === selectedId ? { ...i, ...updates } : i));
    };

    const deleteItem = useCallback(() => {
        if (!selectedId) return;
        // Also remove from any parent row's children array
        setItems(prev => {
            const itemToDelete = prev.find(i => i.id === selectedId);
            if (!itemToDelete) return prev;

            // Remove the item and update any parent that has it as a child
            return prev
                .filter(i => i.id !== selectedId)
                .map(item =>
                    item.children?.includes(selectedId!)
                        ? { ...item, children: item.children.filter((c: string) => c !== selectedId) }
                        : item
                );
        });
        setLayout(prev => prev.filter(l => l.i !== selectedId));
        setSelectedId(null);
        setIsDirty(true);
    }, [selectedId]);

    /** Duplicates the currently selected item with a new ID, offset +1 row down. */
    const duplicateItem = useCallback(() => {
        if (!selectedId) return;
        const source = items.find(i => i.id === selectedId);
        const sourceLayout = layout.find(l => l.i === selectedId);
        if (!source || !sourceLayout) return;

        const newId = generateId();
        const clonedItem = { ...JSON.parse(JSON.stringify(source)), id: newId };
        const clonedLayout = {
            ...sourceLayout,
            i: newId,
            y: sourceLayout.y + sourceLayout.h,
        };

        // If duplicating a row, also duplicate its children
        const newChildItems: any[] = [];
        const newChildLayouts: any[] = [];
        if (source.type === 'row' && source.children?.length > 0) {
            const newChildIds: string[] = [];
            for (const childId of source.children) {
                const childItem = items.find(i => i.id === childId);
                if (!childItem) continue;
                const newChildId = generateId();
                newChildIds.push(newChildId);
                newChildItems.push({ ...JSON.parse(JSON.stringify(childItem)), id: newChildId });
                // Row children may have layout entries too
                const childLayout = layout.find(l => l.i === childId);
                if (childLayout) {
                    newChildLayouts.push({ ...childLayout, i: newChildId });
                }
            }
            clonedItem.children = newChildIds;
        }

        setItems(prev => [...prev, clonedItem, ...newChildItems]);
        setLayout(prev => [...prev, clonedLayout, ...newChildLayouts]);
        setSelectedId(newId);
        setIsDirty(true);
    }, [selectedId, items, layout]);

    const saveTemplate = useCallback(async () => {
        if (!currentAccount || !token) return;
        setIsSaving(true);
        setSaveMessage(null);

        try {
            const payload = {
                name,
                layout: {
                    grid: layout,
                    items: items
                }
            };

            // Always use POST - backend handles upsert logic
            const result: any = await api.post('/api/invoices/templates', payload, token, currentAccount.id);

            if (result && result.id) {
                setTemplateId(result.id);
            }

            setSaveMessage({ type: 'success', text: 'Template saved successfully!' });
            setIsDirty(false);
            setTimeout(() => setSaveMessage(null), 3000);
        } catch (err: any) {
            Logger.error('Failed to save template', { error: err });
            setSaveMessage({ type: 'error', text: err?.message || 'Failed to save template' });
        } finally {
            setIsSaving(false);
        }
    }, [currentAccount, token, name, layout, items]);

    // Track dirty state — only flip dirty on user-initiated changes, not template load
    const hasLoadedRef = useRef(false);
    useEffect(() => {
        // Skip the first render + any renders before/during template load
        if (isLoading) return;
        if (!hasLoadedRef.current) {
            // Mark loaded after the template hydration settles
            hasLoadedRef.current = true;
            return;
        }
        setIsDirty(true);
    }, [layout, items, isLoading]);

    // Warn on page close when dirty
    useEffect(() => {
        const handler = (e: BeforeUnloadEvent) => {
            if (isDirtyRef.current) {
                e.preventDefault();
            }
        };
        window.addEventListener('beforeunload', handler);
        return () => window.removeEventListener('beforeunload', handler);
    }, []);

    // Keyboard shortcuts
    useEffect(() => {
        const handler = (e: KeyboardEvent) => {
            // Don't trigger when typing in inputs/textareas
            const tag = (e.target as HTMLElement).tagName;
            if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;

            if ((e.ctrlKey || e.metaKey) && e.key === 's') {
                e.preventDefault();
                saveTemplate();
            } else if ((e.ctrlKey || e.metaKey) && e.key === 'd') {
                e.preventDefault();
                duplicateItem();
            } else if (e.key === 'Delete' || e.key === 'Backspace') {
                if (selectedIdRef.current) {
                    e.preventDefault();
                    deleteItem();
                }
            } else if (e.key === 'Escape') {
                if (showPreviewRef.current) {
                    setShowPreview(false);
                } else if (selectedIdRef.current) {
                    setSelectedId(null);
                }
            }
        };
        window.addEventListener('keydown', handler);
        return () => window.removeEventListener('keydown', handler);
    }, [saveTemplate, duplicateItem, deleteItem]);

    /** Downloads a PDF using the client-side jsPDF generator. Requires a real order. */
    const handleDownloadPdf = async () => {
        const orderData = previewOrder || demoData;
        setIsDownloadingPdf(true);
        try {
            await generateInvoicePDF(orderData, layout, items, name);
        } catch (err) {
            Logger.error('Failed to generate PDF', { error: err });
            setSaveMessage({ type: 'error', text: 'Failed to generate PDF' });
            setTimeout(() => setSaveMessage(null), 3000);
        } finally {
            setIsDownloadingPdf(false);
        }
    };

    /** Prints the current preview via window.print() */
    const handlePrint = () => {
        window.print();
    };

    /** Navigates back with unsaved changes confirmation */
    const handleBack = () => {
        if (isDirty && !window.confirm('You have unsaved changes. Leave anyway?')) return;
        navigate(-1);
    };

    if (isLoading) {
        return (
            <div className="h-[calc(100vh-64px)] flex items-center justify-center bg-linear-to-br from-slate-50 to-slate-100">
                <div className="flex flex-col items-center gap-4">
                    <div className="relative">
                        <div className="w-16 h-16 rounded-2xl bg-linear-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg animate-pulse">
                            <FileText className="text-white" size={28} />
                        </div>
                    </div>
                    <div className="flex items-center gap-2 text-slate-600">
                        <Loader2 size={18} className="animate-spin" />
                        <span className="font-medium">Loading Invoice Designer...</span>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="h-[calc(100vh-64px)] flex flex-col bg-linear-to-br from-slate-50 via-slate-100 to-slate-50">
            {/* Premium Header */}
            <div className="bg-white/80 backdrop-blur-xl border-b border-slate-200/60 px-6 py-3 flex justify-between items-center shadow-xs">
                <div className="flex items-center gap-4">
                    <button
                        type="button"
                        onClick={handleBack}
                        className="p-2 rounded-xl text-slate-500 hover:text-slate-700 hover:bg-slate-100 transition-all"
                    >
                        <ArrowLeft size={20} />
                    </button>

                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-linear-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-md">
                            <FileText className="text-white" size={18} />
                        </div>
                        <div>
                            <h1 className="font-bold text-slate-800 text-lg leading-tight">Invoice Designer</h1>
                            <p className="text-xs text-slate-500">Customize your invoice template</p>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {/* Preview Toggle */}
                    <button
                        type="button"
                        onClick={() => setShowPreview(!showPreview)}
                        className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-medium text-sm transition-all ${showPreview
                            ? 'bg-indigo-100 text-indigo-700 shadow-inner'
                            : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                            }`}
                    >
                        <Eye size={16} />
                        Preview
                    </button>

                    {/* Save Button */}
                    <button
                        type="button"
                        onClick={saveTemplate}
                        disabled={isSaving}
                        className="flex items-center gap-2 px-5 py-2.5 bg-linear-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-semibold text-sm shadow-lg shadow-indigo-500/25 hover:shadow-xl hover:shadow-indigo-500/30 hover:scale-[1.02] transition-all disabled:opacity-60 disabled:cursor-not-allowed disabled:hover:scale-100"
                    >
                        {isSaving ? (
                            <>
                                <Loader2 size={16} className="animate-spin" />
                                Saving...
                            </>
                        ) : (
                            <>
                                <Save size={16} />
                                Save Template
                            </>
                        )}
                    </button>
                </div>
            </div>

            {/* Toast Notification */}
            {saveMessage && (
                <div className={`fixed top-20 right-6 z-50 flex items-center gap-3 px-5 py-4 rounded-2xl shadow-2xl backdrop-blur-xl transition-all animate-in slide-in-from-right ${saveMessage.type === 'success'
                    ? 'bg-emerald-50/90 border border-emerald-200 text-emerald-800'
                    : 'bg-red-50/90 border border-red-200 text-red-800'
                    }`}>
                    {saveMessage.type === 'success' ? (
                        <div className="w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center">
                            <CheckCircle size={18} className="text-white" />
                        </div>
                    ) : (
                        <div className="w-8 h-8 rounded-full bg-red-500 flex items-center justify-center">
                            <AlertCircle size={18} className="text-white" />
                        </div>
                    )}
                    <span className="text-sm font-semibold">{saveMessage.text}</span>
                    <button
                        type="button"
                        onClick={() => setSaveMessage(null)}
                        className="ml-2 p-1 rounded-full hover:bg-black/5 transition-colors"
                    >
                        <X size={16} />
                    </button>
                </div>
            )}

            {/* Preview Modal */}
            {showPreview && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
                    <div className="relative bg-white rounded-2xl shadow-2xl max-h-[90vh] w-[900px] max-w-[95vw] overflow-hidden flex flex-col">
                        {/* Modal Header */}
                        <div className="sticky top-0 z-10 flex items-center justify-between px-6 py-4 bg-white/95 backdrop-blur-md border-b border-slate-200">
                            <div className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-lg bg-linear-to-br from-indigo-500 to-purple-600 flex items-center justify-center">
                                    <Eye className="text-white" size={14} />
                                </div>
                                <h2 className="font-bold text-slate-800">Invoice Preview</h2>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center gap-3">
                                {/* Order Selection */}
                                <div className="relative">
                                    <select
                                        value={selectedOrderId || ''}
                                        onChange={(e) => setSelectedOrderId(e.target.value || null)}
                                        disabled={loadingOrders}
                                        className="appearance-none px-4 py-2 pr-10 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 cursor-pointer hover:border-indigo-300 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-400 transition-all min-w-[200px]"
                                    >
                                        <option value="">Demo Data</option>
                                        {recentOrders.map((order) => (
                                            <option key={order.id} value={order.wooId || order.id}>
                                                #{order.number} - ${order.total} ({order.status})
                                            </option>
                                        ))}
                                    </select>
                                    <ChevronDown size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                                </div>

                                {/* Page Mode Toggle */}
                                <div className="flex items-center gap-1 p-1 rounded-xl bg-slate-100">
                                    <button
                                        type="button"
                                        onClick={() => setPageMode('single')}
                                        className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${pageMode === 'single'
                                            ? 'bg-white text-indigo-600 shadow-sm'
                                            : 'text-slate-500 hover:text-slate-700'
                                            }`}
                                    >
                                        <File size={14} />
                                        Single
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => setPageMode('multi')}
                                        className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${pageMode === 'multi'
                                            ? 'bg-white text-indigo-600 shadow-sm'
                                            : 'text-slate-500 hover:text-slate-700'
                                            }`}
                                    >
                                        <FileStack size={14} />
                                        Multi-Page
                                    </button>
                                </div>

                                {/* Close Button */}
                                <button
                                    type="button"
                                    onClick={handlePrint}
                                    className="flex items-center gap-2 px-3 py-2 rounded-xl bg-slate-100 text-slate-600 hover:bg-slate-200 text-sm font-medium transition-all"
                                    title="Print invoice"
                                >
                                    <Printer size={14} />
                                    Print
                                </button>

                                <button
                                    type="button"
                                    onClick={handleDownloadPdf}
                                    disabled={isDownloadingPdf}
                                    className="flex items-center gap-2 px-3 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700 text-sm font-medium transition-all disabled:opacity-60"
                                    title="Download as PDF"
                                >
                                    {isDownloadingPdf ? <Loader2 size={14} className="animate-spin" /> : <Download size={14} />}
                                    PDF
                                </button>

                                <button
                                    type="button"
                                    onClick={() => setShowPreview(false)}
                                    className="p-2 rounded-xl text-slate-500 hover:text-slate-700 hover:bg-slate-100 transition-all"
                                >
                                    <X size={20} />
                                </button>
                            </div>
                        </div>

                        {/* Modal Content */}
                        <div className="flex-1 overflow-auto p-8 bg-linear-to-br from-slate-100 via-slate-50 to-slate-100">
                            {loadingOrder ? (
                                <div className="flex items-center justify-center py-16">
                                    <Loader2 size={24} className="animate-spin text-indigo-500" />
                                    <span className="ml-3 text-slate-600">Loading order data...</span>
                                </div>
                            ) : (
                                <InvoiceRenderer
                                    layout={layout}
                                    items={items}
                                    data={previewOrder || demoData}
                                    pageMode={pageMode}
                                />
                            )}
                        </div>

                        {/* Order Info Bar */}
                        {previewOrder && (
                            <div className="px-6 py-3 bg-indigo-50 border-t border-indigo-100 flex items-center justify-between text-sm">
                                <div className="flex items-center gap-4">
                                    <span className="font-medium text-indigo-700">Order #{previewOrder.number}</span>
                                    <span className="text-indigo-600">
                                        {new Date(previewOrder.date_created).toLocaleDateString()}
                                    </span>
                                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${previewOrder.status === 'completed' ? 'bg-emerald-100 text-emerald-700' :
                                        previewOrder.status === 'processing' ? 'bg-blue-100 text-blue-700' :
                                            previewOrder.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                                                'bg-slate-100 text-slate-600'
                                        }`}>
                                        {previewOrder.status}
                                    </span>
                                </div>
                                <div className="text-indigo-600">
                                    {previewOrder.line_items?.length || 0} items • ${previewOrder.total}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Main Content Area */}
            <div className="flex flex-1 overflow-hidden">
                {/* Left Sidebar - Components */}
                <DesignerSidebar onAddItem={addItem} />

                {/* Canvas Area */}
                <DesignerCanvas
                    layout={layout}
                    items={items}
                    selectedId={selectedId}
                    onLayoutChange={(l: any) => setLayout(l)}
                    onSelect={setSelectedId}
                    onDropItem={handleDropItem}
                />

                {/* Right Sidebar - Properties Panel */}
                {selectedId && (
                    <DesignerProperties
                        items={items}
                        selectedId={selectedId}
                        onUpdateItem={updateItem}
                        onDeleteItem={deleteItem}
                        onDuplicateItem={duplicateItem}
                        onClose={() => setSelectedId(null)}
                        token={token || undefined}
                        accountId={currentAccount?.id}
                    />
                )}
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { Logger } from '../utils/logger';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { useVisibilityPolling } from '../hooks/useVisibilityPolling';
import { Globe, LayoutDashboard, Link, FileText, MousePointer, LogOut, LogIn, History, Search, AlertTriangle, Gauge } from 'lucide-react';
import { WebVitalsView } from '../components/analytics/WebVitalsView';
import { getDateRange } from '../utils/dateUtils';
import { LiveSession } from '../types/analytics';
import { VisitorsTable } from '../components/analytics/VisitorsTable';
import { ReportsTable } from '../components/analytics/ReportsTable';
import { AnalyticsOverview } from '../components/analytics/AnalyticsOverview';
import { UrlBuilder } from '../components/analytics/UrlBuilder';
import { RoadblocksView } from '../components/analytics/RoadblocksView';
import VisitorProfileModal from '../components/analytics/VisitorProfileModal';

// Sidebar Menu Items
const MENUS = [
    {
        title: 'Acquisition',
        items: [
            { id: 'overview', label: 'Overview', icon: LayoutDashboard },
            { id: 'realtime', label: 'Real-time Log', icon: History },
            { id: 'channels', label: 'Channels', icon: Globe },
            { id: 'campaigns', label: 'Campaigns', icon: MousePointer },
            { id: 'url-builder', label: 'URL Builder', icon: Link },
        ]
    },
    {
        title: 'Behaviour',
        items: [
            { id: 'pages', label: 'Pages', icon: FileText },
            { id: 'entry', label: 'Entry Pages', icon: LogIn },
            { id: 'exit', label: 'Exit Pages', icon: LogOut },
            { id: 'roadblocks', label: 'Roadblocks', icon: AlertTriangle },
            { id: 'search', label: 'Site Search', icon: Search },
        ]
    },
    {
        title: 'Performance',
        items: [
            { id: 'performance', label: 'Web Vitals', icon: Gauge },
        ]
    }
];


export function LiveAnalyticsPage() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [activeView, setActiveView] = useState('overview');
    const [selectedVisitorId, setSelectedVisitorId] = useState<string | null>(null);

    // Live Data (Shared)
    const [visitors, setVisitors] = useState<LiveSession[]>([]);
    const [carts, setCarts] = useState<LiveSession[]>([]);

    // Report Data (Generic)
    const [reportData, setReportData] = useState<any[]>([]);
    const [loadingReport, setLoadingReport] = useState(false);

    // Date Range (Simple for now: today, 7d, 30d) - Defaults to today
    const [dateRange, setDateRange] = useState('today');

    // Memoized fetch function for visibility polling
    const fetchLiveData = useCallback(async () => {
        if (!currentAccount || !token) return;
        try {
            const [vRes, cRes] = await Promise.all([
                fetch('/api/tracking/live', { headers: { Authorization: `Bearer ${token}`, 'x-account-id': currentAccount.id } }),
                fetch('/api/tracking/carts', { headers: { Authorization: `Bearer ${token}`, 'x-account-id': currentAccount.id } })
            ]);
            if (vRes.ok) setVisitors(await vRes.json());
            if (cRes.ok) setCarts(await cRes.json());
        } catch (e) {
            Logger.error('An error occurred', { error: e });
        }
    }, [currentAccount, token]);

    // Visibility-aware polling with tab coordination
    useVisibilityPolling(fetchLiveData, 5000, [fetchLiveData], 'live-analytics-page');

    useEffect(() => {
        // Fetch Report Data when view changes
        if (activeView !== 'overview' && activeView !== 'realtime' && activeView !== 'url-builder' && activeView !== 'performance') {
            fetchReport(activeView);
        }
    }, [activeView, dateRange, currentAccount]);

    async function fetchReport(viewId: string) {
        setLoadingReport(true);
        try {
            // Determine endpoint
            let endpoint = '';
            if (viewId === 'channels') endpoint = '/api/analytics/acquisition/channels';
            if (viewId === 'campaigns') endpoint = '/api/analytics/acquisition/campaigns';
            if (viewId === 'pages') endpoint = '/api/analytics/behaviour/pages';
            if (viewId === 'search') endpoint = '/api/analytics/behaviour/search';
            if (viewId === 'entry') endpoint = '/api/analytics/behaviour/entry';
            if (viewId === 'exit') endpoint = '/api/analytics/behaviour/exit';

            // Use shared date utility for consistent timezone handling
            const range = getDateRange(dateRange as any);

            const res = await fetch(`${endpoint}?startDate=${range.startDate}&endDate=${range.endDate}`, {
                headers: { Authorization: `Bearer ${token}`, 'x-account-id': currentAccount!.id }
            });

            if (res.ok) {
                setReportData(await res.json());
            }
        } catch (e) { Logger.error('An error occurred', { error: e }); }
        finally { setLoadingReport(false); }
    }

    return (
        <div className="flex flex-col h-[calc(100vh-4rem)] -m-8 overflow-hidden bg-gray-50">
            {/* Horizontal Tabs Header */}
            <div className="bg-white border-b border-gray-200 px-6 py-4">
                <div className="flex items-center justify-between mb-4">
                    <h1 className="text-xl font-bold text-gray-900 capitalize">{activeView.replace('-', ' ')}</h1>

                    {/* Date Range Picker (Only for reports) */}
                    {activeView !== 'overview' && activeView !== 'realtime' && activeView !== 'url-builder' && activeView !== 'performance' && (
                        <select
                            value={dateRange}
                            onChange={e => setDateRange(e.target.value)}
                            className="border border-gray-300 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-blue-500 outline-hidden"
                        >
                            <option value="today">Today</option>
                            <option value="yesterday">Yesterday</option>
                            <option value="7d">Last 7 Days</option>
                            <option value="30d">Last 30 Days</option>
                        </select>
                    )}
                </div>

                {/* Tabs */}
                <div className="flex flex-wrap gap-6">
                    {MENUS.map((menu, i) => (
                        <div key={i} className="flex items-center gap-2">
                            <span className="text-xs font-semibold text-gray-400 uppercase tracking-wider mr-2">{menu.title}</span>
                            <div className="flex items-center gap-1">
                                {menu.items.map(item => (
                                    <button
                                        key={item.id}
                                        onClick={() => setActiveView(item.id)}
                                        className={`flex items-center gap-2 px-3 py-2 text-sm font-medium rounded-lg transition-colors ${activeView === item.id
                                            ? 'bg-blue-50 text-blue-600'
                                            : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                                            }`}
                                    >
                                        <item.icon size={16} />
                                        {item.label}
                                    </button>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Main Content */}
            <main className="flex-1 overflow-auto p-8">
                {activeView === 'overview' && (
                    <AnalyticsOverview
                        visitors={visitors}
                        carts={carts}
                        setActiveView={setActiveView}
                        onVisitorClick={setSelectedVisitorId}
                    />
                )}
                {activeView === 'realtime' && (
                    <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                        <VisitorsTable data={visitors} onVisitorClick={setSelectedVisitorId} />
                    </div>
                )}
                {activeView === 'url-builder' && <UrlBuilder />}
                {activeView === 'roadblocks' && <RoadblocksView dateRange={dateRange} />}
                {activeView === 'performance' && <WebVitalsView />}

                {/* Render Generic Report Table for others */}
                {activeView !== 'overview' && activeView !== 'realtime' && activeView !== 'url-builder' && activeView !== 'roadblocks' && activeView !== 'performance' && (
                    <ReportsTable
                        data={reportData}
                        loading={loadingReport}
                        activeView={activeView}
                    />
                )}
            </main>

            {/* Visitor Profile Modal — opens when any visitor row is clicked */}
            {selectedVisitorId && currentAccount && (
                <VisitorProfileModal
                    visitorId={selectedVisitorId}
                    accountId={currentAccount.id}
                    onClose={() => setSelectedVisitorId(null)}
                />
            )}
        </div>
    );
}

import { useParams, useNavigate, Link } from 'react-router-dom';
import { Logger } from '../utils/logger';
import { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { usePermissions } from '../hooks/usePermissions';
import { formatDate, fixMojibake, formatCurrency } from '../utils/format';
import { User, MapPin, Mail, Phone, Package, CreditCard, RefreshCw, Printer, TrendingUp, Globe, Smartphone, Monitor, Tablet, ChevronDown, ChevronUp, Palette, FileText, Image as ImageIcon, Settings, Truck, ExternalLink, Copy } from 'lucide-react';
import { generateInvoicePDF } from '../utils/InvoiceGenerator';
import { Modal } from '../components/ui/Modal';
import { HistoryTimeline } from '../components/shared/HistoryTimeline';
import { Clock } from 'lucide-react';
import { FraudBadge } from '../components/orders/FraudBadge';
import { OrderTagPanel } from '../components/orders/OrderTagPanel';
import { OrderMetaSection } from '../components/orders/OrderMetaSection';
import { OrderCOGSPanel } from '../components/orders/OrderCOGSPanel';
import { OrderDetailPageSkeleton } from '../components/ui/PageSkeletons';
import { Breadcrumbs } from '../components/ui/Breadcrumbs';
import { useToast } from '../context/ToastContext';

interface Attribution {
    firstTouchSource: string;
    lastTouchSource: string;
    utmSource?: string;
    utmMedium?: string;
    utmCampaign?: string;
    referrer?: string;
    country?: string;
    city?: string;
    deviceType?: string;
    browser?: string;
    os?: string;
}

export function OrderDetailPage() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const toast = useToast();

    const [order, setOrder] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState('');
    const [showRaw, setShowRaw] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const [selectedImage, setSelectedImage] = useState<string | null>(null);
    const [attribution, setAttribution] = useState<Attribution | null>(null);



    useEffect(() => {
        if (id && currentAccount && token) {
            fetchOrder();
        }
    }, [id, currentAccount, token]);

    async function fetchOrder() {
        setIsLoading(true);
        setError('');
        try {
            const res = await fetch(`/api/orders/${id}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (!res.ok) throw new Error('Failed to fetch order');
            const data = await res.json();
            setOrder(data);

            // Fetch attribution data
            fetchAttribution();
        } catch (err) {
            setError('Could not load order details.');
        } finally {
            setIsLoading(false);
        }
    }

    async function fetchAttribution() {
        try {
            const res = await fetch(`/api/orders/${id}/attribution`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                setAttribution(data.attribution);
            }
        } catch (err) {
            // Attribution is optional, don't fail the page
            console.warn('Could not load attribution data');
        }
    }



    const handleGenerateInvoice = async () => {
        setIsGenerating(true);
        try {
            // 1. Fetch Templates
            const res = await fetch(`/api/invoices/templates`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount?.id || ''
                }
            });
            if (!res.ok) throw new Error("Failed to fetch templates");

            const templates = await res.json();

            // Use the most recent template or default
            const template = templates.length > 0 ? templates[0] : null;

            if (!template) {
                toast.error('No invoice template found. Please design one first.');
                return;
            }

            // 2. Generate PDF
            await generateInvoicePDF(order, template.layout?.grid || [], template.layout?.items || [], template.name);

        } catch (e: any) {
            const msg = e?.message || String(e);
            Logger.error('Invoice generation error', { error: msg });
            toast.error(`Failed to generate invoice: ${msg}`);
        } finally {
            setIsGenerating(false);
        }
    };

    /** Callback when tags are updated via the OrderTagPanel */
    function handleTagsChange(newTags: string[]) {
        setOrder((prev: any) => ({ ...prev, tags: newTags }));
    }



    // ... existing useEffect ...

    if (!hasPermission('view_orders') && !isLoading) {
        return <div className="p-10 text-center text-red-500">Access Denied</div>;
    }

    if (isLoading) return <OrderDetailPageSkeleton />;
    if (error || !order) return <div className="p-10 text-center text-red-500">{error || 'Order not found'}</div>;

    const billing = order.billing || {};
    const shipping = order.shipping || {};

    return (
        <div className="max-w-6xl mx-auto space-y-6 pb-20">
            {/* Header / Nav */}
            <Breadcrumbs items={[
                { label: 'Orders', href: '/orders' },
                { label: `#${order.id}` }
            ]} />
            <div className="flex items-center gap-4 mb-6">
                <div className="flex-1">
                    <div className="flex items-center gap-3">
                        <h1 className="text-2xl font-bold text-gray-900">Order #{order.id}</h1>
                        <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
              ${order.status === 'completed' ? 'bg-green-100 text-green-700' :
                                order.status === 'processing' ? 'bg-blue-100 text-blue-700' :
                                    order.status === 'cancelled' ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-700'}`}>
                            {order.status}
                        </span>
                        <FraudBadge orderId={id || ''} />
                    </div>
                    <div className="text-sm text-gray-500 mt-1">Placed on {formatDate(order.date_created)} via {order.payment_method_title}</div>
                </div>
                <div className="flex gap-2">
                    <button
                        onClick={handleGenerateInvoice}
                        disabled={isGenerating}
                        className="btn-white flex items-center gap-2"
                    >
                        {isGenerating ? <div className="animate-spin text-gray-500"><RefreshCw size={16} /></div> : <Printer size={16} />}
                        Generate Invoice
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Main Content - Items */}
                <div className="lg:col-span-2 space-y-6">
                    <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                        <div className="p-4 border-b border-gray-100 bg-gray-50/50 font-semibold text-gray-800 flex items-center gap-2">
                            <Package size={18} className="text-gray-400" />
                            Order Items
                        </div>
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead className="text-xs text-gray-500 uppercase bg-gray-50/30 border-b border-gray-100">
                                    <tr>
                                        <th className="px-6 py-3 font-medium">Item</th>
                                        <th className="px-6 py-3 font-medium text-right">Cost</th>
                                        <th className="px-6 py-3 font-medium text-center">Qty</th>
                                        <th className="px-6 py-3 font-medium text-right">Total</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100">
                                    {order.line_items?.map((item: any) => (
                                        <tr key={item.id} className="hover:bg-gray-50/50">
                                            <td className="px-6 py-4">
                                                <div className="font-medium text-gray-900">{item.name}</div>
                                                <div className="text-xs text-gray-500">SKU: {item.sku || 'N/A'}</div>
                                                {item.meta_data && item.meta_data.length > 0 && (
                                                    <OrderMetaSection metaData={item.meta_data} onImageClick={setSelectedImage} />
                                                )}
                                            </td>
                                            <td className="px-6 py-4 text-right text-gray-600">
                                                {formatCurrency(item.price, order.currency)}
                                            </td>
                                            <td className="px-6 py-4 text-center text-gray-600 bg-gray-50/30">
                                                {item.quantity}
                                            </td>
                                            <td className="px-6 py-4 text-right font-medium text-gray-900">
                                                {formatCurrency(item.total, order.currency)}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                                <tfoot className="bg-gray-50/50 border-t border-gray-100">
                                    <tr>
                                        <td colSpan={3} className="px-6 py-3 text-right text-sm text-gray-500">Subtotal</td>
                                        <td className="px-6 py-3 text-right font-medium text-gray-800">
                                            {formatCurrency(Number(order.total) - Number(order.total_tax) - Number(order.shipping_total), order.currency)}
                                        </td>
                                    </tr>
                                    <tr>
                                        <td colSpan={3} className="px-6 py-2 text-right text-sm text-gray-500">
                                            Shipping
                                            {order.shipping_lines?.[0]?.method_title && (
                                                <span className="ml-1 text-xs text-gray-400">
                                                    ({order.shipping_lines[0].method_title})
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-6 py-2 text-right font-medium text-gray-800">
                                            {formatCurrency(order.shipping_total, order.currency)}
                                        </td>
                                    </tr>
                                    <tr>
                                        <td colSpan={3} className="px-6 py-2 text-right text-sm text-gray-500">Tax</td>
                                        <td className="px-6 py-2 text-right font-medium text-gray-800">
                                            {formatCurrency(order.total_tax, order.currency)}
                                        </td>
                                    </tr>
                                    <tr className="border-t border-gray-200 bg-gray-100">
                                        <td colSpan={3} className="px-6 py-4 text-right font-bold text-gray-900 text-lg">Total</td>
                                        <td className="px-6 py-4 text-right font-bold text-blue-600 text-lg">
                                            {formatCurrency(order.total, order.currency)}
                                        </td>
                                    </tr>
                                </tfoot>
                            </table>
                        </div>
                    </div>

                    {/* Raw Data Toggle */}
                    <div className="border border-gray-200 rounded-lg overflow-hidden">
                        <button
                            onClick={() => setShowRaw(!showRaw)}
                            className="w-full px-4 py-2 bg-gray-50 text-left text-xs font-medium text-gray-500 uppercase hover:bg-gray-100 transition-colors flex justify-between items-center"
                        >
                            <span>Raw Data (Debug)</span>
                            <span>{showRaw ? 'Hide' : 'Show'}</span>
                        </button>
                        {showRaw && (
                            <pre className="p-4 bg-gray-900 text-green-400 text-xs overflow-auto max-h-96 custom-scrollbar">
                                {JSON.stringify(order, null, 2)}
                            </pre>
                        )}
                    </div>
                </div>

                {/* Sidebar - Customer Details */}
                <div className="space-y-6">
                    {/* Tags Panel - First for visibility */}
                    <OrderTagPanel
                        orderId={order.id || order.wooId?.toString() || id || ''}
                        currentTags={order.tags || []}
                        lastUpdate={order.internal_updated_at}
                        onTagsChange={handleTagsChange}
                        onRefresh={fetchOrder}
                    />

                    {/* COGS Breakdown - visible to users with view_cogs permission */}
                    <OrderCOGSPanel orderId={order.id || order.wooId?.toString() || id || ''} currency={order.currency} />

                    {/* Customer Card */}
                    <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-5 space-y-4">
                        <div className="font-semibold text-gray-900 flex items-center gap-2 border-b border-gray-100 pb-3">
                            <User size={18} className="text-blue-500" />
                            Customer Details
                        </div>

                        <div className="space-y-3">
                            <div className="flex items-start gap-3">
                                <div className="p-2 bg-gray-100 rounded-full text-gray-500"><User size={14} /></div>
                                <div>
                                    {order.customer_id && order.customer_id > 0 ? (
                                        <Link
                                            to={`/customers/${order.customer_id}`}
                                            className="text-sm font-medium text-blue-600 hover:text-blue-800 hover:underline"
                                        >
                                            {billing.first_name} {billing.last_name}
                                        </Link>
                                    ) : (
                                        <div className="text-sm font-medium text-gray-900">{billing.first_name} {billing.last_name}</div>
                                    )}
                                    <div className="text-xs text-gray-500">
                                        {order._customerMeta?.ordersCount !== undefined
                                            ? `${order._customerMeta.ordersCount} order${order._customerMeta.ordersCount !== 1 ? 's' : ''} previously`
                                            : 'Guest Customer'}
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-start gap-3">
                                <div className="p-2 bg-gray-100 rounded-full text-gray-500"><Mail size={14} /></div>
                                <div>
                                    <div className="text-sm font-medium text-gray-900 break-all">{billing.email}</div>
                                    <div className="text-xs text-gray-500">Email</div>
                                </div>
                            </div>
                            <div className="flex items-start gap-3">
                                <div className="p-2 bg-gray-100 rounded-full text-gray-500"><Phone size={14} /></div>
                                <div>
                                    <div className="text-sm font-medium text-gray-900">{billing.phone || 'No phone'}</div>
                                    <div className="text-xs text-gray-500">Phone</div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Address Card */}
                    <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-5 space-y-4">
                        <div className="font-semibold text-gray-900 flex items-center gap-2 border-b border-gray-100 pb-3">
                            <MapPin size={18} className="text-blue-500" />
                            Addresses
                        </div>

                        <div className="space-y-4">
                            <div>
                                <div className="text-xs font-semibold text-gray-500 uppercase mb-1">Billing</div>
                                <div className="text-sm text-gray-700 leading-relaxed">
                                    {billing.address_1}<br />
                                    {billing.address_2 && <>{billing.address_2}<br /></>}
                                    {billing.city}, {billing.state} {billing.postcode}<br />
                                    {billing.country}
                                </div>
                            </div>

                            {/* Only show Shipping if different/exists */}
                            {shipping && (
                                <div>
                                    <div className="text-xs font-semibold text-gray-500 uppercase mb-1 pt-3 border-t border-dashed border-gray-200">Shipping</div>
                                    <div className="text-sm text-gray-700 leading-relaxed">
                                        {shipping.address_1}<br />
                                        {shipping.address_2 && <>{shipping.address_2}<br /></>}
                                        {shipping.city}, {shipping.state} {shipping.postcode}<br />
                                        {shipping.country}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Shipment Tracking Card */}
                    {order.tracking_items?.length > 0 && (
                        <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-5 space-y-4">
                            <div className="font-semibold text-gray-900 flex items-center gap-2 border-b border-gray-100 pb-3">
                                <Truck size={18} className="text-blue-500" />
                                Shipment Tracking
                            </div>

                            <div className="space-y-3">
                                {order.tracking_items.map((item: any, idx: number) => (
                                    <div key={idx} className={`space-y-2 ${idx > 0 ? 'pt-3 border-t border-dashed border-gray-200' : ''}`}>
                                        <div className="flex items-center gap-2">
                                            <span className="text-xs font-semibold text-gray-500 uppercase">{item.provider}</span>
                                            {item.dateShipped && (
                                                <span className="text-xs text-gray-400">
                                                    • Shipped {formatDate(item.dateShipped)}
                                                </span>
                                            )}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <code className="text-sm font-mono text-gray-900 bg-gray-50 px-2 py-1 rounded flex-1 truncate">
                                                {item.trackingNumber}
                                            </code>
                                            <button
                                                onClick={() => {
                                                    navigator.clipboard.writeText(item.trackingNumber);
                                                }}
                                                className="p-1.5 hover:bg-gray-100 rounded text-gray-400 hover:text-gray-600 transition-colors"
                                                title="Copy tracking number"
                                            >
                                                <Copy size={14} />
                                            </button>
                                            {item.trackingUrl && (
                                                <a
                                                    href={item.trackingUrl}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="p-1.5 hover:bg-blue-50 rounded text-blue-500 hover:text-blue-700 transition-colors"
                                                    title="Track shipment"
                                                >
                                                    <ExternalLink size={14} />
                                                </a>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Attribution Card */}
                    <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-5 space-y-4">
                        <div className="font-semibold text-gray-900 flex items-center gap-2 border-b border-gray-100 pb-3">
                            <TrendingUp size={18} className="text-blue-500" />
                            Attribution
                        </div>

                        {attribution ? (
                            <div className="space-y-3">
                                {/* Traffic Source */}
                                <div>
                                    <div className="text-xs font-semibold text-gray-500 uppercase mb-2">Traffic Source</div>
                                    <div className="flex flex-wrap gap-2">
                                        <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-700">
                                            First: {attribution.firstTouchSource}
                                        </span>
                                        <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-700">
                                            Last: {attribution.lastTouchSource}
                                        </span>
                                    </div>
                                </div>

                                {/* UTM Parameters */}
                                {(attribution.utmSource || attribution.utmMedium || attribution.utmCampaign) && (
                                    <div>
                                        <div className="text-xs font-semibold text-gray-500 uppercase mb-1 pt-2 border-t border-dashed border-gray-200">UTM Parameters</div>
                                        <div className="space-y-1 text-sm">
                                            {attribution.utmSource && (
                                                <div className="flex gap-2">
                                                    <span className="text-gray-500">Source:</span>
                                                    <span className="text-gray-900">{attribution.utmSource}</span>
                                                </div>
                                            )}
                                            {attribution.utmMedium && (
                                                <div className="flex gap-2">
                                                    <span className="text-gray-500">Medium:</span>
                                                    <span className="text-gray-900">{attribution.utmMedium}</span>
                                                </div>
                                            )}
                                            {attribution.utmCampaign && (
                                                <div className="flex gap-2">
                                                    <span className="text-gray-500">Campaign:</span>
                                                    <span className="text-gray-900">{attribution.utmCampaign}</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                )}

                                {/* Device & Location */}
                                {(attribution.deviceType || attribution.country) && (
                                    <div>
                                        <div className="text-xs font-semibold text-gray-500 uppercase mb-1 pt-2 border-t border-dashed border-gray-200">Device & Location</div>
                                        <div className="flex flex-wrap gap-2">
                                            {attribution.deviceType && (
                                                <span className="inline-flex items-center gap-1 px-2 py-1 rounded-md text-xs bg-gray-100 text-gray-700">
                                                    {attribution.deviceType === 'mobile' ? <Smartphone size={12} /> :
                                                        attribution.deviceType === 'tablet' ? <Tablet size={12} /> : <Monitor size={12} />}
                                                    {attribution.deviceType}
                                                </span>
                                            )}
                                            {attribution.country && (
                                                <span className="inline-flex items-center gap-1 px-2 py-1 rounded-md text-xs bg-gray-100 text-gray-700">
                                                    <Globe size={12} />
                                                    {attribution.city ? `${attribution.city}, ` : ''}{attribution.country}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="text-sm text-gray-500 italic">No attribution data available</div>
                        )}
                    </div>
                </div>

            </div>

            {/* History Section */}
            <div className="bg-white rounded-xl shadow-xs border border-gray-200 p-6">
                <div className="flex items-center gap-2 mb-4">
                    <Clock size={18} className="text-gray-400" />
                    <h2 className="text-lg font-medium text-gray-900">Order History</h2>
                </div>
                <HistoryTimeline resource="ORDER" resourceId={order.id || order.wooId} />
            </div>

            {/* Image Preview Modal */}
            <Modal isOpen={!!selectedImage} onClose={() => setSelectedImage(null)} maxWidth="max-w-4xl" title="Image Preview">
                <div className="flex justify-center bg-gray-50 rounded-lg overflow-hidden">
                    <img src={selectedImage || ''} alt="Preview" className="max-w-full max-h-[80vh] object-contain" />
                </div>
            </Modal>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { Logger } from '../utils/logger';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Plus, FileText, BookOpen, GraduationCap, Trash2, Edit2, EyeOff, Save, ChevronDown, ChevronRight } from 'lucide-react';
import { cn } from '../utils/cn';
import { PoliciesPageSkeleton } from '../components/ui/PageSkeletons';
import { Toast, ToastType } from '../components/ui/Toast';

interface Policy {
    id: string;
    title: string;
    content: string;
    type: 'POLICY' | 'SOP' | 'TRAINING';
    category: string | null;
    isPublished: boolean;
    createdAt: string;
    updatedAt: string;
}

const typeConfig = {
    POLICY: { label: 'Policy', icon: FileText, color: 'bg-blue-100 text-blue-700' },
    SOP: { label: 'SOP', icon: BookOpen, color: 'bg-purple-100 text-purple-700' },
    TRAINING: { label: 'Training', icon: GraduationCap, color: 'bg-green-100 text-green-700' }
};

export function PoliciesPage() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [policies, setPolicies] = useState<Policy[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedPolicy, setSelectedPolicy] = useState<Policy | null>(null);
    const [isEditing, setIsEditing] = useState(false);
    const [expandedTypes, setExpandedTypes] = useState<string[]>(['POLICY', 'SOP', 'TRAINING']);

    // Form state
    const [formTitle, setFormTitle] = useState('');
    const [formContent, setFormContent] = useState('');
    const [formType, setFormType] = useState<'POLICY' | 'SOP' | 'TRAINING'>('POLICY');
    const [formCategory, setFormCategory] = useState('');
    const [formIsPublished, setFormIsPublished] = useState(true);

    // Toast state
    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');

    /** Display a toast notification */
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message);
        setToastType(type);
        setToastVisible(true);
    }, []);

    useEffect(() => {
        if (currentAccount && token) fetchPolicies();
    }, [currentAccount, token]);

    const fetchPolicies = async () => {
        try {
            const res = await fetch('/api/policies', {
                headers: { Authorization: `Bearer ${token}`, 'x-account-id': currentAccount?.id || '' }
            });
            if (res.ok) setPolicies(await res.json());
        } catch (e) {
            Logger.error('Failed to fetch policies:', { error: e });
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreate = () => {
        setSelectedPolicy(null);
        setFormTitle('');
        setFormContent('');
        setFormType('POLICY');
        setFormCategory('');
        setFormIsPublished(true);
        setIsEditing(true);
    };

    const handleEdit = (policy: Policy) => {
        setSelectedPolicy(policy);
        setFormTitle(policy.title);
        setFormContent(policy.content);
        setFormType(policy.type);
        setFormCategory(policy.category || '');
        setFormIsPublished(policy.isPublished);
        setIsEditing(true);
    };

    const handleView = (policy: Policy) => {
        setSelectedPolicy(policy);
        setIsEditing(false);
    };

    const handleSave = async () => {
        // Client-side validation with specific error messages
        if (!formTitle.trim()) {
            showToast('No title entered');
            return;
        }
        if (!formContent.trim()) {
            showToast('No content entered');
            return;
        }

        const body = {
            title: formTitle,
            content: formContent,
            type: formType,
            category: formCategory || null,
            isPublished: formIsPublished
        };

        try {
            const url = selectedPolicy ? `/api/policies/${selectedPolicy.id}` : '/api/policies';
            const method = selectedPolicy ? 'PUT' : 'POST';
            const res = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                },
                body: JSON.stringify(body)
            });

            if (res.ok) {
                fetchPolicies();
                setIsEditing(false);
                showToast(
                    selectedPolicy ? 'Policy updated successfully' : 'Policy created successfully',
                    'success'
                );
                if (!selectedPolicy) {
                    setSelectedPolicy(null);
                } else {
                    const updated = await res.json();
                    setSelectedPolicy(updated);
                }
            } else {
                // Surface the API error message
                const data = await res.json().catch(() => null);
                showToast(data?.error || 'Failed to save policy');
            }
        } catch (e) {
            Logger.error('Failed to save policy:', { error: e });
            showToast('Failed to save policy — network error');
        }
    };

    const handleDelete = async (policyId: string) => {
        if (!confirm('Are you sure you want to delete this policy?')) return;

        try {
            const res = await fetch(`/api/policies/${policyId}`, {
                method: 'DELETE',
                headers: { Authorization: `Bearer ${token}`, 'x-account-id': currentAccount?.id || '' }
            });
            if (res.ok) {
                fetchPolicies();
                showToast('Policy deleted', 'success');
                if (selectedPolicy?.id === policyId) {
                    setSelectedPolicy(null);
                    setIsEditing(false);
                }
            } else {
                const data = await res.json().catch(() => null);
                showToast(data?.error || 'Failed to delete policy');
            }
        } catch (e) {
            Logger.error('Failed to delete policy:', { error: e });
            showToast('Failed to delete policy — network error');
        }
    };

    const toggleType = (type: string) => {
        setExpandedTypes(prev =>
            prev.includes(type) ? prev.filter(t => t !== type) : [...prev, type]
        );
    };

    const groupedPolicies = {
        POLICY: policies.filter(p => p.type === 'POLICY'),
        SOP: policies.filter(p => p.type === 'SOP'),
        TRAINING: policies.filter(p => p.type === 'TRAINING')
    };

    if (isLoading) return <PoliciesPageSkeleton />;

    return (
        <>
            <div className="flex h-[calc(100vh-4rem)]">
                {/* Left Panel: List */}
                <div className="w-80 border-r border-gray-200 bg-white flex flex-col">
                    <div className="p-4 border-b border-gray-200">
                        <div className="flex items-center justify-between mb-2">
                            <h1 className="text-lg font-bold text-gray-900">Policies & SOP</h1>
                            <button
                                onClick={handleCreate}
                                className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                            >
                                <Plus size={18} />
                            </button>
                        </div>
                        <p className="text-xs text-gray-500">Manage policies, SOPs, and training materials</p>
                    </div>

                    <div className="flex-1 overflow-y-auto">
                        {(['POLICY', 'SOP', 'TRAINING'] as const).map(type => {
                            const config = typeConfig[type];
                            const items = groupedPolicies[type];
                            const isExpanded = expandedTypes.includes(type);

                            return (
                                <div key={type} className="border-b border-gray-100">
                                    <button
                                        onClick={() => toggleType(type)}
                                        className="w-full flex items-center gap-2 px-4 py-3 text-left hover:bg-gray-50 transition-colors"
                                    >
                                        {isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
                                        <config.icon size={18} className="text-gray-500" />
                                        <span className="font-medium text-gray-700">{config.label}s</span>
                                        <span className="ml-auto text-xs text-gray-400">{items.length}</span>
                                    </button>

                                    {isExpanded && items.length > 0 && (
                                        <div className="pb-2">
                                            {items.map(policy => (
                                                <button
                                                    key={policy.id}
                                                    onClick={() => handleView(policy)}
                                                    className={cn(
                                                        "w-full flex items-center gap-2 px-6 py-2 text-left text-sm transition-colors",
                                                        selectedPolicy?.id === policy.id
                                                            ? "bg-blue-50 text-blue-700 border-r-2 border-blue-600"
                                                            : "hover:bg-gray-50 text-gray-600"
                                                    )}
                                                >
                                                    <span className="truncate flex-1">{policy.title}</span>
                                                    {!policy.isPublished && (
                                                        <EyeOff size={14} className="text-gray-400" />
                                                    )}
                                                </button>
                                            ))}
                                        </div>
                                    )}

                                    {isExpanded && items.length === 0 && (
                                        <p className="px-6 py-2 text-xs text-gray-400 italic">No {config.label.toLowerCase()}s yet</p>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Right Panel: View/Edit */}
                <div className="flex-1 bg-gray-50 flex flex-col">
                    {!selectedPolicy && !isEditing ? (
                        <div className="flex-1 flex items-center justify-center text-gray-400">
                            <div className="text-center">
                                <BookOpen size={48} className="mx-auto mb-4 opacity-50" />
                                <p>Select a policy to view or click + to create new</p>
                            </div>
                        </div>
                    ) : (
                        <>
                            {/* Header */}
                            <div className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between">
                                {isEditing ? (
                                    <input
                                        type="text"
                                        placeholder="Enter title..."
                                        value={formTitle}
                                        onChange={e => setFormTitle(e.target.value)}
                                        className="text-xl font-bold text-gray-900 bg-transparent border-none outline-hidden w-full"
                                    />
                                ) : (
                                    <div>
                                        <h2 className="text-xl font-bold text-gray-900">{selectedPolicy?.title}</h2>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className={cn("text-xs px-2 py-0.5 rounded-full font-medium", typeConfig[selectedPolicy?.type || 'POLICY'].color)}>
                                                {typeConfig[selectedPolicy?.type || 'POLICY'].label}
                                            </span>
                                            {selectedPolicy?.category && (
                                                <span className="text-xs text-gray-500">• {selectedPolicy.category}</span>
                                            )}
                                        </div>
                                    </div>
                                )}

                                <div className="flex items-center gap-2">
                                    {isEditing ? (
                                        <>
                                            <button
                                                onClick={() => {
                                                    setIsEditing(false);
                                                    if (!selectedPolicy) setSelectedPolicy(null);
                                                }}
                                                className="px-3 py-1.5 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                                            >
                                                Cancel
                                            </button>
                                            <button
                                                onClick={handleSave}
                                                className="flex items-center gap-1 px-4 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                                            >
                                                <Save size={16} />
                                                Save
                                            </button>
                                        </>
                                    ) : (
                                        <>
                                            <button
                                                onClick={() => selectedPolicy && handleEdit(selectedPolicy)}
                                                className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                            >
                                                <Edit2 size={18} />
                                            </button>
                                            <button
                                                onClick={() => selectedPolicy && handleDelete(selectedPolicy.id)}
                                                className="p-2 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </>
                                    )}
                                </div>
                            </div>

                            {/* Metadata Bar (Edit Mode) */}
                            {isEditing && (
                                <div className="bg-white border-b border-gray-200 px-6 py-3 flex items-center gap-4">
                                    <select
                                        value={formType}
                                        onChange={e => setFormType(e.target.value as any)}
                                        className="text-sm border border-gray-300 rounded-lg px-2 py-1"
                                    >
                                        <option value="POLICY">Policy</option>
                                        <option value="SOP">SOP</option>
                                        <option value="TRAINING">Training</option>
                                    </select>
                                    <input
                                        type="text"
                                        placeholder="Category (optional)"
                                        value={formCategory}
                                        onChange={e => setFormCategory(e.target.value)}
                                        className="text-sm border border-gray-300 rounded-lg px-2 py-1 w-40"
                                    />
                                    <label className="flex items-center gap-2 text-sm text-gray-600">
                                        <input
                                            type="checkbox"
                                            checked={formIsPublished}
                                            onChange={e => setFormIsPublished(e.target.checked)}
                                            className="rounded-sm"
                                        />
                                        Published
                                    </label>
                                </div>
                            )}

                            {/* Content */}
                            <div className="flex-1 overflow-y-auto p-6">
                                {isEditing ? (
                                    <textarea
                                        placeholder="Write your policy content here... (Markdown supported)"
                                        value={formContent}
                                        onChange={e => setFormContent(e.target.value)}
                                        className="w-full h-full min-h-[400px] p-4 bg-white border border-gray-200 rounded-lg text-sm font-mono resize-none outline-hidden focus:ring-2 focus:ring-blue-500"
                                    />
                                ) : (
                                    <div className="bg-white rounded-lg border border-gray-200 p-6 prose max-w-none">
                                        {selectedPolicy?.content ? (
                                            <div className="whitespace-pre-wrap">{selectedPolicy.content}</div>
                                        ) : (
                                            <p className="text-gray-400 italic">No content</p>
                                        )}
                                    </div>
                                )}
                            </div>
                        </>
                    )}
                </div>
            </div>

            <Toast
                message={toastMessage}
                isVisible={toastVisible}
                onClose={() => setToastVisible(false)}
                type={toastType}
            />
        </>
    );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { Logger } from '../utils/logger';
import { useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { ArrowLeft, Save, Plus, Trash2, Loader2, Calendar, Copy, ExternalLink, RotateCcw } from 'lucide-react';
import { CreateSupplierModal } from '../components/inventory/CreateSupplierModal';
import { ProductSearchInput, ProductSelection } from '../components/inventory/ProductSearchInput';
import { SupplierSearchInput } from '../components/inventory/SupplierSearchInput';
import { POStatusStepper } from '../components/inventory/POStatusStepper';
import { Toast, ToastType } from '../components/ui/Toast';
import { usePODraftPersistence } from '../hooks/usePODraftPersistence';

interface POItem {
    id?: string;
    productId?: string;
    supplierItemId?: string;
    name: string;
    quantity: number;
    unitCost: number;
    totalCost: number;
    sku?: string;
    wooId?: number;          // WooCommerce product ID for tracking
    variationWooId?: number; // Variant ID if applicable
}

interface Supplier {
    id: string;
    name: string;
    currency: string;
    items: any[];
}

export function PurchaseOrderEditPage() {
    const navigate = useNavigate();
    const { id } = useParams();
    const isNew = !id || id === 'new';
    const { token } = useAuth();
    const { currentAccount } = useAccount();

    const [isLoading, setIsLoading] = useState(false);
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);

    // Form State
    const [supplierId, setSupplierId] = useState('');
    const [status, setStatus] = useState('DRAFT');
    const [notes, setNotes] = useState('');
    const [orderDate, setOrderDate] = useState('');
    const [expectedDate, setExpectedDate] = useState('');
    const [trackingNumber, setTrackingNumber] = useState('');
    const [trackingLink, setTrackingLink] = useState('');
    const [items, setItems] = useState<POItem[]>([]);
    const [showCreateSupplier, setShowCreateSupplier] = useState(false);

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    const [poNumber, setPoNumber] = useState('');

    /** Whether the server data has loaded — prevents draft from overwriting fetched PO */
    const serverDataLoadedRef = useRef(false);
    /** Whether any field has been touched since last save — drives beforeunload guard */
    const isDirtyRef = useRef(false);
    /** Prevents draft restore from firing more than once per PO session */
    const draftRestoredRef = useRef(false);

    // --- Draft persistence ---
    const { loadDraft, clearDraft } = usePODraftPersistence({
        accountId: currentAccount?.id ?? '',
        poId: id ?? 'new',
        formState: { supplierId, status, notes, orderDate, expectedDate, trackingNumber, trackingLink, items },
        enabled: !!currentAccount && !isLoading,
    });

    useEffect(() => {
        if (currentAccount) {
            fetchSuppliers();
            if (!isNew) {
                fetchPO(id!);
            } else {
                // Why: for new POs, try to restore a saved draft
                const draft = loadDraft();
                if (draft) {
                    setSupplierId(draft.supplierId);
                    setStatus(draft.status);
                    setNotes(draft.notes);
                    setOrderDate(draft.orderDate);
                    setExpectedDate(draft.expectedDate);
                    setTrackingNumber(draft.trackingNumber);
                    setTrackingLink(draft.trackingLink);
                    setItems(draft.items);
                    showToast('Draft restored from your last session', 'success');
                }
            }
        }
    }, [currentAccount, token, id]);

    // Why: warn the user before they accidentally close/refresh with unsaved changes
    useEffect(() => {
        const handler = (e: BeforeUnloadEvent) => {
            if (!isDirtyRef.current) return;
            e.preventDefault();
        };
        window.addEventListener('beforeunload', handler);
        return () => window.removeEventListener('beforeunload', handler);
    }, []);

    // Why: mark dirty whenever form state changes (skip initial mount)
    const mountedRef = useRef(false);
    useEffect(() => {
        if (!mountedRef.current) { mountedRef.current = true; return; }
        isDirtyRef.current = true;
    }, [supplierId, status, notes, orderDate, expectedDate, trackingNumber, trackingLink, items]);

    async function fetchSuppliers() {
        // Assume endpoint exists
        try {
            const res = await fetch(`/api/inventory/suppliers`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount!.id }
            });
            if (res.ok) setSuppliers(await res.json());
        } catch (err) { Logger.error('An error occurred', { error: err }); }
    }

    async function fetchPO(poId: string) {
        setIsLoading(true);
        try {
            const res = await fetch(`/api/inventory/purchase-orders/${poId}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount!.id }
            });
            if (res.ok) {
                const data = await res.json();
                setSupplierId(data.supplierId);
                setStatus(data.status);
                setNotes(data.notes || '');
                setOrderDate(data.orderDate ? data.orderDate.split('T')[0] : '');
                setExpectedDate(data.expectedDate ? data.expectedDate.split('T')[0] : '');
                setTrackingNumber(data.trackingNumber || '');
                setTrackingLink(data.trackingLink || '');
                setPoNumber(data.orderNumber || '');

                // Map items
                const serverItems = data.items.map((i: any) => ({
                    id: i.id,
                    productId: i.productId,
                    supplierItemId: i.supplierItemId,
                    name: i.name,
                    sku: i.sku,
                    wooId: i.product?.wooId ?? i.wooId,
                    variationWooId: i.variationWooId ?? undefined,
                    quantity: i.quantity,
                    unitCost: Number(i.unitCost),
                    totalCost: Number(i.totalCost)
                }));
                setItems(serverItems);

                // Why: after loading server data, check for a saved draft with unsaved edits
                if (!draftRestoredRef.current) {
                    draftRestoredRef.current = true;
                    const draft = loadDraft();
                    if (draft) {
                        setSupplierId(draft.supplierId);
                        setStatus(draft.status);
                        setNotes(draft.notes);
                        setOrderDate(draft.orderDate);
                        setExpectedDate(draft.expectedDate);
                        setTrackingNumber(draft.trackingNumber);
                        setTrackingLink(draft.trackingLink);
                        setItems(draft.items);
                        isDirtyRef.current = true;
                        showToast('Unsaved changes restored from your last session', 'success');
                    }
                }
            }
        } catch (err) { Logger.error('An error occurred', { error: err }); }
        finally { setIsLoading(false); }
    }

    const addItem = () => {
        setItems([...items, { name: '', quantity: 1, unitCost: 0, totalCost: 0 }]);
    };

    const updateItem = (index: number, field: keyof POItem, value: any) => {
        const newItems = [...items];
        newItems[index] = { ...newItems[index], [field]: value };

        // Auto calc total
        if (field === 'quantity' || field === 'unitCost') {
            newItems[index].totalCost = newItems[index].quantity * newItems[index].unitCost;
        }

        setItems(newItems);
    };

    const removeItem = (index: number) => {
        setItems(items.filter((_, i) => i !== index));
    };

    const handleSave = async () => {
        if (!supplierId) { showToast('Please select a supplier'); return; }

        setIsLoading(true);
        const payload = {
            supplierId,
            status,
            notes,
            orderDate: orderDate || null,
            expectedDate: expectedDate || null,
            trackingNumber: trackingNumber || null,
            trackingLink: trackingLink || null,
            items: items.map(i => ({
                productId: i.productId,
                supplierItemId: i.supplierItemId,
                variationWooId: i.variationWooId || null,
                name: i.name,
                sku: i.sku,
                quantity: Number(i.quantity),
                unitCost: Number(i.unitCost)
            }))
        };

        try {
            const url = isNew ? `/api/inventory/purchase-orders` : `/api/inventory/purchase-orders/${id}`;
            const method = isNew ? 'POST' : 'PUT';

            const res = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                },
                body: JSON.stringify(payload)
            });

            if (res.ok) {
                clearDraft();
                isDirtyRef.current = false;
                navigate('/inventory?tab=purchasing');
            } else {
                let errorMessage = 'Failed to save';
                try {
                    const errorData = await res.json();
                    errorMessage = errorData.error || errorData.message || `Failed to save (${res.status})`;
                } catch {
                    errorMessage = `Failed to save (HTTP ${res.status})`;
                }
                Logger.error('PO save failed', { status: res.status, errorMessage });
                showToast(errorMessage);
            }
        } catch (err) {
            Logger.error('PO save error', { error: err });
            showToast(`Error saving: ${err instanceof Error ? err.message : 'Network error'}`);
        } finally {
            setIsLoading(false);
        }
    };

    /** Delete a DRAFT PO after user confirmation */
    const handleDelete = async () => {
        if (!window.confirm('Are you sure you want to delete this purchase order? This cannot be undone.')) return;

        setIsLoading(true);
        try {
            const res = await fetch(`/api/inventory/purchase-orders/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                }
            });

            if (res.ok) {
                clearDraft();
                isDirtyRef.current = false;
                navigate('/inventory?tab=purchasing');
            } else {
                let errorMessage = 'Failed to delete';
                try {
                    const errorData = await res.json();
                    errorMessage = errorData.error || errorData.message || `Failed to delete (${res.status})`;
                } catch {
                    errorMessage = `Failed to delete (HTTP ${res.status})`;
                }
                Logger.error('PO delete failed', { status: res.status, errorMessage });
                showToast(errorMessage);
            }
        } catch (err) {
            Logger.error('PO delete error', { error: err });
            showToast(`Error deleting: ${err instanceof Error ? err.message : 'Network error'}`);
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading && !isNew && items.length === 0) {
        return <div className="p-12 text-center"><Loader2 className="animate-spin inline" /> Loading PO...</div>;
    }

    const grandTotal = items.reduce((acc, item) => acc + (item.totalCost || 0), 0);
    const selectedSupplier = suppliers.find(s => s.id === supplierId);
    // Lock the PO from editing once marked as received
    const isLocked = status === 'RECEIVED';

    return (
        <div className="max-w-7xl mx-auto space-y-6">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <button onClick={() => navigate('/inventory?tab=purchasing')} className="p-2 hover:bg-gray-100 rounded-full">
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900">{isNew ? 'New Purchase Order' : `Edit PO ${poNumber || id?.substring(0, 8)}`}</h1>
                        <p className="text-gray-500">Manage order details and items</p>
                    </div>
                </div>
                <div className="flex gap-2">
                    {!isNew && (
                        <button
                            onClick={() => {
                                // Duplicate this PO as new draft
                                navigate('/inventory/purchase-orders/new', {
                                    state: { duplicateFrom: { supplierId, items, notes } }
                                });
                            }}
                            className="flex items-center gap-2 bg-gray-100 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-200"
                            title="Duplicate this order"
                        >
                            <Copy size={18} />
                            Duplicate
                        </button>
                    )}
                    {!isNew && status === 'DRAFT' && (
                        <button
                            onClick={handleDelete}
                            disabled={isLoading}
                            className="flex items-center gap-2 bg-red-50 text-red-600 px-4 py-2 rounded-lg hover:bg-red-100 disabled:opacity-50"
                            title="Delete this draft order"
                        >
                            <Trash2 size={18} />
                            Delete
                        </button>
                    )}
                    {isNew && (
                        <button
                            onClick={() => {
                                clearDraft();
                                setSupplierId(''); setStatus('DRAFT'); setNotes('');
                                setOrderDate(''); setExpectedDate('');
                                setTrackingNumber(''); setTrackingLink('');
                                setItems([]);
                                isDirtyRef.current = false;
                                showToast('Draft discarded', 'success');
                            }}
                            className="flex items-center gap-2 bg-gray-100 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-200"
                            title="Discard saved draft"
                        >
                            <RotateCcw size={18} />
                            Discard Draft
                        </button>
                    )}
                    <button
                        onClick={handleSave}
                        disabled={isLoading}
                        className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 disabled:opacity-50"
                    >
                        {isLoading ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                        Save Order
                    </button>
                </div>
            </div>

            {/* Status Stepper */}
            {!isNew && (
                <POStatusStepper
                    status={status as any}
                    onStatusChange={(newStatus) => setStatus(newStatus)}
                    disabled={isLocked}
                />
            )}

            <div className="grid grid-cols-3 gap-6">
                <div className="col-span-2 space-y-6">
                    {/* Items Panel */}
                    <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-xs">
                        <div className="flex justify-between items-center mb-4">
                            <h2 className="text-lg font-semibold">Order Items</h2>
                            {!isLocked && (
                                <button onClick={addItem} className="text-blue-600 text-sm font-medium hover:underline flex items-center gap-1">
                                    <Plus size={16} /> Add Line Item
                                </button>
                            )}
                        </div>

                        <div className="space-y-3">
                            {items.map((item, idx) => (
                                <div key={idx} className="flex gap-3 items-end p-3 bg-gray-50 rounded-lg border border-gray-100">
                                    <div className="flex-1">
                                        <label className="text-xs font-medium text-gray-500">Item Name / SKU</label>
                                        <ProductSearchInput
                                            initialValue={item.name}
                                            placeholder="Search by SKU or name..."
                                            disabled={isLocked}
                                            onSelect={(product: ProductSelection) => {
                                                const newItems = [...items];
                                                // Use COGS as primary cost, fallback to price only if COGS is null/undefined
                                                const costToUse = product.cogs ?? product.price ?? 0;
                                                newItems[idx] = {
                                                    ...newItems[idx],
                                                    productId: product.productId,
                                                    wooId: product.wooId,
                                                    variationWooId: product.variationWooId,
                                                    name: product.name,
                                                    sku: product.sku,
                                                    unitCost: costToUse,
                                                    totalCost: newItems[idx].quantity * costToUse
                                                };
                                                setItems(newItems);
                                            }}
                                        />
                                        {item.productId && (
                                            <div className="flex items-center gap-2 mt-1">
                                                <span className="text-xs text-green-600">✓ Linked</span>
                                                {item.sku && (
                                                    <span className="text-xs bg-gray-100 text-gray-600 px-1.5 py-0.5 rounded font-mono">
                                                        {item.sku}
                                                    </span>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                    <div className="w-24">
                                        <label className="text-xs font-medium text-gray-500">Qty</label>
                                        <input
                                            type="number"
                                            value={item.quantity}
                                            onChange={(e) => updateItem(idx, 'quantity', Number(e.target.value))}
                                            disabled={isLocked}
                                            className="w-full text-sm p-2 border border-gray-300 rounded-sm"
                                        />
                                    </div>
                                    <div className="w-28">
                                        <label className="text-xs font-medium text-gray-500">Unit Cost</label>
                                        <input
                                            type="number"
                                            value={item.unitCost}
                                            onChange={(e) => updateItem(idx, 'unitCost', Number(e.target.value))}
                                            disabled={isLocked}
                                            className="w-full text-sm p-2 border border-gray-300 rounded-sm"
                                        />
                                    </div>
                                    <div className="w-24 text-right pb-2 font-medium">
                                        ${item.totalCost.toFixed(2)}
                                    </div>
                                    {!isLocked && (
                                        <button onClick={() => removeItem(idx)} className="text-red-500 hover:text-red-700 p-2">
                                            <Trash2 size={16} />
                                        </button>
                                    )}
                                </div>
                            ))}
                            {items.length === 0 && (
                                <div className="text-center py-6 text-gray-400 text-sm bg-gray-50 rounded-sm border border-dashed">
                                    No items added.
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end mt-4 pt-4 border-t">
                            <div className="text-right">
                                <span className="text-gray-500 mr-4">Total Amount</span>
                                <span className="text-2xl font-bold">${grandTotal.toFixed(2)}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    {/* Settings Panel */}
                    <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-xs space-y-4">
                        <h2 className="text-lg font-semibold">Order Details</h2>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Supplier</label>
                            <SupplierSearchInput
                                value={supplierId}
                                suppliers={suppliers.map(s => ({ id: s.id, name: s.name, currency: s.currency }))}
                                onChange={(id) => setSupplierId(id)}
                                onCreateNew={() => setShowCreateSupplier(true)}
                                disabled={!isNew || isLocked}
                                placeholder="Search suppliers..."
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                            <select
                                value={status}
                                onChange={(e) => setStatus(e.target.value)}
                                disabled={isLocked}
                                className="w-full border border-gray-300 rounded-lg p-2.5 outline-hidden focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
                            >
                                <option value="DRAFT">Draft</option>
                                <option value="ORDERED">Ordered</option>
                                <option value="RECEIVED">Received</option>
                                <option value="CANCELLED">Cancelled</option>
                            </select>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Ordered Date</label>
                            <div className="relative">
                                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input
                                    type="date"
                                    value={orderDate}
                                    onChange={(e) => setOrderDate(e.target.value)}
                                    disabled={isLocked}
                                    className="pl-10 w-full border border-gray-300 rounded-lg p-2.5 outline-hidden focus:ring-2 focus:ring-blue-500"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Expected Delivery</label>
                            <div className="relative">
                                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input
                                    type="date"
                                    value={expectedDate}
                                    onChange={(e) => setExpectedDate(e.target.value)}
                                    disabled={isLocked}
                                    className="pl-10 w-full border border-gray-300 rounded-lg p-2.5 outline-hidden focus:ring-2 focus:ring-blue-500"
                                />
                            </div>
                        </div>

                        {/* Tracking Section */}
                        <div className="border-t pt-4">
                            <h3 className="text-sm font-semibold text-gray-700 mb-3">Shipment Tracking</h3>
                            <div className="space-y-3">
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Tracking Number</label>
                                    <input
                                        type="text"
                                        value={trackingNumber}
                                        onChange={(e) => setTrackingNumber(e.target.value)}
                                        disabled={isLocked}
                                        placeholder="e.g. 1Z999AA10123456784"
                                        className="w-full border border-gray-300 rounded-lg p-2.5 outline-hidden focus:ring-2 focus:ring-blue-500 font-mono text-sm"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1">Tracking Link</label>
                                    <div className="flex gap-2">
                                        <input
                                            type="url"
                                            value={trackingLink}
                                            onChange={(e) => setTrackingLink(e.target.value)}
                                            disabled={isLocked}
                                            placeholder="https://tracking.example.com/..."
                                            className="flex-1 border border-gray-300 rounded-lg p-2.5 outline-hidden focus:ring-2 focus:ring-blue-500 text-sm"
                                        />
                                        {trackingLink && (
                                            <a
                                                href={trackingLink}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="flex items-center justify-center px-3 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors"
                                                title="Open tracking link"
                                            >
                                                <ExternalLink size={18} />
                                            </a>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                            <textarea
                                value={notes}
                                onChange={(e) => setNotes(e.target.value)}
                                rows={4}
                                disabled={isLocked}
                                className="w-full border border-gray-300 rounded-lg p-2.5 outline-hidden focus:ring-2 focus:ring-blue-500 resize-none"
                            ></textarea>
                        </div>
                    </div>
                </div>
            </div>

            <CreateSupplierModal
                isOpen={showCreateSupplier}
                onClose={() => setShowCreateSupplier(false)}
                onSuccess={(newSupplier) => {
                    fetchSuppliers().then(() => {
                        setSupplierId(newSupplier.id);
                    });
                    setShowCreateSupplier(false);
                }}
            />

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </div>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../utils/logger';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { useAccountFeature } from '../hooks/useAccountFeature';
import { Loader2, TrendingUp, DollarSign, Users, Package, BarChart3, PieChart, FileText, LayoutGrid, Lock } from 'lucide-react';

import { ReportBuilder } from '../components/ReportBuilder';
import { Toast, ToastType } from '../components/ui/Toast';

import { ReportsSidebar } from '../components/analytics/ReportsSidebar';
import { StockVelocityReport } from '../components/analytics/StockVelocityReport';
import { ProfitabilityReport } from '../components/analytics/ProfitabilityReport';
import { getDateRange, getComparisonRange, DateRangeOption, ComparisonOption } from '../utils/dateUtils';
import { ReportTemplate } from '../types/analytics';

interface SalesData {
    date: string;
    sales: number;
    orders: number;
}

interface TopProduct {
    name: string;
    quantity: number;
}

interface CustomerGrowth {
    date: string;
    newCustomers: number;
}

export function ReportsPage() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const isAdvancedReportsEnabled = useAccountFeature('ADVANCED_REPORTS');
    const [isLoading, setIsLoading] = useState(true);

    // Date Logic
    const [dateOption, setDateOption] = useState<DateRangeOption>('today');
    const [comparisonOption, setComparisonOption] = useState<ComparisonOption>('none');

    const [salesData, setSalesData] = useState<SalesData[]>([]);
    const [topProducts, setTopProducts] = useState<TopProduct[]>([]);
    const [customerGrowth, setCustomerGrowth] = useState<CustomerGrowth[]>([]);


    const [activeTab, setActiveTab] = useState<'overview' | 'stock_velocity' | 'profitability' | 'premade' | 'custom'>('overview');

    // Template State
    const [templates, setTemplates] = useState<ReportTemplate[]>([]);
    const [customReportConfig, setCustomReportConfig] = useState<ReportTemplate['config'] | undefined>(undefined);
    const [shouldAutoRun, setShouldAutoRun] = useState(false);

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    useEffect(() => {
        fetchTemplates();
        fetchData();
    }, [currentAccount, token, dateOption]);

    const fetchTemplates = async () => {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch('/api/analytics/templates', {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (res.ok) {
                setTemplates(await res.json());
            }
        } catch (e) { Logger.error('Failed to load templates', { error: e }); showToast('Failed to load report templates'); }
    };

    const handleSelectTemplate = (template: ReportTemplate) => {
        setCustomReportConfig({
            ...template.config,
            dateRange: dateOption // Override with currently selected date option
        });
        setShouldAutoRun(true);
        // Do NOT switch tabs, stay on 'premade' but update the view
        // setActiveTab('custom'); 
    };

    const handleDeleteTemplate = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        if (!confirm('Are you sure?')) return;
        try {
            await fetch(`/api/analytics/templates/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount!.id }
            });
            fetchTemplates();
            showToast('Template deleted', 'success');
        } catch (e) { Logger.error('Delete failed', { error: e }); showToast('Failed to delete template'); }
    };

    const handleTemplateSaved = () => {
        fetchTemplates();
    };

    async function fetchData() {
        if (!currentAccount || !token) return;
        setIsLoading(true);

        const range = getDateRange(dateOption);

        try {
            const headers = { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id };

            const [salesRes, productsRes, customersRes] = await Promise.all([
                fetch(`/api/analytics/sales-chart?startDate=${range.startDate}&endDate=${range.endDate}&interval=day`, { headers }),
                fetch(`/api/analytics/top-products?startDate=${range.startDate}&endDate=${range.endDate}`, { headers }),
                fetch(`/api/analytics/customer-growth?startDate=${range.startDate}&endDate=${range.endDate}`, { headers })
            ]);

            if (salesRes.ok) setSalesData(await salesRes.json());
            if (productsRes.ok) setTopProducts(await productsRes.json());
            if (customersRes.ok) setCustomerGrowth(await customersRes.json());

        } catch (error) {
            Logger.error('Failed to load reports', { error: error });
            showToast('Failed to load report data');
        } finally {
            setIsLoading(false);
        }
    }

    const totalRevenue = salesData.reduce((acc, curr) => acc + curr.sales, 0);
    const newCustomersCount = customerGrowth.reduce((acc, curr) => acc + curr.newCustomers, 0);

    return (
        <>
            <div className="space-y-6">
                {/* Header */}
                <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900">Reports & Analytics</h1>
                        <p className="text-sm text-gray-500 mt-1">Deep dive into your store performance with custom and premade reports</p>
                    </div>

                    {/* Tab Navigation */}
                    <div className="flex bg-white/80 backdrop-blur-xs p-1.5 rounded-xl border border-gray-200/60 shadow-xs">
                        <button
                            onClick={() => setActiveTab('overview')}
                            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'overview' ? 'bg-linear-to-r from-blue-500 to-blue-600 text-white shadow-md shadow-blue-500/20' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                        >
                            Overview
                        </button>

                        <button
                            onClick={() => setActiveTab('stock_velocity')}
                            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'stock_velocity' ? 'bg-linear-to-r from-blue-500 to-blue-600 text-white shadow-md shadow-blue-500/20' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                        >
                            Stock Velocity
                        </button>
                        <button
                            onClick={() => setActiveTab('profitability')}
                            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'profitability' ? 'bg-linear-to-r from-blue-500 to-blue-600 text-white shadow-md shadow-blue-500/20' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                        >
                            Profitability
                        </button> //
                        <button
                            onClick={() => setActiveTab('premade')}
                            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'premade' ? 'bg-linear-to-r from-purple-500 to-purple-600 text-white shadow-md shadow-purple-500/20' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                        >
                            Report Library
                        </button>
                        <button
                            onClick={() => {
                                setShouldAutoRun(false);
                                setActiveTab('custom');
                            }}
                            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'custom' ? 'bg-linear-to-r from-green-500 to-green-600 text-white shadow-md shadow-green-500/20' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'}`}
                        >
                            Custom Builder
                            {!isAdvancedReportsEnabled && <Lock size={12} className="ml-1 inline-block" />}
                        </button>
                        {!isAdvancedReportsEnabled && (activeTab === 'premade' || activeTab === 'custom' || activeTab === 'stock_velocity') && (
                            <div className="absolute inset-x-0 -bottom-12 flex justify-center pointer-events-none">
                                <div className="bg-gray-900 text-white text-xs py-1 px-3 rounded-full shadow-lg opacity-0 transition-opacity peer-hover:opacity-100">
                                    This feature requires the Advanced Reports addon.
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* Date Range Selector (for applicable tabs) */}
                {(activeTab === 'overview' || activeTab === 'profitability' || activeTab === 'premade') && (
                    <div className="flex justify-end">
                        <div className="flex bg-white border border-gray-200 rounded-xl shadow-xs overflow-hidden">
                            <select
                                value={dateOption}
                                onChange={(e) => setDateOption(e.target.value as DateRangeOption)}
                                className="bg-transparent border-r border-gray-200 px-4 py-2.5 text-sm font-medium text-gray-700 outline-hidden focus:bg-gray-50"
                            >
                                <option value="today">Today</option>
                                <option value="yesterday">Yesterday</option>
                                <option value="7d">Last 7 Days</option>
                                <option value="30d">Last 30 Days</option>
                                <option value="90d">Last 90 Days</option>
                                <option value="ytd">Year to Date</option>
                                <option value="all">All Time</option>
                            </select>
                            <select
                                value={comparisonOption}
                                onChange={(e) => setComparisonOption(e.target.value as ComparisonOption)}
                                className="bg-transparent px-4 py-2.5 text-sm text-gray-500 outline-hidden focus:bg-gray-50"
                            >
                                <option value="none">No Comparison</option>
                                <option value="previous_period">vs Previous Period</option>
                                <option value="previous_year">vs Previous Year</option>
                            </select>
                        </div>
                    </div>
                )}

                {
                    activeTab === 'overview' && (
                        <>
                            {/* KPI Cards */}
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                                    <div className="flex items-center gap-3 text-gray-500 mb-2">
                                        <div className="p-2 bg-green-100 text-green-600 rounded-lg"><DollarSign size={20} /></div>
                                        <span className="text-sm font-medium">Total Revenue</span>
                                    </div>
                                    <div className="text-3xl font-bold text-gray-900">${totalRevenue.toLocaleString()}</div>
                                </div>
                                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                                    <div className="flex items-center gap-3 text-gray-500 mb-2">
                                        <div className="p-2 bg-blue-100 text-blue-600 rounded-lg"><Users size={20} /></div>
                                        <span className="text-sm font-medium">New Customers</span>
                                    </div>
                                    <div className="text-3xl font-bold text-gray-900">{newCustomersCount}</div>
                                </div>
                                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                                    <div className="flex items-center gap-3 text-gray-500 mb-2">
                                        <div className="p-2 bg-purple-100 text-purple-600 rounded-lg"><TrendingUp size={20} /></div>
                                        <span className="text-sm font-medium">Avg Order Value</span>
                                    </div>
                                    <div className="text-3xl font-bold text-gray-900">
                                        ${salesData.length ? (totalRevenue / (salesData.reduce((acc, c) => acc + c.orders, 0) || 1)).toFixed(2) : '0.00'}
                                    </div>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                                {/* Sales Chart (Custom SVG implementation for zero deps) */}
                                <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                                    <h3 className="text-lg font-bold text-gray-900 mb-6">Revenue Trend</h3>
                                    <div className="h-64 relative flex items-end justify-between gap-1">
                                        {isLoading ? (
                                            <div className="w-full h-full flex items-center justify-center"><Loader2 className="animate-spin text-blue-600" /></div>
                                        ) : salesData.length === 0 ? (
                                            <div className="w-full h-full flex items-center justify-center text-gray-400">No data available</div>
                                        ) : (
                                            salesData.map((d, i) => {
                                                const maxSales = Math.max(...salesData.map(s => s.sales), 1);
                                                const height = (d.sales / maxSales) * 100;
                                                return (
                                                    <div key={i} className="flex-1 flex flex-col justify-end group relative items-center">
                                                        <div
                                                            className="w-full bg-blue-500 hover:bg-blue-600 transition-all rounded-t-sm"
                                                            style={{ height: `${height}%` }}
                                                        ></div>
                                                        {/* Tooltip */}
                                                        <div className="absolute bottom-full mb-2 hidden group-hover:block bg-gray-900 text-white text-xs p-2 rounded-sm z-10 whitespace-nowrap">
                                                            {d.date}: ${d.sales}
                                                        </div>
                                                    </div>
                                                );
                                            })
                                        )}
                                    </div>
                                </div>

                                {/* Top Products */}
                                <div className="bg-white p-6 rounded-xl shadow-xs border border-gray-200">
                                    <h3 className="text-lg font-bold text-gray-900 mb-6">Top Selling Products</h3>
                                    <div className="space-y-4">
                                        {isLoading ? (
                                            <div className="flex justify-center p-4"><Loader2 className="animate-spin text-blue-600" /></div>
                                        ) : topProducts.length === 0 ? (
                                            <div className="text-center text-gray-400 py-8">No products yet</div>
                                        ) : topProducts.map((p, i) => (
                                            <div key={i} className="flex items-center justify-between">
                                                <div className="flex items-center gap-3 overflow-hidden">
                                                    <div className="w-8 h-8 rounded-sm bg-gray-100 flex items-center justify-center text-gray-400 shrink-0">
                                                        <Package size={14} />
                                                    </div>
                                                    <span className="text-sm font-medium text-gray-900 truncate">{p.name || 'Unknown Product'}</span>
                                                </div>
                                                <span className="text-sm font-bold text-gray-900">{p.quantity} sold</span>
                                            </div>
                                        ))}
                                    </div>
                                    <button className="w-full mt-6 py-2 text-sm text-blue-600 font-medium hover:bg-blue-50 rounded-lg transition-colors">
                                        View All Products
                                    </button>
                                </div>
                            </div>
                        </>
                    )
                }



                {
                    activeTab === 'stock_velocity' && (
                        <StockVelocityReport />
                    )
                }

                {
                    activeTab === 'profitability' && (
                        <ProfitabilityReport
                            startDate={getDateRange(dateOption).startDate}
                            endDate={getDateRange(dateOption).endDate}
                        />
                    )
                }

                {
                    activeTab === 'premade' && (
                        !isAdvancedReportsEnabled ? (
                            <div className="flex flex-col items-center justify-center py-20 bg-gray-50 border border-gray-200 rounded-xl border-dashed">
                                <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mb-4">
                                    <Lock size={32} className="text-blue-600" />
                                </div>
                                <h3 className="text-lg font-bold text-gray-900">Advanced Reports Required</h3>
                                <p className="text-gray-500 max-w-md text-center mt-2">
                                    The Report Library contains powerful pre-built analysis templates.
                                    Enable the Advanced Reports feature to access this library.
                                </p>
                            </div>
                        ) : (
                            <div className="flex gap-6 items-start h-[calc(100vh-14rem)]">
                                <ReportsSidebar
                                    templates={templates}
                                    selectedTemplateId={undefined} // We could track selected ID state if we wanted to highlight logic
                                    onSelect={handleSelectTemplate}
                                    onDelete={handleDeleteTemplate}
                                />
                                <div className="flex-1 h-full min-h-0 overflow-hidden">
                                    {customReportConfig ? (
                                        <ReportBuilder
                                            initialConfig={customReportConfig}
                                            autoRun={shouldAutoRun}
                                            viewMode={true}
                                            onTemplateSaved={handleTemplateSaved}
                                        />
                                    ) : (
                                        <div className="h-full flex flex-col items-center justify-center text-gray-400 border border-gray-200/60 rounded-2xl bg-gray-50/30">
                                            <div className="p-4 bg-white rounded-2xl shadow-xs mb-4">
                                                <FileText size={48} className="text-gray-300" />
                                            </div>
                                            <p className="text-lg font-medium text-gray-500">Select a report to view details</p>
                                            <p className="text-sm text-gray-400 mt-1 max-w-xs text-center">Choose from the system templates or your saved reports on the left.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )
                    )
                }

                {
                    activeTab === 'custom' && (
                        !isAdvancedReportsEnabled ? (
                            <div className="flex flex-col items-center justify-center py-20 bg-gray-50 border border-gray-200 rounded-xl border-dashed">
                                <div className="w-16 h-16 bg-purple-100 rounded-full flex items-center justify-center mb-4">
                                    <Lock size={32} className="text-purple-600" />
                                </div>
                                <h3 className="text-lg font-bold text-gray-900">Custom Builder Locked</h3>
                                <p className="text-gray-500 max-w-md text-center mt-2">
                                    Build your own custom reports and dashboards with the Advanced Reports addon.
                                </p>
                            </div>
                        ) : (
                            <ReportBuilder
                                initialConfig={customReportConfig}
                                autoRun={shouldAutoRun}
                                onTemplateSaved={handleTemplateSaved}
                            />
                        )
                    )
                }
            </div >

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </>);
}

import { useState, useEffect } from 'react';
import { Logger } from '../utils/logger';
import { useAccount } from '../context/AccountContext';
import { useAuth } from '../context/AuthContext';
import { Star, RefreshCw, Search, Loader2, CheckCircle, ExternalLink, Link2, MessageSquare } from 'lucide-react';
import { Pagination } from '../components/ui/Pagination';
import { formatDate } from '../utils/format';
import { useNavigate } from 'react-router-dom';
import { useDebouncedValue } from '../hooks/useDebouncedValue';
import { TableSkeleton } from '../components/ui/Skeleton';
import { EmptyState } from '../components/ui/EmptyState';
import { RelativeTime } from '../components/ui/RelativeTime';
import { useToast } from '../context/ToastContext';

export const ReviewsPage = () => {
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const navigate = useNavigate();
    const toast = useToast();
    const [reviews, setReviews] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isRematching, setIsRematching] = useState(false);

    // Filters & Pagination
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);
    const [totalReviews, setTotalReviews] = useState(0);

    const fetchReviews = async () => {
        if (!currentAccount || !token) return;

        setIsLoading(true);
        try {
            const params = new URLSearchParams({
                page: page.toString(),
                limit: limit.toString(),
                accountId: currentAccount.id
            });

            if (searchQuery) params.append('search', searchQuery);
            if (statusFilter !== 'all') params.append('status', statusFilter);

            const res = await fetch(`/api/reviews?${params.toString()}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (!res.ok) throw new Error('Failed to fetch reviews');

            const data = await res.json();
            setReviews(data.reviews || []);
            setTotalPages(data.pagination?.pages || 1);
            setTotalReviews(data.pagination?.total || 0);

        } catch (error) {
            Logger.error('Failed to fetch reviews', { error: error });
        } finally {
            setIsLoading(false);
        }
    };

    const handleSync = async () => {
        if (!currentAccount || !token) return;
        setIsSyncing(true);
        try {
            const res = await fetch('/api/sync/manual', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                },
                body: JSON.stringify({
                    accountId: currentAccount.id,
                    types: ['reviews'],
                    incremental: true
                })
            });

            if (!res.ok) throw new Error('Sync failed');

            toast.success('Review sync started in background');
            setTimeout(fetchReviews, 2000);

        } catch (error) {
            Logger.error('Sync failed', { error: error });
            toast.error('Failed to start sync');
        } finally {
            setIsSyncing(false);
        }
    };

    const handleRematch = async () => {
        if (!currentAccount || !token) return;
        setIsRematching(true);
        try {
            const res = await fetch('/api/reviews/rematch-all', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                },
                body: JSON.stringify({})
            });

            if (!res.ok) throw new Error('Rematch failed');
            const result = await res.json();
            toast.success(`Rematch complete! ${result.matchedReviews}/${result.totalReviews} matched (${result.matchRate})`);
            fetchReviews();
        } catch (error) {
            Logger.error('Rematch failed', { error: error });
            toast.error('Failed to rematch reviews');
        } finally {
            setIsRematching(false);
        }
    };

    // Debounce search query to prevent API calls on every keystroke
    const debouncedSearch = useDebouncedValue(searchQuery, 400);

    // Reset page when filters change
    useEffect(() => {
        setPage(1);
    }, [debouncedSearch, statusFilter]);

    // Fetch on changes
    useEffect(() => {
        fetchReviews();
    }, [currentAccount, token, page, limit, debouncedSearch, statusFilter]);

    return (
        <div className="p-6 space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Reviews</h1>
                    <p className="text-sm text-gray-500">Manage and view customer reviews</p>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search reviews..."
                            className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg outline-hidden focus:ring-2 focus:ring-blue-500"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>

                    <select
                        className="border border-gray-300 rounded-lg px-3 py-2 outline-hidden focus:ring-2 focus:ring-blue-500 bg-white"
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                    >
                        <option value="all">All Status</option>
                        <option value="approved">Approved</option>
                        <option value="hold">Pending</option>
                        <option value="spam">Spam</option>
                        <option value="trash">Trash</option>
                    </select>

                    <button
                        onClick={handleRematch}
                        disabled={isRematching || isSyncing}
                        className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
                        title="Re-link reviews to their matching orders"
                    >
                        <Link2 size={18} className={isRematching ? "animate-pulse" : ""} />
                        {isRematching ? 'Matching...' : 'Link to Orders'}
                    </button>

                    <button
                        onClick={handleSync}
                        disabled={isSyncing}
                        className="flex items-center gap-2 bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-50 transition-colors disabled:opacity-50"
                    >
                        <RefreshCw size={18} className={isSyncing ? "animate-spin" : ""} />
                        {isSyncing ? 'Syncing...' : 'Sync'}
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-xs border border-gray-200 overflow-hidden">
                <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                        <tr>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Product</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Reviewer</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Rating</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Review</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                        </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                        {isLoading ? (
                            <TableSkeleton rows={8} columns={6} />
                        ) : reviews.length === 0 ? (
                            <tr><td colSpan={6}>
                                <EmptyState
                                    icon={<MessageSquare size={48} />}
                                    title="No reviews found"
                                    description="Reviews will appear here after syncing. Try adjusting your filters or syncing your store."
                                    action={{ label: 'Sync Reviews', onClick: handleSync, icon: <RefreshCw size={16} /> }}
                                />
                            </td></tr>
                        ) : (
                            reviews.map((review) => (
                                <tr key={review.id} className="hover:bg-gray-50 transition-colors">
                                    <td className="px-6 py-4 text-sm text-gray-900 font-medium">{review.productName || 'Unknown Product'}</td>
                                    <td className="px-6 py-4 text-sm text-gray-900">
                                        <div className="flex flex-col">
                                            <div className="flex items-center gap-2">
                                                <span className="font-medium">
                                                    {review.customer ? (
                                                        <button
                                                            onClick={() => navigate(`/customers/${review.customer.id}`)}
                                                            className="text-blue-600 hover:underline flex items-center gap-1"
                                                        >
                                                            {review.customer.firstName ? `${review.customer.firstName} ${review.customer.lastName || ''}` : review.reviewer}
                                                            <ExternalLink size={12} />
                                                        </button>
                                                    ) : (
                                                        review.reviewer
                                                    )}
                                                </span>
                                                {review.order && (
                                                    <div className="group relative">
                                                        <CheckCircle size={16} className="text-green-500 cursor-help" />
                                                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block w-48 bg-gray-800 text-white text-xs rounded-sm p-2 text-center whitespace-normal z-10 shadow-lg">
                                                            Verified Owner via Order #{review.order.number}
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                            <span className="text-xs text-gray-500">{review.reviewerEmail || ''}</span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-yellow-400">
                                        <div className="flex items-center cursor-default" title={review.content ? `"${review.content.slice(0, 200)}${review.content.length > 200 ? '...' : ''}"` : 'No review text'}>
                                            {Array.from({ length: 5 }).map((_, i) => (
                                                <Star key={i} size={16} fill={i < review.rating ? "currentColor" : "none"} strokeWidth={1} />
                                            ))}
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-sm text-gray-500 max-w-xs truncate" title={review.content}>
                                        {review.content}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                                        <div>{formatDate(review.dateCreated)}</div>
                                        <RelativeTime date={review.dateCreated} />
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                                            ${review.status === 'approved' ? 'bg-green-100 text-green-800' :
                                                review.status === 'hold' ? 'bg-yellow-100 text-yellow-800' :
                                                    'bg-gray-100 text-gray-800'}`}>
                                            {review.status}
                                        </span>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {!isLoading && reviews.length > 0 && (
                <Pagination
                    currentPage={page}
                    totalPages={totalPages}
                    onPageChange={setPage}
                    itemsPerPage={limit}
                    onItemsPerPageChange={(newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    }}
                    allowItemsPerPage={true}
                />
            )}
        </div>
    );
};

import { useState, useEffect, useCallback } from 'react';
import { Logger } from '../utils/logger';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Plus, Users, Edit2, Trash2 } from 'lucide-react';
import { SegmentBuilder, SegmentCriteria } from '../components/segments/SegmentBuilder';
import { useNavigate } from 'react-router-dom';
import { Toast, ToastType } from '../components/ui/Toast';

interface Segment {
    id: string;
    name: string;
    description: string;
    criteria: SegmentCriteria;
    campaigns?: any[];
    _count?: { campaigns: number };
}

export function SegmentsPage() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [segments, setSegments] = useState<Segment[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isCreating, setIsCreating] = useState(false);
    const [editingSegment, setEditingSegment] = useState<Segment | null>(null);
    const [segmentName, setSegmentName] = useState('');
    const [segmentDesc, setSegmentDesc] = useState('');

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);
    useEffect(() => {
        fetchSegments();
    }, [currentAccount, token]);

    async function fetchSegments() {
        if (!currentAccount || !token) return;
        try {
            const res = await fetch(`/api/segments`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            if (res.ok) {
                const data = await res.json();
                setSegments(data);
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setIsLoading(false);
        }
    }

    async function handleSave(criteria: SegmentCriteria) {
        if (!currentAccount || !token) return;

        if (!segmentName.trim()) {
            showToast('Please enter a segment name');
            return;
        }

        const data = {
            name: segmentName,
            description: segmentDesc,
            criteria
        };

        try {
            let res;
            if (editingSegment) {
                res = await fetch(`/api/segments/${editingSegment.id}`, {
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`,
                        'X-Account-ID': currentAccount.id
                    },
                    body: JSON.stringify(data)
                });
            } else {
                res = await fetch(`/api/segments`, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`,
                        'X-Account-ID': currentAccount.id
                    },
                    body: JSON.stringify(data)
                });
            }

            if (res.ok) {
                setIsCreating(false);
                setEditingSegment(null);
                setSegmentName('');
                setSegmentDesc('');
                fetchSegments();
                showToast(editingSegment ? 'Segment updated' : 'Segment created', 'success');
            } else {
                const err = await res.json().catch(() => null);
                showToast(err?.error || 'Failed to save segment');
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
            showToast('Failed to save segment — network error');
        }
    }

    async function handleDelete(id: string) {
        if (!confirm('Are you sure you want to delete this segment?')) return;

        try {
            const res = await fetch(`/api/segments/${id}`, {
                method: 'DELETE',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                }
            });
            if (res.ok) {
                fetchSegments();
                showToast('Segment deleted', 'success');
            } else {
                const err = await res.json().catch(() => null);
                showToast(err?.error || 'Failed to delete segment');
            }
        } catch (err) {
            Logger.error('An error occurred', { error: err });
            showToast('Failed to delete segment');
        }
    }

    if (isCreating || editingSegment) {
        return (
            <>
                <div className="space-y-6 max-w-4xl mx-auto">
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900">{editingSegment ? 'Edit Segment' : 'Create New Segment'}</h1>
                        <p className="text-sm text-gray-500">Define criteria to group your customers.</p>
                    </div>

                    <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-xs space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Segment Name</label>
                            <input
                                type="text"
                                className="w-full border border-gray-300 rounded-sm px-3 py-2 outline-hidden focus:ring-2 focus:ring-blue-500"
                                placeholder="e.g. VIP Customers"
                                value={segmentName}
                                onChange={e => setSegmentName(e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Description (Optional)</label>
                            <input
                                type="text"
                                className="w-full border border-gray-300 rounded-sm px-3 py-2 outline-hidden focus:ring-2 focus:ring-blue-500"
                                placeholder="Customers who spent over $500"
                                value={segmentDesc}
                                onChange={e => setSegmentDesc(e.target.value)}
                            />
                        </div>
                    </div>

                    <SegmentBuilder
                        initialCriteria={editingSegment?.criteria}
                        onSave={handleSave}
                        onCancel={() => {
                            setIsCreating(false);
                            setEditingSegment(null);
                            setSegmentName('');
                            setSegmentDesc('');
                        }}
                    />
                </div>

                <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
            </>
        )
    }

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Segments</h1>
                    <p className="text-sm text-gray-500">Manage customer groups for targeted marketing</p>
                </div>
                <button
                    onClick={() => {
                        setSegmentName('');
                        setSegmentDesc('');
                        setIsCreating(true);
                    }}
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
                >
                    <Plus size={18} />
                    Create Segment
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {segments.map(segment => (
                    <div key={segment.id} className="bg-white p-6 rounded-xl border border-gray-200 shadow-xs hover:shadow-md transition-shadow group relative">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 bg-blue-50 text-blue-600 rounded-lg">
                                <Users size={24} />
                            </div>
                            <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity bg-white p-1 rounded-lg border border-gray-100 shadow-xs">
                                <button
                                    onClick={() => {
                                        setSegmentName(segment.name);
                                        setSegmentDesc(segment.description || '');
                                        setEditingSegment(segment);
                                    }}
                                    className="p-1.5 text-gray-500 hover:text-blue-600 rounded-sm hover:bg-blue-50"
                                >
                                    <Edit2 size={16} />
                                </button>
                                <button
                                    onClick={() => handleDelete(segment.id)}
                                    className="p-1.5 text-gray-500 hover:text-red-600 rounded-sm hover:bg-red-50"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>

                        <h3 className="text-lg font-semibold text-gray-900 mb-1">{segment.name}</h3>
                        <p className="text-sm text-gray-500 line-clamp-2 h-10 mb-4">{segment.description || 'No description'}</p>

                        <div className="flex items-center gap-4 text-xs font-medium text-gray-500 border-t border-gray-100 pt-4">
                            <span className="flex items-center gap-1">
                                <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span>
                                {segment.criteria?.type} Logic
                            </span>
                            <span>
                                {segment.criteria?.rules?.length || 0} Conditions
                            </span>
                            <span>
                                {segment._count?.campaigns || 0} Campaigns
                            </span>
                        </div>
                    </div>
                ))}

                {segments.length === 0 && !isLoading && (
                    <div className="col-span-full py-12 text-center text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                        <Users size={48} className="mx-auto mb-4 opacity-50" />
                        <p className="text-lg font-medium text-gray-900">No segments yet</p>
                        <p className="text-sm mb-6">Create your first segment to start targeting customers.</p>
                        <button
                            onClick={() => setIsCreating(true)}
                            className="text-blue-600 hover:underline"
                        >
                            Create Segment
                        </button>
                    </div>
                )}
            </div>

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </div>
    );
}

