/**
 * SeoPage — Standalone page for SEO keyword insights and tracking.
 *
 * Premium design: gradient header, glass pill tabs, animated tab content.
 * Why a separate page: SEO tracking has enough depth to warrant its own
 * space separate from the Marketing hub.
 *
 * Why selectedSiteUrl lives here: both the Overview and Tracker tabs
 * benefit from a shared domain context so users don't have to re-select
 * when switching tabs.
 */

import { useState, useEffect } from 'react';
import { Target, TrendingUp, Globe, ChevronDown } from 'lucide-react';
import { ErrorBoundary } from '../components/ui/ErrorBoundary';
import { SeoKeywordsPanel } from '../components/Seo/SeoKeywordsPanel';
import { KeywordTrackerPanel } from '../components/Seo/KeywordTrackerPanel';
import { useSearchConsoleStatus, useSetDefaultSite } from '../hooks/useSeoKeywords';

type TabId = 'overview' | 'tracker';

const tabs = [
    { id: 'overview' as TabId, label: 'SEO Overview', icon: Target },
    { id: 'tracker' as TabId, label: 'Keyword Tracker', icon: TrendingUp },
];

/**
 * Extract a human-readable label from a GSC siteUrl.
 * "sc-domain:example.com" → "example.com"
 * "https://example.com/" → "example.com"
 */
function prettySiteUrl(raw: string): string {
    return raw
        .replace(/^sc-domain:/, '')
        .replace(/^https?:\/\//, '')
        .replace(/\/$/, '');
}

export function SeoPage() {
    const [activeTab, setActiveTab] = useState<TabId>('overview');
    const status = useSearchConsoleStatus();
    const sites = status.data?.sites ?? [];
    const [selectedSiteUrl, setSelectedSiteUrl] = useState<string | undefined>();
    const setDefaultSite = useSetDefaultSite();

    /** Initialize from the persisted default, falling back to first site */
    useEffect(() => {
        if (sites.length > 0 && !selectedSiteUrl) {
            const defaultUrl = status.data?.defaultSiteUrl;
            // Use the persisted default if it's still in the connected sites list
            const validDefault = defaultUrl && sites.some((s: { siteUrl: string }) => s.siteUrl === defaultUrl);
            setSelectedSiteUrl(validDefault ? defaultUrl : sites[0].siteUrl);
        }
    }, [sites, selectedSiteUrl, status.data?.defaultSiteUrl]);

    return (
        <div className="space-y-8">
            {/* Hero Header with mesh background */}
            <div className="relative overflow-hidden rounded-2xl bg-gradient-to-br from-slate-50 via-blue-50/50 to-violet-50/30 dark:from-slate-900 dark:via-blue-950/30 dark:to-violet-950/20 border border-slate-200/60 dark:border-slate-700/40 px-8 py-8">
                {/* Decorative gradient orbs */}
                <div className="absolute -top-20 -right-20 w-64 h-64 bg-blue-400/10 dark:bg-blue-500/5 rounded-full blur-3xl" />
                <div className="absolute -bottom-16 -left-16 w-48 h-48 bg-violet-400/10 dark:bg-violet-500/5 rounded-full blur-3xl" />

                <div className="relative z-10 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                    <div className="flex flex-col gap-2">
                        <h1 className="text-3xl font-bold tracking-tight text-gradient">
                            SEO & Organic Search
                        </h1>
                        <p className="text-slate-500 dark:text-slate-400 max-w-lg">
                            Monitor organic search performance, track keyword rankings, and discover growth opportunities.
                        </p>
                    </div>

                    {/* Domain selector — only visible when GSC is connected */}
                    {sites.length > 0 && (
                        <div className="shrink-0">
                            {sites.length === 1 ? (
                                /* Single site: static badge */
                                <div className="inline-flex items-center gap-2 px-4 py-2 rounded-xl bg-white/70 dark:bg-slate-800/60 backdrop-blur-sm border border-slate-200/60 dark:border-slate-700/40 text-sm font-medium text-slate-700 dark:text-slate-300">
                                    <Globe size={14} className="text-blue-500" />
                                    {prettySiteUrl(sites[0].siteUrl)}
                                </div>
                            ) : (
                                /* Multiple sites: dropdown selector */
                                <div className="relative inline-flex items-center">
                                    <Globe size={14} className="absolute left-3 text-blue-500 pointer-events-none z-10" />
                                    <select
                                        id="seo-domain-selector"
                                        value={selectedSiteUrl ?? ''}
                                        onChange={e => {
                                            const url = e.target.value;
                                            setSelectedSiteUrl(url);
                                            setDefaultSite.mutate(url);
                                        }}
                                        className="appearance-none pl-8 pr-8 py-2 rounded-xl bg-white/70 dark:bg-slate-800/60 backdrop-blur-sm border border-slate-200/60 dark:border-slate-700/40 text-sm font-medium text-slate-700 dark:text-slate-300 cursor-pointer hover:border-blue-300 dark:hover:border-blue-600 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500/30"
                                    >
                                        {sites.map((site: { id: string; siteUrl: string }) => (
                                            <option key={site.id} value={site.siteUrl}>
                                                {prettySiteUrl(site.siteUrl)}
                                            </option>
                                        ))}
                                    </select>
                                    <ChevronDown size={14} className="absolute right-2.5 text-slate-400 pointer-events-none" />
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Glass Pill Tabs */}
            <div className="flex bg-slate-100/80 dark:bg-slate-800/60 backdrop-blur-sm p-1 rounded-xl border border-slate-200/50 dark:border-slate-700/40 w-fit">
                {tabs.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex items-center gap-2 px-5 py-2.5 font-medium text-sm rounded-lg transition-all duration-200 ${isActive
                                ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-slate-100 shadow-sm'
                                : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
                                }`}
                        >
                            <Icon size={16} />
                            {tab.label}
                        </button>
                    );
                })}
            </div>

            {/* Animated Tab Content */}
            <div key={activeTab} className="animate-fade-slide-up">
                {activeTab === 'overview' && (
                    <ErrorBoundary>
                        <SeoKeywordsPanel siteUrl={selectedSiteUrl} />
                    </ErrorBoundary>
                )}

                {activeTab === 'tracker' && (
                    <ErrorBoundary>
                        <KeywordTrackerPanel />
                    </ErrorBoundary>
                )}
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useAccount } from '../context/AccountContext';
import { useAccountFeature } from '../hooks/useAccountFeature';
import { SyncStatus } from '../components/sync/SyncStatus';
import { ChatSettings } from '../components/chat/ChatSettings';
import { AISettings } from '../components/settings/AISettings';
import { TrackingScriptHelper } from '../components/settings/TrackingScriptHelper';
import { AppearanceSettings } from '../components/settings/AppearanceSettings';
import { GeneralSettings } from '../components/settings/GeneralSettings';
import { EmailSettings } from '../components/settings/EmailSettings';
import { GoldPriceSettings } from '../components/settings/GoldPriceSettings';
import { InventoryAlertsSettings } from '../components/settings/InventoryAlertsSettings';
import { OrderTagSettings } from '../components/settings/OrderTagSettings';
import { NotificationSettings } from '../components/settings/NotificationSettings';
import { SocialChannelsSettings } from '../components/settings/SocialChannelsSettings';
import { TeamSettings } from '../components/settings/TeamSettings';
import RoleManager from '../components/settings/RoleManager';
import { WebhookSettings } from '../components/settings/WebhookSettings';
import { AdAccountSettings } from '../components/settings/AdAccountSettings';
import { CannedResponsesSettings } from '../components/settings/CannedResponsesSettings';
import { TrackingExclusionSettings } from '../components/settings/TrackingExclusionSettings';
import { CAPISettings } from '../components/settings/CAPISettings';
import {
    LayoutGrid, Palette, MessageSquare, Bot, Activity, RefreshCw,
    Mail, Package, Tags, Coins, Bell, Share2, Users, ChevronRight, Webhook, Megaphone, Zap, Shield
} from 'lucide-react';
import { SettingsPageSkeleton } from '../components/ui/PageSkeletons';

type TabId = 'general' | 'appearance' | 'team' | 'roles' | 'chat' | 'channels' | 'intelligence' | 'analytics' | 'sync' | 'email' | 'inventory' | 'orderTags' | 'goldPrice' | 'notifications' | 'webhooks' | 'ads' | 'cannedResponses' | 'conversions';

const VALID_TABS: TabId[] = ['general', 'appearance', 'team', 'roles', 'chat', 'channels', 'intelligence', 'analytics', 'sync', 'email', 'inventory', 'orderTags', 'goldPrice', 'notifications', 'webhooks', 'ads', 'cannedResponses', 'conversions'];

interface TabDef {
    id: TabId;
    label: string;
    icon: React.ElementType;
    hidden?: boolean;
}

interface Category {
    name: string;
    tabs: TabDef[];
}

/**
 * Why: URL-based tab persistence ensures the active tab survives component
 * remounts (e.g., after saving settings that trigger context refreshes).
 * This follows the 'Tab Persistence' pattern from Navigation Standards.
 */
function useTabFromUrl(): [TabId, (tab: TabId) => void] {
    const [searchParams, setSearchParams] = useSearchParams();

    const tabFromUrl = searchParams.get('tab') as TabId | null;
    const activeTab: TabId = tabFromUrl && VALID_TABS.includes(tabFromUrl) ? tabFromUrl : 'general';

    const setActiveTab = useCallback((tab: TabId) => {
        setSearchParams({ tab }, { replace: true });
    }, [setSearchParams]);

    return [activeTab, setActiveTab];
}

/**
 * Modern sidebar-based settings layout with grouped categories.
 * Responsive: sidebar on lg+, horizontal tabs on mobile.
 */
export function SettingsPage() {
    const { currentAccount } = useAccount();
    const isGoldPriceEnabled = useAccountFeature('GOLD_PRICE_CALCULATOR');
    const isAdTrackingEnabled = useAccountFeature('AD_TRACKING');
    const isAIEnabled = useAccountFeature('AI_WRITER');
    const [activeTab, setActiveTab] = useTabFromUrl();

    if (!currentAccount) return <SettingsPageSkeleton />;

    // Grouped categories for sidebar navigation
    const categories: Category[] = [
        {
            name: 'Store',
            tabs: [
                { id: 'general', label: 'General', icon: LayoutGrid },
                { id: 'appearance', label: 'Appearance', icon: Palette },
                { id: 'team', label: 'Team', icon: Users },
                { id: 'roles', label: 'Roles', icon: Shield },
            ]
        },
        {
            name: 'Commerce',
            tabs: [
                { id: 'orderTags', label: 'Order Tags', icon: Tags },
                { id: 'inventory', label: 'Inventory', icon: Package },
                { id: 'goldPrice', label: 'Gold Price', icon: Coins, hidden: !isGoldPriceEnabled },
            ]
        },
        {
            name: 'Integrations',
            tabs: [
                { id: 'email', label: 'Email', icon: Mail },
                { id: 'channels', label: 'Channels', icon: Share2 },
                { id: 'ads', label: 'Ad Accounts', icon: Megaphone },
                { id: 'conversions', label: 'Tracking Pixels', icon: Zap },
                { id: 'webhooks', label: 'Webhooks', icon: Webhook },
                { id: 'sync', label: 'Sync Status', icon: RefreshCw },
            ]
        },
        {
            name: 'Intelligence',
            tabs: [
                { id: 'chat', label: 'Chat Widget', icon: MessageSquare },
                { id: 'cannedResponses', label: 'Canned Responses', icon: Zap },
                { id: 'intelligence', label: 'AI Models', icon: Bot, hidden: !isAIEnabled },
                { id: 'analytics', label: 'Analytics', icon: Activity },
                { id: 'notifications', label: 'Notifications', icon: Bell },
            ]
        }
    ];

    // Flat list for mobile tabs
    const allTabs = categories.flatMap(c => c.tabs).filter(t => !t.hidden);

    const renderContent = () => {
        switch (activeTab) {
            case 'general':
                return <GeneralSettings />;
            case 'orderTags':
                return <OrderTagSettings />;
            case 'goldPrice':
                return <GoldPriceSettings />;
            case 'appearance':
                return (
                    <SettingsCard title="Whitelabeling & Appearance" description="Customize the look and feel of your dashboard.">
                        <AppearanceSettings />
                    </SettingsCard>
                );
            case 'chat':
                return (
                    <SettingsCard title="Live Chat Configuration" description="Manage auto-replies, business hours, and widget behavior.">
                        <ChatSettings />
                    </SettingsCard>
                );
            case 'intelligence':
                return (
                    <SettingsCard title="Intelligence Configuration" description="Manage AI model selection and API keys.">
                        <AISettings />
                    </SettingsCard>
                );
            case 'analytics':
                return (
                    <div className="space-y-6">
                        <SettingsCard title="Analytics Configuration" description="Setup the tracking script to enable Live View and Real-time Cart tracking.">
                            <TrackingScriptHelper />
                        </SettingsCard>
                        <TrackingExclusionSettings />
                    </div>
                );
            case 'inventory':
                return (
                    <SettingsCard title="Inventory Management" description="Configure stock alerts per account.">
                        <InventoryAlertsSettings />
                    </SettingsCard>
                );
            case 'sync':
                return (
                    <SettingsCard title="Data Sync" description="Manage WooCommerce ↔ OverSeek data synchronization.">
                        <SyncStatus />
                    </SettingsCard>
                );
            case 'email':
                return <EmailSettings />;
            case 'channels':
                return (
                    <SettingsCard title="Social Channels" description="Connect Facebook, Instagram, and TikTok to receive messages in your inbox.">
                        <SocialChannelsSettings />
                    </SettingsCard>
                );
            case 'notifications':
                return <NotificationSettings />;
            case 'cannedResponses':
                return (
                    <SettingsCard title="Canned Responses" description="Create reusable message templates with placeholders.">
                        <CannedResponsesSettings />
                    </SettingsCard>
                );
            case 'team':
                return <TeamSettings />;
            case 'roles':
                return (
                    <SettingsCard title="Roles & Permissions" description="Create custom roles with granular permissions for STAFF members.">
                        <RoleManager />
                    </SettingsCard>
                );
            case 'webhooks':
                return (
                    <SettingsCard title="Webhook Configuration" description="Configure WooCommerce webhooks for instant order sync and notifications.">
                        <WebhookSettings />
                    </SettingsCard>
                );
            case 'ads':
                return (
                    <SettingsCard title="Ad Accounts" description="Connect and manage your Meta and Google Ads accounts.">
                        <AdAccountSettings />
                    </SettingsCard>
                );
            case 'conversions':
                return (
                    <SettingsCard title="Tracking Pixels & CAPI" description="Manage client-side pixel tags and server-side conversion tracking for all ad platforms.">
                        <CAPISettings />
                    </SettingsCard>
                );
            default:
                return null;
        }
    };

    return (
        <div className="min-h-[calc(100vh-6rem)]">
            {/* Page Header */}
            <h1 className="text-2xl font-bold text-slate-900 dark:text-white mb-6">Settings</h1>

            {/* Mobile: Horizontal Tabs */}
            <div className="lg:hidden mb-6">
                <div className="flex overflow-x-auto border-b border-slate-200 dark:border-slate-700 no-scrollbar -mx-4 px-4">
                    {allTabs.map((tab) => {
                        const Icon = tab.icon;
                        const isActive = activeTab === tab.id;
                        return (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id)}
                                className={`
                                    flex items-center gap-2 px-4 py-3 border-b-2 text-sm font-medium whitespace-nowrap transition-colors
                                    ${isActive
                                        ? 'border-blue-600 dark:border-blue-400 text-blue-600 dark:text-blue-400'
                                        : 'border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
                                    }
                                `}
                            >
                                <Icon size={16} />
                                {tab.label}
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Desktop: Sidebar + Content */}
            <div className="hidden lg:flex gap-8">
                {/* Sidebar Navigation */}
                <aside className="w-64 shrink-0 px-1">
                    <nav className="sticky top-24 space-y-6">
                        {categories.map((category) => {
                            const visibleTabs = category.tabs.filter(t => !t.hidden);
                            if (visibleTabs.length === 0) return null;
                            return (
                                <div key={category.name}>
                                    <h3 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider px-3 mb-2">
                                        {category.name}
                                    </h3>
                                    <div className="space-y-1">
                                        {visibleTabs.map((tab) => {
                                            const Icon = tab.icon;
                                            const isActive = activeTab === tab.id;
                                            return (
                                                <button
                                                    key={tab.id}
                                                    onClick={() => setActiveTab(tab.id)}
                                                    className={`
                                                        w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-left text-sm transition-all duration-200 group
                                                        ${isActive
                                                            ? 'bg-blue-50 dark:bg-blue-500/10 text-blue-700 dark:text-blue-400 font-semibold shadow-sm shadow-blue-500/5'
                                                            : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800/50 hover:text-slate-900 dark:hover:text-slate-200'
                                                        }
                                                    `}
                                                >
                                                    <Icon size={18} className={`transition-colors ${isActive ? 'text-blue-600 dark:text-blue-400' : 'text-slate-400 dark:text-slate-500 group-hover:text-slate-600 dark:group-hover:text-slate-300'}`} />
                                                    {tab.label}
                                                    {isActive && <ChevronRight size={14} className="ml-auto text-blue-400 dark:text-blue-500" />}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                    </nav>
                </aside>

                {/* Content Area */}
                <main className="flex-1 min-w-0">
                    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                        {renderContent()}
                    </div>
                </main>
            </div>

            {/* Mobile: Content */}
            <div className="lg:hidden">
                {renderContent()}
            </div>
        </div>
    );
}

/**
 * Wrapper card for settings sections that need consistent styling.
 */
function SettingsCard({ title, description, children }: { title: string; description: string; children: React.ReactNode }) {
    return (
        <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden text-slate-900 dark:text-slate-100 transition-all duration-300">
            <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700/50 bg-slate-50/50 dark:bg-slate-800/50 backdrop-blur-sm">
                <h2 className="text-lg font-semibold text-slate-800 dark:text-white">{title}</h2>
                <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">{description}</p>
            </div>
            <div className="p-6">
                {children}
            </div>
        </div>
    );
}

/**
 * Setup Wizard
 * 
 * Multi-step onboarding wizard for new account creation.
 * Guides users through store connection, plugin setup, email, and ad accounts.
 */

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Logger } from '../utils/logger';

// Onboarding components
import { OnboardingStepIndicator } from '../components/onboarding/OnboardingStepIndicator';
import { StoreStep, PluginStep, EmailStep, AdsStep, ReviewStep } from '../components/onboarding/steps';
import {
    ONBOARDING_STEPS,
    STEP_CONFIG,
    OnboardingDraft,
    createInitialDraft,
    validateStep,
    saveDraftToStorage,
    loadDraftFromStorage,
    clearDraftFromStorage
} from '../components/onboarding/types';

/**
 * Multi-step setup wizard orchestrator.
 * Manages step navigation, validation, persistence, and account creation.
 */
export function SetupWizard() {
    // State - use explicit number type for step to allow any step value
    const [currentStep, setCurrentStep] = useState<number>(ONBOARDING_STEPS.STORE);
    const [draft, setDraft] = useState<OnboardingDraft>(createInitialDraft);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    // Tracks whether an account was created within this wizard session,
    // so the redirect-to-dashboard guard doesn't fire prematurely.
    const createdInSession = useRef(false);

    // Hooks
    const { token, logout, isLoading: authLoading } = useAuth();
    const { refreshAccounts, accounts, isLoading: accountsLoading, currentAccount } = useAccount();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const isAddingNew = searchParams.get('addNew') === 'true';

    // ─────────────────────────────────────────────────────────────────────────
    // Effects
    // ─────────────────────────────────────────────────────────────────────────

    // Redirect to login if not authenticated
    useEffect(() => {
        if (!authLoading && !token) {
            navigate('/login', { replace: true });
        }
    }, [authLoading, token, navigate]);

    // Detect when an account is created mid-wizard (via StoreStep early-create)
    // and suppress the redirect so the user can proceed to the Plugin step.
    useEffect(() => {
        if (currentAccount?.id && currentStep === ONBOARDING_STEPS.STORE) {
            createdInSession.current = true;
        }
    }, [currentAccount, currentStep]);

    // Redirect to dashboard if user already has accounts (unless adding new
    // or the account was just created within this wizard session).
    useEffect(() => {
        if (!accountsLoading && accounts.length > 0 && !isAddingNew && !createdInSession.current) {
            Logger.debug('SetupWizard: User has accounts, redirecting to dashboard');
            navigate('/dashboard');
        }
    }, [accounts, accountsLoading, navigate, isAddingNew]);

    // Load saved draft from localStorage on mount
    useEffect(() => {
        const saved = loadDraftFromStorage();
        if (saved && !isAddingNew) {
            Logger.debug('SetupWizard: Resuming from saved draft', { step: saved.currentStep });
            setDraft(saved.draft);
            setCurrentStep(saved.currentStep);
            // Preserve wizard session flag across page reloads / new tabs
            if (saved.wizardSessionActive) {
                createdInSession.current = true;
            }
        }
    }, [isAddingNew]);

    // Save draft to localStorage on changes
    useEffect(() => {
        if (draft.store.name || draft.completedSteps.length > 0) {
            saveDraftToStorage(draft, currentStep);
        }
    }, [draft, currentStep]);

    // ─────────────────────────────────────────────────────────────────────────
    // Navigation Handlers
    // ─────────────────────────────────────────────────────────────────────────

    const handleNext = useCallback(() => {
        // Validate current step
        const validation = validateStep(currentStep, draft);
        if (!validation.isValid) {
            setError(validation.error || 'Please complete all required fields');
            return;
        }

        setError(null);

        // Mark current step as completed
        if (!draft.completedSteps.includes(currentStep)) {
            setDraft(prev => ({
                ...prev,
                completedSteps: [...prev.completedSteps, currentStep]
            }));
        }

        // Move to next step or finalize
        if (currentStep < ONBOARDING_STEPS.TOTAL) {
            setCurrentStep(prev => prev + 1);
        } else {
            handleFinalize();
        }
    }, [currentStep, draft]);

    const handleBack = useCallback(() => {
        if (currentStep > ONBOARDING_STEPS.STORE) {
            setCurrentStep(prev => prev - 1);
            setError(null);
        }
    }, [currentStep]);

    const handleSkip = useCallback(() => {
        // Mark step as skipped (only for skippable steps)
        const stepConfig = STEP_CONFIG.find(s => s.id === currentStep);
        if (stepConfig?.skippable) {
            if (!draft.skippedSteps.includes(currentStep)) {
                setDraft(prev => ({
                    ...prev,
                    skippedSteps: [...prev.skippedSteps, currentStep]
                }));
            }
        }

        setError(null);

        // Move to next step
        if (currentStep < ONBOARDING_STEPS.TOTAL) {
            setCurrentStep(prev => prev + 1);
        }
    }, [currentStep, draft]);

    /** Navigate directly to a previously completed or skipped step */
    const goToStep = useCallback((stepId: number) => {
        // Only allow navigating to completed, skipped, or the current step
        const canNavigate = draft.completedSteps.includes(stepId)
            || draft.skippedSteps.includes(stepId)
            || stepId === currentStep;
        if (canNavigate && stepId >= ONBOARDING_STEPS.STORE && stepId <= ONBOARDING_STEPS.TOTAL) {
            setCurrentStep(stepId);
            setError(null);
        }
    }, [draft.completedSteps, draft.skippedSteps, currentStep]);

    // ─────────────────────────────────────────────────────────────────────────
    // Finalization
    // ─────────────────────────────────────────────────────────────────────────

    const handleFinalize = useCallback(async () => {
        setIsSubmitting(true);
        setError(null);

        try {
            // Check if account was already created in StoreStep
            if (currentAccount?.id) {
                // Account exists - just update additional settings if needed
                Logger.info('SetupWizard: Account already exists, skipping creation', { accountId: currentAccount.id });

                // Could add PATCH to update email/ads settings here if needed
                // For now, just clear draft and navigate
                clearDraftFromStorage();
                await refreshAccounts();
                navigate('/dashboard');
                return;
            }

            // Fallback: Create account if it wasn't created in StoreStep
            // This handles edge cases where early creation failed
            const res = await fetch('/api/accounts', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({
                    name: draft.store.name,
                    domain: draft.store.domain || draft.store.wooUrl,
                    wooUrl: draft.store.wooUrl,
                    wooConsumerKey: draft.store.wooConsumerKey,
                    wooConsumerSecret: draft.store.wooConsumerSecret,
                    // Optional fields based on what was configured
                    pluginVerified: draft.plugin.verified,
                    emailConfigured: draft.email.enabled && draft.email.verified,
                    adsConfigured: draft.ads.googleConnected || draft.ads.metaConnected
                })
            });

            if (res.status === 401) {
                logout();
                return;
            }

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.error || 'Failed to create account');
            }

            // Clear saved draft
            clearDraftFromStorage();

            // Refresh accounts and navigate
            await refreshAccounts();
            navigate('/dashboard');
        } catch (err) {
            Logger.error('SetupWizard: Account creation failed', { error: err });
            setError(err instanceof Error ? err.message : 'Failed to create account');
        } finally {
            setIsSubmitting(false);
        }
    }, [draft, token, logout, refreshAccounts, navigate, currentAccount]);

    // ─────────────────────────────────────────────────────────────────────────
    // Render
    // ─────────────────────────────────────────────────────────────────────────

    // Loading state
    if (authLoading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50">
                <div className="text-center">
                    <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
                    <p className="text-gray-500">Loading...</p>
                </div>
            </div>
        );
    }

    // Not authenticated
    if (!token) {
        return null;
    }

    // Step props passed to all step components
    const stepProps = {
        draft,
        setDraft,
        onNext: handleNext,
        onBack: handleBack,
        onSkip: handleSkip,
        isSubmitting
    };

    // Render current step content
    const renderStep = () => {
        switch (currentStep) {
            case ONBOARDING_STEPS.STORE:
                return <StoreStep {...stepProps} />;
            case ONBOARDING_STEPS.PLUGIN:
                return <PluginStep {...stepProps} />;
            case ONBOARDING_STEPS.EMAIL:
                return <EmailStep {...stepProps} />;
            case ONBOARDING_STEPS.ADS:
                return <AdsStep {...stepProps} />;
            case ONBOARDING_STEPS.REVIEW:
                return <ReviewStep {...stepProps} />;
            default:
                return <StoreStep {...stepProps} />;
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50">
            <div className="max-w-6xl mx-auto px-4 py-8">
                {/* Header */}
                <div className="text-center mb-8">
                    <h1 className="text-3xl font-bold text-gray-900">
                        {isAddingNew ? 'Add New Store' : 'Welcome to OverSeek'}
                    </h1>
                    <p className="text-gray-500 mt-2">
                        {isAddingNew
                            ? 'Connect another WooCommerce store to your account'
                            : "Let's get your store set up in just a few steps"
                        }
                    </p>
                </div>

                {/* Error Banner */}
                {error && (
                    <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
                        {error}
                    </div>
                )}

                {/* Main Layout */}
                <div className="flex gap-8">
                    {/* Left Sidebar - Step Indicator */}
                    <div className="hidden md:block w-64 flex-shrink-0">
                        <div className="sticky top-8 bg-white rounded-2xl shadow-lg p-6 border border-gray-100">
                            <OnboardingStepIndicator
                                currentStep={currentStep}
                                completedSteps={draft.completedSteps}
                                skippedSteps={draft.skippedSteps}
                                onStepClick={goToStep}
                            />
                        </div>
                    </div>

                    {/* Right Content - Step Form */}
                    <div className="flex-1 min-w-0">
                        <div className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
                            <div className="p-6 md:p-8">
                                {renderStep()}
                            </div>
                        </div>

                        {/* Mobile Step Indicator */}
                        <div className="md:hidden mt-6 flex justify-center gap-2">
                            {STEP_CONFIG.map((step) => {
                                const isClickable = draft.completedSteps.includes(step.id)
                                    || draft.skippedSteps.includes(step.id)
                                    || step.id === currentStep;
                                return (
                                    <button
                                        key={step.id}
                                        type="button"
                                        onClick={() => isClickable && goToStep(step.id)}
                                        className={`w-2.5 h-2.5 rounded-full transition-colors ${isClickable ? 'cursor-pointer' : 'cursor-default'} ${step.id === currentStep
                                            ? 'bg-blue-600'
                                            : draft.completedSteps.includes(step.id)
                                                ? 'bg-green-500'
                                                : draft.skippedSteps.includes(step.id)
                                                    ? 'bg-amber-400'
                                                    : 'bg-gray-300'
                                            }`}
                                        aria-label={`Go to ${step.label}`}
                                    />
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { Logger } from '../utils/logger';
import { useAuth } from '../context/AuthContext';
import { useAccount } from '../context/AccountContext';
import { Trash2, UserPlus, Shield, User, Edit2, Check, X, Settings } from 'lucide-react';
import { Link } from 'react-router-dom';
import { TeamPageSkeleton } from '../components/ui/PageSkeletons';
import { Toast, ToastType } from '../components/ui/Toast';

interface CustomRole {
    id: string;
    name: string;
    permissions: Record<string, boolean>;
}

interface Member {
    userId: string;
    role: 'OWNER' | 'ADMIN' | 'STAFF' | 'VIEWER';
    roleId: string | null;
    maxRole: CustomRole | null;
    user: {
        id: string;
        fullName: string;
        email: string;
        avatarUrl: string | null;
    };
}

const BASE_ROLES = [
    { value: 'OWNER', label: 'Owner', description: 'Full access, can transfer ownership' },
    { value: 'ADMIN', label: 'Admin', description: 'Full access, cannot transfer ownership' },
    { value: 'STAFF', label: 'Staff', description: 'Access based on custom role' },
    { value: 'VIEWER', label: 'Viewer', description: 'Read-only access' },
] as const;

/**
 * Standalone Team Management page.
 * Provides full team management including user invitation, role editing, and removal.
 */
export function TeamPage() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [members, setMembers] = useState<Member[]>([]);
    const [customRoles, setCustomRoles] = useState<CustomRole[]>([]);
    const [email, setEmail] = useState('');
    const [role, setRole] = useState<string>('STAFF');
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState('');
    const [editingUserId, setEditingUserId] = useState<string | null>(null);
    const [editValues, setEditValues] = useState<{ role: string; roleId: string | null }>({ role: 'STAFF', roleId: null });
    const [isSaving, setIsSaving] = useState(false);

    const [toastMessage, setToastMessage] = useState('');
    const [toastVisible, setToastVisible] = useState(false);
    const [toastType, setToastType] = useState<ToastType>('error');
    const showToast = useCallback((message: string, type: ToastType = 'error') => {
        setToastMessage(message); setToastType(type); setToastVisible(true);
    }, []);

    useEffect(() => {
        if (currentAccount && token) {
            fetchMembers();
            fetchCustomRoles();
        }
    }, [currentAccount, token]);

    const fetchMembers = async () => {
        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) setMembers(await res.json());
        } catch (e) {
            Logger.error('Failed to fetch members', { error: e });
        } finally {
            setIsLoading(false);
        }
    };

    const fetchCustomRoles = async () => {
        try {
            const res = await fetch('/api/roles', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'x-account-id': currentAccount?.id || ''
                }
            });
            if (res.ok) {
                const data = await res.json();
                setCustomRoles(data);
            }
        } catch (e) {
            Logger.error('Failed to fetch custom roles', { error: e });
        }
    };

    const handleInvite = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        if (!email) return;

        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                body: JSON.stringify({ email, role })
            });

            if (!res.ok) {
                let errorMessage = 'Failed to add user';
                try {
                    const data = await res.json();
                    errorMessage = data.error || errorMessage;
                } catch {
                    errorMessage = res.statusText || `Error ${res.status}`;
                }
                throw new Error(errorMessage);
            }

            setEmail('');
            fetchMembers();
            showToast('User added to team', 'success');
        } catch (err: any) {
            setError(err.message);
            showToast(err.message);
        }
    };

    const handleRemove = async (userId: string) => {
        if (!confirm('Are you sure you want to remove this member?')) return;
        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users/${userId}`, {
                method: 'DELETE',
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                fetchMembers();
                showToast('Member removed', 'success');
            } else {
                const err = await res.json().catch(() => null);
                showToast(err?.error || 'Failed to remove member');
            }
        } catch (e) {
            Logger.error('Failed to remove member', { error: e });
            showToast('Failed to remove member');
        }
    };

    const startEdit = (member: Member) => {
        setEditingUserId(member.userId);
        setEditValues({ role: member.role, roleId: member.roleId });
    };

    const cancelEdit = () => {
        setEditingUserId(null);
        setEditValues({ role: 'STAFF', roleId: null });
    };

    const saveEdit = async (userId: string) => {
        setIsSaving(true);
        try {
            const res = await fetch(`/api/accounts/${currentAccount?.id}/users/${userId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
                body: JSON.stringify({
                    role: editValues.role,
                    roleId: editValues.roleId
                })
            });

            if (!res.ok) {
                let errorMessage = 'Failed to update user';
                try {
                    const data = await res.json();
                    errorMessage = data.error || errorMessage;
                } catch {
                    errorMessage = res.statusText || `Error ${res.status}`;
                }
                throw new Error(errorMessage);
            }

            setEditingUserId(null);
            fetchMembers();
            showToast('Role updated', 'success');
        } catch (err: any) {
            showToast(err.message);
        } finally {
            setIsSaving(false);
        }
    };

    const getRoleBadgeClass = (role: string) => {
        switch (role) {
            case 'OWNER': return 'bg-purple-100 text-purple-800';
            case 'ADMIN': return 'bg-blue-100 text-blue-800';
            case 'STAFF': return 'bg-green-100 text-green-800';
            case 'VIEWER': return 'bg-gray-100 text-gray-800';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    if (isLoading) return <TeamPageSkeleton />;

    return (
        <div className="p-8 max-w-5xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Team Management</h1>
                    <p className="text-gray-500">Manage members and their access to {currentAccount?.name}</p>
                </div>
                <Link
                    to="/settings?tab=roles"
                    className="flex items-center gap-2 px-4 py-2 text-sm text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    <Settings size={16} />
                    Manage Roles
                </Link>
            </div>

            {/* Invite Card */}
            <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-xs mb-8">
                <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                    <UserPlus size={20} className="text-blue-600" />
                    Add New Member
                </h2>
                <form onSubmit={handleInvite} className="flex gap-4 items-start">
                    <div className="flex-1">
                        <input
                            type="email"
                            placeholder="Enter user email address"
                            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-hidden"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                        />
                        <p className="text-xs text-gray-500 mt-1">User must already be registered with this email.</p>
                        {error && <p className="text-xs text-red-500 mt-1 font-medium">{error}</p>}
                    </div>

                    <select
                        className="px-4 py-2 border rounded-lg bg-white"
                        value={role}
                        onChange={e => setRole(e.target.value)}
                    >
                        <option value="STAFF">Staff</option>
                        <option value="ADMIN">Admin</option>
                        <option value="VIEWER">Viewer</option>
                    </select>

                    <button type="submit" className="px-6 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition-colors">
                        Add User
                    </button>
                </form>
            </div>

            {/* Members List */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-xs overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b border-gray-200">
                        <tr>
                            <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">User</th>
                            <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Base Role</th>
                            <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">Custom Role</th>
                            <th className="px-6 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {members.map(member => {
                            const isEditing = editingUserId === member.userId;
                            const isOwner = member.role === 'OWNER';

                            return (
                                <tr key={member.userId} className="hover:bg-gray-50">
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-gray-500 overflow-hidden">
                                                {member.user.avatarUrl ? (
                                                    <img src={member.user.avatarUrl} alt="" className="w-full h-full object-cover" />
                                                ) : (
                                                    <User size={16} />
                                                )}
                                            </div>
                                            <div>
                                                <div className="font-medium text-gray-900">{member.user.fullName || 'No Name'}</div>
                                                <div className="text-sm text-gray-500">{member.user.email}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        {isEditing && !isOwner ? (
                                            <select
                                                value={editValues.role}
                                                onChange={e => setEditValues({ ...editValues, role: e.target.value })}
                                                className="px-3 py-1.5 text-sm border rounded-lg bg-white"
                                            >
                                                {BASE_ROLES.filter(r => r.value !== 'OWNER').map(r => (
                                                    <option key={r.value} value={r.value}>{r.label}</option>
                                                ))}
                                            </select>
                                        ) : (
                                            <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleBadgeClass(member.role)}`}>
                                                {isOwner && <Shield size={12} />}
                                                {member.role}
                                            </span>
                                        )}
                                    </td>
                                    <td className="px-6 py-4">
                                        {isEditing && !isOwner ? (
                                            <select
                                                value={editValues.roleId || ''}
                                                onChange={e => setEditValues({ ...editValues, roleId: e.target.value || null })}
                                                className="px-3 py-1.5 text-sm border rounded-lg bg-white"
                                            >
                                                <option value="">None</option>
                                                {customRoles.map(r => (
                                                    <option key={r.id} value={r.id}>{r.name}</option>
                                                ))}
                                            </select>
                                        ) : (
                                            member.maxRole ? (
                                                <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800">
                                                    {member.maxRole.name}
                                                </span>
                                            ) : (
                                                <span className="text-gray-400 text-sm">—</span>
                                            )
                                        )}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex items-center justify-end gap-2">
                                            {isEditing ? (
                                                <>
                                                    <button
                                                        onClick={() => saveEdit(member.userId)}
                                                        disabled={isSaving}
                                                        className="p-1.5 text-green-600 hover:bg-green-100 rounded transition-colors"
                                                        title="Save"
                                                    >
                                                        <Check size={16} />
                                                    </button>
                                                    <button
                                                        onClick={cancelEdit}
                                                        className="p-1.5 text-gray-400 hover:bg-gray-100 rounded transition-colors"
                                                        title="Cancel"
                                                    >
                                                        <X size={16} />
                                                    </button>
                                                </>
                                            ) : (
                                                <>
                                                    {!isOwner && (
                                                        <button
                                                            onClick={() => startEdit(member)}
                                                            className="p-1.5 text-blue-600 hover:bg-blue-100 rounded transition-colors"
                                                            title="Edit Role"
                                                        >
                                                            <Edit2 size={16} />
                                                        </button>
                                                    )}
                                                    {!isOwner && (
                                                        <button
                                                            onClick={() => handleRemove(member.userId)}
                                                            className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-100 rounded transition-colors"
                                                            title="Remove User"
                                                        >
                                                            <Trash2 size={16} />
                                                        </button>
                                                    )}
                                                </>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>

            {/* Custom Roles Info */}
            {customRoles.length === 0 && (
                <div className="mt-6 bg-amber-50 border border-amber-200 rounded-xl p-4">
                    <p className="text-sm text-amber-800">
                        <strong>Tip:</strong> Create custom roles in{' '}
                        <Link to="/settings?tab=roles" className="underline hover:no-underline">
                            Settings → Roles
                        </Link>{' '}
                        to define granular permissions for STAFF members.
                    </p>
                </div>
            )}

            <Toast message={toastMessage} isVisible={toastVisible} onClose={() => setToastVisible(false)} type={toastType} />
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import {
    Sparkles,
    Save,
    Loader2,
    Check,
    AlertCircle,
    ChevronDown,
    ChevronUp,
    Info
} from 'lucide-react';

interface AIPrompt {
    id: string;
    name: string;
    description: string;
    content: string;
    updatedAt: string;
}

interface PromptConfig {
    id: string;
    name: string;
    description: string;
    placeholder: string;
    helpText?: string;
}

/**
 * Defines all available AI prompt configurations.
 * Add new prompts here as needed in the future.
 */
const PROMPT_CONFIGS: PromptConfig[] = [
    {
        id: 'product_description',
