        helpText: 'Available variables: {{conversation_history}}, {{customer_details}}, {{policies}}'
    }
];


/**
 * Super Admin page for managing AI prompts across the platform.
 * Prompts are stored in the database and used by various AI features.
 */
export function AdminAIPromptsPage() {
    const { token } = useAuth();
    const [prompts, setPrompts] = useState<AIPrompt[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState<string | null>(null);
    const [formData, setFormData] = useState<Record<string, string>>({});
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [expandedPanels, setExpandedPanels] = useState<Record<string, boolean>>({});

    useEffect(() => {
        fetchPrompts();
        // Expand all panels by default
        const initialExpanded: Record<string, boolean> = {};
        PROMPT_CONFIGS.forEach(config => {
            initialExpanded[config.id] = true;
        });
        setExpandedPanels(initialExpanded);
    }, [token]);

    /**
     * Fetches all AI prompts from the server.
     */
    async function fetchPrompts() {
        try {
            const res = await fetch('/api/admin/ai-prompts', {
                headers: { Authorization: `Bearer ${token}` }
            });

            if (!res.ok) {
                // If endpoint doesn't exist yet, just use empty data
                setPrompts([]);
                initializeFormData([]);
                return;
            }

            const data = await res.json();
            setPrompts(data);
            initializeFormData(data);
        } catch (err) {
            Logger.error('Failed to fetch AI prompts:', { error: err });
            setPrompts([]);
            initializeFormData([]);
        } finally {
            setLoading(false);
        }
    }

    /**
     * Initializes form data with existing prompts or placeholders.
     */
    function initializeFormData(existingPrompts: AIPrompt[]) {
        const initial: Record<string, string> = {};
        PROMPT_CONFIGS.forEach(config => {
            const existing = existingPrompts.find(p => p.id === config.id);
            initial[config.id] = existing?.content || '';
        });
        setFormData(initial);
    }

    /**
     * Saves a single prompt to the server.
     */
    async function handleSave(promptId: string) {
        setSaving(promptId);
        setMessage(null);

        const content = formData[promptId]?.trim();
        if (!content) {
            setMessage({ type: 'error', text: 'Prompt content cannot be empty' });
            setSaving(null);
            return;
        }

        try {
            const res = await fetch(`/api/admin/ai-prompts/${promptId}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ content })
            });

            if (res.ok) {
                const config = PROMPT_CONFIGS.find(c => c.id === promptId);
                setMessage({ type: 'success', text: `${config?.name || 'Prompt'} saved successfully` });
                fetchPrompts();
            } else {
                const err = await res.json();
                setMessage({ type: 'error', text: err.error || 'Failed to save prompt' });
            }
        } catch (err) {
            setMessage({ type: 'error', text: 'Network error while saving' });
        } finally {
            setSaving(null);
        }
    }

    /**
     * Resets a prompt to its default placeholder value.
     */
    function handleResetToDefault(promptId: string) {
        const config = PROMPT_CONFIGS.find(c => c.id === promptId);
        if (config) {
            setFormData(prev => ({
                ...prev,
                [promptId]: config.placeholder
            }));
        }
    }

    /**
     * Toggles panel expansion state.
     */
    function togglePanel(promptId: string) {
        setExpandedPanels(prev => ({
            ...prev,
            [promptId]: !prev[promptId]
        }));
    }

    /**
     * Gets the last updated date for a prompt.
     */
    function getLastUpdated(promptId: string): string | null {
        const prompt = prompts.find(p => p.id === promptId);
        return prompt?.updatedAt ? new Date(prompt.updatedAt).toLocaleDateString() : null;
    }

    /**
     * Checks if a prompt has been configured.
     */
    function isConfigured(promptId: string): boolean {
        return prompts.some(p => p.id === promptId);
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="animate-spin text-gray-400" size={32} />
            </div>
        );
    }

    return (
        <div className="max-w-4xl">
            {/* Header */}
            <div className="flex items-center gap-3 mb-6">
                <Sparkles className="text-purple-600" size={28} />
                <h1 className="text-2xl font-bold text-slate-800">AI Prompts</h1>
            </div>

            <p className="text-slate-600 mb-6">
                Configure AI prompts used throughout the platform. These prompts define how AI generates
                content for various features like product descriptions, email responses, and more.
            </p>

            {/* Global Message */}
            {message && (
                <div className={`mb-6 p-4 rounded-lg flex items-center gap-2 ${message.type === 'success' ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'
                    }`}>
                    {message.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
                    {message.text}
                </div>
            )}

            {/* Prompt Panels */}
            <div className="space-y-4">
                {PROMPT_CONFIGS.map((config) => {
                    const isExpanded = expandedPanels[config.id];
                    const configured = isConfigured(config.id);
                    const lastUpdated = getLastUpdated(config.id);

                    return (
                        <div
                            key={config.id}
                            className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden"
                        >
                            {/* Panel Header - Clickable to expand/collapse */}
                            <button
                                onClick={() => togglePanel(config.id)}
                                className="w-full p-5 flex items-center justify-between bg-linear-to-r from-slate-50 to-white hover:from-slate-100 transition-colors"
                            >
                                <div className="flex items-center gap-3">
                                    <Sparkles className="text-purple-500" size={20} />
                                    <div className="text-left">
                                        <div className="flex items-center gap-2">
                                            <h3 className="font-semibold text-slate-900">{config.name}</h3>
                                            {configured && (
                                                <span className="bg-green-100 text-green-800 text-xs px-2 py-0.5 rounded-full">
                                                    Configured
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-sm text-slate-500">{config.description}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    {lastUpdated && (
                                        <span className="text-xs text-slate-400">
                                            Updated: {lastUpdated}
                                        </span>
                                    )}
                                    {isExpanded ? (
                                        <ChevronUp className="text-slate-400" size={20} />
                                    ) : (
                                        <ChevronDown className="text-slate-400" size={20} />
                                    )}
                                </div>
                            </button>

                            {/* Panel Content */}
                            {isExpanded && (
                                <div className="border-t border-slate-100">
                                    <div className="p-5 space-y-4">
                                        {/* Help Text */}
                                        {config.helpText && (
                                            <div className="flex items-start gap-2 p-3 bg-blue-50 rounded-lg text-sm text-blue-800">
                                                <Info size={16} className="mt-0.5 shrink-0" />
                                                <span>{config.helpText}</span>
                                            </div>
                                        )}

                                        {/* Prompt Textarea */}
                                        <div>
                                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                                Prompt Template
                                            </label>
                                            <textarea
                                                className="w-full p-4 border border-slate-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-purple-500 transition-shadow font-mono text-sm resize-y min-h-[200px]"
                                                placeholder={config.placeholder}
                                                value={formData[config.id] || ''}
                                                onChange={e => setFormData(prev => ({
                                                    ...prev,
                                                    [config.id]: e.target.value
                                                }))}
                                                rows={8}
                                            />
                                        </div>
                                    </div>

                                    {/* Panel Actions */}
                                    <div className="px-5 py-4 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                                        <button
                                            onClick={() => handleResetToDefault(config.id)}
                                            className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors text-sm"
                                        >
                                            Reset to Default
                                        </button>
                                        <button
                                            onClick={() => handleSave(config.id)}
                                            disabled={saving === config.id}
                                            className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 disabled:opacity-50 flex items-center gap-2 transition-colors"
                                        >
                                            {saving === config.id ? (
                                                <Loader2 className="animate-spin" size={16} />
                                            ) : (
                                                <Save size={16} />
                                            )}
                                            Save Prompt
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Footer Note */}
            <div className="mt-8 p-4 bg-amber-50 border border-amber-200 rounded-lg">
                <div className="flex items-start gap-3">
                    <AlertCircle className="text-amber-600 shrink-0 mt-0.5" size={20} />
                    <div className="text-sm text-amber-800">
                        <p className="font-medium mb-1">About AI Prompts</p>
                        <p>
                            These prompts serve as templates for AI-powered features. Use placeholders like
                            <code className="mx-1 px-1 py-0.5 bg-amber-100 rounded-sm">{'{{variable_name}}'}</code>
                            which will be replaced with actual data when the prompt is used.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useNavigate } from 'react-router-dom';
import { LogIn, X, Trash2 } from 'lucide-react';
import { cn } from '../../utils/cn';

interface Account {
    id: string;
    name: string;
    domain: string | null;
    createdAt: string;
    _count: { users: number };
    features: AccountFeature[];
    users?: { userId: string, role: string }[]; // We might need to fetch users separately or include them if needed for impersonation
}

interface AccountFeature {
    id: string;
    featureKey: string;
    isEnabled: boolean;
}

const KNOWN_FEATURES = ['META_ADS', 'GOOGLE_ADS', 'ADVANCED_REPORTS', 'AI_WRITER', 'GOLD_PRICE_CALCULATOR', 'AD_TRACKING'];

export function AdminAccountsPage() {
    const { token, login } = useAuth();
    const { currentAccount, refreshAccounts } = useAccount();
    const navigate = useNavigate();
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [loading, setLoading] = useState(true);
    const [deleteTarget, setDeleteTarget] = useState<Account | null>(null);
    const [confirmName, setConfirmName] = useState('');
    const [deleting, setDeleting] = useState(false);

    const fetchAccounts = () => {
        fetch('/api/admin/accounts', {
            headers: { Authorization: `Bearer ${token}` }
        })
            .then(res => {
                if (!res.ok) {
                    throw new Error(`Failed to fetch accounts: ${res.status}`);
                }
                return res.json();
            })
            .then(data => {
                setAccounts(data);
                setLoading(false);
            })
            .catch(err => {
                Logger.error('AdminAccountsPage fetch error:', { error: err });
                setLoading(false);
            });
    };

    useEffect(() => {
        fetchAccounts();
    }, [token]);

    const handleImpersonate = async (accountId: string) => {
        // First we need to find the OWNER of the account to impersonate
        // The /accounts endpoint includes `_count`, but maybe we should include `users` to find the owner?
        // Let's just fetch users for this account quickly
        try {
            const usersRes = await fetch(`/api/accounts/${accountId}/users`, { // This endpoint allows finding users
                headers: { Authorization: `Bearer ${token}` }
            });

            if (!usersRes.ok) {
                alert(`Failed to fetch users: ${usersRes.status}`);
                return;
            }

            const users = await usersRes.json();

            // Just pick the first element (likely owner or first staff) for demo
            // In a real app we'd let admin pick WHICH user to impersonate
            if (!users || users.length === 0) {
                alert('No users found in this account');
                return;
            }

            const targetUser = users[0].user; // Assuming structure from account.ts: include: { user: ... }

            if (!confirm(`Impersonate ${targetUser.fullName || targetUser.email}?`)) return;

            const res = await fetch('/api/admin/impersonate', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ targetUserId: targetUser.id })
            });

            if (!res.ok) {
                const errorData = await res.json().catch(() => ({ error: 'Unknown error' }));
                alert('Impersonation failed: ' + (errorData.error || res.status));
                return;
            }

            const data = await res.json();
            if (data.token) {
                // EDGE CASE FIX: Pass refresh token for silent refresh support
                login(data.token, data.user, data.refreshToken);
                navigate('/dashboard');
            } else {
                alert('Impersonation failed: ' + data.error);
            }
        } catch (e) {
            Logger.error('An error occurred', { error: e });
            alert('Failed to start impersonation');
        }
    };

    const toggleFeature = async (accountId: string, featureKey: string, currentValue: boolean) => {
        try {
            const res = await fetch(`/api/admin/accounts/${accountId}/toggle-feature`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ featureKey, isEnabled: !currentValue })
            });

            if (res.ok) {
                // Update local state
                setAccounts(prev => prev.map(acc => {
                    if (acc.id !== accountId) return acc;

                    const existingFeatureIndex = acc.features.findIndex(f => f.featureKey === featureKey);
                    const newFeatures = [...acc.features];

                    if (existingFeatureIndex >= 0) {
                        newFeatures[existingFeatureIndex].isEnabled = !currentValue;
                    } else {
                        newFeatures.push({ id: 'temp', featureKey, isEnabled: !currentValue });
                    }
                    return { ...acc, features: newFeatures };
                }));
                if (currentAccount && currentAccount.id === accountId) {
                    refreshAccounts();
                }
            }
        } catch (e) {
            Logger.error('An error occurred', { error: e });
        }
    };

    const handleDeleteAccount = async () => {
        if (!deleteTarget || confirmName !== deleteTarget.name) return;

        setDeleting(true);
        try {
            const res = await fetch(`/api/admin/accounts/${deleteTarget.id}`, {
                method: 'DELETE',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({ confirmAccountName: confirmName })
            });

            if (res.ok) {
                setAccounts(prev => prev.filter(acc => acc.id !== deleteTarget.id));
                setDeleteTarget(null);
                setConfirmName('');
            } else {
                const data = await res.json();
                alert('Delete failed: ' + data.error);
            }
        } catch (e) {
            Logger.error('An error occurred', { error: e });
            alert('Failed to delete account');
        } finally {
            setDeleting(false);
        }
    };

    if (loading) return <div>Loading accounts...</div>;

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold text-slate-800">Manage Accounts</h1>

            <div className="bg-white rounded-xl shadow-xs border border-slate-200 overflow-hidden">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-50 border-b border-slate-100 uppercase text-xs text-slate-500 font-medium">
                        <tr>
                            <th className="p-4">Account Name</th>
                            <th className="p-4">Domain</th>
                            <th className="p-4">Users</th>
                            <th className="p-4">Features</th>
                            <th className="p-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {accounts.map(account => (
                            <tr key={account.id} className="hover:bg-slate-50/50">
                                <td className="p-4 font-medium text-slate-900">{account.name}</td>
                                <td className="p-4 text-slate-500">{account.domain || '-'}</td>
                                <td className="p-4 text-slate-500">{account._count.users}</td>
                                <td className="p-4">
                                    <div className="flex gap-1 flex-wrap">
                                        {KNOWN_FEATURES.map(key => {
                                            const isEnabled = account.features.find(f => f.featureKey === key)?.isEnabled;
                                            return (
                                                <button
                                                    key={key}
                                                    onClick={() => toggleFeature(account.id, key, !!isEnabled)}
                                                    className={cn(
                                                        "px-2 py-1 rounded-sm text-xs transition-colors border",
                                                        isEnabled
                                                            ? "bg-green-50 text-green-700 border-green-200 hover:bg-green-100"
                                                            : "bg-slate-50 text-slate-400 border-slate-200 hover:bg-slate-100 hover:text-slate-600"
                                                    )}
                                                    title={`Toggle ${key}`}
                                                >
                                                    {key.split('_')[0]}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </td>
                                <td className="p-4 text-right">
                                    <div className="flex items-center justify-end gap-2">
                                        <button
                                            onClick={() => handleImpersonate(account.id)}
                                            className="inline-flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-blue-700 bg-blue-50 rounded-lg hover:bg-blue-100 transition-colors"
                                        >
                                            <LogIn size={14} />
                                            Impersonate
                                        </button>
                                        <button
                                            onClick={() => { setDeleteTarget(account); setConfirmName(''); }}
                                            className="inline-flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-red-700 bg-red-50 rounded-lg hover:bg-red-100 transition-colors"
                                        >
                                            <Trash2 size={14} />
                                            Delete
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Delete Confirmation Modal */}
            {deleteTarget && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-xs">
                    <div className="bg-white/95 backdrop-blur-md rounded-2xl shadow-2xl border border-slate-200 p-6 w-full max-w-md mx-4">
                        <h2 className="text-lg font-bold text-slate-900 mb-2">Delete Account</h2>
                        <p className="text-sm text-slate-600 mb-4">
                            This action is <span className="font-semibold text-red-600">irreversible</span>. All data associated with this account will be permanently deleted.
                        </p>
                        <p className="text-sm text-slate-700 mb-4">
                            To confirm, type the account name: <span className="font-mono font-bold text-slate-900">{deleteTarget.name}</span>
                        </p>
                        <input
                            type="text"
                            value={confirmName}
                            onChange={(e) => setConfirmName(e.target.value)}
                            placeholder="Type account name to confirm"
                            className="w-full px-4 py-2 border border-slate-300 rounded-lg text-sm focus:outline-hidden focus:ring-2 focus:ring-red-500 focus:border-transparent mb-4"
                            autoFocus
                        />
                        <div className="flex justify-end gap-3">
                            <button
                                onClick={() => { setDeleteTarget(null); setConfirmName(''); }}
                                className="px-4 py-2 text-sm font-medium text-slate-700 bg-slate-100 rounded-lg hover:bg-slate-200 transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleDeleteAccount}
                                disabled={confirmName !== deleteTarget.name || deleting}
                                className={cn(
                                    "px-4 py-2 text-sm font-medium rounded-lg transition-colors",
                                    confirmName === deleteTarget.name && !deleting
                                        ? "bg-red-600 text-white hover:bg-red-700"
                                        : "bg-slate-200 text-slate-400 cursor-not-allowed"
                                )}
                            >
                                {deleting ? 'Deleting...' : 'Confirm Delete'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import {
    Download, HardDrive, Loader2, RefreshCw, Database, FileJson,
    Trash2, RotateCcw, Save, AlertTriangle, Settings
} from 'lucide-react';
import { cn } from '../../utils/cn';

// ─── Types ──────────────────────────────────────────────────────────

interface Account {
    id: string;
    name: string;
    domain: string | null;
    _count: { users: number };
}

interface BackupPreview {
    accountId: string;
    accountName: string;
    recordCounts: Record<string, number>;
    estimatedSizeKB: number;
}

interface BackupSettings {
    isEnabled: boolean;
    frequency: 'DAILY' | 'EVERY_3_DAYS' | 'WEEKLY';
    maxBackups: number;
    lastBackupAt: string | null;
    nextBackupAt: string | null;
}

interface StoredBackup {
    id: string;
    filename: string;
    sizeBytes: number;
    recordCount: number;
    status: string;
    type: string;
    createdAt: string;
}

// ─── Utilities ──────────────────────────────────────────────────────

/**
 * Trigger a browser file-download from a fetch Response.
 * Why extracted: the same blob→anchor→click→revoke dance was duplicated
 * in handleDownloadBackup and handleDownloadStored.
 */
function downloadBlob(blob: Blob, filename: string) {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    window.URL.revokeObjectURL(url);
}

/** Parse Content-Disposition header for a filename, with fallback. */
function parseFilename(response: Response, fallback: string): string {
    const header = response.headers.get('Content-Disposition');
    if (!header) return fallback;
    const match = header.match(/filename="(.+)"/);
    return match ? match[1] : fallback;
}

// ─── useBackups Hook ────────────────────────────────────────────────

/** Encapsulates all state + data-fetching for the backups page. */
function useBackups() {
    const { token } = useAuth();

    const [accounts, setAccounts] = useState<Account[]>([]);
    const [selectedAccountId, setSelectedAccountId] = useState('');
    const [preview, setPreview] = useState<BackupPreview | null>(null);
    const [settings, setSettings] = useState<BackupSettings | null>(null);
    const [storedBackups, setStoredBackups] = useState<StoredBackup[]>([]);

    const [loading, setLoading] = useState(true);
    const [previewLoading, setPreviewLoading] = useState(false);
    const [savingBackup, setSavingBackup] = useState(false);
    const [downloading, setDownloading] = useState(false);
    const [savingSettings, setSavingSettings] = useState(false);

    const [includeAuditLogs, setIncludeAuditLogs] = useState(false);
    const [includeAnalytics, setIncludeAnalytics] = useState(false);

    /** Shared auth headers to avoid repeating `Bearer ${token}` everywhere. */
    const authHeaders = { Authorization: `Bearer ${token}` };

    // ── Fetchers ──

    const fetchAccounts = useCallback(async () => {
        try {
            const res = await fetch('/api/admin/accounts', { headers: authHeaders });
            if (!res.ok) throw new Error('Failed to fetch accounts');
            setAccounts(await res.json());
        } catch (err) {
            Logger.error('AdminBackupsPage fetch error:', { error: err });
        } finally {
            setLoading(false);
        }
    }, [token]);

    const fetchPreview = useCallback(async (accountId: string) => {
        if (!accountId) { setPreview(null); return; }
        setPreviewLoading(true);
        try {
            const res = await fetch(`/api/admin/accounts/${accountId}/backup/preview`, { headers: authHeaders });
            if (!res.ok) throw new Error('Failed to fetch preview');
            setPreview(await res.json());
        } catch (err) {
            Logger.error('Backup preview error:', { error: err });
            setPreview(null);
        } finally {
            setPreviewLoading(false);
        }
    }, [token]);

    const fetchSettings = useCallback(async (accountId: string) => {
        try {
            const res = await fetch(`/api/admin/accounts/${accountId}/backup/settings`, { headers: authHeaders });
            if (res.ok) setSettings(await res.json());
        } catch (err) {
            Logger.error('Settings fetch error:', { error: err });
        }
    }, [token]);

    const fetchStoredBackups = useCallback(async (accountId: string) => {
        try {
            const res = await fetch(`/api/admin/accounts/${accountId}/backups`, { headers: authHeaders });
            if (res.ok) setStoredBackups(await res.json());
        } catch (err) {
            Logger.error('Stored backups fetch error:', { error: err });
        }
    }, [token]);

    // ── Actions ──

    const handleAccountChange = useCallback((accountId: string) => {
        setSelectedAccountId(accountId);
        setStoredBackups([]);
        setSettings(null);
        if (accountId) {
            fetchPreview(accountId);
            fetchSettings(accountId);
            fetchStoredBackups(accountId);
        } else {
            setPreview(null);
        }
    }, [fetchPreview, fetchSettings, fetchStoredBackups]);

    const handleSaveBackup = useCallback(async () => {
        if (!selectedAccountId) return;
        setSavingBackup(true);
        try {
            const res = await fetch(`/api/admin/accounts/${selectedAccountId}/backup/save`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({ includeAuditLogs, includeAnalytics })
            });
            if (!res.ok) throw new Error('Failed to save backup');
            await fetchStoredBackups(selectedAccountId);
        } catch (err: any) {
            Logger.error('Backup save error:', { error: err });
            alert('Backup failed: ' + err.message);
        } finally {
            setSavingBackup(false);
        }
    }, [selectedAccountId, includeAuditLogs, includeAnalytics, token, fetchStoredBackups]);

    const handleDownloadBackup = useCallback(async () => {
        if (!selectedAccountId) return;
        setDownloading(true);
        try {
            const res = await fetch(`/api/admin/accounts/${selectedAccountId}/backup`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({ includeAuditLogs, includeAnalytics })
            });
            if (!res.ok) throw new Error('Failed to generate backup');
            const fallback = `backup_${new Date().toISOString().split('T')[0]}.json`;
            downloadBlob(await res.blob(), parseFilename(res, fallback));
        } catch (err: any) {
            Logger.error('Backup download error:', { error: err });
            alert('Backup failed: ' + err.message);
        } finally {
            setDownloading(false);
        }
    }, [selectedAccountId, includeAuditLogs, includeAnalytics, token]);

    const handleDownloadStored = useCallback(async (backupId: string, filename: string) => {
        try {
            const res = await fetch(`/api/admin/backups/${backupId}/download`, { headers: authHeaders });
            if (!res.ok) throw new Error('Failed to download');
            downloadBlob(await res.blob(), filename);
        } catch (err) {
            Logger.error('Download error:', { error: err });
        }
    }, [token]);

    const handleDeleteBackup = useCallback(async (backupId: string) => {
        if (!confirm('Delete this backup?')) return;
        try {
            const res = await fetch(`/api/admin/backups/${backupId}`, {
                method: 'DELETE',
                headers: authHeaders
            });
            if (res.ok) setStoredBackups(prev => prev.filter(b => b.id !== backupId));
        } catch (err) {
            Logger.error('Delete backup error:', { error: err });
        }
    }, [token]);

    const handleUpdateSettings = useCallback(async (updates: Partial<BackupSettings>) => {
        if (!selectedAccountId) return;
        setSavingSettings(true);
        try {
            const res = await fetch(`/api/admin/accounts/${selectedAccountId}/backup/settings`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify(updates)
            });
            if (res.ok) setSettings(await res.json());
        } catch (err) {
            Logger.error('Settings update error:', { error: err });
        } finally {
            setSavingSettings(false);
        }
    }, [selectedAccountId, token]);

    const handleRestore = useCallback(async (backupId: string, confirmName: string) => {
        try {
            const res = await fetch(`/api/admin/backups/${backupId}/restore`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({ confirmAccountName: confirmName })
            });
            const data = await res.json();
            if (res.ok) {
                alert(`Restored: ${data.restoredTables.join(', ')}`);
                return true;
            }
            alert('Restore failed: ' + data.error);
            return false;
        } catch (err: any) {
            alert('Restore failed: ' + err.message);
            return false;
        }
    }, [token]);

    useEffect(() => { fetchAccounts(); }, [fetchAccounts]);

    return {
        accounts, selectedAccountId, preview, settings, storedBackups,
        loading, previewLoading, savingBackup, downloading, savingSettings,
        includeAuditLogs, setIncludeAuditLogs, includeAnalytics, setIncludeAnalytics,
        handleAccountChange, handleSaveBackup, handleDownloadBackup,
        handleDownloadStored, handleDeleteBackup, handleUpdateSettings, handleRestore,
        fetchPreview,
    };
}

// ─── RestoreModal ───────────────────────────────────────────────────

interface RestoreModalProps {
    backup: StoredBackup;
    accountName: string;
    onClose: () => void;
    onRestore: (backupId: string, confirmName: string) => Promise<boolean>;
}

/** Dangerous-action confirmation modal for restoring a backup. */
function RestoreModal({ backup, accountName, onClose, onRestore }: RestoreModalProps) {
    const [confirmName, setConfirmName] = useState('');
    const [restoring, setRestoring] = useState(false);

    const handleConfirm = async () => {
        setRestoring(true);
        const ok = await onRestore(backup.id, confirmName);
        setRestoring(false);
        if (ok) onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-xs">
            <div className="bg-white/95 backdrop-blur-md rounded-2xl shadow-2xl border border-slate-200 p-6 w-full max-w-md mx-4">
                <div className="flex items-center gap-3 text-amber-600 mb-4">
                    <AlertTriangle className="w-6 h-6" />
                    <h2 className="text-lg font-bold text-slate-900">Restore Backup</h2>
                </div>
                <p className="text-sm text-slate-600 mb-3">
                    This will <strong className="text-red-600">replace existing data</strong> with the backup from:
                </p>
                <p className="text-sm font-mono bg-slate-100 rounded px-3 py-2 mb-4">
                    {new Date(backup.createdAt).toLocaleString()}
                </p>
                <p className="text-sm text-slate-700 mb-4">
                    Type the account name to confirm: <strong>{accountName}</strong>
                </p>
                <input
                    type="text"
                    value={confirmName}
                    onChange={(e) => setConfirmName(e.target.value)}
                    placeholder="Type account name"
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-amber-500 mb-4"
                    autoFocus
                />
                <div className="flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 text-sm font-medium text-slate-700 bg-slate-100 rounded-lg hover:bg-slate-200"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleConfirm}
                        disabled={confirmName !== accountName || restoring}
                        className={cn(
                            "px-4 py-2 text-sm font-medium rounded-lg",
                            confirmName === accountName && !restoring
                                ? "bg-amber-600 text-white hover:bg-amber-700"
                                : "bg-slate-200 text-slate-400 cursor-not-allowed"
                        )}
                    >
                        {restoring ? 'Restoring...' : 'Confirm Restore'}
                    </button>
                </div>
            </div>
        </div>
    );
}

// ─── Page Component ─────────────────────────────────────────────────

