    Shield, Eye, EyeOff, Info, CheckCircle, AlertCircle
} from 'lucide-react';
import { PLATFORMS, type PlatformId, type FieldConfig } from './credentialsConfig';

// ─── Types ──────────────────────────────────────────────────────────

interface PlatformCredential {
    id: string;
    platform: string;
    credentials: Record<string, string>;
    notes?: string;
    updatedAt: string;
}

// ─── useCredentials Hook ────────────────────────────────────────────

/** Encapsulates all state + data-fetching for the credentials page. */
function useCredentials() {
    const { token } = useAuth();

    const [credentials, setCredentials] = useState<PlatformCredential[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState<string | null>(null);
    const [testing, setTesting] = useState<string | null>(null);
    const [formData, setFormData] = useState<Record<string, Record<string, string>>>({});
    const [notes, setNotes] = useState<Record<string, string>>({});
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [generating, setGenerating] = useState(false);
    const [revealedFields, setRevealedFields] = useState<Record<string, boolean>>({});

    /**
     * Server-sourced callback/webhook URLs keyed by callbackPath.
     * Why: window.location.origin diverges from API_URL behind a reverse proxy.
     */
    const [serverUrls, setServerUrls] = useState<Record<string, string>>({});

    const authHeaders = { Authorization: `Bearer ${token}` };

    const fetchCredentials = useCallback(async () => {
        try {
            const res = await fetch('/api/admin/platform-credentials', { headers: authHeaders });
            const data = await res.json();
            setCredentials(data);

            const initialForm: Record<string, Record<string, string>> = {};
            const initialNotes: Record<string, string> = {};

            PLATFORMS.forEach(platform => {
                initialForm[platform.id] = {};
                platform.fields.forEach(field => {
                    initialForm[platform.id][field.key] = '';
                });
                initialNotes[platform.id] = '';
            });

            data.forEach((cred: PlatformCredential) => {
                if (cred.credentials) {
                    Object.entries(cred.credentials).forEach(([key, value]) => {
                        if (initialForm[cred.platform]) {
                            initialForm[cred.platform][key] = value;
                        }
                    });
                }
                if (cred.notes) {
                    initialNotes[cred.platform] = cred.notes;
                }
            });

            setFormData(initialForm);
            setNotes(initialNotes);
        } catch (err) {
            Logger.error('An error occurred', { error: err });
        } finally {
            setLoading(false);
        }
    }, [token]);

    const fetchCallbackUrls = useCallback(async () => {
        try {
            const res = await fetch('/api/oauth/callback-urls', { headers: authHeaders });
            if (!res.ok) return;
            const data = await res.json();
            const map: Record<string, string> = {};
            if (data.google) map['/api/oauth/google/callback'] = data.google;
            if (data.metaAds) map['/api/oauth/meta/ads/callback'] = data.metaAds;
            if (data.metaMessaging) map['/api/oauth/meta/messaging/callback'] = data.metaMessaging;
            if (data.tiktok) map['/api/oauth/tiktok/callback'] = data.tiktok;
            if (data.metaWebhook) map['/api/meta-webhook'] = data.metaWebhook;
            setServerUrls(map);
        } catch {
            /* Fallback to window.location.origin via default empty map */
        }
    }, [token]);

    const handleSave = useCallback(async (platformId: string) => {
        setSaving(platformId);
        setMessage(null);
        try {
            const creds: Record<string, string> = {};
            Object.entries(formData[platformId] || {}).forEach(([key, value]) => {
                if (value.trim()) creds[key] = value.trim();
            });

            if (Object.keys(creds).length === 0) {
                setMessage({ type: 'error', text: 'Please fill in at least one credential field.' });
                return;
            }

            const res = await fetch(`/api/admin/platform-credentials/${platformId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({ credentials: creds, notes: notes[platformId] })
            });

            if (res.ok) {
                setMessage({ type: 'success', text: `${PLATFORMS.find(p => p.id === platformId)?.name} credentials saved.` });
                fetchCredentials();
            } else {
                const err = await res.json();
                setMessage({ type: 'error', text: err.error || 'Failed to save.' });
            }
        } catch {
            setMessage({ type: 'error', text: 'Network error.' });
        } finally {
            setSaving(null);
        }
    }, [formData, notes, token, fetchCredentials]);

    const handleDelete = useCallback(async (platformId: string) => {
        if (!confirm(`Delete all ${PLATFORMS.find(p => p.id === platformId)?.name} credentials? This cannot be undone.`)) return;
        try {
            const res = await fetch(`/api/admin/platform-credentials/${platformId}`, {
                method: 'DELETE',
                headers: authHeaders
            });
            if (res.ok) {
                setMessage({ type: 'success', text: 'Credentials deleted.' });
                fetchCredentials();
            }
        } catch {
            setMessage({ type: 'error', text: 'Failed to delete.' });
        }
    }, [token, fetchCredentials]);

    /** Tests SMTP connection with the saved credentials. */
    const handleTestSmtp = useCallback(async () => {
        setTesting('PLATFORM_SMTP');
        setMessage(null);
        try {
            const smtpData = formData['PLATFORM_SMTP'] || {};
            if (!smtpData.host || !smtpData.port || !smtpData.username || !smtpData.password) {
                setMessage({ type: 'error', text: 'Host, port, username, and password are required to test.' });
                return;
            }

            const res = await fetch('/api/admin/platform-smtp/test', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', ...authHeaders },
                body: JSON.stringify({
                    host: smtpData.host,
                    port: parseInt(smtpData.port),
                    username: smtpData.username,
                    password: smtpData.password,
                    secure: smtpData.secure === 'true'
                })
            });

            const result = await res.json();
            if (res.ok && result.success) {
                setMessage({ type: 'success', text: 'SMTP connection successful!' });
            } else {
                setMessage({ type: 'error', text: result.error || 'SMTP connection failed.' });
            }
        } catch {
            setMessage({ type: 'error', text: 'Network error during SMTP test.' });
        } finally {
            setTesting(null);
        }
    }, [formData, token]);

    /** Generates VAPID keys via the backend. */
    const handleGenerateVapidKeys = useCallback(async () => {
        setGenerating(true);
        setMessage(null);
        try {
            const res = await fetch('/api/admin/generate-vapid-keys', {
                method: 'POST',
                headers: authHeaders
            });

            if (!res.ok) {
                const text = await res.text();
                let errorMsg = `Server error (${res.status})`;
                try {
                    const err = JSON.parse(text);
                    errorMsg = err.error || err.message || errorMsg;
                } catch {
                    errorMsg = `${res.statusText || 'Server error'} (${res.status})`;
                }
                setMessage({ type: 'error', text: errorMsg });
                return;
            }

            const result = await res.json();
            if (result.alreadyExists) {
                setFormData(prev => ({
                    ...prev,
                    'WEB_PUSH_VAPID': { publicKey: result.publicKey, privateKey: '••••••••' }
                }));
                setMessage({ type: 'success', text: result.message || 'VAPID keys already configured.' });
            } else {
                setFormData(prev => ({
                    ...prev,
                    'WEB_PUSH_VAPID': { publicKey: result.publicKey, privateKey: '(saved securely)' }
                }));
                setMessage({ type: 'success', text: result.message || 'VAPID keys generated and saved!' });
            }
            fetchCredentials();
        } catch (err: unknown) {
            const errorMessage = err instanceof Error ? err.message : 'Network error generating keys';
            setMessage({ type: 'error', text: `Failed to generate keys: ${errorMessage}` });
        } finally {
            setGenerating(false);
        }
    }, [token, fetchCredentials]);

    const toggleReveal = useCallback((fieldKey: string) => {
        setRevealedFields(prev => ({ ...prev, [fieldKey]: !prev[fieldKey] }));
    }, []);

    const isConfigured = useCallback((platformId: string) =>
        credentials.some(c => c.platform === platformId),
        [credentials]);

    const getLastUpdated = useCallback((platformId: string) => {
        const cred = credentials.find(c => c.platform === platformId);
        if (!cred?.updatedAt) return null;
        return new Intl.DateTimeFormat('en-US', { dateStyle: 'medium', timeStyle: 'short' })
            .format(new Date(cred.updatedAt));
    }, [credentials]);

    useEffect(() => { fetchCredentials(); }, [fetchCredentials]);
    useEffect(() => { if (token) fetchCallbackUrls(); }, [fetchCallbackUrls]);

    /** Auto-dismiss success messages after 4 seconds */
    useEffect(() => {
        if (message?.type === 'success') {
            const timer = setTimeout(() => setMessage(null), 4000);
            return () => clearTimeout(timer);
        }
    }, [message]);

    return {
        loading, saving, testing, generating, message, setMessage,
        formData, setFormData, notes, setNotes,
        revealedFields, serverUrls,
        handleSave, handleDelete, handleTestSmtp, handleGenerateVapidKeys,
        toggleReveal, isConfigured, getLastUpdated,
    };
}

// ─── CredentialField ────────────────────────────────────────────────

interface CredentialFieldProps {
    field: FieldConfig;
    platformId: string;
    value: string;
    onChange: (value: string) => void;
    isRevealed: boolean;
    onToggleReveal: () => void;
    configured: boolean;
    /** Whether to style as a required field (red asterisk, solid border) */
    isRequired?: boolean;
}

/**
 * Single credential input field with optional sensitivity toggle.
 * Why extracted: the required-fields and optional-fields sections were
 * ~110 lines of copy-pasted JSX that only differed by filter predicate
 * and minor border styling.
 */
function CredentialField({
    field, value, onChange, isRevealed, onToggleReveal, configured, isRequired = false
}: CredentialFieldProps) {
    const borderClass = isRequired
        ? 'border-slate-300'
        : 'border-slate-200 bg-slate-50 focus:bg-white';

    return (
        <div>
            <label className={`flex items-center gap-1.5 text-sm font-medium mb-1.5 ${isRequired ? 'text-slate-700' : 'text-slate-600'}`}>
                {field.label}
                {isRequired && <span className="text-red-400 text-xs">*</span>}
            </label>
            <div className="relative">
                <input
                    type={field.sensitive && !isRevealed ? 'password' : 'text'}
                    className={`w-full px-3 py-2.5 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-shadow placeholder:text-slate-400 ${borderClass}`}
                    placeholder={configured ? '••••••••' : field.placeholder}
                    value={value}
                    onChange={e => onChange(e.target.value)}
                />
                {field.sensitive && (
                    <button
                        type="button"
                        onClick={onToggleReveal}
                        className="absolute right-2.5 top-1/2 -translate-y-1/2 p-1 text-slate-400 hover:text-slate-600 transition-colors"
                        title={isRevealed ? 'Hide' : 'Show'}
                    >
                        {isRevealed ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                )}
            </div>
            {field.helpText && (
                <p className="mt-1 text-xs text-slate-400 flex items-start gap-1">
                    <Info size={11} className="mt-0.5 shrink-0" />
                    {field.helpText}
                </p>
            )}
        </div>
    );
}

// ─── CopyableUrl ────────────────────────────────────────────────────

/** Copyable URL row — displays a URL with a one-click copy button. */
function CopyableUrl({ label, url, onCopied }: { label: string; url: string; onCopied: () => void }) {
    return (
        <div className="flex items-center gap-3 group">
            <span className="text-xs font-medium text-slate-500 w-32 shrink-0">{label}</span>
            <div className="flex-1 flex items-center gap-2 bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 font-mono text-xs text-slate-700 overflow-x-auto">
                {url}
            </div>
            <button
                onClick={() => { navigator.clipboard.writeText(url); onCopied(); }}
                className="p-2 rounded-lg text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-colors"
                title="Copy to clipboard"
            >
                <Copy size={14} />
            </button>
        </div>
    );
}

// ─── FieldSection ───────────────────────────────────────────────────

interface FieldSectionProps {
    fields: FieldConfig[];
    platformId: string;
    formData: Record<string, Record<string, string>>;
    setFormData: React.Dispatch<React.SetStateAction<Record<string, Record<string, string>>>>;
    revealedFields: Record<string, boolean>;
    toggleReveal: (fieldKey: string) => void;
    configured: boolean;
    isRequired: boolean;
}

/**
 * Renders a group of credential fields (required or optional).
 * Why extracted: eliminates the duplicated filter-then-map JSX block.
 */
function FieldSection({
    fields, platformId, formData, setFormData, revealedFields, toggleReveal, configured, isRequired
}: FieldSectionProps) {
    const filtered = fields.filter(f => isRequired ? f.required : !f.required);
    if (filtered.length === 0) return null;

    return (
        <div>
            <h3 className={`text-xs font-semibold uppercase tracking-wide mb-4 flex items-center gap-2 ${isRequired ? 'text-slate-500' : 'text-slate-400'}`}>
                {isRequired && <Key size={12} />}
                {isRequired ? 'Required Credentials' : 'Optional'}
            </h3>
            <div className="space-y-4">
                {filtered.map(field => {
                    const fieldId = `${platformId}.${field.key}`;
                    return (
                        <CredentialField
                            key={field.key}
                            field={field}
                            platformId={platformId}
                            value={formData[platformId]?.[field.key] || ''}
                            onChange={val => setFormData(prev => ({
                                ...prev,
                                [platformId]: { ...prev[platformId], [field.key]: val }
                            }))}
                            isRevealed={!!revealedFields[fieldId]}
                            onToggleReveal={() => toggleReveal(fieldId)}
                            configured={configured}
                            isRequired={isRequired}
                        />
                    );
                })}
            </div>
        </div>
    );
}

// ─── Page Component ─────────────────────────────────────────────────

/**
 * Super Admin page for managing platform API credentials.
 * Credentials are stored encrypted in the database.
 */
export function AdminCredentialsPage() {
    const {
        loading, saving, testing, generating, message, setMessage,
        formData, setFormData, notes, setNotes,
        revealedFields, serverUrls,
        handleSave, handleDelete, handleTestSmtp, handleGenerateVapidKeys,
        toggleReveal, isConfigured, getLastUpdated,
    } = useCredentials();

    const [activeTab, setActiveTab] = useState<PlatformId>('PLATFORM_SMTP');

    if (loading) {
        return (
            <div className="flex items-center justify-center py-20">
                <Loader2 className="animate-spin text-slate-400" size={28} />
            </div>
        );
    }

    const currentPlatform = PLATFORMS.find(p => p.id === activeTab)!;
    const configured = isConfigured(currentPlatform.id);
    const lastUpdated = getLastUpdated(currentPlatform.id);
    const configuredCount = PLATFORMS.filter(p => isConfigured(p.id)).length;

    return (
        <div className="max-w-4xl">
            {/* ── Page Header ── */}
            <div className="mb-8">
                <div className="flex items-center gap-3 mb-2">
                    <div className="p-2 bg-slate-100 rounded-lg">
                        <Shield className="text-slate-600" size={22} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900">Platform Credentials</h1>
                        <p className="text-sm text-slate-500 mt-0.5">
                            {configuredCount}/{PLATFORMS.length} platforms configured
                        </p>
                    </div>
                </div>
            </div>

            {/* ── Toast Message ── */}
            {message && (
                <div
                    className={`mb-6 px-4 py-3 rounded-lg flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2 duration-200
                        ${message.type === 'success'
                            ? 'bg-emerald-50 text-emerald-800 border border-emerald-200'
                            : 'bg-red-50 text-red-800 border border-red-200'
                        }`}
                >
                    {message.type === 'success' ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
                    {message.text}
                </div>
            )}

            {/* ── Platform Sidebar + Content Layout ── */}
            <div className="flex gap-6">
                {/* Left Sidebar — Platform List */}
                <div className="w-56 shrink-0 space-y-1">
                    {PLATFORMS.map((platform) => {
                        const Icon = platform.icon;
                        const isActive = activeTab === platform.id;
                        const done = isConfigured(platform.id);

                        return (
                            <button
                                key={platform.id}
                                onClick={() => { setActiveTab(platform.id as PlatformId); setMessage(null); }}
                                className={`
                                    w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-left text-sm font-medium transition-all
                                    ${isActive
                                        ? 'bg-blue-50 text-blue-700 shadow-sm ring-1 ring-blue-200'
                                        : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'
                                    }
                                `}
                            >
                                <div className={`p-1.5 rounded-md ${isActive ? platform.iconColor : 'bg-slate-200'}`}>
                                    <Icon size={14} className="text-white" />
                                </div>
                                <span className="flex-1 truncate">{platform.name}</span>
                                {done && <CheckCircle size={14} className="text-emerald-500 shrink-0" />}
                            </button>
                        );
                    })}
                </div>

                {/* Right Content — Active Platform */}
                <div className="flex-1 min-w-0">
                    <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">

                        {/* ── Platform Header ── */}
                        <div className="px-6 py-5 border-b border-slate-100">
                            <div className="flex items-start justify-between">
                                <div className="flex items-center gap-3">
                                    <div className={`p-2.5 rounded-xl ${currentPlatform.iconColor}`}>
                                        <currentPlatform.icon size={20} className="text-white" />
                                    </div>
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <h2 className="text-lg font-semibold text-slate-900">{currentPlatform.name}</h2>
                                            {configured ? (
                                                <span className="inline-flex items-center gap-1 bg-emerald-50 text-emerald-700 text-xs font-medium px-2 py-0.5 rounded-full border border-emerald-200">
                                                    <CheckCircle size={10} /> Active
                                                </span>
                                            ) : (
                                                <span className="inline-flex items-center gap-1 bg-slate-100 text-slate-500 text-xs font-medium px-2 py-0.5 rounded-full">
                                                    Not configured
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-sm text-slate-500 mt-0.5">{currentPlatform.description}</p>
                                        {lastUpdated && (
                                            <p className="text-xs text-slate-400 mt-1">Last updated {lastUpdated}</p>
                                        )}
                                    </div>
                                </div>
                                {currentPlatform.docsUrl && (
                                    <a
                                        href={currentPlatform.docsUrl}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="flex items-center gap-1.5 text-xs font-medium text-blue-600 hover:text-blue-700 bg-blue-50 hover:bg-blue-100 px-3 py-1.5 rounded-lg transition-colors shrink-0"
                                    >
                                        <ExternalLink size={12} />
                                        {currentPlatform.docsLabel || 'Developer Console'}
                                    </a>
                                )}
                            </div>
                        </div>

                        {/* ── URL Configuration Section ── */}
                        {(currentPlatform.callbackPath || currentPlatform.webhookPath) && (
                            <div className="px-6 py-4 bg-slate-50 border-b border-slate-100">
                                <div className="flex items-center gap-2 mb-3">
                                    <Link size={14} className="text-slate-500" />
                                    <span className="text-xs font-semibold text-slate-600 uppercase tracking-wide">Required URLs</span>
                                </div>
                                <p className="text-xs text-slate-500 mb-3">
                                    Copy these URLs into your{' '}
                                    <span className="font-medium text-slate-700">
                                        {currentPlatform.docsLabel || 'developer console'}
                                    </span>.
                                </p>
                                <div className="space-y-2">
                                    {currentPlatform.callbackPath && (
                                        <CopyableUrl
                                            label={currentPlatform.id === 'META_MESSAGING' ? 'OAuth Redirect' : 'Callback URL'}
                                            url={serverUrls[currentPlatform.callbackPath] || `${window.location.origin}${currentPlatform.callbackPath}`}
                                            onCopied={() => setMessage({ type: 'success', text: 'Copied to clipboard!' })}
                                        />
                                    )}
                                    {currentPlatform.webhookPath && (
                                        <CopyableUrl
                                            label="Webhook URL"
                                            url={serverUrls[currentPlatform.webhookPath] || `${window.location.origin}${currentPlatform.webhookPath}`}
                                            onCopied={() => setMessage({ type: 'success', text: 'Copied to clipboard!' })}
                                        />
                                    )}
                                </div>
                            </div>
                        )}

                        {/* ── Credential Fields ── */}
                        <div className="px-6 py-5 space-y-5">
                            <FieldSection
                                fields={currentPlatform.fields}
                                platformId={currentPlatform.id}
                                formData={formData}
                                setFormData={setFormData}
                                revealedFields={revealedFields}
                                toggleReveal={toggleReveal}
                                configured={configured}
                                isRequired={true}
                            />
                            <FieldSection
                                fields={currentPlatform.fields}
                                platformId={currentPlatform.id}
                                formData={formData}
                                setFormData={setFormData}
                                revealedFields={revealedFields}
                                toggleReveal={toggleReveal}
                                configured={configured}
                                isRequired={false}
                            />

                            {/* Notes */}
                            <div className="pt-2 border-t border-slate-100">
                                <label className="text-sm font-medium text-slate-500 mb-1.5 block">Notes</label>
                                <input
                                    type="text"
                                    className="w-full px-3 py-2.5 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-shadow placeholder:text-slate-400 bg-slate-50 focus:bg-white"
                                    placeholder="e.g., Production credentials from Google Cloud Console"
                                    value={notes[currentPlatform.id] || ''}
                                    onChange={e => setNotes(prev => ({ ...prev, [currentPlatform.id]: e.target.value }))}
                                />
                            </div>
                        </div>

                        {/* ── Actions Footer ── */}
                        <div className="px-6 py-4 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
                            <div className="flex items-center gap-2">
                                {configured && (
                                    <button
                                        onClick={() => handleDelete(currentPlatform.id)}
                                        className="px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg flex items-center gap-2 transition-colors"
                                    >
                                        <Trash2 size={14} />
                                        Remove Credentials
                                    </button>
                                )}
                            </div>
                            <div className="flex items-center gap-2">
                                {currentPlatform.testable && (
                                    <button
                                        onClick={() => handleTestSmtp()}
                                        disabled={testing === currentPlatform.id}
                                        className="px-4 py-2 text-sm text-amber-700 border border-amber-300 bg-amber-50 hover:bg-amber-100 rounded-lg flex items-center gap-2 transition-colors disabled:opacity-50"
                                    >
                                        {testing === currentPlatform.id ? <Loader2 className="animate-spin" size={14} /> : <Zap size={14} />}
                                        Test Connection
                                    </button>
                                )}
                                {currentPlatform.id === 'WEB_PUSH_VAPID' && (
                                    <button
                                        onClick={handleGenerateVapidKeys}
                                        disabled={generating}
                                        className="px-4 py-2 text-sm text-violet-700 border border-violet-300 bg-violet-50 hover:bg-violet-100 rounded-lg flex items-center gap-2 transition-colors disabled:opacity-50"
                                    >
                                        {generating ? <Loader2 className="animate-spin" size={14} /> : <Zap size={14} />}
                                        Generate Keys
                                    </button>
                                )}
                                <button
                                    onClick={() => handleSave(currentPlatform.id)}
                                    disabled={saving === currentPlatform.id}
                                    className="px-5 py-2 text-sm bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center gap-2 transition-colors font-medium shadow-sm"
                                >
                                    {saving === currentPlatform.id ? <Loader2 className="animate-spin" size={14} /> : <Save size={14} />}
                                    Save Credentials
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { Users, Server, Activity, AlertTriangle, Database, Trash2, CheckCircle, XCircle, AlertCircle, RefreshCw } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

interface AdminStats {
    totalAccounts: number;
    totalUsers: number;
    activeSyncs: number;
    failedSyncs24h: number;
}

interface ServiceHealth {
    status: 'healthy' | 'degraded' | 'unhealthy';
    latencyMs?: number;
    details?: string;
}

interface SystemHealth {
    status: 'healthy' | 'degraded' | 'unhealthy';
    timestamp: string;
    version: { app: string; node: string; uptimeFormatted: string };
    services: Record<string, ServiceHealth>;
    queues: Record<string, { waiting: number; active: number; completed: number; failed: number }>;
    webhooks: { failed24h: number; processed24h: number; received24h: number };
}

export function AdminDashboard() {
    const { token } = useAuth();
    const [stats, setStats] = useState<AdminStats | null>(null);
    const [health, setHealth] = useState<SystemHealth | null>(null);
    const [loading, setLoading] = useState(true);
    const [clearing, setClearing] = useState(false);

    const fetchData = async () => {
        try {
            const [statsRes, healthRes] = await Promise.all([
                fetch('/api/admin/stats', { headers: { Authorization: `Bearer ${token}` } }),
                fetch('/api/admin/system-health', { headers: { Authorization: `Bearer ${token}` } })
            ]);

            if (statsRes.ok) setStats(await statsRes.json());
            if (healthRes.ok) setHealth(await healthRes.json());
        } catch (err) {
            Logger.error('AdminDashboard fetch error:', { error: err });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [token]);

    const handleClearFailedSyncs = async () => {
        if (!confirm(`Are you sure you want to delete all ${stats?.failedSyncs24h || 0} failed sync logs?\n\nThis action cannot be undone.`)) {
            return;
        }

        setClearing(true);
        try {
            const res = await fetch('/api/admin/sync-logs/failed', {
                method: 'DELETE',
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const result = await res.json();
                alert(`Successfully cleared ${result.deleted} failed sync logs.`);
                fetchData(); // Refresh stats
            } else {
                alert('Failed to clear sync logs');
            }
        } catch (err) {
            Logger.error('Clear failed syncs error:', { error: err });
            alert('Failed to clear sync logs');
        } finally {
            setClearing(false);
        }
    };

    const StatCard = ({ title, value, icon: Icon, color, action }: any) => (
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-xs">
            <div className="flex justify-between items-start">
                <div>
                    <p className="text-sm font-medium text-slate-500">{title}</p>
                    <h3 className="text-3xl font-bold mt-2 text-slate-900">{value}</h3>
                </div>
                <div className={`p-3 rounded-lg ${color}`}>
                    <Icon className="text-white" size={24} />
                </div>
            </div>
            {action && <div className="mt-4">{action}</div>}
        </div>
    );

    const StatusIcon = ({ status }: { status: string }) => {
        if (status === 'healthy') return <CheckCircle className="text-emerald-500" size={18} />;
        if (status === 'degraded') return <AlertCircle className="text-amber-500" size={18} />;
        return <XCircle className="text-rose-500" size={18} />;
    };

    if (loading) return <div className="p-6">Loading admin dashboard...</div>;

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-slate-800">System Overview</h1>
                <button
                    onClick={() => { setLoading(true); fetchData(); }}
                    className="flex items-center gap-2 px-3 py-2 text-sm text-slate-600 hover:text-slate-800 hover:bg-slate-100 rounded-lg transition-colors"
                >
                    <RefreshCw size={16} />
                    Refresh
                </button>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard
                    title="Total Accounts"
                    value={stats?.totalAccounts || 0}
                    icon={Server}
                    color="bg-blue-600"
                />
                <StatCard
                    title="Total Users"
                    value={stats?.totalUsers || 0}
                    icon={Users}
                    color="bg-emerald-600"
                />
                <StatCard
                    title="Active Syncs"
                    value={stats?.activeSyncs || 0}
                    icon={Activity}
                    color="bg-indigo-600"
                />
                <StatCard
                    title="Failed Syncs (24h)"
                    value={stats?.failedSyncs24h || 0}
                    icon={AlertTriangle}
                    color="bg-rose-600"
                    action={
                        (stats?.failedSyncs24h || 0) > 0 && (
                            <button
                                onClick={handleClearFailedSyncs}
                                disabled={clearing}
                                className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-rose-600 hover:text-rose-700 hover:bg-rose-50 border border-rose-200 rounded-lg transition-colors disabled:opacity-50"
                            >
                                <Trash2 size={14} />
                                {clearing ? 'Clearing...' : 'Clear All'}
                            </button>
                        )
                    }
                />
            </div>

            {/* System Health Panel */}
            {health && (
                <div className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Database className="text-slate-400" size={20} />
                            <h2 className="text-lg font-semibold text-slate-800">System Health</h2>
                        </div>
                        <div className="flex items-center gap-2">
                            <StatusIcon status={health.status} />
                            <span className={`text-sm font-medium capitalize ${health.status === 'healthy' ? 'text-emerald-600' :
                                    health.status === 'degraded' ? 'text-amber-600' : 'text-rose-600'
                                }`}>
                                {health.status}
                            </span>
                            <span className="text-xs text-slate-400 ml-2">
                                v{health.version.app} • Up {health.version.uptimeFormatted}
                            </span>
                        </div>
                    </div>

                    <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {/* Services */}
                        {Object.entries(health.services).map(([name, service]) => (
                            <div key={name} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg">
                                <div className="flex items-center gap-2">
                                    <StatusIcon status={service.status} />
                                    <span className="text-sm font-medium text-slate-700 capitalize">{name}</span>
                                </div>
                                <span className="text-xs text-slate-500">
                                    {service.latencyMs !== undefined ? `${service.latencyMs}ms` : service.details || '—'}
                                </span>
                            </div>
                        ))}
                    </div>

                    {/* Queue Stats */}
                    <div className="px-6 pb-6">
                        <h3 className="text-sm font-medium text-slate-500 mb-3">Queue Statistics</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
                            {Object.entries(health.queues).map(([name, q]) => (
                                <div key={name} className="p-3 bg-slate-50 rounded-lg">
                                    <div className="text-xs font-medium text-slate-600 capitalize mb-1">{name.replace(/_/g, ' ')}</div>
                                    <div className="flex items-center gap-2 text-xs">
                                        <span className="text-amber-600">{q.waiting}w</span>
                                        <span className="text-blue-600">{q.active}a</span>
                                        {q.failed > 0 && <span className="text-rose-600">{q.failed}f</span>}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Webhooks */}
                    <div className="px-6 pb-6 border-t border-slate-100 pt-4">
                        <h3 className="text-sm font-medium text-slate-500 mb-3">Webhooks (24h)</h3>
                        <div className="flex items-center gap-6 text-sm">
                            <span className="text-slate-600">Received: <strong>{health.webhooks.received24h}</strong></span>
                            <span className="text-emerald-600">Processed: <strong>{health.webhooks.processed24h}</strong></span>
                            {health.webhooks.failed24h > 0 && (
                                <span className="text-rose-600">Failed: <strong>{health.webhooks.failed24h}</strong></span>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { CheckCircle, XCircle, Clock, RotateCw } from 'lucide-react';
import { cn } from '../../utils/cn';
import { Pagination } from '../../components/ui/Pagination';

interface SyncLog {
    id: string;
    accountId: string;
    account: { name: string };
    entityType: string;
    status: string;
    itemsProcessed: number;
    errorMessage: string | null;
    startedAt: string;
    completedAt: string | null;
}

export function AdminLogsPage() {
    const { token } = useAuth();
    const [logs, setLogs] = useState<SyncLog[]>([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(20);
    const [totalPages, setTotalPages] = useState(1);

    const fetchLogs = (currentPage: number, currentLimit: number) => {
        setLoading(true);
        fetch(`/api/admin/logs?page=${currentPage}&limit=${currentLimit}`, {
            headers: { Authorization: `Bearer ${token}` }
        })
            .then(res => res.json())
            .then(data => {
                setLogs(data.logs);
                setTotalPages(data.totalPages);
                setPage(data.page);
                setLoading(false);
            })
            .catch(err => {
                Logger.error('An error occurred', { error: err });
                setLoading(false);
            });
    };

    useEffect(() => {
        fetchLogs(page, limit);
    }, [token, page, limit]); // Re-fetch when page changes

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-2xl font-bold text-slate-800">System Logs</h1>
                <button
                    onClick={() => fetchLogs(page, limit)}
                    className="p-2 text-slate-500 hover:text-blue-600 transition-colors"
                >
                    <RotateCw size={20} />
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-xs border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-slate-50 border-b border-slate-100 uppercase text-xs text-slate-500 font-medium">
                            <tr>
                                <th className="p-4">Status</th>
                                <th className="p-4">Account</th>
                                <th className="p-4">Entity</th>
                                <th className="p-4">Time</th>
                                <th className="p-4">Details</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {logs.map(log => (
                                <tr key={log.id} className="hover:bg-slate-50/50">
                                    <td className="p-4">
                                        {log.status === 'SUCCESS' && <div className="flex items-center gap-2 text-green-600"><CheckCircle size={16} /> Success</div>}
                                        {log.status === 'FAILED' && <div className="flex items-center gap-2 text-red-600"><XCircle size={16} /> Failed</div>}
                                        {log.status === 'IN_PROGRESS' && <div className="flex items-center gap-2 text-blue-600"><Clock size={16} /> Running</div>}
                                    </td>
                                    <td className="p-4 font-medium text-slate-900">{log.account?.name || 'Unknown'}</td>
                                    <td className="p-4 capitalize">{log.entityType}</td>
                                    <td className="p-4 text-slate-500">
                                        {new Date(log.startedAt).toLocaleString()}
                                    </td>
                                    <td className="p-4">
                                        {log.status === 'FAILED' ? (
                                            <span className="text-red-500 max-w-xs truncate block" title={log.errorMessage || ''}>
                                                {log.errorMessage}
                                            </span>
                                        ) : (
                                            <span className="text-slate-500">{log.itemsProcessed} items</span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                            {!loading && logs.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="p-8 text-center text-slate-400">No logs found</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                <Pagination
                    currentPage={page}
                    totalPages={totalPages}
                    onPageChange={setPage}
                    itemsPerPage={limit}
                    onItemsPerPageChange={(newLimit) => {
                        setLimit(newLimit);
                        setPage(1); // Reset to first page when limit changes
                    }}
                    allowItemsPerPage={true}
                />
            </div>
        </div>
    );
}

import { useEffect, useState, useRef } from 'react';
import { Logger } from '../../utils/logger';
import { useAuth } from '../../context/AuthContext';
import { Settings, Upload, Check, AlertCircle, Loader2, Globe, HardDrive, RefreshCw, UserPlus, ToggleLeft, ToggleRight } from 'lucide-react';

interface DatabaseInfo {
    source: 'manual' | 'auto';
    installed: boolean;
    size: number;
    sizeFormatted: string;
    buildDate: string;
    type: string;
}

interface GeoIPStatus {
    databases: DatabaseInfo[];
}

interface PlatformSettings {
    registrationEnabled: boolean;
    updatedAt: string;
}

/**
 * Super Admin settings page for system configuration.
 * Currently includes GeoIP database management.
 */
export function AdminSettingsPage() {
    const { token } = useAuth();
    const [status, setStatus] = useState<GeoIPStatus | null>(null);
    const [loading, setLoading] = useState(true);
    const [uploading, setUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const [forcingUpdate, setForcingUpdate] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [dragOver, setDragOver] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Platform settings state
    const [platformSettings, setPlatformSettings] = useState<PlatformSettings | null>(null);
    const [togglingRegistration, setTogglingRegistration] = useState(false);

    const fetchStatus = async () => {
        try {
            const res = await fetch('/api/admin/geoip-status', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setStatus(data);
            }
        } catch (e) {
            Logger.error('Failed to fetch GeoIP status:', { error: e });
        } finally {
            setLoading(false);
        }
    };

    const fetchPlatformSettings = async () => {
        try {
            const res = await fetch('/api/admin/platform-settings', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.ok) {
                const data = await res.json();
                setPlatformSettings(data);
            }
        } catch (e) {
            Logger.error('Failed to fetch platform settings:', { error: e });
        }
    };

    const handleToggleRegistration = async () => {
        if (!platformSettings) return;

        setTogglingRegistration(true);
        setMessage(null);
        try {
            const res = await fetch('/api/admin/platform-settings', {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`
                },
                body: JSON.stringify({
                    registrationEnabled: !platformSettings.registrationEnabled
                })
            });
            const data = await res.json();
            if (res.ok) {
                setPlatformSettings(data);
                setMessage({
                    type: 'success',
                    text: data.registrationEnabled
                        ? 'New user registrations enabled'
                        : 'New user registrations disabled'
                });
            } else {
                setMessage({ type: 'error', text: data.error || 'Failed to update settings' });
            }
        } catch (e) {
            setMessage({ type: 'error', text: 'Network request failed' });
        } finally {
            setTogglingRegistration(false);
        }
    };

    useEffect(() => {
        fetchStatus();
        fetchPlatformSettings();
    }, [token]);

    const handleForceUpdate = async () => {
        setForcingUpdate(true);
        setMessage(null);
        try {
            const res = await fetch('/api/admin/geoip-force-update', {
                method: 'POST',
                headers: { Authorization: `Bearer ${token}` }
            });
            const data = await res.json();
            if (res.ok) {
                setMessage({ type: 'success', text: 'Auto-update completed successfully.' });
                fetchStatus();
            } else {
                setMessage({ type: 'error', text: data.error || 'Update failed' });
            }
        } catch (e) {
            setMessage({ type: 'error', text: 'Network request failed' });
        } finally {
            setForcingUpdate(false);
        }
    };

    const handleUpload = async (file: File) => {
        if (!file.name.endsWith('.mmdb')) {
            setMessage({ type: 'error', text: 'Only .mmdb files are accepted' });
            return;
        }

        setUploading(true);
        setUploadProgress(0);
        setMessage(null);

        const formData = new FormData();
        formData.append('database', file);

        try {
            const xhr = new XMLHttpRequest();

            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable) {
                    setUploadProgress(Math.round((e.loaded / e.total) * 100));
                }
            });

            await new Promise<void>((resolve, reject) => {
                xhr.onload = () => {
                    if (xhr.status >= 200 && xhr.status < 300) {
                        const data = JSON.parse(xhr.responseText);
                        setMessage({ type: 'success', text: data.message || 'Database uploaded successfully!' });
                        fetchStatus();
                        resolve();
                    } else {
                        const error = JSON.parse(xhr.responseText);
                        reject(new Error(error.error || 'Upload failed'));
                    }
                };
                xhr.onerror = () => reject(new Error('Network error'));

                xhr.open('POST', '/api/admin/upload-geoip-db');
                xhr.setRequestHeader('Authorization', `Bearer ${token}`);
                xhr.send(formData);
            });
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message || 'Upload failed' });
        } finally {
            setUploading(false);
            setUploadProgress(0);
        }
    };

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            handleUpload(file);
        }
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(false);
        const file = e.dataTransfer.files[0];
        if (file) {
            handleUpload(file);
        }
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        setDragOver(true);
    };

    const handleDragLeave = () => {
        setDragOver(false);
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="animate-spin text-slate-400" size={32} />
            </div>
        );
    }

    const manualDB = status?.databases.find(d => d.source === 'manual');
    const autoDB = status?.databases.find(d => d.source === 'auto');

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                <Settings size={28} />
                System Settings
            </h1>

            {/* Platform Settings Section */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden">
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50">
                    <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                        <UserPlus size={20} className="text-purple-600" />
                        User Registration
                    </h2>
                    <p className="text-sm text-slate-500 mt-1">
                        Control whether new users can register accounts on the platform.
                    </p>
                </div>

                <div className="p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <h3 className="font-medium text-slate-800">Allow New Registrations</h3>
                            <p className="text-sm text-slate-500 mt-1">
                                {platformSettings?.registrationEnabled
                                    ? 'New users can create accounts'
                                    : 'Only existing users can access the platform'}
                            </p>
                        </div>
                        <button
                            onClick={handleToggleRegistration}
                            disabled={togglingRegistration || !platformSettings}
                            className={`
                                relative inline-flex h-8 w-14 items-center rounded-full transition-colors
                                ${platformSettings?.registrationEnabled
                                    ? 'bg-emerald-500 hover:bg-emerald-600'
                                    : 'bg-slate-300 hover:bg-slate-400'}
                                ${togglingRegistration ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
                            `}
                        >
                            {togglingRegistration ? (
                                <Loader2 className="absolute left-1/2 -translate-x-1/2 animate-spin text-white" size={16} />
                            ) : (
                                <span
                                    className={`
                                        inline-block h-6 w-6 transform rounded-full bg-white shadow-sm transition-transform
                                        ${platformSettings?.registrationEnabled ? 'translate-x-7' : 'translate-x-1'}
                                    `}
                                />
                            )}
                        </button>
                    </div>

                    {platformSettings && !platformSettings.registrationEnabled && (
                        <div className="mt-4 p-3 bg-amber-50 border border-amber-200 rounded-lg flex items-start gap-3">
                            <AlertCircle className="text-amber-600 flex-shrink-0 mt-0.5" size={18} />
                            <div className="text-sm text-amber-800">
                                <strong>Registration is disabled.</strong> New users will not be able to create accounts.
                                Existing users and team members added manually can still log in.
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* GeoIP Database Section */}
            <div className="bg-white rounded-xl border border-slate-200 shadow-xs overflow-hidden">
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
                    <div>
                        <h2 className="text-lg font-semibold text-slate-800 flex items-center gap-2">
                            <Globe size={20} className="text-blue-600" />
                            GeoIP Databases
                        </h2>
                        <p className="text-sm text-slate-500 mt-1">
                            Manage IP geolocation providers. The system automatically uses the newest database.
                        </p>
                    </div>
                    <button
                        onClick={fetchStatus}
                        className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
                        title="Refresh status"
                    >
                        <RefreshCw size={18} />
                    </button>
                </div>

                <div className="p-6 space-y-6">
                    {/* Auto DB Card */}
                    <div className="border border-slate-200 rounded-lg p-4">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                    DB-IP Lite (Auto-Update)
                                    {autoDB?.installed && <span className="text-xs bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full">Automated</span>}
                                </h3>
                                <p className="text-sm text-slate-500">Automatically fetches monthly updates from db-ip.com</p>
                            </div>
                            <button
                                onClick={handleForceUpdate}
                                disabled={forcingUpdate}
                                className="text-sm border border-slate-300 px-3 py-1.5 rounded-md hover:bg-slate-50 flex items-center gap-2 disabled:opacity-50"
                            >
                                {forcingUpdate ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}
                                Force Update
                            </button>
                        </div>

                        {autoDB ? (
                            <div className="bg-slate-50 rounded-md p-3 flex items-center gap-4">
                                <div className="p-2 bg-emerald-100 rounded-full">
                                    <Check className="text-emerald-600" size={16} />
                                </div>
                                <div className="text-sm text-slate-600">
                                    <p className="font-medium text-slate-900">Installed</p>
                                    <p>Build Date: {new Date(autoDB.buildDate).toLocaleDateString()}</p>
                                    <p>Size: {autoDB.sizeFormatted}</p>
                                </div>
                            </div>
                        ) : (
                            <div className="bg-amber-50 rounded-md p-3 flex items-center gap-4 text-amber-800">
                                <AlertCircle size={20} />
                                <span className="text-sm">Not installed yet. Will fetch automatically or click Force Update.</span>
                            </div>
                        )}
                    </div>

                    {/* Manual DB Card */}
                    <div className="border border-slate-200 rounded-lg p-4">
                        <div className="mb-4">
                            <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                                MaxMind GeoLite2 (Manual)
                                {manualDB?.installed && <span className="text-xs bg-purple-100 text-purple-700 px-2 py-0.5 rounded-full">Uploaded</span>}
                            </h3>
                            <p className="text-sm text-slate-500">Manually uploaded .mmdb file</p>
                        </div>

                        {manualDB ? (
                            <div className="bg-slate-50 rounded-md p-3 flex items-center gap-4 mb-4">
                                <div className="p-2 bg-emerald-100 rounded-full">
                                    <Check className="text-emerald-600" size={16} />
                                </div>
                                <div className="text-sm text-slate-600">
                                    <p className="font-medium text-slate-900">Installed</p>
                                    <p>Build Date: {new Date(manualDB.buildDate).toLocaleDateString()}</p>
                                    <p>Size: {manualDB.sizeFormatted}</p>
                                </div>
                            </div>
                        ) : (
                            <div className="bg-slate-50 rounded-md p-3 flex items-center gap-4 mb-4 text-slate-500">
                                <div className="p-2 bg-slate-200 rounded-full">
                                    <HardDrive className="text-slate-500" size={16} />
                                </div>
                                <span className="text-sm">No custom database uploaded.</span>
                            </div>
                        )}

                        {/* Upload Dropzone */}
                        <div
                            onDrop={handleDrop}
                            onDragOver={handleDragOver}
                            onDragLeave={handleDragLeave}
                            onClick={() => fileInputRef.current?.click()}
                            className={`
                                border-2 border-dashed rounded-lg p-6 text-center cursor-pointer transition-all
                                ${dragOver ? 'border-blue-500 bg-blue-50' : 'border-slate-300 hover:border-slate-400 hover:bg-slate-50'}
                                ${uploading ? 'pointer-events-none opacity-60' : ''}
                            `}
                        >
                            <input
                                ref={fileInputRef}
                                type="file"
                                accept=".mmdb"
                                onChange={handleFileSelect}
                                className="hidden"
                            />

                            {uploading ? (
                                <div className="space-y-2">
                                    <Loader2 className="animate-spin mx-auto text-blue-600" size={24} />
                                    <p className="text-sm text-slate-600">Uploading... {uploadProgress}%</p>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center gap-2">
                                    <Upload className="text-slate-400" size={24} />
                                    <p className="text-sm font-medium text-slate-600">
                                        {manualDB ? 'Replace Manual Database' : 'Upload Manual Database'}
                                    </p>
                                    <p className="text-xs text-slate-400">
                                        Drag & drop .mmdb file
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Message */}
                    {message && (
                        <div className={`p-4 rounded-lg flex items-center gap-3 ${message.type === 'success' ? 'bg-emerald-50 text-emerald-800' : 'bg-red-50 text-red-800'}`}>
                            {message.type === 'success' ? <Check size={20} /> : <AlertCircle size={20} />}
                            {message.text}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useMemo } from 'react';
import { Logger } from '../../utils/logger';
import { useAccount } from '../../context/AccountContext';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../services/api';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/Card';
import { DateRangeFilter } from '../../components/analytics/DateRangeFilter';
import {
    BarChart3, ShoppingCart, TrendingDown, Search,
    ArrowUpRight
} from 'lucide-react';
import FunnelWidget from '../../components/widgets/FunnelWidget';
import AnalyticsStatsWidget from '../../components/widgets/AnalyticsStatsWidget';

interface AbandonmentData {
    addedToCartCount: number;
    purchasedCount: number;
    abandonedCount: number;
    abandonmentRate: number;
}

interface SearchData {
    topQueries: { query: string; count: number }[];
    totalSearches: number;
}

interface ExitData {
    topExitPages: { page: string; count: number }[];
}

export const AnalyticsOverviewPage: React.FC = () => {
    const [days, setDays] = useState(1); // Default to Today
    const { currentAccount } = useAccount();
    const { token } = useAuth();
    const [abandonment, setAbandonment] = useState<AbandonmentData | null>(null);
    const [searches, setSearches] = useState<SearchData | null>(null);
    const [exits, setExits] = useState<ExitData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            if (!currentAccount || !token) return;
            setLoading(true);
            try {
                const [abandonmentRes, searchesRes, exitsRes] = await Promise.all([
                    api.get<AbandonmentData>(`/api/tracking/abandonment?days=${days}`, token, currentAccount.id),
                    api.get<SearchData>(`/api/tracking/searches?days=${days}`, token, currentAccount.id),
                    api.get<ExitData>(`/api/tracking/exits?days=${days}`, token, currentAccount.id)
                ]);
                setAbandonment(abandonmentRes);
                setSearches(searchesRes);
                setExits(exitsRes);
            } catch (error) {
                Logger.error('Failed to fetch overview:', { error: error });
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [currentAccount, token, days]);

    /** Derive startDate/endDate from the days filter for widget props */
    const dateRange = useMemo(() => {
        const end = new Date();
        const start = new Date();
        start.setDate(end.getDate() - days);
        return {
            startDate: start.toISOString().split('T')[0],
            endDate: end.toISOString().split('T')[0]
        };
    }, [days]);

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-gray-900">Analytics Overview</h1>
                <DateRangeFilter value={days} onChange={setDays} />
            </div>

            {/* Top Row - Funnel & Stats */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <Card className="border-0 shadow-xs">
                    <CardHeader>
                        <CardTitle className="text-sm font-semibold flex items-center gap-2">
                            <TrendingDown className="w-4 h-4 text-green-500" />
                            Conversion Funnel
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="p-0">
                        <FunnelWidget dateRange={dateRange} />
                    </CardContent>
                </Card>

                <Card className="border-0 shadow-xs">
                    <CardHeader>
                        <CardTitle className="text-sm font-semibold flex items-center gap-2">
                            <BarChart3 className="w-4 h-4 text-purple-500" />
                            Audience Insights
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="p-0">
                        <AnalyticsStatsWidget dateRange={dateRange} />
                    </CardContent>
                </Card>
            </div>

            {/* Middle Row - Cart Abandonment */}
            {abandonment && (
                <Card className="border-0 shadow-xs">
                    <CardHeader>
                        <CardTitle className="text-sm font-semibold flex items-center gap-2">
                            <ShoppingCart className="w-4 h-4 text-orange-500" />
                            Cart Abandonment
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                            <div className="bg-blue-50 rounded-xl p-4 text-center">
                                <p className="text-2xl font-bold text-blue-600">{abandonment.addedToCartCount}</p>
                                <p className="text-xs text-gray-500">Added to Cart</p>
                            </div>
                            <div className="bg-green-50 rounded-xl p-4 text-center">
                                <p className="text-2xl font-bold text-green-600">{abandonment.purchasedCount}</p>
                                <p className="text-xs text-gray-500">Purchased</p>
                            </div>
                            <div className="bg-orange-50 rounded-xl p-4 text-center">
                                <p className="text-2xl font-bold text-orange-600">{abandonment.abandonedCount}</p>
                                <p className="text-xs text-gray-500">Abandoned</p>
                            </div>
                            <div className="bg-red-50 rounded-xl p-4 text-center">
                                <p className="text-2xl font-bold text-red-600">{abandonment.abandonmentRate}%</p>
                                <p className="text-xs text-gray-500">Abandonment Rate</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* Bottom Row - Searches & Exits */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {searches && (
                    <Card className="border-0 shadow-xs">
                        <CardHeader>
                            <CardTitle className="text-sm font-semibold flex items-center gap-2">
                                <Search className="w-4 h-4 text-blue-500" />
                                Top Search Terms
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            {searches.topQueries.length === 0 ? (
                                <p className="text-sm text-gray-500 italic">No search data yet</p>
                            ) : (
                                <div className="space-y-2">
                                    {searches.topQueries.slice(0, 8).map((item, i) => (
                                        <div key={item.query} className="flex justify-between text-sm py-1.5 border-b border-gray-50 last:border-0">
                                            <span className="text-gray-700">{item.query}</span>
                                            <span className="text-gray-400">{item.count}</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </CardContent>
                    </Card>
                )}

                {exits && (
                    <Card className="border-0 shadow-xs">
                        <CardHeader>
                            <CardTitle className="text-sm font-semibold flex items-center gap-2">
                                <ArrowUpRight className="w-4 h-4 text-red-500" />
                                Top Exit Pages
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            {exits.topExitPages.length === 0 ? (
                                <p className="text-sm text-gray-500 italic">No exit data yet</p>
                            ) : (
                                <div className="space-y-2">
                                    {exits.topExitPages.slice(0, 8).map((item, i) => (
                                        <div key={item.page} className="flex justify-between text-sm py-1.5 border-b border-gray-50 last:border-0">
                                            <span className="text-gray-700 truncate max-w-[250px]">{item.page}</span>
                                            <span className="text-gray-400">{item.count}</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </CardContent>
                    </Card>
                )}
            </div>
        </div>
    );
};

