                                </button>
                            ))
                        ) : (
                            <div className="px-4 py-6 text-center text-slate-400 text-sm">
                                {cannedResponses.length === 0 ? 'No canned responses yet' : 'No matches found'}
                            </div>
                        )}
                    </div>
                )}

                {/* Hidden File Input */}
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileUpload}
                    className="hidden"
                    accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.xls,.xlsx,.txt,.csv,.zip"
                />

                {/* Toolbar */}
                <div className="flex items-center gap-1 px-3 py-2 border-b border-white/10">
                    <button
                        onClick={handleGenerateAIDraft}
                        disabled={isGeneratingDraft || messages.length === 0}
                        className="p-2 rounded-full hover:bg-purple-500/20 active:bg-purple-500/30 transition-colors disabled:opacity-40"
                        title="Generate AI Draft"
                    >
                        {isGeneratingDraft ? (
                            <Loader2 size={20} className="text-purple-400 animate-spin" />
                        ) : (
                            <Sparkles size={20} className="text-purple-400" />
                        )}
                    </button>
                    <button
                        onClick={() => handleInputChange('/')}
                        className="p-2 rounded-full hover:bg-amber-500/20 active:bg-amber-500/30 transition-colors"
                        title="Canned Responses"
                    >
                        <Zap size={20} className="text-amber-400" />
                    </button>
                    <button
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isUploading}
                        className="p-2 rounded-full hover:bg-slate-600 active:bg-slate-500 transition-colors disabled:opacity-40"
                        title="Attach File"
                    >
                        {isUploading ? (
                            <Loader2 size={20} className="text-slate-400 animate-spin" />
                        ) : (
                            <Paperclip size={20} className="text-slate-400" />
                        )}
                    </button>
                </div>

                {/* Input Area */}
                <div className="flex items-end gap-2 p-3">
                    <div className="flex-1 bg-slate-700/50 rounded-2xl px-4 py-2">
                        <textarea
                            ref={inputRef}
                            value={newMessage}
                            onChange={(e) => {
                                handleInputChange(e.target.value);
                                e.target.style.height = 'auto';
                                e.target.style.height = `${Math.min(e.target.scrollHeight, 128)}px`;
                            }}
                            onKeyDown={handleKeyPress}
                            placeholder="Type a message... (/ for templates)"
                            rows={1}
                            className="w-full bg-transparent resize-none focus:outline-none text-base max-h-32 text-white placeholder-slate-400 overflow-y-auto"
                            style={{ minHeight: '24px', height: 'auto' }}
                        />
                    </div>
                    <button
                        onClick={handleSend}
                        disabled={!newMessage.trim() || sending || showCanned}
                        className={`p-3 rounded-full flex-shrink-0 transition-all ${newMessage.trim() && !sending && !showCanned
                            ? 'bg-indigo-600 text-white active:scale-95'
                            : 'bg-slate-700 text-slate-400'
                            }`}
                    >
                        {sending ? (
                            <Loader2 size={20} className="animate-spin" />
                        ) : (
                            <Send size={20} />
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Mail, Phone, MapPin, ShoppingBag, Calendar, RefreshCw, Package, ChevronRight, DollarSign } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { formatCurrency, formatDate } from '../../utils/format';
import { getStatusColor } from '../../utils/orderStatus';

interface OrderApiResponse {
    id: string;
    rawData?: {
        number?: string;
        status?: string;
        total?: string | number;
        date_created?: string;
    };
    wooId?: string;
    status?: string;
    total?: string | number;
    dateCreated?: string;
}

interface CustomerOrder {
    id: string;
    number: string;
    status: string;
    total: number;
    dateCreated: string;
}

interface CustomerDetails {
    customer: {
        id: string;
        firstName: string;
        lastName: string;
        email: string;
        totalSpent: number;
        ordersCount: number;
        dateCreated: string;
        rawData?: {
            billing?: {
                phone?: string;
                address_1?: string;
                city?: string;
                state?: string;
                postcode?: string;
                country?: string;
            };
        };
    };
    orders: CustomerOrder[];
    activity: { id: string; type: string; message: string; timestamp: string }[];
}

/**
 * MobileCustomerDetail - Mobile-optimized customer profile page
 * Shows customer info, stats, and recent orders
 */
export function MobileCustomerDetail() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [data, setData] = useState<CustomerDetails | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (id) fetchCustomer();
        const handleRefresh = () => { if (id) fetchCustomer(); };
        window.addEventListener('mobile-refresh', handleRefresh);
        return () => window.removeEventListener('mobile-refresh', handleRefresh);
    }, [id, currentAccount, token]);

    const fetchCustomer = async () => {
        if (!currentAccount || !token || !id) {
            setLoading(false);
            return;
        }

        try {
            setLoading(true);
            const res = await fetch(`/api/customers/${id}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (res.ok) {
                const json = await res.json();
                // Map API response to our expected shape
                // API returns: { customer, orders (raw WooOrders), automations, activity }
                const mappedData: CustomerDetails = {
                    customer: {
                        id: json.customer?.id || id,
                        firstName: json.customer?.firstName || '',
                        lastName: json.customer?.lastName || '',
                        email: json.customer?.email || '',
                        totalSpent: Number(json.customer?.totalSpent) || 0,
                        ordersCount: json.customer?.ordersCount || 0,
                        dateCreated: json.customer?.dateCreated || json.customer?.createdAt || '',
                        rawData: json.customer?.rawData
                    },
                    orders: (json.orders || []).map((order: OrderApiResponse) => ({
                        id: order.id,
                        number: order.rawData?.number || order.wooId || order.id,
                        status: order.rawData?.status || order.status || 'unknown',
                        total: Number(order.rawData?.total || order.total) || 0,
                        dateCreated: order.rawData?.date_created || order.dateCreated || ''
                    })),
                    activity: json.activity || []
                };
                setData(mappedData);
            }
        } catch (error) {
            Logger.error('[MobileCustomerDetail] Error:', { error: error });
        } finally {
            setLoading(false);
        }
    };

    // Currency formatting helper using centralized utility
    const formatAccountCurrency = (amount: number) =>
        formatCurrency(amount, currentAccount?.currency || 'USD');

    if (loading) {
        return (
            <div className="space-y-4 animate-pulse">
                <div className="h-8 bg-gray-200 rounded w-1/3" />
                <div className="h-32 bg-gray-200 rounded-xl" />
                <div className="grid grid-cols-2 gap-3">
                    <div className="h-24 bg-gray-200 rounded-xl" />
                    <div className="h-24 bg-gray-200 rounded-xl" />
                </div>
                {[...Array(3)].map((_, i) => <div key={i} className="h-20 bg-gray-200 rounded-xl" />)}
            </div>
        );
    }

    if (!data) {
        return (
            <div className="text-center py-16">
                <ShoppingBag className="mx-auto text-gray-300 mb-4" size={48} />
                <p className="text-gray-500">Customer not found</p>
                <button onClick={() => navigate('/m/customers')} className="mt-4 text-indigo-600 font-medium">
                    Back to Customers
                </button>
            </div>
        );
    }

    const { customer, orders } = data;
    const fullName = `${customer.firstName || ''} ${customer.lastName || ''}`.trim() || 'Unknown';
    const initials = (customer.firstName?.[0] || '') + (customer.lastName?.[0] || '');
    const avgOrder = customer.ordersCount > 0 ? customer.totalSpent / customer.ordersCount : 0;

    return (
        <div className="space-y-4 pb-8">
            {/* Header */}
            <div className="flex items-center gap-3">
                <button onClick={() => navigate('/m/customers')} className="p-2 -ml-2 rounded-lg active:bg-gray-100">
                    <ArrowLeft size={24} className="text-gray-700" />
                </button>
                <div className="flex-1">
                    <h1 className="text-xl font-bold text-gray-900">{fullName}</h1>
                    <p className="text-sm text-gray-500">Customer Profile</p>
                </div>
                <button onClick={fetchCustomer} className="p-2 rounded-full hover:bg-gray-100">
                    <RefreshCw size={20} className="text-gray-600" />
                </button>
            </div>

            {/* Profile Card */}
            <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                <div className="flex items-center gap-4 mb-4">
                    <div className="w-16 h-16 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold text-xl">
                        {initials || '?'}
                    </div>
                    <div className="flex-1">
                        <h2 className="text-lg font-semibold text-gray-900">{fullName}</h2>
                        <div className="flex items-center gap-1 text-sm text-gray-500 mt-1">
                            <Calendar size={14} />
                            <span>Customer since {formatDate(customer.dateCreated)}</span>
                        </div>
                    </div>
                </div>

                {/* Contact Info */}
                <div className="space-y-2 pt-3 border-t border-gray-100">
                    <div className="flex items-center gap-3 text-sm">
                        <Mail size={16} className="text-gray-400" />
                        <a href={`mailto:${customer.email}`} className="text-indigo-600">{customer.email}</a>
                    </div>
                    {customer.rawData?.billing?.phone && (
                        <div className="flex items-center gap-3 text-sm">
                            <Phone size={16} className="text-gray-400" />
                            <a href={`tel:${customer.rawData.billing.phone}`} className="text-indigo-600">
                                {customer.rawData.billing.phone}
                            </a>
                        </div>
                    )}
                    {customer.rawData?.billing?.city && (
                        <div className="flex items-center gap-3 text-sm">
                            <MapPin size={16} className="text-gray-400" />
                            <span className="text-gray-700">
                                {customer.rawData.billing.city}, {customer.rawData.billing.state} {customer.rawData.billing.country}
                            </span>
                        </div>
                    )}
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-3 gap-3">
                <div className="bg-gradient-to-br from-green-50 to-emerald-50 rounded-xl p-3 border border-green-100">
                    <div className="flex items-center gap-1 text-green-600 mb-1">
                        <DollarSign size={14} />
                        <span className="text-xs font-medium">Total</span>
                    </div>
                    <p className="text-lg font-bold text-gray-900">{formatAccountCurrency(customer.totalSpent)}</p>
                </div>
                <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl p-3 border border-indigo-100">
                    <div className="flex items-center gap-1 text-indigo-600 mb-1">
                        <Package size={14} />
                        <span className="text-xs font-medium">Orders</span>
                    </div>
                    <p className="text-lg font-bold text-gray-900">{customer.ordersCount}</p>
                </div>
                <div className="bg-gradient-to-br from-amber-50 to-orange-50 rounded-xl p-3 border border-amber-100">
                    <div className="flex items-center gap-1 text-amber-600 mb-1">
                        <ShoppingBag size={14} />
                        <span className="text-xs font-medium">AOV</span>
                    </div>
                    <p className="text-lg font-bold text-gray-900">{formatAccountCurrency(avgOrder)}</p>
                </div>
            </div>

            {/* Recent Orders */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <h2 className="font-semibold text-gray-900 p-4 border-b border-gray-100">
                    Recent Orders ({orders.length})
                </h2>
                <div className="divide-y divide-gray-100">
                    {orders.length > 0 ? (
                        orders.slice(0, 10).map((order) => (
                            <button
                                key={order.id}
                                onClick={() => navigate(`/m/orders/${order.id}`)}
                                className="w-full p-4 flex items-center gap-3 text-left active:bg-gray-50"
                            >
                                <div className="w-10 h-10 rounded-lg bg-gray-100 flex items-center justify-center">
                                    <Package size={18} className="text-gray-500" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="font-medium text-gray-900">Order #{order.number}</p>
                                    <div className="flex items-center gap-2 mt-0.5">
                                        <span className={`text-xs px-2 py-0.5 rounded-full font-medium uppercase ${getStatusColor(order.status)}`}>
                                            {order.status}
                                        </span>
                                        <span className="text-xs text-gray-500">{formatDate(order.dateCreated)}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <span className="font-medium text-gray-900">{formatAccountCurrency(order.total)}</span>
                                    <ChevronRight size={18} className="text-gray-400" />
                                </div>
                            </button>
                        ))
                    ) : (
                        <div className="p-8 text-center text-gray-400">
                            No orders found
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { Logger } from '../../utils/logger';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useHaptic } from '../../hooks/useHaptic';
import {
    ChevronLeft,
    Search,
    Users,
    Mail,
    ShoppingBag,
    ChevronRight,
    Loader2
} from 'lucide-react';
import { formatCurrency } from '../../utils/format';
import { getInitials } from '../../utils/string';
import { ListSkeleton } from '../../components/mobile/MobileSkeleton';

/**
 * MobileCustomers - Premium dark-mode customer list for PWA.
 * Features search and displays customer metrics.
 */

interface CustomerApiResponse {
    id: string;
    firstName?: string;
    first_name?: string;
    lastName?: string;
    last_name?: string;
    email?: string;
    totalSpent?: number;
    total_spent?: number;
    ordersCount?: number;
    orders_count?: number;
    dateCreated?: string;
    date_created?: string;
    createdAt?: string;
    avatarUrl?: string;
}

interface Customer {
    id: string;
    firstName: string;
    lastName: string;
    email: string;
    totalSpent: number;
    ordersCount: number;
    dateCreated: string;
    avatarUrl?: string;
}

export function MobileCustomers() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { triggerHaptic } = useHaptic();
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [hasMore, setHasMore] = useState(true);

    const fetchCustomers = useCallback(async (reset = false) => {
        if (!currentAccount || !token) return;

        try {
            if (reset) setLoading(true);

            const params = new URLSearchParams();
            params.append('page', reset ? '1' : page.toString());
            params.append('limit', '20');
            if (searchQuery) params.append('q', searchQuery);

            const res = await fetch(`/api/customers?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (!res.ok) throw new Error('Failed to fetch');

            const data = await res.json();
            const newCustomers = (data.customers || data || []).map((c: CustomerApiResponse) => ({
                id: c.id,
                firstName: c.firstName || c.first_name || '',
                lastName: c.lastName || c.last_name || '',
                email: c.email || '',
                totalSpent: Number(c.totalSpent || c.total_spent) || 0,
                ordersCount: c.ordersCount || c.orders_count || 0,
                dateCreated: c.dateCreated || c.date_created || c.createdAt || '',
                avatarUrl: c.avatarUrl
            }));

            if (reset) {
                setCustomers(newCustomers);
                setPage(1);
            } else {
                setCustomers(prev => [...prev, ...newCustomers]);
            }
            setHasMore(newCustomers.length === 20);
        } catch (error) {
            Logger.error('[MobileCustomers] Error:', { error: error });
        } finally {
            setLoading(false);
        }
    }, [currentAccount, token, searchQuery, page]);

    useEffect(() => {
        fetchCustomers(true);
        const handleRefresh = () => fetchCustomers(true);
        window.addEventListener('mobile-refresh', handleRefresh);
        return () => window.removeEventListener('mobile-refresh', handleRefresh);
    }, [currentAccount, token]);

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        triggerHaptic();
        fetchCustomers(true);
    };

    const loadMore = () => {
        if (!loading && hasMore) {
            setPage(p => p + 1);
            fetchCustomers(false);
        }
    };

    const formatAccountCurrency = (amount: number) =>
        formatCurrency(amount, currentAccount?.currency || 'USD');

    if (loading && customers.length === 0) {
        return (
            <div className="space-y-4">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-2xl bg-slate-800/50" />
                    <div className="h-6 w-24 bg-slate-800/50 rounded-lg" />
                </div>
                <ListSkeleton count={6} />
            </div>
        );
    }

    return (
        <div className="space-y-4 animate-fade-slide-up">
            {/* Header */}
            <div className="flex items-center gap-3">
                <button
                    onClick={() => {
                        triggerHaptic();
                        navigate(-1);
                    }}
                    className="w-10 h-10 flex items-center justify-center rounded-2xl bg-slate-700/40 border border-white/10 active:scale-95 transition-transform"
                    aria-label="Go back"
                >
                    <ChevronLeft size={22} className="text-slate-300" />
                </button>
                <h1 className="text-xl font-bold text-white">Customers</h1>
                <span className="ml-auto text-sm text-slate-400 bg-slate-800/50 px-3 py-1 rounded-full">
                    {customers.length}
                </span>
            </div>

            {/* Search */}
            <form onSubmit={handleSearch} className="flex gap-2">
                <div className="flex-1 relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 p-1.5 rounded-lg bg-slate-700/50">
                        <Search size={14} className="text-slate-400" />
                    </div>
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={e => setSearchQuery(e.target.value)}
                        placeholder="Search customers..."
                        className="w-full pl-14 pr-4 py-3.5 pwa-card text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 transition-all"
                    />
                </div>
                <button
                    type="submit"
                    className="px-4 py-3.5 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-2xl active:scale-95 transition-transform shadow-lg shadow-indigo-500/25"
                >
                    <Search size={18} />
                </button>
            </form>

            {/* Stats Summary */}
            {customers.length > 0 && (
                <div className="grid grid-cols-2 gap-3">
                    <div className="pwa-card p-4">
                        <div className="flex items-center gap-2 text-indigo-400 mb-1">
                            <Users size={16} />
                            <span className="text-xs font-medium">Total</span>
                        </div>
                        <p className="text-xl font-bold text-white">{customers.length}</p>
                    </div>
                    <div className="pwa-card p-4">
                        <div className="flex items-center gap-2 text-emerald-400 mb-1">
                            <ShoppingBag size={16} />
                            <span className="text-xs font-medium">Total Spent</span>
                        </div>
                        <p className="text-xl font-bold text-white">
                            {formatAccountCurrency(customers.reduce((sum, c) => sum + c.totalSpent, 0))}
                        </p>
                    </div>
                </div>
            )}

            {/* Customer List */}
            {customers.length === 0 ? (
                <div className="text-center py-16">
                    <div className="w-20 h-20 mx-auto mb-4 pwa-card flex items-center justify-center">
                        <Users className="text-slate-500" size={36} />
                    </div>
                    <p className="text-white font-semibold mb-1">No customers found</p>
                    <p className="text-slate-400 text-sm">Customers will appear here</p>
                </div>
            ) : (
                <div className="space-y-2">
                    {customers.map((customer, index) => (
                        <button
                            key={customer.id}
                            onClick={() => {
                                triggerHaptic();
                                navigate(`/m/customers/${customer.id}`);
                            }}
                            className="w-full pwa-card p-4 flex items-center gap-4 text-left active:bg-slate-700/50 transition-all animate-fade-slide-up"
                            style={{ animationDelay: `${index * 15}ms` }}
                        >
                            {/* Avatar */}
                            {customer.avatarUrl ? (
                                <img
                                    src={customer.avatarUrl}
                                    alt=""
                                    className="w-12 h-12 rounded-xl object-cover flex-shrink-0"
                                />
                            ) : (
                                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold text-lg flex-shrink-0 shadow-lg shadow-indigo-500/25">
                                    {getInitials(`${customer.firstName} ${customer.lastName}`)}
                                </div>
                            )}

                            {/* Info */}
                            <div className="flex-1 min-w-0">
                                <p className="font-semibold text-white truncate">
                                    {customer.firstName} {customer.lastName}
                                </p>
                                <p className="text-sm text-slate-400 truncate flex items-center gap-1.5">
                                    <Mail size={12} />
                                    {customer.email}
                                </p>
                                <div className="flex items-center gap-3 mt-1.5 text-xs">
                                    <span className="flex items-center gap-1 text-slate-500">
                                        <ShoppingBag size={10} />
                                        {customer.ordersCount} orders
                                    </span>
                                    <span className="font-medium text-emerald-400">
                                        {formatAccountCurrency(customer.totalSpent)}
                                    </span>
                                </div>
                            </div>

                            <ChevronRight size={18} className="text-slate-500 flex-shrink-0" />
                        </button>
                    ))}

                    {/* Load More */}
                    {hasMore && (
                        <button
                            onClick={loadMore}
                            disabled={loading}
                            className="w-full py-4 text-indigo-400 font-semibold pwa-card active:bg-slate-700/50 transition-all flex items-center justify-center gap-2"
                        >
                            {loading ? (
                                <>
                                    <Loader2 size={16} className="animate-spin" />
                                    Loading...
                                </>
                            ) : (
                                'Load More'
                            )}
                        </button>
                    )}
                </div>
            )}
        </div>
    );
}

import { useState, useEffect, useMemo } from 'react';
import { Logger } from '../../utils/logger';
import { useNavigate } from 'react-router-dom';
import {
    ShoppingCart,
    MessageSquare,
    TrendingUp,
    Package,
    ArrowRight,
    Bell,
    DollarSign,
    Sun,
    Moon,
    Sunrise,
    Sunset,
    Users
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { getDateRange } from '../../utils/dateUtils';
import { formatCurrency, formatTimeAgo } from '../../utils/format';
import { RevenueAnomalyBanner } from '../../components/mobile/RevenueAnomalyBanner';
import { DashboardSkeleton } from '../../components/mobile/MobileSkeleton';
import { Sparkline, TrendBadge } from '../../components/mobile/Sparkline';
import { usePermissions } from '../../hooks/usePermissions';

/**
 * MobileDashboard - Premium dark dashboard for the PWA companion app.
 * 
 * Features:
 * - Time-of-day greeting with icon
 * - Glassmorphism stat cards with sparklines
 * - Trend indicators
 * - Smooth staggered animations
 */

interface TrendDataDay {
    orders?: number;
    revenue?: number;
}

interface OrderApiResponse {
    id: string;
    orderNumber?: string;
    total?: string | number;
    date_created?: string;
    createdAt?: string;
    status?: string;
}

interface DashboardStats {
    todayOrders: number;
    todayRevenue: number;
    pendingMessages: number;
    lowStockItems: number;
    yesterdayOrders?: number;
    yesterdayRevenue?: number;
}

interface RecentActivity {
    id: string;
    type: 'order' | 'message' | 'inventory';
    title: string;
    subtitle: string;
    time: string;
    status?: string;
}

interface AnomalyData {
    isAnomaly: boolean;
    direction: 'above' | 'below' | 'normal';
    percentChange: number;
    message: string;
}

interface SparklineData {
    orders: number[];
    revenue: number[];
}

export function MobileDashboard() {
    const navigate = useNavigate();
    const { token, user } = useAuth();
    const { currentAccount } = useAccount();
    const { hasPermission } = usePermissions();
    const [stats, setStats] = useState<DashboardStats | null>(null);
    const [activities, setActivities] = useState<RecentActivity[]>([]);
    const [anomaly, setAnomaly] = useState<AnomalyData | null>(null);
    const [sparklines, setSparklines] = useState<SparklineData>({ orders: [], revenue: [] });
    const [loading, setLoading] = useState(true);

    // Time-based greeting
    const greeting = useMemo(() => {
        const hour = new Date().getHours();
        if (hour >= 5 && hour < 12) {
            return { text: 'Good morning', icon: Sunrise, color: 'text-amber-400' };
        } else if (hour >= 12 && hour < 17) {
            return { text: 'Good afternoon', icon: Sun, color: 'text-yellow-400' };
        } else if (hour >= 17 && hour < 21) {
            return { text: 'Good evening', icon: Sunset, color: 'text-orange-400' };
        } else {
            return { text: 'Good night', icon: Moon, color: 'text-indigo-400' };
        }
    }, []);

    const firstName = user?.fullName?.split(' ')[0] || 'there';

    useEffect(() => {
        fetchDashboardData();

        // Listen for pull-to-refresh
        const handleRefresh = () => fetchDashboardData();
        window.addEventListener('mobile-refresh', handleRefresh);
        return () => window.removeEventListener('mobile-refresh', handleRefresh);
    }, [currentAccount, token]);

    const fetchDashboardData = async () => {
        if (!currentAccount || !token) {
            setLoading(false);
            return;
        }

        try {
            setLoading(true);
            const headers = {
                'Authorization': `Bearer ${token}`,
                'X-Account-ID': currentAccount.id
            };

            // Use same date utility as desktop for timezone-aware dates
            const { startDate, endDate } = getDateRange('today');
            const yesterday = getDateRange('yesterday');

            // Fetch all data in parallel (including anomaly detection and 7-day trend)
            const [salesRes, yesterdaySalesRes, messagesRes, inventoryRes, ordersRes, anomalyRes, trendRes] = await Promise.all([
                fetch(`/api/analytics/sales?startDate=${startDate}&endDate=${endDate}`, { headers }),
                fetch(`/api/analytics/sales?startDate=${yesterday.startDate}&endDate=${yesterday.endDate}`, { headers }),
                fetch('/api/chat/unread-count', { headers }),
                fetch('/api/analytics/health', { headers }),
                fetch('/api/sync/orders/search?limit=5', { headers }),
                fetch('/api/analytics/anomalies', { headers }),
                fetch('/api/analytics/trend?days=7', { headers }).catch(() => null)
            ]);

            let todayRevenue = 0, todayOrders = 0, pendingMessages = 0, lowStockItems = 0;
            let yesterdayRevenue = 0, yesterdayOrders = 0;

            if (salesRes.ok) {
                const data = await salesRes.json();
                Logger.debug('[MobileDashboard] Sales API response', { data });
                todayRevenue = data.total || 0;
                todayOrders = data.count || 0;
            } else {
                Logger.error('[MobileDashboard] Sales API failed', { status: salesRes.status });
            }

            if (yesterdaySalesRes.ok) {
                const data = await yesterdaySalesRes.json();
                yesterdayRevenue = data.total || 0;
                yesterdayOrders = data.count || 0;
            }

            if (messagesRes.ok) {
                const data = await messagesRes.json();
                pendingMessages = data.count || 0;
            }

            if (inventoryRes.ok) {
                const data = await inventoryRes.json();
                lowStockItems = Array.isArray(data) ? data.length : 0;
            }

            // Process anomaly data
            if (anomalyRes.ok) {
                const anomalyData = await anomalyRes.json();
                setAnomaly(anomalyData);
            }

            // Process trend data for sparklines
            if (trendRes && trendRes.ok) {
                const trendData = await trendRes.json();
                if (trendData.daily) {
                    setSparklines({
                        orders: trendData.daily.map((d: TrendDataDay) => d.orders || 0),
                        revenue: trendData.daily.map((d: TrendDataDay) => d.revenue || 0)
                    });
                }
            } else {
                // Generate sample sparkline data as fallback
                setSparklines({
                    orders: [todayOrders * 0.7, todayOrders * 0.85, todayOrders * 0.6, todayOrders * 0.9, todayOrders * 0.75, todayOrders * 0.95, todayOrders],
                    revenue: [todayRevenue * 0.65, todayRevenue * 0.8, todayRevenue * 0.7, todayRevenue * 0.85, todayRevenue * 0.75, todayRevenue * 0.9, todayRevenue]
                });
            }

            setStats({ todayOrders, todayRevenue, pendingMessages, lowStockItems, yesterdayOrders, yesterdayRevenue });

            // Parse recent activities from orders
            if (ordersRes.ok) {
                const ordersData = await ordersRes.json();
                const recentActivities: RecentActivity[] = (ordersData.orders || ordersData || [])
                    .slice(0, 5)
                    .map((order: OrderApiResponse) => ({
                        id: order.id,
                        type: 'order' as const,
                        title: `Order #${order.orderNumber || String(order.id).slice(-6)}`,
                        subtitle: `${formatCurrency(Number(order.total || 0), currentAccount?.currency || 'USD')}`,
                        time: formatTimeAgo(order.date_created || order.createdAt || ''),
                        status: order.status
                    }));
                setActivities(recentActivities);
            }
        } catch (error) {
            Logger.error('[MobileDashboard] Error fetching data', { error });
        } finally {
            setLoading(false);
        }
    };

    // Currency formatting helper using centralized utility with account currency
    const formatAccountCurrency = (amount: number) =>
        formatCurrency(amount, currentAccount?.currency || 'USD', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

    // Calculate trend percentages
    const ordersTrend = stats?.yesterdayOrders
        ? ((stats.todayOrders - stats.yesterdayOrders) / stats.yesterdayOrders) * 100
        : 0;
    const revenueTrend = stats?.yesterdayRevenue
        ? ((stats.todayRevenue - stats.yesterdayRevenue) / stats.yesterdayRevenue) * 100
        : 0;

    const quickActions = [
        { label: 'Orders', icon: ShoppingCart, path: '/m/orders', color: 'from-blue-500 to-indigo-600' },
        { label: 'Inbox', icon: MessageSquare, path: '/m/inbox', color: 'from-emerald-500 to-teal-600' },
        { label: 'Analytics', icon: TrendingUp, path: '/m/analytics', color: 'from-purple-500 to-violet-600' },
        { label: 'Inventory', icon: Package, path: '/m/inventory', color: 'from-orange-500 to-amber-600' },
    ];

    // Dark-mode activity status colors - different from standard light-mode utility
    const getDarkStatusColor = (status?: string) => {
        switch (status?.toLowerCase()) {
            case 'completed': return 'bg-emerald-500/20 text-emerald-400';
            case 'processing': return 'bg-blue-500/20 text-blue-400';
            case 'pending': return 'bg-amber-500/20 text-amber-400';
            case 'cancelled': return 'bg-rose-500/20 text-rose-400';
            default: return 'bg-slate-500/20 text-slate-400';
        }
    };

    if (loading) {
        return <DashboardSkeleton />;
    }

    return (
        <div className="space-y-6">
            {/* Revenue Anomaly Alert Banner - only show if user has finance permission */}
            {hasPermission('view_finance') && <RevenueAnomalyBanner anomaly={anomaly} />}

            {/* Greeting Header */}
            <div className="flex items-center justify-between animate-fade-slide-up">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <greeting.icon size={20} className={greeting.color} />
                        <span className={`text-sm font-medium ${greeting.color}`}>{greeting.text}</span>
                    </div>
                    <h1 className="text-2xl font-bold text-white">{firstName} 👋</h1>
                </div>
                <button
                    onClick={() => navigate('/m/notifications')}
                    className="p-3 rounded-2xl bg-slate-700/40 border border-white/10 hover:bg-slate-700/50 active:scale-95 transition-all"
                >
                    <Bell size={20} className="text-slate-300" />
                </button>
            </div>

            {/* Stat Cards with Sparklines */}
            <div className="grid grid-cols-2 gap-3">
                {/* Orders Card */}
                <div
                    className="pwa-card-interactive p-4 animate-fade-slide-up"
                    style={{ animationDelay: '25ms' }}
                    onClick={() => navigate('/m/orders')}
                >
                    <div className="flex items-center justify-between mb-2">
                        <div className="p-2 rounded-xl bg-blue-500/20">
                            <ShoppingCart size={18} className="text-blue-400" />
                        </div>
                        {stats?.yesterdayOrders !== undefined && <TrendBadge value={ordersTrend} />}
                    </div>
                    <p className="text-2xl font-bold text-white mb-0.5">{stats?.todayOrders || 0}</p>
                    <p className="text-xs text-slate-400 mb-2">Orders today</p>
                    <Sparkline data={sparklines.orders} color="#60a5fa" height={24} />
                </div>

                {/* Revenue Card - only show if user has finance permission */}
                {hasPermission('view_finance') && (
                    <div
                        className="pwa-card-interactive p-4 animate-fade-slide-up"
                        style={{ animationDelay: '50ms' }}
