                <div className="pwa-card divide-y divide-white/5 overflow-hidden">
                    {activities.length === 0 ? (
                        <div className="p-6 text-center">
                            <Users size={32} className="text-slate-600 mx-auto mb-2" />
                            <p className="text-slate-400 text-sm">No recent activity</p>
                        </div>
                    ) : (
                        activities.map((activity, index) => (
                            <button
                                key={activity.id}
                                onClick={() => navigate(`/m/orders/${activity.id}`)}
                                className="w-full flex items-center p-4 text-left hover:bg-white/5 active:bg-white/10 transition-colors animate-fade-slide-up"
                                style={{ animationDelay: `${225 + index * 25}ms` }}
                            >
                                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center mr-3 shadow-lg">
                                    <ShoppingCart size={18} className="text-white" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="font-medium text-white truncate">{activity.title}</p>
                                    <p className="text-sm text-slate-400 truncate">{activity.subtitle}</p>
                                </div>
                                <div className="flex flex-col items-end gap-1 ml-2">
                                    <span className="text-xs text-slate-500">{activity.time}</span>
                                    {activity.status && (
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-medium capitalize ${getDarkStatusColor(activity.status)}`}>
                                            {activity.status}
                                        </span>
                                    )}
                                </div>
                            </button>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useNavigate } from 'react-router-dom';
import { MessageSquare, Mail, Instagram, Facebook, Music2, Search, Archive, CheckCheck } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useSocket } from '../../context/SocketContext';
import { useHaptic } from '../../hooks/useHaptic';
import { SwipeableRow } from '../../components/ui/SwipeableRow';
import { formatTimeAgo } from '../../utils/format';
import { getInitials } from '../../utils/string';
import { InboxSkeleton } from '../../components/mobile/MobileSkeleton';

interface ConversationApiResponse {
    id: string;
    wooCustomer?: {
        firstName?: string;
        lastName?: string;
        email?: string;
    };
    guestName?: string;
    guestEmail?: string;
    messages?: { content?: string }[];
    channel?: string;
    isRead?: boolean;
    updatedAt?: string;
}

interface Conversation {
    id: string;
    customerName: string;
    lastMessage: string;
    channel: string;
    unread: boolean;
    updatedAt: string;
}

/**
 * Dark-mode channel config with colors matching glassmorphism theme.
 */
const CHANNEL_CONFIG: Record<string, { icon: typeof Mail; color: string; bg: string }> = {
    email: { icon: Mail, color: 'text-blue-400', bg: 'bg-blue-500/20' },
    facebook: { icon: Facebook, color: 'text-blue-400', bg: 'bg-blue-500/20' },
    instagram: { icon: Instagram, color: 'text-pink-400', bg: 'bg-pink-500/20' },
    tiktok: { icon: Music2, color: 'text-slate-300', bg: 'bg-slate-500/20' },
    default: { icon: MessageSquare, color: 'text-slate-400', bg: 'bg-slate-500/20' }
};

const FILTER_OPTIONS = ['All', 'Unread', 'Email', 'Social'];

/**
 * MobileInbox - Premium dark-mode inbox for PWA.
 * Features swipe actions, search, and channel filters.
 */
export function MobileInbox() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { triggerHaptic } = useHaptic();
    const [conversations, setConversations] = useState<Conversation[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeFilter, setActiveFilter] = useState('All');
    const [searchQuery, setSearchQuery] = useState('');
    const [showSearch, setShowSearch] = useState(false);

    useEffect(() => {
        fetchConversations();
        const handleRefresh = () => fetchConversations();
        window.addEventListener('mobile-refresh', handleRefresh);
        return () => window.removeEventListener('mobile-refresh', handleRefresh);
    }, [currentAccount, token]);

    // Socket listener for real-time updates
    const { socket } = useSocket();
    useEffect(() => {
        if (!socket || !currentAccount) return;

        /**
         * Handle new/updated conversations from socket events.
         * Refreshes conversation list to get full data.
         */
        const handleConversationUpdated = () => {
            // Trigger haptic on incoming message
            triggerHaptic(5);
            fetchConversations();
        };

        socket.on('conversation:updated', handleConversationUpdated);

        return () => {
            socket.off('conversation:updated', handleConversationUpdated);
        };
    }, [socket, currentAccount]);

    const fetchConversations = async () => {
        if (!currentAccount || !token) {
            setLoading(false);
            return;
        }

        try {
            setLoading(true);
            const response = await fetch('/api/chat/conversations?status=OPEN&limit=50', {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (!response.ok) throw new Error('Failed to fetch');

            const data = await response.json();
            const rawConvos = Array.isArray(data) ? data : (data.conversations || []);
            const convos = rawConvos.map((c: ConversationApiResponse) => {
                const customerName = c.wooCustomer
                    ? `${c.wooCustomer.firstName || ''} ${c.wooCustomer.lastName || ''}`.trim() || c.wooCustomer.email
                    : c.guestName || c.guestEmail || 'Unknown';

                const lastMessage = c.messages?.[0]?.content || 'No messages yet';

                return {
                    id: c.id,
                    customerName: customerName || 'Unknown',
                    lastMessage,
                    channel: c.channel || 'CHAT',
                    unread: !c.isRead,
                    updatedAt: c.updatedAt || ''
                };
            });
            setConversations(convos);
        } catch (error) {
            Logger.error('[MobileInbox] Error:', { error: error });
        } finally {
            setLoading(false);
        }
    };

    const handleArchive = async (id: string) => {
        triggerHaptic(15);
        setConversations(prev => prev.filter(c => c.id !== id));

        try {
            await fetch(`/api/chat/${id}`, {
                method: 'PATCH',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ status: 'closed' })
            });
        } catch (error) {
            Logger.error('[MobileInbox] Archive failed:', { error: error });
            fetchConversations();
        }
    };

    const handleMarkRead = async (id: string) => {
        triggerHaptic(10);
        setConversations(prev => prev.map(c =>
            c.id === id ? { ...c, unread: false } : c
        ));

        try {
            await fetch(`/api/chat/${id}/read`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id
                }
            });
        } catch (error) {
            Logger.error('[MobileInbox] Mark read failed:', { error: error });
        }
    };

    const getChannelConfig = (channel: string) =>
        CHANNEL_CONFIG[channel.toLowerCase()] || CHANNEL_CONFIG.default;

    const filteredConversations = conversations.filter(c => {
        if (activeFilter === 'Unread' && !c.unread) return false;
        if (activeFilter === 'Email' && c.channel !== 'email') return false;
        if (activeFilter === 'Social' && c.channel === 'email') return false;
        if (searchQuery && !c.customerName.toLowerCase().includes(searchQuery.toLowerCase())) return false;
        return true;
    });

    const unreadCount = conversations.filter(c => c.unread).length;

    if (loading) {
        return <InboxSkeleton />;
    }

    return (
        <div className="min-h-full flex flex-col space-y-4 animate-fade-slide-up">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <h1 className="text-2xl font-bold text-white">Inbox</h1>
                    {unreadCount > 0 && (
                        <span className="px-2.5 py-0.5 bg-gradient-to-r from-indigo-500 to-purple-600 text-white text-sm font-semibold rounded-full shadow-lg shadow-indigo-500/30">
                            {unreadCount}
                        </span>
                    )}
                </div>
                <button
                    onClick={() => {
                        triggerHaptic();
                        setShowSearch(!showSearch);
                    }}
                    className="p-2.5 rounded-xl bg-slate-700/40 border border-white/10 active:bg-slate-700/50 transition-colors"
                >
                    <Search size={20} className="text-slate-300" />
                </button>
            </div>

            {/* Search Bar (Expandable) */}
            {showSearch && (
                <div className="relative animate-fade-slide-up">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 p-1.5 rounded-lg bg-slate-700/50">
                        <Search size={14} className="text-slate-400" />
                    </div>
                    <input
                        type="text"
                        placeholder="Search conversations..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        autoFocus
                        className="w-full pl-14 pr-4 py-3.5 pwa-card text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 transition-all"
                    />
                </div>
            )}

            {/* Filter Chips */}
            <div className="flex gap-2 overflow-x-auto pb-1 -mx-4 px-4 no-scrollbar">
                {FILTER_OPTIONS.map((filter) => {
                    const isActive = activeFilter === filter;
                    return (
                        <button
                            key={filter}
                            onClick={() => {
                                triggerHaptic();
                                setActiveFilter(filter);
                            }}
                            className={`
                                px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all active:scale-95
                                ${isActive
                                    ? 'bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg shadow-indigo-500/25'
                                    : 'bg-slate-700/40 border border-white/10 text-slate-300'
                                }
                            `}
                        >
                            {filter}
                            {filter === 'Unread' && unreadCount > 0 && (
                                <span className={`ml-1.5 ${isActive ? 'text-indigo-200' : 'text-slate-500'}`}>
                                    ({unreadCount})
                                </span>
                            )}
                        </button>
                    );
                })}
            </div>

            {/* Swipe Hint */}
            {filteredConversations.length > 0 && (
                <p className="text-xs text-slate-500 text-center">
                    ← Swipe left to archive • Swipe right to mark read →
                </p>
            )}

            {/* Conversation List */}
            <div className="flex-1 space-y-2">
                {filteredConversations.length === 0 ? (
                    <div className="text-center py-16">
                        <div className="w-20 h-20 mx-auto mb-4 pwa-card flex items-center justify-center">
                            <MessageSquare className="text-slate-500" size={36} />
                        </div>
                        <p className="text-white font-semibold mb-1">No conversations</p>
                        <p className="text-slate-400 text-sm">Messages will appear here</p>
                    </div>
                ) : (
                    filteredConversations.map((convo, index) => {
                        const channelConfig = getChannelConfig(convo.channel);
                        const ChannelIcon = channelConfig.icon;

                        return (
                            <SwipeableRow
                                key={convo.id}
                                leftAction={convo.unread ? {
                                    icon: <CheckCheck size={24} className="text-white" />,
                                    color: 'bg-emerald-500',
                                    onAction: () => handleMarkRead(convo.id)
                                } : undefined}
                                rightAction={{
                                    icon: <Archive size={24} className="text-white" />,
                                    color: 'bg-slate-600',
                                    onAction: () => handleArchive(convo.id)
                                }}
                            >
                                <button
                                    onClick={() => {
                                        triggerHaptic();
                                        navigate(`/m/inbox/${convo.id}`);
                                    }}
                                    className="w-full flex items-center gap-4 p-4 pwa-card active:bg-slate-700/50 transition-all animate-fade-slide-up"
                                    style={{ animationDelay: `${index * 15}ms` }}
                                >
                                    {/* Avatar */}
                                    <div className="relative flex-shrink-0">
                                        <div className={`
                                            w-12 h-12 rounded-xl flex items-center justify-center text-white font-bold text-lg
                                            ${convo.unread
                                                ? 'bg-gradient-to-br from-indigo-500 to-purple-600 shadow-lg shadow-indigo-500/30'
                                                : 'bg-slate-700'
                                            }
                                        `}>
                                            {getInitials(convo.customerName)}
                                        </div>
                                        {/* Channel Badge */}
                                        <div className={`
                                            absolute -bottom-1 -right-1 w-6 h-6 rounded-lg 
                                            ${channelConfig.bg} 
                                            flex items-center justify-center ring-2 ring-slate-900
                                        `}>
                                            <ChannelIcon size={12} className={channelConfig.color} />
                                        </div>
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0 text-left">
                                        <div className="flex items-center justify-between mb-1">
                                            <span className={`text-base truncate ${convo.unread ? 'font-bold text-white' : 'font-medium text-slate-300'}`}>
                                                {convo.customerName}
                                            </span>
                                            <span className="text-xs text-slate-500 flex-shrink-0 ml-3">
                                                {formatTimeAgo(convo.updatedAt)}
                                            </span>
                                        </div>
                                        <p className={`text-sm line-clamp-2 ${convo.unread ? 'text-slate-300' : 'text-slate-500'}`}>
                                            {convo.lastMessage}
                                        </p>
                                    </div>

                                    {/* Unread Indicator */}
                                    {convo.unread && (
                                        <div className="w-3 h-3 bg-indigo-500 rounded-full flex-shrink-0 animate-pulse shadow-lg shadow-indigo-500/50" />
                                    )}
                                </button>
                            </SwipeableRow>
                        );
                    })
                )}
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { Search, Package2, AlertTriangle, Grid, List, ChevronRight } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { formatCurrency } from '../../utils/format';

interface ProductVariation {
    stock_quantity?: number;
    stockQuantity?: number;
}

interface ProductApiResponse {
    id: string;
    name?: string;
    sku?: string;
    variations?: ProductVariation[];
    stock_quantity?: number;
    stockQuantity?: number;
    low_stock_amount?: number;
    lowStockThreshold?: number;
    price?: number;
    mainImage?: string;
    images?: { src?: string }[];
}

interface Product {
    id: string;
    name: string;
    sku: string;
    stockQuantity: number;
    lowStockThreshold: number;
    price: number;
    image?: string;
}

export function MobileInventory() {
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [filter, setFilter] = useState<'all' | 'low'>('all');
    const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');

    useEffect(() => {
        fetchProducts();
    }, [currentAccount, filter, token]);

    const fetchProducts = async () => {
        if (!currentAccount || !token) {
            setLoading(false);
            return;
        }

        try {
            setLoading(true);
            const params = new URLSearchParams();
            params.append('limit', '50');
            if (searchQuery) params.append('q', searchQuery);

            const response = await fetch(`/api/products?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (!response.ok) throw new Error('Failed to fetch');

            const data = await response.json();
            let items = (data.products || data || []).map((p: ProductApiResponse) => ({
                id: p.id,
                name: p.name || 'Unnamed Product',
                sku: p.sku || '-',
                stockQuantity: (p.variations && p.variations.length > 0)
                    ? p.variations.reduce((sum: number, v: ProductVariation) => sum + (v.stock_quantity || v.stockQuantity || 0), 0)
                    : (p.stock_quantity ?? p.stockQuantity ?? 0),
                lowStockThreshold: p.low_stock_amount ?? p.lowStockThreshold ?? 5,
                price: p.price || 0,
                image: p.mainImage || p.images?.[0]?.src
            }));

            if (filter === 'low') {
                items = items.filter((p: Product) => p.stockQuantity <= p.lowStockThreshold);
            }

            setProducts(items);
        } catch (error) {
            Logger.error('[MobileInventory] Error:', { error: error });
        } finally {
            setLoading(false);
        }
    };

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        fetchProducts();
    };

    const isLowStock = (product: Product) => product.stockQuantity <= product.lowStockThreshold;
    const lowStockCount = products.filter(isLowStock).length;

    // Currency formatting helper
    const formatAccountCurrency = (amount: number) =>
        formatCurrency(amount, currentAccount?.currency || 'USD', { minimumFractionDigits: 0 });

    if (loading) {
        return (
            <div className="space-y-4 animate-pulse">
                <div className="flex items-center justify-between">
                    <div className="h-8 bg-gray-200 rounded w-28" />
                    <div className="flex gap-2">
                        <div className="h-10 w-10 bg-gray-200 rounded-xl" />
                        <div className="h-10 w-10 bg-gray-200 rounded-xl" />
                    </div>
                </div>
                <div className="h-12 bg-gray-200 rounded-2xl" />
                {[...Array(5)].map((_, i) => (
                    <div key={i} className="h-24 bg-gray-200 rounded-2xl" />
                ))}
            </div>
        );
    }

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-gray-900">Inventory</h1>
                <div className="flex gap-2">
                    <button
                        onClick={() => setViewMode('list')}
                        className={`p-2.5 rounded-xl transition-colors ${viewMode === 'list' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-600'}`}
                    >
                        <List size={20} />
                    </button>
                    <button
                        onClick={() => setViewMode('grid')}
                        className={`p-2.5 rounded-xl transition-colors ${viewMode === 'grid' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-600'}`}
                    >
                        <Grid size={20} />
                    </button>
                </div>
            </div>

            {/* Low Stock Alert */}
            {lowStockCount > 0 && (
                <button
                    onClick={() => setFilter(filter === 'low' ? 'all' : 'low')}
                    className={`w-full flex items-center gap-3 p-4 rounded-2xl transition-all active:scale-[0.98] ${filter === 'low'
                        ? 'bg-amber-500 text-white'
                        : 'bg-amber-50 border border-amber-200'
                        }`}
                >
                    <div className={`p-2 rounded-full ${filter === 'low' ? 'bg-amber-400' : 'bg-amber-100'}`}>
                        <AlertTriangle size={20} className={filter === 'low' ? 'text-white' : 'text-amber-600'} />
                    </div>
                    <div className="flex-1 text-left">
                        <p className={`font-semibold ${filter === 'low' ? 'text-white' : 'text-amber-900'}`}>
                            {lowStockCount} item{lowStockCount > 1 ? 's' : ''} low on stock
                        </p>
                        <p className={`text-sm ${filter === 'low' ? 'text-amber-100' : 'text-amber-700'}`}>
                            {filter === 'low' ? 'Showing low stock only' : 'Tap to view'}
                        </p>
                    </div>
                    <ChevronRight size={20} className={filter === 'low' ? 'text-amber-100' : 'text-amber-400'} />
                </button>
            )}

            {/* Search */}
            <form onSubmit={handleSearch} className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                <input
                    type="text"
                    placeholder="Search products..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-12 pr-4 py-3.5 bg-white border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent text-base"
                />
            </form>

            {/* Filter Chips */}
            <div className="flex gap-2">
                <button
                    onClick={() => setFilter('all')}
                    className={`px-4 py-2.5 rounded-full text-sm font-semibold transition-all ${filter === 'all'
                        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200'
                        : 'bg-white text-gray-700 border border-gray-200'
                        }`}
                >
                    All Products
                </button>
                <button
                    onClick={() => setFilter('low')}
                    className={`px-4 py-2.5 rounded-full text-sm font-semibold flex items-center gap-1.5 transition-all ${filter === 'low'
                        ? 'bg-amber-500 text-white shadow-lg shadow-amber-200'
                        : 'bg-white text-gray-700 border border-gray-200'
                        }`}
                >
                    <AlertTriangle size={14} />
                    Low Stock
                </button>
            </div>

            {/* Products */}
            {products.length === 0 ? (
                <div className="text-center py-16">
                    <div className="w-20 h-20 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
                        <Package2 className="text-gray-400" size={36} />
                    </div>
                    <p className="text-gray-900 font-semibold mb-1">No products found</p>
                    <p className="text-gray-500 text-sm">Products will appear here</p>
                </div>
            ) : viewMode === 'grid' ? (
                /* Grid View */
                <div className="grid grid-cols-2 gap-3">
                    {products.map((product) => {
                        const lowStock = isLowStock(product);
                        return (
                            <div
                                key={product.id}
                                className="bg-white rounded-2xl p-3 shadow-sm border border-gray-100 active:scale-[0.98] transition-all"
                            >
                                {product.image ? (
                                    <img src={product.image} alt={product.name} className="w-full h-28 rounded-xl object-cover mb-3" />
                                ) : (
                                    <div className="w-full h-28 rounded-xl bg-gray-100 flex items-center justify-center mb-3">
                                        <Package2 size={32} className="text-gray-400" />
                                    </div>
                                )}
                                <p className="font-semibold text-gray-900 text-sm line-clamp-2 mb-1">{product.name}</p>
                                <p className="text-xs text-gray-500 mb-2">SKU: {product.sku}</p>
                                <div className="flex items-center justify-between">
                                    <span className="text-sm font-bold text-gray-900">{formatAccountCurrency(product.price)}</span>
                                    <span className={`text-sm font-bold ${lowStock ? 'text-amber-600' : 'text-emerald-600'}`}>
                                        {product.stockQuantity}
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            ) : (
                /* List View */
                <div className="space-y-3">
                    {products.map((product) => {
                        const lowStock = isLowStock(product);
                        return (
                            <div
                                key={product.id}
                                className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100 flex items-center gap-4 active:scale-[0.98] transition-all"
                            >
                                {product.image ? (
                                    <img src={product.image} alt={product.name} className="w-16 h-16 rounded-xl object-cover flex-shrink-0" />
                                ) : (
                                    <div className="w-16 h-16 rounded-xl bg-gray-100 flex items-center justify-center flex-shrink-0">
                                        <Package2 size={28} className="text-gray-400" />
                                    </div>
                                )}
                                <div className="flex-1 min-w-0">
                                    <p className="font-semibold text-gray-900 truncate mb-0.5">{product.name}</p>
                                    <p className="text-sm text-gray-500">SKU: {product.sku}</p>
                                    <p className="text-sm font-bold text-gray-900 mt-1">{formatAccountCurrency(product.price)}</p>
                                </div>
                                <div className="text-right flex-shrink-0">
                                    <p className={`text-2xl font-bold ${lowStock ? 'text-amber-600' : 'text-emerald-600'}`}>
                                        {product.stockQuantity}
                                    </p>
                                    <p className="text-xs text-gray-500">in stock</p>
                                    {lowStock && (
                                        <span className="inline-flex items-center gap-1 text-xs text-amber-600 font-medium mt-1">
                                            <AlertTriangle size={10} /> Low
                                        </span>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Package, Truck, CheckCircle, XCircle, Clock, MapPin, User, Mail, Phone, CreditCard, Copy, ExternalLink, X, TrendingUp, Globe, Smartphone, Monitor, Tablet, Tag } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { fixMojibake, formatCurrency, formatDateTime } from '../../utils/format';
import { usePermissions } from '../../hooks/usePermissions';
import { OrderCOGSPanel } from '../../components/orders/OrderCOGSPanel';

interface OrderApiLineItem {
    id: string;
    name?: string;
    quantity?: number;
    total?: string | number;
    price?: string | number;
    image?: { src?: string };
    sku?: string;
    meta_data?: OrderMetaData[];
}

interface Attribution {
    firstTouchSource: string;
    lastTouchSource: string;
    utmSource?: string;
    utmMedium?: string;
    utmCampaign?: string;
    country?: string;
    city?: string;
    deviceType?: string;
}

interface OrderMetaData {
    key: string;
    value: string;
}

interface OrderLineItem {
    id: string;
    name: string;
    quantity: number;
    price: number;
    image?: string;
    sku?: string;
    meta_data?: OrderMetaData[];
}

interface TrackingItem {
    provider: string;
    trackingNumber: string;
    trackingUrl: string | null;
    dateShipped: string | null;
}

interface OrderDetail {
    id: string;
    orderNumber: string;
    status: string;
    createdAt: string;
    total: number;
    subtotal: number;
    shippingTotal: number;
    taxTotal: number;
    paymentMethod: string;
    customer: { name: string; email: string; phone?: string };
    billing: { address1: string; city: string; state: string; postcode: string; country: string };
    shipping: { address1: string; city: string; state: string; postcode: string; country: string };
    lineItems: OrderLineItem[];
    trackingItems: TrackingItem[];
    currency?: string;
}

const STATUS_CONFIG: Record<string, { icon: typeof Package; color: string; bg: string; text: string }> = {
    pending: { icon: Clock, color: 'text-yellow-600', bg: 'bg-yellow-100', text: 'Pending' },
    processing: { icon: Package, color: 'text-blue-600', bg: 'bg-blue-100', text: 'Processing' },
    shipped: { icon: Truck, color: 'text-purple-600', bg: 'bg-purple-100', text: 'Shipped' },
    delivered: { icon: CheckCircle, color: 'text-green-600', bg: 'bg-green-100', text: 'Delivered' },
    completed: { icon: CheckCircle, color: 'text-green-600', bg: 'bg-green-100', text: 'Completed' },
    cancelled: { icon: XCircle, color: 'text-red-600', bg: 'bg-red-100', text: 'Cancelled' },
};

export function MobileOrderDetail() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const [order, setOrder] = useState<OrderDetail | null>(null);
    const [loading, setLoading] = useState(true);
    const [selectedImage, setSelectedImage] = useState<string | null>(null);
    const [attribution, setAttribution] = useState<Attribution | null>(null);
    const [orderTags, setOrderTags] = useState<string[]>([]);
    const { hasPermission } = usePermissions();
    const canViewCogs = hasPermission('view_cogs');

    useEffect(() => {
        if (id) fetchOrder();
        // Listen for refresh events from pull-to-refresh
        const handleRefresh = () => { if (id) fetchOrder(); };
        window.addEventListener('mobile-refresh', handleRefresh);
        return () => window.removeEventListener('mobile-refresh', handleRefresh);
    }, [id, token, currentAccount]);

    const fetchOrder = async () => {
        if (!currentAccount || !token || !id) return;

        try {
            setLoading(true);
            const response = await fetch(`/api/orders/${id}`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (!response.ok) throw new Error('Failed to fetch');
            const o = await response.json();

            setOrder({
                id: o.id,
                orderNumber: o.orderNumber || `#${String(o.id).slice(-6).toUpperCase()}`,
                status: o.status || 'pending',
                createdAt: o.date_created || o.createdAt,
                total: Number(o.total) || 0,
                subtotal: Number(o.subtotal) || 0,
                shippingTotal: Number(o.shipping_total || o.shippingTotal) || 0,
                taxTotal: Number(o.total_tax || o.taxTotal) || 0,
                paymentMethod: o.payment_method_title || o.paymentMethod || 'Unknown',
                customer: {
                    name: o.billing?.first_name ? `${o.billing.first_name} ${o.billing.last_name || ''}`.trim() : 'Guest',
                    email: o.billing?.email || '',
                    phone: o.billing?.phone
                },
                billing: { address1: o.billing?.address_1 || '', city: o.billing?.city || '', state: o.billing?.state || '', postcode: o.billing?.postcode || '', country: o.billing?.country || '' },
                shipping: { address1: o.shipping?.address_1 || o.billing?.address_1 || '', city: o.shipping?.city || o.billing?.city || '', state: o.shipping?.state || o.billing?.state || '', postcode: o.shipping?.postcode || o.billing?.postcode || '', country: o.shipping?.country || o.billing?.country || '' },
                lineItems: (o.line_items || []).map((item: OrderApiLineItem) => ({
                    id: item.id,
                    name: item.name || 'Unknown',
                    quantity: item.quantity || 1,
                    price: Number(item.total || item.price) || 0,
                    image: item.image?.src,
                    sku: item.sku,
                    meta_data: item.meta_data
                })),
                trackingItems: o.tracking_items || [],
                currency: o.currency
            });

            // Store tags separately for removal functionality
            setOrderTags(o.tags || []);

            // Fetch attribution data
            fetchAttribution();
        } catch (error) {
            Logger.error('[MobileOrderDetail] Error:', { error: error });
        } finally {
            setLoading(false);
        }
    };

    const fetchAttribution = async () => {
        if (!currentAccount || !token || !id) return;
        try {
            const res = await fetch(`/api/orders/${id}/attribution`, {
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (res.ok) {
                const data = await res.json();
                setAttribution(data.attribution);
            }
        } catch (err) {
            console.warn('Could not load attribution');
        }
    };

    const formatMoney = (amount: number) => formatCurrency(amount, currentAccount?.currency || 'USD');
    const formatDate = (date: string) => formatDateTime(date);
    const copyToClipboard = (text: string) => { navigator.clipboard.writeText(text); if ('vibrate' in navigator) navigator.vibrate(10); };

    const removeTag = async (tag: string) => {
        if (!currentAccount || !token || !order) return;
        try {
            const res = await fetch(`/api/orders/${id}/tags/${encodeURIComponent(tag)}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}`, 'X-Account-ID': currentAccount.id }
            });
            if (res.ok) {
                const data = await res.json();
                setOrderTags(data.tags);
            }
        } catch (err) {
            Logger.error('Failed to remove tag', { error: err });
        }
    };

    if (loading) return <div className="space-y-4 animate-pulse"><div className="h-10 bg-gray-200 rounded w-1/3" /><div className="h-24 bg-gray-200 rounded-xl" /><div className="h-40 bg-gray-200 rounded-xl" /></div>;
    if (!order) return <div className="text-center py-12"><Package className="mx-auto text-gray-300 mb-4" size={48} /><p className="text-gray-500">Order not found</p><button onClick={() => navigate('/m/orders')} className="mt-4 text-indigo-600 font-medium">Back to Orders</button></div>;

    const statusConfig = STATUS_CONFIG[order.status.toLowerCase()] || STATUS_CONFIG.pending;
    const StatusIcon = statusConfig.icon;

    return (
        <div className="space-y-4 pb-8">
            <div className="flex items-center gap-3">
                <button onClick={() => navigate('/m/orders')} className="p-2 -ml-2 rounded-lg active:bg-gray-100"><ArrowLeft size={24} className="text-gray-700" /></button>
                <div className="flex-1"><h1 className="text-xl font-bold text-gray-900">{order.orderNumber}</h1><p className="text-sm text-gray-500">{formatDate(order.createdAt)}</p></div>
            </div>

            <div className={`${statusConfig.bg} rounded-xl p-4 flex items-center gap-4`}>
                <div className="p-3 bg-white rounded-lg shadow-sm"><StatusIcon size={24} className={statusConfig.color} /></div>
                <div className="flex-1">
                    <p className={`font-semibold ${statusConfig.color}`}>{statusConfig.text}</p>
                    {order.trackingItems.length > 0 && (
                        <button onClick={() => copyToClipboard(order.trackingItems[0].trackingNumber)} className="flex items-center gap-1 text-sm text-gray-600 mt-1">
                            <span>Tracking: {order.trackingItems[0].trackingNumber}</span><Copy size={14} />
                        </button>
                    )}
                </div>
                {order.trackingItems[0]?.trackingUrl && <a href={order.trackingItems[0].trackingUrl} target="_blank" rel="noopener noreferrer" className="p-2 bg-white rounded-lg shadow-sm"><ExternalLink size={20} className="text-gray-600" /></a>}
            </div>

            {/* Shipment Tracking Details */}
            {order.trackingItems.length > 0 && (
                <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                    <div className="flex items-center gap-2 mb-3">
                        <Truck size={18} className="text-indigo-600" />
                        <h2 className="font-semibold text-gray-900">Shipment Tracking</h2>
                    </div>
                    <div className="space-y-3">
                        {order.trackingItems.map((item, idx) => (
                            <div key={idx} className={`space-y-1.5 ${idx > 0 ? 'pt-3 border-t border-gray-100' : ''}`}>
                                <div className="flex items-center justify-between">
                                    <span className="text-xs font-semibold text-gray-500 uppercase">{item.provider}</span>
                                    {item.dateShipped && <span className="text-xs text-gray-400">Shipped {item.dateShipped}</span>}
                                </div>
                                <div className="flex items-center gap-2">
                                    <code className="text-sm font-mono text-gray-900 bg-gray-50 px-2 py-1 rounded flex-1 truncate">{item.trackingNumber}</code>
                                    <button onClick={() => copyToClipboard(item.trackingNumber)} className="p-1.5 active:bg-gray-100 rounded text-gray-400"><Copy size={14} /></button>
                                    {item.trackingUrl && (
                                        <a href={item.trackingUrl} target="_blank" rel="noopener noreferrer" className="p-1.5 active:bg-blue-50 rounded text-blue-500"><ExternalLink size={14} /></a>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                <h2 className="font-semibold text-gray-900 mb-3">Customer</h2>
                <div className="space-y-3">
                    <div className="flex items-center gap-3"><User size={18} className="text-gray-400" /><span className="text-gray-700">{order.customer.name}</span></div>
                    {order.customer.email && <a href={`mailto:${order.customer.email}`} className="flex items-center gap-3"><Mail size={18} className="text-gray-400" /><span className="text-indigo-600">{order.customer.email}</span></a>}
                    {order.customer.phone && <a href={`tel:${order.customer.phone}`} className="flex items-center gap-3"><Phone size={18} className="text-gray-400" /><span className="text-indigo-600">{order.customer.phone}</span></a>}
                </div>
            </div>

            <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                <h2 className="font-semibold text-gray-900 mb-3">Shipping Address</h2>
                <div className="flex items-start gap-3"><MapPin size={18} className="text-gray-400 mt-0.5" /><div className="text-gray-700"><p>{order.shipping.address1}</p><p>{order.shipping.city}, {order.shipping.state} {order.shipping.postcode}</p><p>{order.shipping.country}</p></div></div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <h2 className="font-semibold text-gray-900 p-4 border-b border-gray-100">Items ({order.lineItems.length})</h2>
                <div className="divide-y divide-gray-100">
                    {order.lineItems.map((item) => (
                        <div key={item.id} className="p-4">
                            <div className="flex items-start gap-3">
                                {item.image ? (
                                    <img src={item.image} alt={item.name} className="w-14 h-14 rounded-lg object-cover flex-shrink-0" />
                                ) : (
                                    <div className="w-14 h-14 rounded-lg bg-gray-100 flex items-center justify-center flex-shrink-0">
                                        <Package size={20} className="text-gray-400" />
                                    </div>
                                )}
                                <div className="flex-1 min-w-0">
                                    <p className="font-medium text-gray-900">{item.name}</p>
                                    <div className="flex items-center gap-2 text-sm text-gray-500">
                                        <span>Qty: {item.quantity}</span>
                                        {item.sku && <span>• SKU: {item.sku}</span>}
                                    </div>
                                </div>
                                <span className="font-medium text-gray-900">{formatCurrency(item.price)}</span>
                            </div>
                            {/* Product Variations / Metadata */}
                            {item.meta_data && item.meta_data.length > 0 && (
                                <div className="mt-2 ml-[68px] space-y-1">
                                    {item.meta_data
                                        .filter((meta) => !meta.key.startsWith('_'))
                                        .map((meta, idx) => {
                                            const imageUrls = extractAllImageUrls(meta.value);
                                            return (
                                                <div key={idx} className="text-xs">
                                                    <span className="font-medium text-gray-500 bg-gray-100 px-1.5 py-0.5 rounded">
                                                        {fixMojibake(meta.key)}:
                                                    </span>
                                                    {imageUrls.length > 0 ? (
                                                        <div className="flex flex-wrap gap-2 mt-1">
                                                            {imageUrls.map((imgUrl, imgIdx) => (
                                                                <button
                                                                    key={imgIdx}
                                                                    onClick={() => setSelectedImage(imgUrl)}
                                                                    className="inline-block"
                                                                >
                                                                    <img
                                                                        src={imgUrl}
                                                                        alt={`${meta.key} ${imgIdx + 1}`}
                                                                        className="h-12 w-auto rounded border border-gray-200"
                                                                    />
                                                                </button>
                                                            ))}
                                                        </div>
                                                    ) : (
                                                        <span className="ml-1 text-gray-700 whitespace-pre-line">{fixMojibake(meta.value)}</span>
                                                    )}
                                                </div>
                                            );
                                        })}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                <h2 className="font-semibold text-gray-900 mb-3">Order Summary</h2>
                <div className="space-y-2 text-sm">
                    <div className="flex justify-between"><span className="text-gray-600">Subtotal</span><span className="text-gray-900">{formatCurrency(order.subtotal)}</span></div>
                    <div className="flex justify-between"><span className="text-gray-600">Shipping</span><span className="text-gray-900">{formatCurrency(order.shippingTotal)}</span></div>
                    <div className="flex justify-between"><span className="text-gray-600">Tax</span><span className="text-gray-900">{formatCurrency(order.taxTotal)}</span></div>
                    <div className="flex justify-between pt-2 border-t border-gray-100"><span className="font-semibold text-gray-900">Total</span><span className="font-bold text-gray-900">{formatCurrency(order.total)}</span></div>
                </div>
                <div className="flex items-center gap-2 mt-3 pt-3 border-t border-gray-100"><CreditCard size={16} className="text-gray-400" /><span className="text-sm text-gray-600">{order.paymentMethod}</span></div>
            </div>

            {/* COGS Breakdown - visible to users with view_cogs permission */}
            {canViewCogs && (
                <OrderCOGSPanel orderId={order.id} currency={order.currency} />
            )}

            {/* Tags Section */}
            {orderTags.length > 0 && (
                <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                    <div className="flex items-center gap-2 mb-3">
                        <Tag size={18} className="text-indigo-600" />
                        <h2 className="font-semibold text-gray-900">Tags</h2>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {orderTags.map((tag) => (
                            <span
                                key={tag}
                                className="inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-sm bg-gray-100 text-gray-700 group"
                            >
                                {tag}
                                <button
                                    onClick={() => removeTag(tag)}
                                    className="ml-1 p-0.5 rounded active:bg-gray-200 opacity-60 active:opacity-100"
                                >
                                    <X size={12} />
                                </button>
                            </span>
                        ))}
                    </div>
                </div>
            )}

            {/* Attribution Section */}
            <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                <div className="flex items-center gap-2 mb-3">
                    <TrendingUp size={18} className="text-indigo-600" />
                    <h2 className="font-semibold text-gray-900">Attribution</h2>
                </div>
                {attribution ? (
                    <div className="space-y-3">
                        {/* Traffic Source */}
                        <div className="flex flex-wrap gap-2">
                            <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-700">
                                First: {attribution.firstTouchSource}
                            </span>
                            <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-700">
                                Last: {attribution.lastTouchSource}
                            </span>
                        </div>

                        {/* UTM Parameters */}
                        {(attribution.utmSource || attribution.utmMedium || attribution.utmCampaign) && (
                            <div className="text-xs text-gray-600 space-y-1 pt-2 border-t border-gray-100">
                                {attribution.utmSource && <div>Source: <span className="text-gray-900">{attribution.utmSource}</span></div>}
                                {attribution.utmMedium && <div>Medium: <span className="text-gray-900">{attribution.utmMedium}</span></div>}
                                {attribution.utmCampaign && <div>Campaign: <span className="text-gray-900">{attribution.utmCampaign}</span></div>}
                            </div>
                        )}

                        {/* Device & Location */}
                        {(attribution.deviceType || attribution.country) && (
                            <div className="flex flex-wrap gap-2 pt-2 border-t border-gray-100">
                                {attribution.deviceType && (
                                    <span className="inline-flex items-center gap-1 px-2 py-1 rounded-md text-xs bg-gray-100 text-gray-700">
                                        {attribution.deviceType === 'mobile' ? <Smartphone size={12} /> :
                                            attribution.deviceType === 'tablet' ? <Tablet size={12} /> : <Monitor size={12} />}
                                        {attribution.deviceType}
                                    </span>
                                )}
                                {attribution.country && (
                                    <span className="inline-flex items-center gap-1 px-2 py-1 rounded-md text-xs bg-gray-100 text-gray-700">
                                        <Globe size={12} />
                                        {attribution.city ? `${attribution.city}, ` : ''}{attribution.country}
                                    </span>
                                )}
                            </div>
                        )}
                    </div>
                ) : (
                    <p className="text-sm text-gray-500 italic">No attribution data</p>
                )}
            </div>

            {/* Image Preview Modal */}
            {selectedImage && (
                <div
                    className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4"
                    onClick={() => setSelectedImage(null)}
                >
                    <button
                        className="absolute top-4 right-4 p-2 bg-white/10 rounded-full"
                        onClick={() => setSelectedImage(null)}
                    >
                        <X size={24} className="text-white" />
                    </button>
                    <img
                        src={selectedImage}
                        alt="Preview"
                        className="max-w-full max-h-[85vh] object-contain rounded-lg"
                        onClick={(e) => e.stopPropagation()}
                    />
                </div>
            )}
        </div>
    );
}

/**
 * Extracts an image URL from a meta value.
 * Handles compound values like "filename.webp | https://example.com/path/to/image.webp"
 */
const extractImageUrl = (value: string): string | null => {
    if (typeof value !== 'string') return null;

    const imagePattern = /\.(jpg|jpeg|png|gif|webp|svg|bmp)/i;

    // Direct image URL
    if (imagePattern.test(value) && value.startsWith('http')) {
        return value;
    }

    // Look for URLs within the value (handles "filename | url" format)
    const urlMatch = value.match(/(https?:\/\/[^\s|]+)/g);
    if (urlMatch) {
        for (const url of urlMatch) {
            if (imagePattern.test(url)) {
                return url.trim();
            }
        }
    }

    return null;
};

/**
 * Extracts ALL image URLs from a meta value.
 * WooCommerce can store multiple images per meta entry (newline or pipe separated).
 * Returns an array of all found image URLs.
 */
const extractAllImageUrls = (value: string): string[] => {
    if (typeof value !== 'string') return [];

    const imagePattern = /\.(jpg|jpeg|png|gif|webp|svg|bmp)/i;
    const urls: string[] = [];

    // Find all URLs in the value
    const urlMatches = value.match(/(https?:\/\/[^\s|,\n]+)/g);
    if (urlMatches) {
        for (const url of urlMatches) {
            const cleanUrl = url.trim();
            if (imagePattern.test(cleanUrl) && !urls.includes(cleanUrl)) {
                urls.push(cleanUrl);
            }
        }
    }

    return urls;
};

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useNavigate } from 'react-router-dom';
import {
    Search,
    Package,
    Truck,
    CheckCircle,
    XCircle,
    Clock,
    RefreshCw,
    ShoppingBag
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useHaptic } from '../../hooks/useHaptic';
import { SwipeableRow } from '../../components/ui/SwipeableRow';
import { formatCurrency } from '../../utils/format';
import { OrdersSkeleton } from '../../components/mobile/MobileSkeleton';

interface OrderApiResponse {
    id: string;
    orderNumber?: string;
    billing?: {
        first_name?: string;
        last_name?: string;
        email?: string;
    };
    total?: number;
    status?: string;
    date_created?: string;
    createdAt?: string;
    line_items?: unknown[];
}

interface Order {
    id: string;
    orderNumber: string;
    customerName: string;
    total: number;
    status: string;
    createdAt: string;
    itemCount: number;
}

/**
 * Dark-mode status config with colors matching glassmorphism theme.
 */
const STATUS_CONFIG: Record<string, { icon: typeof Package; color: string; bg: string; label: string; next?: string }> = {
    pending: { icon: Clock, color: 'text-amber-400', bg: 'bg-amber-500/20', label: 'Pending', next: 'processing' },
    processing: { icon: Package, color: 'text-blue-400', bg: 'bg-blue-500/20', label: 'Processing', next: 'shipped' },
    shipped: { icon: Truck, color: 'text-purple-400', bg: 'bg-purple-500/20', label: 'Shipped', next: 'completed' },
    delivered: { icon: CheckCircle, color: 'text-emerald-400', bg: 'bg-emerald-500/20', label: 'Delivered' },
    completed: { icon: CheckCircle, color: 'text-emerald-400', bg: 'bg-emerald-500/20', label: 'Completed' },
    cancelled: { icon: XCircle, color: 'text-red-400', bg: 'bg-red-500/20', label: 'Cancelled' },
    refunded: { icon: RefreshCw, color: 'text-slate-400', bg: 'bg-slate-500/20', label: 'Refunded' },
};

const FILTER_OPTIONS = ['All', 'Pending', 'Processing', 'Shipped', 'Completed'];

/**
 * MobileOrders - Premium dark-mode orders list for PWA.
 * Features swipe-to-advance status, search, and filters.
 */
export function MobileOrders() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount } = useAccount();
    const { triggerHaptic } = useHaptic();
    const [orders, setOrders] = useState<Order[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [activeFilter, setActiveFilter] = useState('All');
    const [hasMore, setHasMore] = useState(true);
    const [page, setPage] = useState(1);

    useEffect(() => {
        fetchOrders(true);
        // Listen for refresh events from pull-to-refresh
        const handleRefresh = () => fetchOrders(true);
        window.addEventListener('mobile-refresh', handleRefresh);
        return () => window.removeEventListener('mobile-refresh', handleRefresh);
    }, [currentAccount, activeFilter, token]);

    const fetchOrders = async (reset = false) => {
        if (!currentAccount || !token) {
            setLoading(false);
            return;
        }

        try {
            if (reset) {
                setLoading(true);
                setPage(1);
            }

            const currentPage = reset ? 1 : page;
            const params = new URLSearchParams();
            params.append('page', currentPage.toString());
            params.append('limit', '20');
            if (activeFilter !== 'All') params.append('status', activeFilter.toLowerCase());
            if (searchQuery) params.append('q', searchQuery);

            const res = await fetch(`/api/sync/orders/search?${params}`, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });

            if (!res.ok) throw new Error('Failed to fetch orders');

            const data = await res.json();
            const newOrders = (data.orders || data || []).map((o: OrderApiResponse) => ({
                id: o.id,
                orderNumber: o.orderNumber || `#${String(o.id).slice(-6).toUpperCase()}`,
                customerName: o.billing?.first_name
                    ? `${o.billing.first_name} ${o.billing.last_name || ''}`.trim()
                    : o.billing?.email || 'Guest',
                total: o.total || 0,
                status: o.status || 'pending',
                createdAt: o.date_created || o.createdAt || '',
                itemCount: o.line_items?.length || 0
            }));

            if (reset) {
                setOrders(newOrders);
            } else {
                setOrders(prev => [...prev, ...newOrders]);
            }

            setHasMore(newOrders.length === 20);
            setPage(currentPage + 1);
        } catch (error) {
            Logger.error('[MobileOrders] Error fetching orders:', { error: error });
        } finally {
            setLoading(false);
        }
    };

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        triggerHaptic();
        fetchOrders(true);
    };

    const handleFilterChange = (filter: string) => {
        triggerHaptic();
        setActiveFilter(filter);
    };

    const formatDate = (date: string) => {
        const d = new Date(date);
        const now = new Date();
        const isToday = d.toDateString() === now.toDateString();
        const isYesterday = new Date(now.getTime() - 86400000).toDateString() === d.toDateString();

        if (isToday) return d.toLocaleTimeString('en-AU', { hour: 'numeric', minute: '2-digit' });
        if (isYesterday) return 'Yesterday';
        return d.toLocaleDateString('en-AU', { day: 'numeric', month: 'short' });
    };

    const formatAccountCurrency = (amount: number) =>
        formatCurrency(amount, currentAccount?.currency || 'USD', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

    const getStatusConfig = (status: string) => {
        return STATUS_CONFIG[status.toLowerCase()] || STATUS_CONFIG.pending;
    };

    const advanceStatus = async (orderId: string, currentStatus: string) => {
        const config = getStatusConfig(currentStatus);
        if (!config.next) return;

        triggerHaptic(15);

        // Optimistically update
        setOrders(prev => prev.map(o =>
            o.id === orderId ? { ...o, status: config.next! } : o
        ));

        try {
            await fetch(`/api/sync/orders/${orderId}`, {
                method: 'PATCH',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount!.id,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ status: config.next })
            });
        } catch (error) {
            Logger.error('[MobileOrders] Status update failed:', { error: error });
            fetchOrders(true);
        }
    };

    if (loading && orders.length === 0) {
        return <OrdersSkeleton />;
    }

    return (
        <div className="space-y-4 animate-fade-slide-up">
            {/* Header */}
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-white">Orders</h1>
                <span className="text-sm text-slate-400 bg-slate-800/50 px-3 py-1 rounded-full">
                    {orders.length} orders
                </span>
            </div>

            {/* Search */}
            <form onSubmit={handleSearch} className="relative">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 p-1.5 rounded-lg bg-slate-700/50">
                    <Search size={16} className="text-slate-400" />
                </div>
                <input
                    type="text"
                    placeholder="Search by order # or customer..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-14 pr-4 py-3.5 pwa-card text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 transition-all"
                />
            </form>

            {/* Filter Chips */}
            <div className="flex gap-2 overflow-x-auto pb-1 -mx-4 px-4 no-scrollbar">
                {FILTER_OPTIONS.map((filter) => {
                    const filterConfig = filter !== 'All' ? getStatusConfig(filter) : null;
                    const isActive = activeFilter === filter;
                    return (
                        <button
                            key={filter}
                            onClick={() => handleFilterChange(filter)}
                            className={`
                                px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all flex items-center gap-2 active:scale-95
                                ${isActive
                                    ? 'bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg shadow-indigo-500/25'
                                    : 'bg-slate-700/40 border border-white/10 text-slate-300'
                                }
                            `}
                        >
                            {filterConfig && <filterConfig.icon size={14} />}
                            {filter}
                        </button>
                    );
                })}
            </div>

            {/* Swipe Hint */}
            {orders.length > 0 && (
                <p className="text-xs text-slate-500 text-center">
                    ← Swipe right to advance order status
                </p>
            )}

            {/* Orders List */}
            <div className="space-y-3">
                {orders.length === 0 ? (
                    <div className="text-center py-16">
                        <div className="w-20 h-20 mx-auto mb-4 pwa-card flex items-center justify-center">
                            <ShoppingBag className="text-slate-500" size={36} />
                        </div>
                        <p className="text-white font-semibold mb-1">No orders found</p>
                        <p className="text-slate-400 text-sm">Orders will appear here</p>
                    </div>
                ) : (
                    orders.map((order, index) => {
                        const config = getStatusConfig(order.status);
                        const StatusIcon = config.icon;
                        const nextConfig = config.next ? getStatusConfig(config.next) : null;
                        const NextIcon = nextConfig?.icon;

                        return (
                            <SwipeableRow
                                key={order.id}
                                leftAction={config.next && NextIcon ? {
                                    icon: <NextIcon size={24} className="text-white" />,
                                    color: 'bg-indigo-500',
                                    onAction: () => advanceStatus(order.id, order.status)
                                } : undefined}
                            >
                                <button
                                    onClick={() => {
                                        triggerHaptic();
                                        navigate(`/m/orders/${order.id}`);
                                    }}
                                    className="w-full pwa-card p-4 active:bg-slate-700/50 transition-all animate-fade-slide-up"
                                    style={{ animationDelay: `${index * 15}ms` }}
                                >
                                    <div className="flex items-start justify-between mb-3">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-xl ${config.bg} flex items-center justify-center`}>
                                                <StatusIcon size={18} className={config.color} />
                                            </div>
                                            <div className="text-left">
                                                <p className="font-bold text-white">{order.orderNumber}</p>
                                                <p className="text-sm text-slate-400">{order.customerName}</p>
                                            </div>
                                        </div>
                                        <span className="text-xs text-slate-500">{formatDate(order.createdAt)}</span>
                                    </div>

                                    <div className="flex items-center justify-between pt-3 border-t border-white/5">
                                        <span className={`text-xs font-medium px-2.5 py-1 rounded-full ${config.bg} ${config.color}`}>
                                            {config.label}
                                        </span>
                                        <p className="text-lg font-bold text-white">{formatAccountCurrency(order.total)}</p>
                                    </div>

                                    {order.itemCount > 0 && (
                                        <p className="text-xs text-slate-500 mt-2">
                                            {order.itemCount} item{order.itemCount > 1 ? 's' : ''}
                                        </p>
                                    )}
                                </button>
                            </SwipeableRow>
                        );
                    })
                )}

                {/* Load More */}
                {hasMore && orders.length > 0 && (
                    <button
                        onClick={() => fetchOrders()}
                        disabled={loading}
                        className="w-full py-4 text-indigo-400 font-semibold disabled:opacity-50 pwa-card active:bg-slate-700/50 transition-all"
                    >
                        {loading ? 'Loading...' : 'Load More Orders'}
                    </button>
                )}
            </div>
        </div>
    );
}

import { useState } from 'react';
import { Logger } from '../../utils/logger';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';
import { useHaptic } from '../../hooks/useHaptic';
import {
    ChevronLeft,
    ChevronRight,
    Bell,
    Package,
    MessageSquare,
    RefreshCw,
    Globe,
    Loader2
} from 'lucide-react';

/**
 * MobileSettings - Premium dark-mode settings for PWA.
 * Provides sync controls and quick access to key settings.
 */

interface SettingItem {
    id: string;
    label: string;
    description: string;
    icon: typeof Bell;
    iconColor: string;
    iconBg: string;
}

export function MobileSettings() {
    const navigate = useNavigate();
    const { token } = useAuth();
    const { currentAccount, accounts, setCurrentAccount } = useAccount();
    const { triggerHaptic } = useHaptic();
    const [syncing, setSyncing] = useState(false);
    const [showSwitcher, setShowSwitcher] = useState(false);


    const settingSections = [
        {
            title: 'Notifications',
            items: [
                {
                    id: 'push',
                    label: 'Push Notifications',
                    description: 'Manage notification preferences',
                    icon: Bell,
                    iconColor: 'text-purple-400',
                    iconBg: 'bg-purple-500/20'
                }
            ]
        },
        {
            title: 'Store Settings',
            items: [
                {
                    id: 'products',
                    label: 'Products & Inventory',
                    description: 'Manage stock settings',
                    icon: Package,
                    iconColor: 'text-orange-400',
                    iconBg: 'bg-orange-500/20'
                },
                {
                    id: 'inbox',
                    label: 'Inbox Settings',
                    description: 'Chat and inbox preferences',
                    icon: MessageSquare,
                    iconColor: 'text-emerald-400',
                    iconBg: 'bg-emerald-500/20'
                }
            ]
        },
        {
            title: 'Active Store',
            items: [
                {
                    id: 'website',
                    label: currentAccount?.name || 'Store',
                    description: currentAccount?.wooUrl || 'No website configured',
                    icon: Globe,
                    iconColor: 'text-blue-400',
                    iconBg: 'bg-blue-500/20'
                }
            ]
        }
    ];

    const handleSync = async () => {
        if (!token || !currentAccount || syncing) return;

        triggerHaptic(20);
        setSyncing(true);
        try {
            await fetch('/api/sync/products/import', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            await fetch('/api/sync/orders/import', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'X-Account-ID': currentAccount.id
                }
            });
            triggerHaptic(30);
        } catch (e) {
            Logger.error('[MobileSettings] Sync error:', { error: e });
        } finally {
            setSyncing(false);
        }
    };

    const handleSettingPress = (id: string) => {
        triggerHaptic();
        switch (id) {
            case 'push':
                navigate('/m/notifications');
                break;
            case 'products':
                navigate('/m/inventory');
                break;
            case 'inbox':
                navigate('/m/inbox');
                break;
            case 'website':
                if (accounts.length > 1) {
                    setShowSwitcher(true);
                }
                break;
            default:
                break;
        }
    };

    return (
        <div className="space-y-6 animate-fade-slide-up">
            {/* Header */}
            <div className="flex items-center gap-3">
                <button
                    onClick={() => {
                        triggerHaptic();
                        navigate(-1);
                    }}
                    className="w-10 h-10 flex items-center justify-center rounded-2xl bg-slate-700/40 border border-white/10 active:scale-95 transition-transform"
                    aria-label="Go back"
                >
                    <ChevronLeft size={22} className="text-slate-300" />
                </button>
                <h1 className="text-xl font-bold text-white">Settings</h1>
            </div>

            {/* Sync Card */}
            <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl p-5 text-white shadow-xl shadow-indigo-500/20">
                <h3 className="font-semibold text-lg">Store Sync</h3>
                <p className="text-sm text-white/70 mt-1">Keep products and orders up to date</p>
                <button
                    onClick={handleSync}
                    disabled={syncing}
                    className="mt-4 w-full py-3.5 bg-white/20 hover:bg-white/30 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all active:scale-[0.98] disabled:opacity-50"
                >
                    {syncing ? (
                        <>
                            <Loader2 size={18} className="animate-spin" />
                            Syncing...
                        </>
                    ) : (
                        <>
                            <RefreshCw size={18} />
                            Sync Now
                        </>
                    )}
                </button>
            </div>

            {/* Settings Sections */}
            {settingSections.map((section, idx) => (
                <div key={idx}>
                    <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-3 px-1">
                        {section.title}
                    </h3>
                    <div className="pwa-card divide-y divide-white/5 overflow-hidden">
                        {section.items.map((item) => {
                            const Icon = item.icon;
                            return (
                                <button
                                    key={item.id}
                                    onClick={() => handleSettingPress(item.id)}
                                    className="w-full flex items-center gap-4 p-4 text-left active:bg-white/5 transition-colors"
                                >
                                    <div className={`w-10 h-10 rounded-xl ${item.iconBg} flex items-center justify-center`}>
                                        <Icon size={20} className={item.iconColor} />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="font-medium text-white">{item.label}</p>
                                        <p className="text-sm text-slate-400 truncate">{item.description}</p>
                                    </div>
                                    <ChevronRight size={18} className="text-slate-500 flex-shrink-0" />
                                </button>
                            );
                        })}
                    </div>
                </div>
            ))}

            {/* App Info */}
            <div className="text-center text-sm text-slate-500 py-4">
                <p>OverSeek Companion v1.0</p>
                <p className="mt-1">© 2026 SLDevs</p>
            </div>

            {/* Account Switcher Modal */}
            {showSwitcher && (
                <div className="fixed inset-0 z-50 flex items-end justify-center">
                    {/* Backdrop */}
                    <div
                        className="absolute inset-0 bg-black/70 backdrop-blur-sm"
                        onClick={() => setShowSwitcher(false)}
                    />
                    {/* Modal */}
                    <div className="relative w-full max-w-md bg-slate-900 border-t border-white/10 rounded-t-3xl p-6 pb-8 animate-fade-slide-up">
                        <div className="w-12 h-1 bg-slate-700 rounded-full mx-auto mb-4" />
                        <h2 className="text-lg font-bold text-white mb-4">Switch Store</h2>
                        <div className="space-y-2 max-h-64 overflow-y-auto">
                            {accounts.map((account) => (
                                <button
                                    key={account.id}
                                    onClick={() => {
                                        triggerHaptic(15);
                                        setCurrentAccount(account);
                                        setShowSwitcher(false);
                                        window.location.reload();
                                    }}
                                    className={`w-full flex items-center gap-3 p-4 rounded-xl text-left transition-colors ${currentAccount?.id === account.id
                                        ? 'bg-indigo-500/20 border-2 border-indigo-500'
                                        : 'bg-slate-800/50 border-2 border-transparent hover:bg-slate-700/50'
                                        }`}
                                >
                                    <div className={`w-10 h-10 rounded-xl ${currentAccount?.id === account.id ? 'bg-indigo-500/20' : 'bg-slate-700'} flex items-center justify-center`}>
                                        <Globe size={18} className={currentAccount?.id === account.id ? 'text-indigo-400' : 'text-slate-400'} />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className={`font-medium truncate ${currentAccount?.id === account.id ? 'text-indigo-400' : 'text-white'}`}>
                                            {account.name}
                                        </p>
                                        <p className="text-sm text-slate-500 truncate">{account.wooUrl}</p>
                                    </div>
                                    {currentAccount?.id === account.id && (
                                        <span className="text-xs font-medium text-indigo-400 bg-indigo-500/20 px-2.5 py-1 rounded-lg">Active</span>
                                    )}
                                </button>
                            ))}
                        </div>
                        <button
                            onClick={() => setShowSwitcher(false)}
                            className="w-full mt-4 py-3.5 bg-slate-800 border border-white/10 rounded-xl font-medium text-slate-300 active:bg-slate-700"
                        >
                            Cancel
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Logger } from '../../utils/logger';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, RefreshCw, MapPin, Monitor, Smartphone, Tablet, Globe, Clock, ShoppingCart, Eye, Search, CreditCard, Package, ChevronDown, ChevronRight } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useAccount } from '../../context/AccountContext';

interface AnalyticsEvent {
    id: string;
    type: string;
    url?: string;
    pageTitle?: string;
    payload?: any;
    createdAt: string;
}

interface AnalyticsVisit {
    id: string;
    visitNumber: number;
    startedAt: string;
    endedAt: string;
    referrer?: string;
    utmSource?: string;
    deviceType?: string;
    browser?: string;
    os?: string;
    country?: string;
    city?: string;
    pageviews: number;
    actions: number;
    events: AnalyticsEvent[];
}

interface VisitorData {
    session: {
        id: string;
        visitorId: string;
        email?: string;
        ipAddress?: string;
        city?: string;
        country?: string;
        deviceType?: string;
        browser?: string;
        os?: string;
        referrer?: string;
        utmSource?: string;
        lastActiveAt: string;
